INSERT INTO recipes VALUES ('2fauth', '2FAuth', '2FAuth is a web based self-hosted alternative to One Time Passcode (OTP) generators like Google Authenticator, designed for both mobile and desktop.', 'developer-tools', ARRAY['Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "2fauth/2fauth:6.1.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}$JSON$::jsonb, $JSON${"metadata": {"name": "2FAuth", "version": "latest", "description": "2FAuth is a web based self-hosted alternative to One Time Passcode (OTP) generators like Google Authenticator, designed for both mobile and desktop.", "category": "developer-tools", "tags": ["Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "2fauth/2fauth:6.1.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}, "links": [{"label": "Website", "url": "https://2fauth.app/"}, {"label": "Documentation", "url": "https://docs.2fauth.app/"}, {"label": "Github", "url": "https://github.com/Bubka/2FAuth"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "2fauth", "port": "$PORT:8000", "volumes": ["/2fauth"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "mysql": {"type": "mysql", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('4gaboards', '4ga Boards', '4ga Boards is a modern, open-source project management and collaboration platform inspired by Trello. It provides a powerful Kanban-style board system for organizing tasks, projects, and workflows. With its intuitive drag-and-drop interface, 4ga Boards makes it easy to visualize work, track progress, and collaborate with teams. The application features customizable boards, lists, and cards, along with support for attachments, user avatars, and project backgrounds. Built with modern web technologies, 4ga Boards offers a seamless experience for managing projects of any size. It''s perfect for teams looking for a self-hosted alternative to commercial project management tools, providing full control over your data and workflows. Whether you''re managing software development sprints, marketing campaigns, or personal todo lists, 4ga Boards provides the flexibility and features you need.', 'project-management', ARRAY['Project Management', 'Kanban', 'Productivity', 'Collaboration', 'Task Management', 'Self-Hosted', 'Team Tools', 'Workflow'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/rargames/4gaboards:3.3.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 1337}}$JSON$::jsonb, $JSON${"metadata": {"name": "4ga Boards", "version": "latest", "description": "4ga Boards is a modern, open-source project management and collaboration platform inspired by Trello. It provides a powerful Kanban-style board system for organizing tasks, projects, and workflows. With its intuitive drag-and-drop interface, 4ga Boards makes it easy to visualize work, track progress, and collaborate with teams. The application features customizable boards, lists, and cards, along with support for attachments, user avatars, and project backgrounds. Built with modern web technologies, 4ga Boards offers a seamless experience for managing projects of any size. It's perfect for teams looking for a self-hosted alternative to commercial project management tools, providing full control over your data and workflows. Whether you're managing software development sprints, marketing campaigns, or personal todo lists, 4ga Boards provides the flexibility and features you need.", "category": "project-management", "tags": ["Project Management", "Kanban", "Productivity", "Collaboration", "Task Management", "Self-Hosted", "Team Tools", "Workflow"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/rargames/4gaboards:3.3.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 1337}}, "links": [{"label": "Website", "url": "https://4gaboards.com/#home"}, {"label": "Documentation", "url": "https://docs.4gaboards.com"}, {"label": "GitHub", "url": "https://github.com/RARgames/4gaboards"}], "instructions": "Default credentials are demo/demo. Change the password after first login.", "install": [{"docker": {"image": "$IMAGE", "name": "4gaboards", "port": "$PORT:1337", "volumes": ["/app/public/user-avatars", "/app/public/project-background-images", "/app/private/attachments"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Default credentials are demo/demo. Change the password after first login."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('8mblocal', '8MB Local', '8MB Local is a self-hosted file processing and conversion application that provides tools for handling files and generating outputs. Built with modern architecture, 8MB Local offers a web-based interface accessible on port 8001 for processing files and managing uploads and outputs. The system stores uploaded files and generated outputs in separate persistent volumes, ensuring your data is preserved across container restarts. Perfect for individuals and organizations looking for a self-hosted solution for file processing and management.', 'file-processing', ARRAY['File Processing', 'Self-Hosted', 'File Management', 'Conversion', 'Docker'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "jms1717/8mblocal:v137"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8001}}$JSON$::jsonb, $JSON${"metadata": {"name": "8MB Local", "version": "latest", "description": "8MB Local is a self-hosted file processing and conversion application that provides tools for handling files and generating outputs. Built with modern architecture, 8MB Local offers a web-based interface accessible on port 8001 for processing files and managing uploads and outputs. The system stores uploaded files and generated outputs in separate persistent volumes, ensuring your data is preserved across container restarts. Perfect for individuals and organizations looking for a self-hosted solution for file processing and management.", "category": "file-processing", "tags": ["File Processing", "Self-Hosted", "File Management", "Conversion", "Docker"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "jms1717/8mblocal:v137"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8001}}, "links": [{"label": "Website", "url": "https://8mb.campuscal.tech/"}, {"label": "GitHub", "url": "https://github.com/JMS1717/8mb.local"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "8mblocal", "port": "$PORT:8001", "volumes": ["/app/uploads", "/app/outputs"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('accent', 'Accent', 'Accent is a free and open-source web-based collaboration platform for translation and localization projects. It provides a clean interface for translators to work together on various file formats including JSON, YAML, Properties, Gettext PO, and many more. Accent supports real-time collaboration, version control integration, and automated workflows to streamline the translation process. It features role-based access control, translation memory, and comprehensive reporting tools to help manage translation projects efficiently.', 'self-hosted', ARRAY[]::text[], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "mirego/accent:v1.29.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Accent", "version": "latest", "description": "Accent is a free and open-source web-based collaboration platform for translation and localization projects. It provides a clean interface for translators to work together on various file formats including JSON, YAML, Properties, Gettext PO, and many more. Accent supports real-time collaboration, version control integration, and automated workflows to streamline the translation process. It features role-based access control, translation memory, and comprehensive reporting tools to help manage translation projects efficiently.", "category": "self-hosted", "tags": [], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "mirego/accent:v1.29.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4000}}, "links": [{"label": "Website", "url": "https://www.accent.reviews"}, {"label": "Documentation", "url": "https://www.accent.reviews/guides/getting-started"}, {"label": "GitHub", "url": "https://github.com/mirego/accent"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "accent", "port": "$PORT:4000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('ackee', 'Ackee', 'Ackee is a self-hosted, Node.js based analytics tool designed for those who value privacy. It operates on your own server, analyzing the traffic of your websites and providing valuable statistics through a minimalistic interface. Ackee offers an overview of all your websites, allowing you to analyze their collective performance. It provides insights into views, referrers, durations, and more. You can easily add, edit, and delete your domains, with a new tracking code just a few clicks away. Ackee''s minimal UI allows you to analyze your data without losing focus, and its multi-step anonymization process ensures your users'' privacy. The app allows you to analyze as many domains and apps as you want, and its interface is designed to be fast and easy to navigate. Ackee also offers a centralized GraphQL API, perfect for collecting data from a variety of sources. It uses a multi-step process to keep tracked data anonymized while still providing helpful analytics.', 'analytics', ARRAY['Analytics', 'Privacy'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "electerious/ackee:3.6.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Ackee", "version": "latest", "description": "Ackee is a self-hosted, Node.js based analytics tool designed for those who value privacy. It operates on your own server, analyzing the traffic of your websites and providing valuable statistics through a minimalistic interface. Ackee offers an overview of all your websites, allowing you to analyze their collective performance. It provides insights into views, referrers, durations, and more. You can easily add, edit, and delete your domains, with a new tracking code just a few clicks away. Ackee's minimal UI allows you to analyze your data without losing focus, and its multi-step anonymization process ensures your users' privacy. The app allows you to analyze as many domains and apps as you want, and its interface is designed to be fast and easy to navigate. Ackee also offers a centralized GraphQL API, perfect for collecting data from a variety of sources. It uses a multi-step process to keep tracked data anonymized while still providing helpful analytics.", "category": "analytics", "tags": ["Analytics", "Privacy"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "electerious/ackee:3.6.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://ackee.electerious.com/"}, {"label": "Documentation", "url": "https://docs.ackee.electerious.com/"}, {"label": "Github", "url": "https://github.com/electerious/Ackee"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "ackee", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('activepieces', 'Activepieces', 'Activepieces is a powerful open-source business automation tool designed to streamline your work without the need for coding. It serves as an excellent alternative to Zapier, allowing you to automate your daily tasks or even your entire business with just a few clicks on the user interface. With Activepieces, you can enjoy the flexibility of using our 3rd party no-code apps to quickly read and write to your favorite apps. Currently, we support 74 apps and counting. The tool is self-hosted, ensuring your data remains on your machine, providing an added layer of security. Activepieces also offers infinite flexibility and powerful logging, making it a robust solution for business automation without limits.', 'no-code', ARRAY['No-Code', 'Business Apps', 'Automation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "activepieces/activepieces:0.82.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Activepieces", "version": "latest", "description": "Activepieces is a powerful open-source business automation tool designed to streamline your work without the need for coding. It serves as an excellent alternative to Zapier, allowing you to automate your daily tasks or even your entire business with just a few clicks on the user interface. With Activepieces, you can enjoy the flexibility of using our 3rd party no-code apps to quickly read and write to your favorite apps. Currently, we support 74 apps and counting. The tool is self-hosted, ensuring your data remains on your machine, providing an added layer of security. Activepieces also offers infinite flexibility and powerful logging, making it a robust solution for business automation without limits.", "category": "no-code", "tags": ["No-Code", "Business Apps", "Automation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "activepieces/activepieces:0.82.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://activepieces.com"}, {"label": "Documentation", "url": "https://activepieces.com/docs"}, {"label": "Github", "url": "https://github.com/activepieces/activepieces"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "activepieces", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('actualbudget', 'Actual Budget', 'Actual is a personal finance tool designed to help you manage your finances with ease and convenience. This local-first application is 100% free and open-source, providing you with a reliable platform to keep track of your financial transactions. It''s written in NodeJS and features a synchronization element that allows your changes to seamlessly move between devices. This means you can access and manage your financial data from any device without any hassle. The app is not just about tracking your expenses, it also includes features for budgeting, account management, and generating reports and filters. With Actual, managing your personal finances becomes a breeze.', 'finance', ARRAY['Finance'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/actualbudget/actual-server:26.2.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5006}}$JSON$::jsonb, $JSON${"metadata": {"name": "Actual Budget", "version": "latest", "description": "Actual is a personal finance tool designed to help you manage your finances with ease and convenience. This local-first application is 100% free and open-source, providing you with a reliable platform to keep track of your financial transactions. It's written in NodeJS and features a synchronization element that allows your changes to seamlessly move between devices. This means you can access and manage your financial data from any device without any hassle. The app is not just about tracking your expenses, it also includes features for budgeting, account management, and generating reports and filters. With Actual, managing your personal finances becomes a breeze.", "category": "finance", "tags": ["Finance"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/actualbudget/actual-server:26.2.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5006}}, "links": [{"label": "Github", "url": "https://github.com/actualbudget/actual"}, {"label": "Documentation", "url": "https://actualbudget.github.io/docs"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "actualbudget", "port": "$PORT:5006", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('adguardhome-sync', 'AdGuard Home Sync', 'AdGuard Home Sync is a tool designed to synchronize filters, blocklists, and configuration between multiple AdGuard Home instances. It allows you to maintain consistent filtering across different AdGuard Home deployments by synchronizing configuration from an origin instance to one or more replica instances.', 'adguard-home', ARRAY['AdGuard Home', 'DNS', 'Ad-blocking', 'Synchronization', 'Configuration Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/adguardhome-sync:0.9.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "AdGuard Home Sync", "version": "latest", "description": "AdGuard Home Sync is a tool designed to synchronize filters, blocklists, and configuration between multiple AdGuard Home instances. It allows you to maintain consistent filtering across different AdGuard Home deployments by synchronizing configuration from an origin instance to one or more replica instances.", "category": "adguard-home", "tags": ["AdGuard Home", "DNS", "Ad-blocking", "Synchronization", "Configuration Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/adguardhome-sync:0.9.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Documentation", "url": "https://github.com/bakito/adguardhome-sync/wiki/FAQ"}, {"label": "Github", "url": "https://github.com/bakito/adguardhome-sync"}], "instructions": "Modify the config file to add your own AdGuard Home instances and cron schedule.", "install": [{"docker": {"image": "$IMAGE", "name": "adguardhome-sync", "port": "$PORT:8080", "volumes": ["/config", "/config/adguardhome-sync.yaml"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Modify the config file to add your own AdGuard Home instances and cron schedule."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('adguardhome', 'AdGuard Home', 'AdGuard Ad Blocker is a comprehensive solution designed to enhance your online browsing experience by eliminating all kinds of ads, from annoying banners and pop-ups to intrusive video ads. It not only removes these distractions but also maintains the functionality and appearance of the websites you visit. The app also offers privacy protection, shielding your data from web analytics and online trackers. In addition, AdGuard ensures browsing security by protecting against phishing and malicious sites. It also includes a parental control feature, providing a safe online environment for children by blocking inappropriate and adult content. The app is designed to work across all browsers and apps, offering a seamless ad-free experience. Moreover, it saves traffic and speeds up page loading by filtering ads before they reach your device. AdGuard is more than just an ad blocker; it''s a tool that enhances your online safety and browsing speed.', 'privacy', ARRAY['Privacy', 'Security'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "adguard/adguardhome:v0.107.74"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "AdGuard Home", "version": "latest", "description": "AdGuard Ad Blocker is a comprehensive solution designed to enhance your online browsing experience by eliminating all kinds of ads, from annoying banners and pop-ups to intrusive video ads. It not only removes these distractions but also maintains the functionality and appearance of the websites you visit. The app also offers privacy protection, shielding your data from web analytics and online trackers. In addition, AdGuard ensures browsing security by protecting against phishing and malicious sites. It also includes a parental control feature, providing a safe online environment for children by blocking inappropriate and adult content. The app is designed to work across all browsers and apps, offering a seamless ad-free experience. Moreover, it saves traffic and speeds up page loading by filtering ads before they reach your device. AdGuard is more than just an ad blocker; it's a tool that enhances your online safety and browsing speed.", "category": "privacy", "tags": ["Privacy", "Security"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "adguard/adguardhome:v0.107.74"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://adguard.com"}, {"label": "Github", "url": "https://github.com/AdguardTeam/AdGuardHome"}, {"label": "Docker", "url": "https://hub.docker.com/r/adguard/adguardhome"}], "instructions": "During the setup phase, if the instance, does not start, you have to disable the service using port 53 on your host server, so adguard can bind the port 53. Then setup the admin account on port 3000, then change it to port 80. To use the DHCP feature, you must also open ports 67/udp 68/tcp-udp.", "install": [{"docker": {"image": "$IMAGE", "name": "adguardhome", "port": "$PORT:3000", "volumes": ["/opt/adguardhome/work", "/opt/adguardhome/conf"], "extra_ports": ["53:53", "784:784", "853:853", "5443:5443", "8853:8853"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "During the setup phase, if the instance, does not start, you have to disable the service using port 53 on your host server, so adguard can bind the port 53. Then setup the admin account on port 3000, then change it to port 80. To use the DHCP feature, you must also open ports 67/udp 68/tcp-udp."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('adminer', 'Adminer', 'Adminer is a comprehensive database management tool, designed to simplify and streamline your database operations. Written in PHP, it is a lightweight yet powerful tool that supports a wide range of databases including MySQL, MariaDB, PostgreSQL, SQLite, MS SQL, Oracle, Elasticsearch, MongoDB and others. With Adminer, you can easily connect to a database server using a username and password, select an existing database or create a new one, and manage all aspects of your database including tables, columns, indexes, foreign keys, triggers, views, stored procedures, and functions. It also allows you to execute any SQL command from a text field or a file, and export your database structure, data, views, routines, and databases to SQL or CSV. Adminer prioritizes security, user experience, performance, feature set, and size, making it a reliable and efficient tool for all your database management needs.', 'databases', ARRAY['Databases', 'Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "adminer:5.4.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Adminer", "version": "latest", "description": "Adminer is a comprehensive database management tool, designed to simplify and streamline your database operations. Written in PHP, it is a lightweight yet powerful tool that supports a wide range of databases including MySQL, MariaDB, PostgreSQL, SQLite, MS SQL, Oracle, Elasticsearch, MongoDB and others. With Adminer, you can easily connect to a database server using a username and password, select an existing database or create a new one, and manage all aspects of your database including tables, columns, indexes, foreign keys, triggers, views, stored procedures, and functions. It also allows you to execute any SQL command from a text field or a file, and export your database structure, data, views, routines, and databases to SQL or CSV. Adminer prioritizes security, user experience, performance, feature set, and size, making it a reliable and efficient tool for all your database management needs.", "category": "databases", "tags": ["Databases", "Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "adminer:5.4.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Website", "url": "https://www.adminer.org/"}, {"label": "Github", "url": "https://github.com/vrana/adminer/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "adminer", "port": "$PORT:8080", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('adventurelog', 'AdventureLog', 'AdventureLog is a comprehensive travel tracking and adventure logging application that helps you document and organize your journeys around the world. Built with modern web technologies and PostGIS for geographic data management, it allows you to record your adventures, track visited locations, and create a visual map of your travels. The application features a clean, intuitive interface for logging trips, storing photos and memories, and analyzing your travel patterns. With support for geographic data through PostGIS, you can visualize your adventures on interactive maps and maintain a complete history of your explorations. Perfect for travelers, adventurers, and anyone who wants to keep a detailed record of their journeys.', 'travel', ARRAY['Travel', 'Logging', 'Geographic', 'Maps', 'PostGIS', 'Self-Hosted', 'Adventure', 'Documentation', 'Media Storage'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/seanmorley15/adventurelog-frontend:v0.12.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5000}}$JSON$::jsonb, $JSON${"metadata": {"name": "AdventureLog", "version": "latest", "description": "AdventureLog is a comprehensive travel tracking and adventure logging application that helps you document and organize your journeys around the world. Built with modern web technologies and PostGIS for geographic data management, it allows you to record your adventures, track visited locations, and create a visual map of your travels. The application features a clean, intuitive interface for logging trips, storing photos and memories, and analyzing your travel patterns. With support for geographic data through PostGIS, you can visualize your adventures on interactive maps and maintain a complete history of your explorations. Perfect for travelers, adventurers, and anyone who wants to keep a detailed record of their journeys.", "category": "travel", "tags": ["Travel", "Logging", "Geographic", "Maps", "PostGIS", "Self-Hosted", "Adventure", "Documentation", "Media Storage"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/seanmorley15/adventurelog-frontend:v0.12.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5000}}, "links": [{"label": "GitHub Frontend", "url": "https://github.com/seanmorley15/adventurelog-frontend"}, {"label": "GitHub Backend", "url": "https://github.com/seanmorley15/adventurelog-backend"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "adventurelog", "port": "$PORT:5000", "volumes": ["/code/media"], "extra_ports": ["8080:8080"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('affinepro', 'Affine', 'Affine is a modern, self-hosted platform designed for collaborative content creation and project management. It offers an intuitive interface, seamless real-time collaboration, and powerful tools for organizing tasks, notes, and ideas. With Affine, you can centralize your workflows and enhance productivity. The platform features a comprehensive workspace that combines note-taking, task management, and project planning in one unified environment.', 'collaboration', ARRAY['Collaboration', 'Self-Hosted', 'Productivity', 'Project Management', 'PostgreSQL', 'Vector Search'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/toeverything/affine:0.26.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3010}}$JSON$::jsonb, $JSON${"metadata": {"name": "Affine", "version": "latest", "description": "Affine is a modern, self-hosted platform designed for collaborative content creation and project management. It offers an intuitive interface, seamless real-time collaboration, and powerful tools for organizing tasks, notes, and ideas. With Affine, you can centralize your workflows and enhance productivity. The platform features a comprehensive workspace that combines note-taking, task management, and project planning in one unified environment.", "category": "collaboration", "tags": ["Collaboration", "Self-Hosted", "Productivity", "Project Management", "PostgreSQL", "Vector Search"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/toeverything/affine:0.26.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3010}}, "links": [{"label": "Website", "url": "https://affine.pro"}, {"label": "Documentation", "url": "https://affine.pro/docs"}, {"label": "Github", "url": "https://github.com/toeverything/Affine"}], "instructions": "The migration service runs automatically during deployment to set up the database schema. It can be safely removed once the process is complete.", "install": [{"docker": {"image": "$IMAGE", "name": "affinepro", "port": "$PORT:3010", "volumes": ["/root/.affine/storage", "/root/.affine/config", "/root/.affine/storage", "/root/.affine/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "The migration service runs automatically during deployment to set up the database schema. It can be safely removed once the process is complete."}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('airsonic-advanced', 'Airsonic Advanced', 'Airsonic Advanced is a more modern implementation of the Airsonic fork with several key performance and feature enhancements. It''s a free, web-based media streamer providing ubiquitous access to your music. Use it to share your music with friends, or to listen to your own music while at work. You can stream to multiple players simultaneously, for instance to one player in your kitchen and another in your living room. It supports very large music collections and works with any audio or video format that can stream over HTTP.', 'music-streaming', ARRAY['Music Streaming', 'Media Server', 'Self-hosted', 'Airsonic', 'Audio', 'Video', 'Podcast', 'Sonos', 'Chromecast', 'DLNA'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "airsonicadvanced/airsonic-advanced:gitcommit-68d11bfbfe051b0acaca2770c3c1f47f8d59201c"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4040}}$JSON$::jsonb, $JSON${"metadata": {"name": "Airsonic Advanced", "version": "latest", "description": "Airsonic Advanced is a more modern implementation of the Airsonic fork with several key performance and feature enhancements. It's a free, web-based media streamer providing ubiquitous access to your music. Use it to share your music with friends, or to listen to your own music while at work. You can stream to multiple players simultaneously, for instance to one player in your kitchen and another in your living room. It supports very large music collections and works with any audio or video format that can stream over HTTP.", "category": "music-streaming", "tags": ["Music Streaming", "Media Server", "Self-hosted", "Airsonic", "Audio", "Video", "Podcast", "Sonos", "Chromecast", "DLNA"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "airsonicadvanced/airsonic-advanced:gitcommit-68d11bfbfe051b0acaca2770c3c1f47f8d59201c"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4040}}, "links": [{"label": "GitHub", "url": "https://github.com/airsonic-advanced/airsonic-advanced"}, {"label": "Documentation", "url": "https://github.com/airsonic-advanced/airsonic-advanced#readme"}, {"label": "Demo", "url": "https://airsonic.github.io/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "airsonic-advanced", "port": "$PORT:4040", "volumes": ["/var/playlists", "/var/podcasts", "/var/airsonic", "/var/music"], "extra_ports": ["4041:4041"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
