INSERT INTO recipes VALUES ('alerta', 'Alerta', 'Alerta is a monitoring system that consolidates and deduplicates alerts from multiple monitoring systems.', 'monitoring', ARRAY['Monitoring', 'Alert Management', 'Web Application', 'PostgreSQL', 'API'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "alerta/alerta-web:9.1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Alerta", "version": "latest", "description": "Alerta is a monitoring system that consolidates and deduplicates alerts from multiple monitoring systems.", "category": "monitoring", "tags": ["Monitoring", "Alert Management", "Web Application", "PostgreSQL", "API"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "alerta/alerta-web:9.1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Website", "url": "https://alerta.io/"}, {"label": "Github", "url": "https://github.com/alerta/alerta"}, {"label": "Documentation", "url": "https://docs.alerta.io/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "alerta", "port": "$PORT:8080", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('alltube', 'AllTube', 'AllTube Download is an application designed to facilitate the downloading of videos from YouTube. It provides an HTML GUI for youtube-dl, a command-line program to download videos from YouTube and other video sites. The app allows users to download videos directly to their server, making it easy to access and manage their favorite content. AllTube supports various configurations and can be customized according to user preferences. It also offers a JSON API, which returns a JSON object generated by youtube-dl, providing detailed information about the video. The app is lightweight and efficient, making it a great choice for those who frequently download videos from YouTube.', 'media', ARRAY['Media', 'Video', 'Downloader'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "dnomd343/alltube:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 24488}}$JSON$::jsonb, $JSON${"metadata": {"name": "AllTube", "version": "latest", "description": "AllTube Download is an application designed to facilitate the downloading of videos from YouTube. It provides an HTML GUI for youtube-dl, a command-line program to download videos from YouTube and other video sites. The app allows users to download videos directly to their server, making it easy to access and manage their favorite content. AllTube supports various configurations and can be customized according to user preferences. It also offers a JSON API, which returns a JSON object generated by youtube-dl, providing detailed information about the video. The app is lightweight and efficient, making it a great choice for those who frequently download videos from YouTube.", "category": "media", "tags": ["Media", "Video", "Downloader"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "dnomd343/alltube:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 24488}}, "links": [{"label": "Github", "url": "https://github.com/Rudloff/alltube"}, {"label": "Docker", "url": "https://hub.docker.com/r/dnomd343/alltube"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "alltube", "port": "$PORT:24488", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('altus', 'Altus', 'Altus is a desktop application that brings WhatsApp Web to your desktop with additional features and customization options. It provides a clean, native desktop experience for WhatsApp Web, with support for multiple accounts, themes, and enhanced functionality beyond the standard web interface.', 'messaging', ARRAY['Messaging', 'WhatsApp', 'Desktop App', 'Communication'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/altus:5.7.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Altus", "version": "latest", "description": "Altus is a desktop application that brings WhatsApp Web to your desktop with additional features and customization options. It provides a clean, native desktop experience for WhatsApp Web, with support for multiple accounts, themes, and enhanced functionality beyond the standard web interface.", "category": "messaging", "tags": ["Messaging", "WhatsApp", "Desktop App", "Communication"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/altus:5.7.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Documentation", "url": "https://docs.linuxserver.io/images/docker-altus/"}, {"label": "Github", "url": "https://github.com/linuxserver/docker-altus"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "altus", "port": "$PORT:3000", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('ampache', 'Ampache', 'Ampache is a web-based audio/video streaming application and file manager that allows you to access your music and videos from anywhere, anytime. With this app, you can browse and manage your music collection through a simple web interface, and even synchronize local and remote catalogs to create a unique, consistent collection. Ampache also offers music streaming capabilities, allowing you to stream your music to your preferred player, control it with Localplay, or directly listen on the web page with the HTML5 player. The app is completely free and open source, and it''s designed to work on almost any internet-enabled device, including your phone, tablet, or television. Ampache is not a media organizer, but a tool that presents an already organized collection in a useful way.', 'media', ARRAY['Media', 'File Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ampache/ampache:7.9.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Ampache", "version": "latest", "description": "Ampache is a web-based audio/video streaming application and file manager that allows you to access your music and videos from anywhere, anytime. With this app, you can browse and manage your music collection through a simple web interface, and even synchronize local and remote catalogs to create a unique, consistent collection. Ampache also offers music streaming capabilities, allowing you to stream your music to your preferred player, control it with Localplay, or directly listen on the web page with the HTML5 player. The app is completely free and open source, and it's designed to work on almost any internet-enabled device, including your phone, tablet, or television. Ampache is not a media organizer, but a tool that presents an already organized collection in a useful way.", "category": "media", "tags": ["Media", "File Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ampache/ampache:7.9.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "http://ampache.org/"}, {"label": "Github", "url": "https://github.com/ampache/ampache"}, {"label": "Github Docker", "url": "https://github.com/ampache/ampache-docker"}, {"label": "DockerHub", "url": "https://hub.docker.com/r/ampache/ampache"}], "instructions": "MySQL Username is \"admin\". The logs will show a line that says \"mysql -uadmin -pjnzYXLz7cMzq -h<host> -P<port>\"\". The password is everything after \"-p\", in this case \"jnzYXLz7cMzq\".", "install": [{"docker": {"image": "$IMAGE", "name": "ampache", "port": "$PORT:80", "volumes": ["/var/www/config", "/var/log/ampache", "/var/lib/mysql", "/media"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "MySQL Username is \"admin\". The logs will show a line that says \"mysql -uadmin -pjnzYXLz7cMzq -h<host> -P<port>\"\". The password is everything after \"-p\", in this case \"jnzYXLz7cMzq\"."}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('anchor', 'Anchor', 'Anchor is a self-hosted application designed to provide a modern web interface for managing and organizing your data. It offers a clean, intuitive user experience with persistent storage capabilities, ensuring your data is safely stored and accessible. Built with privacy and self-hosting in mind, Anchor gives you complete control over your information without relying on external cloud services.', 'self-hosted', ARRAY['Self-Hosted', 'Web Application', 'Data Management', 'Privacy'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/zhfahim/anchor:0.10"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Anchor", "version": "latest", "description": "Anchor is a self-hosted application designed to provide a modern web interface for managing and organizing your data. It offers a clean, intuitive user experience with persistent storage capabilities, ensuring your data is safely stored and accessible. Built with privacy and self-hosting in mind, Anchor gives you complete control over your information without relying on external cloud services.", "category": "self-hosted", "tags": ["Self-Hosted", "Web Application", "Data Management", "Privacy"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/zhfahim/anchor:0.10"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "GitHub", "url": "https://github.com/zhfahim/anchor"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "anchor", "port": "$PORT:3000", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('anonupload', 'AnonUpload', 'AnonUpload is a secure, anonymous file sharing application that does not require a database. It is built with privacy as a priority, ensuring that the direct filename used is not displayed. This PHP file uploader is designed to work anywhere, be it Nginx, Apache, Lightspeed, or any other platform. AnonUpload supports a wide range of file types including jpeg, jpg, gif, png, zip, xls, doc, mp3, mp4, mpeg, wav, avi, rar, 7z, txt and more. It also provides size verification for uploaded files, allowing for a maximum upload size of 10GB and no minimum size. The application also includes a download time feature, which sets a waiting time before a file can be downloaded.', 'file-management', ARRAY['File Management', 'Privacy'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/supernova3339/anonfiles:1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "AnonUpload", "version": "latest", "description": "AnonUpload is a secure, anonymous file sharing application that does not require a database. It is built with privacy as a priority, ensuring that the direct filename used is not displayed. This PHP file uploader is designed to work anywhere, be it Nginx, Apache, Lightspeed, or any other platform. AnonUpload supports a wide range of file types including jpeg, jpg, gif, png, zip, xls, doc, mp3, mp4, mpeg, wav, avi, rar, 7z, txt and more. It also provides size verification for uploaded files, allowing for a maximum upload size of 10GB and no minimum size. The application also includes a download time feature, which sets a waiting time before a file can be downloaded.", "category": "file-management", "tags": ["File Management", "Privacy"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/supernova3339/anonfiles:1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Github", "url": "https://github.com/supernova3339/anonupload"}, {"label": "Enviroment Variables", "url": "https://github.com/Supernova3339/anonupload/blob/main/env.md"}], "instructions": "visit /admin for the administration interface", "install": [{"docker": {"image": "$IMAGE", "name": "anonupload", "port": "$PORT:80", "volumes": ["/var/www/html/files"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "visit /admin for the administration interface"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('anonymousoverflow', 'AnonymousOverflow', 'AnonymousOverflow is an anonymous question and answer platform inspired by Stack Overflow, designed for creating a safe space where users can ask questions without revealing their identity. The platform provides a community-driven Q&A experience with features like upvoting, downvoting, question categorization, and answer moderation. Built with privacy in mind, AnonymousOverflow allows users to participate in discussions and share knowledge while maintaining complete anonymity. Perfect for organizations wanting to create internal Q&A forums, educational institutions seeking anonymous student feedback platforms, or communities that value privacy in knowledge sharing.', 'q&a', ARRAY['Q&A', 'Forum', 'Anonymous', 'Community', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/httpjamesm/anonymousoverflow:release"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "AnonymousOverflow", "version": "latest", "description": "AnonymousOverflow is an anonymous question and answer platform inspired by Stack Overflow, designed for creating a safe space where users can ask questions without revealing their identity. The platform provides a community-driven Q&A experience with features like upvoting, downvoting, question categorization, and answer moderation. Built with privacy in mind, AnonymousOverflow allows users to participate in discussions and share knowledge while maintaining complete anonymity. Perfect for organizations wanting to create internal Q&A forums, educational institutions seeking anonymous student feedback platforms, or communities that value privacy in knowledge sharing.", "category": "q&a", "tags": ["Q&A", "Forum", "Anonymous", "Community", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/httpjamesm/anonymousoverflow:release"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "GitHub", "url": "https://github.com/httpjamesm/anonymousoverflow"}, {"label": "Demo", "url": "https://aohub.httpjames.space"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "anonymousoverflow", "port": "$PORT:8080", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('anse', 'Anse', 'Anse is a modern web application that provides a clean and intuitive interface. It''s a lightweight and efficient solution for your needs.', 'web-application', ARRAY['Web Application', 'UI'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ddiu8081/anse:v1.1.11"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Anse", "version": "latest", "description": "Anse is a modern web application that provides a clean and intuitive interface. It's a lightweight and efficient solution for your needs.", "category": "web-application", "tags": ["Web Application", "UI"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ddiu8081/anse:v1.1.11"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://anse.app"}, {"label": "Github", "url": "https://github.com/ddiu8081/anse"}, {"label": "Documentation", "url": "https://docs.anse.app"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "anse", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('answer', 'Answer', 'Answer is an open-source knowledge-based software designed to facilitate a Q&A environment for your products, customers, teams, and more. It allows users to ask questions and get answers, fostering a dynamic exchange of information. The app features a modern and responsive UI, and it''s extensible with plugins. It also offers content organization capabilities, allowing you to categorize and tag your content for easy navigation. Additionally, Answer integrates with your existing tools and services to streamline your workflow. The app also incorporates gamification elements, rewarding users for their contributions, making the process of knowledge sharing more engaging. It''s a powerful tool for product technical support, customer support, and user communication.', 'community', ARRAY['Community', 'Q&A', 'Knowledge Base', 'Support'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "answerdev/answer:1.2.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Answer", "version": "latest", "description": "Answer is an open-source knowledge-based software designed to facilitate a Q&A environment for your products, customers, teams, and more. It allows users to ask questions and get answers, fostering a dynamic exchange of information. The app features a modern and responsive UI, and it's extensible with plugins. It also offers content organization capabilities, allowing you to categorize and tag your content for easy navigation. Additionally, Answer integrates with your existing tools and services to streamline your workflow. The app also incorporates gamification elements, rewarding users for their contributions, making the process of knowledge sharing more engaging. It's a powerful tool for product technical support, customer support, and user communication.", "category": "community", "tags": ["Community", "Q&A", "Knowledge Base", "Support"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "answerdev/answer:1.2.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Documentation", "url": "https://answer.dev/docs"}, {"label": "Github", "url": "https://github.com/answerdev/answer"}, {"label": "Website", "url": "https://answer.dev/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "answer", "port": "$PORT:80", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('anythingllm', 'Anything-LLM', 'Anything-LLM is an open-source, AI-powered platform that enables users to leverage Large Language Models (LLMs) for creating, managing, and querying custom knowledge bases. It provides seamless integration with OpenAI services, offering a robust, flexible, and extensible environment for LLM-driven applications. Ideal for developers and organizations, Anything-LLM streamlines the deployment of intelligent AI solutions.', 'large-language-models', ARRAY['Large Language Models', 'Knowledge Base', 'OpenAI Integration', 'Customizable', 'Open Source', 'AI-Powered'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "mintplexlabs/anythingllm:1.12"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3001}}$JSON$::jsonb, $JSON${"metadata": {"name": "Anything-LLM", "version": "latest", "description": "Anything-LLM is an open-source, AI-powered platform that enables users to leverage Large Language Models (LLMs) for creating, managing, and querying custom knowledge bases. It provides seamless integration with OpenAI services, offering a robust, flexible, and extensible environment for LLM-driven applications. Ideal for developers and organizations, Anything-LLM streamlines the deployment of intelligent AI solutions.", "category": "large-language-models", "tags": ["Large Language Models", "Knowledge Base", "OpenAI Integration", "Customizable", "Open Source", "AI-Powered"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "mintplexlabs/anythingllm:1.12"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3001}}, "links": [{"label": "Website", "url": "https://anythingllm.com/"}, {"label": "Compose Docs", "url": "https://docs.anythingllm.com/installation-docker/local-docker"}, {"label": "Documentation", "url": "https://docs.anythingllm.com/"}, {"label": "Github", "url": "https://github.com/mintplex-labs/anything-llm"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "anythingllm", "port": "$PORT:3001", "volumes": ["/app/server/storage"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('apache-superset', 'Apache Superset', 'Apache Superset is a modern, enterprise-ready business intelligence web application. It''s fast, lightweight, intuitive, and loaded with options that make it easy for users of all skill sets to explore and visualize their data, from simple line charts to highly detailed geospatial charts.', 'business-intelligence', ARRAY['Business Intelligence', 'Data Visualization', 'Analytics', 'Dashboard', 'SQL'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "apache/superset:6.0.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8088}}$JSON$::jsonb, $JSON${"metadata": {"name": "Apache Superset", "version": "latest", "description": "Apache Superset is a modern, enterprise-ready business intelligence web application. It's fast, lightweight, intuitive, and loaded with options that make it easy for users of all skill sets to explore and visualize their data, from simple line charts to highly detailed geospatial charts.", "category": "business-intelligence", "tags": ["Business Intelligence", "Data Visualization", "Analytics", "Dashboard", "SQL"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "apache/superset:6.0.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8088}}, "links": [{"label": "Github", "url": "https://github.com/apache/superset"}, {"label": "Documentation", "url": "https://superset.apache.org/docs/intro"}, {"label": "Guide", "url": "https://www.restack.io/docs/superset-knowledge-apache-superset-default-login"}], "instructions": "Migrate database with \"superset db upgrade\", adjust roles and permissions with \"superset init\", create admin user with \"superset fab create-admin\". Follow the guide for further references.", "install": [{"docker": {"image": "$IMAGE", "name": "apache-superset", "port": "$PORT:8088", "volumes": ["/app/superset_home"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Migrate database with \"superset db upgrade\", adjust roles and permissions with \"superset init\", create admin user with \"superset fab create-admin\". Follow the guide for further references."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('apprise-api', 'Apprise-API', 'Apprise-API is an open-source notification gateway that provides a unified and straightforward way to send notifications to a variety of services, including email, SMS, chat apps, and more. It supports dozens of platforms out of the box, making it an ideal solution for developers and organizations seeking a robust, flexible, and extensible notification system. With a lightweight and API-driven design, Apprise-API simplifies integration into any project.', 'notifications', ARRAY['Notifications', 'Open Source', 'API', 'Email', 'SMS', 'Chat Apps'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/apprise-api:1.4.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Apprise-API", "version": "latest", "description": "Apprise-API is an open-source notification gateway that provides a unified and straightforward way to send notifications to a variety of services, including email, SMS, chat apps, and more. It supports dozens of platforms out of the box, making it an ideal solution for developers and organizations seeking a robust, flexible, and extensible notification system. With a lightweight and API-driven design, Apprise-API simplifies integration into any project.", "category": "notifications", "tags": ["Notifications", "Open Source", "API", "Email", "SMS", "Chat Apps"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/apprise-api:1.4.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}, "links": [{"label": "Github", "url": "https://github.com/caronc/apprise-api"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "apprise-api", "port": "$PORT:8000", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('appsmith', 'Appsmith', 'Appsmith is a powerful tool designed to help engineers build custom software on top of their data. It simplifies internal tool development for businesses, streamlining operations, automating processes, and integrating multiple apps and data sources. Appsmith allows you to quickly build, deploy, and share applications that run critical business operations. It features intent-based auto-layouts for building responsive apps faster and offers a drag-and-drop interface for creating beautiful UIs without writing a single line of HTML/CSS. You can connect to any database, SaaS tool, or GraphQL/REST API, and query your data directly using SQL or the built-in query builder. Appsmith also provides the ability to write in-line JavaScript or reusable code blocks to extend your app''s functionality, customize your UI, or write conditional logic. It''s a secure, open-source platform that can be self-hosted for total control, privacy, and security.', 'developer-tools', ARRAY['Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "appsmith/appsmith-ce:v1.99"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Appsmith", "version": "latest", "description": "Appsmith is a powerful tool designed to help engineers build custom software on top of their data. It simplifies internal tool development for businesses, streamlining operations, automating processes, and integrating multiple apps and data sources. Appsmith allows you to quickly build, deploy, and share applications that run critical business operations. It features intent-based auto-layouts for building responsive apps faster and offers a drag-and-drop interface for creating beautiful UIs without writing a single line of HTML/CSS. You can connect to any database, SaaS tool, or GraphQL/REST API, and query your data directly using SQL or the built-in query builder. Appsmith also provides the ability to write in-line JavaScript or reusable code blocks to extend your app's functionality, customize your UI, or write conditional logic. It's a secure, open-source platform that can be self-hosted for total control, privacy, and security.", "category": "developer-tools", "tags": ["Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "appsmith/appsmith-ce:v1.99"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://www.appsmith.com/"}, {"label": "Documentation", "url": "https://docs.appsmith.com/"}, {"label": "Github", "url": "https://github.com/appsmithorg/appsmith"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "appsmith", "port": "$PORT:80", "volumes": ["/appsmith-stacks"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('appwrite', 'Appwrite', 'Appwrite is an open-source backend as a service server that abstracts and simplifies complex and repetitive development tasks behind a very simple to use REST API.', 'self-hosted', ARRAY[]::text[], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Appwrite", "version": "latest", "description": "Appwrite is an open-source backend as a service server that abstracts and simplifies complex and repetitive development tasks behind a very simple to use REST API.", "category": "self-hosted", "tags": [], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://appwrite.io"}, {"label": "Documentation", "url": "https://appwrite.io/docs"}, {"label": "Github", "url": "https://github.com/appwrite/appwrite"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "appwrite", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('aptabase', 'Aptabase', 'Aptabase is an open-source, privacy-focused analytics platform for mobile and desktop applications. It provides real-time analytics, crash reporting, and user insights while respecting user privacy.', 'analytics', ARRAY['Analytics', 'Privacy', 'Monitoring', 'Self-hosted', 'Open Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/aptabase/aptabase:main"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Aptabase", "version": "latest", "description": "Aptabase is an open-source, privacy-focused analytics platform for mobile and desktop applications. It provides real-time analytics, crash reporting, and user insights while respecting user privacy.", "category": "analytics", "tags": ["Analytics", "Privacy", "Monitoring", "Self-hosted", "Open Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/aptabase/aptabase:main"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Website", "url": "https://aptabase.com"}, {"label": "Documentation", "url": "https://aptabase.com/docs"}, {"label": "GitHub", "url": "https://github.com/aptabase/aptabase"}], "instructions": "Sign up and open the console logs where it will print the link to authorize the email. Copy the URL part that looks like this. [url, https://your-domain/api/_auth/continue?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ0eXBlIjoiU2lnbkluIiwibmFtZSI6IkFoc29uIFNoYWlraCIsImVtYWlsIjoiYWhzb25zaGFpa2g2MTZAZ21haWwuY29tIiwibmJmIjoxNzQ0MTE5MDgyLCJleHAiOjE3NDQxMTk5ODIsImlhdCI6MTc0NDExOTA4MiwiaXNzIjoiYXB0YWJhc2Utc2gifQ.PxbVTiVOXsTkkxQKV1AOGaaEpLnMOOtgSRMqDY6dkIg]\\u0027. Do not copy this part at the end ]\\u0027", "install": [{"docker": {"image": "$IMAGE", "name": "aptabase", "port": "$PORT:8080", "volumes": ["/var/lib/clickhouse"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Sign up and open the console logs where it will print the link to authorize the email. Copy the URL part that looks like this. [url, https://your-domain/api/_auth/continue?token=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ0eXBlIjoiU2lnbkluIiwibmFtZSI6IkFoc29uIFNoYWlraCIsImVtYWlsIjoiYWhzb25zaGFpa2g2MTZAZ21haWwuY29tIiwibmJmIjoxNzQ0MTE5MDgyLCJleHAiOjE3NDQxMTk5ODIsImlhdCI6MTc0NDExOTA4MiwiaXNzIjoiYXB0YWJhc2Utc2gifQ.PxbVTiVOXsTkkxQKV1AOGaaEpLnMOOtgSRMqDY6dkIg]\\u0027. Do not copy this part at the end ]\\u0027"}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('arangodb', 'ArangoDB', 'ArangoDB is a multi-model NoSQL database system that supports graph, document, and key-value data models. It is designed for scalability, high availability, and flexibility, making it suitable for a wide range of applications, from simple document storage to complex graph processing. ArangoDB offers a native query language (AQL), full-text search capabilities, a built-in HTTP API, and a web-based UI for management. It also provides features like replication, sharding, and ACID transactions to ensure data integrity and performance. With its integrated search engine and support for multi-tenancy, ArangoDB is an ideal choice for both small projects and enterprise-level applications.', 'database', ARRAY['Database', 'NoSQL', 'Graph Database', 'Document Store', 'Key-Value Store'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "arangodb:3.12.9.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8529}}$JSON$::jsonb, $JSON${"metadata": {"name": "ArangoDB", "version": "latest", "description": "ArangoDB is a multi-model NoSQL database system that supports graph, document, and key-value data models. It is designed for scalability, high availability, and flexibility, making it suitable for a wide range of applications, from simple document storage to complex graph processing. ArangoDB offers a native query language (AQL), full-text search capabilities, a built-in HTTP API, and a web-based UI for management. It also provides features like replication, sharding, and ACID transactions to ensure data integrity and performance. With its integrated search engine and support for multi-tenancy, ArangoDB is an ideal choice for both small projects and enterprise-level applications.", "category": "database", "tags": ["Database", "NoSQL", "Graph Database", "Document Store", "Key-Value Store"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "arangodb:3.12.9.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8529}}, "links": [{"label": "Documentation", "url": "https://www.arangodb.com/docs/stable/"}, {"label": "Github", "url": "https://github.com/arangodb/arangodb"}], "instructions": "Login using username; root and password specified in the envs.", "install": [{"docker": {"image": "$IMAGE", "name": "arangodb", "port": "$PORT:8529", "volumes": ["/var/lib/arangodb3"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Login using username; root and password specified in the envs."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('arcadedb', 'ArcadeDB', 'ArcadeDB is a multi-model database that supports multiple data models including Document, Graph, Key-Value, and Vector databases in a single engine. It''s designed for high-performance applications with ACID transactions and real-time analytics capabilities.', 'database', ARRAY['Database', 'Multi-Model', 'Document', 'Graph', 'Key-Value', 'Vector', 'NoSQL', 'ACID', 'Analytics'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "arcadedata/arcadedb:26.4.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 2424}}$JSON$::jsonb, $JSON${"metadata": {"name": "ArcadeDB", "version": "latest", "description": "ArcadeDB is a multi-model database that supports multiple data models including Document, Graph, Key-Value, and Vector databases in a single engine. It's designed for high-performance applications with ACID transactions and real-time analytics capabilities.", "category": "database", "tags": ["Database", "Multi-Model", "Document", "Graph", "Key-Value", "Vector", "NoSQL", "ACID", "Analytics"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "arcadedata/arcadedb:26.4.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 2424}}, "links": [{"label": "Website", "url": "https://arcadedb.com/"}, {"label": "Documentation", "url": "https://docs.arcadedb.com/"}, {"label": "Github", "url": "https://github.com/ArcadeData/arcadedb"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "arcadedb", "port": "$PORT:2424", "volumes": ["/data"], "extra_ports": ["2480:2480"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('archivebox', 'ArchiveBox', 'ArchiveBox is a self-hosted open-source internet archiving solution that allows you to save and browse webpages offline. It enables users to store full snapshots of web pages, including HTML, media, PDFs, and more, preserving them for future reference. ArchiveBox supports various input formats such as bookmarks, RSS feeds, and browser history, making it easy to automate and manage archiving tasks. The web interface provides a structured way to browse archived content, perform full-text searches, and organize saved snapshots efficiently. Additionally, it offers integrations with other tools, supports multiple storage backends, and provides API access for advanced automation.', 'archiving', ARRAY['Archiving', 'Web Scraping', 'Productivity', 'Research'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "archivebox/archivebox:0.7.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}$JSON$::jsonb, $JSON${"metadata": {"name": "ArchiveBox", "version": "latest", "description": "ArchiveBox is a self-hosted open-source internet archiving solution that allows you to save and browse webpages offline. It enables users to store full snapshots of web pages, including HTML, media, PDFs, and more, preserving them for future reference. ArchiveBox supports various input formats such as bookmarks, RSS feeds, and browser history, making it easy to automate and manage archiving tasks. The web interface provides a structured way to browse archived content, perform full-text searches, and organize saved snapshots efficiently. Additionally, it offers integrations with other tools, supports multiple storage backends, and provides API access for advanced automation.", "category": "archiving", "tags": ["Archiving", "Web Scraping", "Productivity", "Research"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "archivebox/archivebox:0.7.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}, "links": [{"label": "Documentation", "url": "https://github.com/ArchiveBox/ArchiveBox/wiki"}, {"label": "Github", "url": "https://github.com/ArchiveBox/ArchiveBox"}], "instructions": "To create superuser, take the console, and do \"su archivebox && archivebox manage createsuperuser\"", "install": [{"docker": {"image": "$IMAGE", "name": "archivebox", "port": "$PORT:8000", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "To create superuser, take the console, and do \"su archivebox && archivebox manage createsuperuser\""}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('argilla', 'Argilla', 'Argilla is a robust platform designed to help engineers and data scientists streamline the management of machine learning data workflows. It simplifies tasks like data labeling, annotation, and quality control, making it easier for businesses to build and maintain high-quality datasets for AI and machine learning projects. Argilla supports efficient collaboration, integrates seamlessly with popular ML frameworks, and provides a user-friendly interface for creating structured datasets. Its open-source nature ensures transparency, flexibility, and the ability to self-host for maximum control over your data and workflows.', 'machine-learning', ARRAY['Machine Learning', 'Data Labeling', 'AI Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "argilla/argilla-server:v2.8.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 6900}}$JSON$::jsonb, $JSON${"metadata": {"name": "Argilla", "version": "latest", "description": "Argilla is a robust platform designed to help engineers and data scientists streamline the management of machine learning data workflows. It simplifies tasks like data labeling, annotation, and quality control, making it easier for businesses to build and maintain high-quality datasets for AI and machine learning projects. Argilla supports efficient collaboration, integrates seamlessly with popular ML frameworks, and provides a user-friendly interface for creating structured datasets. Its open-source nature ensures transparency, flexibility, and the ability to self-host for maximum control over your data and workflows.", "category": "machine-learning", "tags": ["Machine Learning", "Data Labeling", "AI Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "argilla/argilla-server:v2.8.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 6900}}, "links": [{"label": "Website", "url": "https://www.argilla.io/"}, {"label": "Documentation", "url": "https://docs.argilla.io/"}, {"label": "Github", "url": "https://github.com/argilla-io/argilla"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "argilla", "port": "$PORT:6900", "volumes": ["/var/lib/argilla", "/var/lib/argilla", "/usr/share/elasticsearch/data/"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('ariang', 'AriaNg', 'AriaNg is a modern web frontend for aria2, a lightweight multi-protocol & multi-source command-line download utility. It provides a beautiful web interface for managing downloads.', 'download-manager', ARRAY['Download Manager', 'File Transfer', 'Self-hosted', 'Open Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "hurlenko/aria2-ariang:1.3.13"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "AriaNg", "version": "latest", "description": "AriaNg is a modern web frontend for aria2, a lightweight multi-protocol & multi-source command-line download utility. It provides a beautiful web interface for managing downloads.", "category": "download-manager", "tags": ["Download Manager", "File Transfer", "Self-hosted", "Open Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "hurlenko/aria2-ariang:1.3.13"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Website", "url": "https://ariang.mayswind.net"}, {"label": "GitHub", "url": "https://github.com/mayswind/AriaNg"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/hurlenko/aria2-ariang"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "ariang", "port": "$PORT:8080", "volumes": ["/aria2/data", "/aria2/conf"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('astuto', 'Astuto', 'Astuto is a self-hosted customer feedback management platform that helps teams collect, organize, and respond to customer feedback in one centralized location. Built with modern web technologies, Astuto provides a clean and intuitive interface for managing feature requests, bug reports, and customer suggestions. The application enables teams to create public or private feedback boards where customers can submit ideas, vote on features, and track the status of their requests. With built-in categorization, tagging, and status tracking, Astuto helps product teams prioritize development work based on customer demand. The platform supports multiple boards, user authentication, and integration capabilities to streamline the feedback collection process. Perfect for product teams managing customer feedback, startups building customer-driven products, SaaS companies wanting to engage with their user base, or any organization that wants to centralize and manage customer input effectively.', 'customer-feedback', ARRAY['Customer Feedback', 'Product Management', 'Self-Hosted', 'Feedback Management', 'Feature Requests'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "riggraz/astuto:ac6ad92f7ec3f2961c37f17fb090c1fe4184f194"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Astuto", "version": "latest", "description": "Astuto is a self-hosted customer feedback management platform that helps teams collect, organize, and respond to customer feedback in one centralized location. Built with modern web technologies, Astuto provides a clean and intuitive interface for managing feature requests, bug reports, and customer suggestions. The application enables teams to create public or private feedback boards where customers can submit ideas, vote on features, and track the status of their requests. With built-in categorization, tagging, and status tracking, Astuto helps product teams prioritize development work based on customer demand. The platform supports multiple boards, user authentication, and integration capabilities to streamline the feedback collection process. Perfect for product teams managing customer feedback, startups building customer-driven products, SaaS companies wanting to engage with their user base, or any organization that wants to centralize and manage customer input effectively.", "category": "customer-feedback", "tags": ["Customer Feedback", "Product Management", "Self-Hosted", "Feedback Management", "Feature Requests"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "riggraz/astuto:ac6ad92f7ec3f2961c37f17fb090c1fe4184f194"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "GitHub", "url": "https://github.com/riggraz/astuto"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/riggraz/astuto"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "astuto", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('atheos', 'Atheos', 'Atheos is a self-hosted browser-based cloud IDE, updated from Codiad IDE with a modern approach to web development. This lightweight development environment provides fast, interactive coding without the massive overhead of desktop editors. Atheos features built-in Git integration, a comprehensive plugin system, multi-user support with permissions, and supports multiple programming languages. Perfect for developers who want a complete IDE that runs entirely in the browser with minimal server requirements and maximum functionality.', 'ide', ARRAY['IDE', 'Code Editor', 'Cloud IDE', 'Browser-Based', 'Self-Hosted', 'Git Integration', 'Multi-User', 'Plugin System', 'Web Development', 'PHP', 'JavaScript', 'Development Environment'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "hlsiira/atheos:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Atheos", "version": "latest", "description": "Atheos is a self-hosted browser-based cloud IDE, updated from Codiad IDE with a modern approach to web development. This lightweight development environment provides fast, interactive coding without the massive overhead of desktop editors. Atheos features built-in Git integration, a comprehensive plugin system, multi-user support with permissions, and supports multiple programming languages. Perfect for developers who want a complete IDE that runs entirely in the browser with minimal server requirements and maximum functionality.", "category": "ide", "tags": ["IDE", "Code Editor", "Cloud IDE", "Browser-Based", "Self-Hosted", "Git Integration", "Multi-User", "Plugin System", "Web Development", "PHP", "JavaScript", "Development Environment"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "hlsiira/atheos:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "GitHub Repository", "url": "https://github.com/Atheos/Atheos"}, {"label": "Official Website", "url": "https://www.atheos.io"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "atheos", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('atomic-server', 'Atomic Server', 'Atomic Server is a powerful and flexible server for managing and serving atomic data. It provides a robust platform for data management with support for various protocols and formats.', 'atomic', ARRAY['Atomic', 'Server', 'Data Management', 'API', 'Web Interface'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "joepmeneer/atomic-server:v0.38.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Atomic Server", "version": "latest", "description": "Atomic Server is a powerful and flexible server for managing and serving atomic data. It provides a robust platform for data management with support for various protocols and formats.", "category": "atomic", "tags": ["Atomic", "Server", "Data Management", "API", "Web Interface"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "joepmeneer/atomic-server:v0.38.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Github", "url": "https://github.com/joepmeneer/atomic-server"}, {"label": "Documentation", "url": "https://docs.atomicdata.dev"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "atomic-server", "port": "$PORT:80", "volumes": ["/atomic-storage"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('audiobookshelf', 'Audiobookshelf', 'Audiobookshelf is a self-hosted server designed to manage and play your audiobooks and podcasts. It works best when you have an organized directory structure, as it takes information from your folder names, including the author name, series name, book title, publish year, series sequence, and subtitle. The app uses the ID3 metadata tags in audio files to populate data, and it supports the same configuration options you would pass to a Docker container. Audiobookshelf is designed to be deployed on your own server using Easypanel, a modern server control panel. With Audiobookshelf, you can enjoy your favorite audiobooks and podcasts in a well-organized and easily accessible manner.', 'media', ARRAY['Media', 'Educational', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/advplyr/audiobookshelf:2.33.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Audiobookshelf", "version": "latest", "description": "Audiobookshelf is a self-hosted server designed to manage and play your audiobooks and podcasts. It works best when you have an organized directory structure, as it takes information from your folder names, including the author name, series name, book title, publish year, series sequence, and subtitle. The app uses the ID3 metadata tags in audio files to populate data, and it supports the same configuration options you would pass to a Docker container. Audiobookshelf is designed to be deployed on your own server using Easypanel, a modern server control panel. With Audiobookshelf, you can enjoy your favorite audiobooks and podcasts in a well-organized and easily accessible manner.", "category": "media", "tags": ["Media", "Educational", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/advplyr/audiobookshelf:2.33.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://www.audiobookshelf.org"}, {"label": "Documentation", "url": "https://www.audiobookshelf.org/docs"}, {"label": "Github", "url": "https://github.com/advplyr/audiobookshelf"}], "instructions": "Starter Host Path will be bind to \"/audiobooks\" inside the container. You can bind any other directories you want to use for your book and podcast collections.", "install": [{"docker": {"image": "$IMAGE", "name": "audiobookshelf", "port": "$PORT:80", "volumes": ["/config", "/metadata", "/audiobooks"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Starter Host Path will be bind to \"/audiobooks\" inside the container. You can bind any other directories you want to use for your book and podcast collections."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('aurral', 'Aurral', 'Aurral is a self-hosted music discovery and request management app for Lidarr. Search artists via MusicBrainz, add them to Lidarr with granular monitoring options, browse your library, and discover new artists from recommendations. Features include Weekly Flow playlists (powered by Soulseek + Navidrome), multi-user support with permissions, Gotify notifications, and PWA support. Aurral is designed to be safe for your collection—library changes go through Lidarr''s API.', 'music', ARRAY['Music', 'Lidarr', 'Self-Hosted', 'Music Discovery', 'Soulseek', 'Navidrome'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/lklynet/aurral:1.51.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3001}}$JSON$::jsonb, $JSON${"metadata": {"name": "Aurral", "version": "latest", "description": "Aurral is a self-hosted music discovery and request management app for Lidarr. Search artists via MusicBrainz, add them to Lidarr with granular monitoring options, browse your library, and discover new artists from recommendations. Features include Weekly Flow playlists (powered by Soulseek + Navidrome), multi-user support with permissions, Gotify notifications, and PWA support. Aurral is designed to be safe for your collection\u2014library changes go through Lidarr's API.", "category": "music", "tags": ["Music", "Lidarr", "Self-Hosted", "Music Discovery", "Soulseek", "Navidrome"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/lklynet/aurral:1.51.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3001}}, "links": [{"label": "GitHub", "url": "https://github.com/lklynet/aurral"}, {"label": "Container Registry", "url": "https://github.com/lklynet/aurral/pkgs/container/aurral"}, {"label": "Discord", "url": "https://discord.gg/cpPYfgVURJ"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "aurral", "port": "$PORT:3001", "volumes": ["/app/downloads", "/app/backend/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('authentik', 'Authentik', 'Authentik is an open-source Identity Provider focused on flexibility and versatility. It provides secure authentication, authorization, and user management with support for single sign-on (SSO), multi-factor authentication (MFA), and a modern user interface.', 'identity-provider', ARRAY['Identity Provider', 'Authentication', 'SSO', 'Security', 'Access Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/goauthentik/server:2026.2.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Authentik", "version": "latest", "description": "Authentik is an open-source Identity Provider focused on flexibility and versatility. It provides secure authentication, authorization, and user management with support for single sign-on (SSO), multi-factor authentication (MFA), and a modern user interface.", "category": "identity-provider", "tags": ["Identity Provider", "Authentication", "SSO", "Security", "Access Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/goauthentik/server:2026.2.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9000}}, "links": [{"label": "Website", "url": "https://goauthentik.io"}, {"label": "Documentation", "url": "https://goauthentik.io/docs"}, {"label": "GitHub", "url": "https://github.com/goauthentik/authentik"}], "instructions": "After deployment, open /if/flow/initial-setup/ to create the initial admin user. Allow ~60s for migrations to complete.", "install": [{"docker": {"image": "$IMAGE", "name": "authentik", "port": "$PORT:9000", "volumes": ["/media", "/templates", "/media", "/templates"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deployment, open /if/flow/initial-setup/ to create the initial admin user. Allow ~60s for migrations to complete."}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('authorizer', 'Authorizer', 'Authorizer is a powerful tool designed to simplify the process of user authentication and authorization in your applications. It allows you to build secure apps 10x faster with its low code tool and low-cost deployment. With Authorizer, you have full control over your user data, which can be stored in your preferred database. The app supports multiple authentication recipes and allows you to authorize users based on your business roles. It is compatible with OAuth2 and OpenID APIs. Authorizer also offers secure session management with the best services baked in, including HTTP only cookies and Authorization Code flow for mobile-based authentication. It supports a wide range of databases, including major SQL, NoSQL, and GraphDBs. You can customize emails, configure webhooks for various events, and add an extra layer of security with email-based OTP for basic authentication. With Authorizer, you can deploy your authentication and authorization service anywhere with multiple deployment options. It is a comprehensive solution for all your authentication and authorization needs.', 'authentication', ARRAY['Authentication', 'Authorization', 'Security', 'Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lakhansamani/authorizer:2.2.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Authorizer", "version": "latest", "description": "Authorizer is a powerful tool designed to simplify the process of user authentication and authorization in your applications. It allows you to build secure apps 10x faster with its low code tool and low-cost deployment. With Authorizer, you have full control over your user data, which can be stored in your preferred database. The app supports multiple authentication recipes and allows you to authorize users based on your business roles. It is compatible with OAuth2 and OpenID APIs. Authorizer also offers secure session management with the best services baked in, including HTTP only cookies and Authorization Code flow for mobile-based authentication. It supports a wide range of databases, including major SQL, NoSQL, and GraphDBs. You can customize emails, configure webhooks for various events, and add an extra layer of security with email-based OTP for basic authentication. With Authorizer, you can deploy your authentication and authorization service anywhere with multiple deployment options. It is a comprehensive solution for all your authentication and authorization needs.", "category": "authentication", "tags": ["Authentication", "Authorization", "Security", "Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lakhansamani/authorizer:2.2.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Website", "url": "https://authorizer.dev"}, {"label": "Documentation", "url": "https://docs.authorizer.dev/"}, {"label": "Github", "url": "https://github.com/authorizerdev/authorizer"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "authorizer", "port": "$PORT:8080", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('autobrr', 'Autobrr', 'Autobrr is a modern download automation tool for torrent indexers and trackers. It monitors IRC announce channels and RSS feeds from various torrent trackers, automatically downloading torrents that match your custom filters and rules. Autobrr acts as a bridge between torrent indexers and your download clients, enabling advanced automation workflows. It supports numerous torrent clients including qBittorrent, Deluge, Transmission, and rTorrent, and integrates with media management tools like Sonarr, Radarr, and Lidarr. With powerful filtering capabilities based on resolution, codec, release group, and custom regex patterns, Autobrr ensures you only download exactly what you want. Perfect for automating private tracker workflows, racing releases, and maintaining ratio requirements.', 'automation', ARRAY['Automation', 'Torrent', 'Download Manager', 'Private Tracker', 'Media Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/autobrr/autobrr:v1.75"}, "port": {"type": "integer", "title": "Port HTTP", "default": 7474}}$JSON$::jsonb, $JSON${"metadata": {"name": "Autobrr", "version": "latest", "description": "Autobrr is a modern download automation tool for torrent indexers and trackers. It monitors IRC announce channels and RSS feeds from various torrent trackers, automatically downloading torrents that match your custom filters and rules. Autobrr acts as a bridge between torrent indexers and your download clients, enabling advanced automation workflows. It supports numerous torrent clients including qBittorrent, Deluge, Transmission, and rTorrent, and integrates with media management tools like Sonarr, Radarr, and Lidarr. With powerful filtering capabilities based on resolution, codec, release group, and custom regex patterns, Autobrr ensures you only download exactly what you want. Perfect for automating private tracker workflows, racing releases, and maintaining ratio requirements.", "category": "automation", "tags": ["Automation", "Torrent", "Download Manager", "Private Tracker", "Media Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/autobrr/autobrr:v1.75"}, "port": {"type": "integer", "title": "Port HTTP", "default": 7474}}, "links": [{"label": "Website", "url": "https://autobrr.com/"}, {"label": "Documentation", "url": "https://autobrr.com/introduction"}, {"label": "Github", "url": "https://github.com/autobrr/autobrr"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "autobrr", "port": "$PORT:7474", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('autocaliweb', 'AutoCaliWeb', 'AutoCaliWeb is a self-hosted web application for browsing, reading, and managing your eBook, eComic, and PDF library through a clean, modern interface. Built on Calibre-Web with automated enhancements, it provides automatic book ingestion from a watch folder, multi-format conversion, metadata enforcement, and cover generation. Features include an in-browser reader for EPUB, PDF, and CBR formats, OPDS catalog for e-reader apps, Kobo and KOReader sync, Send-to-Kindle, multi-user management with fine-grained permissions, OAuth/OIDC authentication, automatic backups, and support for 20+ languages. It works with any existing Calibre database or creates one automatically.', 'ebooks', ARRAY['Ebooks', 'Library', 'Self-Hosted', 'Calibre', 'OPDS', 'E-Reader'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "gelbphoenix/autocaliweb:v0.12.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8083}}$JSON$::jsonb, $JSON${"metadata": {"name": "AutoCaliWeb", "version": "latest", "description": "AutoCaliWeb is a self-hosted web application for browsing, reading, and managing your eBook, eComic, and PDF library through a clean, modern interface. Built on Calibre-Web with automated enhancements, it provides automatic book ingestion from a watch folder, multi-format conversion, metadata enforcement, and cover generation. Features include an in-browser reader for EPUB, PDF, and CBR formats, OPDS catalog for e-reader apps, Kobo and KOReader sync, Send-to-Kindle, multi-user management with fine-grained permissions, OAuth/OIDC authentication, automatic backups, and support for 20+ languages. It works with any existing Calibre database or creates one automatically.", "category": "ebooks", "tags": ["Ebooks", "Library", "Self-Hosted", "Calibre", "OPDS", "E-Reader"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "gelbphoenix/autocaliweb:v0.12.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8083}}, "links": [{"label": "Codeberg", "url": "https://codeberg.org/gelbphoenix/autocaliweb"}, {"label": "GitHub", "url": "https://github.com/gelbphoenix/autocaliweb"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/gelbphoenix/autocaliweb"}, {"label": "Wiki", "url": "https://codeberg.org/gelbphoenix/autocaliweb/wiki"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "autocaliweb", "port": "$PORT:8083", "volumes": ["/config", "/acw-book-ingest", "/calibre-library"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('automatisch', 'Automatisch', 'Automatisch is a powerful, self-hosted workflow automation tool designed for connecting your apps and automating repetitive tasks. With Automatisch, you can create workflows to sync data, send notifications, and perform various actions seamlessly across different services. This container is based on Docker Baseimage KasmVNC, providing additional environment variables and configurations for enhanced flexibility. It also supports the docker manifest for multi-platform awareness, ensuring the correct image for your architecture.', 'workflow-automation', ARRAY['Workflow Automation', 'Self-Hosted', 'Task Management', 'API Integrations'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "dockeriddonuts/automatisch:2.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Automatisch", "version": "latest", "description": "Automatisch is a powerful, self-hosted workflow automation tool designed for connecting your apps and automating repetitive tasks. With Automatisch, you can create workflows to sync data, send notifications, and perform various actions seamlessly across different services. This container is based on Docker Baseimage KasmVNC, providing additional environment variables and configurations for enhanced flexibility. It also supports the docker manifest for multi-platform awareness, ensuring the correct image for your architecture.", "category": "workflow-automation", "tags": ["Workflow Automation", "Self-Hosted", "Task Management", "API Integrations"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "dockeriddonuts/automatisch:2.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Documentation", "url": "https://automatisch.io/docs"}, {"label": "GitHub", "url": "https://github.com/automatisch/automatisch"}], "instructions": "You can use `user@automatisch.io` email address and `sample` password to log in to Automatisch. Please do not forget to change your email and password from the settings page.", "install": [{"docker": {"image": "$IMAGE", "name": "automatisch", "port": "$PORT:80", "volumes": ["/automatisch/storage", "/automatisch/storage"], "extra_ports": ["443:443"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "You can use `user@automatisch.io` email address and `sample` password to log in to Automatisch. Please do not forget to change your email and password from the settings page."}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('azuracast', 'AzuraCast', 'AzuraCast is a free, open-source web radio management suite. Built for radio station managers and DJs, it provides everything you need to start and manage a successful web radio station, from playlist automation to live streaming capabilities, listener statistics, and more.', 'radio', ARRAY['Radio', 'Streaming', 'Broadcasting', 'Media Management', 'Music'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/azuracast/azuracast:0.23.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "AzuraCast", "version": "latest", "description": "AzuraCast is a free, open-source web radio management suite. Built for radio station managers and DJs, it provides everything you need to start and manage a successful web radio station, from playlist automation to live streaming capabilities, listener statistics, and more.", "category": "radio", "tags": ["Radio", "Streaming", "Broadcasting", "Media Management", "Music"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/azuracast/azuracast:0.23.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Documentation", "url": "https://docs.azuracast.com/"}, {"label": "Github", "url": "https://github.com/AzuraCast/AzuraCast"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "azuracast", "port": "$PORT:80", "volumes": ["/var/azuracast/stations", "/var/azuracast/uploads", "/var/azuracast/backups"], "extra_ports": ["2022:2022"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('babybuddy', 'BabyBuddy', 'BabyBuddy is a comprehensive, user-friendly platform designed to help parents and caregivers manage essential details about their child’s growth and development. It provides tools for tracking feedings, sleep schedules, diaper changes, and milestones, making parenting a more organized and informed journey. With BabyBuddy, you can access detailed insights into your child''s habits, progress, and overall well-being. The app offers customization options to fit individual family needs and supports data export for secure backup or sharing with healthcare professionals. BabyBuddy is lightweight, easy to deploy, and designed with a focus on privacy, ensuring your family’s data is safe and accessible only to you.', 'parenting', ARRAY['Parenting', 'Tracking', 'Child Development', 'Family Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/babybuddy:2.8.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}$JSON$::jsonb, $JSON${"metadata": {"name": "BabyBuddy", "version": "latest", "description": "BabyBuddy is a comprehensive, user-friendly platform designed to help parents and caregivers manage essential details about their child\u2019s growth and development. It provides tools for tracking feedings, sleep schedules, diaper changes, and milestones, making parenting a more organized and informed journey. With BabyBuddy, you can access detailed insights into your child's habits, progress, and overall well-being. The app offers customization options to fit individual family needs and supports data export for secure backup or sharing with healthcare professionals. BabyBuddy is lightweight, easy to deploy, and designed with a focus on privacy, ensuring your family\u2019s data is safe and accessible only to you.", "category": "parenting", "tags": ["Parenting", "Tracking", "Child Development", "Family Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/babybuddy:2.8.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}, "links": [{"label": "Website", "url": "https://babybuddy.app"}, {"label": "Documentation", "url": "https://docs.babybuddy.app"}, {"label": "GitHub", "url": "https://github.com/babybuddy/babybuddy"}], "instructions": "Login username=admin,password=admin", "install": [{"docker": {"image": "$IMAGE", "name": "babybuddy", "port": "$PORT:8000", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Login username=admin,password=admin"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('backrest', 'Backrest', 'Backrest is a web UI and orchestrator for restic backups. It supports scheduling, browsing snapshots, restores, notifications, and any restic-backed storage (S3, B2, rclone remotes, local, etc.). This template keeps the standard data/config/cache/tmp/rclone volumes and optionally bind-mounts host paths at /userdata and /repos like the upstream Docker Compose examples.', 'backup', ARRAY['Backup', 'Restore', 'Data Protection', 'Self-hosted', 'Web Interface', 'Cloud Storage', 'Rclone', 'Scheduling'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/garethgeorge/backrest:v1.13.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9898}}$JSON$::jsonb, $JSON${"metadata": {"name": "Backrest", "version": "latest", "description": "Backrest is a web UI and orchestrator for restic backups. It supports scheduling, browsing snapshots, restores, notifications, and any restic-backed storage (S3, B2, rclone remotes, local, etc.). This template keeps the standard data/config/cache/tmp/rclone volumes and optionally bind-mounts host paths at /userdata and /repos like the upstream Docker Compose examples.", "category": "backup", "tags": ["Backup", "Restore", "Data Protection", "Self-hosted", "Web Interface", "Cloud Storage", "Rclone", "Scheduling"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/garethgeorge/backrest:v1.13.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9898}}, "links": [{"label": "Website", "url": "https://garethgeorge.github.io/backrest/"}, {"label": "Documentation", "url": "https://garethgeorge.github.io/backrest/introduction/getting-started"}, {"label": "GitHub", "url": "https://github.com/garethgeorge/backrest"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/garethgeorge/backrest"}], "instructions": "Backup sources; Use template fields Host path \u2192 /userdata and/or Host path \u2192 /repos for directories you want visible inside the container (same as path/to/backup/data:/userdata and path/to/local/repos:/repos in the official compose). You can also add more bind mounts in Easypanel for other paths, then reference them in backup plans inside Backrest. First run; Open the UI, complete setup (credentials), and configure repos and schedules per the documentation.", "install": [{"docker": {"image": "$IMAGE", "name": "backrest", "port": "$PORT:9898", "volumes": ["/data", "/config", "/cache", "/tmp", "/root/.config/rclone", "/userdata", "/repos"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Backup sources; Use template fields Host path \u2192 /userdata and/or Host path \u2192 /repos for directories you want visible inside the container (same as path/to/backup/data:/userdata and path/to/local/repos:/repos in the official compose). You can also add more bind mounts in Easypanel for other paths, then reference them in backup plans inside Backrest. First run; Open the UI, complete setup (credentials), and configure repos and schedules per the documentation."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('baikal', 'Baikal', 'Baikal is a lightweight, self-hosted CalDAV and CardDAV server that enables users to manage calendars and contacts efficiently. It provides a simple and effective solution for syncing and sharing events, tasks, and address books across multiple devices. Baikal is designed to be easy to install and maintain, making it an excellent choice for individuals and organizations looking for a private, secure, and open-source alternative to cloud-based calendar and contact management services.', 'calendar', ARRAY['Calendar', 'Contacts', 'Self-Hosting', 'Productivity', 'Privacy'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ckulka/baikal:nginx-php8.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Baikal", "version": "latest", "description": "Baikal is a lightweight, self-hosted CalDAV and CardDAV server that enables users to manage calendars and contacts efficiently. It provides a simple and effective solution for syncing and sharing events, tasks, and address books across multiple devices. Baikal is designed to be easy to install and maintain, making it an excellent choice for individuals and organizations looking for a private, secure, and open-source alternative to cloud-based calendar and contact management services.", "category": "calendar", "tags": ["Calendar", "Contacts", "Self-Hosting", "Productivity", "Privacy"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ckulka/baikal:nginx-php8.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://sabre.io/baikal/"}, {"label": "Documentation", "url": "https://sabre.io/baikal/install/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "baikal", "port": "$PORT:80", "volumes": ["/var/www/baikal"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('barrage', 'Barrage', 'Barrage is a minimalistic Deluge WebUI app with full mobile support. It features a responsive mobile-first design, allowing you to manage your torrents with ease from any device. With Barrage, you can add torrents by URL or magnet, sort and filter your torrents, and set global upload and download speed limits. It also allows you to change file priorities and modify torrent options. The app is designed to be deployed with Docker, making it a convenient and efficient tool for managing your torrents.', 'file-management', ARRAY['File Management', 'Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "maulik9898/barrage:0.3.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Barrage", "version": "latest", "description": "Barrage is a minimalistic Deluge WebUI app with full mobile support. It features a responsive mobile-first design, allowing you to manage your torrents with ease from any device. With Barrage, you can add torrents by URL or magnet, sort and filter your torrents, and set global upload and download speed limits. It also allows you to change file priorities and modify torrent options. The app is designed to be deployed with Docker, making it a convenient and efficient tool for managing your torrents.", "category": "file-management", "tags": ["File Management", "Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "maulik9898/barrage:0.3.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Github", "url": "https://github.com/maulik9898/barrage"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "barrage", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('baserow', 'Baserow', 'Baserow is an open-source, no-code database tool that allows you to create your own online database without any technical experience. It is a user-friendly alternative to Airtable, offering the power of a developer right from your browser. Baserow is perfect for organizing your projects, ideas, or business processes, allowing you to structure everything according to your needs. It is a flexible software that can be tailored to your needs, ensuring clear and accessible data for all your team members. With Baserow, you can easily integrate with other software, collaborate in real-time, and enjoy unlimited rows for your data. It is also developer-friendly, allowing for the creation of custom plugins. Baserow offers a free plan for those who want to try it out, as well as premium and advanced plans for users with more advanced needs.', 'no-code', ARRAY['No-Code', 'Databases'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "baserow/baserow:1.34.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Baserow", "version": "latest", "description": "Baserow is an open-source, no-code database tool that allows you to create your own online database without any technical experience. It is a user-friendly alternative to Airtable, offering the power of a developer right from your browser. Baserow is perfect for organizing your projects, ideas, or business processes, allowing you to structure everything according to your needs. It is a flexible software that can be tailored to your needs, ensuring clear and accessible data for all your team members. With Baserow, you can easily integrate with other software, collaborate in real-time, and enjoy unlimited rows for your data. It is also developer-friendly, allowing for the creation of custom plugins. Baserow offers a free plan for those who want to try it out, as well as premium and advanced plans for users with more advanced needs.", "category": "no-code", "tags": ["No-Code", "Databases"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "baserow/baserow:1.34.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://baserow.io/"}, {"label": "Gitlab", "url": "https://gitlab.com/bramw/baserow"}], "instructions": "It may take several minutes for Baserow to boot up.", "install": [{"docker": {"image": "$IMAGE", "name": "baserow", "port": "$PORT:80", "volumes": ["/baserow/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "It may take several minutes for Baserow to boot up."}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('bazarr', 'Bazarr', 'Bazarr is a companion application to Sonarr and Radarr, designed to manage and download subtitles based on your specific needs. It allows you to define your preferences by TV show or movie, and Bazarr handles the rest. The app automatically searches for missing subtitles and downloads them as soon as they become available in your desired language. It also offers a manual search feature to find all matching subtitles, allowing you to choose the one you want and download it to your media directory. Bazarr also regularly searches for matching subtitles and upgrades the ones you previously downloaded if a better one is found. Please note that Bazarr does not scan the disk to detect series and movies, it only manages the series and movies that are indexed in Sonarr and Radarr.', 'media', ARRAY['Media', 'Subtitles', 'Download'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/bazarr:1.5.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 6767}}$JSON$::jsonb, $JSON${"metadata": {"name": "Bazarr", "version": "latest", "description": "Bazarr is a companion application to Sonarr and Radarr, designed to manage and download subtitles based on your specific needs. It allows you to define your preferences by TV show or movie, and Bazarr handles the rest. The app automatically searches for missing subtitles and downloads them as soon as they become available in your desired language. It also offers a manual search feature to find all matching subtitles, allowing you to choose the one you want and download it to your media directory. Bazarr also regularly searches for matching subtitles and upgrades the ones you previously downloaded if a better one is found. Please note that Bazarr does not scan the disk to detect series and movies, it only manages the series and movies that are indexed in Sonarr and Radarr.", "category": "media", "tags": ["Media", "Subtitles", "Download"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/bazarr:1.5.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 6767}}, "links": [{"label": "Website", "url": "https://bazarr.media/"}, {"label": "Documentation", "url": "https://wiki.bazarr.media/"}, {"label": "Github", "url": "https://github.com/morpheus65535/bazarr"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "bazarr", "port": "$PORT:6767", "volumes": ["/config", "/movies", "/tv"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('beaverhabits', 'BeaverHabits', 'BeaverHabits is a self-hosted habit tracking application that helps you build and maintain positive habits through a simple, intuitive web interface. It provides visual tracking of your daily habits, customizable date columns, and supports both database and file-based storage options for flexibility in deployment and data management.', 'habit-tracking', ARRAY['Habit Tracking', 'Productivity', 'Self-Hosted', 'Web Interface', 'Personal Development', 'Goal Setting'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "daya0576/beaverhabits:0.8.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "BeaverHabits", "version": "latest", "description": "BeaverHabits is a self-hosted habit tracking application that helps you build and maintain positive habits through a simple, intuitive web interface. It provides visual tracking of your daily habits, customizable date columns, and supports both database and file-based storage options for flexibility in deployment and data management.", "category": "habit-tracking", "tags": ["Habit Tracking", "Productivity", "Self-Hosted", "Web Interface", "Personal Development", "Goal Setting"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "daya0576/beaverhabits:0.8.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Demo", "url": "https://beaverhabits.com/demo"}, {"label": "Documentation", "url": "https://github.com/daya0576/beaverhabits/wiki"}, {"label": "Github", "url": "https://github.com/daya0576/beaverhabits"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "beaverhabits", "port": "$PORT:8080", "volumes": ["/app/.user"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('bentopdf', 'BentoPDF', 'BentoPDF is a powerful self-hosted PDF manipulation and conversion service that provides a comprehensive API for working with PDF documents. It enables developers and teams to automate PDF operations including conversion, merging, splitting, compression, watermarking, and more through a simple REST API. Built with modern technologies, BentoPDF offers a web interface for manual operations and programmatic access for integration into your applications and workflows. The service supports converting various document formats to PDF, extracting text and images, adding annotations, and manipulating PDF metadata. With no external dependencies on third-party services, BentoPDF ensures your documents remain private and secure on your own infrastructure. Perfect for document management systems, automated report generation, form processing, digital archiving, and any application that requires reliable PDF handling capabilities without the costs and privacy concerns of cloud-based PDF services.', 'pdf', ARRAY['PDF', 'Document Processing', 'Conversion', 'API', 'Automation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "bentopdfteam/bentopdf:sha-fb8c8c0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "BentoPDF", "version": "latest", "description": "BentoPDF is a powerful self-hosted PDF manipulation and conversion service that provides a comprehensive API for working with PDF documents. It enables developers and teams to automate PDF operations including conversion, merging, splitting, compression, watermarking, and more through a simple REST API. Built with modern technologies, BentoPDF offers a web interface for manual operations and programmatic access for integration into your applications and workflows. The service supports converting various document formats to PDF, extracting text and images, adding annotations, and manipulating PDF metadata. With no external dependencies on third-party services, BentoPDF ensures your documents remain private and secure on your own infrastructure. Perfect for document management systems, automated report generation, form processing, digital archiving, and any application that requires reliable PDF handling capabilities without the costs and privacy concerns of cloud-based PDF services.", "category": "pdf", "tags": ["PDF", "Document Processing", "Conversion", "API", "Automation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "bentopdfteam/bentopdf:sha-fb8c8c0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Website", "url": "https://bentopdf.com"}, {"label": "GitHub", "url": "https://github.com/alam00000/bentopdf"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "bentopdf", "port": "$PORT:8080", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('beszel', 'Beszel', 'Beszel is a lightweight server monitoring platform that includes Docker statistics, historical data, and alert functions. It has a friendly web interface, simple configuration, and is ready to use out of the box. It supports automatic backup, multi-user, OAuth authentication, and API access.', 'server-monitoring', ARRAY['Server Monitoring', 'Docker Statistics', 'Historical Data', 'Alerts', 'OAuth'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "henrygd/beszel:0.18.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8090}}$JSON$::jsonb, $JSON${"metadata": {"name": "Beszel", "version": "latest", "description": "Beszel is a lightweight server monitoring platform that includes Docker statistics, historical data, and alert functions. It has a friendly web interface, simple configuration, and is ready to use out of the box. It supports automatic backup, multi-user, OAuth authentication, and API access.", "category": "server-monitoring", "tags": ["Server Monitoring", "Docker Statistics", "Historical Data", "Alerts", "OAuth"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "henrygd/beszel:0.18.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8090}}, "links": [{"label": "Documentation", "url": "https://github.com/henrygd/beszel/blob/main/readme.md"}, {"label": "Github", "url": "https://github.com/henrygd/beszel"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "beszel", "port": "$PORT:8090", "volumes": ["/beszel_data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('birdnetgo', 'BirdNET-Go', 'BirdNET-Go is a real-time bird sound identification and monitoring system that uses advanced AI and machine learning to recognize bird species from audio recordings. It analyzes ambient sounds from microphones or audio files to identify and catalog bird species in your area. BirdNET-Go features automatic species detection with confidence scoring, location-based range filtering to show only birds likely in your region, real-time audio streaming, and comprehensive logging of all detected species. The application supports custom sensitivity settings, overlap detection for better accuracy, and can utilize XNNPACK acceleration for improved performance. Perfect for bird enthusiasts, ornithologists, researchers, and anyone interested in monitoring local bird populations and creating automated bird sound databases.', 'bird-watching', ARRAY['Bird Watching', 'Audio Recognition', 'AI', 'Wildlife Monitoring', 'Ornithology'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/tphakala/birdnet-go:nightly-20260429"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "BirdNET-Go", "version": "latest", "description": "BirdNET-Go is a real-time bird sound identification and monitoring system that uses advanced AI and machine learning to recognize bird species from audio recordings. It analyzes ambient sounds from microphones or audio files to identify and catalog bird species in your area. BirdNET-Go features automatic species detection with confidence scoring, location-based range filtering to show only birds likely in your region, real-time audio streaming, and comprehensive logging of all detected species. The application supports custom sensitivity settings, overlap detection for better accuracy, and can utilize XNNPACK acceleration for improved performance. Perfect for bird enthusiasts, ornithologists, researchers, and anyone interested in monitoring local bird populations and creating automated bird sound databases.", "category": "bird-watching", "tags": ["Bird Watching", "Audio Recognition", "AI", "Wildlife Monitoring", "Ornithology"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/tphakala/birdnet-go:nightly-20260429"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Github", "url": "https://github.com/tphakala/birdnet-go"}, {"label": "Docker Hub", "url": "https://github.com/tphakala/birdnet-go/pkgs/container/birdnet-go"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "birdnetgo", "port": "$PORT:8080", "volumes": ["/config", "/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('blackcandy', 'BlackCandy', 'BlackCandy is a self-hosted music streaming server built with Rails and Hotwire. It provides a clean, modern web interface for streaming your personal music collection. The goal of the project is to create a real personal music center that you can access from anywhere. It features mobile apps for iOS and Android, supports multiple audio formats, and offers a beautiful, responsive interface.', 'music-streaming', ARRAY['Music Streaming', 'Self-hosted', 'Ruby', 'Rails', 'Hotwire', 'Media Server', 'Audio', 'Music Player', 'Personal Music', 'Mobile Apps'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "blackcandy/blackcandy:3.1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "BlackCandy", "version": "latest", "description": "BlackCandy is a self-hosted music streaming server built with Rails and Hotwire. It provides a clean, modern web interface for streaming your personal music collection. The goal of the project is to create a real personal music center that you can access from anywhere. It features mobile apps for iOS and Android, supports multiple audio formats, and offers a beautiful, responsive interface.", "category": "music-streaming", "tags": ["Music Streaming", "Self-hosted", "Ruby", "Rails", "Hotwire", "Media Server", "Audio", "Music Player", "Personal Music", "Mobile Apps"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "blackcandy/blackcandy:3.1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "GitHub", "url": "https://github.com/blackcandy-org/blackcandy"}, {"label": "Documentation", "url": "https://github.com/blackcandy-org/blackcandy#readme"}, {"label": "Demo", "url": "https://demo.blackcandy.org"}], "instructions": "default login is admin@admin.com and password is foobar", "install": [{"docker": {"image": "$IMAGE", "name": "blackcandy", "port": "$PORT:3000", "volumes": ["/media_data", "/app/storage"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "default login is admin@admin.com and password is foobar"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('blender', 'Blender', 'Blender is a comprehensive, free and open-source 3D computer graphics software toolset. It is used for creating animated films, visual effects, art, 3D printed models, motion graphics, interactive 3D applications, virtual reality, and computer games. The app is designed to be accessed at your host, providing a desktop GUI for easy interaction. It supports hardware acceleration for an enhanced desktop experience, although GPU rendering is not supported out of the box. The app is compatible with multiple architectures, ensuring it can be used on a variety of systems. Please note that while this app can run on Arm devices, it is recommended not to mount in /dev/dri due to the OpenGL ES version not being high enough to run Blender.', '3d-graphics', ARRAY['3D Graphics', 'Animation', 'Visual Effects', 'Art', 'Motion Graphics', 'Virtual Reality', 'Computer Games'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/blender:5.1.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Blender", "version": "latest", "description": "Blender is a comprehensive, free and open-source 3D computer graphics software toolset. It is used for creating animated films, visual effects, art, 3D printed models, motion graphics, interactive 3D applications, virtual reality, and computer games. The app is designed to be accessed at your host, providing a desktop GUI for easy interaction. It supports hardware acceleration for an enhanced desktop experience, although GPU rendering is not supported out of the box. The app is compatible with multiple architectures, ensuring it can be used on a variety of systems. Please note that while this app can run on Arm devices, it is recommended not to mount in /dev/dri due to the OpenGL ES version not being high enough to run Blender.", "category": "3d-graphics", "tags": ["3D Graphics", "Animation", "Visual Effects", "Art", "Motion Graphics", "Virtual Reality", "Computer Games"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/blender:5.1.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Documentation", "url": "https://docs.linuxserver.io/images/docker-blender"}, {"label": "Github", "url": "https://github.com/linuxserver/docker-blender"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "blender", "port": "$PORT:3000", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('blinko', 'Blinko', 'Blinko (space) is an open-source, self-hosted “idea hub” that rolls notes, micro-blog posts, paste-bins and lightweight tasks into one minimalist, card-style interface. You jot down thoughts in plain text or Markdown; behind the scenes Blinko indexes every word with an AI-powered RAG engine (works with OpenAI or a local Ollama model), so you can later retrieve anything with natural-language search instead of keywords', 'collaboration', ARRAY['Collaboration', 'Team Management', 'Document Sharing', 'Project Management', 'Real-time', 'Workspace'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "blinkospace/blinko:1.8.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 1111}}$JSON$::jsonb, $JSON${"metadata": {"name": "Blinko", "version": "latest", "description": "Blinko (space) is an open-source, self-hosted \u201cidea hub\u201d that rolls notes, micro-blog posts, paste-bins and lightweight tasks into one minimalist, card-style interface. You jot down thoughts in plain text or Markdown; behind the scenes Blinko indexes every word with an AI-powered RAG engine (works with OpenAI or a local Ollama model), so you can later retrieve anything with natural-language search instead of keywords", "category": "collaboration", "tags": ["Collaboration", "Team Management", "Document Sharing", "Project Management", "Real-time", "Workspace"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "blinkospace/blinko:1.8.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 1111}}, "links": [{"label": "Website", "url": "https://blinko.space/"}, {"label": "Documentation", "url": "https://docs.blinko.space/"}, {"label": "Github", "url": "https://github.com/blinkospace/blinko"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "blinko", "port": "$PORT:1111", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('boltdiy', 'Bolt.Diy', 'Bolt.Diy is an AI-powered agent and community for web development, enabling you to create, edit, and deploy full-stack applications without any local setup. It''s like having a coding genie at your fingertips, transforming your web ideas into reality with just a few prompts. Bolt.Diy streamlines the development process with intelligent suggestions, automated workflows, and seamless deployment, making it the ultimate tool for modern web developers. The app is fully containerized and designed for accessibility across various platforms.', 'ai', ARRAY['AI', 'Web Development', 'Collaboration', 'Full-Stack', 'Deployment', 'Open Source', 'Community'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 5173}}$JSON$::jsonb, $JSON${"metadata": {"name": "Bolt.Diy", "version": "latest", "description": "Bolt.Diy is an AI-powered agent and community for web development, enabling you to create, edit, and deploy full-stack applications without any local setup. It's like having a coding genie at your fingertips, transforming your web ideas into reality with just a few prompts. Bolt.Diy streamlines the development process with intelligent suggestions, automated workflows, and seamless deployment, making it the ultimate tool for modern web developers. The app is fully containerized and designed for accessibility across various platforms.", "category": "ai", "tags": ["AI", "Web Development", "Collaboration", "Full-Stack", "Deployment", "Open Source", "Community"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 5173}}, "links": [{"label": "Github", "url": "https://github.com/stackblitz-labs/bolt.diy"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "boltdiy", "port": "$PORT:5173", "volumes": ["/app"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('bookheaven', 'BookHeaven', 'BookHeaven Server is a self-hosted ebook library manager that lets you organize, read, and manage your ebook collection with a modern responsive UI. It reads metadata directly from ebook files (title, author, cover), allows editing and persists changes back into the file. Features include auto-discovery by the companion Android e-ink reader app, metadata fetching from the internet, reading progress tracking, font management for your devices, multiple profiles, OPDS support, and book importing via a dedicated folder. Built with .NET and Blazor.', 'ebooks', ARRAY['Ebooks', 'Library', 'Self-Hosted', 'E-Reader', 'OPDS', 'Books'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/bookheaven/bookheaven-server:0.16.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "BookHeaven", "version": "latest", "description": "BookHeaven Server is a self-hosted ebook library manager that lets you organize, read, and manage your ebook collection with a modern responsive UI. It reads metadata directly from ebook files (title, author, cover), allows editing and persists changes back into the file. Features include auto-discovery by the companion Android e-ink reader app, metadata fetching from the internet, reading progress tracking, font management for your devices, multiple profiles, OPDS support, and book importing via a dedicated folder. Built with .NET and Blazor.", "category": "ebooks", "tags": ["Ebooks", "Library", "Self-Hosted", "E-Reader", "OPDS", "Books"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/bookheaven/bookheaven-server:0.16.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "GitHub", "url": "https://github.com/BookHeaven/BookHeaven.Server"}, {"label": "Website", "url": "https://bookheaven.ggarrido.dev"}, {"label": "Documentation", "url": "https://bookheaven.ggarrido.dev/getting-started"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "bookheaven", "port": "$PORT:8080", "volumes": ["/app/data", "/app/import"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('bookstack', 'Bookstack', 'BookStack is a free and open-source platform designed to help you organize and store information in a simple and efficient way. It is a self-hosted solution that allows you to create, edit, and manage content through an easy-to-use interface. The content is divided into three real-world groups: Books, Chapters, and Pages, making it easy to navigate and find the information you need. The platform also includes a powerful search feature that allows you to search at the book level or across all books, chapters, and pages. You can also link directly to any paragraph, keeping your documentation interconnected. BookStack offers configuration options that let you customize the system to suit your needs, including changing the name, logo, and registration options. It also includes built-in diagrams.net drawing capability for creating diagrams within your documentation, a markdown editor for those who prefer to write in markdown, and integrated authentication options. The platform supports multiple languages and offers both dark and light modes for a comfortable user experience. It also includes a full role and permission system, multi-factor authentication, and features like cross-book sorting, page revisions, and image management.', 'wiki', ARRAY['Wiki', 'Documentation', 'Open Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/bookstack:26.03.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Bookstack", "version": "latest", "description": "BookStack is a free and open-source platform designed to help you organize and store information in a simple and efficient way. It is a self-hosted solution that allows you to create, edit, and manage content through an easy-to-use interface. The content is divided into three real-world groups: Books, Chapters, and Pages, making it easy to navigate and find the information you need. The platform also includes a powerful search feature that allows you to search at the book level or across all books, chapters, and pages. You can also link directly to any paragraph, keeping your documentation interconnected. BookStack offers configuration options that let you customize the system to suit your needs, including changing the name, logo, and registration options. It also includes built-in diagrams.net drawing capability for creating diagrams within your documentation, a markdown editor for those who prefer to write in markdown, and integrated authentication options. The platform supports multiple languages and offers both dark and light modes for a comfortable user experience. It also includes a full role and permission system, multi-factor authentication, and features like cross-book sorting, page revisions, and image management.", "category": "wiki", "tags": ["Wiki", "Documentation", "Open Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/bookstack:26.03.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://www.bookstackapp.com/"}, {"label": "Documentation", "url": "https://www.bookstackapp.com/docs/"}, {"label": "Github", "url": "https://github.com/BookStackApp/BookStack"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "bookstack", "port": "$PORT:80", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('borgui', 'Borg UI', 'Borg UI is a modern web-based interface for BorgBackup, the popular deduplicating backup program with compression and authenticated encryption. It provides an intuitive dashboard for managing backup repositories, creating and scheduling backups, monitoring backup status, and restoring files through a user-friendly web interface. BorgBackup is known for its efficiency through deduplication at the chunk level, strong encryption using AES-256, and data integrity verification. Borg UI simplifies the complexity of command-line operations by offering visual repository management, backup job configuration, automated scheduling, space-efficient storage tracking, and easy file restoration. The self-hosted solution gives you complete control over your backup infrastructure while maintaining the security and reliability of BorgBackup. With access to your entire filesystem, it can protect any data on your server including application files, databases, configurations, and user data. Perfect for system administrators, developers, and anyone who needs reliable, encrypted, and space-efficient backup solutions without relying on proprietary cloud backup services or complex command-line interfaces.', 'backup', ARRAY['Backup', 'BorgBackup', 'Deduplication', 'Encryption', 'System Administration'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ainullcode/borg-ui:2.0.8"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8081}}$JSON$::jsonb, $JSON${"metadata": {"name": "Borg UI", "version": "latest", "description": "Borg UI is a modern web-based interface for BorgBackup, the popular deduplicating backup program with compression and authenticated encryption. It provides an intuitive dashboard for managing backup repositories, creating and scheduling backups, monitoring backup status, and restoring files through a user-friendly web interface. BorgBackup is known for its efficiency through deduplication at the chunk level, strong encryption using AES-256, and data integrity verification. Borg UI simplifies the complexity of command-line operations by offering visual repository management, backup job configuration, automated scheduling, space-efficient storage tracking, and easy file restoration. The self-hosted solution gives you complete control over your backup infrastructure while maintaining the security and reliability of BorgBackup. With access to your entire filesystem, it can protect any data on your server including application files, databases, configurations, and user data. Perfect for system administrators, developers, and anyone who needs reliable, encrypted, and space-efficient backup solutions without relying on proprietary cloud backup services or complex command-line interfaces.", "category": "backup", "tags": ["Backup", "BorgBackup", "Deduplication", "Encryption", "System Administration"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ainullcode/borg-ui:2.0.8"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8081}}, "links": [{"label": "BorgBackup Docs", "url": "https://borgbackup.readthedocs.io/"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/ainullcode/borg-ui"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "borgui", "port": "$PORT:8081", "volumes": ["/data", "/home/borg/.cache/borg", "/local"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('botpress', 'Botpress', 'Botpress is a revolutionary platform that allows you to build next-generation chatbots powered by OpenAI. It offers an intuitive visual flow editor to bring your users’ conversations to life. With Botpress, you can create chatbots that are always on brand, thanks to ChatGPT’s copywriting abilities. The platform also provides a range of GPT-first tools and features such as dynamic knowledge ingestion, sentiment analysis, automatic self-improvement, data enhancements, and AI recommendations. Botpress supports 100+ languages, enabling you to launch your chatbot globally. It also offers one-click deployment across various channels. With Botpress, building human-like chatbots has never been this easy.', 'chat', ARRAY['Chat', 'AI', 'Automation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "botpress/server:12.31.10"}, "port": {"type": "integer", "title": "Port HTTP", "default": 81}}$JSON$::jsonb, $JSON${"metadata": {"name": "Botpress", "version": "latest", "description": "Botpress is a revolutionary platform that allows you to build next-generation chatbots powered by OpenAI. It offers an intuitive visual flow editor to bring your users\u2019 conversations to life. With Botpress, you can create chatbots that are always on brand, thanks to ChatGPT\u2019s copywriting abilities. The platform also provides a range of GPT-first tools and features such as dynamic knowledge ingestion, sentiment analysis, automatic self-improvement, data enhancements, and AI recommendations. Botpress supports 100+ languages, enabling you to launch your chatbot globally. It also offers one-click deployment across various channels. With Botpress, building human-like chatbots has never been this easy.", "category": "chat", "tags": ["Chat", "AI", "Automation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "botpress/server:12.31.10"}, "port": {"type": "integer", "title": "Port HTTP", "default": 81}}, "links": [{"label": "Website", "url": "https://botpress.com"}, {"label": "Documentation", "url": "https://botpress.com/docs"}, {"label": "Github", "url": "https://github.com/botpress/botpress"}], "instructions": "Botpress needs at least 10 GB of RAM to run!", "install": [{"docker": {"image": "$IMAGE", "name": "botpress", "port": "$PORT:81", "volumes": ["/botpress/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Botpress needs at least 10 GB of RAM to run!"}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('browserless', 'Browserless', 'Browserless is a powerful self-hosted headless browser service designed to automate web interactions. It enables developers to run headless Chrome instances efficiently for web scraping, testing, PDF generation, and automation tasks. Browserless supports Puppeteer, Playwright, and Selenium, providing a scalable and secure environment for handling complex browser automation tasks. The application is optimized for performance, offering session management, request queuing, and robust security features. With Browserless, developers can offload browser-based automation to a dedicated service, reducing local resource consumption and improving workflow efficiency.', 'browser-automation', ARRAY['Browser Automation', 'Web Scraping', 'Testing', 'Puppeteer', 'Playwright', 'Selenium'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/browserless/chromium:v2.40.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Browserless", "version": "latest", "description": "Browserless is a powerful self-hosted headless browser service designed to automate web interactions. It enables developers to run headless Chrome instances efficiently for web scraping, testing, PDF generation, and automation tasks. Browserless supports Puppeteer, Playwright, and Selenium, providing a scalable and secure environment for handling complex browser automation tasks. The application is optimized for performance, offering session management, request queuing, and robust security features. With Browserless, developers can offload browser-based automation to a dedicated service, reducing local resource consumption and improving workflow efficiency.", "category": "browser-automation", "tags": ["Browser Automation", "Web Scraping", "Testing", "Puppeteer", "Playwright", "Selenium"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/browserless/chromium:v2.40.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Documentation", "url": "https://docs.browserless.io/"}, {"label": "Github", "url": "https://github.com/browserless/chrome"}], "instructions": "Update your App to use Browserless. Follow the docs; https://docs.browserless.io/baas/docker/quickstart.", "install": [{"docker": {"image": "$IMAGE", "name": "browserless", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Update your App to use Browserless. Follow the docs; https://docs.browserless.io/baas/docker/quickstart."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('budge', 'Budge', 'Budge is a personal finance management application that helps you track your expenses, manage budgets, and monitor your financial goals. It provides a user-friendly interface for managing your personal finances.', 'finance', ARRAY['Finance', 'Budget', 'Expense Tracking', 'Personal Finance', 'Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/budge:0.0.9"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Budge", "version": "latest", "description": "Budge is a personal finance management application that helps you track your expenses, manage budgets, and monitor your financial goals. It provides a user-friendly interface for managing your personal finances.", "category": "finance", "tags": ["Finance", "Budget", "Expense Tracking", "Personal Finance", "Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/budge:0.0.9"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Github", "url": "https://github.com/linuxserver/budge"}, {"label": "Documentation", "url": "https://github.com/linuxserver/budge#readme"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "budge", "port": "$PORT:80", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('budibase', 'Budibase', 'Budibase is an open-source platform designed to simplify the creation of internal tools, saving teams hundreds of hours in the process. With Budibase, you can generate powerful internal tools and forms in just a few seconds, without any coding experience required. The platform allows you to connect to an external database, pull data from a Rest API, import a CSV, or start from scratch with Budibase''s built-in database. You can design your tools using drag-and-drop components and automate workflows with just a few clicks. Budibase is trusted by over 75,000 teams and is designed to speed up your business operations. Whether you need to collect data securely, automate tasks, or streamline operations, Budibase has you covered.', 'no-code', ARRAY['No-Code', 'Internal tools', 'Forms', 'Workflows'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "budibase/apps:3.37.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Budibase", "version": "latest", "description": "Budibase is an open-source platform designed to simplify the creation of internal tools, saving teams hundreds of hours in the process. With Budibase, you can generate powerful internal tools and forms in just a few seconds, without any coding experience required. The platform allows you to connect to an external database, pull data from a Rest API, import a CSV, or start from scratch with Budibase's built-in database. You can design your tools using drag-and-drop components and automate workflows with just a few clicks. Budibase is trusted by over 75,000 teams and is designed to speed up your business operations. Whether you need to collect data securely, automate tasks, or streamline operations, Budibase has you covered.", "category": "no-code", "tags": ["No-Code", "Internal tools", "Forms", "Workflows"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "budibase/apps:3.37.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9000}}, "links": [{"label": "Website", "url": "https://budibase.com/"}, {"label": "Documentation", "url": "https://docs.budibase.com/docs"}, {"label": "Github", "url": "https://github.com/Budibase/budibase"}], "instructions": "Budibase takes a few minutes to get ready. Sit back, relax, and have a cup of tea!", "install": [{"docker": {"image": "$IMAGE", "name": "budibase", "port": "$PORT:9000", "volumes": ["/opt/couchdb/data", "/data"], "extra_ports": ["9001:9001", "10000:10000"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Budibase takes a few minutes to get ready. Sit back, relax, and have a cup of tea!"}, "services": {"redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('bugsink', 'Bugsink', 'Bugsink is a self-hosted error tracking system compatible with Sentry SDKs.', 'error-tracking', ARRAY['Error Tracking', 'Self-Hosted', 'Monitoring', 'Sentry Compatible'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "bugsink/bugsink:2.1.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Bugsink", "version": "latest", "description": "Bugsink is a self-hosted error tracking system compatible with Sentry SDKs.", "category": "error-tracking", "tags": ["Error Tracking", "Self-Hosted", "Monitoring", "Sentry Compatible"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "bugsink/bugsink:2.1.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}, "links": [{"label": "Website", "url": "https://www.bugsink.com/"}, {"label": "Github", "url": "https://github.com/bugsink/bugsink"}, {"label": "Documentation", "url": "https://www.bugsink.com/docs/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "bugsink", "port": "$PORT:8000", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('bytebase', 'Bytebase', 'Bytebase is a versatile application designed to streamline database management tasks. It supports a wide range of databases including MySQL, PostgreSQL, Snowflake, Oracle, SQL Server, MongoDB, Redis, Redshift, ClickHouse, TiDB, OceanBase, Google Spanner, and MariaDB. With Bytebase, you can easily configure and manage your database instances, perform SQL reviews, manage data models, roles, and permissions, and handle change workflows in batch mode. The app also offers features for secure data handling, VCS integration, slow query management, and disaster recovery. It comes with an embedded PostgreSQL instance for storing its metadata, but for production setup, it is recommended to store the metadata in an external PostgreSQL database. Bytebase is designed to be deployed easily and quickly, offering a step-by-step quick start guide for users.', 'databases', ARRAY['Databases'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "bytebase/bytebase:3.17.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Bytebase", "version": "latest", "description": "Bytebase is a versatile application designed to streamline database management tasks. It supports a wide range of databases including MySQL, PostgreSQL, Snowflake, Oracle, SQL Server, MongoDB, Redis, Redshift, ClickHouse, TiDB, OceanBase, Google Spanner, and MariaDB. With Bytebase, you can easily configure and manage your database instances, perform SQL reviews, manage data models, roles, and permissions, and handle change workflows in batch mode. The app also offers features for secure data handling, VCS integration, slow query management, and disaster recovery. It comes with an embedded PostgreSQL instance for storing its metadata, but for production setup, it is recommended to store the metadata in an external PostgreSQL database. Bytebase is designed to be deployed easily and quickly, offering a step-by-step quick start guide for users.", "category": "databases", "tags": ["Databases"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "bytebase/bytebase:3.17.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Documentation", "url": "https://www.bytebase.com/docs/get-started/install/deploy-with-docker/"}, {"label": "Github", "url": "https://github.com/bytebase/bytebase"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "bytebase", "port": "$PORT:8080", "volumes": ["/var/opt/bytebase"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('bytebin', 'Bytebin', 'Bytebin is a fast, lightweight, and simple pastebin service for sharing text and code snippets. Built with performance in mind, it provides an easy way to store and share content through unique URLs. Bytebin is designed to be minimalistic and efficient, making it perfect for developers who need a straightforward solution for sharing code, logs, or text data with automatic expiration and configurable storage limits.', 'pastebin', ARRAY['Pastebin', 'Code Sharing', 'Text Storage', 'API', 'Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/lucko/bytebin:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Bytebin", "version": "latest", "description": "Bytebin is a fast, lightweight, and simple pastebin service for sharing text and code snippets. Built with performance in mind, it provides an easy way to store and share content through unique URLs. Bytebin is designed to be minimalistic and efficient, making it perfect for developers who need a straightforward solution for sharing code, logs, or text data with automatic expiration and configurable storage limits.", "category": "pastebin", "tags": ["Pastebin", "Code Sharing", "Text Storage", "API", "Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/lucko/bytebin:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "GitHub", "url": "https://github.com/lucko/bytebin"}, {"label": "Documentation", "url": "https://github.com/lucko/bytebin#readme"}], "instructions": "Bytebin exposes a simple HTTP API on port 8080. After deployment, open GET /health for a quick health check, POST /post with your content in the request body to create a paste. Data is persisted in /opt/bytebin/content and /opt/bytebin/db, so existing keys survive restarts and upgrades. Adjust BYTEBIN_MISC_KEYLENGTH and BYTEBIN_CONTENT_MAXSIZE if you need longer keys or larger payload limits.", "install": [{"docker": {"image": "$IMAGE", "name": "bytebin", "port": "$PORT:8080", "volumes": ["/opt/bytebin/content", "/opt/bytebin/db"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Bytebin exposes a simple HTTP API on port 8080. After deployment, open GET /health for a quick health check, POST /post with your content in the request body to create a paste. Data is persisted in /opt/bytebin/content and /opt/bytebin/db, so existing keys survive restarts and upgrades. Adjust BYTEBIN_MISC_KEYLENGTH and BYTEBIN_CONTENT_MAXSIZE if you need longer keys or larger payload limits."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('bytestash', 'ByteStash', 'ByteStash is a self-hosted snippet code storage system designed for developers and teams. It provides a secure, organized platform to store, manage, and share your code snippets. With support for multiple programming languages, syntax highlighting, tagging, and a robust search functionality, ByteStash streamlines code reuse and collaboration. The intuitive interface and powerful features ensure that your code is always at your fingertips, whether you''re working solo or with a team.', 'code-snippets', ARRAY['Code Snippets', 'Development', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/jordan-dalby/bytestash:1.5.11"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5000}}$JSON$::jsonb, $JSON${"metadata": {"name": "ByteStash", "version": "latest", "description": "ByteStash is a self-hosted snippet code storage system designed for developers and teams. It provides a secure, organized platform to store, manage, and share your code snippets. With support for multiple programming languages, syntax highlighting, tagging, and a robust search functionality, ByteStash streamlines code reuse and collaboration. The intuitive interface and powerful features ensure that your code is always at your fingertips, whether you're working solo or with a team.", "category": "code-snippets", "tags": ["Code Snippets", "Development", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/jordan-dalby/bytestash:1.5.11"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5000}}, "links": [{"label": "Documentation", "url": "https://github.com/jordan-dalby/bytestash/wiki"}, {"label": "Github", "url": "https://github.com/jordan-dalby/bytestash"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "bytestash", "port": "$PORT:5000", "volumes": ["/data/snippets"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('cachet', 'Cachet', 'Meet Cachet, the open-source status page system designed to improve downtime communication. Used by great companies worldwide, Cachet allows you to effectively communicate downtime and system outages to your customers, teams, and shareholders. It comes with a beautifully crafted design that is responsive and works seamlessly on your desktop, tablet, and phone. Cachet supports multiple languages and comes with a powerful JSON API for updating your status page with incidents and component status changes. It also allows you to schedule maintenance events ahead of time and provides a dashboard for setting up metrics to measure various aspects such as uptime, error rates, etc. For added security, Cachet supports two-factor authentication. It''s a beautifully simple service for managing your service statuses.', 'monitoring', ARRAY['Monitoring', 'Communication'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/supernova3339/docker-cachet-hq:2.3.18"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Cachet", "version": "latest", "description": "Meet Cachet, the open-source status page system designed to improve downtime communication. Used by great companies worldwide, Cachet allows you to effectively communicate downtime and system outages to your customers, teams, and shareholders. It comes with a beautifully crafted design that is responsive and works seamlessly on your desktop, tablet, and phone. Cachet supports multiple languages and comes with a powerful JSON API for updating your status page with incidents and component status changes. It also allows you to schedule maintenance events ahead of time and provides a dashboard for setting up metrics to measure various aspects such as uptime, error rates, etc. For added security, Cachet supports two-factor authentication. It's a beautifully simple service for managing your service statuses.", "category": "monitoring", "tags": ["Monitoring", "Communication"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/supernova3339/docker-cachet-hq:2.3.18"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}, "links": [{"label": "Website", "url": "https://cachethq.io"}, {"label": "Documentation", "url": "https://docs.cachethq.io/"}, {"label": "Github", "url": "https://github.com/cachethq/cachet"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "cachet", "port": "$PORT:8000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('calcom', 'Calcom', 'Cal.com is a versatile scheduling app designed to streamline the process of setting up meetings, appointments, and events. It allows users to set their availability, connect their existing calendars, and share a personal link for others to book a meeting at a time that works for both parties. The app ensures you never get double booked by checking for conflicts across all your calendars. It also offers workflow automation, enabling you to build processes around your events with automatic notifications, reminders, and follow-ups. With features like round-robin scheduling, routing forms, and meeting overload prevention, Cal.com adapts to any business, making it an ideal solution for doctors, companies, teachers, and experts. The app is available in over 26 languages and can be embedded anywhere for easy access. It also offers simple rescheduling and requires confirmation to ensure smooth scheduling.', 'calendars', ARRAY['Calendars', 'Scheduling', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "calcom/cal.com:v6.2.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Calcom", "version": "latest", "description": "Cal.com is a versatile scheduling app designed to streamline the process of setting up meetings, appointments, and events. It allows users to set their availability, connect their existing calendars, and share a personal link for others to book a meeting at a time that works for both parties. The app ensures you never get double booked by checking for conflicts across all your calendars. It also offers workflow automation, enabling you to build processes around your events with automatic notifications, reminders, and follow-ups. With features like round-robin scheduling, routing forms, and meeting overload prevention, Cal.com adapts to any business, making it an ideal solution for doctors, companies, teachers, and experts. The app is available in over 26 languages and can be embedded anywhere for easy access. It also offers simple rescheduling and requires confirmation to ensure smooth scheduling.", "category": "calendars", "tags": ["Calendars", "Scheduling", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "calcom/cal.com:v6.2.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://cal.com"}, {"label": "Github", "url": "https://github.com/calcom/cal.com"}, {"label": "Docker", "url": "https://hub.docker.com/r/calcom/cal.com"}], "instructions": "After deployment, open the app URL and complete the onboarding wizard to\ncreate your admin account. SMTP credentials are required for booking\nconfirmation and reminder emails \u2014 set them in the form before deploying.\nFor Gmail, use an App Password (not your account password) and set the\nSMTP host to smtp.gmail.com, port 587. For other providers check their\nSMTP documentation. The Prisma Studio option exposes a database browser\non a separate domain \u2014 only enable it in trusted environments.\n", "install": [{"docker": {"image": "$IMAGE", "name": "calcom", "port": "$PORT:3000", "volumes": [], "extra_ports": ["5555:5555"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deployment, open the app URL and complete the onboarding wizard to\ncreate your admin account. SMTP credentials are required for booking\nconfirmation and reminder emails \u2014 set them in the form before deploying.\nFor Gmail, use an App Password (not your account password) and set the\nSMTP host to smtp.gmail.com, port 587. For other providers check their\nSMTP documentation. The Prisma Studio option exposes a database browser\non a separate domain \u2014 only enable it in trusted environments.\n"}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('calibre-web-automated', 'Calibre Web Automated', 'Calibre Web Automated (CWA) is an enhanced version of Calibre Web with automated book processing capabilities. It automatically adds books to your library from an ingest directory, supports Hardcover API integration for enhanced metadata, and provides network share compatibility. CWA processes books according to your configured settings and removes them from the ingest directory after processing, making it perfect for automated eBook management workflows.', 'ebook-management', ARRAY['eBook Management', 'Digital Library', 'Automation', 'Self-Hosted', 'Calibre', 'Books', 'Hardcover'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "crocodilestick/calibre-web-automated:V3.1.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8083}}$JSON$::jsonb, $JSON${"metadata": {"name": "Calibre Web Automated", "version": "latest", "description": "Calibre Web Automated (CWA) is an enhanced version of Calibre Web with automated book processing capabilities. It automatically adds books to your library from an ingest directory, supports Hardcover API integration for enhanced metadata, and provides network share compatibility. CWA processes books according to your configured settings and removes them from the ingest directory after processing, making it perfect for automated eBook management workflows.", "category": "ebook-management", "tags": ["eBook Management", "Digital Library", "Automation", "Self-Hosted", "Calibre", "Books", "Hardcover"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "crocodilestick/calibre-web-automated:V3.1.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8083}}, "links": [{"label": "Docker Hub", "url": "https://hub.docker.com/r/crocodilestick/calibre-web-automated"}, {"label": "Github", "url": "https://github.com/crocodilestick/calibre-web-automated"}], "instructions": "Default login credentials are admin/admin123", "install": [{"docker": {"image": "$IMAGE", "name": "calibre-web-automated", "port": "$PORT:8083", "volumes": ["/config", "/cwa-book-ingest", "/calibre-library", "/config/.config/calibre/plugins"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Default login credentials are admin/admin123"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('calibre-web', 'Calibre Web', 'Calibre Web is a web app providing a clean interface for browsing, reading and downloading eBooks using an existing Calibre database. It is a Python web application that provides a web interface for the Calibre eBook library. It supports multiple users, user management, and provides a modern, responsive interface for accessing your eBook collection from any device.', 'ebook-management', ARRAY['eBook Management', 'Digital Library', 'Reading', 'Self-Hosted', 'Calibre', 'Books'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/calibre-web:0.6.26"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8083}}$JSON$::jsonb, $JSON${"metadata": {"name": "Calibre Web", "version": "latest", "description": "Calibre Web is a web app providing a clean interface for browsing, reading and downloading eBooks using an existing Calibre database. It is a Python web application that provides a web interface for the Calibre eBook library. It supports multiple users, user management, and provides a modern, responsive interface for accessing your eBook collection from any device.", "category": "ebook-management", "tags": ["eBook Management", "Digital Library", "Reading", "Self-Hosted", "Calibre", "Books"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/calibre-web:0.6.26"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8083}}, "links": [{"label": "Docker Hub", "url": "https://hub.docker.com/r/linuxserver/calibre-web"}, {"label": "Github", "url": "https://github.com/janeczku/calibre-web"}], "instructions": "Default login credentials are admin/admin123", "install": [{"docker": {"image": "$IMAGE", "name": "calibre-web", "port": "$PORT:8083", "volumes": ["/config", "/books"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Default login credentials are admin/admin123"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('calibre', 'Calibre', 'Calibre is a comprehensive e-book management tool designed to organize, convert, and read your e-book collection. It supports most of the major e-book formats and is compatible with various e-book reader devices. Calibre can fetch metadata for your books from the internet, enhancing your library with relevant information. It also allows you to download newspapers and convert them into e-books for a more convenient reading experience. The app is cross-platform, running on Linux, Windows, and macOS. With Calibre, you can easily add books to your library, convert them to a format your reader understands, and send them to your device. It also offers advanced features like e-book editing, metadata editing, and e-book comparison. The app is user-friendly, but also offers a Command Line Interface for more power and versatility.', 'documents', ARRAY['Documents', 'E-Commerce'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/calibre:8.16.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Calibre", "version": "latest", "description": "Calibre is a comprehensive e-book management tool designed to organize, convert, and read your e-book collection. It supports most of the major e-book formats and is compatible with various e-book reader devices. Calibre can fetch metadata for your books from the internet, enhancing your library with relevant information. It also allows you to download newspapers and convert them into e-books for a more convenient reading experience. The app is cross-platform, running on Linux, Windows, and macOS. With Calibre, you can easily add books to your library, convert them to a format your reader understands, and send them to your device. It also offers advanced features like e-book editing, metadata editing, and e-book comparison. The app is user-friendly, but also offers a Command Line Interface for more power and versatility.", "category": "documents", "tags": ["Documents", "E-Commerce"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/calibre:8.16.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Website", "url": "https://calibre-ebook.com/"}, {"label": "Documentation", "url": "https://manual.calibre-ebook.com/"}, {"label": "Github", "url": "https://github.com/kovidgoyal/calibre"}], "instructions": "Login using user abc with your set password", "install": [{"docker": {"image": "$IMAGE", "name": "calibre", "port": "$PORT:8080", "volumes": ["/books", "/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Login using user abc with your set password"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('cap', 'Cap', 'Cap is an open source screen recording and sharing platform, providing a lightweight alternative to Loom. With Cap, you can create beautiful, shareable screen recordings with instant sharing capabilities or local recording with full editing features. It supports 4K recording, 60fps capture, and offers both cloud and self-hosted storage options. Perfect for creating tutorials, presentations, educational content, and team collaboration. Cap includes features like auto-generated captions, titles, summaries, chapters, and AI-powered transcriptions.', 'productivity', ARRAY['Productivity', 'Video', 'Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/capsoftware/cap-web:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Cap", "version": "latest", "description": "Cap is an open source screen recording and sharing platform, providing a lightweight alternative to Loom. With Cap, you can create beautiful, shareable screen recordings with instant sharing capabilities or local recording with full editing features. It supports 4K recording, 60fps capture, and offers both cloud and self-hosted storage options. Perfect for creating tutorials, presentations, educational content, and team collaboration. Cap includes features like auto-generated captions, titles, summaries, chapters, and AI-powered transcriptions.", "category": "productivity", "tags": ["Productivity", "Video", "Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/capsoftware/cap-web:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://cap.so/"}, {"label": "GitHub", "url": "https://github.com/capsoftware/cap"}, {"label": "Documentation", "url": "https://cap.so/docs"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "cap", "port": "$PORT:3000", "volumes": ["/data"], "extra_ports": ["9000:9000"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('carbone', 'Carbone', 'Carbone is a high-performance, self-hosted document generation engine. It allows you to generate reports, invoices, and documents in various formats (e.g., PDF, DOCX, XLSX) using JSON data and template-based rendering. Carbone is designed for scalability and speed, making it ideal for automation, bulk document generation, and seamless integration into various systems and workflows. It supports custom templates and advanced features like charts, sub-reports, and conditional formatting to meet a wide range of business needs.', 'document-generation', ARRAY['Document Generation', 'Automation', 'Reporting', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "carbone/carbone-ee:full-5.4.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Carbone", "version": "latest", "description": "Carbone is a high-performance, self-hosted document generation engine. It allows you to generate reports, invoices, and documents in various formats (e.g., PDF, DOCX, XLSX) using JSON data and template-based rendering. Carbone is designed for scalability and speed, making it ideal for automation, bulk document generation, and seamless integration into various systems and workflows. It supports custom templates and advanced features like charts, sub-reports, and conditional formatting to meet a wide range of business needs.", "category": "document-generation", "tags": ["Document Generation", "Automation", "Reporting", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "carbone/carbone-ee:full-5.4.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4000}}, "links": [{"label": "Documentation", "url": "https://carbone.io/documentation/design/overview/getting-started.html"}, {"label": "Github", "url": "https://github.com/carboneio/carbone"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "carbone", "port": "$PORT:4000", "volumes": ["/app/template"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('castopod', 'Castopod', 'Castopod is an open-source hosting platform made for podcasters who want full control over their content. It provides a comprehensive solution for creating, managing, and distributing podcasts with features like built-in analytics, automatic RSS feed generation, and support for the ActivityPub protocol for social interactions. Castopod helps podcasters save time with automatic episode publishing to podcast platforms and social media. The platform includes powerful tools for audience engagement, SEO optimization, and monetization options. With its modern, intuitive interface, Castopod makes podcast hosting accessible while giving creators complete ownership of their content and audience data.', 'podcast', ARRAY['Podcast', 'Audio', 'Content Management', 'ActivityPub', 'Social', 'Podcast Hosting', 'Podcast Management', 'Podcast Player', 'Podcast Analytics', 'Podcast Social Media'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "castopod/castopod:1.15.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Castopod", "version": "latest", "description": "Castopod is an open-source hosting platform made for podcasters who want full control over their content. It provides a comprehensive solution for creating, managing, and distributing podcasts with features like built-in analytics, automatic RSS feed generation, and support for the ActivityPub protocol for social interactions. Castopod helps podcasters save time with automatic episode publishing to podcast platforms and social media. The platform includes powerful tools for audience engagement, SEO optimization, and monetization options. With its modern, intuitive interface, Castopod makes podcast hosting accessible while giving creators complete ownership of their content and audience data.", "category": "podcast", "tags": ["Podcast", "Audio", "Content Management", "ActivityPub", "Social", "Podcast Hosting", "Podcast Management", "Podcast Player", "Podcast Analytics", "Podcast Social Media"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "castopod/castopod:1.15.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}, "links": [{"label": "Website", "url": "https://castopod.org/"}, {"label": "Documentation", "url": "https://docs.castopod.org/"}, {"label": "Github", "url": "https://github.com/ad-aures/castopod"}], "instructions": "First install the application by going on this path \"/cp-install\"", "install": [{"docker": {"image": "$IMAGE", "name": "castopod", "port": "$PORT:8000", "volumes": ["/var/www/castopod/public/media"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "First install the application by going on this path \"/cp-install\""}, "services": {"mysql": {"type": "mysql", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('centrifugo', 'Centrifugo', 'Centrifugo is a scalable real-time messaging server that can be used to add real-time features to your applications. It supports WebSocket and SockJS connections, providing a robust solution for real-time communication.', 'real-time', ARRAY['Real-time', 'WebSocket', 'Messaging', 'Communication', 'Server'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "centrifugo/centrifugo:v6.7.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Centrifugo", "version": "latest", "description": "Centrifugo is a scalable real-time messaging server that can be used to add real-time features to your applications. It supports WebSocket and SockJS connections, providing a robust solution for real-time communication.", "category": "real-time", "tags": ["Real-time", "WebSocket", "Messaging", "Communication", "Server"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "centrifugo/centrifugo:v6.7.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}, "links": [{"label": "Website", "url": "https://centrifugal.dev/"}, {"label": "Documentation", "url": "https://centrifugal.dev/docs/getting-started/introduction"}, {"label": "GitHub", "url": "https://github.com/centrifugal/centrifugo"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "centrifugo", "port": "$PORT:8000", "volumes": ["/centrifugo/config.json"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('changedetection', 'Change Detection', 'Changedetection.io is an intelligent tool designed to monitor changes on websites. It is perfect for smart shoppers, data journalists, research engineers, data scientists, security researchers, and more. The app allows you to watch up to 5,000 URLs and supports over 85 notification formats. It is capable of monitoring simple changes on a website, like price alterations or restock notifications, to deep inspections such as PDF text changes, JSON and XML monitoring, and extensive text triggers. The app also features intelligent product restock detection, making it easier for you to keep track of product availability. Additionally, it can perform interactive browser steps such as filling in text boxes, clicking buttons, and setting up your change detection scenario. With Changedetection.io, you can live your data life proactively, receiving notifications straight away when changes occur on your watched websites.', 'monitoring', ARRAY['Monitoring', 'Data', 'Notifications'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/dgtlmoon/changedetection.io:0.55.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Change Detection", "version": "latest", "description": "Changedetection.io is an intelligent tool designed to monitor changes on websites. It is perfect for smart shoppers, data journalists, research engineers, data scientists, security researchers, and more. The app allows you to watch up to 5,000 URLs and supports over 85 notification formats. It is capable of monitoring simple changes on a website, like price alterations or restock notifications, to deep inspections such as PDF text changes, JSON and XML monitoring, and extensive text triggers. The app also features intelligent product restock detection, making it easier for you to keep track of product availability. Additionally, it can perform interactive browser steps such as filling in text boxes, clicking buttons, and setting up your change detection scenario. With Changedetection.io, you can live your data life proactively, receiving notifications straight away when changes occur on your watched websites.", "category": "monitoring", "tags": ["Monitoring", "Data", "Notifications"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/dgtlmoon/changedetection.io:0.55.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5000}}, "links": [{"label": "Website", "url": "https://changedetection.io"}, {"label": "Github", "url": "https://github.com/dgtlmoon/changedetection.io"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "changedetection", "port": "$PORT:5000", "volumes": ["/datastore"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('changerawr', 'Changerawr', 'Changerawr is a modern, open-source change management platform designed to help organizations track, manage, and implement changes efficiently. Built with Next.js and PostgreSQL, it provides a comprehensive solution for change requests, approval workflows, impact assessment, and rollback procedures. The platform features real-time collaboration, automated notifications, audit trails, and detailed reporting capabilities. Perfect for DevOps teams, IT departments, and organizations that need to maintain control over their change management processes while ensuring transparency and accountability.', 'change-management', ARRAY['Change Management', 'DevOps', 'Project Management', 'Workflow', 'Compliance'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/supernova3339/changerawr:v1.0.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Changerawr", "version": "latest", "description": "Changerawr is a modern, open-source change management platform designed to help organizations track, manage, and implement changes efficiently. Built with Next.js and PostgreSQL, it provides a comprehensive solution for change requests, approval workflows, impact assessment, and rollback procedures. The platform features real-time collaboration, automated notifications, audit trails, and detailed reporting capabilities. Perfect for DevOps teams, IT departments, and organizations that need to maintain control over their change management processes while ensuring transparency and accountability.", "category": "change-management", "tags": ["Change Management", "DevOps", "Project Management", "Workflow", "Compliance"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/supernova3339/changerawr:v1.0.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://github.com/supernova3339/changerawr"}, {"label": "Github", "url": "https://github.com/supernova3339/changerawr"}, {"label": "Documentation", "url": "https://github.com/supernova3339/changerawr#readme"}], "instructions": "To enable automatic updates for Changerawr, configure the Easypanel Project ID, Service ID, panel URL and API token in Environment Variables of Changerawr App Service. These configurations allow the system to automatically detect and apply new updates. Make sure not to use CloudFlare Zero Trust, that will causes issues.", "install": [{"docker": {"image": "$IMAGE", "name": "changerawr", "port": "$PORT:3000", "volumes": ["/app/data", "/app/uploads", "/app/public/generated"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "To enable automatic updates for Changerawr, configure the Easypanel Project ID, Service ID, panel URL and API token in Environment Variables of Changerawr App Service. These configurations allow the system to automatically detect and apply new updates. Make sure not to use CloudFlare Zero Trust, that will causes issues."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('chartdb', 'ChartDB', 'ChartDB is an open-source, web-based database diagramming editor that enables you to visualize and manage database schemas through interactive diagrams. Create entity-relationship diagrams (ERDs) instantly by connecting to your databases and automatically generating visual representations of your schema. The application supports instant schema visualization using a single query and offers AI-powered features through OpenAI integration for intelligent SQL export and schema management. ChartDB provides an intuitive interface for understanding complex database structures, making it perfect for developers, database administrators, and teams who need to document and communicate database designs. With its modern web-based approach, you can access your database diagrams from anywhere and collaborate effectively on database architecture without installing desktop software.', 'database', ARRAY['Database', 'Diagram', 'ERD', 'Visualization', 'Schema', 'Self-Hosted', 'AI', 'Design Tool', 'Documentation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/chartdb/chartdb:1.20.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "ChartDB", "version": "latest", "description": "ChartDB is an open-source, web-based database diagramming editor that enables you to visualize and manage database schemas through interactive diagrams. Create entity-relationship diagrams (ERDs) instantly by connecting to your databases and automatically generating visual representations of your schema. The application supports instant schema visualization using a single query and offers AI-powered features through OpenAI integration for intelligent SQL export and schema management. ChartDB provides an intuitive interface for understanding complex database structures, making it perfect for developers, database administrators, and teams who need to document and communicate database designs. With its modern web-based approach, you can access your database diagrams from anywhere and collaborate effectively on database architecture without installing desktop software.", "category": "database", "tags": ["Database", "Diagram", "ERD", "Visualization", "Schema", "Self-Hosted", "AI", "Design Tool", "Documentation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/chartdb/chartdb:1.20.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://chartdb.io"}, {"label": "GitHub", "url": "https://github.com/chartdb/chartdb"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "chartdb", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('chatchat', 'ChatChat', 'ChatChat is a simple chat application built on modern technologies. It provides a lightweight and responsive chat interface for real-time communication.', 'chat', ARRAY['Chat', 'Communication', 'Web Application'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/okisdev/chatchat:0.1.9"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "ChatChat", "version": "latest", "description": "ChatChat is a simple chat application built on modern technologies. It provides a lightweight and responsive chat interface for real-time communication.", "category": "chat", "tags": ["Chat", "Communication", "Web Application"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/okisdev/chatchat:0.1.9"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "GitHub", "url": "https://github.com/okisdev/chatchat"}, {"label": "Website", "url": "https://chat.okis.dev"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "chatchat", "port": "$PORT:3000", "volumes": ["/app/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('chatgpt-next-web', 'ChatGPT Next Web', 'ChatGPT Next Web is a well-designed, feature-rich web interface for ChatGPT and other LLMs. It provides a clean and intuitive interface for interacting with OpenAI''s ChatGPT, with support for multiple conversation modes, custom prompts, and various AI models. The application is self-hosted, allowing you to maintain control over your conversations and API usage while providing a superior user experience compared to the official ChatGPT web interface.', 'chatgpt', ARRAY['ChatGPT', 'AI', 'OpenAI', 'LLM', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "yidadaa/chatgpt-next-web:v2.16.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "ChatGPT Next Web", "version": "latest", "description": "ChatGPT Next Web is a well-designed, feature-rich web interface for ChatGPT and other LLMs. It provides a clean and intuitive interface for interacting with OpenAI's ChatGPT, with support for multiple conversation modes, custom prompts, and various AI models. The application is self-hosted, allowing you to maintain control over your conversations and API usage while providing a superior user experience compared to the official ChatGPT web interface.", "category": "chatgpt", "tags": ["ChatGPT", "AI", "OpenAI", "LLM", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "yidadaa/chatgpt-next-web:v2.16.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Documentation", "url": "https://github.com/ChatGPTNextWeb/ChatGPT-Next-Web#readme"}, {"label": "GitHub", "url": "https://github.com/ChatGPTNextWeb/ChatGPT-Next-Web"}, {"label": "Website", "url": "https://nextchat.club/login"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "chatgpt-next-web", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('chatpad', 'Chatpad', 'Chatpad AI is a premium quality user interface for ChatGPT, designed to provide the ultimate chatting experience. It''s not just another ChatGPT interface, but a broader vision to revolutionize the way users interact with ChatGPT. The app is free and open-source, with its source code readily available on GitHub for anyone interested. Privacy is a top priority in Chatpad AI, with no tracking, no cookies, and all data being stored locally. The app is crafted with love and care, ensuring the best possible experience for its users. It''s available as a web app and a desktop app, providing flexibility and convenience. Chatpad AI is also self-hostable using Docker, giving users full control over their data and usage.', 'chat', ARRAY['Chat', 'Privacy', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/deiucanta/chatpad"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Chatpad", "version": "latest", "description": "Chatpad AI is a premium quality user interface for ChatGPT, designed to provide the ultimate chatting experience. It's not just another ChatGPT interface, but a broader vision to revolutionize the way users interact with ChatGPT. The app is free and open-source, with its source code readily available on GitHub for anyone interested. Privacy is a top priority in Chatpad AI, with no tracking, no cookies, and all data being stored locally. The app is crafted with love and care, ensuring the best possible experience for its users. It's available as a web app and a desktop app, providing flexibility and convenience. Chatpad AI is also self-hostable using Docker, giving users full control over their data and usage.", "category": "chat", "tags": ["Chat", "Privacy", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/deiucanta/chatpad"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://chatpad.ai"}, {"label": "Github", "url": "https://github.com/deiucanta/chatpad"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "chatpad", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('chatwoot', 'Chatwoot', 'Chatwoot is a new age multi-channel customer experience platform designed for businesses of all sizes. It serves as an open-source customer engagement suite, providing an alternative to platforms like Intercom, Zendesk, and Salesforce Service Cloud. With Chatwoot, you can manage your agents'' workload, track their performance through auto-updating reports, and work smarter with automations. The app allows you to perform key actions on multiple conversations at once and provides super quick responses to customer conversations, making your agents super productive. It also offers features to manage your email, Facebook, Instagram, Line, SMS, Telegram, and Twitter customer interactions directly from the platform. Additionally, Chatwoot provides detailed insights into your conversations and allows you to measure and track your CSAT score on autopilot.', 'chat', ARRAY['Chat', 'Customer Support'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "chatwoot/chatwoot:v4.13.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Chatwoot", "version": "latest", "description": "Chatwoot is a new age multi-channel customer experience platform designed for businesses of all sizes. It serves as an open-source customer engagement suite, providing an alternative to platforms like Intercom, Zendesk, and Salesforce Service Cloud. With Chatwoot, you can manage your agents' workload, track their performance through auto-updating reports, and work smarter with automations. The app allows you to perform key actions on multiple conversations at once and provides super quick responses to customer conversations, making your agents super productive. It also offers features to manage your email, Facebook, Instagram, Line, SMS, Telegram, and Twitter customer interactions directly from the platform. Additionally, Chatwoot provides detailed insights into your conversations and allows you to measure and track your CSAT score on autopilot.", "category": "chat", "tags": ["Chat", "Customer Support"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "chatwoot/chatwoot:v4.13.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Documentation", "url": "https://www.chatwoot.com/help-center"}, {"label": "Github", "url": "https://github.com/chatwoot/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "chatwoot", "port": "$PORT:3000", "volumes": ["/data/storage", "/app/storage", "/app/storage"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('checkmate', 'Checkmate', 'Checkmate is a modern, open-source uptime monitoring solution designed to keep track of your websites, APIs, and services. Built with a focus on simplicity and reliability, it provides real-time monitoring capabilities with instant notifications when your services go down. The application features a clean, intuitive dashboard that displays the current status of all monitored services, historical uptime data, and detailed analytics. Perfect for businesses, developers, and system administrators who need to ensure their digital services remain accessible to users.', 'monitoring', ARRAY['Monitoring', 'Uptime', 'Analytics', 'DevOps'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/bluewave-labs/checkmate-backend-mono:v3.6.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 52345}}$JSON$::jsonb, $JSON${"metadata": {"name": "Checkmate", "version": "latest", "description": "Checkmate is a modern, open-source uptime monitoring solution designed to keep track of your websites, APIs, and services. Built with a focus on simplicity and reliability, it provides real-time monitoring capabilities with instant notifications when your services go down. The application features a clean, intuitive dashboard that displays the current status of all monitored services, historical uptime data, and detailed analytics. Perfect for businesses, developers, and system administrators who need to ensure their digital services remain accessible to users.", "category": "monitoring", "tags": ["Monitoring", "Uptime", "Analytics", "DevOps"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/bluewave-labs/checkmate-backend-mono:v3.6.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 52345}}, "links": [{"label": "Github", "url": "https://github.com/bluewave-labs/checkmate"}, {"label": "Documentation", "url": "https://github.com/bluewave-labs/checkmate#readme"}, {"label": "Website", "url": "https://checkmate.so"}], "instructions": "Go to the /register path to register your user.", "install": [{"docker": {"image": "$IMAGE", "name": "checkmate", "port": "$PORT:52345", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Go to the /register path to register your user."}, "services": {"redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('chevereto', 'Chevereto', 'Chevereto is a powerful, self-hosted image and video hosting platform designed for individuals, communities, and businesses. It allows users to upload, organize, and share media effortlessly. With a clean interface and a wide range of customization options, Chevereto supports private albums, multi-language capabilities, and robust file management, making it the ultimate solution for image and video hosting.', 'image-hosting', ARRAY['Image Hosting', 'File Management', 'Open Source', 'Multi-User', 'Private Albums'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "chevereto/chevereto:4.5.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Chevereto", "version": "latest", "description": "Chevereto is a powerful, self-hosted image and video hosting platform designed for individuals, communities, and businesses. It allows users to upload, organize, and share media effortlessly. With a clean interface and a wide range of customization options, Chevereto supports private albums, multi-language capabilities, and robust file management, making it the ultimate solution for image and video hosting.", "category": "image-hosting", "tags": ["Image Hosting", "File Management", "Open Source", "Multi-User", "Private Albums"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "chevereto/chevereto:4.5.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Github", "url": "https://github.com/chevereto/chevereto"}, {"label": "Documentation", "url": "https://v4-docs.chevereto.com/"}, {"label": "Demo", "url": "https://demo.chevereto.com/"}], "instructions": "Open the nginx domain to access Chevereto", "install": [{"docker": {"image": "$IMAGE", "name": "chevereto", "port": "$PORT:8080", "volumes": ["/var/www/html/images/"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Open the nginx domain to access Chevereto"}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('chiefonboarding', 'Chief-Onboarding', 'Chief-Onboarding is a comprehensive, self-hosted onboarding and employee management platform designed for businesses to streamline their onboarding processes. It allows organizations to manage employee onboarding, document collection, and task tracking efficiently. With a clean interface and robust customization options, Chief-Onboarding supports role-based access, multi-language capabilities, and seamless integration with existing HR systems, making it the ultimate solution for employee onboarding.', 'employee-onboarding', ARRAY['Employee Onboarding', 'HR Management', 'Task Tracking', 'Role-Based Access', 'Document Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "chiefonboarding/chiefonboarding:v2.4.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Chief-Onboarding", "version": "latest", "description": "Chief-Onboarding is a comprehensive, self-hosted onboarding and employee management platform designed for businesses to streamline their onboarding processes. It allows organizations to manage employee onboarding, document collection, and task tracking efficiently. With a clean interface and robust customization options, Chief-Onboarding supports role-based access, multi-language capabilities, and seamless integration with existing HR systems, making it the ultimate solution for employee onboarding.", "category": "employee-onboarding", "tags": ["Employee Onboarding", "HR Management", "Task Tracking", "Role-Based Access", "Document Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "chiefonboarding/chiefonboarding:v2.4.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}, "links": [{"label": "Github", "url": "https://github.com/chiefonboarding/chiefonboarding"}, {"label": "Documentation", "url": "https://docs.chiefonboarding.com/"}, {"label": "Demo", "url": "https://demo.chiefonboarding.com/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "chiefonboarding", "port": "$PORT:8000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('chromium', 'Chromium', 'Chromium is an open-source browser project that is designed to provide a safer, faster, and more stable way for all users to experience the web. This app is a Docker containerized version of Chromium, allowing you to deploy and run the Chromium browser in a Docker environment. The app supports multiple architectures, including x86-64 and arm64, and can be accessed via HTTP or HTTPS. It offers additional environment variables and run configurations to enable or disable specific functionality. The app also allows you to specify one or multiple Chromium CLI flags, which will be passed to the application in full. This containerized version of Chromium is designed to function efficiently with modern websites, and includes options for GPU acceleration and Docker in Docker (DinD) setup.', 'developer-tools', ARRAY['Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/chromium:version-1aac4eaa"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Chromium", "version": "latest", "description": "Chromium is an open-source browser project that is designed to provide a safer, faster, and more stable way for all users to experience the web. This app is a Docker containerized version of Chromium, allowing you to deploy and run the Chromium browser in a Docker environment. The app supports multiple architectures, including x86-64 and arm64, and can be accessed via HTTP or HTTPS. It offers additional environment variables and run configurations to enable or disable specific functionality. The app also allows you to specify one or multiple Chromium CLI flags, which will be passed to the application in full. This containerized version of Chromium is designed to function efficiently with modern websites, and includes options for GPU acceleration and Docker in Docker (DinD) setup.", "category": "developer-tools", "tags": ["Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/chromium:version-1aac4eaa"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Documentation", "url": "https://docs.linuxserver.io/images/docker-chromium"}, {"label": "Github", "url": "https://github.com/linuxserver/docker-chromium"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "chromium", "port": "$PORT:3000", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('cinephage', 'Cinephage', 'Cinephage is a self-hosted media management and streaming application designed for organizing and accessing your movie and TV show collection. It provides a modern web interface for browsing your media library, with features like metadata management, watch tracking, and streaming capabilities. Built with privacy and self-hosting in mind, Cinephage gives you complete control over your media collection without relying on external services.', 'media', ARRAY['Media', 'Streaming', 'Movies', 'TV Shows', 'Self-Hosted', 'Plex Alternative'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/moldytaint/cinephage:sha-7e755e4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Cinephage", "version": "latest", "description": "Cinephage is a self-hosted media management and streaming application designed for organizing and accessing your movie and TV show collection. It provides a modern web interface for browsing your media library, with features like metadata management, watch tracking, and streaming capabilities. Built with privacy and self-hosting in mind, Cinephage gives you complete control over your media collection without relying on external services.", "category": "media", "tags": ["Media", "Streaming", "Movies", "TV Shows", "Self-Hosted", "Plex Alternative"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/moldytaint/cinephage:sha-7e755e4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "GitHub", "url": "https://github.com/moldytaint/cinephage"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "cinephage", "port": "$PORT:3000", "volumes": ["/app/data", "/app/logs", "/media"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('claper', 'Claper', 'Claper is an interactive presentation platform that transforms passive presentations into engaging, real-time experiences.  With Claper, presenters can create interactive presentations that allow audience members to participate through live polls,  Q&A sessions, reactions, and more. The platform offers seamless integration with popular presentation tools and provides  real-time analytics to help presenters understand audience engagement. Claper supports various presentation formats,  file uploads, and customizable branding options, making it perfect for conferences, webinars, educational sessions,  and corporate meetings.', 'presentation', ARRAY['Presentation', 'Interactive', 'Collaboration', 'Analytics'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/claperco/claper:2.4.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Claper", "version": "latest", "description": "Claper is an interactive presentation platform that transforms passive presentations into engaging, real-time experiences.  With Claper, presenters can create interactive presentations that allow audience members to participate through live polls,  Q&A sessions, reactions, and more. The platform offers seamless integration with popular presentation tools and provides  real-time analytics to help presenters understand audience engagement. Claper supports various presentation formats,  file uploads, and customizable branding options, making it perfect for conferences, webinars, educational sessions,  and corporate meetings.", "category": "presentation", "tags": ["Presentation", "Interactive", "Collaboration", "Analytics"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/claperco/claper:2.4.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4000}}, "links": [{"label": "Website", "url": "https://claper.co/"}, {"label": "Documentation", "url": "https://docs.claper.co/"}, {"label": "Github", "url": "https://github.com/ClaperCo/Claper"}], "instructions": "Click Login on the top right corner and register a new account.", "install": [{"docker": {"image": "$IMAGE", "name": "claper", "port": "$PORT:4000", "volumes": ["/app/uploads"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Click Login on the top right corner and register a new account."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('classicpress', 'ClassicPress', 'ClassicPress is a community-led open source content management system for creators. It is a fork of WordPress 6.2 that preserves the TinyMCE classic editor as the default option. It is half the size of WordPress, contains less bloat improving performance, and has no block editor (Gutenberg/Full Site Editing).', 'content-management', ARRAY['Content Management', 'Developer Tools', 'Open Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "classicpress/classicpress:php8.5-apache"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "ClassicPress", "version": "latest", "description": "ClassicPress is a community-led open source content management system for creators. It is a fork of WordPress 6.2 that preserves the TinyMCE classic editor as the default option. It is half the size of WordPress, contains less bloat improving performance, and has no block editor (Gutenberg/Full Site Editing).", "category": "content-management", "tags": ["Content Management", "Developer Tools", "Open Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "classicpress/classicpress:php8.5-apache"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://www.classicpress.net/"}, {"label": "Documentation", "url": "https://docs.classicpress.net/"}, {"label": "Github", "url": "https://github.com/ClassicPress/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "classicpress", "port": "$PORT:80", "volumes": ["/var/www/html"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('clickhouse', 'Clickhouse', 'ClickHouse is an open-source database designed for real-time apps and analytics. It is renowned for its speed and resource efficiency, capable of querying billions of rows in mere milliseconds. ClickHouse supports a wide range of data sources, including databases, data warehouses, streams, logs, analytics, data lake formats, and local files. It is built on a column-oriented database structure, which is ideally suited to Online Analytical Processing (OLAP) scenarios, making it significantly faster in processing most queries. ClickHouse utilizes all available system resources to their full potential to process each analytical query as swiftly as possible. It can be deployed in any environment, whether on your machine or in the cloud, and offers the ability to run fast queries on local files without a server. ClickHouse is trusted by developers working with data at scale, including major companies like Disney+ and Uber.', 'databases', ARRAY['Databases', 'Analytics'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "clickhouse/clickhouse-server:26.3.9.8"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8123}}$JSON$::jsonb, $JSON${"metadata": {"name": "Clickhouse", "version": "latest", "description": "ClickHouse is an open-source database designed for real-time apps and analytics. It is renowned for its speed and resource efficiency, capable of querying billions of rows in mere milliseconds. ClickHouse supports a wide range of data sources, including databases, data warehouses, streams, logs, analytics, data lake formats, and local files. It is built on a column-oriented database structure, which is ideally suited to Online Analytical Processing (OLAP) scenarios, making it significantly faster in processing most queries. ClickHouse utilizes all available system resources to their full potential to process each analytical query as swiftly as possible. It can be deployed in any environment, whether on your machine or in the cloud, and offers the ability to run fast queries on local files without a server. ClickHouse is trusted by developers working with data at scale, including major companies like Disney+ and Uber.", "category": "databases", "tags": ["Databases", "Analytics"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "clickhouse/clickhouse-server:26.3.9.8"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8123}}, "links": [{"label": "Website", "url": "https://clickhouse.com/"}, {"label": "Documentation", "url": "https://clickhouse.com/docs"}, {"label": "Github", "url": "https://github.com/ClickHouse/ClickHouse"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "clickhouse", "port": "$PORT:8123", "volumes": ["/var/lib/clickhouse", "/etc/clickhouse-server/users.d/logging.xml", "/etc/clickhouse-server/config.d/logging.xml"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('cloud9', 'Cloud9', 'Cloud9 is a cloud-based integrated development environment (IDE) designed for developers to code, build, and debug applications collaboratively in real time. It supports a wide range of programming languages and provides a full-featured development environment directly in the browser. Cloud9 allows developers to work on their projects from anywhere, using any device, with the power of a full Linux server behind it. It includes features like built-in terminal, code editor, and support for debugging and running applications seamlessly. Cloud9 is trusted by developers for its efficiency, collaboration tools, and ability to streamline the development workflow.', 'ide', ARRAY['IDE', 'Development', 'Cloud-Based'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/cloud9:1.29.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Cloud9", "version": "latest", "description": "Cloud9 is a cloud-based integrated development environment (IDE) designed for developers to code, build, and debug applications collaboratively in real time. It supports a wide range of programming languages and provides a full-featured development environment directly in the browser. Cloud9 allows developers to work on their projects from anywhere, using any device, with the power of a full Linux server behind it. It includes features like built-in terminal, code editor, and support for debugging and running applications seamlessly. Cloud9 is trusted by developers for its efficiency, collaboration tools, and ability to streamline the development workflow.", "category": "ide", "tags": ["IDE", "Development", "Cloud-Based"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/cloud9:1.29.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}, "links": [{"label": "Website", "url": "https://aws.amazon.com/cloud9/"}, {"label": "Documentation", "url": "https://docs.aws.amazon.com/cloud9/"}, {"label": "Github", "url": "https://github.com/c9"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "cloud9", "port": "$PORT:8000", "volumes": ["/var/run/docker.sock", "/code"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('cloudbeaver', 'CloudBeaver', 'CloudBeaver is a web-based database management tool developed by DBeaver team. It provides a modern, intuitive interface for managing databases through your web browser. CloudBeaver supports multiple database types including PostgreSQL, MySQL, MariaDB, SQLite, Oracle, SQL Server, and many others. Perfect for teams who need collaborative database management without installing desktop software.', 'database', ARRAY['Database', 'SQL', 'Management', 'Web Interface', 'PostgreSQL', 'MySQL', 'Oracle', 'Development', 'Analytics', 'Team Collaboration'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "dbeaver/cloudbeaver:26.0.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8978}}$JSON$::jsonb, $JSON${"metadata": {"name": "CloudBeaver", "version": "latest", "description": "CloudBeaver is a web-based database management tool developed by DBeaver team. It provides a modern, intuitive interface for managing databases through your web browser. CloudBeaver supports multiple database types including PostgreSQL, MySQL, MariaDB, SQLite, Oracle, SQL Server, and many others. Perfect for teams who need collaborative database management without installing desktop software.", "category": "database", "tags": ["Database", "SQL", "Management", "Web Interface", "PostgreSQL", "MySQL", "Oracle", "Development", "Analytics", "Team Collaboration"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "dbeaver/cloudbeaver:26.0.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8978}}, "links": [{"label": "Website", "url": "https://cloudbeaver.io/"}, {"label": "Documentation", "url": "https://github.com/dbeaver/cloudbeaver/wiki"}, {"label": "GitHub", "url": "https://github.com/dbeaver/cloudbeaver"}], "instructions": "On first launch, a setup wizard will guide you to create an administrator account and configure the server. After completing the wizard, log in with the credentials you created.", "install": [{"docker": {"image": "$IMAGE", "name": "cloudbeaver", "port": "$PORT:8978", "volumes": ["/opt/cloudbeaver/workspace"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "On first launch, a setup wizard will guide you to create an administrator account and configure the server. After completing the wizard, log in with the credentials you created."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('cloudcommander', 'Cloud Commander', 'Cloud Commander is a file manager for the web. It includes a command-line console and a text editor. Cloud Commander helps you manage your server and work with files, directories and programs in a web browser from any computer, mobile or tablet.', 'self-hosted', ARRAY[]::text[], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "coderaiser/cloudcmd:19.15.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Cloud Commander", "version": "latest", "description": "Cloud Commander is a file manager for the web. It includes a command-line console and a text editor. Cloud Commander helps you manage your server and work with files, directories and programs in a web browser from any computer, mobile or tablet.", "category": "self-hosted", "tags": [], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "coderaiser/cloudcmd:19.15.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://cloudcmd.io"}, {"label": "Github", "url": "https://github.com/coderaiser/cloudcmd"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "cloudcommander", "port": "$PORT:80", "volumes": ["/root", "/mnt/fs"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('cloudreve', 'Cloudreve', 'Cloudreve is a self-hosted cloud storage platform that allows you to build your own file hosting and sharing service with support for multiple storage backends. Designed as a powerful alternative to commercial cloud storage services, Cloudreve provides a feature-rich web interface for uploading, organizing, and sharing files with complete control over your data. The application supports various storage providers including local storage, remote servers, OneDrive, S3-compatible storage, and more, allowing you to leverage existing infrastructure or cloud services as backends. Key features include drag-and-drop uploads, file previews for images, videos, and documents, shareable download links with optional password protection and expiration dates, and WebDAV support for seamless integration with desktop and mobile applications. Cloudreve offers user management with customizable storage quotas, group permissions, and file policies to control how users interact with the system. The modern, responsive interface works across devices, providing a smooth experience whether accessing from desktop or mobile. Built with performance in mind, Cloudreve uses PostgreSQL for reliable data storage and Redis for caching, ensuring fast and responsive file operations. Perfect for individuals wanting private cloud storage, teams needing collaborative file sharing, organizations requiring self-hosted file management, or anyone seeking an alternative to commercial cloud storage with complete data ownership and privacy.', 'cloud-storage', ARRAY['Cloud Storage', 'File Sharing', 'File Management', 'Self-Hosted', 'Storage', 'Collaboration'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "cloudreve/cloudreve:4.15.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5212}}$JSON$::jsonb, $JSON${"metadata": {"name": "Cloudreve", "version": "latest", "description": "Cloudreve is a self-hosted cloud storage platform that allows you to build your own file hosting and sharing service with support for multiple storage backends. Designed as a powerful alternative to commercial cloud storage services, Cloudreve provides a feature-rich web interface for uploading, organizing, and sharing files with complete control over your data. The application supports various storage providers including local storage, remote servers, OneDrive, S3-compatible storage, and more, allowing you to leverage existing infrastructure or cloud services as backends. Key features include drag-and-drop uploads, file previews for images, videos, and documents, shareable download links with optional password protection and expiration dates, and WebDAV support for seamless integration with desktop and mobile applications. Cloudreve offers user management with customizable storage quotas, group permissions, and file policies to control how users interact with the system. The modern, responsive interface works across devices, providing a smooth experience whether accessing from desktop or mobile. Built with performance in mind, Cloudreve uses PostgreSQL for reliable data storage and Redis for caching, ensuring fast and responsive file operations. Perfect for individuals wanting private cloud storage, teams needing collaborative file sharing, organizations requiring self-hosted file management, or anyone seeking an alternative to commercial cloud storage with complete data ownership and privacy.", "category": "cloud-storage", "tags": ["Cloud Storage", "File Sharing", "File Management", "Self-Hosted", "Storage", "Collaboration"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "cloudreve/cloudreve:4.15.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5212}}, "links": [{"label": "Website", "url": "https://cloudreve.org"}, {"label": "GitHub", "url": "https://github.com/cloudreve/Cloudreve"}, {"label": "Documentation", "url": "https://docs.cloudreve.org"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "cloudreve", "port": "$PORT:5212", "volumes": ["/cloudreve/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('cockpit', 'Cockpit', 'Cockpit is a headless content platform designed to streamline the creation, connection, and delivery of content for creators, marketers, and developers. It is built with an API-first approach, enabling limitless digital solutions. Cockpit offers a range of features including a content hub, multichannel localization, roles & permissions, and revisions. It also comes with a set of ready-to-use addons to support your projects. These include flexible structured content models, an assets manager, SEO and menu routes, content migration, custom action triggers, component-based layouts, full-text search for your content, form submissions collection, and localization. Cockpit is designed to fit your favorite tech stack, making it a versatile tool for all your content needs.', 'cms', ARRAY['CMS'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "cockpithq/cockpit:core-2.14.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Cockpit", "version": "latest", "description": "Cockpit is a headless content platform designed to streamline the creation, connection, and delivery of content for creators, marketers, and developers. It is built with an API-first approach, enabling limitless digital solutions. Cockpit offers a range of features including a content hub, multichannel localization, roles & permissions, and revisions. It also comes with a set of ready-to-use addons to support your projects. These include flexible structured content models, an assets manager, SEO and menu routes, content migration, custom action triggers, component-based layouts, full-text search for your content, form submissions collection, and localization. Cockpit is designed to fit your favorite tech stack, making it a versatile tool for all your content needs.", "category": "cms", "tags": ["CMS"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "cockpithq/cockpit:core-2.14.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://getcockpit.com"}, {"label": "Documentation", "url": "https://getcockpit.com/documentation"}, {"label": "Github", "url": "https://github.com/Cockpit-HQ"}], "instructions": "Navigate to /install to create the initial user account.", "install": [{"docker": {"image": "$IMAGE", "name": "cockpit", "port": "$PORT:80", "volumes": ["/var/www/html", "/var/www/html/storage/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Navigate to /install to create the initial user account."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('coder', 'Coder', 'Coder is an open source cloud development environment (CDE) that you download and host in your cloud. Deploy a single solution in seconds that provisions the infrastructure, IDE, language, and tools your developers desire. Upgrade to the Enterprise version and add security, governance, and observability capabilities for Platform teams.', 'self-hosted', ARRAY[]::text[], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/coder/coder:v2.31.10"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Coder", "version": "latest", "description": "Coder is an open source cloud development environment (CDE) that you download and host in your cloud. Deploy a single solution in seconds that provisions the infrastructure, IDE, language, and tools your developers desire. Upgrade to the Enterprise version and add security, governance, and observability capabilities for Platform teams.", "category": "self-hosted", "tags": [], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/coder/coder:v2.31.10"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://coder.com"}, {"label": "Documentation", "url": "https://coder.com/docs/v2/latest"}, {"label": "Github", "url": "https://github.com/coder/coder"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "coder", "port": "$PORT:80", "volumes": ["/var/run/docker.sock", "/home/coder/.config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('codex-docs', 'CodeX Docs', 'CodeX is a comprehensive platform that brings together passionate engineers, designers, students, graduates, and young specialists from around the globe. The app is dedicated to creating high-quality open-source projects and providing a valuable experience of developing full-fledged products for the global market. CodeX offers a range of products including Editor.js, a block-styled, API-oriented editor for media that generates useful JSON-output with clear data, Hawk.so, a fast and lightweight error tracking service, and CodeX Notes, a simple and fast cross-platform notes application based on Editor.js and Electron. The platform also offers Capella, a cloud service for image storage and delivery, and a platform for integration of services into messengers. With a focus on media, social networks, education, augmented reality, and medicine, CodeX is a one-stop solution for tech enthusiasts looking to make a mark in the global market.', 'developer-tools', ARRAY['Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/codex-team/codex.docs:v2.2.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "CodeX Docs", "version": "latest", "description": "CodeX is a comprehensive platform that brings together passionate engineers, designers, students, graduates, and young specialists from around the globe. The app is dedicated to creating high-quality open-source projects and providing a valuable experience of developing full-fledged products for the global market. CodeX offers a range of products including Editor.js, a block-styled, API-oriented editor for media that generates useful JSON-output with clear data, Hawk.so, a fast and lightweight error tracking service, and CodeX Notes, a simple and fast cross-platform notes application based on Editor.js and Electron. The platform also offers Capella, a cloud service for image storage and delivery, and a platform for integration of services into messengers. With a focus on media, social networks, education, augmented reality, and medicine, CodeX is a one-stop solution for tech enthusiasts looking to make a mark in the global market.", "category": "developer-tools", "tags": ["Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/codex-team/codex.docs:v2.2.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://codex.so"}, {"label": "Documentation", "url": "https://docs.codex.so"}, {"label": "Github", "url": "https://github.com/codex-team/codex.docs"}], "instructions": "View All Configuation on the Docs site - https://docs.codex.so/configuration", "install": [{"docker": {"image": "$IMAGE", "name": "codex-docs", "port": "$PORT:3000", "volumes": ["/usr/src/app/uploads", "/usr/src/app/db", "/usr/src/app/docs-config.yaml"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "View All Configuation on the Docs site - https://docs.codex.so/configuration"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('collabora-office', 'Collabora Office', 'Collabora Online is a powerful, flexible, and secure online office suite designed to break free from vendor lock-in and put you in full control of your documents. It offers a private office suite in the cloud, compatible with trillions of existing documents, and can be integrated into your own infrastructure or accessed via one of our trusted hosting partners. It is excellent for enterprises that need a powerful office suite in the cloud, or on-premise, that protects their privacy and allows them to keep full control of their sensitive corporate data. Collabora Online offers a range of business benefits that support collaboration and productivity whilst maintaining your digital sovereignty and keeping your corporate documents secure. It includes a text document editor, a spreadsheet tool, a presentation creator, and a drawing tool, all designed to provide a true WYSIWYG editing experience and make visualising your document layout incredibly easy. You can open any document, add comments, track changes, format and style your pages, create spreadsheets with advanced formulas, design attractive presentations, and draw shapes and diagrams with ease. Collabora Online is fully open source, offering native integration in Android and iOS, and prioritizing privacy by default.', 'documents', ARRAY['Documents', 'Productivity', 'Privacy'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "collabora/code:25.04.9.4.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9980}}$JSON$::jsonb, $JSON${"metadata": {"name": "Collabora Office", "version": "latest", "description": "Collabora Online is a powerful, flexible, and secure online office suite designed to break free from vendor lock-in and put you in full control of your documents. It offers a private office suite in the cloud, compatible with trillions of existing documents, and can be integrated into your own infrastructure or accessed via one of our trusted hosting partners. It is excellent for enterprises that need a powerful office suite in the cloud, or on-premise, that protects their privacy and allows them to keep full control of their sensitive corporate data. Collabora Online offers a range of business benefits that support collaboration and productivity whilst maintaining your digital sovereignty and keeping your corporate documents secure. It includes a text document editor, a spreadsheet tool, a presentation creator, and a drawing tool, all designed to provide a true WYSIWYG editing experience and make visualising your document layout incredibly easy. You can open any document, add comments, track changes, format and style your pages, create spreadsheets with advanced formulas, design attractive presentations, and draw shapes and diagrams with ease. Collabora Online is fully open source, offering native integration in Android and iOS, and prioritizing privacy by default.", "category": "documents", "tags": ["Documents", "Productivity", "Privacy"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "collabora/code:25.04.9.4.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9980}}, "links": [{"label": "Website", "url": "https://collaboraonline.com"}, {"label": "Documentation", "url": "https://sdk.collaboraonline.com/docs"}, {"label": "Github", "url": "https://github.com/CollaboraOnline"}], "instructions": "Access the admin console at https://<domain>/browser/dist/admin/admin.html", "install": [{"docker": {"image": "$IMAGE", "name": "collabora-office", "port": "$PORT:9980", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Access the admin console at https://<domain>/browser/dist/admin/admin.html"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('commento', 'Commento', 'Commento is a comments widget designed to enhance the interaction on your website. It allows your readers to contribute to the discussion by upvoting comments that add value and downvoting those that don''t. The widget supports markdown formatting, enabling bold, italics, external links, quotes, bullet points, code, and more. Commento also provides moderation tools to manage the conversation, allowing you to lock heated threads, remove off-topic comments, and enforce timeouts. It features a spam detection system, saving you the hassle of dealing with spammers. The widget supports nested replies, making discussions easier to follow. Importantly, Commento does not require your readers to sign up, reducing friction and encouraging more interaction. You can easily customize the look of the widget to match your website''s aesthetics.', 'comments', ARRAY['Comments', 'Discussion', 'Website'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "registry.gitlab.com/commento/commento:v1.8.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Commento", "version": "latest", "description": "Commento is a comments widget designed to enhance the interaction on your website. It allows your readers to contribute to the discussion by upvoting comments that add value and downvoting those that don't. The widget supports markdown formatting, enabling bold, italics, external links, quotes, bullet points, code, and more. Commento also provides moderation tools to manage the conversation, allowing you to lock heated threads, remove off-topic comments, and enforce timeouts. It features a spam detection system, saving you the hassle of dealing with spammers. The widget supports nested replies, making discussions easier to follow. Importantly, Commento does not require your readers to sign up, reducing friction and encouraging more interaction. You can easily customize the look of the widget to match your website's aesthetics.", "category": "comments", "tags": ["Comments", "Discussion", "Website"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "registry.gitlab.com/commento/commento:v1.8.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Website", "url": "https://commento.io/"}, {"label": "Documentation", "url": "https://commento.io/"}, {"label": "Gitlab", "url": "https://gitlab.com/commento/commento"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "commento", "port": "$PORT:8080", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('commentoplusplus', 'Commento++', 'Commento++ is a free, open-source application designed to provide a fast, lightweight comments box that you can embed in your static website. It offers a range of features including Markdown support, Disqus import, voting, automated spam detection, moderation tools, sticky comments, thread locking, and OAuth login. It also supports hot-reloading of comments and email notifications. Commento++ is designed to respect your privacy, with no adverts, and offers a more attractive comments box compared to other free and open-source alternatives. It is significantly lighter and faster than alternatives and can be deployed with a single click to a free Heroku account. For maximum control, you can also choose to self-host the application.', 'comments', ARRAY['Comments', 'Website', 'Open Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "caroga/commentoplusplus:v1.8.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Commento++", "version": "latest", "description": "Commento++ is a free, open-source application designed to provide a fast, lightweight comments box that you can embed in your static website. It offers a range of features including Markdown support, Disqus import, voting, automated spam detection, moderation tools, sticky comments, thread locking, and OAuth login. It also supports hot-reloading of comments and email notifications. Commento++ is designed to respect your privacy, with no adverts, and offers a more attractive comments box compared to other free and open-source alternatives. It is significantly lighter and faster than alternatives and can be deployed with a single click to a free Heroku account. For maximum control, you can also choose to self-host the application.", "category": "comments", "tags": ["Comments", "Website", "Open Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "caroga/commentoplusplus:v1.8.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Github", "url": "https://github.com/souramoo/commentoplusplus"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "commentoplusplus", "port": "$PORT:8080", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('confluence', 'Confluence', 'Confluence is a powerful team collaboration and knowledge-sharing tool. It allows you to create, organize, and collaborate on content in a centralized space. Designed for project management, documentation, and team communication, Confluence helps streamline workflows and enhances productivity. It offers seamless integration with other Atlassian products such as Jira and Bitbucket, making it an ideal solution for agile teams. The intuitive editor and advanced search capabilities ensure that team knowledge is easily accessible. With extensive customization, permission controls, and plugin support, Confluence is a scalable solution for teams of all sizes.', 'collaboration', ARRAY['Collaboration', 'Documentation', 'Productivity', 'Project Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "atlassian/confluence-server:8.6-ubuntu-jdk17"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8090}}$JSON$::jsonb, $JSON${"metadata": {"name": "Confluence", "version": "latest", "description": "Confluence is a powerful team collaboration and knowledge-sharing tool. It allows you to create, organize, and collaborate on content in a centralized space. Designed for project management, documentation, and team communication, Confluence helps streamline workflows and enhances productivity. It offers seamless integration with other Atlassian products such as Jira and Bitbucket, making it an ideal solution for agile teams. The intuitive editor and advanced search capabilities ensure that team knowledge is easily accessible. With extensive customization, permission controls, and plugin support, Confluence is a scalable solution for teams of all sizes.", "category": "collaboration", "tags": ["Collaboration", "Documentation", "Productivity", "Project Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "atlassian/confluence-server:8.6-ubuntu-jdk17"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8090}}, "links": [{"label": "Documentation", "url": "https://confluence.atlassian.com"}, {"label": "Dockerhub", "url": "https://hub.docker.com/r/atlassian/confluence-server"}], "instructions": "Get the License Key to access Confluence.", "install": [{"docker": {"image": "$IMAGE", "name": "confluence", "port": "$PORT:8090", "volumes": ["/var/atlassian/application-data/confluence"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Get the License Key to access Confluence."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('convertx', 'Convertx', 'Convertx is a free, open-source application designed to provide a fast, lightweight media conversion tool that you can use on your desktop or integrate into your workflows. It offers a range of features including support for multiple file formats, batch processing, video trimming, audio extraction, and format customization. It also supports hot-reloading of tasks and notifications upon completion.', 'media-conversion', ARRAY['Media Conversion', 'Open Source', 'Efficiency', 'Customization'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/c4illin/convertx:v0.17.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Convertx", "version": "latest", "description": "Convertx is a free, open-source application designed to provide a fast, lightweight media conversion tool that you can use on your desktop or integrate into your workflows. It offers a range of features including support for multiple file formats, batch processing, video trimming, audio extraction, and format customization. It also supports hot-reloading of tasks and notifications upon completion.", "category": "media-conversion", "tags": ["Media Conversion", "Open Source", "Efficiency", "Customization"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/c4illin/convertx:v0.17.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Github", "url": "https://github.com/C4illin/ConvertX/tree/main"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "convertx", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('convex', 'Convex', 'Convex is the open-source reactive database and backend platform designed for modern app developers. It provides real-time data synchronization, TypeScript-first development, and built-in features like authentication, file storage, and serverless functions. The self-hosted version includes the main backend service, dashboard for data management, and PostgreSQL database support. Perfect for building full-stack applications with automatic caching, real-time updates, and strong consistency guarantees.', 'database', ARRAY['Database', 'Backend', 'Real-time', 'TypeScript', 'Serverless', 'Full-stack', 'Reactive', 'WebSocket', 'API', 'Authentication'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/get-convex/convex-backend:e03b3a72dc412eeff4c1a6958ef1879712fb70e6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3210}}$JSON$::jsonb, $JSON${"metadata": {"name": "Convex", "version": "latest", "description": "Convex is the open-source reactive database and backend platform designed for modern app developers. It provides real-time data synchronization, TypeScript-first development, and built-in features like authentication, file storage, and serverless functions. The self-hosted version includes the main backend service, dashboard for data management, and PostgreSQL database support. Perfect for building full-stack applications with automatic caching, real-time updates, and strong consistency guarantees.", "category": "database", "tags": ["Database", "Backend", "Real-time", "TypeScript", "Serverless", "Full-stack", "Reactive", "WebSocket", "API", "Authentication"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/get-convex/convex-backend:e03b3a72dc412eeff4c1a6958ef1879712fb70e6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3210}}, "links": [{"label": "Website", "url": "https://www.convex.dev"}, {"label": "Documentation", "url": "https://docs.convex.dev"}, {"label": "GitHub", "url": "https://github.com/get-convex/convex-backend"}], "instructions": "Click the \"Generate Admin Key\" script on the backend service, copy the printed key, then use it to log into the Convex dashboard.", "install": [{"docker": {"image": "$IMAGE", "name": "convex", "port": "$PORT:3210", "volumes": ["/convex/data"], "extra_ports": ["3211:3211", "6791:6791"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Click the \"Generate Admin Key\" script on the backend service, copy the printed key, then use it to log into the Convex dashboard."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('cookcli', 'CookCLI', 'CookCLI is a command line recipe manager for Cooklang files that can also run a local web interface for browsing and working with recipe collections. This template deploys the CookCLI server mode with persistent recipe storage.', 'recipes', ARRAY['Recipes', 'Cooklang', 'CLI', 'Productivity', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/cooklang/cookcli:0.29.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9080}}$JSON$::jsonb, $JSON${"metadata": {"name": "CookCLI", "version": "latest", "description": "CookCLI is a command line recipe manager for Cooklang files that can also run a local web interface for browsing and working with recipe collections. This template deploys the CookCLI server mode with persistent recipe storage.", "category": "recipes", "tags": ["Recipes", "Cooklang", "CLI", "Productivity", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/cooklang/cookcli:0.29.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9080}}, "links": [{"label": "Website", "url": "https://cooklang.org/cli/"}, {"label": "Documentation", "url": "https://cooklang.org/cli/help/"}, {"label": "GitHub", "url": "https://github.com/cooklang/cookcli"}], "instructions": "Deploy the template and open the app URL to access the CookCLI web interface.", "install": [{"docker": {"image": "$IMAGE", "name": "cookcli", "port": "$PORT:9080", "volumes": ["/recipes"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Deploy the template and open the app URL to access the CookCLI web interface."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('coralproject', 'Coral', 'Coral is a revolutionary app designed to enhance the commenting experience on your website. It employs smart technology and effective design to improve interactions, making it easier for commenters to engage in meaningful discussions. With Coral, commenters can easily identify journalists in the conversation, mute disruptive voices, share discussions, receive notifications, and see new comment alerts instantly. The app also provides a full suite of tools for moderators to easily identify disruptive comments and highlight the best submissions, all backed by smart AI technology. Coral is built for publishing, increasing loyalty and engagement on your website, giving you complete control of the interactions and data, without inserting any ads or trackers on your page. It''s lightweight, secure, flexible, responsive, and fully customizable, allowing you to connect it to your existing registration system and customize the look and feel to match your brand. Coral is used across the globe in nearly 20 countries and 14 languages, in newsrooms large and small, trusted by more than 500 news sites in 28 countries, including The Washington Post, The Financial Times, Wired, USA Today, and Foreign Policy.', 'communication', ARRAY['Communication', 'Community', 'Privacy'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "coralproject/talk:9.11.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Coral", "version": "latest", "description": "Coral is a revolutionary app designed to enhance the commenting experience on your website. It employs smart technology and effective design to improve interactions, making it easier for commenters to engage in meaningful discussions. With Coral, commenters can easily identify journalists in the conversation, mute disruptive voices, share discussions, receive notifications, and see new comment alerts instantly. The app also provides a full suite of tools for moderators to easily identify disruptive comments and highlight the best submissions, all backed by smart AI technology. Coral is built for publishing, increasing loyalty and engagement on your website, giving you complete control of the interactions and data, without inserting any ads or trackers on your page. It's lightweight, secure, flexible, responsive, and fully customizable, allowing you to connect it to your existing registration system and customize the look and feel to match your brand. Coral is used across the globe in nearly 20 countries and 14 languages, in newsrooms large and small, trusted by more than 500 news sites in 28 countries, including The Washington Post, The Financial Times, Wired, USA Today, and Foreign Policy.", "category": "communication", "tags": ["Communication", "Community", "Privacy"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "coralproject/talk:9.11.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://coralproject.net/"}, {"label": "Documentation", "url": "https://docs.coralproject.net/"}, {"label": "Github", "url": "https://github.com/coralproject/talk"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "coralproject", "port": "$PORT:3000", "volumes": [], "extra_ports": ["9000:9000"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('corsfix', 'Corsfix', 'Corsfix is a CORS proxy that eliminates cross-origin errors and lets you fetch any data for your website with zero hassle. It acts as an intermediary between your applications and target servers, automatically adding the necessary CORS headers to responses. Corsfix handles your requests securely while keeping API keys and credentials safe.', 'proxy', ARRAY['Proxy', 'CORS', 'Networking', 'Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/corsfix/corsfix-app:b464c8b69d10e035c416df4bbe082ae896090c67"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Corsfix", "version": "latest", "description": "Corsfix is a CORS proxy that eliminates cross-origin errors and lets you fetch any data for your website with zero hassle. It acts as an intermediary between your applications and target servers, automatically adding the necessary CORS headers to responses. Corsfix handles your requests securely while keeping API keys and credentials safe.", "category": "proxy", "tags": ["Proxy", "CORS", "Networking", "Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/corsfix/corsfix-app:b464c8b69d10e035c416df4bbe082ae896090c67"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Corsfix CORS proxy", "url": "https://corsfix.com"}, {"label": "Documentation", "url": "https://corsfix.com/docs"}, {"label": "Github", "url": "https://github.com/corsfix/corsfix"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "corsfix", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('corteza', 'Corteza', 'Corteza is a powerful, open-source low-code platform designed to streamline the process of app development, business process integration, and data harmonization. Built with a backend in Golang and a front end in Vue.js, Corteza allows you to easily build native web apps and expand your software ecosystem with complete control and flexibility. You can connect with any record data source, control everything you build, transform your data into a standardized JSON format, and build unlimited web applications and process workflows using block-based tools and Javascript automations. Corteza is cloud-native and deploys via Docker containers, providing a seamless and efficient app development experience. It is 100% free and open-source, ensuring that it will always be accessible to all.', 'low-code-platform', ARRAY['Low-Code Platform', 'App Development', 'Business Process', 'Integration', 'Data Harmonization'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "cortezaproject/corteza:2024.9.8"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Corteza", "version": "latest", "description": "Corteza is a powerful, open-source low-code platform designed to streamline the process of app development, business process integration, and data harmonization. Built with a backend in Golang and a front end in Vue.js, Corteza allows you to easily build native web apps and expand your software ecosystem with complete control and flexibility. You can connect with any record data source, control everything you build, transform your data into a standardized JSON format, and build unlimited web applications and process workflows using block-based tools and Javascript automations. Corteza is cloud-native and deploys via Docker containers, providing a seamless and efficient app development experience. It is 100% free and open-source, ensuring that it will always be accessible to all.", "category": "low-code-platform", "tags": ["Low-Code Platform", "App Development", "Business Process", "Integration", "Data Harmonization"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "cortezaproject/corteza:2024.9.8"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://cortezaproject.org"}, {"label": "Documentation", "url": "https://docs.cortezaproject.org"}, {"label": "Github", "url": "https://github.com/cortezaproject/corteza"}], "instructions": "Create an account to login. The first account created will have administrator priviledges. Go to /admin for the admijnistration interface", "install": [{"docker": {"image": "$IMAGE", "name": "corteza", "port": "$PORT:80", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Create an account to login. The first account created will have administrator priviledges. Go to /admin for the admijnistration interface"}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('countly', 'Countly', 'Countly is an innovative, open-source analytics and engagement platform designed to help you understand and optimize customer journeys in web, mobile, and desktop applications. Built with a flexible architecture, Countly supports multiple integrations and can be deployed on-premises or in the cloud. This platform enables developers and product managers to gain real-time insights into user behavior, track important metrics, and enhance product experiences through push notifications, A/B testing, and other engagement features. Countly is cloud-native, deploys via Docker containers, and provides data control, security, and a streamlined experience for building and monitoring user engagement. Countly is 100% free and open-source, ensuring it is accessible to everyone.', 'analytics', ARRAY['Analytics', 'User Engagement', 'Real-Time Insights', 'Open-Source', 'A/B Testing'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "countly/countly-server:v25.03.43"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Countly", "version": "latest", "description": "Countly is an innovative, open-source analytics and engagement platform designed to help you understand and optimize customer journeys in web, mobile, and desktop applications. Built with a flexible architecture, Countly supports multiple integrations and can be deployed on-premises or in the cloud. This platform enables developers and product managers to gain real-time insights into user behavior, track important metrics, and enhance product experiences through push notifications, A/B testing, and other engagement features. Countly is cloud-native, deploys via Docker containers, and provides data control, security, and a streamlined experience for building and monitoring user engagement. Countly is 100% free and open-source, ensuring it is accessible to everyone.", "category": "analytics", "tags": ["Analytics", "User Engagement", "Real-Time Insights", "Open-Source", "A/B Testing"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "countly/countly-server:v25.03.43"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://count.ly"}, {"label": "Documentation", "url": "https://docs.count.ly"}, {"label": "GitHub", "url": "https://github.com/countly/countly-server"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "countly", "port": "$PORT:80", "volumes": ["/usr/share/countly"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('crawel4ai', 'Crawl4AI', 'Crawl4AI is an advanced AI-powered web crawling and data extraction tool designed to streamline the process of collecting, processing, and structuring web data for AI applications. It allows you to efficiently crawl websites, extract relevant information, and store it in structured formats such as JSON, CSV, or vector databases. With Crawl4AI, you can integrate real-time web data into your AI models, enhancing their knowledge base and enabling dynamic responses. It supports both cloud-based and on-premise deployments, making it flexible for different use cases. Crawl4AI comes with powerful features such as intelligent content filtering, automated rate-limiting handling, JavaScript rendering for dynamic pages, built-in APIs for seamless integration, and robust authentication support. The latest version, Crawl4AI 2.1, introduces enhanced AI-based content classification, improved speed optimizations, support for multi-agent crawling, and various bug fixes.', 'web-crawling', ARRAY['Web Crawling', 'AI Data Extraction', 'Machine Learning', 'Vector Database', 'AI-Powered Search'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 11235}}$JSON$::jsonb, $JSON${"metadata": {"name": "Crawl4AI", "version": "latest", "description": "Crawl4AI is an advanced AI-powered web crawling and data extraction tool designed to streamline the process of collecting, processing, and structuring web data for AI applications. It allows you to efficiently crawl websites, extract relevant information, and store it in structured formats such as JSON, CSV, or vector databases. With Crawl4AI, you can integrate real-time web data into your AI models, enhancing their knowledge base and enabling dynamic responses. It supports both cloud-based and on-premise deployments, making it flexible for different use cases. Crawl4AI comes with powerful features such as intelligent content filtering, automated rate-limiting handling, JavaScript rendering for dynamic pages, built-in APIs for seamless integration, and robust authentication support. The latest version, Crawl4AI 2.1, introduces enhanced AI-based content classification, improved speed optimizations, support for multi-agent crawling, and various bug fixes.", "category": "web-crawling", "tags": ["Web Crawling", "AI Data Extraction", "Machine Learning", "Vector Database", "AI-Powered Search"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 11235}}, "links": [{"label": "GitHub", "url": "https://github.com/unclecode/crawl4ai"}, {"label": "Documentation", "url": "https://docs.crawl4ai.com/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "crawel4ai", "port": "$PORT:11235", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('cronicle', 'Cronicle', 'Cronicle is a powerful, multi-server task scheduler and runner, with an easy-to-use web-based interface. It allows you to schedule and run scripts, commands, or software programs on a recurring basis, similar to cron jobs but with the added capability of visual management and log tracking. Cronicle supports complex workflows including dependencies between tasks, and it can distribute tasks across multiple servers for load balancing. It''s ideal for automating backups, updates, data processing tasks, and more in a distributed environment.', 'automation', ARRAY['Automation', 'Task Scheduler', 'Distributed Computing'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "soulteary/cronicle:0.9.80"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3012}}$JSON$::jsonb, $JSON${"metadata": {"name": "Cronicle", "version": "latest", "description": "Cronicle is a powerful, multi-server task scheduler and runner, with an easy-to-use web-based interface. It allows you to schedule and run scripts, commands, or software programs on a recurring basis, similar to cron jobs but with the added capability of visual management and log tracking. Cronicle supports complex workflows including dependencies between tasks, and it can distribute tasks across multiple servers for load balancing. It's ideal for automating backups, updates, data processing tasks, and more in a distributed environment.", "category": "automation", "tags": ["Automation", "Task Scheduler", "Distributed Computing"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "soulteary/cronicle:0.9.80"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3012}}, "links": [{"label": "Website", "url": "https://cronicle.net/"}, {"label": "Github", "url": "https://github.com/jhuckaby/Cronicle"}], "instructions": "The default username is 'admin' and the default password is 'admin'", "install": [{"docker": {"image": "$IMAGE", "name": "cronicle", "port": "$PORT:3012", "volumes": ["/opt/cronicle/data", "/opt/cronicle/logs", "/opt/cronicle/plugins"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "The default username is 'admin' and the default password is 'admin'"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('crontab-guru', 'Crontab Guru', 'Crontab Guru is a simple web interface for managing and testing cron expressions. It provides an intuitive dashboard for creating, editing, and validating crontab entries with real-time feedback. Perfect for system administrators and developers who need to schedule tasks and want to ensure their cron expressions are correct before deployment.', 'cron', ARRAY['Cron', 'Scheduling', 'System Administration', 'Task Management', 'Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "dockeriddonuts/crontab-dashboard:1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Crontab Guru", "version": "latest", "description": "Crontab Guru is a simple web interface for managing and testing cron expressions. It provides an intuitive dashboard for creating, editing, and validating crontab entries with real-time feedback. Perfect for system administrators and developers who need to schedule tasks and want to ensure their cron expressions are correct before deployment.", "category": "cron", "tags": ["Cron", "Scheduling", "System Administration", "Task Management", "Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "dockeriddonuts/crontab-dashboard:1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9000}}, "links": [{"label": "Website", "url": "https://crontab.guru"}, {"label": "Documentation", "url": "https://crontab.guru/examples.html"}], "instructions": "Login using the default credentials; admin/secret123", "install": [{"docker": {"image": "$IMAGE", "name": "crontab-guru", "port": "$PORT:9000", "volumes": ["/var/spool/cron/crontabs"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Login using the default credentials; admin/secret123"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('crosswatch', 'Crosswatch', 'CrossWatch is a self-hosted synchronization engine that keeps Plex, Jellyfin, Emby, SIMKL, Trakt, AniList, TMDb, MDBList, and Tautulli aligned. It runs locally with a web UI on port 8787 where you link accounts, define sync pairs, run them manually or on a schedule, and review stats and history. It includes a built-in tracker with snapshots, profiles for separate setups (e.g. family or different servers), watchlist and progress sync, scrobbling and webhooks to trackers, and tools like Analyzer, Editor, and Captures for stuck or inconsistent items. Configuration persists under /config; set TZ for your timezone.', 'media', ARRAY['Media', 'Sync', 'Plex', 'Jellyfin', 'Emby', 'Trakt', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/cenodude/crosswatch:0.9.18"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8787}}$JSON$::jsonb, $JSON${"metadata": {"name": "Crosswatch", "version": "latest", "description": "CrossWatch is a self-hosted synchronization engine that keeps Plex, Jellyfin, Emby, SIMKL, Trakt, AniList, TMDb, MDBList, and Tautulli aligned. It runs locally with a web UI on port 8787 where you link accounts, define sync pairs, run them manually or on a schedule, and review stats and history. It includes a built-in tracker with snapshots, profiles for separate setups (e.g. family or different servers), watchlist and progress sync, scrobbling and webhooks to trackers, and tools like Analyzer, Editor, and Captures for stuck or inconsistent items. Configuration persists under /config; set TZ for your timezone.", "category": "media", "tags": ["Media", "Sync", "Plex", "Jellyfin", "Emby", "Trakt", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/cenodude/crosswatch:0.9.18"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8787}}, "links": [{"label": "Website", "url": "https://crosswatch.app"}, {"label": "Documentation", "url": "https://wiki.crosswatch.app"}, {"label": "GitHub", "url": "https://github.com/cenodude/CrossWatch"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "crosswatch", "port": "$PORT:8787", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('crowdsec', 'CrowdSec', 'CrowdSec is a free, modern, and collaborative security engine utilizing crowdsourcing to generate cyber threat intelligence data. It analyzes visitor behavior & provides an adapted response to all kinds of attacks. It can read logs, spot malevolent visitors, and trigger appropriate remediation.', 'security', ARRAY['Security', 'IDS', 'IPS', 'Firewall', 'Protection'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "crowdsecurity/crowdsec"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "CrowdSec", "version": "latest", "description": "CrowdSec is a free, modern, and collaborative security engine utilizing crowdsourcing to generate cyber threat intelligence data. It analyzes visitor behavior & provides an adapted response to all kinds of attacks. It can read logs, spot malevolent visitors, and trigger appropriate remediation.", "category": "security", "tags": ["Security", "IDS", "IPS", "Firewall", "Protection"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "crowdsecurity/crowdsec"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://www.crowdsec.net/"}, {"label": "Documentation", "url": "https://docs.crowdsec.net/"}, {"label": "Github", "url": "https://github.com/crowdsecurity/crowdsec"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "crowdsec", "port": "$PORT:80", "volumes": ["/etc/crowdsec/acquis.yaml", "/var/log/nginx", "/var/lib/crowdsec/data/", "/etc/crowdsec/"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('cryptgeon', 'Cryptgeon', 'Cryptgeon is a secure, open source sharing note or file service inspired by PrivNote. It includes a server, a web page and a CLI client.', 'secure-sharing', ARRAY['Secure Sharing', 'File Sharing', 'Notes', 'Open Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "cupcakearmy/cryptgeon:2.9.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Cryptgeon", "version": "latest", "description": "Cryptgeon is a secure, open source sharing note or file service inspired by PrivNote. It includes a server, a web page and a CLI client.", "category": "secure-sharing", "tags": ["Secure Sharing", "File Sharing", "Notes", "Open Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "cupcakearmy/cryptgeon:2.9.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}, "links": [{"label": "Github", "url": "https://github.com/cupcakearmy/cryptgeon"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "cryptgeon", "port": "$PORT:8000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('cryptpad', 'Cryptpad', 'CryptPad is an open-source collaborative office suite that offers end-to-end encryption, ensuring your data remains private and secure. It provides a full suite of applications, allowing you to work on various projects in real-time with your colleagues or friends. Whether you''re planning a camping trip or setting up client briefs, CryptPad makes it easy to share files and collaborate without the need for account creation or app downloads. It''s more than just a document editor; it''s a secure platform for all your collaborative needs.', 'collaboration', ARRAY['Collaboration', 'Privacy', 'Office Suite', 'Encryption', 'Open-source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "promasu/cryptpad:v5.2.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Cryptpad", "version": "latest", "description": "CryptPad is an open-source collaborative office suite that offers end-to-end encryption, ensuring your data remains private and secure. It provides a full suite of applications, allowing you to work on various projects in real-time with your colleagues or friends. Whether you're planning a camping trip or setting up client briefs, CryptPad makes it easy to share files and collaborate without the need for account creation or app downloads. It's more than just a document editor; it's a secure platform for all your collaborative needs.", "category": "collaboration", "tags": ["Collaboration", "Privacy", "Office Suite", "Encryption", "Open-source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "promasu/cryptpad:v5.2.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://cryptpad.org"}, {"label": "Docs", "url": "https://docs.cryptpad.org"}, {"label": "Github", "url": "https://github.com/cryptpad"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "cryptpad", "port": "$PORT:80", "volumes": ["/cryptpad/blob", "/cryptpad/block", "/cryptpad/customize", "/cryptpad/data", "/cryptpad/datastore", "/cryptpad/config/config.js"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('cs2', 'Counter-Strike 2 Dedicated Server', 'Counter-Strike 2 Dedicated Server allows you to host your own CS2 game server with full control over configuration and settings. This self-hosted gaming solution provides a professional-grade server environment for competitive matches, casual gameplay, or private practice sessions. The server supports various game modes including casual, competitive, and deathmatch, with extensive customization options for maps, player limits, server rules, and bot configurations. Features include RCON remote administration, CSTV for broadcasting matches, workshop map support, and comprehensive logging. Perfect for gaming communities, esports teams, or anyone wanting to run their own CS2 server with dedicated resources and low latency.', 'gaming', ARRAY['Gaming', 'Game Server', 'Counter-Strike', 'FPS', 'Multiplayer'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "joedwards32/cs2:4.0.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Counter-Strike 2 Dedicated Server", "version": "latest", "description": "Counter-Strike 2 Dedicated Server allows you to host your own CS2 game server with full control over configuration and settings. This self-hosted gaming solution provides a professional-grade server environment for competitive matches, casual gameplay, or private practice sessions. The server supports various game modes including casual, competitive, and deathmatch, with extensive customization options for maps, player limits, server rules, and bot configurations. Features include RCON remote administration, CSTV for broadcasting matches, workshop map support, and comprehensive logging. Perfect for gaming communities, esports teams, or anyone wanting to run their own CS2 server with dedicated resources and low latency.", "category": "gaming", "tags": ["Gaming", "Game Server", "Counter-Strike", "FPS", "Multiplayer"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "joedwards32/cs2:4.0.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Steam Game Server Account Management", "url": "https://steamcommunity.com/dev/managegameservers"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/joedwards32/cs2"}, {"label": "CS2 Dedicated Servers Wiki", "url": "https://developer.valvesoftware.com/wiki/Counter-Strike_2/Dedicated_Servers"}, {"label": "Github", "url": "https://github.com/joedwards32/CS2"}], "instructions": "IMPORTANT - You must obtain a Game Server Token from https://steamcommunity.com/dev/managegameservers before your server can be listed publicly.", "install": [{"docker": {"image": "$IMAGE", "name": "cs2", "port": "$PORT:80", "volumes": ["/home/steam/cs2-dedicated/"], "extra_ports": ["27015:27015", "27020:27020"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "IMPORTANT - You must obtain a Game Server Token from https://steamcommunity.com/dev/managegameservers before your server can be listed publicly."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('cubejs', 'CubeJS', 'Cube is a Semantic Layer for every data app that aims to connect data silos, drive consistent metrics, and power your AI and analytics with context. It allows you to define and manage metrics upstream to consolidate your workflow, centralize definitions, and create a single source of truth. The app also provides granular access controls to grant column- and role-based operational and viewing permissions upstream. Cube ensures your data is reliably performant with a powerful caching layer and advanced preaggregation capabilities. Furthermore, it allows you to connect your data to any front-end application to build beautiful custom visualizations with Cube’s GraphQL, REST, and SQL APIs. Cube is an API-first, four-part semantic layer that enables data engineers and developers to make their data consistent, secure, performant, and accessible across every application.', 'analytics', ARRAY['Analytics'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "cubejs/cube:v1.6.39"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4000}}$JSON$::jsonb, $JSON${"metadata": {"name": "CubeJS", "version": "latest", "description": "Cube is a Semantic Layer for every data app that aims to connect data silos, drive consistent metrics, and power your AI and analytics with context. It allows you to define and manage metrics upstream to consolidate your workflow, centralize definitions, and create a single source of truth. The app also provides granular access controls to grant column- and role-based operational and viewing permissions upstream. Cube ensures your data is reliably performant with a powerful caching layer and advanced preaggregation capabilities. Furthermore, it allows you to connect your data to any front-end application to build beautiful custom visualizations with Cube\u2019s GraphQL, REST, and SQL APIs. Cube is an API-first, four-part semantic layer that enables data engineers and developers to make their data consistent, secure, performant, and accessible across every application.", "category": "analytics", "tags": ["Analytics"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "cubejs/cube:v1.6.39"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4000}}, "links": [{"label": "Website", "url": "https://cube.dev"}, {"label": "Documentation", "url": "https://cube.dev/docs"}, {"label": "Github", "url": "https://github.com/cube-js/cube.js"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "cubejs", "port": "$PORT:4000", "volumes": ["/cube/conf"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('cupdate', 'Cupdate', 'Cupdate is a self-hosted web application for monitoring and managing Docker container updates. It provides a centralized dashboard to track available updates for your running containers, view container versions, and manage update notifications. By connecting to the Docker daemon via the Docker socket, Cupdate scans all running containers and checks for newer image versions available in container registries. The web interface displays an overview of your container infrastructure with update status, image tags, registry information, and visual indicators for outdated containers. Cupdate features automatic update checking on a configurable schedule, support for multiple container registries, detailed container information with links to documentation and registries, and the ability to manage container logos and metadata. With its lightweight architecture and persistent storage using BoltDB and SQLite, Cupdate offers an efficient solution for staying informed about container updates without requiring complex automation or CI/CD pipelines. Perfect for home lab administrators managing multiple Docker containers, DevOps teams maintaining staging environments, system administrators tracking container versions across servers, or anyone who wants visibility into their Docker infrastructure''s update status without manually checking each container.', 'docker', ARRAY['Docker', 'Container Management', 'Update Monitoring', 'System Administration', 'DevOps'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/alexgustafsson/cupdate:0.24.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Cupdate", "version": "latest", "description": "Cupdate is a self-hosted web application for monitoring and managing Docker container updates. It provides a centralized dashboard to track available updates for your running containers, view container versions, and manage update notifications. By connecting to the Docker daemon via the Docker socket, Cupdate scans all running containers and checks for newer image versions available in container registries. The web interface displays an overview of your container infrastructure with update status, image tags, registry information, and visual indicators for outdated containers. Cupdate features automatic update checking on a configurable schedule, support for multiple container registries, detailed container information with links to documentation and registries, and the ability to manage container logos and metadata. With its lightweight architecture and persistent storage using BoltDB and SQLite, Cupdate offers an efficient solution for staying informed about container updates without requiring complex automation or CI/CD pipelines. Perfect for home lab administrators managing multiple Docker containers, DevOps teams maintaining staging environments, system administrators tracking container versions across servers, or anyone who wants visibility into their Docker infrastructure's update status without manually checking each container.", "category": "docker", "tags": ["Docker", "Container Management", "Update Monitoring", "System Administration", "DevOps"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/alexgustafsson/cupdate:0.24.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Website", "url": "https://alexgustafsson.github.io/cupdate"}, {"label": "GitHub", "url": "https://github.com/alexgustafsson/cupdate"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "cupdate", "port": "$PORT:8080", "volumes": ["/var/run/docker.sock", "/var/run/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('cusdis', 'Cusdis', 'Cusdis is a lightweight, open-source comment system designed with privacy as a priority. It serves as an alternative to Disqus, offering a simple and user-friendly way to integrate a comment system into your existing website. The app is incredibly lightweight, with the JS SDK embedded to your website being only around 5kb. It features built-in i18n and dark-mode for a seamless user experience. Cusdis ensures you stay updated with new comments through email notifications, and allows for quick approval of comments directly from the notification email or webhook. You can also set a webhook URL that triggers when your website receives a new comment, allowing you to integrate Cusdis with your favorite tools such as Telegram. The app offers flexibility with its pricing, providing a free self-hosting option, a free cloud option with limited features, and a Cloud Pro option for unlimited access.', 'comments', ARRAY['Comments', 'Privacy', 'Open-source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "djyde/cusdis:1.3.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Cusdis", "version": "latest", "description": "Cusdis is a lightweight, open-source comment system designed with privacy as a priority. It serves as an alternative to Disqus, offering a simple and user-friendly way to integrate a comment system into your existing website. The app is incredibly lightweight, with the JS SDK embedded to your website being only around 5kb. It features built-in i18n and dark-mode for a seamless user experience. Cusdis ensures you stay updated with new comments through email notifications, and allows for quick approval of comments directly from the notification email or webhook. You can also set a webhook URL that triggers when your website receives a new comment, allowing you to integrate Cusdis with your favorite tools such as Telegram. The app offers flexibility with its pricing, providing a free self-hosting option, a free cloud option with limited features, and a Cloud Pro option for unlimited access.", "category": "comments", "tags": ["Comments", "Privacy", "Open-source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "djyde/cusdis:1.3.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://cusdis.com"}, {"label": "Documentation", "url": "https://cusdis.com/docs"}, {"label": "Github", "url": "https://github.com/djyde/cusdis/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "cusdis", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('cyberchef', 'CyberChef', 'CyberChef, also known as the Cyber Swiss Army Knife, is a versatile web app designed to perform a wide array of ''cyber'' operations within a web browser. It offers simple encoding methods like XOR and Base64, alongside more complex encryption techniques such as AES, DES, and Blowfish. CyberChef also provides tools for creating binary and hexdumps, compressing and decompressing data, calculating hashes and checksums, parsing IPv6 and X.509, changing character encodings, and much more. The app is designed to be user-friendly, enabling both technical and non-technical analysts to manipulate data in complex ways without the need for intricate tools or algorithms. CyberChef is still under active development, with ongoing testing, bug fixing, new feature additions, and documentation improvements.', 'developer-tools', ARRAY['Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "mpepping/cyberchef:v10.24.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}$JSON$::jsonb, $JSON${"metadata": {"name": "CyberChef", "version": "latest", "description": "CyberChef, also known as the Cyber Swiss Army Knife, is a versatile web app designed to perform a wide array of 'cyber' operations within a web browser. It offers simple encoding methods like XOR and Base64, alongside more complex encryption techniques such as AES, DES, and Blowfish. CyberChef also provides tools for creating binary and hexdumps, compressing and decompressing data, calculating hashes and checksums, parsing IPv6 and X.509, changing character encodings, and much more. The app is designed to be user-friendly, enabling both technical and non-technical analysts to manipulate data in complex ways without the need for intricate tools or algorithms. CyberChef is still under active development, with ongoing testing, bug fixing, new feature additions, and documentation improvements.", "category": "developer-tools", "tags": ["Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "mpepping/cyberchef:v10.24.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}, "links": [{"label": "Documentation", "url": "https://github.com/gchq/CyberChef/wiki"}, {"label": "Github", "url": "https://github.com/gchq/CyberChef"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "cyberchef", "port": "$PORT:8000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('cypht', 'Cypht', 'Cypht is a modern, open-source webmail client that allows you to access multiple email accounts from a single interface. It supports various email protocols and provides a clean, intuitive user experience.', 'email', ARRAY['Email', 'Webmail', 'Self-hosted', 'Open Source', 'Communication'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "cypht/cypht:2.7.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Cypht", "version": "latest", "description": "Cypht is a modern, open-source webmail client that allows you to access multiple email accounts from a single interface. It supports various email protocols and provides a clean, intuitive user experience.", "category": "email", "tags": ["Email", "Webmail", "Self-hosted", "Open Source", "Communication"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "cypht/cypht:2.7.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://cypht.org"}, {"label": "Documentation", "url": "https://www.cypht.org/documentation/"}, {"label": "GitHub", "url": "https://github.com/jasonmunro/cypht"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/cypht/cypht"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "cypht", "port": "$PORT:80", "volumes": ["/var/log/nginx", "/var/log/php", "/var/log/supervisord", "/usr/local/share/cypht/site/fonts"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('daapd', 'Daapd', 'Daapd is a robust, open-source DAAP (Digital Audio Access Protocol) server that allows users to share music libraries over a network. It is designed to work seamlessly with iTunes, Roku SoundBridges, and other DAAP clients, providing an efficient and reliable way to stream audio content across devices. Daapd also supports streaming internet radio, podcasts, and AirPlay devices. With its powerful backend, Daapd ensures smooth performance, a wide range of supported formats, and advanced features like library management and transcoding.', 'daap', ARRAY['DAAP', 'Music Server', 'Audio Streaming'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/daapd:28.10.20250118"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3689}}$JSON$::jsonb, $JSON${"metadata": {"name": "Daapd", "version": "latest", "description": "Daapd is a robust, open-source DAAP (Digital Audio Access Protocol) server that allows users to share music libraries over a network. It is designed to work seamlessly with iTunes, Roku SoundBridges, and other DAAP clients, providing an efficient and reliable way to stream audio content across devices. Daapd also supports streaming internet radio, podcasts, and AirPlay devices. With its powerful backend, Daapd ensures smooth performance, a wide range of supported formats, and advanced features like library management and transcoding.", "category": "daap", "tags": ["DAAP", "Music Server", "Audio Streaming"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/daapd:28.10.20250118"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3689}}, "links": [{"label": "Website", "url": "https://github.com/ejurgensen/forked-daapd"}, {"label": "Documentation", "url": "https://ejurgensen.github.io/forked-daapd/"}, {"label": "Github", "url": "https://github.com/ejurgensen/forked-daapd"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "daapd", "port": "$PORT:3689", "volumes": ["/music", "/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('dailytxt', 'DailyTxT', 'DailyTxT is a secure, encrypted personal diary web application that allows users to write and manage daily entries with end-to-end encryption. It provides a user-friendly interface for journaling with features like file uploads, search functionality, and multi-language support. All data is encrypted locally, ensuring complete privacy and security for personal thoughts and memories.', 'diary', ARRAY['Diary', 'Journal', 'Encryption', 'Privacy', 'Personal', 'Web App', 'File Storage', 'Self-hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "phitux/dailytxt:2.6.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "DailyTxT", "version": "latest", "description": "DailyTxT is a secure, encrypted personal diary web application that allows users to write and manage daily entries with end-to-end encryption. It provides a user-friendly interface for journaling with features like file uploads, search functionality, and multi-language support. All data is encrypted locally, ensuring complete privacy and security for personal thoughts and memories.", "category": "diary", "tags": ["Diary", "Journal", "Encryption", "Privacy", "Personal", "Web App", "File Storage", "Self-hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "phitux/dailytxt:2.6.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Demo", "url": "https://dailytxt.phitux.de"}, {"label": "Documentation", "url": "https://github.com/PhiTux/DailyTxT#readme"}, {"label": "GitHub", "url": "https://github.com/PhiTux/DailyTxT"}], "instructions": "After deployment, open DailyTxT from your app domain and create your first account (if allow registration is enabled).", "install": [{"docker": {"image": "$IMAGE", "name": "dailytxt", "port": "$PORT:80", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deployment, open DailyTxT from your app domain and create your first account (if allow registration is enabled)."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('damselfly', 'Damselfly', 'Damselfly is a modern, self-hosted photo management system that helps you organize, search, and share your photo collection. It uses AI-powered image recognition to automatically tag and categorize your photos, making it easy to find specific images in your collection.', 'photo-management', ARRAY['Photo Management', 'AI', 'Image Recognition', 'Self-hosted', 'Photography'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "webreaper/damselfly:4.5.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 6363}}$JSON$::jsonb, $JSON${"metadata": {"name": "Damselfly", "version": "latest", "description": "Damselfly is a modern, self-hosted photo management system that helps you organize, search, and share your photo collection. It uses AI-powered image recognition to automatically tag and categorize your photos, making it easy to find specific images in your collection.", "category": "photo-management", "tags": ["Photo Management", "AI", "Image Recognition", "Self-hosted", "Photography"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "webreaper/damselfly:4.5.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 6363}}, "links": [{"label": "GitHub", "url": "https://github.com/Webreaper/Damselfly"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/webreaper/damselfly"}], "instructions": "Add your photos and libraries in the respected volumes or change them to bind volumes as per your need.", "install": [{"docker": {"image": "$IMAGE", "name": "damselfly", "port": "$PORT:6363", "volumes": ["/config", "/thumbs", "/pictures"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Add your photos and libraries in the respected volumes or change them to bind volumes as per your need."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('daptin', 'Daptin', 'Daptin is an open-source backend development framework that enables rapid development and deployment of production-ready JSONAPI microservices. Design your data model and have a production-ready JSON API online in minutes.', 'backend', ARRAY['Backend', 'API', 'Microservices', 'JSON:API', 'Database'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "daptin/daptin:v0.11.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Daptin", "version": "latest", "description": "Daptin is an open-source backend development framework that enables rapid development and deployment of production-ready JSONAPI microservices. Design your data model and have a production-ready JSON API online in minutes.", "category": "backend", "tags": ["Backend", "API", "Microservices", "JSON:API", "Database"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "daptin/daptin:v0.11.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Documentation", "url": "https://daptin.github.io/docs/"}, {"label": "Website", "url": "https://daptin.github.io/daptin/"}, {"label": "GitHub", "url": "https://github.com/daptin/daptin"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "daptin", "port": "$PORT:8080", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('darktable', 'Darktable', 'Darktable is an open-source photography workflow application and raw developer. It manages your digital negatives in a database, lets you view them through a zoomable lighttable, and enables you to develop raw images and enhance them with powerful editing tools. This browser-accessible version provides the full Darktable desktop application through a web interface, allowing you to edit photos from anywhere without local installation.', 'photography', ARRAY['Photography', 'Image Editing', 'RAW', 'Desktop', 'Browser'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/darktable:25.4.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Darktable", "version": "latest", "description": "Darktable is an open-source photography workflow application and raw developer. It manages your digital negatives in a database, lets you view them through a zoomable lighttable, and enables you to develop raw images and enhance them with powerful editing tools. This browser-accessible version provides the full Darktable desktop application through a web interface, allowing you to edit photos from anywhere without local installation.", "category": "photography", "tags": ["Photography", "Image Editing", "RAW", "Desktop", "Browser"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/darktable:25.4.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://www.darktable.org/"}, {"label": "Documentation", "url": "https://docs.darktable.org/"}, {"label": "GitHub", "url": "https://github.com/darktable-org/darktable"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "darktable", "port": "$PORT:3000", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('dashdot', 'Dashdot', 'Dash. (or dashdot) is a visually stunning, modern server dashboard designed with a glassmorphism aesthetic. It''s built on the latest technology and is intended for use with smaller VPS and private servers. The dashboard is feature-rich, offering a dark/light mode, customizable widgets, beautiful animations and styles, and support for multiple architectures. It provides a high level of personalization options, allowing you to tailor the dashboard to your specific needs. Dash. is an open-source project, welcoming contributions from those interested in further developing the platform.', 'dashboard', ARRAY['Dashboard'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "mauricenino/dashdot:6.3.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3001}}$JSON$::jsonb, $JSON${"metadata": {"name": "Dashdot", "version": "latest", "description": "Dash. (or dashdot) is a visually stunning, modern server dashboard designed with a glassmorphism aesthetic. It's built on the latest technology and is intended for use with smaller VPS and private servers. The dashboard is feature-rich, offering a dark/light mode, customizable widgets, beautiful animations and styles, and support for multiple architectures. It provides a high level of personalization options, allowing you to tailor the dashboard to your specific needs. Dash. is an open-source project, welcoming contributions from those interested in further developing the platform.", "category": "dashboard", "tags": ["Dashboard"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "mauricenino/dashdot:6.3.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3001}}, "links": [{"label": "Website", "url": "https://getdashdot.com/"}, {"label": "Github", "url": "https://github.com/MauriceNino/dashdot"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "dashdot", "port": "$PORT:3001", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('dashy', 'Dashy', 'Dashy is the ultimate homepage for your homelab, designed to be your personal, privacy-respecting dashboard. It is highly customizable and easy to use, offering a unique user experience with its built-in themes and UI color palette editor. Dashy can auto-fetch icons from the favicon of each of your apps or services, and it provides an instant overview of the health of each of your apps with status indicators. It also features a simple authentication feature for protecting your dashboard, and supports multiple users with granular controls. Dashy comes with 50+ pre-built widgets for displaying dynamic content from any API-enabled service. It offers alternate views for a minimal view or a workspace view, and allows you to choose how to launch your apps. Dashy also includes a search and shortcuts feature for easy navigation, and an optional cloud backup and sync service for off-site config backup. The app supports multiple languages and is easily configurable through a simple YAML file or directly through the UI.', 'dashboard', ARRAY['Dashboard'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lissy93/dashy:3.3.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Dashy", "version": "latest", "description": "Dashy is the ultimate homepage for your homelab, designed to be your personal, privacy-respecting dashboard. It is highly customizable and easy to use, offering a unique user experience with its built-in themes and UI color palette editor. Dashy can auto-fetch icons from the favicon of each of your apps or services, and it provides an instant overview of the health of each of your apps with status indicators. It also features a simple authentication feature for protecting your dashboard, and supports multiple users with granular controls. Dashy comes with 50+ pre-built widgets for displaying dynamic content from any API-enabled service. It offers alternate views for a minimal view or a workspace view, and allows you to choose how to launch your apps. Dashy also includes a search and shortcuts feature for easy navigation, and an optional cloud backup and sync service for off-site config backup. The app supports multiple languages and is easily configurable through a simple YAML file or directly through the UI.", "category": "dashboard", "tags": ["Dashboard"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lissy93/dashy:3.3.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://dashy.to/"}, {"label": "Documentation", "url": "https://dashy.to/docs/"}, {"label": "Github", "url": "https://github.com/lissy93/dashy"}], "instructions": "After deploying the project, it may take a while before the app is available (5 minutes).", "install": [{"docker": {"image": "$IMAGE", "name": "dashy", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deploying the project, it may take a while before the app is available (5 minutes)."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('databasus', 'Databasus', 'Databasus is a free, open source, self-hosted backup platform focused on PostgreSQL with support for MySQL, MariaDB, and MongoDB. It helps you schedule backups, apply retention policies, store backups in multiple destinations, and receive notifications about backup progress.', 'backup', ARRAY['Backup', 'Database', 'PostgreSQL', 'MySQL', 'MongoDB', 'DevOps'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "databasus/databasus:v3.33.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4005}}$JSON$::jsonb, $JSON${"metadata": {"name": "Databasus", "version": "latest", "description": "Databasus is a free, open source, self-hosted backup platform focused on PostgreSQL with support for MySQL, MariaDB, and MongoDB. It helps you schedule backups, apply retention policies, store backups in multiple destinations, and receive notifications about backup progress.", "category": "backup", "tags": ["Backup", "Database", "PostgreSQL", "MySQL", "MongoDB", "DevOps"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "databasus/databasus:v3.33.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4005}}, "links": [{"label": "Website", "url": "https://databasus.com"}, {"label": "Documentation", "url": "https://databasus.com/installation"}, {"label": "GitHub", "url": "https://github.com/databasus/databasus"}, {"label": "Container registry", "url": "https://hub.docker.com/r/databasus/databasus"}], "instructions": "After deployment, open your domain and complete the initial setup in the Databasus UI. The template already mounts persistent storage at /databasus-data so configuration and backup metadata survive restarts.", "install": [{"docker": {"image": "$IMAGE", "name": "databasus", "port": "$PORT:4005", "volumes": ["/databasus-data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deployment, open your domain and complete the initial setup in the Databasus UI. The template already mounts persistent storage at /databasus-data so configuration and backup metadata survive restarts."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('dataline', 'Dataline', 'Dataline is a powerful data management and visualization tool that helps users organize, analyze, and visualize their data in an intuitive way. It provides a user-friendly interface for data manipulation, chart creation, and data sharing capabilities. With its modern design and robust features, Dataline makes it easy to work with various data formats and create meaningful visualizations.', 'data', ARRAY['Data', 'Visualization', 'Analytics', 'Management', 'Charts'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ramiawar/dataline:v1.2.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 7377}}$JSON$::jsonb, $JSON${"metadata": {"name": "Dataline", "version": "latest", "description": "Dataline is a powerful data management and visualization tool that helps users organize, analyze, and visualize their data in an intuitive way. It provides a user-friendly interface for data manipulation, chart creation, and data sharing capabilities. With its modern design and robust features, Dataline makes it easy to work with various data formats and create meaningful visualizations.", "category": "data", "tags": ["Data", "Visualization", "Analytics", "Management", "Charts"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ramiawar/dataline:v1.2.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 7377}}, "links": [{"label": "GitHub", "url": "https://github.com/ramiawar/dataline"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/ramiawar/dataline"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "dataline", "port": "$PORT:7377", "volumes": ["/home/.dataline"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('dcm', 'DCM', 'DCM is a lightweight self-hosted web interface for managing and monitoring Docker containers. It provides a simple dashboard to view container status, start/stop operations, and inspect basic container details. Designed to be minimal and easy to deploy, DCM helps you keep an eye on your containers without exposing the full Docker API or using heavier management stacks. Ideal for small home labs or users who want a quick overview of their running services via a browser.', 'docker', ARRAY['Docker', 'Dashboard', 'Monitoring', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/ajnart/dcm:sha-6d86fd5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 7576}}$JSON$::jsonb, $JSON${"metadata": {"name": "DCM", "version": "latest", "description": "DCM is a lightweight self-hosted web interface for managing and monitoring Docker containers. It provides a simple dashboard to view container status, start/stop operations, and inspect basic container details. Designed to be minimal and easy to deploy, DCM helps you keep an eye on your containers without exposing the full Docker API or using heavier management stacks. Ideal for small home labs or users who want a quick overview of their running services via a browser.", "category": "docker", "tags": ["Docker", "Dashboard", "Monitoring", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/ajnart/dcm:sha-6d86fd5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 7576}}, "links": [{"label": "GitHub", "url": "https://github.com/ajnart/dcm"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/ajnart/dcm"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "dcm", "port": "$PORT:7576", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('deluge', 'Deluge', 'Deluge is a comprehensive BitTorrent client designed to cater to your torrenting needs. It operates on a daemon/client model and is equipped with various user interfaces, including GTK-UI, Web-UI, and Console-UI. At its core, Deluge uses libtorrent to efficiently manage the BitTorrent protocol. The app allows you to start various user-interfaces and the Deluge daemon with simple commands. It also provides a web UI that can be accessed at http://localhost:8112 with the default password ''deluge''. For advanced users, Deluge offers features like bandwidth tweaking, VPN, and reverse proxy.', 'file-management', ARRAY['File Management', 'Networking Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/deluge:2.2.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 6881}}$JSON$::jsonb, $JSON${"metadata": {"name": "Deluge", "version": "latest", "description": "Deluge is a comprehensive BitTorrent client designed to cater to your torrenting needs. It operates on a daemon/client model and is equipped with various user interfaces, including GTK-UI, Web-UI, and Console-UI. At its core, Deluge uses libtorrent to efficiently manage the BitTorrent protocol. The app allows you to start various user-interfaces and the Deluge daemon with simple commands. It also provides a web UI that can be accessed at http://localhost:8112 with the default password 'deluge'. For advanced users, Deluge offers features like bandwidth tweaking, VPN, and reverse proxy.", "category": "file-management", "tags": ["File Management", "Networking Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/deluge:2.2.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 6881}}, "links": [{"label": "Documentation", "url": "http://dev.deluge-torrent.org/wiki/UserGuide"}, {"label": "Github", "url": "https://github.com/deluge-torrent/deluge"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "deluge", "port": "$PORT:6881", "volumes": ["/config", "/downloads"], "extra_ports": ["8112:8112"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('devlake', 'DevLake', 'DevLake is a highly customizable and self-hosted tool for engineering metrics and data integration. It enables teams to collect, transform, and visualize data from various development tools like GitHub, GitLab, and Jira. DevLake provides insightful dashboards and reports for continuous improvement, streamlining your software delivery process.', 'engineering-metrics', ARRAY['Engineering Metrics', 'Data Integration', 'Analytics', 'Open-Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "DevLake", "version": "latest", "description": "DevLake is a highly customizable and self-hosted tool for engineering metrics and data integration. It enables teams to collect, transform, and visualize data from various development tools like GitHub, GitLab, and Jira. DevLake provides insightful dashboards and reports for continuous improvement, streamlining your software delivery process.", "category": "engineering-metrics", "tags": ["Engineering Metrics", "Data Integration", "Analytics", "Open-Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Documentation", "url": "https://devlake.apache.org/docs/GettingStarted"}, {"label": "Github", "url": "https://github.com/apache/incubator-devlake"}], "instructions": "Wait for the migration on backend to complete. Access Grafana using https://domain/grafana", "install": [{"docker": {"image": "$IMAGE", "name": "devlake", "port": "$PORT:3000", "volumes": ["/app/logs", "/var/lib/grafana"], "extra_ports": ["4000:4000", "8080:8080"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Wait for the migration on backend to complete. Access Grafana using https://domain/grafana"}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('dify', 'Dify', 'Dify is an open-source platform designed to simplify the development and operation of AI applications using large language models (LLMs). It provides features like visual prompt orchestration, RAG pipeline, agent capabilities, model management, and LLMOps for efficient monitoring and analysis.', 'self-hosted', ARRAY[]::text[], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Dify", "version": "latest", "description": "Dify is an open-source platform designed to simplify the development and operation of AI applications using large language models (LLMs). It provides features like visual prompt orchestration, RAG pipeline, agent capabilities, model management, and LLMOps for efficient monitoring and analysis.", "category": "self-hosted", "tags": [], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://dify.ai"}, {"label": "Documentation", "url": "https://docs.dify.ai"}, {"label": "Github", "url": "https://github.com/langgenius/dify"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "dify", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('dillinger', 'Dillinger', 'Dillinger is an open-source, online Markdown editor designed to provide a seamless and user-friendly experience for writing and editing Markdown files. With its intuitive interface, Dillinger supports real-time preview, file imports/exports, and integration with popular cloud storage services such as Dropbox, Google Drive, GitHub, and OneDrive. It allows users to write Markdown efficiently and export their work in various formats, including HTML, PDF, and Markdown itself. Dillinger operates as a modern, distraction-free editor that simplifies writing and content creation for developers, writers, and professionals.', 'markdown-editor', ARRAY['Markdown Editor', 'Content Creation', 'Productivity Tools', 'Cloud Integration', 'File Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/dillinger:3.39.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Dillinger", "version": "latest", "description": "Dillinger is an open-source, online Markdown editor designed to provide a seamless and user-friendly experience for writing and editing Markdown files. With its intuitive interface, Dillinger supports real-time preview, file imports/exports, and integration with popular cloud storage services such as Dropbox, Google Drive, GitHub, and OneDrive. It allows users to write Markdown efficiently and export their work in various formats, including HTML, PDF, and Markdown itself. Dillinger operates as a modern, distraction-free editor that simplifies writing and content creation for developers, writers, and professionals.", "category": "markdown-editor", "tags": ["Markdown Editor", "Content Creation", "Productivity Tools", "Cloud Integration", "File Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/dillinger:3.39.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Demo", "url": "https://dillinger.io/"}, {"label": "GitHub", "url": "https://github.com/joemccann/dillinger"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "dillinger", "port": "$PORT:8080", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('directus', 'Directus', 'Directus is a modern, open-source data platform that instantly transforms any SQL database into an API and a beautiful no-code app. It is designed to work with any SQL database, allowing you to maintain complete control over your new or existing database without the need for migration to a proprietary data model. The Directus API layers on top of your database, providing both REST and GraphQL APIs for your data. The Directus App enables your entire team to safely and intuitively browse, manage, and visualize data. It is a flexible platform that can be used as a Backend-as-a-Service, a Headless CMS, an Internal Tool Builder, and for Data Management & Analytics. With Directus, you can connect external digital experiences, design APIs, control data flows, build internal tools, and much more.', 'developer-tools', ARRAY['Developer Tools', 'CMS', 'Databases'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "directus/directus:11.17.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8055}}$JSON$::jsonb, $JSON${"metadata": {"name": "Directus", "version": "latest", "description": "Directus is a modern, open-source data platform that instantly transforms any SQL database into an API and a beautiful no-code app. It is designed to work with any SQL database, allowing you to maintain complete control over your new or existing database without the need for migration to a proprietary data model. The Directus API layers on top of your database, providing both REST and GraphQL APIs for your data. The Directus App enables your entire team to safely and intuitively browse, manage, and visualize data. It is a flexible platform that can be used as a Backend-as-a-Service, a Headless CMS, an Internal Tool Builder, and for Data Management & Analytics. With Directus, you can connect external digital experiences, design APIs, control data flows, build internal tools, and much more.", "category": "developer-tools", "tags": ["Developer Tools", "CMS", "Databases"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "directus/directus:11.17.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8055}}, "links": [{"label": "Website", "url": "https://directus.io/"}, {"label": "Documentation", "url": "https://docs.directus.io/"}, {"label": "Github", "url": "https://github.com/directus/docs"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "directus", "port": "$PORT:8055", "volumes": ["/directus/uploads", "/directus/extensions"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "mysql": {"type": "mysql", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('discourse', 'Discourse', 'Discourse is a modern, open-source discussion platform that provides a clean, intuitive interface for community discussions. It''s perfect for forums, mailing lists, chat rooms, and more.', 'forum', ARRAY['Forum', 'Discussion', 'Self-hosted', 'Open Source', 'Community'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "bitnami/discourse:3.4.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Discourse", "version": "latest", "description": "Discourse is a modern, open-source discussion platform that provides a clean, intuitive interface for community discussions. It's perfect for forums, mailing lists, chat rooms, and more.", "category": "forum", "tags": ["Forum", "Discussion", "Self-hosted", "Open Source", "Community"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "bitnami/discourse:3.4.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://www.discourse.org"}, {"label": "Documentation", "url": "https://docs.discourse.org"}, {"label": "GitHub", "url": "https://github.com/discourse/discourse"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/bitnami/discourse"}], "instructions": "Once clicked, please wait for the installation to complete, it will take time. It is also resource intensive, so make sure you have more than 8GB of RAM.", "install": [{"docker": {"image": "$IMAGE", "name": "discourse", "port": "$PORT:3000", "volumes": ["/bitnami/discourse", "/bitnami/discourse"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Once clicked, please wait for the installation to complete, it will take time. It is also resource intensive, so make sure you have more than 8GB of RAM."}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('dittofeed', 'Dittofeed', 'Dittofeed is an advanced, self-hosted customer engagement platform designed to streamline and enhance your marketing automation workflows. It empowers businesses with real-time insights, robust data-driven personalization, and multi-channel communication tools, including email, SMS, and push notifications. Dittofeed offers a user-friendly interface, powerful API integrations, and extensive customization options, making it ideal for organizations of all sizes. By providing a self-hosted solution, Dittofeed ensures data privacy and compliance while giving you full control over your infrastructure and customer data.', 'marketing-automation', ARRAY['Marketing Automation', 'Self-Hosted', 'Customer Engagement', 'Multi-Channel', 'Real-Time Analytics'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "dittofeed/dittofeed-lite:v0.23.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Dittofeed", "version": "latest", "description": "Dittofeed is an advanced, self-hosted customer engagement platform designed to streamline and enhance your marketing automation workflows. It empowers businesses with real-time insights, robust data-driven personalization, and multi-channel communication tools, including email, SMS, and push notifications. Dittofeed offers a user-friendly interface, powerful API integrations, and extensive customization options, making it ideal for organizations of all sizes. By providing a self-hosted solution, Dittofeed ensures data privacy and compliance while giving you full control over your infrastructure and customer data.", "category": "marketing-automation", "tags": ["Marketing Automation", "Self-Hosted", "Customer Engagement", "Multi-Channel", "Real-Time Analytics"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "dittofeed/dittofeed-lite:v0.23.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://dittofeed.com"}, {"label": "Documentation", "url": "https://docs.dittofeed.com/introduction"}, {"label": "Github", "url": "https://github.com/dittofeed/dittofeed"}], "instructions": "Please remove the bootstrap environment variable after the initial setup is complete.", "install": [{"docker": {"image": "$IMAGE", "name": "dittofeed", "port": "$PORT:80", "volumes": ["/var/lib/clickhouse", "/var/log/clickhouse-server", "/data", "/etc/temporal/config/dynamicconfig/prod.yaml", "/etc/temporal/config/dynamicconfig/prod.yaml"], "extra_ports": ["3000:3000", "8080:8080", "9000:9000", "9001:9001"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Please remove the bootstrap environment variable after the initial setup is complete."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('dnote', 'Dnote', 'Dnote is a simple command-line notebook application that helps you capture and organize your thoughts. It provides a clean interface for taking notes and organizing them into books.', 'note-taking', ARRAY['Note Taking', 'CLI', 'Organization', 'Self-Hosted', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "dnote/dnote:3.0.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3001}}$JSON$::jsonb, $JSON${"metadata": {"name": "Dnote", "version": "latest", "description": "Dnote is a simple command-line notebook application that helps you capture and organize your thoughts. It provides a clean interface for taking notes and organizing them into books.", "category": "note-taking", "tags": ["Note Taking", "CLI", "Organization", "Self-Hosted", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "dnote/dnote:3.0.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3001}}, "links": [{"label": "GitHub", "url": "https://github.com/dnote/dnote"}, {"label": "Website", "url": "https://dnote.io"}, {"label": "Documentation", "url": "https://www.getdnote.com/blog/introducing-dnote-web/"}], "instructions": "Configure SMTP to enable email verification and password resets. Dnote v3 uses embedded SQLite \u2014 no external database is required.", "install": [{"docker": {"image": "$IMAGE", "name": "dnote", "port": "$PORT:3001", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Configure SMTP to enable email verification and password resets. Dnote v3 uses embedded SQLite \u2014 no external database is required."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('docker-mailserver', 'Docker Mailserver', 'A fullstack but simple mail server (SMTP, IMAP, LDAP, Antispam, Antivirus, etc.) running inside a container. It provides a complete email solution with features like spam filtering, virus scanning, and secure email delivery.', 'email', ARRAY['Email', 'SMTP', 'IMAP', 'LDAP', 'Antispam', 'Antivirus'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "docker.io/mailserver/docker-mailserver:v15.1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 25}}$JSON$::jsonb, $JSON${"metadata": {"name": "Docker Mailserver", "version": "latest", "description": "A fullstack but simple mail server (SMTP, IMAP, LDAP, Antispam, Antivirus, etc.) running inside a container. It provides a complete email solution with features like spam filtering, virus scanning, and secure email delivery.", "category": "email", "tags": ["Email", "SMTP", "IMAP", "LDAP", "Antispam", "Antivirus"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "docker.io/mailserver/docker-mailserver:v15.1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 25}}, "links": [{"label": "Github", "url": "https://github.com/docker-mailserver/docker-mailserver"}, {"label": "Guide", "url": "https://github.com/docker-mailserver/docker-mailserver/blob/master/mailserver.env"}], "instructions": "Follow the guide to configure the mail server with environment variables.", "install": [{"docker": {"image": "$IMAGE", "name": "docker-mailserver", "port": "$PORT:25", "volumes": ["/var/mail", "/var/mail-state", "/var/log/mail", "/tmp/docker-mailserver", "/etc/localtime"], "extra_ports": ["143:143", "465:465", "587:587", "993:993"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Follow the guide to configure the mail server with environment variables."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('docker-registry', 'Docker Registry', 'Docker Registry 2.0 is a powerful application designed to store and distribute Docker images. This app is an implementation of the Docker Registry HTTP API V2, compatible with Docker 1.6 and later versions. It provides a secure and scalable base for building a large scale registry solution or running a simple private registry. Docker Registry 2.0 is a core library for many registry operators including Docker Hub, GitHub Container Registry, GitLab Container Registry, and DigitalOcean Container Registry. It is also used by the CNCF Harbor Project and VMware Harbor Registry. The app allows users to efficiently store, manage, package, and exchange content, providing a professional grade and extensible content distribution system.', 'developer-tools', ARRAY['Developer Tools', 'Databases'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "registry:3.1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Docker Registry", "version": "latest", "description": "Docker Registry 2.0 is a powerful application designed to store and distribute Docker images. This app is an implementation of the Docker Registry HTTP API V2, compatible with Docker 1.6 and later versions. It provides a secure and scalable base for building a large scale registry solution or running a simple private registry. Docker Registry 2.0 is a core library for many registry operators including Docker Hub, GitHub Container Registry, GitLab Container Registry, and DigitalOcean Container Registry. It is also used by the CNCF Harbor Project and VMware Harbor Registry. The app allows users to efficiently store, manage, package, and exchange content, providing a professional grade and extensible content distribution system.", "category": "developer-tools", "tags": ["Developer Tools", "Databases"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "registry:3.1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5000}}, "links": [{"label": "Website", "url": "https://hub.docker.com/_/registry"}, {"label": "Github", "url": "https://github.com/distribution/distribution"}], "instructions": "The Registry doesn't have a UI. To interact with the registry you should use the Docker CLI.", "install": [{"docker": {"image": "$IMAGE", "name": "docker-registry", "port": "$PORT:5000", "volumes": ["/var/lib/registry"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "The Registry doesn't have a UI. To interact with the registry you should use the Docker CLI."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('dockge', 'Dockge', 'Dockge is a modern, self-hosted Docker Compose management tool that provides a beautiful and intuitive web interface for managing your Docker Compose stacks. It allows you to create, edit, start, stop, and monitor your Docker Compose applications through a user-friendly dashboard. Dockge simplifies Docker Compose management with features like real-time logs, stack monitoring, and easy configuration editing.', 'docker-compose', ARRAY['Docker Compose', 'Container Management', 'Self-Hosted', 'Web Interface', 'Monitoring', 'DevOps', 'Infrastructure', 'YAML Editor', 'Logs', 'Stack Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "louislam/dockge:1.5.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5001}}$JSON$::jsonb, $JSON${"metadata": {"name": "Dockge", "version": "latest", "description": "Dockge is a modern, self-hosted Docker Compose management tool that provides a beautiful and intuitive web interface for managing your Docker Compose stacks. It allows you to create, edit, start, stop, and monitor your Docker Compose applications through a user-friendly dashboard. Dockge simplifies Docker Compose management with features like real-time logs, stack monitoring, and easy configuration editing.", "category": "docker-compose", "tags": ["Docker Compose", "Container Management", "Self-Hosted", "Web Interface", "Monitoring", "DevOps", "Infrastructure", "YAML Editor", "Logs", "Stack Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "louislam/dockge:1.5.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5001}}, "links": [{"label": "GitHub", "url": "https://github.com/louislam/dockge"}, {"label": "Documentation", "url": "https://dockge.kuma.pet/"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/louislam/dockge"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "dockge", "port": "$PORT:5001", "volumes": ["/var/run/docker.sock", "/app/data", "/root/dockge/stacks"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('dockhand', 'Dockhand', 'Dockhand is a modern Docker container management and monitoring tool that provides an intuitive web interface for managing your Docker containers, images, volumes, and networks. With real-time container statistics, log viewing, and container lifecycle management, Dockhand simplifies Docker operations for both developers and system administrators. The application offers comprehensive container management capabilities including start, stop, restart, and removal operations, along with detailed container information and resource usage monitoring. Perfect for developers who need a visual interface for Docker management, system administrators monitoring container infrastructure, or teams looking for an alternative to command-line Docker tools.', 'docker', ARRAY['Docker', 'Container Management', 'Monitoring', 'DevOps', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "fnsys/dockhand:48a80675"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Dockhand", "version": "latest", "description": "Dockhand is a modern Docker container management and monitoring tool that provides an intuitive web interface for managing your Docker containers, images, volumes, and networks. With real-time container statistics, log viewing, and container lifecycle management, Dockhand simplifies Docker operations for both developers and system administrators. The application offers comprehensive container management capabilities including start, stop, restart, and removal operations, along with detailed container information and resource usage monitoring. Perfect for developers who need a visual interface for Docker management, system administrators monitoring container infrastructure, or teams looking for an alternative to command-line Docker tools.", "category": "docker", "tags": ["Docker", "Container Management", "Monitoring", "DevOps", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "fnsys/dockhand:48a80675"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "GitHub", "url": "https://github.com/fnsys/dockhand"}, {"label": "Website", "url": "https://dockhand.pro"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/fnsys/dockhand"}], "instructions": "After deployment, access Dockhand at your domain. The application requires\naccess to the Docker socket to manage containers. Make sure you have the\nnecessary permissions to access the Docker daemon.\n", "install": [{"docker": {"image": "$IMAGE", "name": "dockhand", "port": "$PORT:3000", "volumes": ["/var/run/docker.sock", "/app/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deployment, access Dockhand at your domain. The application requires\naccess to the Docker socket to manage containers. Make sure you have the\nnecessary permissions to access the Docker daemon.\n"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('docmost', 'Docmost', 'Docmost is a secure and versatile self-hosted platform for document management and collaboration. It enables organizations to efficiently store, manage, and share documents while maintaining complete control over their data. Docmost is built to streamline workflows, enhance team collaboration, and ensure data privacy. It provides an intuitive interface and robust features for document editing, version control, and seamless integrations with other tools and services. Designed for businesses of all sizes, Docmost empowers teams to work smarter and more securely.', 'document-management', ARRAY['Document Management', 'Collaboration', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "docmost/docmost:0.80.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Docmost", "version": "latest", "description": "Docmost is a secure and versatile self-hosted platform for document management and collaboration. It enables organizations to efficiently store, manage, and share documents while maintaining complete control over their data. Docmost is built to streamline workflows, enhance team collaboration, and ensure data privacy. It provides an intuitive interface and robust features for document editing, version control, and seamless integrations with other tools and services. Designed for businesses of all sizes, Docmost empowers teams to work smarter and more securely.", "category": "document-management", "tags": ["Document Management", "Collaboration", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "docmost/docmost:0.80.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Documentation", "url": "https://docmost.com/docs/"}, {"label": "Github", "url": "https://github.com/Docmost/Docmost"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "docmost", "port": "$PORT:3000", "volumes": ["/app/data/storage"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('docpht', 'DocPHT', 'DocPHT is a document management system that helps you organize and manage your documents. It provides a simple and intuitive interface for storing, organizing, and sharing documents.', 'document-management', ARRAY['Document Management', 'Organization', 'Self-Hosted', 'Web Application', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "docpht/docpht:v1.3.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "DocPHT", "version": "latest", "description": "DocPHT is a document management system that helps you organize and manage your documents. It provides a simple and intuitive interface for storing, organizing, and sharing documents.", "category": "document-management", "tags": ["Document Management", "Organization", "Self-Hosted", "Web Application", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "docpht/docpht:v1.3.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "GitHub", "url": "https://github.com/docpht/docpht"}, {"label": "Website", "url": "https://docpht.org"}, {"label": "Documentation", "url": "https://docs.docpht.org"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "docpht", "port": "$PORT:80", "volumes": ["/var/www/app/src/config", "/var/www/app/data", "/var/www/app/pages"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('docspell', 'Docspell', 'Docspell is a personal document management system designed to archive and organize your digital documents. It helps you scan, organize, search, and retrieve your documents with ease. Docspell automatically processes documents, extracts text via OCR, and makes your documents searchable through full-text search powered by Solr. The system consists of multiple components a REST server for the web interface, a job executor (joex) for background processing, a directory consumer for automatic document ingestion, and Solr for powerful search capabilities. Docspell helps you categorize documents, add metadata, and efficiently manage your paperwork in a secure, self-hosted environment.', 'document-management', ARRAY['Document Management', 'OCR', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/docspell/restserver:v0.43"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Docspell", "version": "latest", "description": "Docspell is a personal document management system designed to archive and organize your digital documents. It helps you scan, organize, search, and retrieve your documents with ease. Docspell automatically processes documents, extracts text via OCR, and makes your documents searchable through full-text search powered by Solr. The system consists of multiple components a REST server for the web interface, a job executor (joex) for background processing, a directory consumer for automatic document ingestion, and Solr for powerful search capabilities. Docspell helps you categorize documents, add metadata, and efficiently manage your paperwork in a secure, self-hosted environment.", "category": "document-management", "tags": ["Document Management", "OCR", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/docspell/restserver:v0.43"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Documentation", "url": "https://docspell.org/docs/"}, {"label": "Github", "url": "https://github.com/eikek/docspell"}], "instructions": "The initial setup requires creating a user account.", "install": [{"docker": {"image": "$IMAGE", "name": "docspell", "port": "$PORT:80", "volumes": ["/opt/docs"], "extra_ports": ["7880:7880"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "The initial setup requires creating a user account."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('documenso', 'Documenso', 'The open source DocuSign alternative. Securely sign documents without giving up your privacy or freedom.', 'document-management', ARRAY['Document Management', 'E-Signatures', 'Business Tools', 'Legal'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "documenso/documenso:v2.9.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Documenso", "version": "latest", "description": "The open source DocuSign alternative. Securely sign documents without giving up your privacy or freedom.", "category": "document-management", "tags": ["Document Management", "E-Signatures", "Business Tools", "Legal"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "documenso/documenso:v2.9.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://documenso.com/"}, {"label": "Documentation", "url": "https://docs.documenso.com/"}, {"label": "Github", "url": "https://github.com/documenso/documenso"}, {"label": "Stackoverflow", "url": "https://stackoverflow.com/questions/21141215/creating-a-p12-file"}], "instructions": "Please follow the below given stackoverflow instructions to create the .p12 file and provide the path of that file to the required field.", "install": [{"docker": {"image": "$IMAGE", "name": "documenso", "port": "$PORT:3000", "volumes": ["/app/certs/cert.p12"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Please follow the below given stackoverflow instructions to create the .p12 file and provide the path of that file to the required field."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('documize', 'Documize', 'Documize Zerabase is a powerful business tool designed to manage product delivery and insight discovery. It serves as a Product Engineering Hub, unifying product plans, assets, documents, app analytics, and customer conversations. This remarkable offline-first desktop software becomes your product headquarters, centralizing content and information for everyone to see and act upon, making it a game-changer for product teams. On the other hand, the Community feature of Documize offers a simple, delightful way to capture and share knowledge management. It covers processes, guidelines, manuals, and everything in-between, allowing you to document your business with ease. It''s designed for both technical and non-technical users, organizing content through labels, spaces, and categories. The Community+ edition offers advanced capabilities such as content approval workflows, content organization, version management, lifecycle management, feedback capture, PDF export, analytics, reporting, and more.', 'documentation', ARRAY['Documentation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/easypanel-community/docker-documize:5.13"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Documize", "version": "latest", "description": "Documize Zerabase is a powerful business tool designed to manage product delivery and insight discovery. It serves as a Product Engineering Hub, unifying product plans, assets, documents, app analytics, and customer conversations. This remarkable offline-first desktop software becomes your product headquarters, centralizing content and information for everyone to see and act upon, making it a game-changer for product teams. On the other hand, the Community feature of Documize offers a simple, delightful way to capture and share knowledge management. It covers processes, guidelines, manuals, and everything in-between, allowing you to document your business with ease. It's designed for both technical and non-technical users, organizing content through labels, spaces, and categories. The Community+ edition offers advanced capabilities such as content approval workflows, content organization, version management, lifecycle management, feedback capture, PDF export, analytics, reporting, and more.", "category": "documentation", "tags": ["Documentation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/easypanel-community/docker-documize:5.13"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://documize.com"}, {"label": "Documentation", "url": "https://docs.documize.com/docs"}, {"label": "Github", "url": "https://github.com/documize/community"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "documize", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('docuseal', 'DocuSeal', 'DocuSeal is an open source platform that provides secure and efficient digital document signing and processing. Create PDF forms to have them filled and signed online on any device with an easy-to-use, mobile-optimized web tool.', 'pdf', ARRAY['PDF'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "docuseal/docuseal:2.5.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "DocuSeal", "version": "latest", "description": "DocuSeal is an open source platform that provides secure and efficient digital document signing and processing. Create PDF forms to have them filled and signed online on any device with an easy-to-use, mobile-optimized web tool.", "category": "pdf", "tags": ["PDF"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "docuseal/docuseal:2.5.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://www.docuseal.co/"}, {"label": "Documentation", "url": "https://www.docuseal.co/docs"}, {"label": "Github", "url": "https://github.com/docusealco/docuseal"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "docuseal", "port": "$PORT:3000", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('dokuwiki', 'Dokuwiki', 'DokuWiki is a highly versatile, open-source wiki software that is simple to use and doesn''t require a database. It is known for its clean and readable syntax, making it a favorite among administrators due to its ease of maintenance, backup, and integration. DokuWiki is equipped with built-in access controls and authentication connectors, making it particularly useful in an enterprise context. It supports a wide range of use cases beyond a traditional wiki, thanks to the large number of plugins available. DokuWiki is designed for collaboration, allowing quick updates and easy addition of new pages while maintaining a history of every change. It can be used as a corporate knowledge base, private notebook, software manual, project workspace, CMS, intranet, and more. DokuWiki supports customization at all levels of expertise, from easy configuration via the admin interface to developing your own extensions.', 'wiki', ARRAY['Wiki'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/dokuwiki:2025-05-14"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Dokuwiki", "version": "latest", "description": "DokuWiki is a highly versatile, open-source wiki software that is simple to use and doesn't require a database. It is known for its clean and readable syntax, making it a favorite among administrators due to its ease of maintenance, backup, and integration. DokuWiki is equipped with built-in access controls and authentication connectors, making it particularly useful in an enterprise context. It supports a wide range of use cases beyond a traditional wiki, thanks to the large number of plugins available. DokuWiki is designed for collaboration, allowing quick updates and easy addition of new pages while maintaining a history of every change. It can be used as a corporate knowledge base, private notebook, software manual, project workspace, CMS, intranet, and more. DokuWiki supports customization at all levels of expertise, from easy configuration via the admin interface to developing your own extensions.", "category": "wiki", "tags": ["Wiki"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/dokuwiki:2025-05-14"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://dokuwiki.org"}, {"label": "Documentation", "url": "https://www.dokuwiki.org/manual"}, {"label": "Github", "url": "https://github.com/splitbrain/dokuwiki"}], "instructions": "Go to http://IP-ADDRESS:PORT/install.php to configure your install then restart your container when finished to remove install.php", "install": [{"docker": {"image": "$IMAGE", "name": "dokuwiki", "port": "$PORT:80", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Go to http://IP-ADDRESS:PORT/install.php to configure your install then restart your container when finished to remove install.php"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('dolibarr', 'Dolibarr', 'Dolibarr ERP/CRM is an open-source platform designed for small to medium-sized enterprises (SMEs) to manage business operations seamlessly. It offers a comprehensive suite of tools for managing customers, invoices, orders, products, projects, and more. With its modular architecture and user-friendly interface, Dolibarr provides flexibility and scalability for businesses looking for an efficient and customizable ERP/CRM solution.', 'erp', ARRAY['ERP', 'CRM', 'Open Source', 'Invoicing', 'Inventory Management', 'Project Management', 'Small Business', 'Customizable'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "dolibarr/dolibarr:23"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Dolibarr", "version": "latest", "description": "Dolibarr ERP/CRM is an open-source platform designed for small to medium-sized enterprises (SMEs) to manage business operations seamlessly. It offers a comprehensive suite of tools for managing customers, invoices, orders, products, projects, and more. With its modular architecture and user-friendly interface, Dolibarr provides flexibility and scalability for businesses looking for an efficient and customizable ERP/CRM solution.", "category": "erp", "tags": ["ERP", "CRM", "Open Source", "Invoicing", "Inventory Management", "Project Management", "Small Business", "Customizable"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "dolibarr/dolibarr:23"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://www.dolibarr.org/"}, {"label": "Documentation", "url": "https://wiki.dolibarr.org/"}, {"label": "Compose Docs", "url": "https://github.com/Dolibarr/dolibarr/blob/develop/README.md"}, {"label": "GitHub", "url": "https://github.com/Dolibarr/dolibarr"}], "instructions": "Default Credentials; username; admin, password; admin", "install": [{"docker": {"image": "$IMAGE", "name": "dolibarr", "port": "$PORT:80", "volumes": ["/var/www/scripts/docker-init.d", "/var/www/scripts/before-starting.d"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Default Credentials; username; admin, password; admin"}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('dolphin', 'Dolphin', 'Dolphin is a powerful GameCube and Wii emulator that allows you to play your favorite Nintendo games on modern hardware. With support for high-definition graphics, save states, and enhanced controls, Dolphin brings classic gaming to life with improved performance and visual quality. This browser-accessible version provides the full Dolphin emulator through a web interface, enabling you to play retro games from anywhere without local installation.', 'gaming', ARRAY['Gaming', 'Emulator', 'GameCube', 'Wii', 'Nintendo', 'Desktop', 'Browser'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/dolphin:40d9d3af-ls61"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Dolphin", "version": "latest", "description": "Dolphin is a powerful GameCube and Wii emulator that allows you to play your favorite Nintendo games on modern hardware. With support for high-definition graphics, save states, and enhanced controls, Dolphin brings classic gaming to life with improved performance and visual quality. This browser-accessible version provides the full Dolphin emulator through a web interface, enabling you to play retro games from anywhere without local installation.", "category": "gaming", "tags": ["Gaming", "Emulator", "GameCube", "Wii", "Nintendo", "Desktop", "Browser"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/dolphin:40d9d3af-ls61"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://dolphin-emu.org/"}, {"label": "Documentation", "url": "https://dolphin-emu.org/docs/guides/"}, {"label": "GitHub", "url": "https://github.com/dolphin-emu/dolphin"}], "instructions": "Open Dolphin in your browser and complete the first-run wizard. Add your game files under `/config` (for example in `/config/roms`) so they persist across updates/redeploys, then configure that path in Dolphin's game directories. For best performance, run this template on a host with hardware acceleration enabled and use a gamepad when possible.", "install": [{"docker": {"image": "$IMAGE", "name": "dolphin", "port": "$PORT:3000", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Open Dolphin in your browser and complete the first-run wizard. Add your game files under `/config` (for example in `/config/roms`) so they persist across updates/redeploys, then configure that path in Dolphin's game directories. For best performance, run this template on a host with hardware acceleration enabled and use a gamepad when possible."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('domainlocker', 'Domain Locker', 'Domain Locker is a self-hosted domain portfolio management and monitoring application designed to help you keep track of all your registered domains. It provides centralized management for domain registrations, expiration dates, renewal reminders, DNS records, SSL certificates, and hosting information. Domain Locker features automated WHOIS lookups, expiration notifications via email, domain health checks, and comprehensive reporting. With scheduled updates and monitoring, you''ll never miss a domain renewal deadline again. The application includes automatic daily checks for domain updates and sends timely expiration reminders. Perfect for domain investors, web developers, agencies, and anyone managing multiple domain portfolios who needs a reliable system to track and monitor their digital assets.', 'domain-management', ARRAY['Domain Management', 'Domain Monitoring', 'WHOIS', 'DNS', 'Domain Portfolio'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lissy93/domain-locker:0.1.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Domain Locker", "version": "latest", "description": "Domain Locker is a self-hosted domain portfolio management and monitoring application designed to help you keep track of all your registered domains. It provides centralized management for domain registrations, expiration dates, renewal reminders, DNS records, SSL certificates, and hosting information. Domain Locker features automated WHOIS lookups, expiration notifications via email, domain health checks, and comprehensive reporting. With scheduled updates and monitoring, you'll never miss a domain renewal deadline again. The application includes automatic daily checks for domain updates and sends timely expiration reminders. Perfect for domain investors, web developers, agencies, and anyone managing multiple domain portfolios who needs a reliable system to track and monitor their digital assets.", "category": "domain-management", "tags": ["Domain Management", "Domain Monitoring", "WHOIS", "DNS", "Domain Portfolio"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lissy93/domain-locker:0.1.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Github", "url": "https://github.com/Lissy93/domain-locker"}, {"label": "Website", "url": "https://domain-locker.com"}, {"label": "Documentation", "url": "https://domain-locker.com/about"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "domainlocker", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('domainmod', 'DomainMod', 'DomainMOD is a comprehensive open-source application designed to help you manage your domains and other internet assets in one central location. With DomainMOD, you can keep track of your domains, SSL certificates, registrar and SSL accounts, web hosting, DNS servers, IP addresses, and more. The application also offers a Bulk Domain Updater, allowing you to modify multiple domains at once, saving you time and effort. DomainMOD also includes a Data Warehouse feature, which lets you import data from your WHM web servers for analysis and reporting. The app is mobile-friendly, ensuring you can access your data anytime, anywhere. Furthermore, DomainMOD respects your privacy, ensuring only you have access to your data.', 'domain-management', ARRAY['Domain Management', 'Web Hosting', 'Data Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "domainmod/domainmod:4.23"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "DomainMod", "version": "latest", "description": "DomainMOD is a comprehensive open-source application designed to help you manage your domains and other internet assets in one central location. With DomainMOD, you can keep track of your domains, SSL certificates, registrar and SSL accounts, web hosting, DNS servers, IP addresses, and more. The application also offers a Bulk Domain Updater, allowing you to modify multiple domains at once, saving you time and effort. DomainMOD also includes a Data Warehouse feature, which lets you import data from your WHM web servers for analysis and reporting. The app is mobile-friendly, ensuring you can access your data anytime, anywhere. Furthermore, DomainMOD respects your privacy, ensuring only you have access to your data.", "category": "domain-management", "tags": ["Domain Management", "Web Hosting", "Data Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "domainmod/domainmod:4.23"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://domainmod.org/"}, {"label": "Documentation", "url": "https://domainmod.org/docs/"}, {"label": "Github", "url": "https://github.com/domainmod/domainmod/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "domainmod", "port": "$PORT:80", "volumes": ["/var/www/html"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('doppelganger', 'Doppelganger', 'Doppelganger (Figranium) is a self-hosted browser automation and scraping platform built on Playwright. It offers a visual task editor, structured JSON task format, and execution modes for simple scraping to complex, human-like browser interactions. Includes noVNC for remote browser viewing.', 'automation', ARRAY['Automation', 'Scraping', 'Playwright', 'Browser', 'Open Source', 'Self-hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "mnemosyneai/doppelganger:v0.12.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 11345}}$JSON$::jsonb, $JSON${"metadata": {"name": "Doppelganger", "version": "latest", "description": "Doppelganger (Figranium) is a self-hosted browser automation and scraping platform built on Playwright. It offers a visual task editor, structured JSON task format, and execution modes for simple scraping to complex, human-like browser interactions. Includes noVNC for remote browser viewing.", "category": "automation", "tags": ["Automation", "Scraping", "Playwright", "Browser", "Open Source", "Self-hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "mnemosyneai/doppelganger:v0.12.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 11345}}, "links": [{"label": "Website", "url": "https://doppelgangerdev.com"}, {"label": "Documentation", "url": "https://figranium.dev/docs/overview"}, {"label": "GitHub", "url": "https://github.com/mnemosynestack/doppelganger"}], "instructions": "Open your app domain to access the Doppelganger web interface and create your first automation task.\nData persistence is enabled in the mounted `/app/data` volume and update to a newer image tag when available.\n", "install": [{"docker": {"image": "$IMAGE", "name": "doppelganger", "port": "$PORT:11345", "volumes": ["/app/data"], "extra_ports": ["54311:54311"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Open your app domain to access the Doppelganger web interface and create your first automation task.\nData persistence is enabled in the mounted `/app/data` volume and update to a newer image tag when available.\n"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('doublecommander', 'Double Commander', 'A cross-platform open-source file manager with two panels side by side. It is inspired by Total Commander and features a modern interface with extensive file management capabilities.', 'file-manager', ARRAY['File Manager', 'FTP Client', 'Self-hosted', 'Open Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/doublecommander:version-9bcf3fdc"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Double Commander", "version": "latest", "description": "A cross-platform open-source file manager with two panels side by side. It is inspired by Total Commander and features a modern interface with extensive file management capabilities.", "category": "file-manager", "tags": ["File Manager", "FTP Client", "Self-hosted", "Open Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/doublecommander:version-9bcf3fdc"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "GitHub", "url": "https://github.com/doublecmd/doublecmd"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/linuxserver/doublecommander"}, {"label": "Website", "url": "https://doublecmd.sourceforge.io"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "doublecommander", "port": "$PORT:3000", "volumes": ["/config", "/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('dozzle', 'Dozzle', 'Dozzle is a lightweight, web-based Docker log viewer designed for real-time monitoring and easy troubleshooting. It allows you to view logs of other Docker containers in real-time, streaming new log entries to the web interface without the need for page refreshes. Despite its capabilities, Dozzle is a small application that consumes very little memory and CPU, ensuring it doesn''t cause performance issues when run alongside other containers. It also supports connecting to multiple remote hosts, providing a simple drop-down menu to switch between different hosts. Dozzle doesn''t store any log files and is solely for live monitoring of your container logs. It also features an intelligent fuzzy search for container names, regex log search, split screen for viewing multiple logs, and live stats with memory and CPU usage. It also provides authentication with a username and password for added security.', 'monitoring', ARRAY['Monitoring', 'Logging'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "amir20/dozzle:v10.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Dozzle", "version": "latest", "description": "Dozzle is a lightweight, web-based Docker log viewer designed for real-time monitoring and easy troubleshooting. It allows you to view logs of other Docker containers in real-time, streaming new log entries to the web interface without the need for page refreshes. Despite its capabilities, Dozzle is a small application that consumes very little memory and CPU, ensuring it doesn't cause performance issues when run alongside other containers. It also supports connecting to multiple remote hosts, providing a simple drop-down menu to switch between different hosts. Dozzle doesn't store any log files and is solely for live monitoring of your container logs. It also features an intelligent fuzzy search for container names, regex log search, split screen for viewing multiple logs, and live stats with memory and CPU usage. It also provides authentication with a username and password for added security.", "category": "monitoring", "tags": ["Monitoring", "Logging"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "amir20/dozzle:v10.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Website", "url": "https://dozzle.dev"}, {"label": "Github", "url": "https://github.com/amir20/dozzle"}, {"label": "Docker", "url": "https://hub.docker.com/r/amir20/dozzle"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "dozzle", "port": "$PORT:8080", "volumes": ["/var/run/docker.sock"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('dpaste', 'dPaste', 'dPaste is a simple and lightweight pastebin service that allows you to share text snippets, code, and other content quickly. It provides a clean interface for creating, sharing, and managing pastes with support for syntax highlighting and expiration times.', 'pastebin', ARRAY['Pastebin', 'Code Sharing', 'Text Sharing', 'Self-Hosted', 'Development Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "darrenofficial/dpaste:64068f7a"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}$JSON$::jsonb, $JSON${"metadata": {"name": "dPaste", "version": "latest", "description": "dPaste is a simple and lightweight pastebin service that allows you to share text snippets, code, and other content quickly. It provides a clean interface for creating, sharing, and managing pastes with support for syntax highlighting and expiration times.", "category": "pastebin", "tags": ["Pastebin", "Code Sharing", "Text Sharing", "Self-Hosted", "Development Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "darrenofficial/dpaste:64068f7a"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}, "links": [{"label": "Github", "url": "https://github.com/DarrenOfficial/dpaste"}], "instructions": "After installation, access the web interface through the provided domain to start creating and sharing pastes.", "install": [{"docker": {"image": "$IMAGE", "name": "dpaste", "port": "$PORT:8000", "volumes": ["/db"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After installation, access the web interface through the provided domain to start creating and sharing pastes."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('dragonfly', 'DragonflyDB', 'DragonflyDB is a modern, high-performance, Redis-compatible in-memory datastore that''s designed for cloud workloads. It offers superior performance with up to 25x higher throughput than Redis while using fewer resources. DragonflyDB is fully compatible with Redis APIs and commands, making it a drop-in replacement that doesn''t require code changes. It features automatic snapshots, optional persistence to disk, built-in replication, and efficient memory management. Perfect for caching, session storage, real-time analytics, and any use case that requires blazing-fast data access with lower operational costs.', 'database', ARRAY['Database', 'Cache', 'In-Memory', 'Redis', 'Performance'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "docker.dragonflydb.io/dragonflydb/dragonfly:v1.38.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 6379}}$JSON$::jsonb, $JSON${"metadata": {"name": "DragonflyDB", "version": "latest", "description": "DragonflyDB is a modern, high-performance, Redis-compatible in-memory datastore that's designed for cloud workloads. It offers superior performance with up to 25x higher throughput than Redis while using fewer resources. DragonflyDB is fully compatible with Redis APIs and commands, making it a drop-in replacement that doesn't require code changes. It features automatic snapshots, optional persistence to disk, built-in replication, and efficient memory management. Perfect for caching, session storage, real-time analytics, and any use case that requires blazing-fast data access with lower operational costs.", "category": "database", "tags": ["Database", "Cache", "In-Memory", "Redis", "Performance"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "docker.dragonflydb.io/dragonflydb/dragonfly:v1.38.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 6379}}, "links": [{"label": "Website", "url": "https://www.dragonflydb.io/"}, {"label": "Documentation", "url": "https://www.dragonflydb.io/docs"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/dragonflydb/dragonfly"}, {"label": "Github", "url": "https://github.com/dragonflydb/dragonfly"}], "instructions": "After deployment, you can connect to DragonflyDB using any Redis client on port 6379. Make sure to use the password you configured for secure access. Data is automatically persisted to the mounted volume based on the snapshot schedule.", "install": [{"docker": {"image": "$IMAGE", "name": "dragonfly", "port": "$PORT:6379", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deployment, you can connect to DragonflyDB using any Redis client on port 6379. Make sure to use the password you configured for secure access. Data is automatically persisted to the mounted volume based on the snapshot schedule."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('drawdb', 'DrawDB', 'DrawDB is a free, simple, and intuitive online database schema editor and SQL generator.  It provides a robust and user-friendly database entity relationship (ER) editor that runs  directly in your browser. With DrawDB, you can build database diagrams with a few clicks,  export SQL scripts, customize your editor, and manage database schemas without creating an  account. The tool supports multiple database types including MySQL, PostgreSQL, SQLite, SQL Server, and more.', 'database', ARRAY['Database', 'Schema Design', 'ER Diagram', 'SQL Generator', 'Database Design', 'Entity Relationship', 'MySQL', 'PostgreSQL', 'SQLite', 'Visual Editor'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/drawdb-io/drawdb:v1.6.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "DrawDB", "version": "latest", "description": "DrawDB is a free, simple, and intuitive online database schema editor and SQL generator.  It provides a robust and user-friendly database entity relationship (ER) editor that runs  directly in your browser. With DrawDB, you can build database diagrams with a few clicks,  export SQL scripts, customize your editor, and manage database schemas without creating an  account. The tool supports multiple database types including MySQL, PostgreSQL, SQLite, SQL Server, and more.", "category": "database", "tags": ["Database", "Schema Design", "ER Diagram", "SQL Generator", "Database Design", "Entity Relationship", "MySQL", "PostgreSQL", "SQLite", "Visual Editor"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/drawdb-io/drawdb:v1.6.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "GitHub", "url": "https://github.com/drawdb-io/drawdb"}, {"label": "Documentation", "url": "https://github.com/drawdb-io/drawdb#readme"}, {"label": "Demo", "url": "https://drawdb.app"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "drawdb", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('drawio', 'Draw.io', 'Draw.io is a versatile, self-hosted diagramming tool designed for individuals and teams. It provides an intuitive, drag-and-drop interface for creating flowcharts, network diagrams, UML diagrams, and more. Draw.io supports integrations with various cloud storage solutions such as Google Drive, OneDrive, and local storage for easy file management. With a focus on simplicity and functionality, Draw.io enables seamless collaboration and offline access, ensuring that users can work efficiently. Its rich library of shapes, templates, and customization options caters to a wide range of diagramming needs.', 'diagramming', ARRAY['Diagramming', 'Collaboration', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "jgraph/drawio:29.7.9"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Draw.io", "version": "latest", "description": "Draw.io is a versatile, self-hosted diagramming tool designed for individuals and teams. It provides an intuitive, drag-and-drop interface for creating flowcharts, network diagrams, UML diagrams, and more. Draw.io supports integrations with various cloud storage solutions such as Google Drive, OneDrive, and local storage for easy file management. With a focus on simplicity and functionality, Draw.io enables seamless collaboration and offline access, ensuring that users can work efficiently. Its rich library of shapes, templates, and customization options caters to a wide range of diagramming needs.", "category": "diagramming", "tags": ["Diagramming", "Collaboration", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "jgraph/drawio:29.7.9"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Website", "url": "https://drawio-app.com/"}, {"label": "Documentation", "url": "https://github.com/jgraph/drawio/wiki"}, {"label": "Github", "url": "https://github.com/jgraph/drawio"}, {"label": "Docker Guide", "url": "https://www.drawio.com/blog/diagrams-docker-app"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "drawio", "port": "$PORT:8080", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('drone-runner', 'Drone Runner', 'Drone.io is a self-service Continuous Integration platform designed for busy development teams. It automates software build and testing, making it easier for teams to manage their development process. The platform allows for configuration as a code, with pipelines configured through a simple, easy-to-read file committed to your git repository. Each pipeline step is executed inside an isolated Docker container that is automatically downloaded at runtime. Drone.io integrates seamlessly with multiple source code management systems, including GitHub, GitHubEnterprise, Bitbucket, and GitLab. It supports multiple operating systems and architectures, and works with any language, database, or service that runs inside a Docker container. The platform also allows for advanced customization, including custom access controls, approval workflows, secret management, and yaml syntax extensions. Drone.io ensures that every build runs in an isolated Docker container, providing full control and preventing conflicting builds on shared servers.', 'developer-tools', ARRAY['Developer Tools', 'Continuous Integration', 'Automation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "drone/drone-runner-docker:1.8.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Drone Runner", "version": "latest", "description": "Drone.io is a self-service Continuous Integration platform designed for busy development teams. It automates software build and testing, making it easier for teams to manage their development process. The platform allows for configuration as a code, with pipelines configured through a simple, easy-to-read file committed to your git repository. Each pipeline step is executed inside an isolated Docker container that is automatically downloaded at runtime. Drone.io integrates seamlessly with multiple source code management systems, including GitHub, GitHubEnterprise, Bitbucket, and GitLab. It supports multiple operating systems and architectures, and works with any language, database, or service that runs inside a Docker container. The platform also allows for advanced customization, including custom access controls, approval workflows, secret management, and yaml syntax extensions. Drone.io ensures that every build runs in an isolated Docker container, providing full control and preventing conflicting builds on shared servers.", "category": "developer-tools", "tags": ["Developer Tools", "Continuous Integration", "Automation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "drone/drone-runner-docker:1.8.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://drone.io/"}, {"label": "Documentation", "url": "https://github.com/harness/drone#setup-documentation"}, {"label": "Github", "url": "https://github.com/harness/drone"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "drone-runner", "port": "$PORT:3000", "volumes": ["/var/run/docker.sock"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('drone', 'Drone', 'Drone.io is a self-service Continuous Integration platform designed for busy development teams. It automates software build and testing, making it an essential tool for efficient and effective software development. Drone.io is configured with a simple, easy-to-read file that you commit to your git repository, and each pipeline step is executed inside an isolated Docker container that is automatically downloaded at runtime. The platform integrates seamlessly with multiple source code management systems, including GitHub, GitHubEnterprise, Bitbucket, and GitLab, and supports multiple operating systems and architectures. Drone.io works with any language, database or service that runs inside a Docker container, and allows you to create and share plugins for pre-configured steps in your pipeline. Advanced customization is made easy with Drone.io, with features for implementing custom access controls, approval workflows, secret management, yaml syntax extensions and more. The platform also ensures isolated builds to avoid conflicts on shared servers, and offers effortless scaling.', 'developer-tools', ARRAY['Developer Tools', 'Continuous Integration', 'Automation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "drone/drone:2.27.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Drone", "version": "latest", "description": "Drone.io is a self-service Continuous Integration platform designed for busy development teams. It automates software build and testing, making it an essential tool for efficient and effective software development. Drone.io is configured with a simple, easy-to-read file that you commit to your git repository, and each pipeline step is executed inside an isolated Docker container that is automatically downloaded at runtime. The platform integrates seamlessly with multiple source code management systems, including GitHub, GitHubEnterprise, Bitbucket, and GitLab, and supports multiple operating systems and architectures. Drone.io works with any language, database or service that runs inside a Docker container, and allows you to create and share plugins for pre-configured steps in your pipeline. Advanced customization is made easy with Drone.io, with features for implementing custom access controls, approval workflows, secret management, yaml syntax extensions and more. The platform also ensures isolated builds to avoid conflicts on shared servers, and offers effortless scaling.", "category": "developer-tools", "tags": ["Developer Tools", "Continuous Integration", "Automation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "drone/drone:2.27.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://drone.io/"}, {"label": "Documentation", "url": "https://github.com/harness/drone#setup-documentation"}, {"label": "Github", "url": "https://github.com/harness/drone"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "drone", "port": "$PORT:80", "volumes": ["/var/run/docker.sock", "/data"], "extra_ports": ["3000:3000"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('droppy', 'Droppy', 'Droppy is a self-hosted file storage and sharing server with a modern, web-based interface. It allows you to securely upload, manage, and share files and folders from any device with a browser. Droppy supports drag-and-drop uploads, real-time updates, and previews for a variety of file types including images, videos, and documents. With its user-friendly interface and robust feature set, Droppy is ideal for personal or team file management. It is lightweight, written in Node.js, and supports customization through environment variables and themes.', 'file-sharing', ARRAY['File Sharing', 'Storage', 'Productivity', 'Collaboration'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "silverwind/droppy:12.2.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8989}}$JSON$::jsonb, $JSON${"metadata": {"name": "Droppy", "version": "latest", "description": "Droppy is a self-hosted file storage and sharing server with a modern, web-based interface. It allows you to securely upload, manage, and share files and folders from any device with a browser. Droppy supports drag-and-drop uploads, real-time updates, and previews for a variety of file types including images, videos, and documents. With its user-friendly interface and robust feature set, Droppy is ideal for personal or team file management. It is lightweight, written in Node.js, and supports customization through environment variables and themes.", "category": "file-sharing", "tags": ["File Sharing", "Storage", "Productivity", "Collaboration"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "silverwind/droppy:12.2.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8989}}, "links": [{"label": "Documentation", "url": "https://github.com/silverwind/droppy/wiki"}, {"label": "Github", "url": "https://github.com/silverwind/droppy"}, {"label": "Website", "url": "https://www.droppyjs.com/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "droppy", "port": "$PORT:8989", "volumes": ["/config", "/files"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('drupal', 'Drupal', 'Drupal is a powerful open-source content management system (CMS) designed to help you create and manage complex, dynamic websites with ease. Drupal is highly customizable, offering robust tools for managing content, users, permissions, and workflows. It supports custom themes, modules, and integrations, enabling you to create tailored experiences for any type of website, from blogs and portfolios to eCommerce platforms and enterprise-level solutions. Drupal prioritizes flexibility, scalability, and security, making it a preferred choice for developers, businesses, and organizations worldwide.', 'content-management', ARRAY['Content Management', 'Website Development', 'Open Source', 'Enterprise CMS', 'Modular Architecture'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "drupal:11.2.11-apache"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Drupal", "version": "latest", "description": "Drupal is a powerful open-source content management system (CMS) designed to help you create and manage complex, dynamic websites with ease. Drupal is highly customizable, offering robust tools for managing content, users, permissions, and workflows. It supports custom themes, modules, and integrations, enabling you to create tailored experiences for any type of website, from blogs and portfolios to eCommerce platforms and enterprise-level solutions. Drupal prioritizes flexibility, scalability, and security, making it a preferred choice for developers, businesses, and organizations worldwide.", "category": "content-management", "tags": ["Content Management", "Website Development", "Open Source", "Enterprise CMS", "Modular Architecture"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "drupal:11.2.11-apache"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://www.drupal.org/"}, {"label": "Documentation", "url": "https://www.drupal.org/docs"}, {"label": "Github", "url": "https://github.com/drupal/drupal"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "drupal", "port": "$PORT:80", "volumes": ["/var/www/html/modules", "/var/www/html/profiles", "/var/www/html/themes", "/var/www/html/sites"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('dumbassets', 'DumbAssets', 'DumbAssets is a self-hosted asset management service that provides secure file storage, organization, and sharing capabilities. It features PIN protection, configurable access controls, and notification integration. Perfect for teams and organizations that need centralized asset management.', 'asset-management', ARRAY['Asset Management', 'File Storage', 'File Sharing', 'Web Interface', 'Security'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "dumbwareio/dumbassets:1.0.11"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "DumbAssets", "version": "latest", "description": "DumbAssets is a self-hosted asset management service that provides secure file storage, organization, and sharing capabilities. It features PIN protection, configurable access controls, and notification integration. Perfect for teams and organizations that need centralized asset management.", "category": "asset-management", "tags": ["Asset Management", "File Storage", "File Sharing", "Web Interface", "Security"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "dumbwareio/dumbassets:1.0.11"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://www.dumbware.io/DumbAssets"}, {"label": "Documentation", "url": "https://github.com/dumbwareio/dumbassets#readme"}, {"label": "GitHub", "url": "https://github.com/dumbwareio/dumbassets"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "dumbassets", "port": "$PORT:3000", "volumes": ["/app/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('dumbbudget', 'DumbBudget', 'DumbBudget is a simple, self-hosted personal budgeting app from DumbWare.io. Track income and expenses with categories, PIN protection, multi-currency support, CSV export, and a responsive PWA UI. Data persists under /app/data.', 'budget-management', ARRAY['Budget Management', 'Personal Finance', 'Expense Tracking', 'Financial Planning', 'Web Interface'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "dumbwareio/dumbbudget:b9db5cb32d14b7b78675d8be054611d4829253ef"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "DumbBudget", "version": "latest", "description": "DumbBudget is a simple, self-hosted personal budgeting app from DumbWare.io. Track income and expenses with categories, PIN protection, multi-currency support, CSV export, and a responsive PWA UI. Data persists under /app/data.", "category": "budget-management", "tags": ["Budget Management", "Personal Finance", "Expense Tracking", "Financial Planning", "Web Interface"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "dumbwareio/dumbbudget:b9db5cb32d14b7b78675d8be054611d4829253ef"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://dumbware.io"}, {"label": "Documentation", "url": "https://github.com/dumbwareio/dumbbudget/blob/main/README.md"}, {"label": "GitHub", "url": "https://github.com/dumbwareio/dumbbudget"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/dumbwareio/dumbbudget"}], "instructions": "**BASE_URL** is set to your primary HTTPS domain\u2014required for correct links and\nauth behind a reverse proxy.\n**DUMBBUDGET_PIN:** Leave the template default empty for open access (no PIN\ngate), or set a PIN in the form / env to require it at login (see upstream\nsecurity notes on rate limits and lockouts).\n**SITE_TITLE** appears in the UI header; **INSTANCE_NAME** is optional metadata\nfor multi-instance setups (matches upstream docker-compose).\n**CURRENCY** must be a supported ISO code (see documentation link). After\ndeploy, open the app and complete any first-run prompts.\n", "install": [{"docker": {"image": "$IMAGE", "name": "dumbbudget", "port": "$PORT:3000", "volumes": ["/app/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "**BASE_URL** is set to your primary HTTPS domain\u2014required for correct links and\nauth behind a reverse proxy.\n**DUMBBUDGET_PIN:** Leave the template default empty for open access (no PIN\ngate), or set a PIN in the form / env to require it at login (see upstream\nsecurity notes on rate limits and lockouts).\n**SITE_TITLE** appears in the UI header; **INSTANCE_NAME** is optional metadata\nfor multi-instance setups (matches upstream docker-compose).\n**CURRENCY** must be a supported ISO code (see documentation link). After\ndeploy, open the app and complete any first-run prompts.\n"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('dumbdo', 'Dumbdo', 'DumbDo is a stupidly simple todo list application that just works. No complex database, no unnecessary features - just todos. It features a clean, minimal interface with dark/light mode support, file-based storage, and PIN protection. Built with the "Dumb" design system principles, it''s fast, lightweight, and fully responsive with PWA support.', 'todo-list', ARRAY['Todo List', 'Task Management', 'Self-Hosted', 'Lightweight', 'PWA', 'Dark Mode', 'Simple', 'Docker', 'Fast', 'Minimal'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "dumbwareio/dumbdo:d4dff81e4eab16de0974a94742e1cd3bc51a369a"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Dumbdo", "version": "latest", "description": "DumbDo is a stupidly simple todo list application that just works. No complex database, no unnecessary features - just todos. It features a clean, minimal interface with dark/light mode support, file-based storage, and PIN protection. Built with the \"Dumb\" design system principles, it's fast, lightweight, and fully responsive with PWA support.", "category": "todo-list", "tags": ["Todo List", "Task Management", "Self-Hosted", "Lightweight", "PWA", "Dark Mode", "Simple", "Docker", "Fast", "Minimal"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "dumbwareio/dumbdo:d4dff81e4eab16de0974a94742e1cd3bc51a369a"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://www.dumbware.io/DumbDo"}, {"label": "GitHub", "url": "https://github.com/dumbwareio/dumbdo"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/dumbwareio/dumbdo"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "dumbdo", "port": "$PORT:3000", "volumes": ["/app/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('dumbdrop', 'DumbDrop', 'DumbDrop is a simple file sharing service for quick file uploads and downloads. It provides a clean web interface for sharing files with optional PIN protection and configurable file size limits. Perfect for temporary file sharing and quick document distribution.', 'file-sharing', ARRAY['File Sharing', 'Upload', 'Download', 'Simple', 'Web Interface'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "dumbwareio/dumbdrop:sha-ff8f813f493e89c7da056e7a3101ce2ef48e3960"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "DumbDrop", "version": "latest", "description": "DumbDrop is a simple file sharing service for quick file uploads and downloads. It provides a clean web interface for sharing files with optional PIN protection and configurable file size limits. Perfect for temporary file sharing and quick document distribution.", "category": "file-sharing", "tags": ["File Sharing", "Upload", "Download", "Simple", "Web Interface"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "dumbwareio/dumbdrop:sha-ff8f813f493e89c7da056e7a3101ce2ef48e3960"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://www.dumbware.io/DumbDrop"}, {"label": "Documentation", "url": "https://github.com/dumbwareio/dumbdrop#readme"}, {"label": "GitHub", "url": "https://github.com/dumbwareio/dumbdrop"}, {"label": "Container Registry", "url": "https://hub.docker.com/r/dumbwareio/dumbdrop"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "dumbdrop", "port": "$PORT:3000", "volumes": ["/app/uploads"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('dumbkan', 'DumbKan', 'DumbKan is a simple, self-hosted Kanban board application for project management and task organization. It provides a clean interface for creating boards, managing tasks, and collaborating on projects. Perfect for teams and individuals who need a lightweight project management solution.', 'kanban', ARRAY['Kanban', 'Project Management', 'Task Management', 'Collaboration', 'Web Interface'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "dumbwareio/dumbkan:nightly-20250303-051955"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "DumbKan", "version": "latest", "description": "DumbKan is a simple, self-hosted Kanban board application for project management and task organization. It provides a clean interface for creating boards, managing tasks, and collaborating on projects. Perfect for teams and individuals who need a lightweight project management solution.", "category": "kanban", "tags": ["Kanban", "Project Management", "Task Management", "Collaboration", "Web Interface"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "dumbwareio/dumbkan:nightly-20250303-051955"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://www.dumbware.io/DumbKan"}, {"label": "Documentation", "url": "https://github.com/dumbwareio/dumbkan#readme"}, {"label": "GitHub", "url": "https://github.com/dumbwareio/dumbkan"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "dumbkan", "port": "$PORT:3000", "volumes": ["/app/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('dumbpad', 'DumbPad', 'DumbPad is a simple note-taking application for quick text storage and sharing. It provides a clean web-based text editor with optional PIN protection for secure note management. Perfect for quick notes, temporary text storage, and collaborative text editing.', 'notes', ARRAY['Notes', 'Text Editor', 'Productivity', 'Simple', 'Web Interface'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "dumbwareio/dumbpad:1.0.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "DumbPad", "version": "latest", "description": "DumbPad is a simple note-taking application for quick text storage and sharing. It provides a clean web-based text editor with optional PIN protection for secure note management. Perfect for quick notes, temporary text storage, and collaborative text editing.", "category": "notes", "tags": ["Notes", "Text Editor", "Productivity", "Simple", "Web Interface"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "dumbwareio/dumbpad:1.0.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://www.dumbware.io/DumbPad"}, {"label": "Documentation", "url": "https://github.com/dumbwareio/dumbpad#readme"}, {"label": "GitHub", "url": "https://github.com/dumbwareio/dumbpad"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "dumbpad", "port": "$PORT:3000", "volumes": ["/app/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('dumbterm', 'DumbTerm', 'DumbTerm is a web-based terminal emulator that provides secure terminal access through your browser. It features PIN protection, session management, and configurable security settings. Perfect for remote server access, development environments, and system administration tasks.', 'terminal', ARRAY['Terminal', 'SSH', 'Web Interface', 'Security', 'System Administration'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "dumbwareio/dumbterm:1.2.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "DumbTerm", "version": "latest", "description": "DumbTerm is a web-based terminal emulator that provides secure terminal access through your browser. It features PIN protection, session management, and configurable security settings. Perfect for remote server access, development environments, and system administration tasks.", "category": "terminal", "tags": ["Terminal", "SSH", "Web Interface", "Security", "System Administration"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "dumbwareio/dumbterm:1.2.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://www.dumbware.io/DumbTerm"}, {"label": "Documentation", "url": "https://github.com/dumbwareio/dumbterm#readme"}, {"label": "GitHub", "url": "https://github.com/dumbwareio/dumbterm"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "dumbterm", "port": "$PORT:3000", "volumes": ["/root/.config", "/root/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('dumbwhois', 'DumbWhois', 'DumbWhois is a simple WHOIS lookup service for domain information queries. It provides both a web interface and API endpoint for retrieving domain registration details, nameserver information, and other domain-related data. Perfect for developers and system administrators who need quick domain lookups.', 'whois', ARRAY['WHOIS', 'Domain', 'Lookup', 'API', 'Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "dumbwareio/dumbwhois:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "DumbWhois", "version": "latest", "description": "DumbWhois is a simple WHOIS lookup service for domain information queries. It provides both a web interface and API endpoint for retrieving domain registration details, nameserver information, and other domain-related data. Perfect for developers and system administrators who need quick domain lookups.", "category": "whois", "tags": ["WHOIS", "Domain", "Lookup", "API", "Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "dumbwareio/dumbwhois:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "hhttps://www.dumbware.io/DumbWhoIs"}, {"label": "Documentation", "url": "https://github.com/dumbwareio/dumbwhois#readme"}, {"label": "GitHub", "url": "https://github.com/dumbwareio/dumbwhois"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "dumbwhois", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('duplicati', 'Duplicati', 'Duplicati is a free, open-source backup software designed to store encrypted backups online. It is compatible with Windows, macOS, and Linux. The software works with standard protocols like FTP, SSH, WebDAV, and popular services such as Backblaze B2, Tardigrade, Microsoft OneDrive, Amazon S3, Google Drive, box.com, Mega, hubiC, and many others. Duplicati allows you to backup files and folders with strong AES-256 encryption, saving space with incremental backups and data deduplication. It can run backups on any machine through a web-based interface or via command line interface. Duplicati has a built-in scheduler and auto-updater, ensuring your backups are always up-to-date. It is designed for online backups from scratch, handling network issues efficiently. For instance, interrupted backups can be resumed, and Duplicati regularly tests the content of backups, detecting broken backups on corrupt storage systems before it’s too late. The software is configured by a web interface that runs in any browser and can be accessed from anywhere.', 'backup', ARRAY['Backup', 'Data Security', 'Cloud Storage'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/duplicati:2.2.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8200}}$JSON$::jsonb, $JSON${"metadata": {"name": "Duplicati", "version": "latest", "description": "Duplicati is a free, open-source backup software designed to store encrypted backups online. It is compatible with Windows, macOS, and Linux. The software works with standard protocols like FTP, SSH, WebDAV, and popular services such as Backblaze B2, Tardigrade, Microsoft OneDrive, Amazon S3, Google Drive, box.com, Mega, hubiC, and many others. Duplicati allows you to backup files and folders with strong AES-256 encryption, saving space with incremental backups and data deduplication. It can run backups on any machine through a web-based interface or via command line interface. Duplicati has a built-in scheduler and auto-updater, ensuring your backups are always up-to-date. It is designed for online backups from scratch, handling network issues efficiently. For instance, interrupted backups can be resumed, and Duplicati regularly tests the content of backups, detecting broken backups on corrupt storage systems before it\u2019s too late. The software is configured by a web interface that runs in any browser and can be accessed from anywhere.", "category": "backup", "tags": ["Backup", "Data Security", "Cloud Storage"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/duplicati:2.2.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8200}}, "links": [{"label": "Website", "url": "https://www.duplicati.com/"}, {"label": "Documentation", "url": "https://duplicati.readthedocs.io/en/latest/"}, {"label": "Github", "url": "https://github.com/duplicati/duplicati"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "duplicati", "port": "$PORT:8200", "volumes": ["/host", "/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('easyappointments', 'EasyAppointments', 'EasyAppointments is an open-source, self-hosted scheduling platform designed to help businesses manage appointments seamlessly. It enables organizations to handle booking, customer management, and service scheduling with ease. With an intuitive interface and robust customization options, EasyAppointments supports integrations, multi-language capabilities, and detailed reporting, making it a versatile solution for appointment scheduling.', 'appointment-scheduling', ARRAY['Appointment Scheduling', 'Booking System', 'Open Source', 'Calendar Integration', 'Multi-Language'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "alextselegidis/easyappointments:1.5.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "EasyAppointments", "version": "latest", "description": "EasyAppointments is an open-source, self-hosted scheduling platform designed to help businesses manage appointments seamlessly. It enables organizations to handle booking, customer management, and service scheduling with ease. With an intuitive interface and robust customization options, EasyAppointments supports integrations, multi-language capabilities, and detailed reporting, making it a versatile solution for appointment scheduling.", "category": "appointment-scheduling", "tags": ["Appointment Scheduling", "Booking System", "Open Source", "Calendar Integration", "Multi-Language"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "alextselegidis/easyappointments:1.5.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Github", "url": "https://github.com/alextselegidis/easyappointments"}, {"label": "Documentation", "url": "https://easyappointments.org/"}, {"label": "Demo", "url": "https://demo.easyappointments.org/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "easyappointments", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('easyshortener', 'Easyshortener', 'Easyshortener is a multi-user link shortening application designed for simplicity and security. It allows multiple users to manage their links from a built-in administration panel. The app is built with a focus on user experience, ensuring it is easy to use. It also features built-in two-factor authentication, providing an extra layer of security for your peace of mind. Easyshortener is built for Docker, making it easy to deploy with your favorite container engine. Additionally, the app allows for registration and redirect tracking for all links, and can be set to force HTTPS connection for enhanced security.', 'url-shortener', ARRAY['URL Shortener', 'Link Management', 'Security'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/easypanel-community/easyshortener:1.1.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Easyshortener", "version": "latest", "description": "Easyshortener is a multi-user link shortening application designed for simplicity and security. It allows multiple users to manage their links from a built-in administration panel. The app is built with a focus on user experience, ensuring it is easy to use. It also features built-in two-factor authentication, providing an extra layer of security for your peace of mind. Easyshortener is built for Docker, making it easy to deploy with your favorite container engine. Additionally, the app allows for registration and redirect tracking for all links, and can be set to force HTTPS connection for enhanced security.", "category": "url-shortener", "tags": ["URL Shortener", "Link Management", "Security"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/easypanel-community/easyshortener:1.1.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Github", "url": "https://github.com/easypanel-community/easyshortener"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "easyshortener", "port": "$PORT:80", "volumes": ["/var/www/html"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('elasticsearch', 'Elasticsearch', 'Elasticsearch is a dynamic search and analytics engine designed for seamless handling of extensive data across various formats. With a user-friendly interface and a robust query language, it enables effortless advanced searches and data analysis. Boasting high performance and scalability, Elasticsearch ensures rapid search responses and efficient data retrieval, making it suitable for diverse applications. The platform prioritizes security with features like role-based access control and encryption, while its real-time indexing and distributed architecture support resilience and reliability. Whether you''re a developer or IT professional, Elasticsearch provides a centralized solution for managing and extracting valuable insights from your data, offering a powerful search and analytics experience.', 'data-analytics', ARRAY['Data Analytics', 'Search Engine', 'Security', 'Scalability'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "docker.elastic.co/elasticsearch/elasticsearch:9.2.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9200}}$JSON$::jsonb, $JSON${"metadata": {"name": "Elasticsearch", "version": "latest", "description": "Elasticsearch is a dynamic search and analytics engine designed for seamless handling of extensive data across various formats. With a user-friendly interface and a robust query language, it enables effortless advanced searches and data analysis. Boasting high performance and scalability, Elasticsearch ensures rapid search responses and efficient data retrieval, making it suitable for diverse applications. The platform prioritizes security with features like role-based access control and encryption, while its real-time indexing and distributed architecture support resilience and reliability. Whether you're a developer or IT professional, Elasticsearch provides a centralized solution for managing and extracting valuable insights from your data, offering a powerful search and analytics experience.", "category": "data-analytics", "tags": ["Data Analytics", "Search Engine", "Security", "Scalability"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "docker.elastic.co/elasticsearch/elasticsearch:9.2.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9200}}, "links": [{"label": "Website", "url": "https://www.elastic.co"}, {"label": "Documentation", "url": "https://www.elastic.co/guide/index.html"}, {"label": "Github", "url": "https://github.com/elastic/elasticsearch"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "elasticsearch", "port": "$PORT:9200", "volumes": ["/usr/share/elasticsearch/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('element', 'Element', 'Element is a secure communications platform designed to protect and strengthen your business critical communications. It offers real-time trusted communication across organizations, giving you the freedom to communicate on your own terms. With Element, you can control your data through its open source and flexible hosting, enabling data sovereignty. The app allows you to structure discussion spaces, customize chat rooms, and share live data through widgets and integrations to boost your productivity. It also provides instant messaging, voice/video calls, location sharing, voting polls and more. Element ensures your data is secure by default, allowing you to focus on getting your work done. You have complete independence to own and control your entire communication platform, configure networks to suit organizational requirements, and strengthen cybersecurity and business continuity plans. Element is led by the creators of Matrix, the decentralized open standard for secure and sovereign real time communication.', 'chat', ARRAY['Chat', 'Communication', 'Security'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "vectorim/element-web:v1.12.17"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Element", "version": "latest", "description": "Element is a secure communications platform designed to protect and strengthen your business critical communications. It offers real-time trusted communication across organizations, giving you the freedom to communicate on your own terms. With Element, you can control your data through its open source and flexible hosting, enabling data sovereignty. The app allows you to structure discussion spaces, customize chat rooms, and share live data through widgets and integrations to boost your productivity. It also provides instant messaging, voice/video calls, location sharing, voting polls and more. Element ensures your data is secure by default, allowing you to focus on getting your work done. You have complete independence to own and control your entire communication platform, configure networks to suit organizational requirements, and strengthen cybersecurity and business continuity plans. Element is led by the creators of Matrix, the decentralized open standard for secure and sovereign real time communication.", "category": "chat", "tags": ["Chat", "Communication", "Security"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "vectorim/element-web:v1.12.17"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://element.io/"}, {"label": "Documentation", "url": "https://github.com/vector-im/element-web/wiki"}, {"label": "Github", "url": "https://github.com/vector-im/element-web"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "element", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('elkarbackup', 'ElkarBackup', 'ElkarBackup is a robust open-source backup management system designed to streamline data protection and recovery for diverse environments. With an intuitive web-based interface and extensive automation capabilities, it simplifies backup scheduling and execution. ElkarBackup supports various storage backends and ensures reliable backup operations with robust monitoring and reporting features. Whether you''re managing personal data or enterprise-scale systems, ElkarBackup offers an efficient and user-friendly solution for safeguarding your critical information.', 'backup-management', ARRAY['Backup Management', 'Automation', 'Data Recovery', 'Open Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "elkarbackup/elkarbackup:2.3.9"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "ElkarBackup", "version": "latest", "description": "ElkarBackup is a robust open-source backup management system designed to streamline data protection and recovery for diverse environments. With an intuitive web-based interface and extensive automation capabilities, it simplifies backup scheduling and execution. ElkarBackup supports various storage backends and ensures reliable backup operations with robust monitoring and reporting features. Whether you're managing personal data or enterprise-scale systems, ElkarBackup offers an efficient and user-friendly solution for safeguarding your critical information.", "category": "backup-management", "tags": ["Backup Management", "Automation", "Data Recovery", "Open Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "elkarbackup/elkarbackup:2.3.9"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://elkarbackup.github.io"}, {"label": "Documentation", "url": "https://elkarbackup.github.io/elkarbackup/"}, {"label": "Github", "url": "https://github.com/elkarbackup/elkarbackup"}], "instructions": "Login using root/root, custom settingss can be configured with the provided envs.", "install": [{"docker": {"image": "$IMAGE", "name": "elkarbackup", "port": "$PORT:80", "volumes": ["/app/backups", "/app/uploads", "/app/.ssh"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Login using root/root, custom settingss can be configured with the provided envs."}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('emailengine', 'EmailEngine', 'EmailEngine is a powerful email automation and integration tool designed to simplify email processing for applications. It provides a seamless interface for managing IMAP and SMTP connections, allowing applications to send, receive, and process emails efficiently. With built-in webhook support and extensive API capabilities, EmailEngine enables developers to automate email workflows and integrate email functionality effortlessly. Whether handling transactional emails or managing large-scale email operations, EmailEngine offers a reliable and feature-rich solution.', 'email-automation', ARRAY['Email Automation', 'Webhooks', 'API Integration', 'Open Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "postalsys/emailengine:v2.63.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 2525}}$JSON$::jsonb, $JSON${"metadata": {"name": "EmailEngine", "version": "latest", "description": "EmailEngine is a powerful email automation and integration tool designed to simplify email processing for applications. It provides a seamless interface for managing IMAP and SMTP connections, allowing applications to send, receive, and process emails efficiently. With built-in webhook support and extensive API capabilities, EmailEngine enables developers to automate email workflows and integrate email functionality effortlessly. Whether handling transactional emails or managing large-scale email operations, EmailEngine offers a reliable and feature-rich solution.", "category": "email-automation", "tags": ["Email Automation", "Webhooks", "API Integration", "Open Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "postalsys/emailengine:v2.63.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 2525}}, "links": [{"label": "Website", "url": "https://emailengine.app"}, {"label": "Documentation", "url": "https://api.emailengine.app/"}, {"label": "Github", "url": "https://github.com/postalsys/emailengine"}], "instructions": "Set the SMTP password for email submissions on the server.", "install": [{"docker": {"image": "$IMAGE", "name": "emailengine", "port": "$PORT:2525", "volumes": [], "extra_ports": ["3000:3000", "9993:9993"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Set the SMTP password for email submissions on the server."}, "services": {"redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('emby-stat', 'Emby-Stat', 'Emby-Stat is an advanced statistics and analytics tool for Emby and Jellyfin media servers. It allows you to gain deeper insights into your media library, viewing habits, and server usage. With detailed statistics and customizable reports, Emby-Stat helps you visualize and analyze your media server data effectively. It also provides a user-friendly interface to track playback history, top media consumption trends, and server activity over time. Emby-Stat integrates seamlessly with Emby, giving you the ability to enhance your media management with data-driven decisions.', 'media', ARRAY['Media', 'Analytics', 'Statistics'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/embystat:0.2.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 6555}}$JSON$::jsonb, $JSON${"metadata": {"name": "Emby-Stat", "version": "latest", "description": "Emby-Stat is an advanced statistics and analytics tool for Emby and Jellyfin media servers. It allows you to gain deeper insights into your media library, viewing habits, and server usage. With detailed statistics and customizable reports, Emby-Stat helps you visualize and analyze your media server data effectively. It also provides a user-friendly interface to track playback history, top media consumption trends, and server activity over time. Emby-Stat integrates seamlessly with Emby, giving you the ability to enhance your media management with data-driven decisions.", "category": "media", "tags": ["Media", "Analytics", "Statistics"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/embystat:0.2.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 6555}}, "links": [{"label": "Website", "url": "https://embystat.org/"}, {"label": "Documentation", "url": "https://docs.embystat.org/"}, {"label": "Github", "url": "https://github.com/mregni/EmbyStat"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "emby-stat", "port": "$PORT:6555", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('emby', 'Emby', 'Emby is a personal media server that brings all of your home videos, music, and photos together into one place for easy access. It automatically converts and streams your media on-the-fly, allowing you to play it on any device. With Emby, you can enjoy your media while away from home without the need to fumble with IP addresses. It also offers live TV streaming to any device, DVR management, and a library of recordings. Emby organizes your personal media into rich, beautiful displays and notifies you of server activity based on events and actions that are important to you. It also offers parental controls to easily manage content access for your children. Emby apps are available for all of your favorite devices, including Android, iPhone, iPad, Windows Phone, and Windows Tablets, allowing you to take your home videos, music, and photos with you wherever you go.', 'media', ARRAY['Media'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/emby:4.9.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8096}}$JSON$::jsonb, $JSON${"metadata": {"name": "Emby", "version": "latest", "description": "Emby is a personal media server that brings all of your home videos, music, and photos together into one place for easy access. It automatically converts and streams your media on-the-fly, allowing you to play it on any device. With Emby, you can enjoy your media while away from home without the need to fumble with IP addresses. It also offers live TV streaming to any device, DVR management, and a library of recordings. Emby organizes your personal media into rich, beautiful displays and notifies you of server activity based on events and actions that are important to you. It also offers parental controls to easily manage content access for your children. Emby apps are available for all of your favorite devices, including Android, iPhone, iPad, Windows Phone, and Windows Tablets, allowing you to take your home videos, music, and photos with you wherever you go.", "category": "media", "tags": ["Media"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/emby:4.9.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8096}}, "links": [{"label": "Website", "url": "https://emby.media/"}, {"label": "Documentation", "url": "https://support.emby.media/support/home"}, {"label": "Github", "url": "https://github.com/MediaBrowser/Emby"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "emby", "port": "$PORT:8096", "volumes": ["/config", "/data/tvshows", "/data/movies", "/opt/vc/lib"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('enclosed', 'Enclosed', 'Enclosed is a minimalist file sharing and URL shortening service. It provides a simple and efficient way to share files and shorten URLs with a clean, modern interface. Perfect for personal or small team use, it offers secure file storage and easy link management.', 'file-sharing', ARRAY['File Sharing', 'URL Shortener', 'Self-Hosted', 'Storage', 'Sharing'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "corentinth/enclosed:1.16.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8787}}$JSON$::jsonb, $JSON${"metadata": {"name": "Enclosed", "version": "latest", "description": "Enclosed is a minimalist file sharing and URL shortening service. It provides a simple and efficient way to share files and shorten URLs with a clean, modern interface. Perfect for personal or small team use, it offers secure file storage and easy link management.", "category": "file-sharing", "tags": ["File Sharing", "URL Shortener", "Self-Hosted", "Storage", "Sharing"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "corentinth/enclosed:1.16.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8787}}, "links": [{"label": "Github", "url": "https://github.com/corentinth/enclosed"}, {"label": "Website", "url": "https://enclosed.cc"}], "instructions": "After installation, access the web interface through the provided domain to start sharing files and shortening URLs.", "install": [{"docker": {"image": "$IMAGE", "name": "enclosed", "port": "$PORT:8787", "volumes": ["/app/.data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After installation, access the web interface through the provided domain to start sharing files and shortening URLs."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('endurain', 'Endurain', 'Endurain is a cutting-edge endurance tracking and training platform designed for athletes and fitness enthusiasts. It offers a user-friendly interface to track workouts, set goals, and analyze performance metrics. With Endurain, you can manage your training routines using detailed analytics, route planning, and personalized coaching features. It supports integrations with fitness devices and third-party tools, making it a versatile solution for athletes at any level. Its emphasis on data-driven insights and seamless user experience ensures athletes stay motivated and achieve their fitness goals. Endurain is distributed under an open-source license, allowing for customization to meet unique training needs.', 'endurance-training', ARRAY['Endurance Training', 'Open Source', 'Fitness Tracking', 'Workout Analytics', 'Route Planning', 'Performance Metrics', 'Goal Setting'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/joaovitoriasilva/endurain:v0.16.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Endurain", "version": "latest", "description": "Endurain is a cutting-edge endurance tracking and training platform designed for athletes and fitness enthusiasts. It offers a user-friendly interface to track workouts, set goals, and analyze performance metrics. With Endurain, you can manage your training routines using detailed analytics, route planning, and personalized coaching features. It supports integrations with fitness devices and third-party tools, making it a versatile solution for athletes at any level. Its emphasis on data-driven insights and seamless user experience ensures athletes stay motivated and achieve their fitness goals. Endurain is distributed under an open-source license, allowing for customization to meet unique training needs.", "category": "endurance-training", "tags": ["Endurance Training", "Open Source", "Fitness Tracking", "Workout Analytics", "Route Planning", "Performance Metrics", "Goal Setting"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/joaovitoriasilva/endurain:v0.16.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Github", "url": "https://github.com/joaovitoriasilva/endurain"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "endurain", "port": "$PORT:8080", "volumes": ["/app/backend/user_images", "/app/backend/files/bulk_import", "/app/backend/files/processed", "/app/backend/logs"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('ersatztv', 'ErsatzTV', 'ErsatzTV is a modern, web-based IPTV server that creates custom TV channels from your local media library. It streams your movies, TV shows, and other content as continuous TV channels that can be watched on any IPTV-compatible device or application. ErsatzTV provides a sophisticated scheduling system, allowing you to create program guides, manage commercial breaks, and simulate a real TV experience with your personal media collection. Perfect for home entertainment setups, media centers, and creating personalized TV channels from your existing content library.', 'iptv', ARRAY['IPTV', 'Media Server', 'TV Channels', 'Streaming', 'Home Entertainment', 'Media Center', 'Plex Alternative'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/ersatztv/ersatztv:v26.3.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8409}}$JSON$::jsonb, $JSON${"metadata": {"name": "ErsatzTV", "version": "latest", "description": "ErsatzTV is a modern, web-based IPTV server that creates custom TV channels from your local media library. It streams your movies, TV shows, and other content as continuous TV channels that can be watched on any IPTV-compatible device or application. ErsatzTV provides a sophisticated scheduling system, allowing you to create program guides, manage commercial breaks, and simulate a real TV experience with your personal media collection. Perfect for home entertainment setups, media centers, and creating personalized TV channels from your existing content library.", "category": "iptv", "tags": ["IPTV", "Media Server", "TV Channels", "Streaming", "Home Entertainment", "Media Center", "Plex Alternative"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/ersatztv/ersatztv:v26.3.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8409}}, "links": [{"label": "Website", "url": "https://ersatztv.org"}, {"label": "GitHub", "url": "https://github.com/ersatztv/ersatztv"}, {"label": "Documentation", "url": "https://ersatztv.github.io/ersatztv/"}], "instructions": "The application uses /transcode as a temporary directory for processing media files, which is mounted as a volume for optimal performance.", "install": [{"docker": {"image": "$IMAGE", "name": "ersatztv", "port": "$PORT:8409", "volumes": ["/config", "/media", "/transcode"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "The application uses /transcode as a temporary directory for processing media files, which is mounted as a volume for optimal performance."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('espocrm', 'EspoCRM', 'EspoCRM is a powerful web application designed to streamline your company''s relationships. This versatile tool allows you to manage and evaluate all types of relationships, including people, companies, projects, and opportunities, all within an easy-to-use and intuitive interface. EspoCRM is trusted by over 50,000 companies across 163 countries, and has been enhancing business operations for 9 years. It is widely used across various sectors such as wholesale and retail trade, e-commerce, banking, call-centers, manufacturing, education, travel & tourism, real estate, healthcare, and insurance. EspoCRM is designed to skyrocket your sales, transform your marketing strategy, and deliver an exceptional customer experience. It is a free self-hosted and cloud CRM software that can be used simultaneously by many people. Increase your company’s profitability and build customer loyalty with EspoCRM, your open source sales tool.', 'crm', ARRAY['CRM'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "espocrm/espocrm:9.3.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "EspoCRM", "version": "latest", "description": "EspoCRM is a powerful web application designed to streamline your company's relationships. This versatile tool allows you to manage and evaluate all types of relationships, including people, companies, projects, and opportunities, all within an easy-to-use and intuitive interface. EspoCRM is trusted by over 50,000 companies across 163 countries, and has been enhancing business operations for 9 years. It is widely used across various sectors such as wholesale and retail trade, e-commerce, banking, call-centers, manufacturing, education, travel & tourism, real estate, healthcare, and insurance. EspoCRM is designed to skyrocket your sales, transform your marketing strategy, and deliver an exceptional customer experience. It is a free self-hosted and cloud CRM software that can be used simultaneously by many people. Increase your company\u2019s profitability and build customer loyalty with EspoCRM, your open source sales tool.", "category": "crm", "tags": ["CRM"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "espocrm/espocrm:9.3.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://espocrm.com"}, {"label": "Demo", "url": "https://demo.espocrm.com"}, {"label": "Documentation", "url": "https://docs.espocrm.com"}, {"label": "Github", "url": "https://github.com/espocrm"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "espocrm", "port": "$PORT:80", "volumes": ["/var/www/html", "/var/www/html", "/var/www/html"], "extra_ports": ["8080:8080"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('etherpad', 'Etherpad', 'Etherpad is an open-source online editor that enables real-time collaborative editing directly in your browser. Users can simultaneously work on documents, such as articles, press releases, or to-do lists, with all changes visible to everyone in real time. It supports import/export to various data exchange formats and can be customized with plugins to suit specific needs, making it a versatile tool for a wide range of collaborative tasks.', 'collaboration', ARRAY['Collaboration', 'Communication', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "etherpad/etherpad:2.7.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9001}}$JSON$::jsonb, $JSON${"metadata": {"name": "Etherpad", "version": "latest", "description": "Etherpad is an open-source online editor that enables real-time collaborative editing directly in your browser. Users can simultaneously work on documents, such as articles, press releases, or to-do lists, with all changes visible to everyone in real time. It supports import/export to various data exchange formats and can be customized with plugins to suit specific needs, making it a versatile tool for a wide range of collaborative tasks.", "category": "collaboration", "tags": ["Collaboration", "Communication", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "etherpad/etherpad:2.7.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9001}}, "links": [{"label": "Website", "url": "https://etherpad.org"}, {"label": "Documentation", "url": "https://etherpad.org/doc/v1.8.18/"}, {"label": "Github", "url": "https://github.com/ether/etherpad-lite"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "etherpad", "port": "$PORT:9001", "volumes": ["/opt"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('ever-gauzy', 'Ever Gauzy', 'Ever Gauzy is an open business management platform covering ERP CRM HRM ATS and project management with time tracking invoicing and reporting. This template deploys the official API web UI and PostgreSQL stack similar to the upstream docker compose demo layout.', 'erp', ARRAY['ERP', 'CRM', 'HRM', 'Business Management', 'Time Tracking'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Ever Gauzy", "version": "latest", "description": "Ever Gauzy is an open business management platform covering ERP CRM HRM ATS and project management with time tracking invoicing and reporting. This template deploys the official API web UI and PostgreSQL stack similar to the upstream docker compose demo layout.", "category": "erp", "tags": ["ERP", "CRM", "HRM", "Business Management", "Time Tracking"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://gauzy.co/"}, {"label": "Documentation", "url": "https://docs.gauzy.co/"}, {"label": "GitHub", "url": "https://github.com/ever-co/ever-gauzy"}], "instructions": "Deploy and wait for PostgreSQL the API and the web UI to become healthy. Open the web service URL shown in Easypanel. Register yourself and complete the wizard to start using the application.", "install": [{"docker": {"image": "$IMAGE", "name": "ever-gauzy", "port": "$PORT:3000", "volumes": [], "extra_ports": ["4200:4200"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Deploy and wait for PostgreSQL the API and the web UI to become healthy. Open the web service URL shown in Easypanel. Register yourself and complete the wizard to start using the application."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('evo-ai', 'Evo AI', 'AI-powered API platform for conversational applications', 'ai', ARRAY['AI', 'API', 'Conversational', 'NLP', 'Machine Learning'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "evoapicloud/evo-ai:0.1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Evo AI", "version": "latest", "description": "AI-powered API platform for conversational applications", "category": "ai", "tags": ["AI", "API", "Conversational", "NLP", "Machine Learning"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "evoapicloud/evo-ai:0.1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://evoai.co/"}, {"label": "Documentation", "url": "https://docs.evoai.co/"}, {"label": "GitHub", "url": "https://github.com/EvolutionAPI/evo-ai"}], "instructions": "Use admin email - admin@evoai.com and password admin123 to login.", "install": [{"docker": {"image": "$IMAGE", "name": "evo-ai", "port": "$PORT:80", "volumes": ["/app/logs", "/app/static"], "extra_ports": ["8000:8000"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Use admin email - admin@evoai.com and password admin123 to login."}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('evobot', 'EvoBot', 'EvoBot is a music bot designed for Discord, a popular communication platform. It''s built with TypeScript and discord.js, and it uses a Command Handler from discordjs.guide. The bot allows users to play music directly from YouTube either by using a URL or a search query. It also supports playing YouTube playlists. In addition to playing music, EvoBot offers a variety of commands for managing the playback. Users can control the volume, pause and resume playback, skip songs, and even move songs within the queue. The bot also provides lyrics for songs and can show its uptime. EvoBot supports multiple languages, making it accessible to users around the world.', 'chat', ARRAY['Chat', 'Media', 'Music', 'Discord'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "eritislami/evobot:2.9.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "EvoBot", "version": "latest", "description": "EvoBot is a music bot designed for Discord, a popular communication platform. It's built with TypeScript and discord.js, and it uses a Command Handler from discordjs.guide. The bot allows users to play music directly from YouTube either by using a URL or a search query. It also supports playing YouTube playlists. In addition to playing music, EvoBot offers a variety of commands for managing the playback. Users can control the volume, pause and resume playback, skip songs, and even move songs within the queue. The bot also provides lyrics for songs and can show its uptime. EvoBot supports multiple languages, making it accessible to users around the world.", "category": "chat", "tags": ["Chat", "Media", "Music", "Discord"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "eritislami/evobot:2.9.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Github", "url": "https://github.com/eritislami/evobot"}, {"label": "Documentation", "url": "https://github.com/eritislami/evobot#%EF%B8%8F-configuration"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "evobot", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('evolutionapi', 'Evolution API', 'Evolution API is a self-hosted platform designed to empower small businesses, entrepreneurs, and individuals by providing a robust API for integrating messaging solutions such as WhatsApp™. It offers seamless integration with other tools like Typebot, Chatwoot, and OpenAI to enhance communication and automation capabilities. Evolution API is a free and customizable solution that allows users to maintain control over their messaging infrastructure.', 'messaging', ARRAY['Messaging', 'Communication', 'Automation', 'Open Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "evoapicloud/evolution-api:v2.3.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Evolution API", "version": "latest", "description": "Evolution API is a self-hosted platform designed to empower small businesses, entrepreneurs, and individuals by providing a robust API for integrating messaging solutions such as WhatsApp\u2122. It offers seamless integration with other tools like Typebot, Chatwoot, and OpenAI to enhance communication and automation capabilities. Evolution API is a free and customizable solution that allows users to maintain control over their messaging infrastructure.", "category": "messaging", "tags": ["Messaging", "Communication", "Automation", "Open Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "evoapicloud/evolution-api:v2.3.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Website", "url": "https://evolution-api.com"}, {"label": "Documentation", "url": "https://doc.evolution-api.com/v1/en/get-started/introduction"}, {"label": "Github", "url": "https://github.com/EvolutionAPI/evolution-api"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "evolutionapi", "port": "$PORT:8080", "volumes": ["/evolution/instances"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('excalidraw', 'Excalidraw', 'Excalidraw is an open-source virtual whiteboard designed to bring your creativity to life. It allows you to create beautiful hand-drawn like diagrams, wireframes, or any other visuals you can imagine. The app is equipped with an infinite, canvas-based whiteboard that supports a hand-drawn like style. It offers a wide range of tools including rectangle, circle, diamond, arrow, line, free-draw, eraser, and more. You can customize your drawings with the help of image support and shape libraries. The app also supports localization and allows you to export your creations to PNG, SVG, and clipboard. It also features an open format that lets you export drawings as an .excalidraw json file. The app is also equipped with features like arrow-binding, labeled arrows, undo/redo, and zoom and panning support. Excalidraw also offers real-time collaboration and end-to-end encryption for secure and efficient teamwork.', 'productivity', ARRAY['Productivity', 'Collaboration', 'Visualization'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "excalidraw/excalidraw:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Excalidraw", "version": "latest", "description": "Excalidraw is an open-source virtual whiteboard designed to bring your creativity to life. It allows you to create beautiful hand-drawn like diagrams, wireframes, or any other visuals you can imagine. The app is equipped with an infinite, canvas-based whiteboard that supports a hand-drawn like style. It offers a wide range of tools including rectangle, circle, diamond, arrow, line, free-draw, eraser, and more. You can customize your drawings with the help of image support and shape libraries. The app also supports localization and allows you to export your creations to PNG, SVG, and clipboard. It also features an open format that lets you export drawings as an .excalidraw json file. The app is also equipped with features like arrow-binding, labeled arrows, undo/redo, and zoom and panning support. Excalidraw also offers real-time collaboration and end-to-end encryption for secure and efficient teamwork.", "category": "productivity", "tags": ["Productivity", "Collaboration", "Visualization"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "excalidraw/excalidraw:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://excalidraw.com/"}, {"label": "Github", "url": "https://github.com/excalidraw/excalidraw"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "excalidraw", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('expenseowl', 'ExpenseOwl', 'ExpenseOwl is a simple, self-hosted expense tracker designed for quick expense entry and essential tracking features. Built with a modern UI and user-friendly interface, it makes managing your personal finances straightforward and efficient. The application focuses on simplicity and ease of use, allowing you to quickly log expenses, categorize spending, and track your budget without complexity. ExpenseOwl stores all your financial data securely with persistent storage, ensuring your expense history is always available. Perfect for individuals who want a lightweight, privacy-focused expense tracking solution without the overhead of complex financial management software. The application can be used with simple file-based storage or connected to a PostgreSQL database for more advanced data management needs.', 'finance', ARRAY['Finance', 'Expense Tracking', 'Budget', 'Self-Hosted', 'Personal Finance', 'Money Management', 'Lightweight'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "tanq16/expenseowl:v4.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "ExpenseOwl", "version": "latest", "description": "ExpenseOwl is a simple, self-hosted expense tracker designed for quick expense entry and essential tracking features. Built with a modern UI and user-friendly interface, it makes managing your personal finances straightforward and efficient. The application focuses on simplicity and ease of use, allowing you to quickly log expenses, categorize spending, and track your budget without complexity. ExpenseOwl stores all your financial data securely with persistent storage, ensuring your expense history is always available. Perfect for individuals who want a lightweight, privacy-focused expense tracking solution without the overhead of complex financial management software. The application can be used with simple file-based storage or connected to a PostgreSQL database for more advanced data management needs.", "category": "finance", "tags": ["Finance", "Expense Tracking", "Budget", "Self-Hosted", "Personal Finance", "Money Management", "Lightweight"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "tanq16/expenseowl:v4.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "GitHub", "url": "https://github.com/Tanq16/ExpenseOwl"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/tanq16/expenseowl"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "expenseowl", "port": "$PORT:8080", "volumes": ["/app/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('ezbookkeeping', 'ezBookkeeping', 'ezBookkeeping is a simple and easy-to-use personal bookkeeping application that helps you manage your personal finances. It provides features for tracking income, expenses, and account balances.', 'finance', ARRAY['Finance', 'Bookkeeping', 'Personal Finance', 'Budgeting', 'Open Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "mayswind/ezbookkeeping:SNAPSHOT-20260429"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "ezBookkeeping", "version": "latest", "description": "ezBookkeeping is a simple and easy-to-use personal bookkeeping application that helps you manage your personal finances. It provides features for tracking income, expenses, and account balances.", "category": "finance", "tags": ["Finance", "Bookkeeping", "Personal Finance", "Budgeting", "Open Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "mayswind/ezbookkeeping:SNAPSHOT-20260429"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Github", "url": "https://github.com/mayswind/ezbookkeeping"}, {"label": "Documentation", "url": "https://github.com/mayswind/ezbookkeeping/wiki"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "ezbookkeeping", "port": "$PORT:8080", "volumes": ["/ezbookkeeping/data", "/ezbookkeeping/storage"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('faraday', 'Faraday', 'Faraday is a powerful open-source vulnerability management platform designed to streamline security assessments and pentesting workflows. It provides centralized visibility, real-time collaboration, and automation capabilities to help security teams manage vulnerabilities efficiently. Faraday supports integration with multiple security tools, offering a unified interface to collect, analyze, and report findings. With its scalable architecture and robust API, Faraday enables teams to enhance their security operations while maintaining compliance and improving response times.', 'vulnerability-management', ARRAY['Vulnerability Management', 'Pentesting', 'Security Operations', 'Open Source', 'Cybersecurity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "faradaysec/faraday:5.20.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5985}}$JSON$::jsonb, $JSON${"metadata": {"name": "Faraday", "version": "latest", "description": "Faraday is a powerful open-source vulnerability management platform designed to streamline security assessments and pentesting workflows. It provides centralized visibility, real-time collaboration, and automation capabilities to help security teams manage vulnerabilities efficiently. Faraday supports integration with multiple security tools, offering a unified interface to collect, analyze, and report findings. With its scalable architecture and robust API, Faraday enables teams to enhance their security operations while maintaining compliance and improving response times.", "category": "vulnerability-management", "tags": ["Vulnerability Management", "Pentesting", "Security Operations", "Open Source", "Cybersecurity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "faradaysec/faraday:5.20.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5985}}, "links": [{"label": "Website", "url": "https://www.faradaysec.com/"}, {"label": "Documentation", "url": "https://docs.faradaysec.com/"}, {"label": "Github", "url": "https://github.com/infobyte/faraday"}], "instructions": "Username is faraday; check for the password in the Overview Console logs.", "install": [{"docker": {"image": "$IMAGE", "name": "faraday", "port": "$PORT:5985", "volumes": ["/home/faraday/.faraday"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Username is faraday; check for the password in the Overview Console logs."}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('farmos', 'farmOS', 'farmOS is a web-based farm management and record-keeping platform built on Drupal. It helps track assets, logs, plans, and maps for agricultural operations while remaining fully self-hosted and extensible.', 'agriculture', ARRAY['Agriculture', 'Farm Management', 'Record Keeping', 'Drupal', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "farmos/farmos:4.0.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "farmOS", "version": "latest", "description": "farmOS is a web-based farm management and record-keeping platform built on Drupal. It helps track assets, logs, plans, and maps for agricultural operations while remaining fully self-hosted and extensible.", "category": "agriculture", "tags": ["Agriculture", "Farm Management", "Record Keeping", "Drupal", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "farmos/farmos:4.0.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://farmos.org/"}, {"label": "Documentation", "url": "https://farmos.org/hosting/install/"}, {"label": "Github", "url": "https://github.com/farmOS/farmOS"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/farmos/farmos"}], "instructions": "After deployment, open your domain and complete the farmOS web installer. In the database step, choose SQLite and use a database file path under `sites/default/files` so it remains persistent. This template persists the farmOS `sites` and `keys` directories for settings, uploaded files, SQLite database storage, and key material across upgrades.", "install": [{"docker": {"image": "$IMAGE", "name": "farmos", "port": "$PORT:80", "volumes": ["/opt/drupal/web/sites", "/opt/drupal/keys"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deployment, open your domain and complete the farmOS web installer. In the database step, choose SQLite and use a database file path under `sites/default/files` so it remains persistent. This template persists the farmOS `sites` and `keys` directories for settings, uploaded files, SQLite database storage, and key material across upgrades."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('fathom', 'Fathom', 'Fathom is a simple, privacy-focused alternative to Google Analytics. It provides fast, lightweight and privacy-first website analytics without compromising user data.', 'analytics', ARRAY['Analytics', 'Privacy', 'GDPR', 'Web Analytics', 'Statistics'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "usefathom/fathom:version-1.2.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Fathom", "version": "latest", "description": "Fathom is a simple, privacy-focused alternative to Google Analytics. It provides fast, lightweight and privacy-first website analytics without compromising user data.", "category": "analytics", "tags": ["Analytics", "Privacy", "GDPR", "Web Analytics", "Statistics"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "usefathom/fathom:version-1.2.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Website", "url": "https://usefathom.com"}, {"label": "Documentation", "url": "https://usefathom.com/docs"}, {"label": "GitHub", "url": "https://github.com/usefathom/fathom"}], "instructions": "Open Fathom from your domain, complete the initial admin setup, then add your website and embed the generated tracking script in your site pages.", "install": [{"docker": {"image": "$IMAGE", "name": "fathom", "port": "$PORT:8080", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Open Fathom from your domain, complete the initial admin setup, then add your website and embed the generated tracking script in your site pages."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('feedpushr', 'Feedpushr', 'Feedpushr is a simple and fast RSS/Atom feed aggregator that can push notifications to various services. It supports multiple output formats and can be used to monitor and aggregate RSS/Atom feeds.', 'rss', ARRAY['RSS', 'Atom', 'Feed', 'Aggregator', 'Notifications'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ncarlier/feedpushr:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Feedpushr", "version": "latest", "description": "Feedpushr is a simple and fast RSS/Atom feed aggregator that can push notifications to various services. It supports multiple output formats and can be used to monitor and aggregate RSS/Atom feeds.", "category": "rss", "tags": ["RSS", "Atom", "Feed", "Aggregator", "Notifications"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ncarlier/feedpushr:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Github", "url": "https://github.com/ncarlier/feedpushr"}, {"label": "Documentation", "url": "https://docs.readflow.app/en/integrations/examples/feedpushr/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "feedpushr", "port": "$PORT:8080", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('fenrus', 'Fenrus', 'Fenrus is a sleek and modern dashboard application designed to provide a centralized hub for accessing your self-hosted services and applications. It offers a clean, customizable interface that allows you to organize your various web applications and resources in a single, easy-to-navigate dashboard. Fenrus supports both dark and light themes, custom backgrounds, and different layout options to match your preferences. It''s perfect for home server enthusiasts who want a beautiful and functional starting point for their self-hosted ecosystem.', 'dashboard', ARRAY['Dashboard', 'Home Lab', 'Self-hosted', 'Web Interface', 'Organization'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "revenz/fenrus:23.08"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Fenrus", "version": "latest", "description": "Fenrus is a sleek and modern dashboard application designed to provide a centralized hub for accessing your self-hosted services and applications. It offers a clean, customizable interface that allows you to organize your various web applications and resources in a single, easy-to-navigate dashboard. Fenrus supports both dark and light themes, custom backgrounds, and different layout options to match your preferences. It's perfect for home server enthusiasts who want a beautiful and functional starting point for their self-hosted ecosystem.", "category": "dashboard", "tags": ["Dashboard", "Home Lab", "Self-hosted", "Web Interface", "Organization"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "revenz/fenrus:23.08"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Docker", "url": "https://hub.docker.com/r/revenz/fenrus"}, {"label": "GitHub", "url": "https://github.com/revenz/Fenrus"}], "instructions": "Access the dashboard at the configured port to start customizing your experience", "install": [{"docker": {"image": "$IMAGE", "name": "fenrus", "port": "$PORT:3000", "volumes": ["/app/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Access the dashboard at the configured port to start customizing your experience"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('ferron', 'Ferron', 'Ferron is a fast, memory-safe web server written in Rust. This template deploys Ferron with the official Docker image and exposes it through your Easypanel domain so you can start serving web traffic quickly.', 'web-server', ARRAY['Web Server', 'Reverse Proxy', 'Rust', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ferronserver/ferron:2-debian"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Ferron", "version": "latest", "description": "Ferron is a fast, memory-safe web server written in Rust. This template deploys Ferron with the official Docker image and exposes it through your Easypanel domain so you can start serving web traffic quickly.", "category": "web-server", "tags": ["Web Server", "Reverse Proxy", "Rust", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ferronserver/ferron:2-debian"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://www.ferronweb.org/"}, {"label": "Documentation", "url": "https://www.ferronweb.org/docs/"}, {"label": "GitHub", "url": "https://github.com/ferronweb/ferron"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/ferronserver/ferron"}], "instructions": "Deploy the template, then configure Ferron by mounting your own configuration and content files as needed for your use case.", "install": [{"docker": {"image": "$IMAGE", "name": "ferron", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Deploy the template, then configure Ferron by mounting your own configuration and content files as needed for your use case."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('fider', 'Fider', 'Fider is a feature-rich solution designed to help you understand and prioritize your customers'' needs. It allows your customers to share their ideas, vote, and discuss what they need the most. With Fider, you can keep everyone informed about the status of their suggestions, whether they are started, completed, or declined. The app offers a one-click sign-in feature, making it easy for visitors to contribute. You can customize Fider to match your brand''s identity, and even control access to your site by making it private. The app also supports multiple languages, making it accessible to a global audience. Fider allows you to tag your content for easy organization and uses the popular Markdown language for text styling. It also provides a public API for integration into your process and can integrate with any system that supports Webhook. With Fider, you can collect valuable feedback, respond to suggestions, and keep your audience in the loop, all in one place.', 'productivity', ARRAY['Productivity', 'Feedback', 'Collaboration'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "getfider/fider:v0.35.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Fider", "version": "latest", "description": "Fider is a feature-rich solution designed to help you understand and prioritize your customers' needs. It allows your customers to share their ideas, vote, and discuss what they need the most. With Fider, you can keep everyone informed about the status of their suggestions, whether they are started, completed, or declined. The app offers a one-click sign-in feature, making it easy for visitors to contribute. You can customize Fider to match your brand's identity, and even control access to your site by making it private. The app also supports multiple languages, making it accessible to a global audience. Fider allows you to tag your content for easy organization and uses the popular Markdown language for text styling. It also provides a public API for integration into your process and can integrate with any system that supports Webhook. With Fider, you can collect valuable feedback, respond to suggestions, and keep your audience in the loop, all in one place.", "category": "productivity", "tags": ["Productivity", "Feedback", "Collaboration"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "getfider/fider:v0.35.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://fider.io"}, {"label": "Documentation", "url": "https://fider.io/docs"}, {"label": "Github", "url": "https://github.com/getfider/fider"}], "instructions": "Fider REQUIRES email in order for installation to work!", "install": [{"docker": {"image": "$IMAGE", "name": "fider", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Fider REQUIRES email in order for installation to work!"}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('filebrowser', 'Filebrowser', 'File Browser is a versatile app designed to provide a file managing interface within a specified directory. It''s a powerful tool that allows you to upload, delete, preview, rename, and edit your files with ease. The app supports the creation of multiple users, with each user having their own directory, making it an ideal solution for managing files in a multi-user environment. File Browser also offers a range of customization options, including the ability to change the way users authenticate with the server, execute shell commands before or after certain events, and personalize the installation with custom branding. It can be used as a standalone app, offering a comprehensive and user-friendly solution for all your file management needs.', 'file-management', ARRAY['File Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "filebrowser/filebrowser:v2.63.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Filebrowser", "version": "latest", "description": "File Browser is a versatile app designed to provide a file managing interface within a specified directory. It's a powerful tool that allows you to upload, delete, preview, rename, and edit your files with ease. The app supports the creation of multiple users, with each user having their own directory, making it an ideal solution for managing files in a multi-user environment. File Browser also offers a range of customization options, including the ability to change the way users authenticate with the server, execute shell commands before or after certain events, and personalize the installation with custom branding. It can be used as a standalone app, offering a comprehensive and user-friendly solution for all your file management needs.", "category": "file-management", "tags": ["File Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "filebrowser/filebrowser:v2.63.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://filebrowser.org/"}, {"label": "Github", "url": "https://github.com/filebrowser/filebrowser"}], "instructions": "Default credentials: User:\"admin\" Password:\"admin\"", "install": [{"docker": {"image": "$IMAGE", "name": "filebrowser", "port": "$PORT:80", "volumes": ["/srv", "/database", "/.filebrowser.json"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Default credentials: User:\"admin\" Password:\"admin\""}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('filegator', 'Filegator', 'Filegator is a free, open-source, self-hosted web application for managing files and folders. It provides a user-friendly interface for organizing, uploading, downloading, and sharing files with comprehensive file management capabilities. Built with PHP, it offers multi-user support with different access permissions, roles, and home folders. All basic file operations are supported including copy, move, rename, edit, create, delete, preview, zip, unzip, download, and upload. The file upload feature supports drag & drop, progress bar, pause and resume functionality with chunked uploads for large files. Perfect for teams, students, field workers, and anyone needing a simple yet powerful file sharing and management solution.', 'file-management', ARRAY['File Management', 'Storage', 'Collaboration'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "filegator/filegator:v7.14.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Filegator", "version": "latest", "description": "Filegator is a free, open-source, self-hosted web application for managing files and folders. It provides a user-friendly interface for organizing, uploading, downloading, and sharing files with comprehensive file management capabilities. Built with PHP, it offers multi-user support with different access permissions, roles, and home folders. All basic file operations are supported including copy, move, rename, edit, create, delete, preview, zip, unzip, download, and upload. The file upload feature supports drag & drop, progress bar, pause and resume functionality with chunked uploads for large files. Perfect for teams, students, field workers, and anyone needing a simple yet powerful file sharing and management solution.", "category": "file-management", "tags": ["File Management", "Storage", "Collaboration"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "filegator/filegator:v7.14.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Github", "url": "https://github.com/filegator/filegator"}, {"label": "Documentation", "url": "https://docs.filegator.io"}, {"label": "Website", "url": "https://filegator.io"}], "instructions": "Login using credentials - admin/admin123", "install": [{"docker": {"image": "$IMAGE", "name": "filegator", "port": "$PORT:8080", "volumes": ["/var/www/filegator/repository"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Login using credentials - admin/admin123"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('filepizza', 'FilePizza', 'FilePizza is a peer-to-peer file sharing platform that enables secure, direct file transfers between users without storing files on servers. Using WebRTC technology, it creates direct connections between browsers for fast, private file sharing. The platform includes Redis for session management and COTURN server for NAT traversal, ensuring reliable connections across different network configurations. Perfect for sharing large files securely without upload limits or storage concerns.', 'file-sharing', ARRAY['File Sharing', 'Peer-to-Peer', 'WebRTC', 'Privacy', 'Direct Transfer', 'Real-time', 'Secure', 'Cross-Platform'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "kern/filepizza:3258673"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3478}}$JSON$::jsonb, $JSON${"metadata": {"name": "FilePizza", "version": "latest", "description": "FilePizza is a peer-to-peer file sharing platform that enables secure, direct file transfers between users without storing files on servers. Using WebRTC technology, it creates direct connections between browsers for fast, private file sharing. The platform includes Redis for session management and COTURN server for NAT traversal, ensuring reliable connections across different network configurations. Perfect for sharing large files securely without upload limits or storage concerns.", "category": "file-sharing", "tags": ["File Sharing", "Peer-to-Peer", "WebRTC", "Privacy", "Direct Transfer", "Real-time", "Secure", "Cross-Platform"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "kern/filepizza:3258673"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3478}}, "links": [{"label": "Website", "url": "https://file.pizza"}, {"label": "GitHub", "url": "https://github.com/kern/filepizza"}, {"label": "Documentation", "url": "https://github.com/kern/filepizza#readme"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "filepizza", "port": "$PORT:3478", "volumes": [], "extra_ports": ["5349:5349", "8080:8080"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('filerise', 'Filerise', 'Filerise is a modern file sharing and management platform that allows you to upload, organize, and share files securely. It provides a clean web interface for file management with features like user authentication, file uploads, metadata management, and configurable upload limits.', 'file-management', ARRAY['File Management', 'File Sharing', 'Web Interface', 'Self-Hosted', 'Storage'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "error311/filerise-docker:v3.12.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Filerise", "version": "latest", "description": "Filerise is a modern file sharing and management platform that allows you to upload, organize, and share files securely. It provides a clean web interface for file management with features like user authentication, file uploads, metadata management, and configurable upload limits.", "category": "file-management", "tags": ["File Management", "File Sharing", "Web Interface", "Self-Hosted", "Storage"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "error311/filerise-docker:v3.12.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://filerise.net"}, {"label": "Documentation", "url": "https://filerise.net/docs/"}, {"label": "Github", "url": "https://github.com/error311/filerise"}], "instructions": "On first launch, you will be guided to create the initial admin user.", "install": [{"docker": {"image": "$IMAGE", "name": "filerise", "port": "$PORT:80", "volumes": ["/var/www/uploads", "/var/www/users", "/var/www/metadata"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "On first launch, you will be guided to create the initial admin user."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('filerun', 'Filerun', 'FileRun is a private, fully controlled file management and sharing solution. It''s like having your own personal Google Drive, but with complete control and privacy. FileRun allows you to instantly access your files on any server without the need for importing or scanning. It supports access via FTP, SMB, and WebDAV, reflecting any changes made to your files instantly. You can sync files using desktop apps and access your files on the go with compatible mobile apps. FileRun is also great for managing photos with fast thumbnail and preview generation, timeline browsing, and metadata support. It even allows you to group photos from various folders into virtual albums that you can share online. The new virtual drive feature lets you access files directly from your computer without using up all your disk space. FileRun also supports collaboration with guest users and file requests for easy file collection and submission. It also integrates with various plugins for file editing, viewing, and conversion. FileRun ensures your files are safe with automatic file versioning and a trash folder for deleted files. It also allows for full customization to match your branding. FileRun is secure, loaded with features, and offers a smooth and intuitive mobile experience.', 'file-management', ARRAY['File Management', 'Storage', 'Privacy'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "filerun/filerun:8.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Filerun", "version": "latest", "description": "FileRun is a private, fully controlled file management and sharing solution. It's like having your own personal Google Drive, but with complete control and privacy. FileRun allows you to instantly access your files on any server without the need for importing or scanning. It supports access via FTP, SMB, and WebDAV, reflecting any changes made to your files instantly. You can sync files using desktop apps and access your files on the go with compatible mobile apps. FileRun is also great for managing photos with fast thumbnail and preview generation, timeline browsing, and metadata support. It even allows you to group photos from various folders into virtual albums that you can share online. The new virtual drive feature lets you access files directly from your computer without using up all your disk space. FileRun also supports collaboration with guest users and file requests for easy file collection and submission. It also integrates with various plugins for file editing, viewing, and conversion. FileRun ensures your files are safe with automatic file versioning and a trash folder for deleted files. It also allows for full customization to match your branding. FileRun is secure, loaded with features, and offers a smooth and intuitive mobile experience.", "category": "file-management", "tags": ["File Management", "Storage", "Privacy"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "filerun/filerun:8.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://filerun.com/"}, {"label": "Documentation", "url": "https://docs.filerun.com"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "filerun", "port": "$PORT:80", "volumes": ["/var/www/html", "/user-files"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('fileshelter', 'FileShelter', 'A simple and secure file sharing application that allows users to upload and share files with a clean web interface. Files are stored on the server and can be accessed through unique URLs.', 'file-sharing', ARRAY['File Sharing', 'Self-hosted', 'Open Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "epoupon/fileshelter:6.4.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5091}}$JSON$::jsonb, $JSON${"metadata": {"name": "FileShelter", "version": "latest", "description": "A simple and secure file sharing application that allows users to upload and share files with a clean web interface. Files are stored on the server and can be accessed through unique URLs.", "category": "file-sharing", "tags": ["File Sharing", "Self-hosted", "Open Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "epoupon/fileshelter:6.4.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5091}}, "links": [{"label": "GitHub", "url": "https://github.com/epoupon/fileshelter"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/epoupon/fileshelter"}, {"label": "Website", "url": "https://fileshelter-demo.poupon.dev"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "fileshelter", "port": "$PORT:5091", "volumes": ["/var/fileshelter"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('filestash', 'Filestash', 'Filestash is a self-hosted file management and sharing platform designed for individuals and teams. It offers a secure, user-friendly interface to store, organize, and access all your files from one centralized location. With support for multiple file types, seamless integration with popular storage backends, tagging, and powerful search functionality, Filestash simplifies file management and boosts productivity. Whether working on personal projects or collaborating with your team, Filestash ensures your files are always accessible and easy to manage.', 'file-management', ARRAY['File Management', 'Collaboration', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "machines/filestash:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8334}}$JSON$::jsonb, $JSON${"metadata": {"name": "Filestash", "version": "latest", "description": "Filestash is a self-hosted file management and sharing platform designed for individuals and teams. It offers a secure, user-friendly interface to store, organize, and access all your files from one centralized location. With support for multiple file types, seamless integration with popular storage backends, tagging, and powerful search functionality, Filestash simplifies file management and boosts productivity. Whether working on personal projects or collaborating with your team, Filestash ensures your files are always accessible and easy to manage.", "category": "file-management", "tags": ["File Management", "Collaboration", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "machines/filestash:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8334}}, "links": [{"label": "Documentation", "url": "https://www.filestash.app/docs/"}, {"label": "Github", "url": "https://github.com/mickael-kerjean/filestash"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "filestash", "port": "$PORT:8334", "volumes": ["/app/data/state/"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('filewizard', 'FileWizard', 'FileWizard is a self hosted browser based utility for file conversion OCR and audio transcription. It wraps FFmpeg LibreOffice Pandoc ImageMagick faster-whisper Tesseract and more behind a FastAPI backend and a simple web UI.', 'files', ARRAY['Files', 'Conversion', 'OCR', 'Transcription', 'FastAPI'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "loredcast/filewizard:0.4-latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}$JSON$::jsonb, $JSON${"metadata": {"name": "FileWizard", "version": "latest", "description": "FileWizard is a self hosted browser based utility for file conversion OCR and audio transcription. It wraps FFmpeg LibreOffice Pandoc ImageMagick faster-whisper Tesseract and more behind a FastAPI backend and a simple web UI.", "category": "files", "tags": ["Files", "Conversion", "OCR", "Transcription", "FastAPI"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "loredcast/filewizard:0.4-latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}, "links": [{"label": "Documentation", "url": "https://github.com/LoredCast/filewizard/wiki"}, {"label": "GitHub", "url": "https://github.com/LoredCast/filewizard"}], "instructions": "After deploy open your domain on port 8000. For local trusted use keep Local only enabled. To use OIDC authentication set Local only to false then add OAuth settings in settings.yml.", "install": [{"docker": {"image": "$IMAGE", "name": "filewizard", "port": "$PORT:8000", "volumes": ["/app/config", "/app/uploads", "/app/processed"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deploy open your domain on port 8000. For local trusted use keep Local only enabled. To use OIDC authentication set Local only to false then add OAuth settings in settings.yml."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('filezilla', 'Filezilla Client', 'FileZilla Client is a fast and reliable cross-platform FTP, FTPS and SFTP client. It is designed with a lot of useful features and an intuitive graphical user interface. The app is capable of delivering a true lossless image at a high framerate to your web browser. It supports multiple architectures and can be accessed via HTTP or HTTPS. The app also allows you to specify the user PUID and group PGID to avoid permission issues between the host OS and the container. It also provides the ability to override the default umask settings for services started within the containers.', 'file-management', ARRAY['File Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/filezilla:3.68.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Filezilla Client", "version": "latest", "description": "FileZilla Client is a fast and reliable cross-platform FTP, FTPS and SFTP client. It is designed with a lot of useful features and an intuitive graphical user interface. The app is capable of delivering a true lossless image at a high framerate to your web browser. It supports multiple architectures and can be accessed via HTTP or HTTPS. The app also allows you to specify the user PUID and group PGID to avoid permission issues between the host OS and the container. It also provides the ability to override the default umask settings for services started within the containers.", "category": "file-management", "tags": ["File Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/filezilla:3.68.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Documentation", "url": "https://docs.linuxserver.io/images/docker-filezilla"}, {"label": "Github", "url": "https://github.com/linuxserver/docker-filezilla"}], "instructions": "use abc:abc to login. To access the login interface, add ?login=true to your URL.", "install": [{"docker": {"image": "$IMAGE", "name": "filezilla", "port": "$PORT:3000", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "use abc:abc to login. To access the login interface, add ?login=true to your URL."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('firebird', 'Firebird', 'Firebird is a powerful, open-source relational database management system (RDBMS) that offers high performance, scalability, and SQL compliance. It is designed for both small and large-scale applications, providing robust multi-user support, stored procedures, triggers, and full ACID compliance. Firebird is lightweight, requiring minimal configuration while delivering strong reliability and security. It supports multiple authentication methods and integrates seamlessly with various programming languages and frameworks. With its containerized deployment, Firebird ensures easy scalability and simplified management.', 'database', ARRAY['Database', 'SQL', 'Relational Database', 'Open Source', 'FirebirdDB'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "firebirdsql/firebird:5.0.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3050}}$JSON$::jsonb, $JSON${"metadata": {"name": "Firebird", "version": "latest", "description": "Firebird is a powerful, open-source relational database management system (RDBMS) that offers high performance, scalability, and SQL compliance. It is designed for both small and large-scale applications, providing robust multi-user support, stored procedures, triggers, and full ACID compliance. Firebird is lightweight, requiring minimal configuration while delivering strong reliability and security. It supports multiple authentication methods and integrates seamlessly with various programming languages and frameworks. With its containerized deployment, Firebird ensures easy scalability and simplified management.", "category": "database", "tags": ["Database", "SQL", "Relational Database", "Open Source", "FirebirdDB"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "firebirdsql/firebird:5.0.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3050}}, "links": [{"label": "Documentation", "url": "https://firebirdsql.org/manual/"}, {"label": "Github", "url": "https://github.com/FirebirdSQL/firebird"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "firebird", "port": "$PORT:3050", "volumes": ["/var/lib/firebird/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('firecrawl', 'Firecrawl', 'Firecrawl is an API service that takes a URL, crawls it, and converts it into clean markdown or structured data. It crawls all accessible subpages and gives you clean data for each. No sitemap required. Featuring advanced scraping, crawling, and data extraction capabilities with LLM-ready formats, anti-bot mechanisms, dynamic content handling, and powerful customization options. Perfect for AI applications, data extraction, and web automation.', 'web-scraping', ARRAY['Web Scraping', 'Data Extraction', 'AI', 'LLM', 'Crawler', 'API'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/firecrawl/firecrawl:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3002}}$JSON$::jsonb, $JSON${"metadata": {"name": "Firecrawl", "version": "latest", "description": "Firecrawl is an API service that takes a URL, crawls it, and converts it into clean markdown or structured data. It crawls all accessible subpages and gives you clean data for each. No sitemap required. Featuring advanced scraping, crawling, and data extraction capabilities with LLM-ready formats, anti-bot mechanisms, dynamic content handling, and powerful customization options. Perfect for AI applications, data extraction, and web automation.", "category": "web-scraping", "tags": ["Web Scraping", "Data Extraction", "AI", "LLM", "Crawler", "API"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/firecrawl/firecrawl:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3002}}, "links": [{"label": "Website", "url": "https://firecrawl.dev/"}, {"label": "GitHub", "url": "https://github.com/firecrawl/firecrawl"}, {"label": "Documentation", "url": "https://docs.firecrawl.dev/"}], "instructions": "After deployment, access Firecrawl at the main domain on port 3002. The API\nruns in standalone mode with Redis, RabbitMQ, and NuQ Postgres. Use a fresh\ndeployment so the nuq-postgres image can run its init script and create the\nnuq schema. If you see \"relation nuq.queue_scrape does not exist\", delete the\nnuq-postgres volume and redeploy to re-run the schema setup.\n", "install": [{"docker": {"image": "$IMAGE", "name": "firecrawl", "port": "$PORT:3002", "volumes": ["/app/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deployment, access Firecrawl at the main domain on port 3002. The API\nruns in standalone mode with Redis, RabbitMQ, and NuQ Postgres. Use a fresh\ndeployment so the nuq-postgres image can run its init script and create the\nnuq schema. If you see \"relation nuq.queue_scrape does not exist\", delete the\nnuq-postgres volume and redeploy to re-run the schema setup.\n"}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('fireflyiii', 'FireFlyIII', 'Firefly III is a self-hosted personal finance manager designed to help you take control of your finances. It provides a simple and intuitive interface for tracking expenses, creating budgets, and generating insightful reports. With its robust features, Firefly III enables you to analyze your financial data effectively.', 'personal-finance', ARRAY['Personal Finance', 'Self-Hosted', 'Budgeting', 'Expense Tracking'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "fireflyiii/core:version-6.6.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "FireFlyIII", "version": "latest", "description": "Firefly III is a self-hosted personal finance manager designed to help you take control of your finances. It provides a simple and intuitive interface for tracking expenses, creating budgets, and generating insightful reports. With its robust features, Firefly III enables you to analyze your financial data effectively.", "category": "personal-finance", "tags": ["Personal Finance", "Self-Hosted", "Budgeting", "Expense Tracking"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "fireflyiii/core:version-6.6.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Documentation", "url": "https://firefly-iii.org/documentation/"}, {"label": "Github", "url": "https://github.com/firefly-iii/firefly-iii"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "fireflyiii", "port": "$PORT:8080", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('firefox', 'Firefox', 'Firefox Browser, also known as Mozilla Firefox or simply Firefox, is a free and open-source web browser developed by the Mozilla Foundation and its subsidiary, the Mozilla Corporation. This app allows you to deploy and run Firefox in a containerized environment, providing a secure and isolated space for your browsing activities. Firefox uses the Gecko layout engine to render web pages, implementing current and anticipated web standards. The app supports multiple architectures and can be accessed via HTTP or HTTPS. It also offers additional environment variables and run configurations to enable or disable specific functionalities. This containerized version of Firefox is capable of delivering a true lossless image at a high framerate to your web browser, providing an optimal browsing experience.', 'web-browsers', ARRAY['Web Browsers', 'Internet'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/firefox:1150.0.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Firefox", "version": "latest", "description": "Firefox Browser, also known as Mozilla Firefox or simply Firefox, is a free and open-source web browser developed by the Mozilla Foundation and its subsidiary, the Mozilla Corporation. This app allows you to deploy and run Firefox in a containerized environment, providing a secure and isolated space for your browsing activities. Firefox uses the Gecko layout engine to render web pages, implementing current and anticipated web standards. The app supports multiple architectures and can be accessed via HTTP or HTTPS. It also offers additional environment variables and run configurations to enable or disable specific functionalities. This containerized version of Firefox is capable of delivering a true lossless image at a high framerate to your web browser, providing an optimal browsing experience.", "category": "web-browsers", "tags": ["Web Browsers", "Internet"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/firefox:1150.0.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Documentation", "url": "https://docs.linuxserver.io/images/docker-firefox"}, {"label": "Github", "url": "https://github.com/linuxserver/docker-firefox"}], "instructions": "use abc:abc to login. To access the login interface, add ?login=true to your URL.", "install": [{"docker": {"image": "$IMAGE", "name": "firefox", "port": "$PORT:3000", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "use abc:abc to login. To access the login interface, add ?login=true to your URL."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('fireshare', 'Fireshare', 'Fireshare is a simple, user-friendly app designed to make sharing your game clips, videos, or other media a breeze. With Fireshare, you no longer have to go through the hassle of uploading your short clips to YouTube and waiting for them to process. Instead, you can easily self-host your clips and share them with your friends through unique links generated by the app. All you need to do is put your videos in a folder and Fireshare will handle the rest. The app also allows you to view all your videos, edit their details, and decide whether you want them to show up on the public feed. Fireshare also supports foldered sorting, allowing you to organize your videos into categories of your choosing. The app is mobile-friendly and supports open graph data, allowing websites and messaging apps to display the title, description, and video thumbnails in your posts.', 'media', ARRAY['Media', 'File Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "shaneisrael/fireshare:v1.6.8"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Fireshare", "version": "latest", "description": "Fireshare is a simple, user-friendly app designed to make sharing your game clips, videos, or other media a breeze. With Fireshare, you no longer have to go through the hassle of uploading your short clips to YouTube and waiting for them to process. Instead, you can easily self-host your clips and share them with your friends through unique links generated by the app. All you need to do is put your videos in a folder and Fireshare will handle the rest. The app also allows you to view all your videos, edit their details, and decide whether you want them to show up on the public feed. Fireshare also supports foldered sorting, allowing you to organize your videos into categories of your choosing. The app is mobile-friendly and supports open graph data, allowing websites and messaging apps to display the title, description, and video thumbnails in your posts.", "category": "media", "tags": ["Media", "File Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "shaneisrael/fireshare:v1.6.8"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://v.fireshare.net"}, {"label": "Github", "url": "https://github.com/ShaneIsrael/fireshare"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "fireshare", "port": "$PORT:80", "volumes": ["/processed", "/data", "/videos"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('flagsmith', 'Flagsmith', 'Flagsmith is a powerful, self-hosted service for feature flag management, remote configuration, and experimentation. It provides a clean and simple interface, supports integrations with various tools, and offers advanced analytics for feature usage and experimentation results. With Flagsmith, you can maintain control over your feature management and deployment process.', 'feature-flags', ARRAY['Feature Flags', 'Remote Configuration', 'Analytics', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "flagsmith/flagsmith:2.231.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Flagsmith", "version": "latest", "description": "Flagsmith is a powerful, self-hosted service for feature flag management, remote configuration, and experimentation. It provides a clean and simple interface, supports integrations with various tools, and offers advanced analytics for feature usage and experimentation results. With Flagsmith, you can maintain control over your feature management and deployment process.", "category": "feature-flags", "tags": ["Feature Flags", "Remote Configuration", "Analytics", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "flagsmith/flagsmith:2.231.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}, "links": [{"label": "Documentation", "url": "https://docs.flagsmith.com/"}, {"label": "GitHub", "url": "https://github.com/Flagsmith/flagsmith"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "flagsmith", "port": "$PORT:8000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('flame', 'Flame', 'Flame is a self-hosted startpage for your server, designed to be your very own application hub. Inspired by SUI, its sleek design is not only visually appealing but also incredibly easy to use. With Flame, you can create, update, and delete your applications and bookmarks directly from the app using built-in GUI editors. It also allows you to pin your favorite items to the homescreen for quick and easy access. The app features an integrated search bar with local filtering and 11 web search providers, and even gives you the ability to add your own. Flame also includes an authentication system to protect your settings, apps, and bookmarks. The interface is highly customizable, with dozens of options including support for custom CSS, 15 built-in color themes, and a custom theme builder. Additionally, Flame features a weather widget with current temperature, cloud coverage, and animated weather status. It also integrates with Docker to automatically pick and add apps based on their labels.', 'dashboard', ARRAY['Dashboard', 'Bookmarks', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "pawelmalak/flame:multiarch2.4.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5005}}$JSON$::jsonb, $JSON${"metadata": {"name": "Flame", "version": "latest", "description": "Flame is a self-hosted startpage for your server, designed to be your very own application hub. Inspired by SUI, its sleek design is not only visually appealing but also incredibly easy to use. With Flame, you can create, update, and delete your applications and bookmarks directly from the app using built-in GUI editors. It also allows you to pin your favorite items to the homescreen for quick and easy access. The app features an integrated search bar with local filtering and 11 web search providers, and even gives you the ability to add your own. Flame also includes an authentication system to protect your settings, apps, and bookmarks. The interface is highly customizable, with dozens of options including support for custom CSS, 15 built-in color themes, and a custom theme builder. Additionally, Flame features a weather widget with current temperature, cloud coverage, and animated weather status. It also integrates with Docker to automatically pick and add apps based on their labels.", "category": "dashboard", "tags": ["Dashboard", "Bookmarks", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "pawelmalak/flame:multiarch2.4.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5005}}, "links": [{"label": "Website", "url": "https://github.com/pawelmalak/flame"}, {"label": "Documentation", "url": "https://github.com/pawelmalak/flame"}, {"label": "Github", "url": "https://github.com/pawelmalak/flame"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "flame", "port": "$PORT:5005", "volumes": ["/app/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('flaresolverr', 'FlareSolverr', 'FlareSolverr is a proxy server designed to help bots and scripts bypass web protections like Cloudflare''s anti-bot page. It acts as an intermediary that can execute JavaScript and handle cookies and sessions, making it appear as if requests are coming from a real web browser. This tool is particularly useful for web scraping and automated data collection tasks where access to JavaScript-heavy websites is required. FlareSolverr supports multiple platforms and can be integrated into existing scraping setups to solve CAPTCHAs and manage browser sessions efficiently.', 'web-scraping', ARRAY['Web Scraping', 'Proxy Server', 'Anti-bot Bypass', 'CAPTCHA Solving', 'Cloudflare Bypass'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/flaresolverr/flaresolverr:v3.4.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "FlareSolverr", "version": "latest", "description": "FlareSolverr is a proxy server designed to help bots and scripts bypass web protections like Cloudflare's anti-bot page. It acts as an intermediary that can execute JavaScript and handle cookies and sessions, making it appear as if requests are coming from a real web browser. This tool is particularly useful for web scraping and automated data collection tasks where access to JavaScript-heavy websites is required. FlareSolverr supports multiple platforms and can be integrated into existing scraping setups to solve CAPTCHAs and manage browser sessions efficiently.", "category": "web-scraping", "tags": ["Web Scraping", "Proxy Server", "Anti-bot Bypass", "CAPTCHA Solving", "Cloudflare Bypass"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/flaresolverr/flaresolverr:v3.4.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://github.com/FlareSolverr/FlareSolverr"}, {"label": "Documentation", "url": "https://github.com/FlareSolverr/FlareSolverr/wiki"}, {"label": "Github", "url": "https://github.com/FlareSolverr/FlareSolverr"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "flaresolverr", "port": "$PORT:80", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('flarum', 'Flarum', 'Experience a modern, fast, and free forum experience with our app. Designed with an elegant UI, our app is mobile-first, easily stylable, and lightweight, ensuring a seamless experience on any device. It prioritizes security and trust, providing a safe environment for users. The app is also localised into many languages, with 41 translation packs available, making it accessible to users worldwide. Whether you''re a leading telephone network serving millions of customers, an avid adventurer sharing your experiences, or a provider of communication and entertainment, our app is the perfect platform for you. It''s not just a forum, it''s a revolution in community engagement.', 'forums', ARRAY['Forums', 'Communication', 'Social Networking'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "crazymax/flarum:1.8.10"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Flarum", "version": "latest", "description": "Experience a modern, fast, and free forum experience with our app. Designed with an elegant UI, our app is mobile-first, easily stylable, and lightweight, ensuring a seamless experience on any device. It prioritizes security and trust, providing a safe environment for users. The app is also localised into many languages, with 41 translation packs available, making it accessible to users worldwide. Whether you're a leading telephone network serving millions of customers, an avid adventurer sharing your experiences, or a provider of communication and entertainment, our app is the perfect platform for you. It's not just a forum, it's a revolution in community engagement.", "category": "forums", "tags": ["Forums", "Communication", "Social Networking"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "crazymax/flarum:1.8.10"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}, "links": [{"label": "Website", "url": "https://flarum.org/"}, {"label": "Documentation", "url": "https://docs.flarum.org/"}, {"label": "Github", "url": "https://github.com/flarum/flarum"}], "instructions": "Please use the credentials flarum:flarum to login.", "install": [{"docker": {"image": "$IMAGE", "name": "flarum", "port": "$PORT:8000", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Please use the credentials flarum:flarum to login."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('flashpaper', 'FlashPaper', 'FlashPaper is a secure, self-destructing message service that allows you to share sensitive information safely. Messages are encrypted and automatically destroyed after being viewed once, ensuring that sensitive data remains secure and temporary.', 'security', ARRAY['Security', 'Privacy', 'Encryption', 'Self-Destructing', 'Communication'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/andrewpaglusch/flashpaper:2.4.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "FlashPaper", "version": "latest", "description": "FlashPaper is a secure, self-destructing message service that allows you to share sensitive information safely. Messages are encrypted and automatically destroyed after being viewed once, ensuring that sensitive data remains secure and temporary.", "category": "security", "tags": ["Security", "Privacy", "Encryption", "Self-Destructing", "Communication"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/andrewpaglusch/flashpaper:2.4.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Github", "url": "https://github.com/AndrewPaglusch/FlashPaper"}, {"label": "Website", "url": "https://flashpaper.io"}], "instructions": "After installation, access the web interface through the provided domain to start creating self-destructing messages.", "install": [{"docker": {"image": "$IMAGE", "name": "flashpaper", "port": "$PORT:80", "volumes": ["/var/www/html/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After installation, access the web interface through the provided domain to start creating self-destructing messages."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('flatnotes', 'Flatnotes', 'Flatnotes is an open-source, self-hosted note-taking platform designed to help individuals and teams manage their notes efficiently. It provides a lightweight and intuitive interface for creating, organizing, and sharing notes. With robust customization options, Flatnotes supports markdown editing, tagging, and a responsive design, making it a versatile solution for note management.', 'note-taking', ARRAY['Note-Taking', 'Markdown', 'Open Source', 'Self-Hosted', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "dullage/flatnotes:v5.5.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Flatnotes", "version": "latest", "description": "Flatnotes is an open-source, self-hosted note-taking platform designed to help individuals and teams manage their notes efficiently. It provides a lightweight and intuitive interface for creating, organizing, and sharing notes. With robust customization options, Flatnotes supports markdown editing, tagging, and a responsive design, making it a versatile solution for note management.", "category": "note-taking", "tags": ["Note-Taking", "Markdown", "Open Source", "Self-Hosted", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "dullage/flatnotes:v5.5.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Github", "url": "https://github.com/dullage/flatnotes"}, {"label": "Demo", "url": "https://flatnotes.dullage.com/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "flatnotes", "port": "$PORT:8080", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('flowise', 'Flowise', 'Flowise is an open-source UI visual tool that allows you to build your own customized LLM (Language Learning Model) flow with ease. It is built on top of LangChainJS and is written in Node Typescript/Javascript. With Flowise, you can see your LLM apps running live, making the process of building and testing faster and more efficient. The app is extensible, allowing for custom component integrations. It offers a variety of features such as QnA retrieval chain, language translation chain, and a conversational agent with memory for chat models. Flowise is designed to make the process of visualizing and building LLM apps simple and accessible.', 'developer-tools', ARRAY['Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "flowiseai/flowise:3.1.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Flowise", "version": "latest", "description": "Flowise is an open-source UI visual tool that allows you to build your own customized LLM (Language Learning Model) flow with ease. It is built on top of LangChainJS and is written in Node Typescript/Javascript. With Flowise, you can see your LLM apps running live, making the process of building and testing faster and more efficient. The app is extensible, allowing for custom component integrations. It offers a variety of features such as QnA retrieval chain, language translation chain, and a conversational agent with memory for chat models. Flowise is designed to make the process of visualizing and building LLM apps simple and accessible.", "category": "developer-tools", "tags": ["Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "flowiseai/flowise:3.1.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://flowiseai.com"}, {"label": "Documentation", "url": "https://docs.flowiseai.com"}, {"label": "Github", "url": "https://github.com/FlowiseAI/Flowise"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "flowise", "port": "$PORT:80", "volumes": ["/root/.flowise"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('focalboard', 'Focalboard', 'Mattermost Boards is an open-source project management tool designed for technical teams. It centralizes, plans, and tracks all your work in one place, helping your organization maintain a single source of truth. This ensures your teams stay aligned to complete tasks, reach milestones, and achieve their goals. The app allows you to manage all your tasks on a Kanban, table, gallery, and calendar view, focusing on the highest priority items with board filters. It also offers real-time collaboration features, including card comments, @mention teammates, and board permissions to share your board with the entire team or specific individuals. Mattermost Boards comes with pre-built templates for quick setup or the option to create a fully custom board from scratch. It also includes features like unlimited boards, file sharing, customizable templates, project cards & tasks, archiving & back-up snapshots, and more. Mattermost Boards is an open-source alternative to tools like Asana, Trello, and Notion.', 'project-management', ARRAY['Project Management', 'Collaboration', 'Task Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "mattermost/focalboard:7.11.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Focalboard", "version": "latest", "description": "Mattermost Boards is an open-source project management tool designed for technical teams. It centralizes, plans, and tracks all your work in one place, helping your organization maintain a single source of truth. This ensures your teams stay aligned to complete tasks, reach milestones, and achieve their goals. The app allows you to manage all your tasks on a Kanban, table, gallery, and calendar view, focusing on the highest priority items with board filters. It also offers real-time collaboration features, including card comments, @mention teammates, and board permissions to share your board with the entire team or specific individuals. Mattermost Boards comes with pre-built templates for quick setup or the option to create a fully custom board from scratch. It also includes features like unlimited boards, file sharing, customizable templates, project cards & tasks, archiving & back-up snapshots, and more. Mattermost Boards is an open-source alternative to tools like Asana, Trello, and Notion.", "category": "project-management", "tags": ["Project Management", "Collaboration", "Task Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "mattermost/focalboard:7.11.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}, "links": [{"label": "Website", "url": "https://focalboard.com"}, {"label": "Documentation", "url": "https://docs.mattermost.com/guides/boards.html"}, {"label": "Github", "url": "https://github.com/mattermost/focalboard"}, {"label": "Docker", "url": "https://hub.docker.com/r/mattermost/focalboard"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "focalboard", "port": "$PORT:8000", "volumes": ["/opt/focalboard/data", "/opt/focalboard/config.json"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('foldingathome', 'Folding@Home', 'Folding@Home is a distributed computing project that simulates protein folding and other molecular dynamics to help researchers understand how proteins work and how they can malfunction. By donating your unused computing power, you become a citizen scientist contributing to research on diseases like COVID-19, Alzheimer''s, cancer, and many others. The project uses your computer to run simulations that help scientists develop new treatments and understand biological processes.', 'science', ARRAY['Science', 'Research', 'Distributed Computing', 'Medical Research', 'Protein Folding', 'Citizen Science', 'Volunteer Computing'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/foldingathome:8.5.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 7396}}$JSON$::jsonb, $JSON${"metadata": {"name": "Folding@Home", "version": "latest", "description": "Folding@Home is a distributed computing project that simulates protein folding and other molecular dynamics to help researchers understand how proteins work and how they can malfunction. By donating your unused computing power, you become a citizen scientist contributing to research on diseases like COVID-19, Alzheimer's, cancer, and many others. The project uses your computer to run simulations that help scientists develop new treatments and understand biological processes.", "category": "science", "tags": ["Science", "Research", "Distributed Computing", "Medical Research", "Protein Folding", "Citizen Science", "Volunteer Computing"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/foldingathome:8.5.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 7396}}, "links": [{"label": "Website", "url": "https://foldingathome.org/"}, {"label": "Documentation", "url": "https://foldingathome.org/start-folding/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "foldingathome", "port": "$PORT:7396", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('forgejo', 'Forgejo', 'Forgejo is a community-driven, lightweight, and self-hosted Git service that offers a seamless platform for managing repositories, collaborating on code, and controlling your versioning needs. As a fork of Gitea, Forgejo builds on a solid foundation and enhances features with contributions from a vibrant community. It supports all major platforms, including Linux, macOS, Windows, and ARM-based systems. Forgejo is lightweight, extensible, and easy to set up, making it an excellent choice for individuals and teams looking for a self-hosted Git service. Its open-source nature ensures privacy, transparency, and the flexibility to self-host for maximum control.', 'code-hosting', ARRAY['Code Hosting', 'Self-Hosted', 'Git Service'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "codeberg.org/forgejo/forgejo:15.0.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Forgejo", "version": "latest", "description": "Forgejo is a community-driven, lightweight, and self-hosted Git service that offers a seamless platform for managing repositories, collaborating on code, and controlling your versioning needs. As a fork of Gitea, Forgejo builds on a solid foundation and enhances features with contributions from a vibrant community. It supports all major platforms, including Linux, macOS, Windows, and ARM-based systems. Forgejo is lightweight, extensible, and easy to set up, making it an excellent choice for individuals and teams looking for a self-hosted Git service. Its open-source nature ensures privacy, transparency, and the flexibility to self-host for maximum control.", "category": "code-hosting", "tags": ["Code Hosting", "Self-Hosted", "Git Service"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "codeberg.org/forgejo/forgejo:15.0.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://forgejo.org/"}, {"label": "Documentation", "url": "https://docs.forgejo.org/"}, {"label": "Github", "url": "https://codeberg.org/forgejo/forgejo"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "forgejo", "port": "$PORT:3000", "volumes": ["/data", "/etc/timezone", "/etc/localtime"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('formbricks', 'Formbricks', 'Formbricks provides a free and open source surveying platform. Gather feedback at every point in the user journey with beautiful in-app, website, link and email surveys. Build on top of Formbricks or leverage prebuilt data analysis capabilities.', 'survey', ARRAY['Survey', 'Forms', 'Experience Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/formbricks/formbricks:4.9.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Formbricks", "version": "latest", "description": "Formbricks provides a free and open source surveying platform. Gather feedback at every point in the user journey with beautiful in-app, website, link and email surveys. Build on top of Formbricks or leverage prebuilt data analysis capabilities.", "category": "survey", "tags": ["Survey", "Forms", "Experience Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/formbricks/formbricks:4.9.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://formbricks.com"}, {"label": "Github", "url": "https://github.com/formbricks/formbricks"}, {"label": "Docker", "url": "https://ghcr.io/formbricks/formbricks"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "formbricks", "port": "$PORT:3000", "volumes": ["/home/nextjs/apps/web/uploads/"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('formio', 'Form.io', 'Form.io is a form and data management platform for progressive web applications. It provides a drag-and-drop form builder, API platform, and data management system that allows developers to rapidly build complex forms and workflows. Form.io combines the power of JSON Schema with a robust API to create dynamic, data-driven applications.', 'forms', ARRAY['Forms', 'Form Builder', 'API Platform', 'Data Management', 'Workflow', 'MongoDB'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "formio/formio:4.6.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3001}}$JSON$::jsonb, $JSON${"metadata": {"name": "Form.io", "version": "latest", "description": "Form.io is a form and data management platform for progressive web applications. It provides a drag-and-drop form builder, API platform, and data management system that allows developers to rapidly build complex forms and workflows. Form.io combines the power of JSON Schema with a robust API to create dynamic, data-driven applications.", "category": "forms", "tags": ["Forms", "Form Builder", "API Platform", "Data Management", "Workflow", "MongoDB"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "formio/formio:4.6.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3001}}, "links": [{"label": "Official Website", "url": "https://form.io/"}, {"label": "Documentation", "url": "https://help.form.io/"}, {"label": "GitHub", "url": "https://github.com/formio/formio"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "formio", "port": "$PORT:3001", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('fossbilling', 'FOSSBilling', 'FOSSBilling is a free, open-source billing and client management system designed for hosting providers, service providers, and freelancers. It provides comprehensive tools for managing clients, products, services, invoices, and payments. FOSSBilling features automated billing cycles, support ticket management, domain registration integration, customizable invoice templates, and multi-currency support. The platform includes a client portal where customers can manage their services, view invoices, and submit support tickets. With support for multiple payment gateways including PayPal, Stripe, and others, FOSSBilling streamlines the entire billing workflow. Perfect for web hosting companies, SaaS providers, and service-based businesses who need professional billing automation without expensive licensing fees.', 'billing', ARRAY['Billing', 'Invoice', 'Client Management', 'Payment Processing', 'Hosting'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "fossbilling/fossbilling:0.7.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "FOSSBilling", "version": "latest", "description": "FOSSBilling is a free, open-source billing and client management system designed for hosting providers, service providers, and freelancers. It provides comprehensive tools for managing clients, products, services, invoices, and payments. FOSSBilling features automated billing cycles, support ticket management, domain registration integration, customizable invoice templates, and multi-currency support. The platform includes a client portal where customers can manage their services, view invoices, and submit support tickets. With support for multiple payment gateways including PayPal, Stripe, and others, FOSSBilling streamlines the entire billing workflow. Perfect for web hosting companies, SaaS providers, and service-based businesses who need professional billing automation without expensive licensing fees.", "category": "billing", "tags": ["Billing", "Invoice", "Client Management", "Payment Processing", "Hosting"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "fossbilling/fossbilling:0.7.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://fossbilling.org/"}, {"label": "Documentation", "url": "https://fossbilling.org/docs"}, {"label": "Github", "url": "https://github.com/FOSSBilling/FOSSBilling"}], "instructions": "After deployment, open your domain and run the FOSSBilling web installer.\nUse MySQL connection details, keep /var/www/html on persistent storage as configured.\n", "install": [{"docker": {"image": "$IMAGE", "name": "fossbilling", "port": "$PORT:80", "volumes": ["/var/www/html"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deployment, open your domain and run the FOSSBilling web installer.\nUse MySQL connection details, keep /var/www/html on persistent storage as configured.\n"}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('fossflow', 'FOSSFlow', 'FOSSFlow is an open-source diagramming and flowchart application that enables users to create, edit, and manage technical diagrams, flowcharts, and process visualizations. Built for developers, system architects, and technical teams, FOSSFlow provides an intuitive interface for designing workflows, system architectures, database schemas, and network diagrams. The application supports server-side storage for persistent diagram saving and optional Git backup integration for version control and collaboration. With a lightweight Node.js backend and modern frontend, FOSSFlow offers a self-hosted alternative to cloud-based diagramming tools, giving you complete control over your technical documentation and diagrams. Perfect for teams that need to document systems, design workflows, create technical specifications, and maintain architectural diagrams without relying on external services or sharing sensitive information with third parties.', 'diagramming', ARRAY['Diagramming', 'Flowchart', 'Documentation', 'Visualization', 'Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "stnsmith/fossflow:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "FOSSFlow", "version": "latest", "description": "FOSSFlow is an open-source diagramming and flowchart application that enables users to create, edit, and manage technical diagrams, flowcharts, and process visualizations. Built for developers, system architects, and technical teams, FOSSFlow provides an intuitive interface for designing workflows, system architectures, database schemas, and network diagrams. The application supports server-side storage for persistent diagram saving and optional Git backup integration for version control and collaboration. With a lightweight Node.js backend and modern frontend, FOSSFlow offers a self-hosted alternative to cloud-based diagramming tools, giving you complete control over your technical documentation and diagrams. Perfect for teams that need to document systems, design workflows, create technical specifications, and maintain architectural diagrams without relying on external services or sharing sensitive information with third parties.", "category": "diagramming", "tags": ["Diagramming", "Flowchart", "Documentation", "Visualization", "Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "stnsmith/fossflow:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Docker Hub", "url": "https://hub.docker.com/r/stnsmith/fossflow"}, {"label": "Github", "url": "https://github.com/stan-smith/FossFLOW"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "fossflow", "port": "$PORT:80", "volumes": ["/data/diagrams"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('foundryvtt', 'FoundryVTT', 'Foundry Virtual Tabletop is a modern, self-hosted virtual tabletop platform designed for playing tabletop roleplaying games online. It provides a comprehensive suite of tools for game masters and players, including dynamic lighting, fog of war, automated combat systems, and extensive customization options. FoundryVTT supports multiple game systems and offers a rich ecosystem of community-created modules and content. With its powerful JavaScript API and intuitive interface, FoundryVTT delivers an immersive gaming experience that rivals traditional tabletop gaming.', 'gaming', ARRAY['Gaming', 'Virtual Tabletop', 'RPG', 'Self-Hosted', 'Multiplayer', 'Game Master Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "felddy/foundryvtt:14.361.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 30000}}$JSON$::jsonb, $JSON${"metadata": {"name": "FoundryVTT", "version": "latest", "description": "Foundry Virtual Tabletop is a modern, self-hosted virtual tabletop platform designed for playing tabletop roleplaying games online. It provides a comprehensive suite of tools for game masters and players, including dynamic lighting, fog of war, automated combat systems, and extensive customization options. FoundryVTT supports multiple game systems and offers a rich ecosystem of community-created modules and content. With its powerful JavaScript API and intuitive interface, FoundryVTT delivers an immersive gaming experience that rivals traditional tabletop gaming.", "category": "gaming", "tags": ["Gaming", "Virtual Tabletop", "RPG", "Self-Hosted", "Multiplayer", "Game Master Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "felddy/foundryvtt:14.361.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 30000}}, "links": [{"label": "Website", "url": "https://foundryvtt.com/"}, {"label": "Documentation", "url": "https://foundryvtt.com/kb/"}, {"label": "GitHub (container source)", "url": "https://github.com/felddy/foundryvtt-docker"}, {"label": "Docker Hub (container image)", "url": "https://hub.docker.com/r/felddy/foundryvtt"}, {"label": "Community", "url": "https://discord.gg/foundryvtt"}], "instructions": "FoundryVTT is proprietary software, so there is no official public `foundryvtt/foundryvtt` Docker image on Docker Hub. This template uses `felddy/foundryvtt`, which is the widely used community container maintained specifically for licensed FoundryVTT deployments. You must provide a valid FoundryVTT release URL and your foundryvtt.com account credentials so the container can download your licensed build. Keep these credentials private. On first startup, complete setup in the web UI, set an admin key, and activate your FoundryVTT license. All persistent data is stored in `/data`.", "install": [{"docker": {"image": "$IMAGE", "name": "foundryvtt", "port": "$PORT:30000", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "FoundryVTT is proprietary software, so there is no official public `foundryvtt/foundryvtt` Docker image on Docker Hub. This template uses `felddy/foundryvtt`, which is the widely used community container maintained specifically for licensed FoundryVTT deployments. You must provide a valid FoundryVTT release URL and your foundryvtt.com account credentials so the container can download your licensed build. Keep these credentials private. On first startup, complete setup in the web UI, set an admin key, and activate your FoundryVTT license. All persistent data is stored in `/data`."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('frappe-helpdesk', 'Frappe Helpdesk', 'Frappe Helpdesk is a comprehensive customer support and ticketing system built on the Frappe framework. It provides a complete solution for managing customer inquiries, support tickets, and service requests. The platform offers multi-channel support, automated workflows, knowledge base integration, and detailed analytics to help teams deliver exceptional customer service. Frappe Helpdesk features a modern, responsive interface that works seamlessly across desktop and mobile devices, making it easy for support agents to manage tickets and for customers to submit and track their requests. The system supports team collaboration, SLA management, and integration with various communication channels including email, chat, and social media platforms.', 'helpdesk', ARRAY['Helpdesk', 'Customer Support', 'Ticketing', 'CRM', 'Open Source', 'Web App', 'Self-hosted', 'MariaDB', 'Redis'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "frappe/bench:v5.25.9"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Frappe Helpdesk", "version": "latest", "description": "Frappe Helpdesk is a comprehensive customer support and ticketing system built on the Frappe framework. It provides a complete solution for managing customer inquiries, support tickets, and service requests. The platform offers multi-channel support, automated workflows, knowledge base integration, and detailed analytics to help teams deliver exceptional customer service. Frappe Helpdesk features a modern, responsive interface that works seamlessly across desktop and mobile devices, making it easy for support agents to manage tickets and for customers to submit and track their requests. The system supports team collaboration, SLA management, and integration with various communication channels including email, chat, and social media platforms.", "category": "helpdesk", "tags": ["Helpdesk", "Customer Support", "Ticketing", "CRM", "Open Source", "Web App", "Self-hosted", "MariaDB", "Redis"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "frappe/bench:v5.25.9"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}, "links": [{"label": "Website", "url": "https://frappe.io/"}, {"label": "Documentation", "url": "https://frappe.io/docs"}, {"label": "GitHub", "url": "https://github.com/frappe/frappe"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "frappe-helpdesk", "port": "$PORT:8000", "volumes": ["/workspace", "/workspace/init.sh"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('frappe-lms', 'Frappe LMS', 'LMS (Learning Management System) is a comprehensive educational platform built on the Frappe framework that enables organizations to create, manage, and deliver online learning content. The system provides course management, student enrollment, progress tracking, assessments, and interactive learning features. Built with modern web technologies, it offers a robust and scalable solution for educational institutions, corporate training programs, and online learning platforms. The Frappe-based architecture ensures reliability, extensibility, and ease of customization for specific learning requirements.', 'learning-management', ARRAY['Learning Management', 'Education', 'E-Learning', 'Course Management', 'Student Portal'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "frappe/bench:v5.29.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Frappe LMS", "version": "latest", "description": "LMS (Learning Management System) is a comprehensive educational platform built on the Frappe framework that enables organizations to create, manage, and deliver online learning content. The system provides course management, student enrollment, progress tracking, assessments, and interactive learning features. Built with modern web technologies, it offers a robust and scalable solution for educational institutions, corporate training programs, and online learning platforms. The Frappe-based architecture ensures reliability, extensibility, and ease of customization for specific learning requirements.", "category": "learning-management", "tags": ["Learning Management", "Education", "E-Learning", "Course Management", "Student Portal"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "frappe/bench:v5.29.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}, "links": [{"label": "Github", "url": "https://github.com/frappe/lms"}, {"label": "Documentation", "url": "https://frappe.io/learning"}, {"label": "Website", "url": "https://frappeframework.com"}], "instructions": "Default login credentials are Administrator/admin. It takes 5-7 minutes to install the app.", "install": [{"docker": {"image": "$IMAGE", "name": "frappe-lms", "port": "$PORT:8000", "volumes": ["/workspace/init.sh", "/workspace"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Default login credentials are Administrator/admin. It takes 5-7 minutes to install the app."}, "services": {"mysql": {"type": "mysql", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('freescout', 'Freescout', 'FreeScout is a powerful, open-source help desk and shared inbox application. It''s a self-hosted alternative to Zendesk & Help Scout, offering you complete control over your customer support without compromising on privacy. FreeScout is designed to be lightweight yet robust, capable of handling unlimited support agents, tickets, and mailboxes. It offers seamless email integration, automatic replies, internal notes, conversation forwarding, merging, and moving, among other features. The application is mobile-friendly and supports multiple languages. It also includes features like push notifications, starred conversations, collision detection, and flexible notifications for user agents. FreeScout also offers a range of integrations, including Slack, WhatsApp, Facebook, and Telegram, and supports translating tickets, live chat, time tracking, custom fields, and more. It''s the perfect solution for those who need professional customer support but can''t afford to pay for Zendesk or Help Scout.', 'customer-support', ARRAY['Customer Support'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "tiredofit/freescout:php8.1-1.17.158"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Freescout", "version": "latest", "description": "FreeScout is a powerful, open-source help desk and shared inbox application. It's a self-hosted alternative to Zendesk & Help Scout, offering you complete control over your customer support without compromising on privacy. FreeScout is designed to be lightweight yet robust, capable of handling unlimited support agents, tickets, and mailboxes. It offers seamless email integration, automatic replies, internal notes, conversation forwarding, merging, and moving, among other features. The application is mobile-friendly and supports multiple languages. It also includes features like push notifications, starred conversations, collision detection, and flexible notifications for user agents. FreeScout also offers a range of integrations, including Slack, WhatsApp, Facebook, and Telegram, and supports translating tickets, live chat, time tracking, custom fields, and more. It's the perfect solution for those who need professional customer support but can't afford to pay for Zendesk or Help Scout.", "category": "customer-support", "tags": ["Customer Support"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "tiredofit/freescout:php8.1-1.17.158"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://freescout.net"}, {"label": "Documentation", "url": "https://github.com/freescout-helpdesk/freescout/wiki"}, {"label": "Github", "url": "https://github.com/freescout-helpdesk/freescout/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "freescout", "port": "$PORT:80", "volumes": ["/www/logs", "/data", "/assets/modules"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('freshrss', 'Freshrss', 'FreshRSS is a free, self-hostable aggregator for RSS feeds. It allows you to gather and read your favorite news sources in one place, providing a streamlined and efficient way to stay informed. The app supports multiple platforms and can be easily accessed through a web user interface. FreshRSS also offers the ability to use external databases, enabling users to create a user and database in their MySQL/MariaDB server. Additional extensions can be added to enhance the functionality of the app. FreshRSS is designed to be simple to use, yet powerful, providing a comprehensive solution for RSS feed aggregation.', 'rss', ARRAY['RSS'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/freshrss:1.28.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Freshrss", "version": "latest", "description": "FreshRSS is a free, self-hostable aggregator for RSS feeds. It allows you to gather and read your favorite news sources in one place, providing a streamlined and efficient way to stay informed. The app supports multiple platforms and can be easily accessed through a web user interface. FreshRSS also offers the ability to use external databases, enabling users to create a user and database in their MySQL/MariaDB server. Additional extensions can be added to enhance the functionality of the app. FreshRSS is designed to be simple to use, yet powerful, providing a comprehensive solution for RSS feed aggregation.", "category": "rss", "tags": ["RSS"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/freshrss:1.28.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Documentation", "url": "https://docs.linuxserver.io/images/docker-freshrss"}, {"label": "Github", "url": "https://github.com/linuxserver/docker-freshrss"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "freshrss", "port": "$PORT:80", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('fusionauth', 'FusionAuth', 'FusionAuth is a powerful, self-hosted identity and access management platform designed for developers. It provides a robust set of features, including user authentication, authorization, and user management, all accessible through a modern API or web interface. FusionAuth supports advanced features like social login, SSO, passwordless login, and multi-factor authentication.', 'identity-management', ARRAY['Identity Management', 'Authentication', 'Authorization', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "fusionauth/fusionauth-app:1.66.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9011}}$JSON$::jsonb, $JSON${"metadata": {"name": "FusionAuth", "version": "latest", "description": "FusionAuth is a powerful, self-hosted identity and access management platform designed for developers. It provides a robust set of features, including user authentication, authorization, and user management, all accessible through a modern API or web interface. FusionAuth supports advanced features like social login, SSO, passwordless login, and multi-factor authentication.", "category": "identity-management", "tags": ["Identity Management", "Authentication", "Authorization", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "fusionauth/fusionauth-app:1.66.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9011}}, "links": [{"label": "Documentation", "url": "https://fusionauth.io/docs"}, {"label": "Github", "url": "https://github.com/FusionAuth"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "fusionauth", "port": "$PORT:9011", "volumes": ["/usr/local/fusionauth/config", "/usr/share/opensearch/data"], "extra_ports": ["9200:9200"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('gameyfin', 'Gameyfin', 'Gameyfin is a free and open-source application for managing your video game library. Track installed and wanted games, fetch metadata (e.g. IGDB, Steam), and use plugins for downloads and extra providers. It runs as a Kotlin / Spring Boot app with a web UI, PF4J plugins, and optional OIDC. Docker is the recommended install path; persist db, data, plugin data, logs, and mount at least one folder for your game files.', 'games', ARRAY['Games', 'Library', 'Self-Hosted', 'Metadata', 'Docker', 'IGDB'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/gameyfin/gameyfin:2.4.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Gameyfin", "version": "latest", "description": "Gameyfin is a free and open-source application for managing your video game library. Track installed and wanted games, fetch metadata (e.g. IGDB, Steam), and use plugins for downloads and extra providers. It runs as a Kotlin / Spring Boot app with a web UI, PF4J plugins, and optional OIDC. Docker is the recommended install path; persist db, data, plugin data, logs, and mount at least one folder for your game files.", "category": "games", "tags": ["Games", "Library", "Self-Hosted", "Metadata", "Docker", "IGDB"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/gameyfin/gameyfin:2.4.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Website", "url": "https://gameyfin.org"}, {"label": "Documentation", "url": "https://gameyfin.org/installation/docker/"}, {"label": "GitHub", "url": "https://github.com/gameyfin/gameyfin"}, {"label": "Container registry (GHCR)", "url": "https://github.com/gameyfin/gameyfin/pkgs/container/gameyfin"}], "instructions": "APP_KEY is generated on deploy (32 random bytes, Base64). Do not change it\nafter data exists or the app cannot decrypt secrets in the database; if you\nrecreate the service, restore the same APP_KEY from a backup.\nLibraries: Put (or bind) your games under the library volume; inside\nGameyfin, add libraries whose paths are under `/library`\n(https://gameyfin.org/installation/getting-started/).\nPUID / PGID default to 1000; set them to your host user/group if file\npermissions on mounted volumes are wrong.\nOptional: for the bundled torrent plugin, publish host ports 6969 and 6881\non this service.\n", "install": [{"docker": {"image": "$IMAGE", "name": "gameyfin", "port": "$PORT:8080", "volumes": ["/opt/gameyfin/db", "/opt/gameyfin/data", "/opt/gameyfin/plugindata", "/opt/gameyfin/logs", "/library"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "APP_KEY is generated on deploy (32 random bytes, Base64). Do not change it\nafter data exists or the app cannot decrypt secrets in the database; if you\nrecreate the service, restore the same APP_KEY from a backup.\nLibraries: Put (or bind) your games under the library volume; inside\nGameyfin, add libraries whose paths are under `/library`\n(https://gameyfin.org/installation/getting-started/).\nPUID / PGID default to 1000; set them to your host user/group if file\npermissions on mounted volumes are wrong.\nOptional: for the bundled torrent plugin, publish host ports 6969 and 6881\non this service.\n"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('gatus', 'Gatus', 'Gatus is a self-hosted automated service health dashboard that monitors the uptime and performance of your services, APIs, and websites. The application provides a clean, modern web interface to visualize the health status of all your monitored endpoints in real-time. Gatus performs periodic health checks on configured endpoints, evaluating custom conditions like HTTP status codes, response body content, response times, and more. The dashboard displays detailed metrics including uptime percentages, average response times, and historical status data. With support for various alerting integrations including Discord, Slack, PagerDuty, and custom webhooks, Gatus can notify you immediately when services go down or fail health checks. The application supports complex condition evaluation using JSON path queries, pattern matching, and response time thresholds. Perfect for DevOps teams monitoring microservices infrastructure, system administrators tracking critical services, developers needing uptime monitoring for their applications, or anyone who wants a simple, self-hosted alternative to commercial monitoring services with complete control over their health checks and data.', 'monitoring', ARRAY['Monitoring', 'Health Check', 'Uptime', 'Dashboard', 'Self-Hosted', 'DevOps'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "twinproduction/gatus:v5.35.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Gatus", "version": "latest", "description": "Gatus is a self-hosted automated service health dashboard that monitors the uptime and performance of your services, APIs, and websites. The application provides a clean, modern web interface to visualize the health status of all your monitored endpoints in real-time. Gatus performs periodic health checks on configured endpoints, evaluating custom conditions like HTTP status codes, response body content, response times, and more. The dashboard displays detailed metrics including uptime percentages, average response times, and historical status data. With support for various alerting integrations including Discord, Slack, PagerDuty, and custom webhooks, Gatus can notify you immediately when services go down or fail health checks. The application supports complex condition evaluation using JSON path queries, pattern matching, and response time thresholds. Perfect for DevOps teams monitoring microservices infrastructure, system administrators tracking critical services, developers needing uptime monitoring for their applications, or anyone who wants a simple, self-hosted alternative to commercial monitoring services with complete control over their health checks and data.", "category": "monitoring", "tags": ["Monitoring", "Health Check", "Uptime", "Dashboard", "Self-Hosted", "DevOps"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "twinproduction/gatus:v5.35.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "GitHub", "url": "https://github.com/TwiN/gatus"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/twinproduction/gatus"}], "instructions": "you can modify the config from the config.yaml file in the storage section.", "install": [{"docker": {"image": "$IMAGE", "name": "gatus", "port": "$PORT:8080", "volumes": ["/config/config.yaml"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "you can modify the config from the config.yaml file in the storage section."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('gerrit', 'Gerrit', 'Gerrit is a web-based code review tool that integrates with Git. It provides a framework for reviewing code changes before they are merged into the codebase, making it an essential tool for collaborative software development.', 'git', ARRAY['Git', 'Code Review', 'Version Control', 'Collaboration', 'Development'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "gerritcodereview/gerrit:3.13.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Gerrit", "version": "latest", "description": "Gerrit is a web-based code review tool that integrates with Git. It provides a framework for reviewing code changes before they are merged into the codebase, making it an essential tool for collaborative software development.", "category": "git", "tags": ["Git", "Code Review", "Version Control", "Collaboration", "Development"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "gerritcodereview/gerrit:3.13.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Website", "url": "https://www.gerritcodereview.com/"}, {"label": "Documentation", "url": "https://gerrit-documentation.storage.googleapis.com/Documentation/3.7.1/index.html"}, {"label": "GitHub", "url": "https://github.com/GerritCodeReview/gerrit"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "gerrit", "port": "$PORT:8080", "volumes": ["/var/gerrit/git", "/var/gerrit/index", "/var/gerrit/cache"], "extra_ports": ["29418:29418"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('ghost-file-sharing', 'Ghost File Sharing', 'Our app is a powerful tool designed to streamline your workflow and enhance productivity. It allows you to easily find code, projects, and people on GitHub, making it simpler than ever to collaborate and contribute to open-source projects. With this app, you can stay updated with product updates, company news, and more by subscribing to our newsletter. It also offers a range of features designed to ensure the security of your work, making it a reliable choice for enterprises. Whether you''re a developer looking for a robust platform or a company seeking to leverage the power of open-source, our app is the perfect solution for you.', 'code-hosting', ARRAY['Code Hosting', 'Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/voxelin/ghost:stable"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Ghost File Sharing", "version": "latest", "description": "Our app is a powerful tool designed to streamline your workflow and enhance productivity. It allows you to easily find code, projects, and people on GitHub, making it simpler than ever to collaborate and contribute to open-source projects. With this app, you can stay updated with product updates, company news, and more by subscribing to our newsletter. It also offers a range of features designed to ensure the security of your work, making it a reliable choice for enterprises. Whether you're a developer looking for a robust platform or a company seeking to leverage the power of open-source, our app is the perfect solution for you.", "category": "code-hosting", "tags": ["Code Hosting", "Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/voxelin/ghost:stable"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Github", "url": "https://github.com/voxelin/gh0.st"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "ghost-file-sharing", "port": "$PORT:8080", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('ghost', 'Ghost', 'Ghost is a robust application designed for new-media creators looking to turn their audience into a business. It provides a suite of modern tools to build a website, publish engaging content, send newsletters, and offer paid subscriptions to members. Ghost allows you to launch your website with a selection of beautiful free themes and design settings that can be tweaked to match your brand and style. It also offers an editor built for professionals, with advanced workflows and a user-friendly interface. With Ghost, you can expand your story beyond words, incorporating image galleries, gifs, video, audio, and more into your content. The app also includes built-in newsletters, allowing you to deliver posts by email to your audience. Ghost simplifies the process of building an indie publication with memberships and subscriptions, with native signup forms that convert anonymous views into logged-in members. It also provides detailed engagement analytics to understand what content is getting the most attention and who your biggest fans are. Ghost also supports offers and promotions to entice new subscribers and grow your business.', 'cms', ARRAY['CMS', 'Blog', 'Business Apps'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghost:6.35.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 2368}}$JSON$::jsonb, $JSON${"metadata": {"name": "Ghost", "version": "latest", "description": "Ghost is a robust application designed for new-media creators looking to turn their audience into a business. It provides a suite of modern tools to build a website, publish engaging content, send newsletters, and offer paid subscriptions to members. Ghost allows you to launch your website with a selection of beautiful free themes and design settings that can be tweaked to match your brand and style. It also offers an editor built for professionals, with advanced workflows and a user-friendly interface. With Ghost, you can expand your story beyond words, incorporating image galleries, gifs, video, audio, and more into your content. The app also includes built-in newsletters, allowing you to deliver posts by email to your audience. Ghost simplifies the process of building an indie publication with memberships and subscriptions, with native signup forms that convert anonymous views into logged-in members. It also provides detailed engagement analytics to understand what content is getting the most attention and who your biggest fans are. Ghost also supports offers and promotions to entice new subscribers and grow your business.", "category": "cms", "tags": ["CMS", "Blog", "Business Apps"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghost:6.35.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 2368}}, "links": [{"label": "Website", "url": "https://ghost.org/"}, {"label": "Documentation", "url": "https://ghost.org/resources/"}, {"label": "Github", "url": "https://github.com/docker-library/ghost"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "ghost", "port": "$PORT:2368", "volumes": ["/var/lib/ghost/content"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('ghostfolio', 'Ghostfolio', 'Ghostfolio is a self-hosted wealth management application that allows users to track and analyze their investment portfolios. It provides insights into asset allocation, risk exposure, and financial growth, helping individuals make informed decisions about their finances. With Ghostfolio, users can connect their brokerage accounts, monitor their investments in real-time, and gain a comprehensive overview of their financial health. The application is accessible via a web interface and offers API support for integrations. Built for privacy and control, Ghostfolio is an excellent solution for self-hosted personal finance management.', 'investment-tracking', ARRAY['Investment Tracking', 'Personal Finance', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghostfolio/ghostfolio:2.255.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Ghostfolio", "version": "latest", "description": "Ghostfolio is a self-hosted wealth management application that allows users to track and analyze their investment portfolios. It provides insights into asset allocation, risk exposure, and financial growth, helping individuals make informed decisions about their finances. With Ghostfolio, users can connect their brokerage accounts, monitor their investments in real-time, and gain a comprehensive overview of their financial health. The application is accessible via a web interface and offers API support for integrations. Built for privacy and control, Ghostfolio is an excellent solution for self-hosted personal finance management.", "category": "investment-tracking", "tags": ["Investment Tracking", "Personal Finance", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghostfolio/ghostfolio:2.255.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Documentation", "url": "https://ghostfolio.dev/docs/"}, {"label": "Github", "url": "https://github.com/ghostfolio/ghostfolio"}], "instructions": "Click on get started, create account and save the generated token safely for logins.", "install": [{"docker": {"image": "$IMAGE", "name": "ghostfolio", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Click on get started, create account and save the generated token safely for logins."}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('ghstats', 'GHStats', 'GHStats is a self-hosted GitHub statistics and analytics tool that helps you track and visualize your GitHub repository metrics. Monitor stars, traffic, clones, views, and other important repository statistics over time with an intuitive web interface. The application collects and stores historical data from your GitHub repositories, allowing you to analyze trends and growth patterns that would otherwise be lost after GitHub''s 14-day statistics retention period. Perfect for developers, project maintainers, and organizations who want to maintain long-term analytics of their GitHub presence. GHStats requires a GitHub personal access token to fetch repository statistics and stores all collected data persistently for historical analysis and visualization.', 'github', ARRAY['GitHub', 'Analytics', 'Statistics', 'Monitoring', 'Self-Hosted', 'Repository', 'Tracking', 'Metrics'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/vladkens/ghstats:v0.8.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "GHStats", "version": "latest", "description": "GHStats is a self-hosted GitHub statistics and analytics tool that helps you track and visualize your GitHub repository metrics. Monitor stars, traffic, clones, views, and other important repository statistics over time with an intuitive web interface. The application collects and stores historical data from your GitHub repositories, allowing you to analyze trends and growth patterns that would otherwise be lost after GitHub's 14-day statistics retention period. Perfect for developers, project maintainers, and organizations who want to maintain long-term analytics of their GitHub presence. GHStats requires a GitHub personal access token to fetch repository statistics and stores all collected data persistently for historical analysis and visualization.", "category": "github", "tags": ["GitHub", "Analytics", "Statistics", "Monitoring", "Self-Hosted", "Repository", "Tracking", "Metrics"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/vladkens/ghstats:v0.8.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Documentation", "url": "https://github.com/vladkens/ghstats/blob/main/readme.md"}, {"label": "GitHub", "url": "https://github.com/vladkens/ghstats"}], "instructions": "Create a GitHub personal access token before deploying. Open https://github.com/settings/tokens and generate a classic token with at least the public_repo scope so GHStats can collect repository traffic data. If you want private repositories included, use repo scope and set GHS_INCLUDE_PRIVATE=true in a custom environment override. Paste the token into the GitHub Token field in this template. The app reads it as GITHUB_TOKEN and starts collecting metrics into /app/data. After deployment, open the assigned domain on port 8080. The first sync may take a little time depending on repository count, then dashboard history updates on the hourly scheduler.", "install": [{"docker": {"image": "$IMAGE", "name": "ghstats", "port": "$PORT:8080", "volumes": ["/app/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Create a GitHub personal access token before deploying. Open https://github.com/settings/tokens and generate a classic token with at least the public_repo scope so GHStats can collect repository traffic data. If you want private repositories included, use repo scope and set GHS_INCLUDE_PRIVATE=true in a custom environment override. Paste the token into the GitHub Token field in this template. The app reads it as GITHUB_TOKEN and starts collecting metrics into /app/data. After deployment, open the assigned domain on port 8080. The first sync may take a little time depending on repository count, then dashboard history updates on the hourly scheduler."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('gitea', 'Gitea', 'Gitea is a lightweight DevOps platform designed to streamline operations from planning to production. It enables the creation and management of repositories, exploration of commit history and code files, review and merging of code commits, and more. Gitea also supports standard Git features, including tags, cherry-picking, hooks, and integrated collaboration tools. It features an integrated CI/CD system, Gitea Actions, that is compatible with GitHub Actions. With Gitea, you can efficiently manage a project''s requirements, features, and bugs through issue tasks, labeling, and kanban project boards. It supports more than 20 different kinds of public or private package management. Gitea is an open-source project that accelerates development and collaboration, offering universal compatibility and flexible deployment options. It also provides a powerful built-in CI/CD system and is developed with a focus on security. Gitea can be tailored to your requirements and is integrated with your favorite tools to boost your workflow.', 'code-hosting', ARRAY['Code Hosting', 'Developer Tools', 'Documentation', 'Project Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "gitea/gitea:1.26.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 22}}$JSON$::jsonb, $JSON${"metadata": {"name": "Gitea", "version": "latest", "description": "Gitea is a lightweight DevOps platform designed to streamline operations from planning to production. It enables the creation and management of repositories, exploration of commit history and code files, review and merging of code commits, and more. Gitea also supports standard Git features, including tags, cherry-picking, hooks, and integrated collaboration tools. It features an integrated CI/CD system, Gitea Actions, that is compatible with GitHub Actions. With Gitea, you can efficiently manage a project's requirements, features, and bugs through issue tasks, labeling, and kanban project boards. It supports more than 20 different kinds of public or private package management. Gitea is an open-source project that accelerates development and collaboration, offering universal compatibility and flexible deployment options. It also provides a powerful built-in CI/CD system and is developed with a focus on security. Gitea can be tailored to your requirements and is integrated with your favorite tools to boost your workflow.", "category": "code-hosting", "tags": ["Code Hosting", "Developer Tools", "Documentation", "Project Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "gitea/gitea:1.26.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 22}}, "links": [{"label": "Website", "url": "https://gitea.io/en-us/"}, {"label": "Documentation", "url": "https://docs.gitea.io/en-us/"}, {"label": "Github", "url": "https://github.com/go-gitea/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "gitea", "port": "$PORT:22", "volumes": ["/data", "/etc/timezone", "/etc/localtime"], "extra_ports": ["2222:2222", "3000:3000"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('github-actions-runner', 'Github Actions Runner', 'A GitHub Actions runner is a service that runs the jobs defined in your GitHub workflows.
INSERT INTO recipes VALUES ('github-desktop', 'Github Desktop', 'Github Desktop is an open-source, Electron-based application that simplifies the way you interact with GitHub. Written in TypeScript and using React, this app provides a user-friendly interface for managing your GitHub repositories. It allows you to access your GitHub account, manage your repositories, make changes, and track updates, all from the convenience of your desktop. The app is accessible via http://yourhost:3000/ or https://yourhost:3001/. It supports multiple architectures and can be easily deployed using Docker. Please note that this app requires specific environment variables and run configurations for optimal functionality.', 'developer-tools', ARRAY['Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/github-desktop:3.4.13"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Github Desktop", "version": "latest", "description": "Github Desktop is an open-source, Electron-based application that simplifies the way you interact with GitHub. Written in TypeScript and using React, this app provides a user-friendly interface for managing your GitHub repositories. It allows you to access your GitHub account, manage your repositories, make changes, and track updates, all from the convenience of your desktop. The app is accessible via http://yourhost:3000/ or https://yourhost:3001/. It supports multiple architectures and can be easily deployed using Docker. Please note that this app requires specific environment variables and run configurations for optimal functionality.", "category": "developer-tools", "tags": ["Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/github-desktop:3.4.13"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Documentation", "url": "https://docs.linuxserver.io/images/docker-github-desktop"}, {"label": "Github", "url": "https://github.com/desktop/desktop"}], "instructions": "use abc:abc to login. To access the login interface, add ?login=true to your URL.", "install": [{"docker": {"image": "$IMAGE", "name": "github-desktop", "port": "$PORT:3000", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "use abc:abc to login. To access the login interface, add ?login=true to your URL."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('gladys', 'Gladys Assistant', 'Gladys Assistant is a privacy-first, open-source home automation platform that allows you to control and automate your smart home devices. Built with Node.js, Gladys provides a comprehensive solution for managing IoT devices, creating automation scenarios, and monitoring your home environment. The system supports a wide range of devices including Zigbee, Z-Wave, Bluetooth, WiFi, and more. Gladys stores all data locally in SQLite, ensuring your home automation data remains private. Perfect for home automation enthusiasts looking for a self-hosted alternative to commercial smart home platforms.', 'home-automation', ARRAY['Home Automation', 'IoT', 'Smart Home', 'Self-Hosted', 'Privacy', 'Zigbee', 'Z-Wave', 'Docker'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "gladysassistant/gladys:sha-569dfde"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Gladys Assistant", "version": "latest", "description": "Gladys Assistant is a privacy-first, open-source home automation platform that allows you to control and automate your smart home devices. Built with Node.js, Gladys provides a comprehensive solution for managing IoT devices, creating automation scenarios, and monitoring your home environment. The system supports a wide range of devices including Zigbee, Z-Wave, Bluetooth, WiFi, and more. Gladys stores all data locally in SQLite, ensuring your home automation data remains private. Perfect for home automation enthusiasts looking for a self-hosted alternative to commercial smart home platforms.", "category": "home-automation", "tags": ["Home Automation", "IoT", "Smart Home", "Self-Hosted", "Privacy", "Zigbee", "Z-Wave", "Docker"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "gladysassistant/gladys:sha-569dfde"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Website", "url": "https://gladysassistant.com"}, {"label": "GitHub", "url": "https://github.com/GladysAssistant/Gladys"}, {"label": "Documentation", "url": "https://gladysassistant.com/docs"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "gladys", "port": "$PORT:8080", "volumes": ["/var/run/docker.sock", "/var/lib/gladysassistant", "/dev", "/run/udev"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('glance', 'Glance', 'Glance is a fast and lightweight self-hosted dashboard that allows you to monitor various real-time data sources through customizable widgets. With support for RSS feeds, market prices, YouTube uploads, Twitch streams, weather forecasts, server stats, Docker container status, and more, Glance provides a centralized hub for tracking essential information. The dashboard is fully themeable, optimized for mobile devices, and highly configurable through YAML-based settings.', 'dashboard', ARRAY['Dashboard', 'Productivity', 'Self-Hosted', 'Customizable', 'Widgets'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "glanceapp/glance:v0.8.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Glance", "version": "latest", "description": "Glance is a fast and lightweight self-hosted dashboard that allows you to monitor various real-time data sources through customizable widgets. With support for RSS feeds, market prices, YouTube uploads, Twitch streams, weather forecasts, server stats, Docker container status, and more, Glance provides a centralized hub for tracking essential information. The dashboard is fully themeable, optimized for mobile devices, and highly configurable through YAML-based settings.", "category": "dashboard", "tags": ["Dashboard", "Productivity", "Self-Hosted", "Customizable", "Widgets"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "glanceapp/glance:v0.8.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Documentation", "url": "https://github.com/glanceapp/glance/blob/main/docs/configuration.md"}, {"label": "Github", "url": "https://github.com/glanceapp/glance"}], "instructions": "You can edit the Yaml configuration as per your needs.", "install": [{"docker": {"image": "$IMAGE", "name": "glance", "port": "$PORT:8080", "volumes": ["/app/config", "/app/config/glance.yml"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "You can edit the Yaml configuration as per your needs."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('glances', 'Glances', 'Glances is a cross-platform, real-time system monitoring tool designed to offer a unified view of your system''s performance and health. It provides an intuitive interface that displays critical information, including CPU usage, memory, disk I/O, network activity, and more. Built to work seamlessly on Linux, macOS, Windows, and ARM-based systems, Glances is highly extensible with plugins and supports remote monitoring via a web-based UI or API. With its open-source foundation, Glances ensures transparency and flexibility, making it a perfect choice for individuals and teams looking for a lightweight yet powerful monitoring solution.', 'system-monitoring', ARRAY['System Monitoring', 'Real-Time Metrics', 'Open Source', 'Cross-Platform', 'Extensible'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "nicolargo/glances:4.5.0.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 61208}}$JSON$::jsonb, $JSON${"metadata": {"name": "Glances", "version": "latest", "description": "Glances is a cross-platform, real-time system monitoring tool designed to offer a unified view of your system's performance and health. It provides an intuitive interface that displays critical information, including CPU usage, memory, disk I/O, network activity, and more. Built to work seamlessly on Linux, macOS, Windows, and ARM-based systems, Glances is highly extensible with plugins and supports remote monitoring via a web-based UI or API. With its open-source foundation, Glances ensures transparency and flexibility, making it a perfect choice for individuals and teams looking for a lightweight yet powerful monitoring solution.", "category": "system-monitoring", "tags": ["System Monitoring", "Real-Time Metrics", "Open Source", "Cross-Platform", "Extensible"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "nicolargo/glances:4.5.0.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 61208}}, "links": [{"label": "Website", "url": "https://nicolargo.github.io/glances/"}, {"label": "Documentation", "url": "https://glances.readthedocs.io/en/stable/"}, {"label": "GitHub", "url": "https://github.com/nicolargo/glances"}], "instructions": "To use Glances with Podman, you can mount a bind volume \"/run/user/1000/podman/podman.sock:/run/user/1000/podman/podman.sock\".", "install": [{"docker": {"image": "$IMAGE", "name": "glances", "port": "$PORT:61208", "volumes": ["/var/run/docker.sock"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "To use Glances with Podman, you can mount a bind volume \"/run/user/1000/podman/podman.sock:/run/user/1000/podman/podman.sock\"."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('glasskeep', 'Glass Keep', 'Glass Keep is a lightweight, self-hosted note-taking and organization application designed for personal knowledge management. It provides a clean, intuitive interface for creating, organizing, and managing notes, thoughts, and ideas. Glass Keep features markdown support, rich text editing, categories, tags, and powerful search capabilities to help you find information quickly. Built with Node.js and SQLite, it offers fast performance and easy deployment without requiring complex database setup. All your notes are stored locally in a SQLite database, ensuring privacy and complete control over your data. Perfect for individuals who want a simple, fast, and private note-taking solution without the complexity of larger systems.', 'notes', ARRAY['Notes', 'Knowledge Management', 'Note Taking', 'Markdown', 'SQLite'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "nikunjsingh/glass-keep:v20260114-1008"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Glass Keep", "version": "latest", "description": "Glass Keep is a lightweight, self-hosted note-taking and organization application designed for personal knowledge management. It provides a clean, intuitive interface for creating, organizing, and managing notes, thoughts, and ideas. Glass Keep features markdown support, rich text editing, categories, tags, and powerful search capabilities to help you find information quickly. Built with Node.js and SQLite, it offers fast performance and easy deployment without requiring complex database setup. All your notes are stored locally in a SQLite database, ensuring privacy and complete control over your data. Perfect for individuals who want a simple, fast, and private note-taking solution without the complexity of larger systems.", "category": "notes", "tags": ["Notes", "Knowledge Management", "Note Taking", "Markdown", "SQLite"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "nikunjsingh/glass-keep:v20260114-1008"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Website", "url": "https://github.com/nikunjsingh93/react-glass-keep"}, {"label": "Documentation", "url": "https://github.com/nikunjsingh93/react-glass-keep#readme"}, {"label": "GitHub", "url": "https://github.com/nikunjsingh93/react-glass-keep"}], "instructions": "Open the web app on your assigned domain. The application uses the ADMIN_EMAILS value from this template to mark admin users. This template uses the Docker image name recommended by the upstream README and pins it to a static version tag instead of latest.For a fresh deployment, the default admin username is admin and the default password is admin. If you set the Admin Email/Username field before first start, that value is used to auto-promote the corresponding admin user(s). Create or manage users using the admin route at https://<your-domain>/#/admin. After login you can change admin settings in the Admin Panel and create additional users as needed.", "install": [{"docker": {"image": "$IMAGE", "name": "glasskeep", "port": "$PORT:8080", "volumes": ["/app/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Open the web app on your assigned domain. The application uses the ADMIN_EMAILS value from this template to mark admin users. This template uses the Docker image name recommended by the upstream README and pins it to a static version tag instead of latest.For a fresh deployment, the default admin username is admin and the default password is admin. If you set the Admin Email/Username field before first start, that value is used to auto-promote the corresponding admin user(s). Create or manage users using the admin route at https://<your-domain>/#/admin. After login you can change admin settings in the Admin Panel and create additional users as needed."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('glitchtip', 'GlitchTip', 'GlitchTip is a simple, open-source error tracking application designed to collect, organize, and alert you about every error from your project in real time. It allows you to monitor your software''s performance, track errors, and check your site''s uptime all in one place. GlitchTip is compatible with Sentry client SDKs, offering a more straightforward operation. It provides a comprehensive error tracking system, reporting your website or application''s exceptions, log messages, Content Security Policy violations, and more. With GlitchTip, you can also monitor your application''s performance, identifying slow web requests, database calls, and other transactions. Additionally, it offers uptime monitoring, pinging your site and alerting you when it''s not responding. GlitchTip is the perfect choice for those who value simplicity, affordability, and the freedom provided by open source.', 'monitoring', ARRAY['Monitoring', 'Developer Tools', 'Logging'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "glitchtip/glitchtip:v6.0.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "GlitchTip", "version": "latest", "description": "GlitchTip is a simple, open-source error tracking application designed to collect, organize, and alert you about every error from your project in real time. It allows you to monitor your software's performance, track errors, and check your site's uptime all in one place. GlitchTip is compatible with Sentry client SDKs, offering a more straightforward operation. It provides a comprehensive error tracking system, reporting your website or application's exceptions, log messages, Content Security Policy violations, and more. With GlitchTip, you can also monitor your application's performance, identifying slow web requests, database calls, and other transactions. Additionally, it offers uptime monitoring, pinging your site and alerting you when it's not responding. GlitchTip is the perfect choice for those who value simplicity, affordability, and the freedom provided by open source.", "category": "monitoring", "tags": ["Monitoring", "Developer Tools", "Logging"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "glitchtip/glitchtip:v6.0.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://glitchtip.com/"}, {"label": "Gitlab", "url": "https://gitlab.com/glitchtip"}, {"label": "Docker", "url": "https://hub.docker.com/r/glitchtip/glitchtip"}, {"label": "Documentation", "url": "https://glitchtip.com/documentation"}], "instructions": "To create an admin user, run the command ./manage.py createsuperuser", "install": [{"docker": {"image": "$IMAGE", "name": "glitchtip", "port": "$PORT:80", "volumes": ["/code/uploads", "/code/uploads"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "To create an admin user, run the command ./manage.py createsuperuser"}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('glpi', 'GLPI', 'GLPI (Gestionnaire Libre de Parc Informatique) is a powerful IT asset management and help desk software designed to streamline IT operations. It offers features like inventory management, ticketing, and reporting, making it an ideal solution for IT teams. With its robust plugin support and user-friendly interface, GLPI provides extensive customization options to adapt to various organizational needs. This containerized version is based on Docker Baseimage KasmVNC, ensuring smooth multi-platform support and flexible deployment.', 'it-asset-management', ARRAY['IT Asset Management', 'Help Desk', 'Ticketing', 'Customization', 'Reporting', 'Plugins', 'IT Operations'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "diouxx/glpi:9.1.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "GLPI", "version": "latest", "description": "GLPI (Gestionnaire Libre de Parc Informatique) is a powerful IT asset management and help desk software designed to streamline IT operations. It offers features like inventory management, ticketing, and reporting, making it an ideal solution for IT teams. With its robust plugin support and user-friendly interface, GLPI provides extensive customization options to adapt to various organizational needs. This containerized version is based on Docker Baseimage KasmVNC, ensuring smooth multi-platform support and flexible deployment.", "category": "it-asset-management", "tags": ["IT Asset Management", "Help Desk", "Ticketing", "Customization", "Reporting", "Plugins", "IT Operations"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "diouxx/glpi:9.1.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Documentation", "url": "https://glpi-project.org/documentation/"}, {"label": "Github", "url": "https://github.com/glpi-project/glpi"}], "instructions": "Default login is; glpi/glpi, and other credentials can be found on the Github repository or during the installation wizard.", "install": [{"docker": {"image": "$IMAGE", "name": "glpi", "port": "$PORT:80", "volumes": ["/var/www/html/glpi"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Default login is; glpi/glpi, and other credentials can be found on the Github repository or during the installation wizard."}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('gmail-cleaner', 'Gmail Cleaner', 'Gmail Cleaner is a privacy-focused self-hosted tool to bulk unsubscribe, delete, archive, and mark Gmail messages as read by sender. It runs locally with your own Google OAuth credentials and keeps auth tokens in persistent storage.', 'gmail', ARRAY['Gmail', 'Email', 'Cleanup', 'Privacy', 'Automation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/gururagavendra/gmail-cleaner:v1.3.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8766}}$JSON$::jsonb, $JSON${"metadata": {"name": "Gmail Cleaner", "version": "latest", "description": "Gmail Cleaner is a privacy-focused self-hosted tool to bulk unsubscribe, delete, archive, and mark Gmail messages as read by sender. It runs locally with your own Google OAuth credentials and keeps auth tokens in persistent storage.", "category": "gmail", "tags": ["Gmail", "Email", "Cleanup", "Privacy", "Automation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/gururagavendra/gmail-cleaner:v1.3.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8766}}, "links": [{"label": "Documentation", "url": "https://github.com/Gururagavendra/gmail-cleaner#readme"}, {"label": "GitHub", "url": "https://github.com/gururagavendra/gmail-cleaner"}, {"label": "Setup video", "url": "https://youtu.be/CmOWn8Tm5ZE"}, {"label": "Container registry", "url": "https://github.com/gururagavendra/gmail-cleaner/pkgs/container/gmail-cleaner"}], "instructions": "Paste your downloaded Google OAuth client JSON into Credentials JSON before deploying. In Google Cloud Console, add an Authorized redirect URI that uses your OAuth host and external OAuth port (for example, https://your-domain/). After deploy, open the app domain, click Sign In, and complete the OAuth flow.", "install": [{"docker": {"image": "$IMAGE", "name": "gmail-cleaner", "port": "$PORT:8766", "volumes": ["/app/credentials.json", "/app/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Paste your downloaded Google OAuth client JSON into Credentials JSON before deploying. In Google Cloud Console, add an Authorized redirect URI that uses your OAuth host and external OAuth port (for example, https://your-domain/). After deploy, open the app domain, click Sign In, and complete the OAuth flow."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('goaway', 'Goaway', 'Goaway is a DNS service that provides filtering and blocking capabilities for unwanted content. It acts as a DNS server that can block malicious domains, advertisements, and other unwanted traffic while providing a clean web interface for management.', 'dns', ARRAY['DNS', 'Network Security', 'Ad Blocking', 'Content Filtering', 'Privacy'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "pommee/goaway:0.57.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 53}}$JSON$::jsonb, $JSON${"metadata": {"name": "Goaway", "version": "latest", "description": "Goaway is a DNS service that provides filtering and blocking capabilities for unwanted content. It acts as a DNS server that can block malicious domains, advertisements, and other unwanted traffic while providing a clean web interface for management.", "category": "dns", "tags": ["DNS", "Network Security", "Ad Blocking", "Content Filtering", "Privacy"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "pommee/goaway:0.57.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 53}}, "links": [{"label": "Website", "url": "https://pommee.github.io/goaway/"}, {"label": "Documentation", "url": "https://pommee.github.io/goaway/getting-started/"}, {"label": "GitHub", "url": "https://github.com/pommee/goaway"}], "instructions": "The login credentials are user = admin and password is generated on the startup logs of GoAway inside overview section. In order to mount the DNS port, you have to make sure your host machine has the port 53 not being used by any other service.", "install": [{"docker": {"image": "$IMAGE", "name": "goaway", "port": "$PORT:53", "volumes": ["/home/appuser"], "extra_ports": ["8080:8080"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "The login credentials are user = admin and password is generated on the startup logs of GoAway inside overview section. In order to mount the DNS port, you have to make sure your host machine has the port 53 not being used by any other service."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('gocd', 'GoCD', 'GoCD is a continuous delivery and release automation server. It helps you automate and streamline your build-test-release cycle, making it easy to manage complex deployment pipelines. GoCD provides end-to-end visibility and traceability from commit to deployment, with the ability to model complex workflows and dependencies with ease. It supports parallel and sequential execution, and provides powerful value stream visualization to help you optimize your delivery process.', 'ci/cd', ARRAY['CI/CD', 'Continuous Delivery', 'DevOps', 'Automation', 'Pipeline Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "gocd/gocd-server:v25.4.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8153}}$JSON$::jsonb, $JSON${"metadata": {"name": "GoCD", "version": "latest", "description": "GoCD is a continuous delivery and release automation server. It helps you automate and streamline your build-test-release cycle, making it easy to manage complex deployment pipelines. GoCD provides end-to-end visibility and traceability from commit to deployment, with the ability to model complex workflows and dependencies with ease. It supports parallel and sequential execution, and provides powerful value stream visualization to help you optimize your delivery process.", "category": "ci/cd", "tags": ["CI/CD", "Continuous Delivery", "DevOps", "Automation", "Pipeline Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "gocd/gocd-server:v25.4.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8153}}, "links": [{"label": "Website", "url": "https://www.gocd.org/"}, {"label": "Documentation", "url": "https://docs.gocd.org/"}, {"label": "Github", "url": "https://github.com/gocd/gocd"}], "instructions": "Open GoCD from your domain, complete the first-time admin login flow, then create your initial pipeline and connect your source repository and build agents.", "install": [{"docker": {"image": "$IMAGE", "name": "gocd", "port": "$PORT:8153", "volumes": ["/godata", "/home/go"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Open GoCD from your domain, complete the first-time admin login flow, then create your initial pipeline and connect your source repository and build agents."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('goclaw', 'GoClaw', 'Enterprise AI agent platform with teams, delegation & orchestration. Single Go binary, 13+ LLM providers, 10+ channels, browser automation, and memory system.', 'ai', ARRAY['AI', 'Gateway', 'Multi-Agent', 'LLM'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/nextlevelbuilder/goclaw:v3.11.3-full"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "GoClaw", "version": "latest", "description": "Enterprise AI agent platform with teams, delegation & orchestration. Single Go binary, 13+ LLM providers, 10+ channels, browser automation, and memory system.", "category": "ai", "tags": ["AI", "Gateway", "Multi-Agent", "LLM"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/nextlevelbuilder/goclaw:v3.11.3-full"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://goclaw.sh"}, {"label": "Documentation", "url": "https://docs.goclaw.sh"}, {"label": "Github", "url": "https://github.com/nextlevelbuilder/goclaw"}], "instructions": "After installation, access the web dashboard via your configured domain.\nTo add more LLM API keys (e.g., Anthropic, Groq), edit the environment variables of the GoClaw App Service.\nSecure tokens like the Gateway Token and Encryption Key are auto-generated.\n", "install": [{"docker": {"image": "$IMAGE", "name": "goclaw", "port": "$PORT:80", "volumes": ["/app/data", "/app/workspace", "/app/skills", "/etc/nginx/conf.d/default.conf"], "extra_ports": ["9222:9222"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After installation, access the web dashboard via your configured domain.\nTo add more LLM API keys (e.g., Anthropic, Groq), edit the environment variables of the GoClaw App Service.\nSecure tokens like the Gateway Token and Encryption Key are auto-generated.\n"}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('gogs', 'Gogs', 'Gogs is a self-hosted Git service designed to be simple, stable, and extensible. It allows you to set up your own Git service in the most painless way possible. The app is built with Go, enabling it to run on all platforms that Go supports, including Linux, macOS, Windows, and ARM-based systems. Gogs is lightweight and has low minimal requirements, making it possible to run even on an inexpensive Raspberry Pi. It offers a range of features including user dashboard, access to repositories via SSH, HTTP and HTTPS protocols, repository and organization management, and more. Gogs is 100% open source and free of charge, with all source code available under the MIT License.', 'code-hosting', ARRAY['Code Hosting'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "gogs/gogs:0.14.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 22}}$JSON$::jsonb, $JSON${"metadata": {"name": "Gogs", "version": "latest", "description": "Gogs is a self-hosted Git service designed to be simple, stable, and extensible. It allows you to set up your own Git service in the most painless way possible. The app is built with Go, enabling it to run on all platforms that Go supports, including Linux, macOS, Windows, and ARM-based systems. Gogs is lightweight and has low minimal requirements, making it possible to run even on an inexpensive Raspberry Pi. It offers a range of features including user dashboard, access to repositories via SSH, HTTP and HTTPS protocols, repository and organization management, and more. Gogs is 100% open source and free of charge, with all source code available under the MIT License.", "category": "code-hosting", "tags": ["Code Hosting"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "gogs/gogs:0.14.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 22}}, "links": [{"label": "Website", "url": "https://gogs.io/"}, {"label": "Documentation", "url": "https://gogs.io/docs"}, {"label": "Github", "url": "https://github.com/gogs/gogs"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "gogs", "port": "$PORT:22", "volumes": ["/data", "/backup"], "extra_ports": ["3000:3000"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('gokapi', 'Gokapi', 'Gokapi is a lightweight file-sharing server that allows you to easily upload and share files with others. It provides a simple web interface for file uploads, generates shareable links, and supports features like password protection, automatic file expiration, and customizable download limits.', 'file-sharing', ARRAY['File Sharing', 'Upload Server', 'File Transfer', 'Temporary Storage'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "f0rc3/gokapi:v2.2.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 53842}}$JSON$::jsonb, $JSON${"metadata": {"name": "Gokapi", "version": "latest", "description": "Gokapi is a lightweight file-sharing server that allows you to easily upload and share files with others. It provides a simple web interface for file uploads, generates shareable links, and supports features like password protection, automatic file expiration, and customizable download limits.", "category": "file-sharing", "tags": ["File Sharing", "Upload Server", "File Transfer", "Temporary Storage"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "f0rc3/gokapi:v2.2.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 53842}}, "links": [{"label": "Github", "url": "https://github.com/Forceu/Gokapi"}, {"label": "Documentation", "url": "https://gokapi.readthedocs.io/en/latest/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "gokapi", "port": "$PORT:53842", "volumes": ["/app/config", "/app/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('gonic', 'Gonic', 'Gonic is a music streaming server / subsonic server API implementation, written in Go. It provides a simple and efficient way to stream your music collection through a web interface or compatible clients. Gonic supports various audio formats and offers features like transcoding, cover art, and playlist management.', 'media', ARRAY['Media', 'Music', 'Streaming', 'Subsonic', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "sentriz/gonic:4b3721b"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Gonic", "version": "latest", "description": "Gonic is a music streaming server / subsonic server API implementation, written in Go. It provides a simple and efficient way to stream your music collection through a web interface or compatible clients. Gonic supports various audio formats and offers features like transcoding, cover art, and playlist management.", "category": "media", "tags": ["Media", "Music", "Streaming", "Subsonic", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "sentriz/gonic:4b3721b"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Documentation", "url": "https://github.com/sentriz/gonic/wiki"}, {"label": "Github", "url": "https://github.com/sentriz/gonic"}, {"label": "DockerHub", "url": "https://hub.docker.com/r/sentriz/gonic"}], "instructions": "Login credentials are admin/admin", "install": [{"docker": {"image": "$IMAGE", "name": "gonic", "port": "$PORT:80", "volumes": ["/data", "/cache", "/music", "/podcasts", "/playlists"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Login credentials are admin/admin"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('gopeed', 'GoPeed', 'GoPeed is a high-performance download manager that supports HTTP, HTTPS, FTP, BitTorrent, and other protocols. It features a modern web interface and supports multiple download task.', 'download-manager', ARRAY['Download Manager', 'File Transfer', 'Self-hosted', 'Open Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "liwei2633/gopeed:v1.9.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9999}}$JSON$::jsonb, $JSON${"metadata": {"name": "GoPeed", "version": "latest", "description": "GoPeed is a high-performance download manager that supports HTTP, HTTPS, FTP, BitTorrent, and other protocols. It features a modern web interface and supports multiple download task.", "category": "download-manager", "tags": ["Download Manager", "File Transfer", "Self-hosted", "Open Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "liwei2633/gopeed:v1.9.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9999}}, "links": [{"label": "Website", "url": "https://gopeed.com/"}, {"label": "GitHub", "url": "https://github.com/GopeedLab/gopeed"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/liwei2633/gopeed"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "gopeed", "port": "$PORT:9999", "volumes": ["/root/Downloads"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('gotenberg', 'Gotenberg', 'Gotenberg is a Docker-powered stateless API designed to handle PDF files. It offers a developer-friendly interface to interact with robust tools like Chromium and LibreOffice, enabling the conversion of various document formats such as HTML, Markdown, Word, Excel, and more into PDF files. The app also supports an asynchronous workflow with a webhook feature, allowing you to upload the output file to your preferred destination. Gotenberg is a modular platform, meaning you can customize each module according to your needs. Additionally, it provides the option to build your own Docker image by adding new tools and creating modules that offer new routes to the API.', 'developer-tools', ARRAY['Developer Tools', 'Documents', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "gotenberg/gotenberg:8.32.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Gotenberg", "version": "latest", "description": "Gotenberg is a Docker-powered stateless API designed to handle PDF files. It offers a developer-friendly interface to interact with robust tools like Chromium and LibreOffice, enabling the conversion of various document formats such as HTML, Markdown, Word, Excel, and more into PDF files. The app also supports an asynchronous workflow with a webhook feature, allowing you to upload the output file to your preferred destination. Gotenberg is a modular platform, meaning you can customize each module according to your needs. Additionally, it provides the option to build your own Docker image by adding new tools and creating modules that offer new routes to the API.", "category": "developer-tools", "tags": ["Developer Tools", "Documents", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "gotenberg/gotenberg:8.32.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://gotenberg.dev/"}, {"label": "Documentation", "url": "https://gotenberg.dev/docs/get-started/live-demo"}, {"label": "Github", "url": "https://github.com/gotenberg/gotenberg"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "gotenberg", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('gotify', 'Gotify', 'Gotify is a simple, self-hosted server for sending and receiving messages. It is designed with a user-friendly interface and a straightforward API, making it easy to use across different platforms. The core of Gotify is the server, which features a WebUI and functionality for sending messages via a REST-API, subscribing/receiving messages via a web socket connection, and managing users, clients, and applications. Gotify also includes an Android client for subscribing to the message stream of the server, creating push notifications for newly received messages. Additionally, there is a command line client for pushing messages to the server. All these features make Gotify a versatile tool for managing and exchanging messages while maintaining control over your data.', 'communication', ARRAY['Communication', 'Push Notifications', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "gotify/server:2.9.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Gotify", "version": "latest", "description": "Gotify is a simple, self-hosted server for sending and receiving messages. It is designed with a user-friendly interface and a straightforward API, making it easy to use across different platforms. The core of Gotify is the server, which features a WebUI and functionality for sending messages via a REST-API, subscribing/receiving messages via a web socket connection, and managing users, clients, and applications. Gotify also includes an Android client for subscribing to the message stream of the server, creating push notifications for newly received messages. Additionally, there is a command line client for pushing messages to the server. All these features make Gotify a versatile tool for managing and exchanging messages while maintaining control over your data.", "category": "communication", "tags": ["Communication", "Push Notifications", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "gotify/server:2.9.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://gotify.net/"}, {"label": "Documentation", "url": "https://gotify.net/docs/"}, {"label": "Github", "url": "https://github.com/gotify"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "gotify", "port": "$PORT:80", "volumes": ["/app/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('gotosocial', 'GoToSocial', 'GoToSocial is a lightweight, customizable, and safety-focused social network server that provides a fun and fast entryway into the Fediverse. It is written in Golang and allows you to keep in touch with friends, post, read, and share images and articles without being tracked or advertised to. If you''ve used platforms like Twitter or Tumblr, GoToSocial will feel familiar. You can follow people, have followers, make posts that others can favorite, reply to, and share, and scroll through posts from people you follow using a timeline. You can write long or short posts, post images, and even block people or limit unwanted interactions by posting just to your friends. GoToSocial is not designed for influencers with tens of thousands of followers, nor is it designed to be addictive. Your timeline and experience are shaped by who you follow and how you interact with people, not by engagement metrics. GoToSocial is ideal for small or single-user instances running on low-powered devices, like single-board computers or old laptops repurposed as home servers. It is simple to install and maintain, and prioritizes good security and sensible defaults.', 'social-networking', ARRAY['Social Networking'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "superseriousbusiness/gotosocial:0.21.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "GoToSocial", "version": "latest", "description": "GoToSocial is a lightweight, customizable, and safety-focused social network server that provides a fun and fast entryway into the Fediverse. It is written in Golang and allows you to keep in touch with friends, post, read, and share images and articles without being tracked or advertised to. If you've used platforms like Twitter or Tumblr, GoToSocial will feel familiar. You can follow people, have followers, make posts that others can favorite, reply to, and share, and scroll through posts from people you follow using a timeline. You can write long or short posts, post images, and even block people or limit unwanted interactions by posting just to your friends. GoToSocial is not designed for influencers with tens of thousands of followers, nor is it designed to be addictive. Your timeline and experience are shaped by who you follow and how you interact with people, not by engagement metrics. GoToSocial is ideal for small or single-user instances running on low-powered devices, like single-board computers or old laptops repurposed as home servers. It is simple to install and maintain, and prioritizes good security and sensible defaults.", "category": "social-networking", "tags": ["Social Networking"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "superseriousbusiness/gotosocial:0.21.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Website", "url": "https://gotosocial.org/"}, {"label": "Documentation", "url": "https://docs.gotosocial.org/en/latest/"}, {"label": "Github", "url": "https://github.com/superseriousbusiness/gotosocial/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "gotosocial", "port": "$PORT:8080", "volumes": ["/gotosocial/storage"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('grafana-otel-lgtm', 'Grafana OTEL LGTM', 'Grafana OTEL LGTM is an all-in-one OpenTelemetry backend bundled into a single Docker image. It includes the OpenTelemetry Collector, Prometheus for metrics, Grafana Loki for logs, Grafana Tempo for traces, Grafana Pyroscope for application profiles, and Grafana for unified visualization. The collector automatically routes telemetry signals to the correct backend — metrics to Prometheus, logs to Loki, traces to Tempo, and profiles to Pyroscope. It works out of the box with OpenTelemetry''s default settings, so applications instrumented with any OpenTelemetry SDK can send data immediately. Optional eBPF auto-instrumentation (OBI) can generate traces and RED metrics for HTTP/gRPC services with zero code changes.', 'observability', ARRAY['Observability', 'OpenTelemetry', 'Grafana', 'Prometheus', 'Monitoring', 'Logging', 'Tracing'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "grafana/otel-lgtm:0.27.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Grafana OTEL LGTM", "version": "latest", "description": "Grafana OTEL LGTM is an all-in-one OpenTelemetry backend bundled into a single Docker image. It includes the OpenTelemetry Collector, Prometheus for metrics, Grafana Loki for logs, Grafana Tempo for traces, Grafana Pyroscope for application profiles, and Grafana for unified visualization. The collector automatically routes telemetry signals to the correct backend \u2014 metrics to Prometheus, logs to Loki, traces to Tempo, and profiles to Pyroscope. It works out of the box with OpenTelemetry's default settings, so applications instrumented with any OpenTelemetry SDK can send data immediately. Optional eBPF auto-instrumentation (OBI) can generate traces and RED metrics for HTTP/gRPC services with zero code changes.", "category": "observability", "tags": ["Observability", "OpenTelemetry", "Grafana", "Prometheus", "Monitoring", "Logging", "Tracing"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "grafana/otel-lgtm:0.27.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://grafana.com/"}, {"label": "GitHub", "url": "https://github.com/grafana/docker-otel-lgtm"}, {"label": "Documentation", "url": "https://grafana.com/docs/opentelemetry/docker-lgtm"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/grafana/otel-lgtm"}], "instructions": "After deployment, access the Grafana dashboard via the service domain. \nLog in with the default credentials: username \"admin\", password\n\"admin\". All data sources (Prometheus, Loki, Tempo, Pyroscope) are\npre-configured. Point your OpenTelemetry-instrumented applications to the\nOTLP endpoints \u2014 port 4317 for gRPC and port 4318 for HTTP. No additional\nconfiguration is needed; the image works with OpenTelemetry defaults.\n", "install": [{"docker": {"image": "$IMAGE", "name": "grafana-otel-lgtm", "port": "$PORT:3000", "volumes": ["/data"], "extra_ports": ["4317:4317", "4318:4318"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deployment, access the Grafana dashboard via the service domain. \nLog in with the default credentials: username \"admin\", password\n\"admin\". All data sources (Prometheus, Loki, Tempo, Pyroscope) are\npre-configured. Point your OpenTelemetry-instrumented applications to the\nOTLP endpoints \u2014 port 4317 for gRPC and port 4318 for HTTP. No additional\nconfiguration is needed; the image works with OpenTelemetry defaults.\n"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('grafana', 'Grafana', 'Grafana is a powerful, open-source platform designed to provide comprehensive metrics, logs, and trace data visualization. It allows users to query, visualize, and alert on their data, offering high-scale distributed tracing and scalable, performant metrics. The app also includes features for incident response and management, performance testing, and on-call management. Grafana can connect to various data sources and applications, providing operational dashboards for your data anywhere. It also offers a free forever plan, allowing users to monitor their data with 10,000 series metrics, 50 GB of logs, 50 GB of traces, and 500 VUh of k6 testing. Grafana is a versatile tool for anyone looking to gain insights from their data.', 'monitoring', ARRAY['Monitoring', 'Logs', 'Metrics', 'Traces'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "grafana/grafana-oss:13.0.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Grafana", "version": "latest", "description": "Grafana is a powerful, open-source platform designed to provide comprehensive metrics, logs, and trace data visualization. It allows users to query, visualize, and alert on their data, offering high-scale distributed tracing and scalable, performant metrics. The app also includes features for incident response and management, performance testing, and on-call management. Grafana can connect to various data sources and applications, providing operational dashboards for your data anywhere. It also offers a free forever plan, allowing users to monitor their data with 10,000 series metrics, 50 GB of logs, 50 GB of traces, and 500 VUh of k6 testing. Grafana is a versatile tool for anyone looking to gain insights from their data.", "category": "monitoring", "tags": ["Monitoring", "Logs", "Metrics", "Traces"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "grafana/grafana-oss:13.0.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://grafana.com"}, {"label": "Documentation", "url": "https://grafana.com/docs"}, {"label": "Github", "url": "https://github.com/grafana/grafana"}], "instructions": "Login with admin:admin", "install": [{"docker": {"image": "$IMAGE", "name": "grafana", "port": "$PORT:3000", "volumes": ["/var/lib/grafana"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Login with admin:admin"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('grav', 'Grav', 'Grav is an award-winning, open-source, flat-file content management system (CMS) designed to help you build faster websites. It''s been voted ''Best Open Source CMS'' in 2016 and ''Best Flat File CMS'' in 2017, 2019, 2020, and 2021. Grav is known for its fast performance, extensibility, and user-friendly interface. With Grav, you can easily modify flexible configuration settings, edit content with a powerful markdown editor, and install a wide range of modern themes with one click. It also offers a built-in package manager for easy plugin installation. Grav is packed with features and tools that make content creation enjoyable. It supports one-click installs, powerful content filtering, dynamic content types, multi-language support, simple backups and restores, image media processing, and easy theme customization. Whether you''re creating landing pages, portfolios, product sites, personal resumes, e-commerce sites, blogs, business sites, or documentation, Grav provides the flexibility and power you need.', 'cms', ARRAY['CMS'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/grav:1.7.52"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Grav", "version": "latest", "description": "Grav is an award-winning, open-source, flat-file content management system (CMS) designed to help you build faster websites. It's been voted 'Best Open Source CMS' in 2016 and 'Best Flat File CMS' in 2017, 2019, 2020, and 2021. Grav is known for its fast performance, extensibility, and user-friendly interface. With Grav, you can easily modify flexible configuration settings, edit content with a powerful markdown editor, and install a wide range of modern themes with one click. It also offers a built-in package manager for easy plugin installation. Grav is packed with features and tools that make content creation enjoyable. It supports one-click installs, powerful content filtering, dynamic content types, multi-language support, simple backups and restores, image media processing, and easy theme customization. Whether you're creating landing pages, portfolios, product sites, personal resumes, e-commerce sites, blogs, business sites, or documentation, Grav provides the flexibility and power you need.", "category": "cms", "tags": ["CMS"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/grav:1.7.52"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://getgrav.org"}, {"label": "Documentation", "url": "https://learn.getgrav.org"}, {"label": "Github", "url": "https://github.com/getgrav/grav"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "grav", "port": "$PORT:80", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('grayduckmail', 'Gray Duck Mail', 'Gray Duck Mail is a user-friendly email discussion list application that offers an alternative to traditional email discussion group software. It is designed to be simple to set up and manage, making the process of running an email discussion list effortless. Gray Duck Mail is perfect for managing mailing lists between small to medium size groups, such as neighborhoods, schools, workplaces, and families. With Gray Duck Mail, you can send one email and automatically keep everyone in the loop. The application monitors a remote mail server for messages and processes them by relaying the message to all list members. It also automatically handles user subscriptions, unsubscription requests, and email bounces. Gray Duck Mail works with any external email host that allows for POP3/SMTP connections and message forwarding or aliasing. It relies totally on an external mail provider, allowing you to use an existing web host or email account.', 'email', ARRAY['Email'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "wagesj45/gray-duck-mail"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Gray Duck Mail", "version": "latest", "description": "Gray Duck Mail is a user-friendly email discussion list application that offers an alternative to traditional email discussion group software. It is designed to be simple to set up and manage, making the process of running an email discussion list effortless. Gray Duck Mail is perfect for managing mailing lists between small to medium size groups, such as neighborhoods, schools, workplaces, and families. With Gray Duck Mail, you can send one email and automatically keep everyone in the loop. The application monitors a remote mail server for messages and processes them by relaying the message to all list members. It also automatically handles user subscriptions, unsubscription requests, and email bounces. Gray Duck Mail works with any external email host that allows for POP3/SMTP connections and message forwarding or aliasing. It relies totally on an external mail provider, allowing you to use an existing web host or email account.", "category": "email", "tags": ["Email"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "wagesj45/gray-duck-mail"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://grayduckmail.com"}, {"label": "Github", "url": "https://github.com/wagesj45/gray-duck-mail"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "grayduckmail", "port": "$PORT:80", "volumes": ["/database"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('grist', 'Grist', 'Grist is an open-source, customizable data management platform that combines the power of a spreadsheet with the structure of a database. Designed for teams and individuals who need to organize, analyze, and share information, Grist offers a flexible and collaborative environment for data management. It supports relational data linking, allowing users to create complex, connected data tables, and provides tools for custom views, formulas, and dashboards. Grist’s user-friendly interface empowers users to build powerful applications without requiring extensive coding knowledge.', 'data-management', ARRAY['Data Management', 'Spreadsheet', 'Database', 'Collaboration', 'No-Code', 'Customizable Dashboards', 'Data Security', 'API Integration', 'Templates', 'Data Import/Export'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "gristlabs/grist:1.7.13"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8484}}$JSON$::jsonb, $JSON${"metadata": {"name": "Grist", "version": "latest", "description": "Grist is an open-source, customizable data management platform that combines the power of a spreadsheet with the structure of a database. Designed for teams and individuals who need to organize, analyze, and share information, Grist offers a flexible and collaborative environment for data management. It supports relational data linking, allowing users to create complex, connected data tables, and provides tools for custom views, formulas, and dashboards. Grist\u2019s user-friendly interface empowers users to build powerful applications without requiring extensive coding knowledge.", "category": "data-management", "tags": ["Data Management", "Spreadsheet", "Database", "Collaboration", "No-Code", "Customizable Dashboards", "Data Security", "API Integration", "Templates", "Data Import/Export"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "gristlabs/grist:1.7.13"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8484}}, "links": [{"label": "Website", "url": "https://www.getgrist.com"}, {"label": "Documentation", "url": "https://support.getgrist.com"}, {"label": "GitHub", "url": "https://github.com/gristlabs/grist-core"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "grist", "port": "$PORT:8484", "volumes": ["/persist"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('grocy', 'Grocy', 'Grocy is a self-hosted groceries and household management solution. It helps you streamline your daily chores, track inventory, manage shopping lists, plan meals, and keep tabs on household tasks. With Grocy, you can efficiently manage your pantry, reduce waste, and optimize your shopping experience. Grocy provides a user-friendly interface to organize your household activities and track consumables with expiration dates, giving you better control over your time and resources.', 'erp', ARRAY['ERP', 'Groceries', 'Household Management', 'Inventory', 'Meal Planning', 'Tasks'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/grocy:4.6.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Grocy", "version": "latest", "description": "Grocy is a self-hosted groceries and household management solution. It helps you streamline your daily chores, track inventory, manage shopping lists, plan meals, and keep tabs on household tasks. With Grocy, you can efficiently manage your pantry, reduce waste, and optimize your shopping experience. Grocy provides a user-friendly interface to organize your household activities and track consumables with expiration dates, giving you better control over your time and resources.", "category": "erp", "tags": ["ERP", "Groceries", "Household Management", "Inventory", "Meal Planning", "Tasks"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/grocy:4.6.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://grocy.info/"}, {"label": "Documentation", "url": "https://github.com/grocy/docs"}, {"label": "Github", "url": "https://github.com/grocy/grocy"}], "instructions": "default credentials; username; admin, password; admin", "install": [{"docker": {"image": "$IMAGE", "name": "grocy", "port": "$PORT:80", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "default credentials; username; admin, password; admin"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('habridge', 'Habridge', 'Habridge is an open-source software solution that emulates Philips Hue bridges, enabling the integration of various smart devices with home automation systems. It provides a simple yet powerful interface for controlling and managing smart lights, switches, and other IoT devices. Habridge supports a wide range of integrations, including Amazon Alexa, Google Home, and custom APIs, allowing users to create a seamless smart home experience. With its focus on flexibility and ease of use, Habridge empowers users to control their home automation setup with precision and efficiency.', 'smart-home', ARRAY['Smart Home', 'Home Automation', 'IoT', 'Device Integration', 'Open-Source', 'Alexa Integration', 'Google Home Integration', 'Custom Commands', 'Philips Hue Emulation', 'Voice-Controlled Automation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/habridge:5.4.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Habridge", "version": "latest", "description": "Habridge is an open-source software solution that emulates Philips Hue bridges, enabling the integration of various smart devices with home automation systems. It provides a simple yet powerful interface for controlling and managing smart lights, switches, and other IoT devices. Habridge supports a wide range of integrations, including Amazon Alexa, Google Home, and custom APIs, allowing users to create a seamless smart home experience. With its focus on flexibility and ease of use, Habridge empowers users to control their home automation setup with precision and efficiency.", "category": "smart-home", "tags": ["Smart Home", "Home Automation", "IoT", "Device Integration", "Open-Source", "Alexa Integration", "Google Home Integration", "Custom Commands", "Philips Hue Emulation", "Voice-Controlled Automation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/habridge:5.4.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Website", "url": "https://github.com/bwssytems/ha-bridge"}, {"label": "Github", "url": "https://github.com/bwssytems/ha-bridge"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "habridge", "port": "$PORT:8080", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('hackmdio', 'HackMD', 'HackMD is a simple and powerful note-taking app that allows you to create notes, write and organize your thoughts, and collaborate with others in real time. It''s a great tool for anyone who wants to stay organized and productive while working remotely or on the go.', 'no-code', ARRAY['No-Code', 'Collaboration', 'Note Taking'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "hackmdio/hackmd:2.6.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "HackMD", "version": "latest", "description": "HackMD is a simple and powerful note-taking app that allows you to create notes, write and organize your thoughts, and collaborate with others in real time. It's a great tool for anyone who wants to stay organized and productive while working remotely or on the go.", "category": "no-code", "tags": ["No-Code", "Collaboration", "Note Taking"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "hackmdio/hackmd:2.6.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://hackmd.io/"}, {"label": "Github", "url": "https://github.com/hackmdio/codimd"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "hackmdio", "port": "$PORT:3000", "volumes": ["/home/hackmd/app/public/uploads", "/var/lib/postgresql/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('hammond', 'Hammond', 'Hammond is a self-hosted vehicle management system designed to track fuel and other expenses related to your vehicles. It supports multiple users sharing multiple vehicles, making it an ideal solution for families, businesses, or any group with shared vehicles. With Hammond, you can manage multiple vehicles, track fuel and other expenses, and even save attachments against vehicles. The app also features quick entries, allowing you to take a photo of a receipt or pump screen for later entry. It provides vehicle-level and overall reporting, helping you keep a close eye on your vehicle expenses. Furthermore, Hammond allows you to import data from Clarkson or Fuelly, making the transition to this system seamless and straightforward.', 'finance', ARRAY['Finance', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "akhilrex/hammond:1.0.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Hammond", "version": "latest", "description": "Hammond is a self-hosted vehicle management system designed to track fuel and other expenses related to your vehicles. It supports multiple users sharing multiple vehicles, making it an ideal solution for families, businesses, or any group with shared vehicles. With Hammond, you can manage multiple vehicles, track fuel and other expenses, and even save attachments against vehicles. The app also features quick entries, allowing you to take a photo of a receipt or pump screen for later entry. It provides vehicle-level and overall reporting, helping you keep a close eye on your vehicle expenses. Furthermore, Hammond allows you to import data from Clarkson or Fuelly, making the transition to this system seamless and straightforward.", "category": "finance", "tags": ["Finance", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "akhilrex/hammond:1.0.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Documentation", "url": "https://github.com/akhilrex/hammond/tree/master/docs"}, {"label": "Github", "url": "https://github.com/akhilrex/hammond"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "hammond", "port": "$PORT:3000", "volumes": ["/assets", "/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('handbrake-web', 'Handbrake Web', 'Handbrake Web is a self-hosted video transcoding solution that provides a web-based interface for managing and processing video encoding jobs using the powerful HandBrake video transcoder. The application features a distributed architecture with a central server for job management and dedicated workers for processing, allowing you to scale encoding capacity by adding more workers. The web interface enables you to upload videos, configure encoding presets, monitor job progress, and manage your transcoding queue from any browser. Handbrake Web supports all the encoding formats and options available in HandBrake, including H.264, H.265/HEVC, VP9, and AV1 codecs, as well as various container formats like MP4, MKV, and WebM. The worker-based architecture allows for parallel processing of multiple videos and can leverage hardware acceleration when available. Perfect for media enthusiasts who need to convert video collections to different formats, content creators preparing videos for multiple platforms, home server administrators managing media libraries, or anyone who needs a reliable self-hosted solution for batch video transcoding without installing desktop applications.', 'video', ARRAY['Video', 'Transcoding', 'Media', 'HandBrake', 'Encoding', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/thenickoftime/handbrake-web-server:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9999}}$JSON$::jsonb, $JSON${"metadata": {"name": "Handbrake Web", "version": "latest", "description": "Handbrake Web is a self-hosted video transcoding solution that provides a web-based interface for managing and processing video encoding jobs using the powerful HandBrake video transcoder. The application features a distributed architecture with a central server for job management and dedicated workers for processing, allowing you to scale encoding capacity by adding more workers. The web interface enables you to upload videos, configure encoding presets, monitor job progress, and manage your transcoding queue from any browser. Handbrake Web supports all the encoding formats and options available in HandBrake, including H.264, H.265/HEVC, VP9, and AV1 codecs, as well as various container formats like MP4, MKV, and WebM. The worker-based architecture allows for parallel processing of multiple videos and can leverage hardware acceleration when available. Perfect for media enthusiasts who need to convert video collections to different formats, content creators preparing videos for multiple platforms, home server administrators managing media libraries, or anyone who needs a reliable self-hosted solution for batch video transcoding without installing desktop applications.", "category": "video", "tags": ["Video", "Transcoding", "Media", "HandBrake", "Encoding", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/thenickoftime/handbrake-web-server:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9999}}, "links": [{"label": "GitHub", "url": "https://github.com/TheNickOfTime/handbrake-web"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "handbrake-web", "port": "$PORT:9999", "volumes": ["/data", "/video", "/video"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('hastebin', 'Hastebin', 'Haste is an open-source software that allows you to quickly and easily share text snippets. It''s designed to be simple, pretty, and easy to use. With Haste, you can create a ''paste'' of your text and it will generate a unique URL that you can share. This is particularly useful for sharing code snippets or other information that you want to quickly share with others. Haste is written in node.js and can be backed by either a file system or redis, providing flexibility in how it''s set up. It also includes a utility called haste-client that allows you to create pastes directly from your command line. Haste is designed to work well with a variety of browsers, including Firefox, Chrome, and Safari.', 'code-hosting', ARRAY['Code Hosting', 'Documents'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "rlister/hastebin:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Hastebin", "version": "latest", "description": "Haste is an open-source software that allows you to quickly and easily share text snippets. It's designed to be simple, pretty, and easy to use. With Haste, you can create a 'paste' of your text and it will generate a unique URL that you can share. This is particularly useful for sharing code snippets or other information that you want to quickly share with others. Haste is written in node.js and can be backed by either a file system or redis, providing flexibility in how it's set up. It also includes a utility called haste-client that allows you to create pastes directly from your command line. Haste is designed to work well with a variety of browsers, including Firefox, Chrome, and Safari.", "category": "code-hosting", "tags": ["Code Hosting", "Documents"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "rlister/hastebin:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Documentation", "url": "https://github.com/toptal/haste-server/wiki"}, {"label": "Github", "url": "https://github.com/toptal/haste-server"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "hastebin", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('hastypaste', 'Hasty Paste', 'Hasty Paste is a fast and minimalistic app designed for quickly pasting and sharing text. It is primarily used for sharing debug logs and similar content to aid developers in providing tech support. The app is publicly accessible with no authentication required. It generates random IDs for each paste, with an optional ''long'' ID to reduce the chances of brute force attacks. Users can also add expiring pastes. The app features a dark theme and optional syntax highlighting. It is designed to use minimal resources and does not require JavaScript. Hasty Paste also allows users to choose their file system and offers a custom flat-file system. The app is named ''Hasty Paste'' to reflect its speed and ease of use.', 'documents', ARRAY['Documents'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/enchant97/hasty-paste:2.3.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Hasty Paste", "version": "latest", "description": "Hasty Paste is a fast and minimalistic app designed for quickly pasting and sharing text. It is primarily used for sharing debug logs and similar content to aid developers in providing tech support. The app is publicly accessible with no authentication required. It generates random IDs for each paste, with an optional 'long' ID to reduce the chances of brute force attacks. Users can also add expiring pastes. The app features a dark theme and optional syntax highlighting. It is designed to use minimal resources and does not require JavaScript. Hasty Paste also allows users to choose their file system and offers a custom flat-file system. The app is named 'Hasty Paste' to reflect its speed and ease of use.", "category": "documents", "tags": ["Documents"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/enchant97/hasty-paste:2.3.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Documentation", "url": "https://enchantedcode.co.uk/hasty-paste/"}, {"label": "Github", "url": "https://github.com/enchant97/hasty-paste"}], "instructions": "Hasty Paste takes a minute or two on first launch.", "install": [{"docker": {"image": "$IMAGE", "name": "hastypaste", "port": "$PORT:80", "volumes": ["/app/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Hasty Paste takes a minute or two on first launch."}, "services": {"redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('hasura', 'Hasura', 'Hasura is a powerful Data API Platform that automates the process of building, securing, optimizing, and deploying GraphQL and REST APIs. It eliminates the need for manual API creation, enabling developers to generate APIs effortlessly by connecting to existing databases. This results in rapid, scalable application development. Hasura is compatible with a variety of popular databases, including PostgreSQL, MySQL, and MongoDB, allowing you to build GraphQL APIs on top of your existing databases. It also provides comprehensive tools to secure APIs beyond authentication and authorization. With Hasura, you can accelerate the development of new applications or add new features to an existing application in days instead of weeks. It also helps in fast-tracking cloud migration, frontend and backend modernization, and application re-architecture projects by automating 80% of your API development work.', 'developer-tools', ARRAY['Developer Tools', 'Databases', 'API Development'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "hasura/graphql-engine:v2.48.16.ubi"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Hasura", "version": "latest", "description": "Hasura is a powerful Data API Platform that automates the process of building, securing, optimizing, and deploying GraphQL and REST APIs. It eliminates the need for manual API creation, enabling developers to generate APIs effortlessly by connecting to existing databases. This results in rapid, scalable application development. Hasura is compatible with a variety of popular databases, including PostgreSQL, MySQL, and MongoDB, allowing you to build GraphQL APIs on top of your existing databases. It also provides comprehensive tools to secure APIs beyond authentication and authorization. With Hasura, you can accelerate the development of new applications or add new features to an existing application in days instead of weeks. It also helps in fast-tracking cloud migration, frontend and backend modernization, and application re-architecture projects by automating 80% of your API development work.", "category": "developer-tools", "tags": ["Developer Tools", "Databases", "API Development"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "hasura/graphql-engine:v2.48.16.ubi"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Website", "url": "https://hasura.io/"}, {"label": "Documentation", "url": "https://hasura.io/docs/latest/deployment/deployment-guides/kubernetes"}, {"label": "Github", "url": "https://github.com/hasura/graphql-engine"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "hasura", "port": "$PORT:8080", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('headphones', 'Headphones', 'Headphones is an open-source application designed to manage and organize your music library with precision and efficiency. It provides a powerful interface for searching, downloading, and managing albums and tracks, ensuring your music collection is always up-to-date. Headphones integrates seamlessly with popular media servers and download clients, offering an automated solution for music enthusiasts. With its focus on flexibility and ease of use, Headphones empowers users to curate their music library effortlessly.', 'music-management', ARRAY['Music Management', 'Open-Source', 'Automated Downloads', 'Media Servers', 'Plex Integration', 'Emby Integration', 'Metadata Management', 'Music Library', 'Music Automation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/headphones:version-a78f38c1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8181}}$JSON$::jsonb, $JSON${"metadata": {"name": "Headphones", "version": "latest", "description": "Headphones is an open-source application designed to manage and organize your music library with precision and efficiency. It provides a powerful interface for searching, downloading, and managing albums and tracks, ensuring your music collection is always up-to-date. Headphones integrates seamlessly with popular media servers and download clients, offering an automated solution for music enthusiasts. With its focus on flexibility and ease of use, Headphones empowers users to curate their music library effortlessly.", "category": "music-management", "tags": ["Music Management", "Open-Source", "Automated Downloads", "Media Servers", "Plex Integration", "Emby Integration", "Metadata Management", "Music Library", "Music Automation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/headphones:version-a78f38c1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8181}}, "links": [{"label": "Website", "url": "https://github.com/rembo10/headphones"}, {"label": "Github", "url": "https://github.com/rembo10/headphones"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "headphones", "port": "$PORT:8181", "volumes": ["/config", "/downloads", "/music"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('healthchecks', 'Healthchecks.io', 'Healthchecks.io is an open-source application designed for monitoring cron jobs, periodic tasks, and application endpoints. It provides a lightweight and efficient way to ensure critical processes are running as expected. Healthchecks.io integrates with a wide range of notification methods, allowing users to be alerted when tasks fail to execute within their expected intervals. With its user-friendly interface and robust feature set, Healthchecks.io empowers users to maintain reliable task execution and system monitoring.', 'task-monitoring', ARRAY['Task Monitoring', 'Open-Source', 'Cron Jobs', 'System Monitoring', 'Notifications', 'Self-Hosted', 'Alerting', 'Health Monitoring'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/healthchecks:4.2.20260428"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Healthchecks.io", "version": "latest", "description": "Healthchecks.io is an open-source application designed for monitoring cron jobs, periodic tasks, and application endpoints. It provides a lightweight and efficient way to ensure critical processes are running as expected. Healthchecks.io integrates with a wide range of notification methods, allowing users to be alerted when tasks fail to execute within their expected intervals. With its user-friendly interface and robust feature set, Healthchecks.io empowers users to maintain reliable task execution and system monitoring.", "category": "task-monitoring", "tags": ["Task Monitoring", "Open-Source", "Cron Jobs", "System Monitoring", "Notifications", "Self-Hosted", "Alerting", "Health Monitoring"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/healthchecks:4.2.20260428"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}, "links": [{"label": "Website", "url": "https://healthchecks.io"}, {"label": "Github", "url": "https://github.com/healthchecks/healthchecks"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "healthchecks", "port": "$PORT:8000", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('hedgedoc', 'HedgeDoc', 'HedgeDoc, previously known as CodiMD, is an open-source, web-based, self-hosted, collaborative markdown editor. It allows you to collaborate on notes, graphs, and presentations in real-time. Simply share your note-link with your co-workers and they can join in the collaboration. The editor runs directly in your browser, allowing you to stay in control of your data by keeping it on your server. HedgeDoc also offers a presentation mode for building and presenting slides in markdown, and supports a variety of graphs, diagrams, and embedded content. It features an easy-to-use permission system for managing note permissions, and keeps track of changes to your notes through revisions, even allowing you to revert to older versions. Despite its extensive features, HedgeDoc has low system requirements and can run smoothly even on a Raspberry Pi.', 'documents', ARRAY['Documents', 'Collaboration', 'Note-taking'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "quay.io/hedgedoc/hedgedoc:1.10.8"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "HedgeDoc", "version": "latest", "description": "HedgeDoc, previously known as CodiMD, is an open-source, web-based, self-hosted, collaborative markdown editor. It allows you to collaborate on notes, graphs, and presentations in real-time. Simply share your note-link with your co-workers and they can join in the collaboration. The editor runs directly in your browser, allowing you to stay in control of your data by keeping it on your server. HedgeDoc also offers a presentation mode for building and presenting slides in markdown, and supports a variety of graphs, diagrams, and embedded content. It features an easy-to-use permission system for managing note permissions, and keeps track of changes to your notes through revisions, even allowing you to revert to older versions. Despite its extensive features, HedgeDoc has low system requirements and can run smoothly even on a Raspberry Pi.", "category": "documents", "tags": ["Documents", "Collaboration", "Note-taking"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "quay.io/hedgedoc/hedgedoc:1.10.8"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://hedgedoc.org/"}, {"label": "Documentation", "url": "https://docs.hedgedoc.org/"}, {"label": "Github", "url": "https://git.hedgedoc.org/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "hedgedoc", "port": "$PORT:3000", "volumes": ["/hedgedoc/public/uploads"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('heimdall', 'Heimdall', 'Heimdall Application Dashboard is a versatile and visually pleasing dashboard for all your web applications. It provides a simple and elegant interface where you can add links to any web application or site you frequently use. The app is designed with simplicity in mind, avoiding the trap of over-complication that many projects fall into. With Heimdall, you can add a link to anything, whether it''s intrinsically supported or not, by simply filling in the name, background color, and the link URL. The app also supports Foundation and Enhanced apps. Foundation apps are those supported by Heimdall, and Enhanced apps are like Foundation apps but with the added feature of displaying extra information automatically by entering API credentials. Heimdall is all about making your web application experience smooth, simple, and enjoyable.', 'dashboard', ARRAY['Dashboard'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/heimdall:2.7.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Heimdall", "version": "latest", "description": "Heimdall Application Dashboard is a versatile and visually pleasing dashboard for all your web applications. It provides a simple and elegant interface where you can add links to any web application or site you frequently use. The app is designed with simplicity in mind, avoiding the trap of over-complication that many projects fall into. With Heimdall, you can add a link to anything, whether it's intrinsically supported or not, by simply filling in the name, background color, and the link URL. The app also supports Foundation and Enhanced apps. Foundation apps are those supported by Heimdall, and Enhanced apps are like Foundation apps but with the added feature of displaying extra information automatically by entering API credentials. Heimdall is all about making your web application experience smooth, simple, and enjoyable.", "category": "dashboard", "tags": ["Dashboard"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/heimdall:2.7.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://heimdall.site/"}, {"label": "Documentation", "url": "https://heimdall.site/"}, {"label": "Github", "url": "https://github.com/linuxserver/Heimdall"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "heimdall", "port": "$PORT:80", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('hemmelig', 'Hemmelig', 'Hemmelig is a secure, self-hosted secret sharing platform that allows you to share sensitive information like passwords, API keys, and confidential documents safely. Built with security in mind, Hemmelig provides end-to-end encryption, expiration dates, and access controls to ensure your secrets remain protected. Perfect for teams, developers, and organizations who need to share sensitive information securely without relying on external services.', 'security', ARRAY['Security', 'Secret Sharing', 'Encryption', 'Self-Hosted', 'Password Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "hemmeligapp/hemmelig:v7.4.8"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Hemmelig", "version": "latest", "description": "Hemmelig is a secure, self-hosted secret sharing platform that allows you to share sensitive information like passwords, API keys, and confidential documents safely. Built with security in mind, Hemmelig provides end-to-end encryption, expiration dates, and access controls to ensure your secrets remain protected. Perfect for teams, developers, and organizations who need to share sensitive information securely without relying on external services.", "category": "security", "tags": ["Security", "Secret Sharing", "Encryption", "Self-Hosted", "Password Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "hemmeligapp/hemmelig:v7.4.8"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://hemmelig.app"}, {"label": "GitHub", "url": "https://github.com/HemmeligOrg/Hemmelig.app"}], "instructions": "v7 uses BetterAuth and SQLite \u2014 no initial admin credentials are needed in the config. Register your first account via the web UI after deployment.", "install": [{"docker": {"image": "$IMAGE", "name": "hemmelig", "port": "$PORT:3000", "volumes": ["/app/database", "/app/uploads"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "v7 uses BetterAuth and SQLite \u2014 no initial admin credentials are needed in the config. Register your first account via the web UI after deployment."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('heyform', 'HeyForm', 'HeyForm is an open-source form builder platform designed to create, manage, and share forms with ease. It simplifies form creation workflows for businesses, developers, and individuals by offering intuitive UI components and backend management. HeyForm provides robust support for form encryption, session management, and integrations with third-party services like MongoDB and Redis. Its flexible API allows developers to customize and extend functionalities while ensuring data security. HeyForm''s clean design and modular architecture make it scalable and adaptable for growing business needs, enabling effective form creation, storage, and analysis.', 'form-builder', ARRAY['Form Builder', 'Form Encryption', 'MongoDB Integration', 'Redis Integration', 'API-Driven', 'Scalable Architecture', 'Multi-Tenancy', 'Notifications', 'Data Security'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "heyform/community-edition:v0.1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}$JSON$::jsonb, $JSON${"metadata": {"name": "HeyForm", "version": "latest", "description": "HeyForm is an open-source form builder platform designed to create, manage, and share forms with ease. It simplifies form creation workflows for businesses, developers, and individuals by offering intuitive UI components and backend management. HeyForm provides robust support for form encryption, session management, and integrations with third-party services like MongoDB and Redis. Its flexible API allows developers to customize and extend functionalities while ensuring data security. HeyForm's clean design and modular architecture make it scalable and adaptable for growing business needs, enabling effective form creation, storage, and analysis.", "category": "form-builder", "tags": ["Form Builder", "Form Encryption", "MongoDB Integration", "Redis Integration", "API-Driven", "Scalable Architecture", "Multi-Tenancy", "Notifications", "Data Security"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "heyform/community-edition:v0.1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}, "links": [{"label": "Website", "url": "https://heyform.net/"}, {"label": "Documentation", "url": "https://docs.heyform.net"}, {"label": "GitHub", "url": "https://github.com/heyform/heyform"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "heyform", "port": "$PORT:8000", "volumes": ["/data/db"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('hiccup', 'Hiccup', 'Hiccup is a static start page application designed to help you access your most important links quickly and efficiently. It allows you to categorize your links, add them via drag and drop, and even search for them using various search providers. The app also supports multiple profiles, enabling you to switch between different sets of links based on your needs. Hiccup also features a built-in config manager for easy management of your link configurations. The app is designed to be used anywhere you can serve a static webpage from, such as your home server or a new browser tab. It also supports full keyboard navigation for quick and easy access to your links.', 'productivity', ARRAY['Productivity', 'Bookmarks'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "bleckbeard/hiccup:v0.5.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Hiccup", "version": "latest", "description": "Hiccup is a static start page application designed to help you access your most important links quickly and efficiently. It allows you to categorize your links, add them via drag and drop, and even search for them using various search providers. The app also supports multiple profiles, enabling you to switch between different sets of links based on your needs. Hiccup also features a built-in config manager for easy management of your link configurations. The app is designed to be used anywhere you can serve a static webpage from, such as your home server or a new browser tab. It also supports full keyboard navigation for quick and easy access to your links.", "category": "productivity", "tags": ["Productivity", "Bookmarks"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "bleckbeard/hiccup:v0.5.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Github", "url": "https://github.com/ashwin-pc/hiccup"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "hiccup", "port": "$PORT:80", "volumes": ["/usr/share/nginx/html"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('homarr', 'Homarr', 'Homarr is a powerful dashboard designed to simplify the management of your server. It provides a sleek, modern interface that brings all your apps and services together in one place, allowing you to access and control everything with ease. Homarr seamlessly integrates with the apps you''ve added, offering valuable insights and complete control. You can add your self-hosted applications or favorite websites to your dashboard and organize them as you like. Homarr supports integration with many popular applications to enhance your user experience. It is customizable, accessible, and supports 23 languages. With Homarr, you can control and monitor your network directly, use integrations to display data and control apps, and even create your own dashboard using a comprehensible and easy-to-use visual editor. Homarr is open-source and allows commercial usage. It features a quick search function to easily navigate through your apps and supported integrations.', 'dashboard', ARRAY['Dashboard', 'Homepage', 'Self-hosted', 'Widgets', 'Bookmarks', 'Monitoring', 'Customizable', 'Web App'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/homarr-labs/homarr:v1.59.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 7574}}$JSON$::jsonb, $JSON${"metadata": {"name": "Homarr", "version": "latest", "description": "Homarr is a powerful dashboard designed to simplify the management of your server. It provides a sleek, modern interface that brings all your apps and services together in one place, allowing you to access and control everything with ease. Homarr seamlessly integrates with the apps you've added, offering valuable insights and complete control. You can add your self-hosted applications or favorite websites to your dashboard and organize them as you like. Homarr supports integration with many popular applications to enhance your user experience. It is customizable, accessible, and supports 23 languages. With Homarr, you can control and monitor your network directly, use integrations to display data and control apps, and even create your own dashboard using a comprehensible and easy-to-use visual editor. Homarr is open-source and allows commercial usage. It features a quick search function to easily navigate through your apps and supported integrations.", "category": "dashboard", "tags": ["Dashboard", "Homepage", "Self-hosted", "Widgets", "Bookmarks", "Monitoring", "Customizable", "Web App"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/homarr-labs/homarr:v1.59.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 7574}}, "links": [{"label": "Website", "url": "https://homarr.dev"}, {"label": "GitHub", "url": "https://github.com/homarr-labs/homarr"}, {"label": "Documentation", "url": "https://homarr.dev/docs/getting-started/"}, {"label": "Easypanel Documentation", "url": "https://homarr.dev/docs/getting-started/installation/easy-panel"}], "instructions": "On first launch, Homarr will display an onboarding wizard. Create your admin account to get started.", "install": [{"docker": {"image": "$IMAGE", "name": "homarr", "port": "$PORT:7574", "volumes": ["/appdata"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "On first launch, Homarr will display an onboarding wizard. Create your admin account to get started."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('homeassistant', 'Home Assistant', 'Home Assistant is an open-source home automation app that prioritizes local control and privacy. It allows you to manage and automate a wide range of devices and services in your home, from electricity grids and solar panels to voice-controlled devices. With its advanced configuration options, you can customize your home automation to suit your needs. It also offers features like multi-factor authentication for added security. Home Assistant is perfect to run on a Raspberry Pi or a local server, providing a comprehensive solution for your home automation needs.', 'home-automation', ARRAY['Home Automation', 'Open Source', 'Privacy'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/homeassistant:2026.4.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8123}}$JSON$::jsonb, $JSON${"metadata": {"name": "Home Assistant", "version": "latest", "description": "Home Assistant is an open-source home automation app that prioritizes local control and privacy. It allows you to manage and automate a wide range of devices and services in your home, from electricity grids and solar panels to voice-controlled devices. With its advanced configuration options, you can customize your home automation to suit your needs. It also offers features like multi-factor authentication for added security. Home Assistant is perfect to run on a Raspberry Pi or a local server, providing a comprehensive solution for your home automation needs.", "category": "home-automation", "tags": ["Home Automation", "Open Source", "Privacy"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/homeassistant:2026.4.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8123}}, "links": [{"label": "Documentation", "url": "https://www.home-assistant.io/docs/"}, {"label": "Github", "url": "https://github.com/home-assistant"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "homeassistant", "port": "$PORT:8123", "volumes": ["/config", "/config/configuration.yaml"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('homebox', 'Homebox', 'Homebox is an inventory management system that helps you keep track of your belongings, their location, and other details to simplify home organization.', 'inventory', ARRAY['Inventory', 'Organization', 'Home Management', 'Self-Hosted', 'Personal'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/sysadminsmedia/homebox:0.25.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 7745}}$JSON$::jsonb, $JSON${"metadata": {"name": "Homebox", "version": "latest", "description": "Homebox is an inventory management system that helps you keep track of your belongings, their location, and other details to simplify home organization.", "category": "inventory", "tags": ["Inventory", "Organization", "Home Management", "Self-Hosted", "Personal"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/sysadminsmedia/homebox:0.25.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 7745}}, "links": [{"label": "Website", "url": "https://homebox.software/en/"}, {"label": "GitHub", "url": "https://github.com/sysadminsmedia/homebox"}, {"label": "Documentation", "url": "https://homebox.software/en/quick-start/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "homebox", "port": "$PORT:7745", "volumes": ["/data/"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('homepage', 'Homepage', 'Homepage is a self-hosted dashboard designed to provide a centralized hub for accessing and managing your server and web services. With an intuitive and customizable interface, Homepage makes it easy to organize links, monitor system health, and view important metrics in one place. It supports a wide range of integrations, including Docker, Kubernetes, and popular web services, making it an ideal tool for individuals and teams looking to streamline access and management of their infrastructure. Being open-source, Homepage offers transparency, flexibility, and control to users.', 'dashboard', ARRAY['Dashboard', 'Self-Hosted', 'Open Source', 'Customizable', 'Infrastructure Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/gethomepage/homepage:v1.12.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Homepage", "version": "latest", "description": "Homepage is a self-hosted dashboard designed to provide a centralized hub for accessing and managing your server and web services. With an intuitive and customizable interface, Homepage makes it easy to organize links, monitor system health, and view important metrics in one place. It supports a wide range of integrations, including Docker, Kubernetes, and popular web services, making it an ideal tool for individuals and teams looking to streamline access and management of their infrastructure. Being open-source, Homepage offers transparency, flexibility, and control to users.", "category": "dashboard", "tags": ["Dashboard", "Self-Hosted", "Open Source", "Customizable", "Infrastructure Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/gethomepage/homepage:v1.12.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://gethomepage.dev/"}, {"label": "Documentation", "url": "https://gethomepage.dev/widgets/authoring/"}, {"label": "GitHub", "url": "https://github.com/gethomepage/homepage"}], "instructions": "Configure settings.yaml for customization.", "install": [{"docker": {"image": "$IMAGE", "name": "homepage", "port": "$PORT:80", "volumes": ["/var/run/docker.sock", "/app/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Configure settings.yaml for customization."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('homer', 'Homer', 'Homer is a straightforward, static homepage for your server, designed to keep all your services easily accessible. It operates based on a simple yaml configuration file. This app serves as a full static HTML/JS dashboard, providing a centralized platform where you can manage and access all your services. It features a search function, grouping, theme customization, and offline health checks. It also supports keyboard shortcuts for quick navigation. Homer is designed to be served by an HTTP server and is perfect for those who want to keep their services organized and within reach.', 'dashboard', ARRAY['Dashboard'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "b4bz/homer:v26.4.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Homer", "version": "latest", "description": "Homer is a straightforward, static homepage for your server, designed to keep all your services easily accessible. It operates based on a simple yaml configuration file. This app serves as a full static HTML/JS dashboard, providing a centralized platform where you can manage and access all your services. It features a search function, grouping, theme customization, and offline health checks. It also supports keyboard shortcuts for quick navigation. Homer is designed to be served by an HTTP server and is perfect for those who want to keep their services organized and within reach.", "category": "dashboard", "tags": ["Dashboard"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "b4bz/homer:v26.4.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Github", "url": "https://github.com/bastienwirtz/homer"}, {"label": "Demo", "url": "https://homer-demo.netlify.app"}], "instructions": "The config files can be found under \"/etc/easypanel/projects/PROJECT_NAME/homer/volumes/assets\"", "install": [{"docker": {"image": "$IMAGE", "name": "homer", "port": "$PORT:8080", "volumes": ["/www/assets"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "The config files can be found under \"/etc/easypanel/projects/PROJECT_NAME/homer/volumes/assets\""}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('honey', 'Honey', 'Honey is a lightweight web application developed by dani3l0. It provides a clean and intuitive interface for accessing and managing your data. The application is containerized for easy deployment and configuration, making it ideal for self-hosted environments. Honey uses a file-based configuration system, allowing for simple customization and persistence across container restarts. With its efficient design and minimal resource requirements, Honey is a great addition to any self-hosted service collection.', 'web-application', ARRAY['Web Application', 'Self-hosted', 'Docker', 'Lightweight'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/dani3l0/honey:v2.4.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4173}}$JSON$::jsonb, $JSON${"metadata": {"name": "Honey", "version": "latest", "description": "Honey is a lightweight web application developed by dani3l0. It provides a clean and intuitive interface for accessing and managing your data. The application is containerized for easy deployment and configuration, making it ideal for self-hosted environments. Honey uses a file-based configuration system, allowing for simple customization and persistence across container restarts. With its efficient design and minimal resource requirements, Honey is a great addition to any self-hosted service collection.", "category": "web-application", "tags": ["Web Application", "Self-hosted", "Docker", "Lightweight"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/dani3l0/honey:v2.4.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4173}}, "links": [{"label": "Demo", "url": "https://honeyy.vercel.app"}, {"label": "GitHub", "url": "https://github.com/dani3l0/honey"}, {"label": "Container", "url": "https://github.com/dani3l0/honey/pkgs/container/honey"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "honey", "port": "$PORT:4173", "volumes": ["/app/dist/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('hortusfox', 'HortusFox', 'HortusFox is a free, open-source, self-hosted, collaborative plant management system designed for individuals and groups to easily manage their plants, tasks, calendar, inventory, and more, all within a user-friendly web application.', 'plant-management', ARRAY['Plant Management', 'Collaboration', 'Self-Hosted', 'Open Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/danielbrendel/hortusfox-web:v5.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "HortusFox", "version": "latest", "description": "HortusFox is a free, open-source, self-hosted, collaborative plant management system designed for individuals and groups to easily manage their plants, tasks, calendar, inventory, and more, all within a user-friendly web application.", "category": "plant-management", "tags": ["Plant Management", "Collaboration", "Self-Hosted", "Open Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/danielbrendel/hortusfox-web:v5.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Documentation", "url": "https://hortusfox.github.io/"}, {"label": "Github", "url": "https://github.com/danielbrendel/hortusfox-web?tab=readme-ov-file#docker"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "hortusfox", "port": "$PORT:80", "volumes": ["/var/www/html/public/img", "/var/www/html/app/logs", "/var/www/html/public/backup", "/var/www/html/public/themes", "/var/www/html/app/migrations"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('httplaceholder', 'HTTP Placeholder', 'HTTP Placeholder is a powerful API mocking tool that allows you to create mock HTTP endpoints for testing and development purposes. It provides a simple way to simulate API responses and test your applications without relying on real backend services.', 'api', ARRAY['API', 'Testing', 'Development', 'Mocking', 'HTTP'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "dukeofharen/httplaceholder:2024.12.27.10"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5000}}$JSON$::jsonb, $JSON${"metadata": {"name": "HTTP Placeholder", "version": "latest", "description": "HTTP Placeholder is a powerful API mocking tool that allows you to create mock HTTP endpoints for testing and development purposes. It provides a simple way to simulate API responses and test your applications without relying on real backend services.", "category": "api", "tags": ["API", "Testing", "Development", "Mocking", "HTTP"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "dukeofharen/httplaceholder:2024.12.27.10"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5000}}, "links": [{"label": "Github", "url": "https://github.com/dukeofharen/httplaceholder"}, {"label": "Documentation", "url": "https://github.com/dukeofharen/httplaceholder/wiki"}], "instructions": "After installation, access the web interface through the provided domain to start creating and managing your mock endpoints.", "install": [{"docker": {"image": "$IMAGE", "name": "httplaceholder", "port": "$PORT:5000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After installation, access the web interface through the provided domain to start creating and managing your mock endpoints."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('huginn', 'Huginn', 'Huginn is a system for building agents that perform automated tasks for you online. They can read the web, watch for events, and take actions on your behalf.', 'automation', ARRAY['Automation', 'Web Scraping', 'API', 'Data Processing', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "huginn/huginn:5dbeee394a982bd29ba63c06013cd9cb58191cc6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Huginn", "version": "latest", "description": "Huginn is a system for building agents that perform automated tasks for you online. They can read the web, watch for events, and take actions on your behalf.", "category": "automation", "tags": ["Automation", "Web Scraping", "API", "Data Processing", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "huginn/huginn:5dbeee394a982bd29ba63c06013cd9cb58191cc6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://huginn.io/"}, {"label": "Documentation", "url": "https://github.com/huginn/huginn/wiki"}, {"label": "GitHub", "url": "https://github.com/huginn/huginn"}], "instructions": "Open Huginn from your domain, complete the initial account setup, then create or import agents and configure credentials for the external services they use.", "install": [{"docker": {"image": "$IMAGE", "name": "huginn", "port": "$PORT:3000", "volumes": ["/var/lib/mysql"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Open Huginn from your domain, complete the initial account setup, then create or import agents and configure credentials for the external services they use."}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('huly', 'Huly', 'Huly is an all-in-one project management platform and self-hosted alternative to Linear, Jira, Slack, Notion, and Motion. It combines issue tracking, CRM, HRM, ATS (Applicant Tracking), chat, documents, and team collaboration in a single platform. Built on a robust framework for business applications, Huly offers real-time document collaboration with Y.js CRDT, full-text search via Elasticsearch, S3-compatible file storage with MinIO, and event-driven architecture with Redpanda (Kafka). Requires 2+ vCPUs and 8+ GB RAM minimum.', 'project-management', ARRAY['Project Management', 'CRM', 'Self-Hosted', 'Collaboration', 'Issue Tracking'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "v0.7.382"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Huly", "version": "latest", "description": "Huly is an all-in-one project management platform and self-hosted alternative to Linear, Jira, Slack, Notion, and Motion. It combines issue tracking, CRM, HRM, ATS (Applicant Tracking), chat, documents, and team collaboration in a single platform. Built on a robust framework for business applications, Huly offers real-time document collaboration with Y.js CRDT, full-text search via Elasticsearch, S3-compatible file storage with MinIO, and event-driven architecture with Redpanda (Kafka). Requires 2+ vCPUs and 8+ GB RAM minimum.", "category": "project-management", "tags": ["Project Management", "CRM", "Self-Hosted", "Collaboration", "Issue Tracking"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "v0.7.382"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://huly.io"}, {"label": "GitHub", "url": "https://github.com/hcengineering/platform"}, {"label": "Documentation", "url": "https://docs.huly.io"}], "instructions": "After deployment, access Huly via the main service domain. On first visit, click \"Sign up\" to create your account, then create a workspace. Email notifications (password recovery, etc.) are disabled by default\u2014add the mail service and SMTP config for production. Allow ~60 seconds for all services to initialize on first startup.", "install": [{"docker": {"image": "$IMAGE", "name": "huly", "port": "$PORT:80", "volumes": ["/etc/nginx/conf.d/default.conf", "/cockroach/cockroach-data", "/cockroach/certs", "/var/lib/redpanda/data", "/data", "/usr/share/elasticsearch/data"], "extra_ports": ["8094:8094"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deployment, access Huly via the main service domain. On first visit, click \"Sign up\" to create your account, then create a workspace. Email notifications (password recovery, etc.) are disabled by default\u2014add the mail service and SMTP config for production. Allow ~60 seconds for all services to initialize on first startup."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('humhub', 'HumHub', 'HumHub is a flexible open-source social network kit designed to facilitate communication and collaboration. It allows you to create your own customized social network, social intranet, or large social enterprise application tailored to your specific needs. Whether you''re looking to boost your business, support your customers, educate your students, or organize your football club, HumHub provides the tools to make it happen. It features an intuitive user interface and a powerful module system that can be extended with third-party tools, your own creations, or existing software. With HumHub, you have full control over your server and data. The app also offers features like posts and updates, file sharing, liking and commenting, and ''Spaces'' for group communication. You can extend your profile, create a portfolio, connect with others, and find people with specific skills. With its module system, you can modify anything on HumHub according to your requirements. The app also supports live updates, notifications, activity streams, dashboards, user profiles, groups, directories, file sharing, public access, search functionality, and mobile readiness.', 'social-networking', ARRAY['Social Networking'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "mriedmann/humhub:1.15.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "HumHub", "version": "latest", "description": "HumHub is a flexible open-source social network kit designed to facilitate communication and collaboration. It allows you to create your own customized social network, social intranet, or large social enterprise application tailored to your specific needs. Whether you're looking to boost your business, support your customers, educate your students, or organize your football club, HumHub provides the tools to make it happen. It features an intuitive user interface and a powerful module system that can be extended with third-party tools, your own creations, or existing software. With HumHub, you have full control over your server and data. The app also offers features like posts and updates, file sharing, liking and commenting, and 'Spaces' for group communication. You can extend your profile, create a portfolio, connect with others, and find people with specific skills. With its module system, you can modify anything on HumHub according to your requirements. The app also supports live updates, notifications, activity streams, dashboards, user profiles, groups, directories, file sharing, public access, search functionality, and mobile readiness.", "category": "social-networking", "tags": ["Social Networking"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "mriedmann/humhub:1.15.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://www.humhub.com"}, {"label": "Documentation", "url": "http://docs.humhub.org/"}, {"label": "Github", "url": "https://github.com/humhub/humhub/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "humhub", "port": "$PORT:80", "volumes": ["/var/www/localhost/htdocs/protected/config", "/var/www/localhost/htdocs/uploads", "/var/www/localhost/htdocs/protected/modules"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('huntarr', 'Huntarr', 'Huntarr is an automated media library enhancement tool that continuously monitors and improves your Radarr, Sonarr, and Lidarr collections. It works by periodically scanning your media libraries to identify missing items, failed downloads, and opportunities for quality upgrades, then automatically triggering searches to fill gaps and improve your collection. Huntarr acts as an intelligent automation layer on top of your existing *arr stack, ensuring your media library stays complete and up-to-date without manual intervention. The application features configurable scan intervals, customizable search triggers, support for multiple quality profiles, and detailed logging for tracking improvements. With its set-it-and-forget-it approach, Huntarr continuously works in the background to enhance your media collection by finding better quality versions, locating missing episodes or movies, and automatically requesting upgrades based on your configured quality preferences. The web interface provides visibility into scan history, search statistics, and library health metrics. Perfect for users who want their media libraries to automatically improve over time, home media server enthusiasts managing large collections, or anyone running Radarr/Sonarr/Lidarr who wants to ensure their libraries are always complete and optimized without constant manual searching.', 'media-automation', ARRAY['Media Automation', 'Radarr', 'Sonarr', 'Lidarr', 'Library Management', 'Media Server'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "huntarr/huntarr:9.2.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9705}}$JSON$::jsonb, $JSON${"metadata": {"name": "Huntarr", "version": "latest", "description": "Huntarr is an automated media library enhancement tool that continuously monitors and improves your Radarr, Sonarr, and Lidarr collections. It works by periodically scanning your media libraries to identify missing items, failed downloads, and opportunities for quality upgrades, then automatically triggering searches to fill gaps and improve your collection. Huntarr acts as an intelligent automation layer on top of your existing *arr stack, ensuring your media library stays complete and up-to-date without manual intervention. The application features configurable scan intervals, customizable search triggers, support for multiple quality profiles, and detailed logging for tracking improvements. With its set-it-and-forget-it approach, Huntarr continuously works in the background to enhance your media collection by finding better quality versions, locating missing episodes or movies, and automatically requesting upgrades based on your configured quality preferences. The web interface provides visibility into scan history, search statistics, and library health metrics. Perfect for users who want their media libraries to automatically improve over time, home media server enthusiasts managing large collections, or anyone running Radarr/Sonarr/Lidarr who wants to ensure their libraries are always complete and optimized without constant manual searching.", "category": "media-automation", "tags": ["Media Automation", "Radarr", "Sonarr", "Lidarr", "Library Management", "Media Server"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "huntarr/huntarr:9.2.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9705}}, "links": [{"label": "Website", "url": "https://huntarr.io/"}, {"label": "GitHub", "url": "https://github.com/plexguide/Huntarr.io"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/huntarr/huntarr"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "huntarr", "port": "$PORT:9705", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('hyperdx', 'HyperDX', 'HyperDX is an open-source observability platform that unifies logs, metrics, traces, and session replays in one place. Built on ClickHouse for blazing-fast performance, it allows you to search terabytes of events in seconds without complex syntax. Perfect for debugging production issues, monitoring application performance, and correlating user sessions with backend traces. Recently acquired by ClickHouse to accelerate the future of open-source observability.', 'observability', ARRAY['Observability', 'Monitoring', 'Logging', 'Tracing', 'APM', 'ClickHouse', 'OpenTelemetry', 'Session Replay'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "docker.hyperdx.io/hyperdx/hyperdx-local:2-beta"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4317}}$JSON$::jsonb, $JSON${"metadata": {"name": "HyperDX", "version": "latest", "description": "HyperDX is an open-source observability platform that unifies logs, metrics, traces, and session replays in one place. Built on ClickHouse for blazing-fast performance, it allows you to search terabytes of events in seconds without complex syntax. Perfect for debugging production issues, monitoring application performance, and correlating user sessions with backend traces. Recently acquired by ClickHouse to accelerate the future of open-source observability.", "category": "observability", "tags": ["Observability", "Monitoring", "Logging", "Tracing", "APM", "ClickHouse", "OpenTelemetry", "Session Replay"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "docker.hyperdx.io/hyperdx/hyperdx-local:2-beta"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4317}}, "links": [{"label": "HyperDX Official Site", "url": "https://www.hyperdx.io/"}, {"label": "Documentation", "url": "https://www.hyperdx.io/docs"}, {"label": "GitHub Repository", "url": "https://github.com/hyperdxio/hyperdx"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "hyperdx", "port": "$PORT:4317", "volumes": [], "extra_ports": ["8080:8080", "8123:8123"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('icecoder', 'ICEcoder', 'ICEcoder is a revolutionary browser-based code editor designed to streamline and modernize the process of website development. It allows you to code directly within your web browser, either online or offline, eliminating the need for multiple programs. With ICEcoder, you can test your sites on actual web servers and maintain them with ease after development, making for a fast and intelligent development process. It''s not just limited to online use - you can also use it as a desktop code editor, provided you have PHP 7.0+. It comes packed with a multitude of features and plugins to enhance your coding experience, including multiple cursors, 80+ highlighting themes, a find & replace builder, login security, coding assistance, visual code difference display, and database management with the Adminer plugin. The latest version, ICEcoder 8.1, introduces regex search on find and replace, double click tab to collapse file manager, active line number highlighting, and many more improvements and bug fixes.', 'code-hosting', ARRAY['Code Hosting', 'Developer Tools', 'Web Hosting'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/easypanel-community/docker-icecoder:8.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "ICEcoder", "version": "latest", "description": "ICEcoder is a revolutionary browser-based code editor designed to streamline and modernize the process of website development. It allows you to code directly within your web browser, either online or offline, eliminating the need for multiple programs. With ICEcoder, you can test your sites on actual web servers and maintain them with ease after development, making for a fast and intelligent development process. It's not just limited to online use - you can also use it as a desktop code editor, provided you have PHP 7.0+. It comes packed with a multitude of features and plugins to enhance your coding experience, including multiple cursors, 80+ highlighting themes, a find & replace builder, login security, coding assistance, visual code difference display, and database management with the Adminer plugin. The latest version, ICEcoder 8.1, introduces regex search on find and replace, double click tab to collapse file manager, active line number highlighting, and many more improvements and bug fixes.", "category": "code-hosting", "tags": ["Code Hosting", "Developer Tools", "Web Hosting"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/easypanel-community/docker-icecoder:8.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://icecoder.net"}, {"label": "Documentation", "url": "https://icecoder.net/manual"}, {"label": "Github", "url": "https://github.com/icecoder/ICEcoder"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "icecoder", "port": "$PORT:80", "volumes": ["/icecoder"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('ideon', 'Ideon', 'Ideon is a self-hosted visual workspace that lets teams organize repositories, notes, links, and files on an infinite collaborative canvas. It combines spatial organization with real-time sync so project context stays visible and connected.', 'workspace', ARRAY['Workspace', 'Collaboration', 'Productivity', 'Knowledge Management', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/3xpyth0n/ideon:v0.7.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Ideon", "version": "latest", "description": "Ideon is a self-hosted visual workspace that lets teams organize repositories, notes, links, and files on an infinite collaborative canvas. It combines spatial organization with real-time sync so project context stays visible and connected.", "category": "workspace", "tags": ["Workspace", "Collaboration", "Productivity", "Knowledge Management", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/3xpyth0n/ideon:v0.7.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://theideon.com/"}, {"label": "Documentation", "url": "https://github.com/3xpyth0n/ideon#readme"}, {"label": "GitHub", "url": "https://github.com/3xpyth0n/ideon"}], "instructions": "Deploy the template and wait for the database and app services to start, then open the app URL and create your account. Check the documentation for further configurations", "install": [{"docker": {"image": "$IMAGE", "name": "ideon", "port": "$PORT:3000", "volumes": ["/app/storage"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Deploy the template and wait for the database and app services to start, then open the app URL and create your account. Check the documentation for further configurations"}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('illa', 'Illa', 'Illa Cloud is a revolutionary browser-based code editor designed to streamline and modernize the process of website development. It allows you to code directly within your web browser, either online or offline, eliminating the need for multiple programs. With Illa Cloud, you can test your sites on actual web servers and maintain them with ease after development, making for a fast and intelligent development process. It''s not just limited to online use - you can also use it as a desktop code editor, provided you have PHP 7.0+. It comes packed with a multitude of features and plugins to enhance your coding experience, including multiple cursors, 80+ highlighting themes, a find & replace builder, login security, coding assistance, visual code difference display, and database management with the Adminer plugin. The latest version, Illa Cloud 8.1, introduces regex search on find and replace, double click tab to collapse file manager, active line number highlighting, and many more improvements and bug fixes.', 'cloud-ide', ARRAY['Cloud IDE', 'Developer Tools', 'Web Development'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "illasoft/illa-builder:v4.8.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 2022}}$JSON$::jsonb, $JSON${"metadata": {"name": "Illa", "version": "latest", "description": "Illa Cloud is a revolutionary browser-based code editor designed to streamline and modernize the process of website development. It allows you to code directly within your web browser, either online or offline, eliminating the need for multiple programs. With Illa Cloud, you can test your sites on actual web servers and maintain them with ease after development, making for a fast and intelligent development process. It's not just limited to online use - you can also use it as a desktop code editor, provided you have PHP 7.0+. It comes packed with a multitude of features and plugins to enhance your coding experience, including multiple cursors, 80+ highlighting themes, a find & replace builder, login security, coding assistance, visual code difference display, and database management with the Adminer plugin. The latest version, Illa Cloud 8.1, introduces regex search on find and replace, double click tab to collapse file manager, active line number highlighting, and many more improvements and bug fixes.", "category": "cloud-ide", "tags": ["Cloud IDE", "Developer Tools", "Web Development"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "illasoft/illa-builder:v4.8.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 2022}}, "links": [{"label": "Website", "url": "https://illacloud.com/"}, {"label": "Documentation", "url": "https://docs.illacloud.com/"}], "instructions": "Defualt username; root and password; password", "install": [{"docker": {"image": "$IMAGE", "name": "illa", "port": "$PORT:2022", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Defualt username; root and password; password"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('imagor-studio', 'Imagor Studio', 'Imagor Studio is a self-hosted image gallery and live editing web application designed for photographers, content creators, and digital artists. It provides a modern web interface for browsing, organizing, and editing your image collections with real-time image transformation capabilities. Built on top of the Imagor image processing server, the studio interface offers intuitive tools for image manipulation including resizing, cropping, filtering, and format conversion without modifying original files. All edits are performed on-demand using URL-based parameters, ensuring your source images remain untouched while generating optimized versions for different use cases. The application features a responsive gallery view for browsing images, a built-in editor with live preview, support for various image formats, and SQLite database for managing metadata and user preferences. With its lightweight architecture and flexible storage options, Imagor Studio enables you to maintain a private image library with professional editing capabilities accessible from any web browser. Perfect for photographers managing personal portfolios, content creators organizing media assets, web developers optimizing images for websites, or anyone needing a self-hosted alternative to cloud-based image management services with built-in editing tools.', 'image-gallery', ARRAY['Image Gallery', 'Image Editor', 'Photography', 'Media Management', 'Image Processing'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "shumc/imagor-studio:1.2.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Imagor Studio", "version": "latest", "description": "Imagor Studio is a self-hosted image gallery and live editing web application designed for photographers, content creators, and digital artists. It provides a modern web interface for browsing, organizing, and editing your image collections with real-time image transformation capabilities. Built on top of the Imagor image processing server, the studio interface offers intuitive tools for image manipulation including resizing, cropping, filtering, and format conversion without modifying original files. All edits are performed on-demand using URL-based parameters, ensuring your source images remain untouched while generating optimized versions for different use cases. The application features a responsive gallery view for browsing images, a built-in editor with live preview, support for various image formats, and SQLite database for managing metadata and user preferences. With its lightweight architecture and flexible storage options, Imagor Studio enables you to maintain a private image library with professional editing capabilities accessible from any web browser. Perfect for photographers managing personal portfolios, content creators organizing media assets, web developers optimizing images for websites, or anyone needing a self-hosted alternative to cloud-based image management services with built-in editing tools.", "category": "image-gallery", "tags": ["Image Gallery", "Image Editor", "Photography", "Media Management", "Image Processing"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "shumc/imagor-studio:1.2.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Website", "url": "https://imagor.net/"}, {"label": "Documentation", "url": "https://docs.studio.imagor.net/"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/shumc/imagor-studio"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "imagor-studio", "port": "$PORT:8080", "volumes": ["/app/data", "/app/gallery"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('imgproxy', 'imgproxy', 'imgproxy is a powerful app designed to optimize images for web use, making websites and apps run faster while saving storage and SaaS costs. It works by resizing and processing images on the fly, eliminating the need for disk space and reducing the cost of conforming all saved images to specific formats. imgproxy offers a wide range of features for editing images, including resizing, cropping, contrast adjustment, pixelization, saturation, rotating, and more. It also provides security features to protect against common attack vectors in image processing. With imgproxy, you can upload images directly to the cloud or your cluster and request images by specifying parameters in the request URL. The app uses the world’s fastest image processing library, libvips, ensuring quick processing and a small memory footprint. imgproxy Pro plans offer advanced features and vary by capacity and types of support.', 'image-processing', ARRAY['Image Processing', 'Optimization', 'Web Development'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "darthsim/imgproxy:v3.31.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "imgproxy", "version": "latest", "description": "imgproxy is a powerful app designed to optimize images for web use, making websites and apps run faster while saving storage and SaaS costs. It works by resizing and processing images on the fly, eliminating the need for disk space and reducing the cost of conforming all saved images to specific formats. imgproxy offers a wide range of features for editing images, including resizing, cropping, contrast adjustment, pixelization, saturation, rotating, and more. It also provides security features to protect against common attack vectors in image processing. With imgproxy, you can upload images directly to the cloud or your cluster and request images by specifying parameters in the request URL. The app uses the world\u2019s fastest image processing library, libvips, ensuring quick processing and a small memory footprint. imgproxy Pro plans offer advanced features and vary by capacity and types of support.", "category": "image-processing", "tags": ["Image Processing", "Optimization", "Web Development"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "darthsim/imgproxy:v3.31.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Website", "url": "https://imgproxy.net/"}, {"label": "Documentation", "url": "https://docs.imgproxy.net/"}, {"label": "Github", "url": "https://www.github.com/imgproxy/imgproxy"}], "instructions": "To generate a image URL you can use the following link: https://progapandist.github.io/imgproxy-form/#. Your Salt and Key can be found in the environment variables once you create the service. You can also find more environment variables here: https://docs.imgproxy.net/configuration", "install": [{"docker": {"image": "$IMAGE", "name": "imgproxy", "port": "$PORT:8080", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "To generate a image URL you can use the following link: https://progapandist.github.io/imgproxy-form/#. Your Salt and Key can be found in the environment variables once you create the service. You can also find more environment variables here: https://docs.imgproxy.net/configuration"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('immich', 'Immich', 'Immich is a self-hosted photo and video backup solution designed for individuals and families to store and manage their media files efficiently. It provides a modern interface with features like automatic uploads, deduplication, and powerful search capabilities. Immich ensures that you maintain full control over your media while offering a smooth and user-friendly experience.', 'media-backup', ARRAY['Media Backup', 'Self-Hosted', 'Machine Learning', 'Photo Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/immich-app/immich-server:v2.7.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Immich", "version": "latest", "description": "Immich is a self-hosted photo and video backup solution designed for individuals and families to store and manage their media files efficiently. It provides a modern interface with features like automatic uploads, deduplication, and powerful search capabilities. Immich ensures that you maintain full control over your media while offering a smooth and user-friendly experience.", "category": "media-backup", "tags": ["Media Backup", "Self-Hosted", "Machine Learning", "Photo Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/immich-app/immich-server:v2.7.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Documentation", "url": "https://immich.app/docs"}, {"label": "Github", "url": "https://github.com/immich-app/immich"}], "instructions": "Wait for the migration to complete.", "install": [{"docker": {"image": "$IMAGE", "name": "immich", "port": "$PORT:80", "volumes": ["/usr/src/app/upload"], "extra_ports": ["2283:2283"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Wait for the migration to complete."}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('inbox-zero', 'Inbox Zero', 'Inbox Zero is an email management platform that helps you clean your inbox, manage subscriptions, and automate email workflows.', 'email', ARRAY['Email', 'Productivity', 'AI', 'Self-Hosted', 'Automation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/elie222/inbox-zero:v1.10.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Inbox Zero", "version": "latest", "description": "Inbox Zero is an email management platform that helps you clean your inbox, manage subscriptions, and automate email workflows.", "category": "email", "tags": ["Email", "Productivity", "AI", "Self-Hosted", "Automation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/elie222/inbox-zero:v1.10.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "GitHub", "url": "https://github.com/elie222/inbox-zero"}, {"label": "Website", "url": "https://www.getinboxzero.com/"}], "instructions": "The Google Client ID and Secret are required for the OAuth flow to work. Select the LLM provider and fill the API keys for the provider.", "install": [{"docker": {"image": "$IMAGE", "name": "inbox-zero", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "The Google Client ID and Secret are required for the OAuth flow to work. Select the LLM provider and fill the API keys for the provider."}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('infisical', 'Infisical', 'Infisical is a robust, self-hosted platform designed for securely managing and accessing secrets, environment variables, and API keys. It provides a user-friendly interface, seamless integration with popular development and CI/CD tools, and advanced encryption to ensure the safety of sensitive data. With Infisical, you maintain full control over your secrets infrastructure, providing enhanced security and flexibility for your workflows.', 'secret-management', ARRAY['Secret Management', 'Self-Hosted', 'Security', 'Environment Variables', 'Encryption'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "infisical/infisical:v0.159.27"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Infisical", "version": "latest", "description": "Infisical is a robust, self-hosted platform designed for securely managing and accessing secrets, environment variables, and API keys. It provides a user-friendly interface, seamless integration with popular development and CI/CD tools, and advanced encryption to ensure the safety of sensitive data. With Infisical, you maintain full control over your secrets infrastructure, providing enhanced security and flexibility for your workflows.", "category": "secret-management", "tags": ["Secret Management", "Self-Hosted", "Security", "Environment Variables", "Encryption"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "infisical/infisical:v0.159.27"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Documentation", "url": "https://infisical.com/docs"}, {"label": "Github", "url": "https://github.com/Infisical/infisical"}], "instructions": "You may delete the migration service once the migration is completed.", "install": [{"docker": {"image": "$IMAGE", "name": "infisical", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "You may delete the migration service once the migration is completed."}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('influxdb', 'InfluxDB', 'InfluxDB is a time-series database designed to handle high write and query loads commonly required for real-time analytics. It’s optimized for storing timestamped data, making it ideal for monitoring metrics, tracking events, and handling sensor data. With its efficient storage engine, InfluxDB offers built-in support for data compression and compaction, allowing for efficient data retention and storage. This database supports SQL-like queries through InfluxQL, integrates seamlessly with popular data visualization tools like Grafana, and can handle data from IoT devices, DevOps monitoring, finance, and more.', 'time-series', ARRAY['Time-Series', 'Monitoring', 'Analytics', 'IoT', 'Database'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "influxdb:2.9.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8086}}$JSON$::jsonb, $JSON${"metadata": {"name": "InfluxDB", "version": "latest", "description": "InfluxDB is a time-series database designed to handle high write and query loads commonly required for real-time analytics. It\u2019s optimized for storing timestamped data, making it ideal for monitoring metrics, tracking events, and handling sensor data. With its efficient storage engine, InfluxDB offers built-in support for data compression and compaction, allowing for efficient data retention and storage. This database supports SQL-like queries through InfluxQL, integrates seamlessly with popular data visualization tools like Grafana, and can handle data from IoT devices, DevOps monitoring, finance, and more.", "category": "time-series", "tags": ["Time-Series", "Monitoring", "Analytics", "IoT", "Database"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "influxdb:2.9.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8086}}, "links": [{"label": "Website", "url": "https://www.influxdata.com/"}, {"label": "Documentation", "url": "https://docs.influxdata.com/"}, {"label": "Github", "url": "https://github.com/influxdata/influxdb"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "influxdb", "port": "$PORT:8086", "volumes": ["/var/lib/influxdb2", "/etc/influxdb2"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('invidious', 'Invidious', 'Invidious is a privacy-respecting alternative frontend for YouTube, designed to offer a lightweight, ad-free, and tracking-free viewing experience. It allows users to watch YouTube videos without being tracked, bypasses regional restrictions, and provides advanced features like video downloads, subscription management, and audio-only mode. Invidious supports multiple languages and offers a minimal interface with various themes for enhanced user experience. Additionally, it integrates seamlessly with other platforms by providing RSS feeds for subscriptions and API support.', 'privacy', ARRAY['Privacy', 'YouTube Alternative', 'Open Source', 'Video Streaming', 'Lightweight'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "quay.io/invidious/invidious:2026.02.16-e7f8b15"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Invidious", "version": "latest", "description": "Invidious is a privacy-respecting alternative frontend for YouTube, designed to offer a lightweight, ad-free, and tracking-free viewing experience. It allows users to watch YouTube videos without being tracked, bypasses regional restrictions, and provides advanced features like video downloads, subscription management, and audio-only mode. Invidious supports multiple languages and offers a minimal interface with various themes for enhanced user experience. Additionally, it integrates seamlessly with other platforms by providing RSS feeds for subscriptions and API support.", "category": "privacy", "tags": ["Privacy", "YouTube Alternative", "Open Source", "Video Streaming", "Lightweight"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "quay.io/invidious/invidious:2026.02.16-e7f8b15"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://invidious.io/"}, {"label": "Documentation", "url": "https://docs.invidious.io/"}, {"label": "GitHub", "url": "https://github.com/iv-org/invidious"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "invidious", "port": "$PORT:3000", "volumes": [], "extra_ports": ["5432:5432"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('invoiceninja', 'InvoiceNinja', 'Invoice Ninja is a powerful, open-source platform for managing invoices, quotes, and payments, specifically designed for freelancers and small businesses. It allows you to automate billing, track payments, and manage expenses effortlessly. With a user-friendly interface and robust feature set, Invoice Ninja supports multi-currency, recurring billing, and various payment gateways, providing a comprehensive invoicing solution.', 'invoicing', ARRAY['Invoicing', 'Payments', 'Billing', 'Expense Management', 'Open Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "invoiceninja/invoiceninja:5.13.19"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "InvoiceNinja", "version": "latest", "description": "Invoice Ninja is a powerful, open-source platform for managing invoices, quotes, and payments, specifically designed for freelancers and small businesses. It allows you to automate billing, track payments, and manage expenses effortlessly. With a user-friendly interface and robust feature set, Invoice Ninja supports multi-currency, recurring billing, and various payment gateways, providing a comprehensive invoicing solution.", "category": "invoicing", "tags": ["Invoicing", "Payments", "Billing", "Expense Management", "Open Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "invoiceninja/invoiceninja:5.13.19"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Github", "url": "https://github.com/invoiceninja/invoiceninja"}, {"label": "Documentation", "url": "https://invoiceninja.github.io/docs/"}, {"label": "Demo", "url": "https://demo.invoiceninja.com"}], "instructions": "Open the nginx domain to access InvoiceNinja", "install": [{"docker": {"image": "$IMAGE", "name": "invoiceninja", "port": "$PORT:80", "volumes": ["/var/www/app/storage", "/var/www/app/public", "/etc/nginx/conf.d/vhost.template", "/var/www/app/public"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Open the nginx domain to access InvoiceNinja"}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('invoiceshelf', 'InvoiceShelf', 'InvoiceShelf is an open-source web & mobile app that helps you track expenses, payments & create professional invoices & estimates. Web Application is made using Laravel & VueJS while the Mobile Apps are built using React Native.', 'finance', ARRAY['Finance', 'Invoice Management', 'Payment Tracking', 'Accounting'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "invoiceshelf/invoiceshelf:2.3.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "InvoiceShelf", "version": "latest", "description": "InvoiceShelf is an open-source web & mobile app that helps you track expenses, payments & create professional invoices & estimates. Web Application is made using Laravel & VueJS while the Mobile Apps are built using React Native.", "category": "finance", "tags": ["Finance", "Invoice Management", "Payment Tracking", "Accounting"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "invoiceshelf/invoiceshelf:2.3.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://invoiceshelf.com/"}, {"label": "Documentation", "url": "https://docs.invoiceshelf.com/"}, {"label": "Github", "url": "https://github.com/InvoiceShelf/InvoiceShelf"}], "instructions": "Visit the website to complete installation.", "install": [{"docker": {"image": "$IMAGE", "name": "invoiceshelf", "port": "$PORT:80", "volumes": ["/data", "/conf"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Visit the website to complete installation."}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('iobroker', 'ioBroker', 'ioBroker is a powerful open-source IoT platform that allows you to connect different smart home systems and devices into one platform. It supports a wide range of protocols and devices, making it a versatile solution for home automation.', 'iot', ARRAY['IoT', 'Home Automation', 'Smart Home', 'Automation', 'Self-hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "buanet/iobroker:v11.1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8081}}$JSON$::jsonb, $JSON${"metadata": {"name": "ioBroker", "version": "latest", "description": "ioBroker is a powerful open-source IoT platform that allows you to connect different smart home systems and devices into one platform. It supports a wide range of protocols and devices, making it a versatile solution for home automation.", "category": "iot", "tags": ["IoT", "Home Automation", "Smart Home", "Automation", "Self-hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "buanet/iobroker:v11.1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8081}}, "links": [{"label": "Website", "url": "https://www.iobroker.net"}, {"label": "Documentation", "url": "https://www.iobroker.net/#en/documentation"}, {"label": "GitHub", "url": "https://github.com/ioBroker/ioBroker"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/buanet/iobroker"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "iobroker", "port": "$PORT:8081", "volumes": ["/opt/iobroker"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('isaiah', 'Isaiah', 'Isaiah is a Docker-based application that provides a simple and efficient way to manage containerized applications. It offers a web interface for monitoring and controlling Docker containers with a clean, user-friendly interface. Isaiah allows you to view container status, logs, and resource usage, making it easier to maintain your Docker infrastructure.', 'docker', ARRAY['Docker', 'Container Management', 'Web Interface', 'Monitoring'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "mosswill/isaiah:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Isaiah", "version": "latest", "description": "Isaiah is a Docker-based application that provides a simple and efficient way to manage containerized applications. It offers a web interface for monitoring and controlling Docker containers with a clean, user-friendly interface. Isaiah allows you to view container status, logs, and resource usage, making it easier to maintain your Docker infrastructure.", "category": "docker", "tags": ["Docker", "Container Management", "Web Interface", "Monitoring"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "mosswill/isaiah:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Docker", "url": "https://hub.docker.com/r/mosswill/isaiah"}, {"label": "GitHub", "url": "https://github.com/will-moss/isaiah"}], "instructions": "Access the web interface to manage your Docker containers", "install": [{"docker": {"image": "$IMAGE", "name": "isaiah", "port": "$PORT:80", "volumes": ["/var/run/docker.sock"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Access the web interface to manage your Docker containers"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('isso', 'Isso', 'Isso is a lightweight commenting server designed to be a seamless alternative to Disqus. It is written in Python and JavaScript, and it allows users to leave comments on your website in a simple and straightforward manner. The app supports anonymous comments, preserving the identity of your users, and is easy to manage. Users can write comments in Markdown, and they also have the ability to edit or delete their own comments within a default time frame of 15 minutes. The app uses a SQLite backend, ensuring that your comments are not treated as Big Data. Additionally, it offers Disqus and WordPress import features, allowing you to migrate your existing comments without any hassle. The app is easily integrated into your website by embedding a single JavaScript file.', 'documentation', ARRAY['Documentation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/isso-comments/isso:0.14.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Isso", "version": "latest", "description": "Isso is a lightweight commenting server designed to be a seamless alternative to Disqus. It is written in Python and JavaScript, and it allows users to leave comments on your website in a simple and straightforward manner. The app supports anonymous comments, preserving the identity of your users, and is easy to manage. Users can write comments in Markdown, and they also have the ability to edit or delete their own comments within a default time frame of 15 minutes. The app uses a SQLite backend, ensuring that your comments are not treated as Big Data. Additionally, it offers Disqus and WordPress import features, allowing you to migrate your existing comments without any hassle. The app is easily integrated into your website by embedding a single JavaScript file.", "category": "documentation", "tags": ["Documentation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/isso-comments/isso:0.14.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Documentation", "url": "https://isso-comments.de/docs/"}, {"label": "Github", "url": "https://github.com/posativ/isso"}], "instructions": "Go to /admin for administration interface", "install": [{"docker": {"image": "$IMAGE", "name": "isso", "port": "$PORT:8080", "volumes": ["/config", "/db", "/tmp", "/config/isso.cfg"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Go to /admin for administration interface"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('itop', 'iTop', 'iTop is a self-hosted, open-source IT service management (ITSM) solution designed for businesses and organizations to manage their IT assets, incidents, and workflows efficiently. It provides a modern web interface for tracking and organizing IT infrastructure, support tickets, change requests, and service catalogs. iTop includes role-based user management, real-time notifications, and detailed reporting tools to help IT teams maintain operational efficiency. It supports multiple authentication methods, including LDAP and SAML, making it suitable for enterprise environments. Additionally, iTop offers API access for integration with third-party tools and automation of IT processes. Its containerized deployment ensures scalability and easy management.', 'itsm', ARRAY['ITSM', 'IT Asset Management', 'Help Desk', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "vbkunin/itop:3.2.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "iTop", "version": "latest", "description": "iTop is a self-hosted, open-source IT service management (ITSM) solution designed for businesses and organizations to manage their IT assets, incidents, and workflows efficiently. It provides a modern web interface for tracking and organizing IT infrastructure, support tickets, change requests, and service catalogs. iTop includes role-based user management, real-time notifications, and detailed reporting tools to help IT teams maintain operational efficiency. It supports multiple authentication methods, including LDAP and SAML, making it suitable for enterprise environments. Additionally, iTop offers API access for integration with third-party tools and automation of IT processes. Its containerized deployment ensures scalability and easy management.", "category": "itsm", "tags": ["ITSM", "IT Asset Management", "Help Desk", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "vbkunin/itop:3.2.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Documentation", "url": "https://www.itophub.io/wiki/page"}, {"label": "Github", "url": "https://github.com/Combodo/iTop"}], "instructions": "On the installation wizard, please connect to the DB.", "install": [{"docker": {"image": "$IMAGE", "name": "itop", "port": "$PORT:80", "volumes": ["/var/www/html/"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "On the installation wizard, please connect to the DB."}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('itsmng', 'ITSM-NG', 'ITSM-NG is a free and open-source IT Service Management (ITSM) solution designed to help organizations manage their IT services, assets, and support operations efficiently. Born from the GLPI project, ITSM-NG offers a comprehensive ITIL-aligned platform for incident management, problem management, change management, asset tracking, and service catalog. It features a modern interface, customizable workflows, automated ticket routing, SLA management, knowledge base, and extensive reporting capabilities. ITSM-NG supports multi-tenancy, LDAP/Active Directory integration, and provides a powerful plugin system for extending functionality. Perfect for IT teams seeking a professional, self-hosted solution for managing their IT operations and improving service delivery.', 'itsm', ARRAY['ITSM', 'Service Management', 'Helpdesk', 'Asset Management', 'ITIL'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "itsmng/itsm-ng:2.1.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "ITSM-NG", "version": "latest", "description": "ITSM-NG is a free and open-source IT Service Management (ITSM) solution designed to help organizations manage their IT services, assets, and support operations efficiently. Born from the GLPI project, ITSM-NG offers a comprehensive ITIL-aligned platform for incident management, problem management, change management, asset tracking, and service catalog. It features a modern interface, customizable workflows, automated ticket routing, SLA management, knowledge base, and extensive reporting capabilities. ITSM-NG supports multi-tenancy, LDAP/Active Directory integration, and provides a powerful plugin system for extending functionality. Perfect for IT teams seeking a professional, self-hosted solution for managing their IT operations and improving service delivery.", "category": "itsm", "tags": ["ITSM", "Service Management", "Helpdesk", "Asset Management", "ITIL"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "itsmng/itsm-ng:2.1.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://www.itsm-ng.org/"}, {"label": "Github", "url": "https://github.com/itsmng/itsm-ng"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/itsmng/itsm-ng"}], "instructions": "Default login credentials are itsm/itsm", "install": [{"docker": {"image": "$IMAGE", "name": "itsmng", "port": "$PORT:80", "volumes": ["/var/www/itsm-ng/config", "/var/www/itsm-ng/plugins", "/var/www/itsm-ng/files"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Default login credentials are itsm/itsm"}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('ittools', 'It Tools', 'IT-Tools is a comprehensive suite of handy tools designed to assist developers in their day-to-day tasks. It includes a wide range of features such as Crypto Token generator, Hash text Bcrypt, UUIDs v4 generator, Encrypt/Decrypt text, BIP39 passphrase generator, and many more. The app also offers various converters like Date-time converter, Integer base converter, Roman numeral converter, and Base64 string encoder/decoder among others. It provides a platform for developers to generate QR codes, SVG placeholders, and even record videos from their camera. With additional features like Git cheatsheet, Random port generator, Crontab generator, and JSON prettify and format, IT-Tools is a one-stop solution for all developer needs.', 'developer-tools', ARRAY['Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "corentinth/it-tools:2024.10.22-7ca5933"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "It Tools", "version": "latest", "description": "IT-Tools is a comprehensive suite of handy tools designed to assist developers in their day-to-day tasks. It includes a wide range of features such as Crypto Token generator, Hash text Bcrypt, UUIDs v4 generator, Encrypt/Decrypt text, BIP39 passphrase generator, and many more. The app also offers various converters like Date-time converter, Integer base converter, Roman numeral converter, and Base64 string encoder/decoder among others. It provides a platform for developers to generate QR codes, SVG placeholders, and even record videos from their camera. With additional features like Git cheatsheet, Random port generator, Crontab generator, and JSON prettify and format, IT-Tools is a one-stop solution for all developer needs.", "category": "developer-tools", "tags": ["Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "corentinth/it-tools:2024.10.22-7ca5933"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://it-tools.tech"}, {"label": "Github", "url": "https://github.com/CorentinTh/it-tools"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "ittools", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('jackett', 'Jackett', 'Jackett is a versatile, open-source indexer proxy for torrenting and Usenet, enabling users to integrate popular trackers with applications like Sonarr, Radarr, and more. Designed to be lightweight and efficient, Jackett streamlines the process of accessing trackers, offering a seamless experience for managing and automating downloads.', 'torrenting', ARRAY['Torrenting', 'Usenet', 'Indexer Proxy', 'Open-Source', 'Automation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/jackett:0.24.1815"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9117}}$JSON$::jsonb, $JSON${"metadata": {"name": "Jackett", "version": "latest", "description": "Jackett is a versatile, open-source indexer proxy for torrenting and Usenet, enabling users to integrate popular trackers with applications like Sonarr, Radarr, and more. Designed to be lightweight and efficient, Jackett streamlines the process of accessing trackers, offering a seamless experience for managing and automating downloads.", "category": "torrenting", "tags": ["Torrenting", "Usenet", "Indexer Proxy", "Open-Source", "Automation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/jackett:0.24.1815"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9117}}, "links": [{"label": "Website", "url": "https://jackett.sh/"}, {"label": "Github", "url": "https://github.com/Jackett/Jackett"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "jackett", "port": "$PORT:9117", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('jaeger', 'Jaeger', 'Jaeger is an end-to-end distributed tracing system used for monitoring and troubleshooting microservices-based architectures. It helps developers track requests across complex systems, visualize latencies, and diagnose performance issues. Jaeger supports multiple storage backends and provides powerful querying and visualization capabilities. It is designed to be scalable and production-ready, making it a valuable tool for debugging and optimizing distributed applications.', 'observability', ARRAY['Observability', 'Monitoring', 'Distributed Tracing'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "jaegertracing/all-in-one:1.76.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5775}}$JSON$::jsonb, $JSON${"metadata": {"name": "Jaeger", "version": "latest", "description": "Jaeger is an end-to-end distributed tracing system used for monitoring and troubleshooting microservices-based architectures. It helps developers track requests across complex systems, visualize latencies, and diagnose performance issues. Jaeger supports multiple storage backends and provides powerful querying and visualization capabilities. It is designed to be scalable and production-ready, making it a valuable tool for debugging and optimizing distributed applications.", "category": "observability", "tags": ["Observability", "Monitoring", "Distributed Tracing"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "jaegertracing/all-in-one:1.76.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5775}}, "links": [{"label": "Website", "url": "https://www.jaegertracing.io"}, {"label": "Documentation", "url": "https://www.jaegertracing.io/docs/latest"}, {"label": "Github", "url": "https://github.com/jaegertracing/jaeger"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "jaeger", "port": "$PORT:5775", "volumes": ["/tmp"], "extra_ports": ["5778:5778", "6831:6831", "6832:6832", "9411:9411", "14268:14268", "16686:16686"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('jellyfin', 'Jellyfin', 'Jellyfin is a free software media system that allows you to take full control of your media. It enables you to collect, manage, and stream your media from your own server to any device. With Jellyfin, you can enjoy your entire movie collection, watch your favorite shows, listen to your music, and even read your books and comics. It also offers features for live TV and DVR, allowing you to watch TV and set automatic recordings to expand your library. Jellyfin also provides a SyncPlay feature, making remote movie nights easier than ever. The app is available on most popular platforms, ensuring your media is ready to follow you wherever you go. Jellyfin is licensed under the GNU GPL, meaning you can use, study, modify, build, and distribute it for free. It is a privacy-focused solution with no tracking or central servers collecting your data.', 'media', ARRAY['Media'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/jellyfin:10.11.8"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8096}}$JSON$::jsonb, $JSON${"metadata": {"name": "Jellyfin", "version": "latest", "description": "Jellyfin is a free software media system that allows you to take full control of your media. It enables you to collect, manage, and stream your media from your own server to any device. With Jellyfin, you can enjoy your entire movie collection, watch your favorite shows, listen to your music, and even read your books and comics. It also offers features for live TV and DVR, allowing you to watch TV and set automatic recordings to expand your library. Jellyfin also provides a SyncPlay feature, making remote movie nights easier than ever. The app is available on most popular platforms, ensuring your media is ready to follow you wherever you go. Jellyfin is licensed under the GNU GPL, meaning you can use, study, modify, build, and distribute it for free. It is a privacy-focused solution with no tracking or central servers collecting your data.", "category": "media", "tags": ["Media"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/jellyfin:10.11.8"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8096}}, "links": [{"label": "Website", "url": "https://jellyfin.org/"}, {"label": "Documentation", "url": "https://jellyfin.org/docs"}, {"label": "Github", "url": "https://github.com/jellyfin/jellyfin"}], "instructions": "Jellyfin takes a few minutes to get ready. Sit back, relax, and get some popcorn!", "install": [{"docker": {"image": "$IMAGE", "name": "jellyfin", "port": "$PORT:8096", "volumes": ["/data/tvshows", "/data/movies", "/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Jellyfin takes a few minutes to get ready. Sit back, relax, and get some popcorn!"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('jellyseerr', 'Jellyseerr', 'Overseerr is a powerful application designed to streamline the process of managing your media library. It offers full Plex integration, allowing you to log in and manage user access with Plex, and syncs with your Plex library to show what titles you already have. The app also integrates with Sonarr and Radarr, with plans for more services in the future. Overseerr features an easy-to-use request system, letting users request individual seasons or movies through a clean, user-friendly interface. The app also boasts a simple request management UI, making it easy to approve recent requests without having to navigate through the app. It also offers a granular permission system and localization into other languages. The mobile-friendly design ensures you can approve requests on the go. Jellyseerr, a fork of Overseerr, extends these features to Jellyfin and Emby media servers, offering full integration with these platforms. It also supports movies, shows, mixed libraries, and allows for easy integration with your existing services. Jellyseerr also offers a customizable request system, a simple request management UI, a granular permission system, and support for various notification agents.', 'media', ARRAY['Media', 'Request Management', 'Integration'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "fallenbagel/jellyseerr:sha-42eec24"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5055}}$JSON$::jsonb, $JSON${"metadata": {"name": "Jellyseerr", "version": "latest", "description": "Overseerr is a powerful application designed to streamline the process of managing your media library. It offers full Plex integration, allowing you to log in and manage user access with Plex, and syncs with your Plex library to show what titles you already have. The app also integrates with Sonarr and Radarr, with plans for more services in the future. Overseerr features an easy-to-use request system, letting users request individual seasons or movies through a clean, user-friendly interface. The app also boasts a simple request management UI, making it easy to approve recent requests without having to navigate through the app. It also offers a granular permission system and localization into other languages. The mobile-friendly design ensures you can approve requests on the go. Jellyseerr, a fork of Overseerr, extends these features to Jellyfin and Emby media servers, offering full integration with these platforms. It also supports movies, shows, mixed libraries, and allows for easy integration with your existing services. Jellyseerr also offers a customizable request system, a simple request management UI, a granular permission system, and support for various notification agents.", "category": "media", "tags": ["Media", "Request Management", "Integration"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "fallenbagel/jellyseerr:sha-42eec24"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5055}}, "links": [{"label": "Documentation", "url": "https://github.com/Fallenbagel/jellyseerr/tree/develop/docs"}, {"label": "Github", "url": "https://github.com/Fallenbagel/jellyseerr"}], "instructions": "none", "install": [{"docker": {"image": "$IMAGE", "name": "jellyseerr", "port": "$PORT:5055", "volumes": ["/app/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "none"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('jenkins', 'Jenkins', 'Jenkins is an open source automation server. It helps automate the parts of software development related to building, testing, and deploying, facilitating continuous integration, and continuous delivery. It is a server-based system that runs in servlet containers such as Apache Tomcat.', 'automation', ARRAY['Automation', 'CI/CD', 'DevOps', 'Jenkins'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "jenkins/jenkins:2.562"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Jenkins", "version": "latest", "description": "Jenkins is an open source automation server. It helps automate the parts of software development related to building, testing, and deploying, facilitating continuous integration, and continuous delivery. It is a server-based system that runs in servlet containers such as Apache Tomcat.", "category": "automation", "tags": ["Automation", "CI/CD", "DevOps", "Jenkins"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "jenkins/jenkins:2.562"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Website", "url": "https://www.jenkins.io/"}, {"label": "Documentation", "url": "https://www.jenkins.io/doc/book/"}, {"label": "Github", "url": "https://github.com/jenkinsci/jenkins"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "jenkins", "port": "$PORT:8080", "volumes": ["/var/jenkins_home", "/var/run/docker.sock"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('jirafeau', 'Jirafeau', 'Jirafeau is an open-source software designed for simple and efficient file sharing. It operates on a ''one-click-filesharing'' principle, where you select your file, upload it, and share a link. The app allows you to send large files without any size limit, thanks to the HTML5 file API. It also provides a real-time progress report, showing speed, percentage, and remaining upload time. Jirafeau offers optional password protection for both uploading and downloading, and you can set an expiration time for downloads. The app also has a self-destruct feature, which deletes the file after the first download. It uses base 64 encoding to shorten URLs and allows for maximal upload size configuration. Jirafeau also features optional data encryption and a small administration interface.', 'file-management', ARRAY['File Management', 'Data Science'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "jgeusebroek/jirafeau:20221008"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Jirafeau", "version": "latest", "description": "Jirafeau is an open-source software designed for simple and efficient file sharing. It operates on a 'one-click-filesharing' principle, where you select your file, upload it, and share a link. The app allows you to send large files without any size limit, thanks to the HTML5 file API. It also provides a real-time progress report, showing speed, percentage, and remaining upload time. Jirafeau offers optional password protection for both uploading and downloading, and you can set an expiration time for downloads. The app also has a self-destruct feature, which deletes the file after the first download. It uses base 64 encoding to shorten URLs and allows for maximal upload size configuration. Jirafeau also features optional data encryption and a small administration interface.", "category": "file-management", "tags": ["File Management", "Data Science"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "jgeusebroek/jirafeau:20221008"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Github", "url": "https://gitlab.com/mojo42/Jirafeau"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "jirafeau", "port": "$PORT:80", "volumes": ["/data", "/cfg", "/jirafeau"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('joomla', 'Joomla', 'Joomla is a powerful, open-source content management system (CMS) that allows users to build dynamic websites and applications. It offers a user-friendly interface, extensive customization options through templates and extensions, and robust security features. Joomla is highly scalable and supports multilingual content, making it a versatile choice for businesses, organizations, and personal websites. The application is accessible via your host on standard web ports and is easy to deploy using containers.', 'cms', ARRAY['CMS', 'Website Builder', 'Open-Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "joomla:6.1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Joomla", "version": "latest", "description": "Joomla is a powerful, open-source content management system (CMS) that allows users to build dynamic websites and applications. It offers a user-friendly interface, extensive customization options through templates and extensions, and robust security features. Joomla is highly scalable and supports multilingual content, making it a versatile choice for businesses, organizations, and personal websites. The application is accessible via your host on standard web ports and is easy to deploy using containers.", "category": "cms", "tags": ["CMS", "Website Builder", "Open-Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "joomla:6.1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Documentation", "url": "https://docs.joomla.org"}, {"label": "Github", "url": "https://github.com/joomla/joomla-cms"}], "instructions": "Complete the Installation Wizard.", "install": [{"docker": {"image": "$IMAGE", "name": "joomla", "port": "$PORT:80", "volumes": ["/var/www/html"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Complete the Installation Wizard."}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('joplin', 'Joplin', 'Joplin is an open-source note-taking application that allows you to capture your thoughts and access them securely from any device. It supports multimedia notes, including images, videos, PDFs, and audio files, and even allows the creation of math expressions and diagrams. With Joplin Cloud, you can share your notes and collaborate with others. The app also features a web clipper extension for saving web pages or screenshots as notes. Joplin can be customized with plugins, themes, and multiple text editors, and it synchronizes with various services, including Joplin Cloud, Dropbox, and OneDrive. All notes are saved in an open format and secured with end-to-end encryption.', 'notes', ARRAY['Notes', 'Productivity', 'Developer Tools', 'Documentation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "joplin/server:3.6.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Joplin", "version": "latest", "description": "Joplin is an open-source note-taking application that allows you to capture your thoughts and access them securely from any device. It supports multimedia notes, including images, videos, PDFs, and audio files, and even allows the creation of math expressions and diagrams. With Joplin Cloud, you can share your notes and collaborate with others. The app also features a web clipper extension for saving web pages or screenshots as notes. Joplin can be customized with plugins, themes, and multiple text editors, and it synchronizes with various services, including Joplin Cloud, Dropbox, and OneDrive. All notes are saved in an open format and secured with end-to-end encryption.", "category": "notes", "tags": ["Notes", "Productivity", "Developer Tools", "Documentation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "joplin/server:3.6.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://joplinapp.org/"}, {"label": "Github", "url": "https://github.com/laurent22/joplin/"}, {"label": "Docker", "url": "https://hub.docker.com/r/joplin/server"}], "instructions": "Default login email: admin@localhost, password: admin", "install": [{"docker": {"image": "$IMAGE", "name": "joplin", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Default login email: admin@localhost, password: admin"}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('journiv', 'Journiv', 'Journiv is a self-hosted journaling and note-taking application designed for personal reflection and documentation. The application provides a secure, private platform for writing and organizing your thoughts, experiences, and memories. Built with a modern web interface, Journiv offers features for creating journal entries, organizing content with tags and categories, and searching through your journal history. The application uses SQLite for lightweight data storage, Redis for caching and background task processing, and Celery for asynchronous operations. With support for rich text editing, file attachments, and export capabilities, Journiv helps you maintain a comprehensive digital journal. The platform prioritizes privacy and data ownership, ensuring all your journal entries remain on your own infrastructure. Perfect for individuals who want a private journaling solution, writers maintaining personal writing projects, users seeking a self-hosted alternative to cloud-based note-taking services, or anyone who values complete control over their personal reflections and memories.', 'journal', ARRAY['Journal', 'Note Taking', 'Writing', 'Self-Hosted', 'Personal'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "swalabtech/journiv-app:0.1.0-beta.22"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Journiv", "version": "latest", "description": "Journiv is a self-hosted journaling and note-taking application designed for personal reflection and documentation. The application provides a secure, private platform for writing and organizing your thoughts, experiences, and memories. Built with a modern web interface, Journiv offers features for creating journal entries, organizing content with tags and categories, and searching through your journal history. The application uses SQLite for lightweight data storage, Redis for caching and background task processing, and Celery for asynchronous operations. With support for rich text editing, file attachments, and export capabilities, Journiv helps you maintain a comprehensive digital journal. The platform prioritizes privacy and data ownership, ensuring all your journal entries remain on your own infrastructure. Perfect for individuals who want a private journaling solution, writers maintaining personal writing projects, users seeking a self-hosted alternative to cloud-based note-taking services, or anyone who values complete control over their personal reflections and memories.", "category": "journal", "tags": ["Journal", "Note Taking", "Writing", "Self-Hosted", "Personal"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "swalabtech/journiv-app:0.1.0-beta.22"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}, "links": [{"label": "Website", "url": "https://journiv.com"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/swalabtech/journiv-app"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "journiv", "port": "$PORT:8000", "volumes": ["/data", "/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('jsreport', 'JSReport', 'JSReport is an open-source reporting platform designed for developers to generate, manage, and customize reports using JavaScript. It provides a powerful templating engine, flexible rendering, and a web-based studio for designing reports. JSReport supports multiple output formats, including PDF, Excel, HTML, and more, making it ideal for businesses and applications that require automated document generation. It can be self-hosted and integrated with various databases and applications for seamless reporting.', 'reporting', ARRAY['Reporting', 'PDF Generation', 'Data Visualization', 'Business Intelligence', 'Self-Hosting'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "jsreport/jsreport:4.13.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5488}}$JSON$::jsonb, $JSON${"metadata": {"name": "JSReport", "version": "latest", "description": "JSReport is an open-source reporting platform designed for developers to generate, manage, and customize reports using JavaScript. It provides a powerful templating engine, flexible rendering, and a web-based studio for designing reports. JSReport supports multiple output formats, including PDF, Excel, HTML, and more, making it ideal for businesses and applications that require automated document generation. It can be self-hosted and integrated with various databases and applications for seamless reporting.", "category": "reporting", "tags": ["Reporting", "PDF Generation", "Data Visualization", "Business Intelligence", "Self-Hosting"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "jsreport/jsreport:4.13.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5488}}, "links": [{"label": "Website", "url": "https://jsreport.net/"}, {"label": "Documentation", "url": "https://jsreport.net/learn"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "jsreport", "port": "$PORT:5488", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('jumpserver', 'JumpServer', 'JumpServer is an open-source, enterprise-grade bastion host and privileged access management (PAM) solution. It provides secure access to servers, databases, and other IT resources through a web-based interface. JumpServer supports multiple authentication methods, session recording, command auditing, and fine-grained access control. It''s designed to help organizations manage and monitor privileged access to critical infrastructure while maintaining security compliance and audit trails.', 'bastion-host', ARRAY['Bastion Host', 'PAM', 'Privileged Access Management', 'Security', 'SSH', 'RDP', 'Session Recording', 'Audit', 'Compliance', 'Access Control', 'Web Interface', 'Enterprise'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "jumpserver/jms_all:v4.10.16"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "JumpServer", "version": "latest", "description": "JumpServer is an open-source, enterprise-grade bastion host and privileged access management (PAM) solution. It provides secure access to servers, databases, and other IT resources through a web-based interface. JumpServer supports multiple authentication methods, session recording, command auditing, and fine-grained access control. It's designed to help organizations manage and monitor privileged access to critical infrastructure while maintaining security compliance and audit trails.", "category": "bastion-host", "tags": ["Bastion Host", "PAM", "Privileged Access Management", "Security", "SSH", "RDP", "Session Recording", "Audit", "Compliance", "Access Control", "Web Interface", "Enterprise"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "jumpserver/jms_all:v4.10.16"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "GitHub", "url": "https://github.com/jumpserver/jumpserver"}, {"label": "Documentation", "url": "https://docs.jumpserver.org/"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/jumpserver/jms_all"}], "instructions": "Login using the default admin credentials; admin/ChangeMe.", "install": [{"docker": {"image": "$IMAGE", "name": "jumpserver", "port": "$PORT:80", "volumes": ["/opt/jumpserver/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Login using the default admin credentials; admin/ChangeMe."}, "services": {"mysql": {"type": "mysql", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('jupyter-notebook', 'JupyterNotebook', 'Jupyter Notebook is a popular, free, and open-source web application that allows you to create and share documents containing live code, equations, visualizations, and narrative text. It supports numerous programming languages and is widely used for data cleaning and transformation, numerical simulation, statistical modeling, data visualization, machine learning, and much more. The app is designed to be accessed via your web browser, providing an interactive interface for easy development and experimentation. It supports hardware acceleration for enhanced performance in computational tasks. The app is compatible with multiple architectures, ensuring it can run on various systems.', 'data-science', ARRAY['Data Science', 'Machine Learning', 'Visualization', 'Statistical Modeling', 'Numerical Simulation', 'Interactive Computing', 'Data Analysis'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 8888}}$JSON$::jsonb, $JSON${"metadata": {"name": "JupyterNotebook", "version": "latest", "description": "Jupyter Notebook is a popular, free, and open-source web application that allows you to create and share documents containing live code, equations, visualizations, and narrative text. It supports numerous programming languages and is widely used for data cleaning and transformation, numerical simulation, statistical modeling, data visualization, machine learning, and much more. The app is designed to be accessed via your web browser, providing an interactive interface for easy development and experimentation. It supports hardware acceleration for enhanced performance in computational tasks. The app is compatible with multiple architectures, ensuring it can run on various systems.", "category": "data-science", "tags": ["Data Science", "Machine Learning", "Visualization", "Statistical Modeling", "Numerical Simulation", "Interactive Computing", "Data Analysis"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 8888}}, "links": [{"label": "Documentation", "url": "https://jupyter-notebook.readthedocs.io/en/stable/"}, {"label": "Github", "url": "https://github.com/jupyter/notebook"}], "instructions": "Run \"jupyter server list\" in the console of the service and copy the token. Then either login with the token or create a password using that.", "install": [{"docker": {"image": "$IMAGE", "name": "jupyter-notebook", "port": "$PORT:8888", "volumes": ["/home/jovyan/work"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Run \"jupyter server list\" in the console of the service and copy the token. Then either login with the token or create a password using that."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('kan', 'Kan', 'Kan is a self-hosted Kanban app (Trello-style) built with Next.js, tRPC, Better Auth, and PostgreSQL. It supports boards, workspaces, labels, comments, Trello import, and optional email, Redis, S3, and OAuth. The published web container does not apply database migrations on startup; upstream expects a separate migrate image (Drizzle) to run before the web process, matching their Docker Compose stack.', 'project-management', ARRAY['Project Management', 'Kanban', 'Task Tracking', 'Self-hosted', 'Next.js', 'PostgreSQL', 'Team Collaboration'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/kanbn/kan:0.5.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Kan", "version": "latest", "description": "Kan is a self-hosted Kanban app (Trello-style) built with Next.js, tRPC, Better Auth, and PostgreSQL. It supports boards, workspaces, labels, comments, Trello import, and optional email, Redis, S3, and OAuth. The published web container does not apply database migrations on startup; upstream expects a separate migrate image (Drizzle) to run before the web process, matching their Docker Compose stack.", "category": "project-management", "tags": ["Project Management", "Kanban", "Task Tracking", "Self-hosted", "Next.js", "PostgreSQL", "Team Collaboration"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/kanbn/kan:0.5.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://kan.bn"}, {"label": "Documentation", "url": "https://docs.kan.bn/"}, {"label": "GitHub", "url": "https://github.com/kanbn/kan"}, {"label": "Container registry (GHCR)", "url": "https://github.com/kanbn/kan/pkgs/container/kan"}], "instructions": "Deploy order matches upstream: Postgres \u2192 migrate (kan-migrate, runs\n`drizzle-kit migrate` once) \u2192 web. If the web app errors on first boot,\nwait for the migrate service to finish successfully, then restart the web service.\nSecrets: BETTER_AUTH_SECRET is generated for you; keep it stable across\nrestarts. Auth: With defaults, use sign-up on the login page unless you set\nNEXT_PUBLIC_DISABLE_SIGN_UP in env (see docs). Optional: Redis, SMTP, S3, and\nOAuth env vars are documented upstream.\n", "install": [{"docker": {"image": "$IMAGE", "name": "kan", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Deploy order matches upstream: Postgres \u2192 migrate (kan-migrate, runs\n`drizzle-kit migrate` once) \u2192 web. If the web app errors on first boot,\nwait for the migrate service to finish successfully, then restart the web service.\nSecrets: BETTER_AUTH_SECRET is generated for you; keep it stable across\nrestarts. Auth: With defaults, use sign-up on the login page unless you set\nNEXT_PUBLIC_DISABLE_SIGN_UP in env (see docs). Optional: Redis, SMTP, S3, and\nOAuth env vars are documented upstream.\n"}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('kanboard', 'Kanboard', 'Kanboard is a free and open-source project management software that utilizes the Kanban methodology. It provides a visual and clear overview of your tasks, allowing you to easily manage your projects by dragging and dropping tasks between columns. The app is designed with simplicity and minimalism in mind, limiting the number of features to maintain focus on your work. It also includes a search and filter function, enabling you to quickly find tasks using a simple query language. Tasks can be broken down into sub-tasks, with the ability to add comments, documents, and change various aspects such as color, category, assignee, and due date. Kanboard also offers automated actions to streamline your workflow, eliminating the need for repetitive manual tasks. It supports multiple authentication backends and is translated in over 30 languages.', 'project-management', ARRAY['Project Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "kanboard/kanboard:v1.2.52"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Kanboard", "version": "latest", "description": "Kanboard is a free and open-source project management software that utilizes the Kanban methodology. It provides a visual and clear overview of your tasks, allowing you to easily manage your projects by dragging and dropping tasks between columns. The app is designed with simplicity and minimalism in mind, limiting the number of features to maintain focus on your work. It also includes a search and filter function, enabling you to quickly find tasks using a simple query language. Tasks can be broken down into sub-tasks, with the ability to add comments, documents, and change various aspects such as color, category, assignee, and due date. Kanboard also offers automated actions to streamline your workflow, eliminating the need for repetitive manual tasks. It supports multiple authentication backends and is translated in over 30 languages.", "category": "project-management", "tags": ["Project Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "kanboard/kanboard:v1.2.52"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://kanboard.org/"}, {"label": "Documentation", "url": "https://docs.kanboard.org/en/latest/"}, {"label": "Github", "url": "https://github.com/kanboard/kanboard"}], "instructions": "Default login username: admin, password: admin", "install": [{"docker": {"image": "$IMAGE", "name": "kanboard", "port": "$PORT:80", "volumes": ["/var/www/app/data", "/var/www/app/plugins", "/etc/nginx/ssl"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Default login username: admin, password: admin"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('kapowarr', 'Kapowarr', 'Kapowarr is a comic book management system that helps you organize and manage your digital comic collection. It provides a user-friendly interface for browsing, reading, and managing your comics.', 'comics', ARRAY['Comics', 'Manga', 'Digital Library', 'Reading', 'Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "mrcas/kapowarr:v1.3.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5656}}$JSON$::jsonb, $JSON${"metadata": {"name": "Kapowarr", "version": "latest", "description": "Kapowarr is a comic book management system that helps you organize and manage your digital comic collection. It provides a user-friendly interface for browsing, reading, and managing your comics.", "category": "comics", "tags": ["Comics", "Manga", "Digital Library", "Reading", "Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "mrcas/kapowarr:v1.3.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5656}}, "links": [{"label": "Github", "url": "https://github.com/Casvt/Kapowarr"}, {"label": "Documentation", "url": "https://casvt.github.io/Kapowarr/"}], "instructions": "Open Kapowarr on the given domain, then go to settings and confirm your library path points to `/comics-1` and your temporary download path points to `/app/temp_downloads`. Add your series and import existing files into the library, then configure metadata and download preferences from the web UI.", "install": [{"docker": {"image": "$IMAGE", "name": "kapowarr", "port": "$PORT:5656", "volumes": ["/app/db", "/app/temp_downloads", "/comics-1"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Open Kapowarr on the given domain, then go to settings and confirm your library path points to `/comics-1` and your temporary download path points to `/app/temp_downloads`. Add your series and import existing files into the library, then configure metadata and download preferences from the web UI."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('karakeep', 'Karakeep', 'Knowledge management system that helps you collect, search, and retrieve information efficiently.', 'knowledge-management', ARRAY['Knowledge Management', 'Search', 'Web Scraping', 'Organization'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/karakeep-app/karakeep:0.31.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Karakeep", "version": "latest", "description": "Knowledge management system that helps you collect, search, and retrieve information efficiently.", "category": "knowledge-management", "tags": ["Knowledge Management", "Search", "Web Scraping", "Organization"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/karakeep-app/karakeep:0.31.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://karakeep.app"}, {"label": "Documentation", "url": "https://docs.karakeep.app"}, {"label": "Github", "url": "https://github.com/karakeep-app/karakeep"}], "instructions": "Please provide the OpenAI API Key and Sign Up for the user account.", "install": [{"docker": {"image": "$IMAGE", "name": "karakeep", "port": "$PORT:3000", "volumes": ["/data", "/meili_data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Please provide the OpenAI API Key and Sign Up for the user account."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('kavita', 'Kavita', 'Kavita is a high-speed, sleekly designed, self-hosted digital library that supports a wide range of file formats. It allows you to quickly resume your reading from your homepage, browse your Manga, Comics, and Books, and search for your favorite manga with ease. Kavita also provides full support for all fields from ComicInfo.xml (and EPUB) for metadata filtering. It features built-in ratings and reviews for each Manga, integrated chapters and volumes, and user & library management. Kavita also includes a responsive Manga/Comic/Image Reader with impressive caching for a seamless reading experience, and a customizable Book reader. It also provides server and user stats, and premium features with a Kavita+ Subscription. Kavita supports a wide array of file formats for Manga/Comics, Books, and Raw Images. It also offers user management and sharing features, allowing you to create users and share your libraries with them. Kavita is fast, efficient, and responsive, offering full text search, grouping and organizing features, full metadata support and filtering ability, and cool stats for individual user accounts and your server.', 'media', ARRAY['Media', 'File Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "jvmilazz0/kavita:0.9.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Kavita", "version": "latest", "description": "Kavita is a high-speed, sleekly designed, self-hosted digital library that supports a wide range of file formats. It allows you to quickly resume your reading from your homepage, browse your Manga, Comics, and Books, and search for your favorite manga with ease. Kavita also provides full support for all fields from ComicInfo.xml (and EPUB) for metadata filtering. It features built-in ratings and reviews for each Manga, integrated chapters and volumes, and user & library management. Kavita also includes a responsive Manga/Comic/Image Reader with impressive caching for a seamless reading experience, and a customizable Book reader. It also provides server and user stats, and premium features with a Kavita+ Subscription. Kavita supports a wide array of file formats for Manga/Comics, Books, and Raw Images. It also offers user management and sharing features, allowing you to create users and share your libraries with them. Kavita is fast, efficient, and responsive, offering full text search, grouping and organizing features, full metadata support and filtering ability, and cool stats for individual user accounts and your server.", "category": "media", "tags": ["Media", "File Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "jvmilazz0/kavita:0.9.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5000}}, "links": [{"label": "Website", "url": "https://www.kavitareader.com/"}, {"label": "Documentation", "url": "https://wiki.kavitareader.com/"}, {"label": "Github", "url": "https://github.com/Kareadita/Kavita"}], "instructions": "Register your user and make sure the Username does not contain spaces.", "install": [{"docker": {"image": "$IMAGE", "name": "kavita", "port": "$PORT:5000", "volumes": ["/kavita/config", "/manga", "/comics", "/books"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Register your user and make sure the Username does not contain spaces."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('keepassxc', 'KeePassXC', 'KeePassXC is a modern, secure, and open-source password manager that stores and manages your passwords in an encrypted database. It provides strong security features and cross-platform compatibility.', 'security', ARRAY['Security', 'Password Manager', 'Encryption', 'Open Source', 'Cross-Platform'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/keepassxc:2.7.11"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "KeePassXC", "version": "latest", "description": "KeePassXC is a modern, secure, and open-source password manager that stores and manages your passwords in an encrypted database. It provides strong security features and cross-platform compatibility.", "category": "security", "tags": ["Security", "Password Manager", "Encryption", "Open Source", "Cross-Platform"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/keepassxc:2.7.11"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://keepassxc.org"}, {"label": "Documentation", "url": "https://keepassxc.org/docs"}, {"label": "GitHub", "url": "https://github.com/keepassxreboot/keepassxc"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "keepassxc", "port": "$PORT:3000", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('keeper', 'Keeper', 'Keeper is a simple and open-source calendar synchronization and booking tool that allows you to pull events from remotely hosted iCal or ICS links and push them to one or many calendars. Built with modern architecture using Next.js and Bun, Keeper provides a comprehensive solution for calendar management and synchronization. The standalone version includes all services (web, API, cron) in a single container, making it easy to deploy. Keeper supports multiple calendar providers including Google Calendar, iCloud, Outlook, CalDAV, and Fastmail. Perfect for individuals and organizations looking to synchronize calendars across different platforms with a self-hosted solution.', 'calendar', ARRAY['Calendar', 'Synchronization', 'Self-Hosted', 'iCal', 'ICS', 'Booking', 'Docker'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/ridafkih/keeper-standalone:1.11.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Keeper", "version": "latest", "description": "Keeper is a simple and open-source calendar synchronization and booking tool that allows you to pull events from remotely hosted iCal or ICS links and push them to one or many calendars. Built with modern architecture using Next.js and Bun, Keeper provides a comprehensive solution for calendar management and synchronization. The standalone version includes all services (web, API, cron) in a single container, making it easy to deploy. Keeper supports multiple calendar providers including Google Calendar, iCloud, Outlook, CalDAV, and Fastmail. Perfect for individuals and organizations looking to synchronize calendars across different platforms with a self-hosted solution.", "category": "calendar", "tags": ["Calendar", "Synchronization", "Self-Hosted", "iCal", "ICS", "Booking", "Docker"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/ridafkih/keeper-standalone:1.11.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://keeper.sh"}, {"label": "GitHub", "url": "https://github.com/ridafkih/keeper.sh"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "keeper", "port": "$PORT:80", "volumes": ["/var/lib/postgresql/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('keeweb', 'KeeWeb', 'KeeWeb is a modern, fast, and self-hosted password manager designed for individuals and teams. It provides a sleek, responsive user interface for managing and securing your passwords efficiently. KeeWeb supports importing and syncing password databases from various sources such as Dropbox, OneDrive, or local storage. It offers seamless offline access, powerful search capabilities, and advanced encryption to protect your sensitive data. KeeWeb ensures a consistent experience across desktop and web applications, with customization options to suit your preferences.', 'security', ARRAY['Security', 'Password Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/keeweb/keeweb:1.19.0-amd64"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "KeeWeb", "version": "latest", "description": "KeeWeb is a modern, fast, and self-hosted password manager designed for individuals and teams. It provides a sleek, responsive user interface for managing and securing your passwords efficiently. KeeWeb supports importing and syncing password databases from various sources such as Dropbox, OneDrive, or local storage. It offers seamless offline access, powerful search capabilities, and advanced encryption to protect your sensitive data. KeeWeb ensures a consistent experience across desktop and web applications, with customization options to suit your preferences.", "category": "security", "tags": ["Security", "Password Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/keeweb/keeweb:1.19.0-amd64"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://keeweb.info/"}, {"label": "Documentation", "url": "https://github.com/keeweb/keeweb/wiki"}, {"label": "Github", "url": "https://github.com/keeweb/keeweb"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "keeweb", "port": "$PORT:80", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('keila', 'Keila', 'Keila is a reliable and easy-to-use email newsletter tool that helps you grow your contact lists and send data-driven campaigns effortlessly. With Keila, you can import your existing contacts simply by uploading a CSV file. The app offers complete freedom to add custom data and tags to your contacts, which can be used to filter contacts and as merge fields in campaigns. Keila also features powerful segmentation, allowing you to create smart subsets of your contact lists. The app respects the privacy of your contacts and ensures that your data remains yours. Keila provides live statistics for your newsletters, including open and click rates, and allows you to integrate your email newsletter with other applications using its powerful API. Keila is proudly Open Source, made in Germany, and hosted in the EU, ensuring strict European privacy standards.', 'email', ARRAY['Email'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "pentacent/keila:0.20"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Keila", "version": "latest", "description": "Keila is a reliable and easy-to-use email newsletter tool that helps you grow your contact lists and send data-driven campaigns effortlessly. With Keila, you can import your existing contacts simply by uploading a CSV file. The app offers complete freedom to add custom data and tags to your contacts, which can be used to filter contacts and as merge fields in campaigns. Keila also features powerful segmentation, allowing you to create smart subsets of your contact lists. The app respects the privacy of your contacts and ensures that your data remains yours. Keila provides live statistics for your newsletters, including open and click rates, and allows you to integrate your email newsletter with other applications using its powerful API. Keila is proudly Open Source, made in Germany, and hosted in the EU, ensuring strict European privacy standards.", "category": "email", "tags": ["Email"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "pentacent/keila:0.20"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://keila.io"}, {"label": "Documentation", "url": "https://keila.io/docs"}, {"label": "Github", "url": "https://github.com/pentacent/keila"}], "instructions": "Login with changeme@easypanel.io:password123 - change this from the administraton panel", "install": [{"docker": {"image": "$IMAGE", "name": "keila", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Login with changeme@easypanel.io:password123 - change this from the administraton panel"}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('kener', 'Kener', 'Kener is an advanced, self-hosted status page system designed for individuals and teams. It offers a sleek, responsive user interface for monitoring and communicating the status of your services efficiently. Kener supports real-time monitoring, incident management, and customizable status pages. With seamless offline access, powerful search capabilities, and robust encryption, Kener ensures your service status is transparent and secure. It provides a consistent experience across desktop and web applications, with customization options to suit your preferences.', 'status-page', ARRAY['Status Page', 'Monitoring', 'Incident Management', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/rajnandan1/kener:4.0.23"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Kener", "version": "latest", "description": "Kener is an advanced, self-hosted status page system designed for individuals and teams. It offers a sleek, responsive user interface for monitoring and communicating the status of your services efficiently. Kener supports real-time monitoring, incident management, and customizable status pages. With seamless offline access, powerful search capabilities, and robust encryption, Kener ensures your service status is transparent and secure. It provides a consistent experience across desktop and web applications, with customization options to suit your preferences.", "category": "status-page", "tags": ["Status Page", "Monitoring", "Incident Management", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/rajnandan1/kener:4.0.23"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://kener.ing/"}, {"label": "Documentation", "url": "https://kener.ing/docs"}, {"label": "GitHub", "url": "https://github.com/rajnandan1/kener"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "kener", "port": "$PORT:3000", "volumes": ["/app/database"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "mysql": {"type": "mysql", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('keycloak', 'Keycloak', 'Keycloak is an open-source Identity and Access Management tool that adds authentication to applications and secures services with minimal effort. It eliminates the need for storing or authenticating users, providing user federation, robust authentication, user management, and fine-grained authorization. Keycloak offers a Single-Sign On feature, allowing users to authenticate with Keycloak rather than individual applications, ensuring a seamless login experience across multiple applications. It also supports social login and can authenticate users with existing OpenID Connect or SAML 2.0 Identity Providers. Keycloak has built-in support to connect to existing LDAP or Active Directory servers and provides a centralized admin console for managing all aspects of the server. It also offers an account management console for users to manage their own accounts. Based on standard protocols, Keycloak supports OpenID Connect, OAuth 2.0, and SAML, and provides fine-grained authorization services for advanced permission management.', 'identity-and-access-management', ARRAY['Identity and Access Management', 'Authentication', 'Authorization', 'Single Sign-On', 'User Federation', 'Social Login', 'Admin Console', 'Account Management', 'Standard Protocols', 'Fine-Grained Authorization'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "quay.io/keycloak/keycloak:26.4.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Keycloak", "version": "latest", "description": "Keycloak is an open-source Identity and Access Management tool that adds authentication to applications and secures services with minimal effort. It eliminates the need for storing or authenticating users, providing user federation, robust authentication, user management, and fine-grained authorization. Keycloak offers a Single-Sign On feature, allowing users to authenticate with Keycloak rather than individual applications, ensuring a seamless login experience across multiple applications. It also supports social login and can authenticate users with existing OpenID Connect or SAML 2.0 Identity Providers. Keycloak has built-in support to connect to existing LDAP or Active Directory servers and provides a centralized admin console for managing all aspects of the server. It also offers an account management console for users to manage their own accounts. Based on standard protocols, Keycloak supports OpenID Connect, OAuth 2.0, and SAML, and provides fine-grained authorization services for advanced permission management.", "category": "identity-and-access-management", "tags": ["Identity and Access Management", "Authentication", "Authorization", "Single Sign-On", "User Federation", "Social Login", "Admin Console", "Account Management", "Standard Protocols", "Fine-Grained Authorization"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "quay.io/keycloak/keycloak:26.4.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Website", "url": "https://www.keycloak.org"}, {"label": "Documentation", "url": "https://www.keycloak.org/documentation"}, {"label": "Github", "url": "https://github.com/keycloak/keycloak"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "keycloak", "port": "$PORT:8080", "volumes": ["/opt/keycloak", "/opt/bitnami/keycloak/themes"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('khoj', 'Khoj', 'Khoj is an AI-powered personal search and chat application that helps you find and organize your personal knowledge. It supports various AI models, web search integration, and code execution capabilities.', 'ai', ARRAY['AI', 'Search', 'Chat', 'Self-Hosted', 'Knowledge Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/khoj-ai/khoj:2.0.0-beta.28"}, "port": {"type": "integer", "title": "Port HTTP", "default": 42110}}$JSON$::jsonb, $JSON${"metadata": {"name": "Khoj", "version": "latest", "description": "Khoj is an AI-powered personal search and chat application that helps you find and organize your personal knowledge. It supports various AI models, web search integration, and code execution capabilities.", "category": "ai", "tags": ["AI", "Search", "Chat", "Self-Hosted", "Knowledge Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/khoj-ai/khoj:2.0.0-beta.28"}, "port": {"type": "integer", "title": "Port HTTP", "default": 42110}}, "links": [{"label": "Website", "url": "https://khoj.dev"}, {"label": "Documentation", "url": "https://docs.khoj.dev"}, {"label": "GitHub", "url": "https://github.com/khoj-ai/khoj"}], "instructions": "Configure your chat model provider and search api providers with khoj environment variables.", "install": [{"docker": {"image": "$IMAGE", "name": "khoj", "port": "$PORT:42110", "volumes": ["/root/.khoj/", "/root/.cache/torch/sentence_transformers", "/root/.cache/huggingface", "/app/data", "/etc/searxng"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Configure your chat model provider and search api providers with khoj environment variables."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('kicad', 'KiCad', 'KiCad is an open-source software suite for electronic design automation (EDA), enabling the design and simulation of electronic circuits and printed circuit boards (PCBs). It provides a comprehensive set of tools for schematic capture, PCB layout, and 3D visualization. KiCad supports extensive libraries of components and footprints, allowing designers to create custom designs with ease. Its robust features, such as design rule checking, netlist generation, and Gerber export, make it a preferred choice for professionals and hobbyists alike. With a focus on flexibility and open-source principles, KiCad empowers users to bring their electronic design projects to life.', 'electronic-design-automation', ARRAY['Electronic Design Automation', 'PCB Design', 'Schematic Capture', '3D Visualization', 'Open-Source', 'Component Libraries', 'Gerber Export', 'Design Rule Checking', 'Multi-Layer Boards', 'Circuit Simulation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/kicad:8.0.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "KiCad", "version": "latest", "description": "KiCad is an open-source software suite for electronic design automation (EDA), enabling the design and simulation of electronic circuits and printed circuit boards (PCBs). It provides a comprehensive set of tools for schematic capture, PCB layout, and 3D visualization. KiCad supports extensive libraries of components and footprints, allowing designers to create custom designs with ease. Its robust features, such as design rule checking, netlist generation, and Gerber export, make it a preferred choice for professionals and hobbyists alike. With a focus on flexibility and open-source principles, KiCad empowers users to bring their electronic design projects to life.", "category": "electronic-design-automation", "tags": ["Electronic Design Automation", "PCB Design", "Schematic Capture", "3D Visualization", "Open-Source", "Component Libraries", "Gerber Export", "Design Rule Checking", "Multi-Layer Boards", "Circuit Simulation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/kicad:8.0.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://www.kicad.org"}, {"label": "Documentation", "url": "https://docs.kicad.org"}, {"label": "Github", "url": "https://github.com/KiCad/kicad-source-mirror"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "kicad", "port": "$PORT:3000", "volumes": ["/config"], "extra_ports": ["3001:3001"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('killbill', 'KillBill', 'KillBill is an open-source subscription billing and payment platform designed to simplify complex billing workflows for SaaS and other businesses. It provides robust support for recurring billing, invoicing, and payment management while offering flexibility for customization. KillBill ensures seamless integration with third-party payment gateways, making it adaptable for global payment needs. It supports multiple plugins to extend functionality, enabling businesses to manage tax compliance, analytics, notifications, and more. The platform''s Kaui UI offers an intuitive administrative console for managing subscriptions, invoices, payments, and tenants. KillBill''s API-driven design allows developers to customize and automate every aspect of the billing process. Its modular architecture ensures it can scale with the growing needs of businesses, providing robust tools for revenue management.', 'subscription-management', ARRAY['Subscription Management', 'Recurring Billing', 'Invoicing', 'Payment Management', 'API-Driven', 'Extensible Plugins', 'Multi-Tenancy', 'Kaui Admin Console', 'Revenue Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "killbill/killbill:0.24.17"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "KillBill", "version": "latest", "description": "KillBill is an open-source subscription billing and payment platform designed to simplify complex billing workflows for SaaS and other businesses. It provides robust support for recurring billing, invoicing, and payment management while offering flexibility for customization. KillBill ensures seamless integration with third-party payment gateways, making it adaptable for global payment needs. It supports multiple plugins to extend functionality, enabling businesses to manage tax compliance, analytics, notifications, and more. The platform's Kaui UI offers an intuitive administrative console for managing subscriptions, invoices, payments, and tenants. KillBill's API-driven design allows developers to customize and automate every aspect of the billing process. Its modular architecture ensures it can scale with the growing needs of businesses, providing robust tools for revenue management.", "category": "subscription-management", "tags": ["Subscription Management", "Recurring Billing", "Invoicing", "Payment Management", "API-Driven", "Extensible Plugins", "Multi-Tenancy", "Kaui Admin Console", "Revenue Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "killbill/killbill:0.24.17"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Website", "url": "https://killbill.io"}, {"label": "Documentation", "url": "https://docs.killbill.io"}, {"label": "GitHub", "url": "https://github.com/killbill/killbill"}], "instructions": "You have to configure the KillBill URL in your Kaui Environment Section. Then access the Kaui App Service to access KillBill. Default credentials username; admin, password; password.", "install": [{"docker": {"image": "$IMAGE", "name": "killbill", "port": "$PORT:8080", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "You have to configure the KillBill URL in your Kaui Environment Section. Then access the Kaui App Service to access KillBill. Default credentials username; admin, password; password."}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('kimai', 'Kimai', 'Kimai is an open-source time-tracking solution designed for freelancers, small businesses, and enterprises to manage time-tracking needs efficiently. It enables users to track work hours, manage projects, and create accurate reports and invoices based on time entries. With a focus on simplicity and flexibility, Kimai is ideal for organizations looking to improve productivity, manage employee timesheets, and handle client billing without the complexity of traditional ERP systems. Kimai offers a modular architecture, allowing for easy customization to meet unique requirements, and it supports multi-user environments with permissions to manage data access.', 'time-tracking', ARRAY['Time Tracking', 'Project Management', 'Invoicing', 'Reporting', 'Multi-User', 'Multi-Currency', 'Plugins', 'Analytics', 'Multi-Language', 'Secure Data Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "kimai/kimai2:apache-2.56.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8001}}$JSON$::jsonb, $JSON${"metadata": {"name": "Kimai", "version": "latest", "description": "Kimai is an open-source time-tracking solution designed for freelancers, small businesses, and enterprises to manage time-tracking needs efficiently. It enables users to track work hours, manage projects, and create accurate reports and invoices based on time entries. With a focus on simplicity and flexibility, Kimai is ideal for organizations looking to improve productivity, manage employee timesheets, and handle client billing without the complexity of traditional ERP systems. Kimai offers a modular architecture, allowing for easy customization to meet unique requirements, and it supports multi-user environments with permissions to manage data access.", "category": "time-tracking", "tags": ["Time Tracking", "Project Management", "Invoicing", "Reporting", "Multi-User", "Multi-Currency", "Plugins", "Analytics", "Multi-Language", "Secure Data Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "kimai/kimai2:apache-2.56.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8001}}, "links": [{"label": "Website", "url": "https://www.kimai.org"}, {"label": "Documentation", "url": "https://www.kimai.org/documentation"}, {"label": "GitHub", "url": "https://github.com/kimai/kimai"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "kimai", "port": "$PORT:8001", "volumes": ["/opt/kimai/var/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('kitchenowl', 'KitchenOwl', 'KitchenOwl is a self-hosted grocery list and recipe manager designed to help you organize your kitchen and meal planning. It provides a clean web interface for managing shopping lists, recipes, and inventory. Perfect for families and individuals who want to streamline their grocery shopping and meal preparation.', 'grocery-lists', ARRAY['Grocery Lists', 'Recipe Management', 'Meal Planning', 'Family', 'Web Interface'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "tombursch/kitchenowl-web:v0.7.8"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "KitchenOwl", "version": "latest", "description": "KitchenOwl is a self-hosted grocery list and recipe manager designed to help you organize your kitchen and meal planning. It provides a clean web interface for managing shopping lists, recipes, and inventory. Perfect for families and individuals who want to streamline their grocery shopping and meal preparation.", "category": "grocery-lists", "tags": ["Grocery Lists", "Recipe Management", "Meal Planning", "Family", "Web Interface"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "tombursch/kitchenowl-web:v0.7.8"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://kitchenowl.org/"}, {"label": "GitHub", "url": "https://github.com/Tombursch/kitchenowl"}, {"label": "Documentation", "url": "https://docs.kitchenowl.org/latest/"}, {"label": "DockerHub Frontend", "url": "https://hub.docker.com/r/tombursch/kitchenowl-web"}, {"label": "DockerHub Backend", "url": "https://hub.docker.com/r/tombursch/kitchenowl-backend"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "kitchenowl", "port": "$PORT:80", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('koito', 'Koito', 'Koito is a self-hosted, themeable ListenBrainz-compatible scrobbler for tracking music listening history and visualizing listening habits. It supports relay of listens to other ListenBrainz-compatible servers, import from Last.fm, Maloja, Spotify, and ListenBrainz, and features like artist statistics, interest-over-time graphs, and Spotify-wrapped-style rewinds. Built with Go and featuring a sleek modern UI with multiple built-in themes and custom theme support, Koito provides comprehensive music listening analytics while maintaining complete control over your scrobbling data.', 'music', ARRAY['Music', 'Scrobbler', 'ListenBrainz', 'Self-Hosted', 'Analytics', 'Music Tracking', 'Last.fm'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "gabehf/koito:v0.1.8"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4110}}$JSON$::jsonb, $JSON${"metadata": {"name": "Koito", "version": "latest", "description": "Koito is a self-hosted, themeable ListenBrainz-compatible scrobbler for tracking music listening history and visualizing listening habits. It supports relay of listens to other ListenBrainz-compatible servers, import from Last.fm, Maloja, Spotify, and ListenBrainz, and features like artist statistics, interest-over-time graphs, and Spotify-wrapped-style rewinds. Built with Go and featuring a sleek modern UI with multiple built-in themes and custom theme support, Koito provides comprehensive music listening analytics while maintaining complete control over your scrobbling data.", "category": "music", "tags": ["Music", "Scrobbler", "ListenBrainz", "Self-Hosted", "Analytics", "Music Tracking", "Last.fm"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "gabehf/koito:v0.1.8"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4110}}, "links": [{"label": "Website", "url": "https://koito.io"}, {"label": "GitHub", "url": "https://github.com/gabehf/koito"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "koito", "port": "$PORT:4110", "volumes": ["/etc/koito"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('kokoro', 'Kokoro', 'Kokoro is a powerful, browser-based AI voice generator that lets you create natural-sounding voices without installing anything. Use it directly in your browser or self-host it for your own applications with OpenAI API compatibility!', 'ai', ARRAY['AI', 'Voice Generation', 'Browser-Based', 'OpenAI API'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/eduardolat/kokoro-web:0.1.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Kokoro", "version": "latest", "description": "Kokoro is a powerful, browser-based AI voice generator that lets you create natural-sounding voices without installing anything. Use it directly in your browser or self-host it for your own applications with OpenAI API compatibility!", "category": "ai", "tags": ["AI", "Voice Generation", "Browser-Based", "OpenAI API"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/eduardolat/kokoro-web:0.1.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Github", "url": "https://github.com/eduardolat/kokoro-web"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "kokoro", "port": "$PORT:80", "volumes": ["/kokoro/cache"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('komga', 'Komga', 'Komga is a free and open source comics/mangas server that provides an intuitive platform for comic and manga enthusiasts. It allows you to browse libraries, series, and books via a responsive web UI that is compatible with desktops, tablets, and phones. With Komga, you can easily organize your library with collections and read lists, and edit metadata for your series and books. The app also has the ability to import embedded metadata automatically. It features a web reader with multiple reading modes and allows you to manage multiple users with per-library access control, age restrictions, and labels restrictions. Additionally, Komga offers a REST API for interaction with other tools and scripts, and provides features for downloading book files, whole series, or read lists. It also has a duplicate files detection system and can import books from outside your libraries directly into your series folder. Komga also supports the import of ComicRack cbl read lists.', 'media', ARRAY['Media'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "gotson/komga:1.24.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 25600}}$JSON$::jsonb, $JSON${"metadata": {"name": "Komga", "version": "latest", "description": "Komga is a free and open source comics/mangas server that provides an intuitive platform for comic and manga enthusiasts. It allows you to browse libraries, series, and books via a responsive web UI that is compatible with desktops, tablets, and phones. With Komga, you can easily organize your library with collections and read lists, and edit metadata for your series and books. The app also has the ability to import embedded metadata automatically. It features a web reader with multiple reading modes and allows you to manage multiple users with per-library access control, age restrictions, and labels restrictions. Additionally, Komga offers a REST API for interaction with other tools and scripts, and provides features for downloading book files, whole series, or read lists. It also has a duplicate files detection system and can import books from outside your libraries directly into your series folder. Komga also supports the import of ComicRack cbl read lists.", "category": "media", "tags": ["Media"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "gotson/komga:1.24.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 25600}}, "links": [{"label": "Github", "url": "https://github.com/gotson/komga"}, {"label": "Website", "url": "https://komga.org"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "komga", "port": "$PORT:25600", "volumes": ["/config", "/data", "/etc/timezone"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('komiser', 'Komiser', 'Komiser is an open-source cloud resource manager that helps you understand, manage, and optimize your cloud infrastructure costs. It provides a unified dashboard to monitor and manage resources across multiple cloud providers, offering insights into resource usage, cost optimization opportunities, and security best practices.', 'cloud-management', ARRAY['Cloud Management', 'Cost Optimization', 'Resource Monitoring', 'Security', 'Multi-Cloud'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "tailwarden/komiser:3.1.22"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Komiser", "version": "latest", "description": "Komiser is an open-source cloud resource manager that helps you understand, manage, and optimize your cloud infrastructure costs. It provides a unified dashboard to monitor and manage resources across multiple cloud providers, offering insights into resource usage, cost optimization opportunities, and security best practices.", "category": "cloud-management", "tags": ["Cloud Management", "Cost Optimization", "Resource Monitoring", "Security", "Multi-Cloud"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "tailwarden/komiser:3.1.22"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://komiser.io/"}, {"label": "Documentation", "url": "https://docs.komiser.io/"}, {"label": "GitHub", "url": "https://github.com/tailwarden/komiser"}], "instructions": "Once deployed, please provide your credentials in the credentials.yaml file, and then restart the service.", "install": [{"docker": {"image": "$IMAGE", "name": "komiser", "port": "$PORT:3000", "volumes": ["/etc/config/config.toml", "/etc/config/credentials.yaml"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Once deployed, please provide your credentials in the credentials.yaml file, and then restart the service."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('komodo', 'Komodo', 'Komodo is a comprehensive server management platform that provides monitoring and control capabilities for Docker containers and system processes. It offers a unified dashboard to manage your infrastructure, with features including container management, process monitoring, resource tracking, and system metrics visualization.', 'server-management', ARRAY['Server Management', 'Docker', 'Monitoring', 'Automation', 'MongoDB'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/moghtech/komodo-core:2.2.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9120}}$JSON$::jsonb, $JSON${"metadata": {"name": "Komodo", "version": "latest", "description": "Komodo is a comprehensive server management platform that provides monitoring and control capabilities for Docker containers and system processes. It offers a unified dashboard to manage your infrastructure, with features including container management, process monitoring, resource tracking, and system metrics visualization.", "category": "server-management", "tags": ["Server Management", "Docker", "Monitoring", "Automation", "MongoDB"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/moghtech/komodo-core:2.2.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9120}}, "links": [{"label": "Website", "url": "https://komo.do"}, {"label": "GitHub", "url": "https://github.com/moghtech/komodo"}, {"label": "Documentation", "url": "https://komo.do/docs/intro"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "komodo", "port": "$PORT:9120", "volumes": ["/backups", "/config/keys", "/var/run/docker.sock", "/proc", "/etc/komodo", "/config/keys"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('kopia', 'Kopia', 'Kopia is a robust open-source backup and restore tool designed to provide fast and secure backups of your important data. It allows you to create encrypted snapshots of your files and directories, which can be stored on the cloud storage of your choice, network-attached storage, server, or locally on your machine. Kopia supports a wide range of storage locations including Amazon S3, Azure Blob Storage, Backblaze B2, Google Cloud Storage, and many more. It also supports both CLI and GUI versions, making it accessible for both advanced and regular users. Kopia''s unique features include compression, deduplication, end-to-end ''zero knowledge'' encryption, and error correction, ensuring your data is safe, secure, and easily retrievable.', 'backup', ARRAY['Backup', 'Data Management', 'Security'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "kopia/kopia:20260502.0.42513"}, "port": {"type": "integer", "title": "Port HTTP", "default": 51515}}$JSON$::jsonb, $JSON${"metadata": {"name": "Kopia", "version": "latest", "description": "Kopia is a robust open-source backup and restore tool designed to provide fast and secure backups of your important data. It allows you to create encrypted snapshots of your files and directories, which can be stored on the cloud storage of your choice, network-attached storage, server, or locally on your machine. Kopia supports a wide range of storage locations including Amazon S3, Azure Blob Storage, Backblaze B2, Google Cloud Storage, and many more. It also supports both CLI and GUI versions, making it accessible for both advanced and regular users. Kopia's unique features include compression, deduplication, end-to-end 'zero knowledge' encryption, and error correction, ensuring your data is safe, secure, and easily retrievable.", "category": "backup", "tags": ["Backup", "Data Management", "Security"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "kopia/kopia:20260502.0.42513"}, "port": {"type": "integer", "title": "Port HTTP", "default": 51515}}, "links": [{"label": "Website", "url": "https://kopia.io/"}, {"label": "Docs", "url": "https://kopia.io/docs/"}, {"label": "Github", "url": "https://github.com/kopia/kopia/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "kopia", "port": "$PORT:51515", "volumes": ["/app/config", "/app/cache", "/app/logs", "/data", "/repository", "/tmp"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('krakend', 'KrakenD', 'KrakenD is a high-performance API Gateway that helps you build microservices architecture. It''s designed to be ultra-fast and lightweight, aggregating multiple services into a single API endpoint. It''s perfect for building microservices, mobile backends, and public APIs.', 'api-gateway', ARRAY['API Gateway', 'Microservices', 'Backend', 'High Performance', 'Open Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "devopsfaith/krakend:2.9.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "KrakenD", "version": "latest", "description": "KrakenD is a high-performance API Gateway that helps you build microservices architecture. It's designed to be ultra-fast and lightweight, aggregating multiple services into a single API endpoint. It's perfect for building microservices, mobile backends, and public APIs.", "category": "api-gateway", "tags": ["API Gateway", "Microservices", "Backend", "High Performance", "Open Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "devopsfaith/krakend:2.9.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Website", "url": "https://www.krakend.io/"}, {"label": "Documentation", "url": "https://www.krakend.io/docs/"}, {"label": "GitHub", "url": "https://github.com/krakend"}], "instructions": "Please follow the official documentation for more information and customizations.", "install": [{"docker": {"image": "$IMAGE", "name": "krakend", "port": "$PORT:8080", "volumes": ["/etc/krakend"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Please follow the official documentation for more information and customizations."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('kroki', 'Kroki', 'Kroki is a self-hosted diagramming and visualization service that allows users to generate diagrams from textual descriptions. It supports multiple diagramming formats, including Mermaid, BPMN, Excalidraw, PlantUML, Graphviz, and more. With Kroki, users can convert structured text into graphical representations quickly and efficiently. The application provides a simple API, making it easy to integrate with other tools. It is lightweight, supports multiple diagram rendering engines, and ensures full control over your data with a self-hosted deployment.', 'diagramming', ARRAY['Diagramming', 'Visualization', 'Self-Hosted', 'API-Based'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "yuzutech/kroki"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Kroki", "version": "latest", "description": "Kroki is a self-hosted diagramming and visualization service that allows users to generate diagrams from textual descriptions. It supports multiple diagramming formats, including Mermaid, BPMN, Excalidraw, PlantUML, Graphviz, and more. With Kroki, users can convert structured text into graphical representations quickly and efficiently. The application provides a simple API, making it easy to integrate with other tools. It is lightweight, supports multiple diagram rendering engines, and ensures full control over your data with a self-hosted deployment.", "category": "diagramming", "tags": ["Diagramming", "Visualization", "Self-Hosted", "API-Based"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "yuzutech/kroki"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}}, "links": [{"label": "Documentation", "url": "https://kroki.io/#docs"}, {"label": "Github", "url": "https://github.com/yuzutech/kroki"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "kroki", "port": "$PORT:8000", "volumes": [], "extra_ports": ["8002:8002", "8003:8003", "8004:8004"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('kutt', 'Kutt', 'Kutt is a free and open-source app designed to make your links shorter and more manageable. With Kutt, you can create, protect, and delete your links, and monitor them with detailed statistics. You can also set custom domains for your links, adding a personal touch to your URLs. The app also provides an API, allowing you to create, delete, and get URLs from anywhere. Kutt also offers browser extensions for Chrome and Firefox for easy access and use. The app is completely open source and free, giving you the freedom to host it on your own server if you wish.', 'url-shortener', ARRAY['URL Shortener', 'Link Management', 'Analytics'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "kutt/kutt:v3.2.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}$JSON$::jsonb, $JSON${"metadata": {"name": "Kutt", "version": "latest", "description": "Kutt is a free and open-source app designed to make your links shorter and more manageable. With Kutt, you can create, protect, and delete your links, and monitor them with detailed statistics. You can also set custom domains for your links, adding a personal touch to your URLs. The app also provides an API, allowing you to create, delete, and get URLs from anywhere. Kutt also offers browser extensions for Chrome and Firefox for easy access and use. The app is completely open source and free, giving you the freedom to host it on your own server if you wish.", "category": "url-shortener", "tags": ["URL Shortener", "Link Management", "Analytics"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "kutt/kutt:v3.2.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}}, "links": [{"label": "Website", "url": "https://kutt.it/"}, {"label": "Documentation", "url": "https://docs.kutt.it/"}, {"label": "Github", "url": "https://github.com/thedevs-network/kutt"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "kutt", "port": "$PORT:3000", "volumes": ["/usr/src/app"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('kuzzle', 'Kuzzle', 'Kuzzle is a free and open-source backend platform designed to accelerate the development of web, mobile, and Internet of Things (IoT) applications. It provides real-time features, multi-protocol API support, and robust user management, enabling developers to focus on building high-level business functionalities. Kuzzle is fully customizable through plugins and offers client SDKs for seamless integration with various platforms. Its flexibility and scalability make it an ideal choice for IoT, geolocation, and enterprise applications.', 'backend', ARRAY['Backend', 'IoT', 'Real-Time', 'API', 'Geolocation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "kuzzleio/kuzzle:2.54.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 1883}}$JSON$::jsonb, $JSON${"metadata": {"name": "Kuzzle", "version": "latest", "description": "Kuzzle is a free and open-source backend platform designed to accelerate the development of web, mobile, and Internet of Things (IoT) applications. It provides real-time features, multi-protocol API support, and robust user management, enabling developers to focus on building high-level business functionalities. Kuzzle is fully customizable through plugins and offers client SDKs for seamless integration with various platforms. Its flexibility and scalability make it an ideal choice for IoT, geolocation, and enterprise applications.", "category": "backend", "tags": ["Backend", "IoT", "Real-Time", "API", "Geolocation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "kuzzleio/kuzzle:2.54.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 1883}}, "links": [{"label": "Website", "url": "https://kuzzle.io/"}, {"label": "Documentation", "url": "https://docs.kuzzle.io/"}, {"label": "Github", "url": "https://github.com/kuzzleio/kuzzle"}], "instructions": "You should connect with the Kuzzle instance using the provided domain which proxying back to the HTTP/WebSocket connection.", "install": [{"docker": {"image": "$IMAGE", "name": "kuzzle", "port": "$PORT:1883", "volumes": ["/usr/share/elasticsearch"], "extra_ports": ["7512:7512"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "You should connect with the Kuzzle instance using the provided domain which proxying back to the HTTP/WebSocket connection."}, "services": {"redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('labelstudio', 'Label Studio', 'Label Studio is an open source data labeling tool. It lets you label data types like audio, text, images, videos, and time series with a simple and straightforward UI and export to various model formats. It can be used to prepare raw data or improve existing training data to get more accurate ML models.', 'machine-learning', ARRAY['Machine Learning', 'Data Annotation', 'Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "heartexlabs/label-studio:1.23.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Label Studio", "version": "latest", "description": "Label Studio is an open source data labeling tool. It lets you label data types like audio, text, images, videos, and time series with a simple and straightforward UI and export to various model formats. It can be used to prepare raw data or improve existing training data to get more accurate ML models.", "category": "machine-learning", "tags": ["Machine Learning", "Data Annotation", "Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "heartexlabs/label-studio:1.23.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Website", "url": "https://labelstud.io/"}, {"label": "Documentation", "url": "https://labelstud.io/guide/"}, {"label": "Github", "url": "https://github.com/HumanSignal/label-studio/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "labelstudio", "port": "$PORT:80", "volumes": ["/label-studio/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('lago', 'Lago', 'Lago is an open-source metered billing and usage-based pricing platform that helps businesses implement complex pricing models with precision and transparency. Built for modern SaaS companies, Lago provides real-time usage tracking, flexible pricing configurations, automated invoicing, and comprehensive billing analytics. Perfect for businesses that need to implement usage-based pricing, hybrid pricing models, or complex billing scenarios with features like prepaid credits, graduated pricing, and multi-dimensional metering.', 'billing', ARRAY['Billing', 'Metered Billing', 'Usage-Based Pricing', 'SaaS', 'Invoicing', 'Payment Processing', 'Analytics', 'API', 'Open Source', 'Revenue Management', 'Subscription Management', 'Financial Technology'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "getlago/api:v1.31.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Lago", "version": "latest", "description": "Lago is an open-source metered billing and usage-based pricing platform that helps businesses implement complex pricing models with precision and transparency. Built for modern SaaS companies, Lago provides real-time usage tracking, flexible pricing configurations, automated invoicing, and comprehensive billing analytics. Perfect for businesses that need to implement usage-based pricing, hybrid pricing models, or complex billing scenarios with features like prepaid credits, graduated pricing, and multi-dimensional metering.", "category": "billing", "tags": ["Billing", "Metered Billing", "Usage-Based Pricing", "SaaS", "Invoicing", "Payment Processing", "Analytics", "API", "Open Source", "Revenue Management", "Subscription Management", "Financial Technology"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "getlago/api:v1.31.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Github", "url": "https://github.com/getlago/lago"}, {"label": "Website", "url": "https://getlago.com"}, {"label": "Documentation", "url": "https://docs.getlago.com"}], "instructions": "You have to generate a RSA private key \"openssl genrsa 2048 | base64\" and provide it to the service, otherwise the service will not work. You can contact Easypanel support if you need help.", "install": [{"docker": {"image": "$IMAGE", "name": "lago", "port": "$PORT:80", "volumes": ["/app/storage", "/app/storage"], "extra_ports": ["3000:3000"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "You have to generate a RSA private key \"openssl genrsa 2048 | base64\" and provide it to the service, otherwise the service will not work. You can contact Easypanel support if you need help."}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('langflow', 'Langflow', 'Langflow is an innovative application designed to facilitate the experimentation and prototyping of LangChain pipelines. It provides a user-friendly interface for creating flows by simply dragging and connecting LangChain components such as LLMs, prompt serializers, agents, and chains. You can easily modify prompt parameters, link chains and agents, track an agent''s thought process, and export your flow. Once your flow is ready, you can export it as a JSON file for use with LangChain. Langflow also integrates with langchain-serve for one-command deployment to Jina AI Cloud. With Langflow, building and deploying LangChain pipelines has never been easier.', 'data-science', ARRAY['Data Science', 'Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "langflowai/langflow:1.9.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 7860}}$JSON$::jsonb, $JSON${"metadata": {"name": "Langflow", "version": "latest", "description": "Langflow is an innovative application designed to facilitate the experimentation and prototyping of LangChain pipelines. It provides a user-friendly interface for creating flows by simply dragging and connecting LangChain components such as LLMs, prompt serializers, agents, and chains. You can easily modify prompt parameters, link chains and agents, track an agent's thought process, and export your flow. Once your flow is ready, you can export it as a JSON file for use with LangChain. Langflow also integrates with langchain-serve for one-command deployment to Jina AI Cloud. With Langflow, building and deploying LangChain pipelines has never been easier.", "category": "data-science", "tags": ["Data Science", "Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "langflowai/langflow:1.9.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 7860}}, "links": [{"label": "Github", "url": "https://github.com/logspace-ai/langflow"}], "instructions": "Default username=admin, password=admin", "install": [{"docker": {"image": "$IMAGE", "name": "langflow", "port": "$PORT:7860", "volumes": ["/var/lib/langflow"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Default username=admin, password=admin"}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('langfuse', 'Langfuse', 'Langfuse is a powerful, self-hosted observability platform designed for AI applications. It simplifies monitoring, debugging, and optimizing your AI workflows with detailed insights, customizable metrics, and flexible integrations. Langfuse provides a clean and intuitive interface, robust API access, and plugin support to extend its functionality. It ensures privacy and compliance by allowing you to maintain full control over your data with a self-hosted solution. The application is accessible via your host and supports multi-platform awareness, ensuring compatibility with various architectures.', 'observability', ARRAY['Observability', 'Self-Hosted', 'AI Monitoring', 'Analytics'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "langfuse/langfuse:3.174.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Langfuse", "version": "latest", "description": "Langfuse is a powerful, self-hosted observability platform designed for AI applications. It simplifies monitoring, debugging, and optimizing your AI workflows with detailed insights, customizable metrics, and flexible integrations. Langfuse provides a clean and intuitive interface, robust API access, and plugin support to extend its functionality. It ensures privacy and compliance by allowing you to maintain full control over your data with a self-hosted solution. The application is accessible via your host and supports multi-platform awareness, ensuring compatibility with various architectures.", "category": "observability", "tags": ["Observability", "Self-Hosted", "AI Monitoring", "Analytics"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "langfuse/langfuse:3.174.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Documentation", "url": "https://langfuse.com/docs"}, {"label": "Github", "url": "https://github.com/langfuse/langfuse"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "langfuse", "port": "$PORT:80", "volumes": ["/var/lib/clickhouse", "/var/log/clickhouse-server", "/data"], "extra_ports": ["9000:9000", "9001:9001"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('languagetool', 'Languagetool', 'LanguageTool is your personal writing assistant, designed to enhance your writing skills and ensure error-free communication. This multilingual app offers a comprehensive spelling, style, and grammar checker, capable of correcting or paraphrasing texts in a variety of languages. It integrates seamlessly with various platforms including browsers like Chrome, Edge, Firefox, Safari, Opera, and email platforms like Gmail and Outlook. It also works with office plugins such as Google Docs, Word, OpenOffice, and LibreOffice. LanguageTool is equipped with an AI-based style and grammar checker trusted by renowned organizations worldwide. It offers a distraction-free writing experience, a personal dictionary, and quality scoring for evaluating style and grammar. The app also features a ''Picky Mode'' for advanced punctuation, style, and typography suggestions. LanguageTool is not just about correcting mistakes, it also helps improve your writing style by detecting overused phrases, foreign terms, redundant words, and improper word choice. It even assists in paraphrasing sentences to make them more formal, fluent, simple or concise. LanguageTool is the perfect tool for anyone who wants to deliver clear, precise, and stylistically correct writing.', 'productivity', ARRAY['Productivity', 'Writing', 'Grammar Checker'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "silviof/docker-languagetool:6.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8010}}$JSON$::jsonb, $JSON${"metadata": {"name": "Languagetool", "version": "latest", "description": "LanguageTool is your personal writing assistant, designed to enhance your writing skills and ensure error-free communication. This multilingual app offers a comprehensive spelling, style, and grammar checker, capable of correcting or paraphrasing texts in a variety of languages. It integrates seamlessly with various platforms including browsers like Chrome, Edge, Firefox, Safari, Opera, and email platforms like Gmail and Outlook. It also works with office plugins such as Google Docs, Word, OpenOffice, and LibreOffice. LanguageTool is equipped with an AI-based style and grammar checker trusted by renowned organizations worldwide. It offers a distraction-free writing experience, a personal dictionary, and quality scoring for evaluating style and grammar. The app also features a 'Picky Mode' for advanced punctuation, style, and typography suggestions. LanguageTool is not just about correcting mistakes, it also helps improve your writing style by detecting overused phrases, foreign terms, redundant words, and improper word choice. It even assists in paraphrasing sentences to make them more formal, fluent, simple or concise. LanguageTool is the perfect tool for anyone who wants to deliver clear, precise, and stylistically correct writing.", "category": "productivity", "tags": ["Productivity", "Writing", "Grammar Checker"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "silviof/docker-languagetool:6.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8010}}, "links": [{"label": "Website", "url": "https://languagetool.org"}, {"label": "Github", "url": "https://github.com/languagetool-org/languagetool"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "languagetool", "port": "$PORT:8010", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('lavalink', 'Lavalink', 'Lavalink is a standalone audio sending node designed to facilitate the process of sending audio without it ever reaching any of your shards. It is powered by Lavaplayer and Koe, and is currently being used in production by several popular bots. The app offers a range of features including Twitch/YouTube stream support, an event system, seeking, volume control, and a REST API for resolving Lavaplayer tracks and controlling players. It also provides statistics which are useful for load balancing. Lavalink is designed to have a minimal CPU/memory footprint, and it supports plugins. It is compatible with Java 17 LTS or newer, and it follows Semantic Versioning.', 'developer-tools', ARRAY['Developer Tools', 'Media', 'Music'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "fredboat/lavalink:c7eb5d3-alpine"}, "port": {"type": "integer", "title": "Port HTTP", "default": 2333}}$JSON$::jsonb, $JSON${"metadata": {"name": "Lavalink", "version": "latest", "description": "Lavalink is a standalone audio sending node designed to facilitate the process of sending audio without it ever reaching any of your shards. It is powered by Lavaplayer and Koe, and is currently being used in production by several popular bots. The app offers a range of features including Twitch/YouTube stream support, an event system, seeking, volume control, and a REST API for resolving Lavaplayer tracks and controlling players. It also provides statistics which are useful for load balancing. Lavalink is designed to have a minimal CPU/memory footprint, and it supports plugins. It is compatible with Java 17 LTS or newer, and it follows Semantic Versioning.", "category": "developer-tools", "tags": ["Developer Tools", "Media", "Music"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "fredboat/lavalink:c7eb5d3-alpine"}, "port": {"type": "integer", "title": "Port HTTP", "default": 2333}}, "links": [{"label": "Documentation", "url": "https://github.com/freyacodes/Lavalink/blob/master/README.md"}, {"label": "Github", "url": "https://github.com/freyacodes/Lavalink"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "lavalink", "port": "$PORT:2333", "volumes": ["/opt/Lavalink"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('lazylibrarian', 'LazyLibrarian', 'LazyLibrarian is an open-source tool designed to manage and automate the downloading, organizing, and serving of eBooks, audiobooks, and magazines. It integrates seamlessly with Usenet and torrent services to fetch content based on user preferences. With LazyLibrarian, you can search, download, and manage your media library effortlessly. It supports multiple download providers, metadata retrieval, and integration with Calibre for organizing your eBook collection. LazyLibrarian is user-friendly, flexible, and provides a centralized solution for book lovers to manage their digital libraries.', 'ebooks', ARRAY['eBooks', 'Audiobooks', 'Library', 'Media Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/lazylibrarian:c3a20585-ls280"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5299}}$JSON$::jsonb, $JSON${"metadata": {"name": "LazyLibrarian", "version": "latest", "description": "LazyLibrarian is an open-source tool designed to manage and automate the downloading, organizing, and serving of eBooks, audiobooks, and magazines. It integrates seamlessly with Usenet and torrent services to fetch content based on user preferences. With LazyLibrarian, you can search, download, and manage your media library effortlessly. It supports multiple download providers, metadata retrieval, and integration with Calibre for organizing your eBook collection. LazyLibrarian is user-friendly, flexible, and provides a centralized solution for book lovers to manage their digital libraries.", "category": "ebooks", "tags": ["eBooks", "Audiobooks", "Library", "Media Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/lazylibrarian:c3a20585-ls280"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5299}}, "links": [{"label": "Website", "url": "https://lazylibrarian.gitlab.io"}, {"label": "Documentation", "url": "https://lazylibrarian.gitlab.io"}, {"label": "Github", "url": "https://gitlab.com/LazyLibrarian/LazyLibrarian"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "lazylibrarian", "port": "$PORT:5299", "volumes": ["/config", "/downloads", "/books"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('leantime', 'Leantime', 'Leantime is an open-source project management system designed for startups and small teams. It offers a simple and intuitive interface to manage tasks, projects, and team collaboration efficiently. With Leantime, you can organize your work using timelines, kanban boards, and task lists. It also includes features like time tracking, milestones, and idea boards to streamline project workflows. Leantime supports integrations with various third-party tools, making it a flexible and scalable solution. Its emphasis on usability and simplicity ensures that teams can focus on productivity and achieving goals. Leantime is distributed under an open-source license, allowing for customization to meet the unique needs of any organization.', 'project-management', ARRAY['Project Management', 'Open Source', 'Collaboration', 'Task Management', 'Kanban', 'Time Tracking', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "leantime/leantime:3.7.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}$JSON$::jsonb, $JSON${"metadata": {"name": "Leantime", "version": "latest", "description": "Leantime is an open-source project management system designed for startups and small teams. It offers a simple and intuitive interface to manage tasks, projects, and team collaboration efficiently. With Leantime, you can organize your work using timelines, kanban boards, and task lists. It also includes features like time tracking, milestones, and idea boards to streamline project workflows. Leantime supports integrations with various third-party tools, making it a flexible and scalable solution. Its emphasis on usability and simplicity ensures that teams can focus on productivity and achieving goals. Leantime is distributed under an open-source license, allowing for customization to meet the unique needs of any organization.", "category": "project-management", "tags": ["Project Management", "Open Source", "Collaboration", "Task Management", "Kanban", "Time Tracking", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "leantime/leantime:3.7.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}}, "links": [{"label": "Website", "url": "https://leantime.io/"}, {"label": "Documentation", "url": "https://docs.leantime.io/"}, {"label": "Github", "url": "https://github.com/Leantime/leantime"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "leantime", "port": "$PORT:8080", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('lenpaste', 'Lenpaste', 'Lenpaste is a web service that allows you to share notes anonymously. It is an open-source alternative to pastebin.com. The app supports multiple languages and uses cookies only to store settings. It can work without JavaScript and has its own API. Lenpaste allows you to set maximum length for the paste title and body, maximum lifetime of the paste, and rate limits for viewing and creating pastes. It also provides options to prohibit search engine crawlers from indexing the site and to set information about the server admin. Lenpaste is self-hosted and provides a list of public servers managed by various contributors.', 'code-hosting', ARRAY['Code Hosting', 'Documents', 'Notes'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "git.lcomrade.su/root/lenpaste:1.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}$JSON$::jsonb, $JSON${"metadata": {"name": "Lenpaste", "version": "latest", "description": "Lenpaste is a web service that allows you to share notes anonymously. It is an open-source alternative to pastebin.com. The app supports multiple languages and uses cookies only to store settings. It can work without JavaScript and has its own API. Lenpaste allows you to set maximum length for the paste title and body, maximum lifetime of the paste, and rate limits for viewing and creating pastes. It also provides options to prohibit search engine crawlers from indexing the site and to set information about the server admin. Lenpaste is self-hosted and provides a list of public servers managed by various contributors.", "category": "code-hosting", "tags": ["Code Hosting", "Documents", "Notes"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "git.lcomrade.su/root/lenpaste:1.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}}, "links": [{"label": "Documentation", "url": "https://git.lcomrade.su/root/lenpaste/src/branch/main/docs"}, {"label": "Gitea", "url": "https://git.lcomrade.su/root/lenpaste"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "lenpaste", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('librechat', 'LibreChat', 'LibreChat is a free, open source clone of ChatGPT that supports multiple AI providers and models. It offers a familiar chat interface with support for OpenAI, Anthropic, Google, Azure OpenAI, and many other AI providers. LibreChat features conversation management, preset configurations, plugin support, multi-user authentication, and extensive customization options. It includes advanced features like RAG (Retrieval Augmented Generation), web search capabilities, file uploads, image generation, and comprehensive user management. Perfect for organizations and individuals who want ChatGPT-like functionality while maintaining full control over their data and conversations.', 'ai', ARRAY['AI', 'ChatGPT', 'OpenAI', 'Anthropic', 'Google', 'Multi-Provider', 'RAG', 'Chat Interface', 'Self-Hosted', 'Enterprise'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 3080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "LibreChat", "version": "latest", "description": "LibreChat is a free, open source clone of ChatGPT that supports multiple AI providers and models. It offers a familiar chat interface with support for OpenAI, Anthropic, Google, Azure OpenAI, and many other AI providers. LibreChat features conversation management, preset configurations, plugin support, multi-user authentication, and extensive customization options. It includes advanced features like RAG (Retrieval Augmented Generation), web search capabilities, file uploads, image generation, and comprehensive user management. Perfect for organizations and individuals who want ChatGPT-like functionality while maintaining full control over their data and conversations.", "category": "ai", "tags": ["AI", "ChatGPT", "OpenAI", "Anthropic", "Google", "Multi-Provider", "RAG", "Chat Interface", "Self-Hosted", "Enterprise"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 3080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://librechat.ai"}, {"label": "Documentation", "url": "https://docs.librechat.ai"}, {"label": "GitHub", "url": "https://github.com/danny-avila/LibreChat"}], "instructions": "Configure the OpenAI API Key.", "install": [{"docker": {"image": "$IMAGE", "name": "librechat", "port": "$PORT:3080", "volumes": ["/app/client/public/images", "/app/uploads", "/app/api/logs", "/app/librechat.yaml", "/meili_data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Configure the OpenAI API Key."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('libredesk', 'Libredesk', 'Libredesk is a modern, self-hosted helpdesk and customer support platform built with Rust. It provides a comprehensive solution for managing customer inquiries, tickets, and support workflows. Libredesk features a clean web interface, multi-user support, ticket management, and integration capabilities for businesses of all sizes.', 'helpdesk', ARRAY['Helpdesk', 'Customer Support', 'Ticket Management', 'Self-Hosted', 'Web Interface'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "libredesk/libredesk:v1.0.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Libredesk", "version": "latest", "description": "Libredesk is a modern, self-hosted helpdesk and customer support platform built with Rust. It provides a comprehensive solution for managing customer inquiries, tickets, and support workflows. Libredesk features a clean web interface, multi-user support, ticket management, and integration capabilities for businesses of all sizes.", "category": "helpdesk", "tags": ["Helpdesk", "Customer Support", "Ticket Management", "Self-Hosted", "Web Interface"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "libredesk/libredesk:v1.0.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://libredesk.io"}, {"label": "Documentation", "url": "https://docs.libredesk.io/introduction"}, {"label": "DockerHub", "url": "https://hub.docker.com/r/libredesk/libredesk"}], "instructions": "Default credentials are System/${SystemUserPassword}", "install": [{"docker": {"image": "$IMAGE", "name": "libredesk", "port": "$PORT:9000", "volumes": ["/libredesk/uploads", "/libredesk/config.toml"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Default credentials are System/${SystemUserPassword}"}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('librenms', 'LibreNMS', 'LibreNMS is a fully featured network monitoring system that provides a wealth of features and device support. It includes support for multiple authentication methods, API access, alerting, and automatic discovery.', 'network-monitoring', ARRAY['Network Monitoring', 'SNMP', 'Syslog', 'Self-Hosted', 'Network Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "librenms/librenms:25.3.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 162}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "LibreNMS", "version": "latest", "description": "LibreNMS is a fully featured network monitoring system that provides a wealth of features and device support. It includes support for multiple authentication methods, API access, alerting, and automatic discovery.", "category": "network-monitoring", "tags": ["Network Monitoring", "SNMP", "Syslog", "Self-Hosted", "Network Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "librenms/librenms:25.3.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 162}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.librenms.org"}, {"label": "Documentation", "url": "https://docs.librenms.org"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "librenms", "port": "$PORT:162", "volumes": ["/data", "/data", "/data", "/data"], "extra_ports": ["514:514", "8000:8000"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('libreoffice', 'LibreOffice', 'LibreOffice is a free and powerful office suite app that serves as a successor to OpenOffice.org. It features a clean interface and feature-rich tools that help you unleash your creativity and enhance your productivity. The app can be accessed at http://yourhost:3000/ or https://yourhost:3001/. It is designed to deliver a true lossless image at a high framerate to your web browser. The app also supports multiple architectures, ensuring that it can be used on a variety of platforms. This app is perfect for those who need a comprehensive office suite for their daily tasks.', 'productivity', ARRAY['Productivity', 'Documents', 'Office Suite'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/libreoffice:25.8.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "LibreOffice", "version": "latest", "description": "LibreOffice is a free and powerful office suite app that serves as a successor to OpenOffice.org. It features a clean interface and feature-rich tools that help you unleash your creativity and enhance your productivity. The app can be accessed at http://yourhost:3000/ or https://yourhost:3001/. It is designed to deliver a true lossless image at a high framerate to your web browser. The app also supports multiple architectures, ensuring that it can be used on a variety of platforms. This app is perfect for those who need a comprehensive office suite for their daily tasks.", "category": "productivity", "tags": ["Productivity", "Documents", "Office Suite"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/libreoffice:25.8.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://docs.linuxserver.io/images/docker-libreoffice"}, {"label": "Github", "url": "https://github.com/linuxserver/docker-libreoffice"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "libreoffice", "port": "$PORT:3000", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('librespeed', 'LibreSpeed', 'LibreSpeed is a free and open-source HTML5-based speed test application that you can host on your own server. It provides a lightweight, self-hosted alternative to commercial speed test services like Speedtest.net. LibreSpeed allows you to measure download speed, upload speed, ping, and jitter of your internet connection through a clean, modern web interface. It''s perfect for network administrators, ISPs, or anyone who wants to monitor their internet connection performance without relying on third-party services. The application stores test results and provides analytics to track connection quality over time.', 'speed-test', ARRAY['Speed Test', 'Network Tools', 'Self-Hosted', 'Performance Monitoring', 'Bandwidth Testing', 'Internet Speed', 'Network Diagnostics', 'Analytics'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/librespeed:5.4.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "LibreSpeed", "version": "latest", "description": "LibreSpeed is a free and open-source HTML5-based speed test application that you can host on your own server. It provides a lightweight, self-hosted alternative to commercial speed test services like Speedtest.net. LibreSpeed allows you to measure download speed, upload speed, ping, and jitter of your internet connection through a clean, modern web interface. It's perfect for network administrators, ISPs, or anyone who wants to monitor their internet connection performance without relying on third-party services. The application stores test results and provides analytics to track connection quality over time.", "category": "speed-test", "tags": ["Speed Test", "Network Tools", "Self-Hosted", "Performance Monitoring", "Bandwidth Testing", "Internet Speed", "Network Diagnostics", "Analytics"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/librespeed:5.4.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/librespeed/speedtest"}, {"label": "Documentation", "url": "https://docs.linuxserver.io/images/docker-librespeed/"}, {"label": "Demo", "url": "https://librespeed.org/"}], "instructions": "Leave \"Results Password\" empty to auto-generate a strong password at deploy time, or set your own value if you want a fixed credential. After deployment, open LibreSpeed from your app domain and use the configured password to access historical test results.", "install": [{"docker": {"image": "$IMAGE", "name": "librespeed", "port": "$PORT:80", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Leave \"Results Password\" empty to auto-generate a strong password at deploy time, or set your own value if you want a fixed credential. After deployment, open LibreSpeed from your app domain and use the configured password to access historical test results."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('libretranslate', 'LibreTranslate', 'LibreTranslate is a free and open-source machine translation app that is entirely self-hosted. Unlike other translation apps, it does not rely on proprietary providers such as Google or Azure to perform translations. Instead, its translation engine is powered by the open-source Argos Translate library. LibreTranslate can translate text between different languages, auto-detect the language of the input text, and even handle HTML content. It provides a simple and intuitive interface for users to input the text they want to translate, select the source and target languages, and get the translated text. With LibreTranslate, you can enjoy a reliable, accurate, and privacy-friendly translation service right at your fingertips.', 'translation', ARRAY['Translation', 'API', 'Open Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "libretranslate/libretranslate:v1.9.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "LibreTranslate", "version": "latest", "description": "LibreTranslate is a free and open-source machine translation app that is entirely self-hosted. Unlike other translation apps, it does not rely on proprietary providers such as Google or Azure to perform translations. Instead, its translation engine is powered by the open-source Argos Translate library. LibreTranslate can translate text between different languages, auto-detect the language of the input text, and even handle HTML content. It provides a simple and intuitive interface for users to input the text they want to translate, select the source and target languages, and get the translated text. With LibreTranslate, you can enjoy a reliable, accurate, and privacy-friendly translation service right at your fingertips.", "category": "translation", "tags": ["Translation", "API", "Open Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "libretranslate/libretranslate:v1.9.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://github.com/LibreTranslate/LibreTranslate/blob/master/README.md"}, {"label": "Github", "url": "https://github.com/LibreTranslate/LibreTranslate"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "libretranslate", "port": "$PORT:5000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('lidarr', 'Lidarr', 'Lidarr is an audio collection manager designed for Usenet and BitTorrent users. It monitors multiple RSS feeds for new music and interfaces with clients and indexers to grab, sort, and rename albums and songs. Lidarr also has the capability to automatically upgrade the quality of existing tracks in your library when a better quality format becomes available. The app features a calendar to see all your upcoming releases in one place, manual search to find all the releases and choose the ones you want, and automatic handling of failed downloads. Lidarr ensures you get the right release every time with its custom formats feature, which allows fine control over release prioritization and selection. It also supports major platforms like Windows, Linux, macOS, and others.', 'media', ARRAY['Media', 'Download Manager', 'Music'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/lidarr:3.1.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8686}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Lidarr", "version": "latest", "description": "Lidarr is an audio collection manager designed for Usenet and BitTorrent users. It monitors multiple RSS feeds for new music and interfaces with clients and indexers to grab, sort, and rename albums and songs. Lidarr also has the capability to automatically upgrade the quality of existing tracks in your library when a better quality format becomes available. The app features a calendar to see all your upcoming releases in one place, manual search to find all the releases and choose the ones you want, and automatic handling of failed downloads. Lidarr ensures you get the right release every time with its custom formats feature, which allows fine control over release prioritization and selection. It also supports major platforms like Windows, Linux, macOS, and others.", "category": "media", "tags": ["Media", "Download Manager", "Music"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/lidarr:3.1.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8686}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://lidarr.audio/"}, {"label": "Documentation", "url": "https://wiki.servarr.com/lidarr"}, {"label": "Github", "url": "https://github.com/Lidarr/Lidarr"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "lidarr", "port": "$PORT:8686", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('lightdash', 'LightDash', 'LightDash is a modern, open-source business intelligence (BI) and data exploration tool designed to help teams visualize and understand their data. It connects directly to your existing data warehouse and provides an intuitive interface for building and sharing dashboards. With LightDash, you can create actionable insights from your data without needing advanced technical skills.', 'business-intelligence', ARRAY['Business Intelligence', 'Data Visualization', 'Open Source', 'Data Analytics'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lightdash/lightdash:0.2503.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "LightDash", "version": "latest", "description": "LightDash is a modern, open-source business intelligence (BI) and data exploration tool designed to help teams visualize and understand their data. It connects directly to your existing data warehouse and provides an intuitive interface for building and sharing dashboards. With LightDash, you can create actionable insights from your data without needing advanced technical skills.", "category": "business-intelligence", "tags": ["Business Intelligence", "Data Visualization", "Open Source", "Data Analytics"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lightdash/lightdash:0.2503.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://docs.lightdash.com/"}, {"label": "Github", "url": "https://github.com/lightdash/lightdash"}], "instructions": "Configure the Environmental Variables as per the requirements.", "install": [{"docker": {"image": "$IMAGE", "name": "lightdash", "port": "$PORT:3000", "volumes": ["/usr/app/dbt"], "extra_ports": ["8080:8080"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Configure the Environmental Variables as per the requirements."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('limesurvey', 'Limesurvey', 'Welcome to LimeSurvey, the world''s #1 survey platform designed to provide you with the best online survey tool that''s fresh, quick, and anonymous. Whether you''re a student, professional, or enterprise, LimeSurvey allows you to design a survey and gather insightful data, all for free. With LimeSurvey, you can create a simple questionnaire or poll, or even a sophisticated survey with complex validation rules, conditional logic, and quota management. It''s the perfect alternative to Google Forms or Doodle. LimeSurvey is also the optimal online survey tool for research institutes, universities, and other educational establishments, offering free surveys, polls, and other open-source possibilities. With easy-to-use templates and an on-hand customer service team, LimeSurvey is your go-to solution for all your survey needs.', 'analytics', ARRAY['Analytics', 'Business Apps', 'Educational'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "tiredofit/limesurvey:6-1.6.99"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Limesurvey", "version": "latest", "description": "Welcome to LimeSurvey, the world's #1 survey platform designed to provide you with the best online survey tool that's fresh, quick, and anonymous. Whether you're a student, professional, or enterprise, LimeSurvey allows you to design a survey and gather insightful data, all for free. With LimeSurvey, you can create a simple questionnaire or poll, or even a sophisticated survey with complex validation rules, conditional logic, and quota management. It's the perfect alternative to Google Forms or Doodle. LimeSurvey is also the optimal online survey tool for research institutes, universities, and other educational establishments, offering free surveys, polls, and other open-source possibilities. With easy-to-use templates and an on-hand customer service team, LimeSurvey is your go-to solution for all your survey needs.", "category": "analytics", "tags": ["Analytics", "Business Apps", "Educational"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "tiredofit/limesurvey:6-1.6.99"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://limesurvey.org/"}, {"label": "Documentation", "url": "https://manual.limesurvey.org"}, {"label": "Github", "url": "https://github.com/LimeSurvey/LimeSurvey"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "limesurvey", "port": "$PORT:80", "volumes": ["/www/html/upload", "/www/logs", "/assets/custom"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('lingva', 'Lingva Translate', 'Lingva Translate is a free, open-source alternative front-end for Google Translate. Supports 100+ languages via scraping—no direct Google access, no user tracking. Built with Next.js and ChakraUI. Provides REST API for translation, audio, and language detection. Privacy-focused translation.', 'translation', ARRAY['Translation', 'Google Translate', 'Privacy', 'Open Source', 'Self-hosted', 'API'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "thedaviddelta/lingva-translate:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Lingva Translate", "version": "latest", "description": "Lingva Translate is a free, open-source alternative front-end for Google Translate. Supports 100+ languages via scraping\u2014no direct Google access, no user tracking. Built with Next.js and ChakraUI. Provides REST API for translation, audio, and language detection. Privacy-focused translation.", "category": "translation", "tags": ["Translation", "Google Translate", "Privacy", "Open Source", "Self-hosted", "API"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "thedaviddelta/lingva-translate:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://lingva.thedaviddelta.com"}, {"label": "GitHub", "url": "https://github.com/TheDavidDelta/lingva-translate"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/thedaviddelta/lingva-translate"}], "instructions": "After deployment, access the web UI on your assigned domain. Set the site\ndomain to your public URL (e.g. https://lingva.yourdomain.com) for correct\nAPI links. Use the REST API at /api/v1/:source/:target/:query for translations.\n", "install": [{"docker": {"image": "$IMAGE", "name": "lingva", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deployment, access the web UI on your assigned domain. Set the site\ndomain to your public URL (e.g. https://lingva.yourdomain.com) for correct\nAPI links. Use the REST API at /api/v1/:source/:target/:query for translations.\n"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('linkding', 'linkding', 'Linkding is a self-hosted bookmark manager that allows you to efficiently manage and organize your bookmarks. With a clean and optimized user interface, you can easily add, share, and edit bookmarks. The app also allows you to add notes to your bookmarks using Markdown and provides a ''read it later'' functionality. It automatically generates titles, descriptions, and icons for your bookmarked websites and creates snapshots of them on the Internet Archive Wayback Machine. You can also import and export bookmarks in Netscape HTML format. The app offers light and dark themes for your convenience. It also provides a REST API for developing third-party apps and an admin panel for user self-service and raw data access.', 'bookmarks', ARRAY['Bookmarks', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "sissbruecker/linkding:1.45.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9090}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "linkding", "version": "latest", "description": "Linkding is a self-hosted bookmark manager that allows you to efficiently manage and organize your bookmarks. With a clean and optimized user interface, you can easily add, share, and edit bookmarks. The app also allows you to add notes to your bookmarks using Markdown and provides a 'read it later' functionality. It automatically generates titles, descriptions, and icons for your bookmarked websites and creates snapshots of them on the Internet Archive Wayback Machine. You can also import and export bookmarks in Netscape HTML format. The app offers light and dark themes for your convenience. It also provides a REST API for developing third-party apps and an admin panel for user self-service and raw data access.", "category": "bookmarks", "tags": ["Bookmarks", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "sissbruecker/linkding:1.45.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9090}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/sissbruecker/linkding"}, {"label": "Demo", "url": "https://demo.linkding.link/"}], "instructions": "If the login fails with a error 500, please restart the \"linkding\" app service. This can be caused by the database not being properly reachable at linkding's first start.", "install": [{"docker": {"image": "$IMAGE", "name": "linkding", "port": "$PORT:9090", "volumes": ["/etc/linkding/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "If the login fails with a error 500, please restart the \"linkding\" app service. This can be caused by the database not being properly reachable at linkding's first start."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('linkedout', 'LinkedOut', 'A comprehensive LinkedIn automation platform that helps streamline your LinkedIn outreach and engagement. The platform combines a modern Next.js frontend for managing campaigns and contacts, a robust PocketBase backend for secure data storage and user management, and powerful n8n workflow automation for handling LinkedIn interactions and follow-ups. With optional ngrok tunneling support for local development and testing, and easy deployment via Docker and Easypanel, LinkedOut provides everything needed to automate and scale your LinkedIn presence effectively.', 'linkedin', ARRAY['LinkedIn', 'Automation', 'Workflow', 'Social Media'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "dockeriddonuts/easypanel-linkedout-frontend:1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "LinkedOut", "version": "latest", "description": "A comprehensive LinkedIn automation platform that helps streamline your LinkedIn outreach and engagement. The platform combines a modern Next.js frontend for managing campaigns and contacts, a robust PocketBase backend for secure data storage and user management, and powerful n8n workflow automation for handling LinkedIn interactions and follow-ups. With optional ngrok tunneling support for local development and testing, and easy deployment via Docker and Easypanel, LinkedOut provides everything needed to automate and scale your LinkedIn presence effectively.", "category": "linkedin", "tags": ["LinkedIn", "Automation", "Workflow", "Social Media"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "dockeriddonuts/easypanel-linkedout-frontend:1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://github.com/maxt-n8n/linkedout#readme"}, {"label": "GitHub", "url": "https://github.com/maxt-n8n/linkedout"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "linkedout", "port": "$PORT:3000", "volumes": ["/app/data", "/pb_data", "/home/node/.n8n"], "extra_ports": ["4040:4040", "5678:5678", "8090:8090"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('linksnatch', 'Linksnatch', 'Linksnatch is a link management application that helps you organize and track your bookmarks and URLs. It provides a simple interface for managing and categorizing your links.', 'bookmark-manager', ARRAY['Bookmark Manager', 'Link Management', 'Organization', 'Self-Hosted', 'Web Application'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "varunsridharan/linksnatch:1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Linksnatch", "version": "latest", "description": "Linksnatch is a link management application that helps you organize and track your bookmarks and URLs. It provides a simple interface for managing and categorizing your links.", "category": "bookmark-manager", "tags": ["Bookmark Manager", "Link Management", "Organization", "Self-Hosted", "Web Application"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "varunsridharan/linksnatch:1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/amitmerchant1990/linksnatch"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "linksnatch", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('linkstack', 'LinkStack', 'LinkStack is a powerful open-source alternative to Linktree, designed to provide an efficient solution for managing and sharing links online. It offers a highly customizable link sharing platform with an intuitive, user-friendly interface. Unlike other link management platforms, LinkStack allows users to host their links on their own web server or web hosting provider, giving them complete control over their online presence. This makes LinkStack an ideal solution for businesses and organizations looking to manage multiple links. With LinkStack, users can easily link to their own custom page and provide their followers with access to all the links they need in one convenient location. LinkStack also offers a self-hosted option for users who want complete control over their data without having it sold to third-party companies. The platform can be easily implemented through a simple drag and drop process, eliminating the need for complex terminal commands or source code manipulation. LinkStack is committed to providing a free, privacy-focused solution for managing and sharing links online, without sacrificing user privacy and control over their data.', 'link-management', ARRAY['Link Management', 'Customizable', 'Privacy-Focused'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "linkstackorg/linkstack:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "LinkStack", "version": "latest", "description": "LinkStack is a powerful open-source alternative to Linktree, designed to provide an efficient solution for managing and sharing links online. It offers a highly customizable link sharing platform with an intuitive, user-friendly interface. Unlike other link management platforms, LinkStack allows users to host their links on their own web server or web hosting provider, giving them complete control over their online presence. This makes LinkStack an ideal solution for businesses and organizations looking to manage multiple links. With LinkStack, users can easily link to their own custom page and provide their followers with access to all the links they need in one convenient location. LinkStack also offers a self-hosted option for users who want complete control over their data without having it sold to third-party companies. The platform can be easily implemented through a simple drag and drop process, eliminating the need for complex terminal commands or source code manipulation. LinkStack is committed to providing a free, privacy-focused solution for managing and sharing links online, without sacrificing user privacy and control over their data.", "category": "link-management", "tags": ["Link Management", "Customizable", "Privacy-Focused"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "linkstackorg/linkstack:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/linkstackorg/linkstack"}, {"label": "Website", "url": "https://linkstack.org"}], "instructions": "Use the SQLite DB type in the installation wizard", "install": [{"docker": {"image": "$IMAGE", "name": "linkstack", "port": "$PORT:80", "volumes": ["/htdocs"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Use the SQLite DB type in the installation wizard"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('linkwarden', 'LinkWarden', 'LinkWarden is a powerful, self-hosted service designed for managing and archiving bookmarks. It provides an intuitive interface for organizing and accessing your saved links, supports advanced features for enhanced productivity, and offers detailed link preservation options. With LinkWarden, you can maintain control over your bookmarks and ensure they remain accessible.', 'bookmark-manager', ARRAY['Bookmark Manager', 'Self-Hosted', 'Productivity', 'Archiving'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/linkwarden/linkwarden:v2.14.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "LinkWarden", "version": "latest", "description": "LinkWarden is a powerful, self-hosted service designed for managing and archiving bookmarks. It provides an intuitive interface for organizing and accessing your saved links, supports advanced features for enhanced productivity, and offers detailed link preservation options. With LinkWarden, you can maintain control over your bookmarks and ensure they remain accessible.", "category": "bookmark-manager", "tags": ["Bookmark Manager", "Self-Hosted", "Productivity", "Archiving"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/linkwarden/linkwarden:v2.14.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://linkwarden.app/docs"}, {"label": "Github", "url": "https://github.com/linkwarden/linkwarden"}], "instructions": "Configure Environment Variables as per your needs.", "install": [{"docker": {"image": "$IMAGE", "name": "linkwarden", "port": "$PORT:3000", "volumes": ["/data/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Configure Environment Variables as per your needs."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('listmonk', 'Listmonk', 'Listmonk is a self-hosted, high-performance mailing list and newsletter manager. It is designed to manage millions of subscribers across various single and double opt-in lists, with custom JSON attributes for each subscriber. The app allows you to query and segment subscribers with SQL expressions and offers a fast bulk importer for easy integration with external CRMs and subscriber databases. Listmonk also provides a simple API for sending transactional messages to subscribers using pre-defined templates. These messages can be sent via email, SMS, Whatsapp, or any medium via Messenger interfaces. The app also includes simple analytics and visualization tools, a powerful templating system for creating dynamic email templates, and a media manager for uploading images for email campaigns. Listmonk is free, open-source, and designed for high performance, with a single binary application that runs everywhere with a minimal CPU and memory footprint.', 'email', ARRAY['Email', 'Analytics', 'Privacy'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "listmonk/listmonk:v5.1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Listmonk", "version": "latest", "description": "Listmonk is a self-hosted, high-performance mailing list and newsletter manager. It is designed to manage millions of subscribers across various single and double opt-in lists, with custom JSON attributes for each subscriber. The app allows you to query and segment subscribers with SQL expressions and offers a fast bulk importer for easy integration with external CRMs and subscriber databases. Listmonk also provides a simple API for sending transactional messages to subscribers using pre-defined templates. These messages can be sent via email, SMS, Whatsapp, or any medium via Messenger interfaces. The app also includes simple analytics and visualization tools, a powerful templating system for creating dynamic email templates, and a media manager for uploading images for email campaigns. Listmonk is free, open-source, and designed for high performance, with a single binary application that runs everywhere with a minimal CPU and memory footprint.", "category": "email", "tags": ["Email", "Analytics", "Privacy"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "listmonk/listmonk:v5.1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://listmonk.app/"}, {"label": "Documentation", "url": "https://listmonk.app/docs/"}, {"label": "Github", "url": "https://github.com/knadh/listmonk"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "listmonk", "port": "$PORT:9000", "volumes": ["/listmonk/uploads"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('litecart', 'LiteCart', 'LiteCart is a free and open-source e-commerce platform that provides a complete solution for creating and managing online stores. It features a user-friendly interface, customizable themes, and essential e-commerce functionality including product management, order processing, and customer management. LiteCart is built with PHP and MySQL, making it easy to deploy and maintain.', 'e-commerce', ARRAY['E-commerce', 'Online Store', 'Shopping Cart', 'PHP', 'MySQL'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "shurco/litecart:v0.2.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "LiteCart", "version": "latest", "description": "LiteCart is a free and open-source e-commerce platform that provides a complete solution for creating and managing online stores. It features a user-friendly interface, customizable themes, and essential e-commerce functionality including product management, order processing, and customer management. LiteCart is built with PHP and MySQL, making it easy to deploy and maintain.", "category": "e-commerce", "tags": ["E-commerce", "Online Store", "Shopping Cart", "PHP", "MySQL"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "shurco/litecart:v0.2.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.litecart.net/"}, {"label": "Documentation", "url": "https://www.litecart.net/en/wiki/"}, {"label": "Github", "url": "https://github.com/litecart/litecart"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "litecart", "port": "$PORT:8080", "volumes": ["/lc_base", "/lc_digitals", "/lc_uploads", "/site"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('litellm', 'LiteLLM', 'LiteLLM is a lightweight, self-hosted library designed for integrating language models like GPT into your applications. It provides an easy-to-use interface for sending and receiving prompts and responses, with support for multiple model configurations, API keys, and detailed debugging options. With LiteLLM, you can streamline your AI workflows while maintaining full control over your data and configurations.', 'language-models', ARRAY['Language Models', 'Self-Hosted', 'AI Integration'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/berriai/litellm:v1.85.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "LiteLLM", "version": "latest", "description": "LiteLLM is a lightweight, self-hosted library designed for integrating language models like GPT into your applications. It provides an easy-to-use interface for sending and receiving prompts and responses, with support for multiple model configurations, API keys, and detailed debugging options. With LiteLLM, you can streamline your AI workflows while maintaining full control over your data and configurations.", "category": "language-models", "tags": ["Language Models", "Self-Hosted", "AI Integration"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/berriai/litellm:v1.85.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://docs.litellm.ai/docs/"}, {"label": "Github", "url": "https://github.com/berriai/litellm"}], "instructions": "Use the provided master-key as the password for UI login.", "install": [{"docker": {"image": "$IMAGE", "name": "litellm", "port": "$PORT:4000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Use the provided master-key as the password for UI login."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('livebook', 'Livebook', 'Livebook is a web application for writing interactive and collaborative code notebooks for Elixir. It features an intuitive and interactive workflow for data science and machine learning in Elixir, with support for rich output including charts, maps, tables, and more. Livebook allows you to create, share, and collaborate on notebooks that combine narrative, code, and results in a single document.', 'development', ARRAY['Development', 'Elixir', 'Notebook', 'Data Science', 'Interactive'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/livebook-dev/livebook:0.16.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Livebook", "version": "latest", "description": "Livebook is a web application for writing interactive and collaborative code notebooks for Elixir. It features an intuitive and interactive workflow for data science and machine learning in Elixir, with support for rich output including charts, maps, tables, and more. Livebook allows you to create, share, and collaborate on notebooks that combine narrative, code, and results in a single document.", "category": "development", "tags": ["Development", "Elixir", "Notebook", "Data Science", "Interactive"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/livebook-dev/livebook:0.16.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://livebook.dev/"}, {"label": "GitHub", "url": "https://github.com/livebook-dev/livebook"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "livebook", "port": "$PORT:8080", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('livestreamdvr', 'LiveStreamDVR', 'LiveStreamDVR (formerly TwitchAutomator) is a powerful tool for automatically recording and archiving live streams from Twitch. It provides a web interface to manage recordings, schedule streams to record, and organize your VOD library.', 'twitch', ARRAY['Twitch', 'Streaming', 'Recording', 'VOD', 'Archive'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "mrbrax/twitchautomator:master"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "LiveStreamDVR", "version": "latest", "description": "LiveStreamDVR (formerly TwitchAutomator) is a powerful tool for automatically recording and archiving live streams from Twitch. It provides a web interface to manage recordings, schedule streams to record, and organize your VOD library.", "category": "twitch", "tags": ["Twitch", "Streaming", "Recording", "VOD", "Archive"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "mrbrax/twitchautomator:master"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/MrBrax/LiveStreamDVR"}], "instructions": "After installation, access the web interface through the provided domain to start configuring your stream recordings.", "install": [{"docker": {"image": "$IMAGE", "name": "livestreamdvr", "port": "$PORT:8080", "volumes": ["/usr/local/share/twitchautomator/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After installation, access the web interface through the provided domain to start configuring your stream recordings."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('llana', 'llana', 'Llana is a lightweight no-code API wrapper that exposes a REST API for any database within minutes. Stop wasting time building endpoints, just connect your database and start playing. Open source, free to use, and no vendor lock-in.', 'api', ARRAY['API', 'No-Code', 'Database', 'Open Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "juicyllama/llana:v1.32"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "llana", "version": "latest", "description": "Llana is a lightweight no-code API wrapper that exposes a REST API for any database within minutes. Stop wasting time building endpoints, just connect your database and start playing. Open source, free to use, and no vendor lock-in.", "category": "api", "tags": ["API", "No-Code", "Database", "Open Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "juicyllama/llana:v1.32"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://llana.io/"}, {"label": "GitHub", "url": "https://github.com/juicyllama/llana"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "llana", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('lldap', 'LLDAP', 'LLDAP (Lightweight LDAP) is a simple, lightweight, high-performance LDAP server designed for authentication in small to medium-sized deployments. It provides an intuitive web UI for user management and a complete implementation of LDAP search and bind operations. LLDAP is perfect for self-hosted applications that require LDAP authentication without the complexity of full-featured LDAP servers like OpenLDAP. It stores user data in an embedded SQLite database by default but also supports PostgreSQL, making it easy to set up and maintain. With features like password hashing, account creation/deletion, group management, and MFA support, LLDAP offers a modern solution for identity management in your self-hosted infrastructure.', 'ldap', ARRAY['LDAP', 'Authentication', 'Identity Management', 'User Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lldap/lldap:2026-05-05"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3890}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "LLDAP", "version": "latest", "description": "LLDAP (Lightweight LDAP) is a simple, lightweight, high-performance LDAP server designed for authentication in small to medium-sized deployments. It provides an intuitive web UI for user management and a complete implementation of LDAP search and bind operations. LLDAP is perfect for self-hosted applications that require LDAP authentication without the complexity of full-featured LDAP servers like OpenLDAP. It stores user data in an embedded SQLite database by default but also supports PostgreSQL, making it easy to set up and maintain. With features like password hashing, account creation/deletion, group management, and MFA support, LLDAP offers a modern solution for identity management in your self-hosted infrastructure.", "category": "ldap", "tags": ["LDAP", "Authentication", "Identity Management", "User Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lldap/lldap:2026-05-05"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3890}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/nitnelave/lldap"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/nitnelave/lldap"}], "instructions": "Login using the username \"admin\" and the password you would decide.", "install": [{"docker": {"image": "$IMAGE", "name": "lldap", "port": "$PORT:3890", "volumes": ["/data"], "extra_ports": ["17170:17170"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Login using the username \"admin\" and the password you would decide."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('lms', 'LMS', 'LMS (Lightweight Music Server) is a self-hosted music streaming software that provides access to your music collection from anywhere using a web interface. It features Subsonic/OpenSubsonic API support, multi-valued tags, artist relationships, MusicBrainz integration, ListenBrainz support, recommendation engine, and comprehensive music discovery features.', 'music-streaming', ARRAY['Music Streaming', 'Subsonic', 'MusicBrainz', 'ListenBrainz', 'Self-Hosted', 'Audio Streaming'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "epoupon/lms:3.76.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5082}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "LMS", "version": "latest", "description": "LMS (Lightweight Music Server) is a self-hosted music streaming software that provides access to your music collection from anywhere using a web interface. It features Subsonic/OpenSubsonic API support, multi-valued tags, artist relationships, MusicBrainz integration, ListenBrainz support, recommendation engine, and comprehensive music discovery features.", "category": "music-streaming", "tags": ["Music Streaming", "Subsonic", "MusicBrainz", "ListenBrainz", "Self-Hosted", "Audio Streaming"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "epoupon/lms:3.76.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5082}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Demo", "url": "https://lms-demo.poupon.dev"}, {"label": "Github", "url": "https://github.com/epoupon/lms"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "lms", "port": "$PORT:5082", "volumes": ["/music", "/var/lms"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('lobechat', 'LobeChat', 'LobeChat is an open-source, AI-powered chat application designed to integrate with OpenAI services. It provides a seamless user experience, combining conversational AI capabilities with a customizable and extensible architecture. LobeChat is ideal for both personal and professional use cases, offering robust features for modern AI chat applications.', 'ai-chat', ARRAY['AI Chat', 'OpenAI Integration', 'Customizable', 'Open Source', 'Conversational AI'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lobehub/lobe-chat:1.143.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3210}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "LobeChat", "version": "latest", "description": "LobeChat is an open-source, AI-powered chat application designed to integrate with OpenAI services. It provides a seamless user experience, combining conversational AI capabilities with a customizable and extensible architecture. LobeChat is ideal for both personal and professional use cases, offering robust features for modern AI chat applications.", "category": "ai-chat", "tags": ["AI Chat", "OpenAI Integration", "Customizable", "Open Source", "Conversational AI"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lobehub/lobe-chat:1.143.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3210}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://lobehub.com/"}, {"label": "Compose Docs", "url": "https://lobehub.com/docs/self-hosting/server-database/docker-compose"}, {"label": "Documentation", "url": "https://lobehub.com/docs/usage/start"}, {"label": "Github", "url": "https://github.com/lobehub/lobe-chat"}], "instructions": "Configure your OpenAI API key and proxy URL to start using the application.", "install": [{"docker": {"image": "$IMAGE", "name": "lobechat", "port": "$PORT:3210", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Configure your OpenAI API key and proxy URL to start using the application."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('localai', 'LocalAI', 'LocalAI is a drop-in replacement REST API that''s compatible with OpenAI API specifications for local inferencing. It allows you to run LLMs, generate images, audio (and not only) locally or on-premises with consumer grade hardware, supporting multiple model families and not requiring GPU.', 'ai', ARRAY['AI', 'LLM', 'OpenAI', 'Local Inference', 'Machine Learning'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "localai/localai:v2.29.0-aio-cpu"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "LocalAI", "version": "latest", "description": "LocalAI is a drop-in replacement REST API that's compatible with OpenAI API specifications for local inferencing. It allows you to run LLMs, generate images, audio (and not only) locally or on-premises with consumer grade hardware, supporting multiple model families and not requiring GPU.", "category": "ai", "tags": ["AI", "LLM", "OpenAI", "Local Inference", "Machine Learning"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "localai/localai:v2.29.0-aio-cpu"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://localai.io/"}, {"label": "Documentation", "url": "https://localai.io/docs/"}, {"label": "Github", "url": "https://github.com/mudler/LocalAI"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "localai", "port": "$PORT:8080", "volumes": ["/build/models"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('logchimp', 'LogChimp', 'LogChimp is an open-source feedback and changelog platform that lets you collect product feedback, publish updates, and keep users informed from a single place. It provides an API, a web UI, and a themed frontend for your users to submit ideas, vote, and read announcements. Built with PostgreSQL and Valkey (Redis), it supports self-hosted deployments with migrations, background processing, and email notifications.', 'feedback', ARRAY['Feedback', 'Changelog', 'Product Management', 'Self-Hosted', 'PostgreSQL'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "LogChimp", "version": "latest", "description": "LogChimp is an open-source feedback and changelog platform that lets you collect product feedback, publish updates, and keep users informed from a single place. It provides an API, a web UI, and a themed frontend for your users to submit ideas, vote, and read announcements. Built with PostgreSQL and Valkey (Redis), it supports self-hosted deployments with migrations, background processing, and email notifications.", "category": "feedback", "tags": ["Feedback", "Changelog", "Product Management", "Self-Hosted", "PostgreSQL"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://logchimp.codecarrot.net"}, {"label": "Documentation", "url": "https://docs.logchimp.codecarrot.net/platform/what-is-logchimp"}, {"label": "GitHub", "url": "https://github.com/logchimp/logchimp"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "logchimp", "port": "$PORT:3000", "volumes": ["/data"], "extra_ports": ["8000:8000"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('logseq', 'Logseq', 'Logseq is a powerful tool designed to enhance your note-taking and task management experience. It allows you to connect your notes, increasing your understanding and productivity. With features like PDF Annotations, Flashcards, and Whiteboards, it caters to a wide range of users including students, academics, writers, project managers, and developers. Logseq helps you capture, structure, and review your class notes with ease using the Linked References, Queries, and Search features. It also aids in memorizing facts and insights using the Flashcards feature. You can organize your thoughts and ideas, and quickly turn them into outlines using Block References. The app also offers tips and tricks to improve your note-taking skills, whether you''re a beginner, intermediate, or expert. With Logseq, you can create your own processes, generate tables of relevant information, and always find what you''re looking for. It also helps you stay on top of your relationships, conversations, and meetings, making it a safe space for your thoughts. Logseq is designed to store your interests, questions, ideas, favorite quotes, reminders, reading and meeting notes easily and future-proof. It also offers real-time, encrypted file syncing so you''ll always have your notes backed up and securely available on any device. The Whiteboards feature provides a new canvas for your thoughts, allowing you to connect, associate and understand in new ways.', 'notes', ARRAY['Notes', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/logseq/logseq-webapp"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Logseq", "version": "latest", "description": "Logseq is a powerful tool designed to enhance your note-taking and task management experience. It allows you to connect your notes, increasing your understanding and productivity. With features like PDF Annotations, Flashcards, and Whiteboards, it caters to a wide range of users including students, academics, writers, project managers, and developers. Logseq helps you capture, structure, and review your class notes with ease using the Linked References, Queries, and Search features. It also aids in memorizing facts and insights using the Flashcards feature. You can organize your thoughts and ideas, and quickly turn them into outlines using Block References. The app also offers tips and tricks to improve your note-taking skills, whether you're a beginner, intermediate, or expert. With Logseq, you can create your own processes, generate tables of relevant information, and always find what you're looking for. It also helps you stay on top of your relationships, conversations, and meetings, making it a safe space for your thoughts. Logseq is designed to store your interests, questions, ideas, favorite quotes, reminders, reading and meeting notes easily and future-proof. It also offers real-time, encrypted file syncing so you'll always have your notes backed up and securely available on any device. The Whiteboards feature provides a new canvas for your thoughts, allowing you to connect, associate and understand in new ways.", "category": "notes", "tags": ["Notes", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/logseq/logseq-webapp"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://logseq.com"}, {"label": "Documentation", "url": "https://docs.logseq.com"}, {"label": "Github", "url": "https://github.com/logseq/logseq"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "logseq", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('logto', 'Logto', 'Logto is an Auth0 alternative designed for modern apps and SaaS products. It offers a seamless developer experience and is well-suited for individuals and growing companies.', 'identity-management', ARRAY['Identity Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "svhd/logto:1.39.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Logto", "version": "latest", "description": "Logto is an Auth0 alternative designed for modern apps and SaaS products. It offers a seamless developer experience and is well-suited for individuals and growing companies.", "category": "identity-management", "tags": ["Identity Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "svhd/logto:1.39.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://logto.io/"}, {"label": "Documentation", "url": "https://docs.logto.io/"}, {"label": "Github", "url": "https://github.com/logto-io/logto"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "logto", "port": "$PORT:80", "volumes": [], "extra_ports": ["3002:3002"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('lollypop', 'Lollypop', 'Lollypop is a self-hosted, high-performance music library manager and player. It is designed to handle extensive music collections, offering a sleek and modern interface for browsing, organizing, and playing your favorite tracks. The app supports multiple audio formats, playlists, and smart sorting options. Lollypop integrates seamlessly with online services to fetch album artwork, lyrics, and artist information. It also provides a simple API for managing playlists and controlling playback remotely. Lollypop is open-source, free, and designed to run efficiently on minimal hardware, making it a lightweight yet powerful solution for all your music needs.', 'music', ARRAY['Music', 'Player', 'Library Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/lollypop:1.4.45"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Lollypop", "version": "latest", "description": "Lollypop is a self-hosted, high-performance music library manager and player. It is designed to handle extensive music collections, offering a sleek and modern interface for browsing, organizing, and playing your favorite tracks. The app supports multiple audio formats, playlists, and smart sorting options. Lollypop integrates seamlessly with online services to fetch album artwork, lyrics, and artist information. It also provides a simple API for managing playlists and controlling playback remotely. Lollypop is open-source, free, and designed to run efficiently on minimal hardware, making it a lightweight yet powerful solution for all your music needs.", "category": "music", "tags": ["Music", "Player", "Library Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/lollypop:1.4.45"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://lollypop.app/"}, {"label": "Documentation", "url": "https://lollypop.app/docs/"}, {"label": "Github", "url": "https://github.com/linuxserver/lollypop"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "lollypop", "port": "$PORT:3000", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('loonflow', 'Loonflow', 'Loonflow is a comprehensive workflow management system that provides end-to-end workflow automation and process management capabilities. Built with Django and React, Loonflow offers a complete solution for designing, executing, and monitoring business workflows. The system consists of a PostgreSQL database for data persistence, Redis for task queue management, a Django backend API, a React frontend UI, and Celery workers for asynchronous task processing. Perfect for organizations looking to automate business processes and manage complex workflows with a self-hosted solution.', 'workflow', ARRAY['Workflow', 'Automation', 'Process Management', 'Self-Hosted', 'Django', 'Celery', 'Enterprise'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Loonflow", "version": "latest", "description": "Loonflow is a comprehensive workflow management system that provides end-to-end workflow automation and process management capabilities. Built with Django and React, Loonflow offers a complete solution for designing, executing, and monitoring business workflows. The system consists of a PostgreSQL database for data persistence, Redis for task queue management, a Django backend API, a React frontend UI, and Celery workers for asynchronous task processing. Perfect for organizations looking to automate business processes and manage complex workflows with a self-hosted solution.", "category": "workflow", "tags": ["Workflow", "Automation", "Process Management", "Self-Hosted", "Django", "Celery", "Enterprise"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/blackholll/loonflow"}, {"label": "Documentation", "url": "https://loonflow.readthedocs.io/en/r3.0/"}], "instructions": "You can change the lanaguage by clicking the admin icon, click the first option, and then change it to American English in the dropdown.", "install": [{"docker": {"image": "$IMAGE", "name": "loonflow", "port": "$PORT:80", "volumes": [], "extra_ports": ["8000:8000"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "You can change the lanaguage by clicking the admin icon, click the first option, and then change it to American English in the dropdown."}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('lowcoder', 'Lowcoder', 'Open-source low-code platform to build internal tools with minimal effort.', 'low-code', ARRAY['Low-Code', 'Internal Tools', 'Application Builder', 'Automation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Lowcoder", "version": "latest", "description": "Open-source low-code platform to build internal tools with minimal effort.", "category": "low-code", "tags": ["Low-Code", "Internal Tools", "Application Builder", "Automation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://lowcoder.org/"}, {"label": "Documentation", "url": "https://docs.lowcoder.org/"}, {"label": "Github", "url": "https://github.com/lowcoder-org/lowcoder"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "lowcoder", "port": "$PORT:3000", "volumes": ["/lowcoder-stacks", "/lowcoder/assets", "/lowcoder/assets"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('lubelogger', 'LubeLogger', 'LubeLogger is a self-hosted vehicle maintenance and service tracking application that helps you keep comprehensive records of all your vehicle''s maintenance activities, repairs, and modifications. Designed for car enthusiasts, fleet managers, and anyone who wants to maintain detailed service histories, LubeLogger provides an intuitive web interface to log oil changes, tire rotations, repairs, upgrades, and more. The application allows you to track multiple vehicles, set maintenance reminders based on mileage or time intervals, and maintain a complete history of all service records with costs and notes. With support for uploading receipts and documents, you can keep all your vehicle maintenance information in one centralized location. LubeLogger features automatic odometer tracking, service interval reminders, cost analysis and reporting, tax deduction calculations for business use, and comprehensive search and filtering capabilities. Built with ASP.NET, it provides a responsive web interface that works seamlessly across desktop and mobile devices, allowing you to update maintenance records from anywhere. Perfect for vehicle owners who want to maintain detailed service histories, car collectors managing multiple vehicles, fleet managers tracking maintenance across multiple assets, mechanics and auto shops offering service tracking to customers, or anyone preparing to sell a vehicle and wanting to demonstrate a complete maintenance history to potential buyers.', 'productivity', ARRAY['Productivity', 'Vehicle Management', 'Maintenance Tracking', 'Self-Hosted', 'Fleet Management', 'Record Keeping'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/hargata/lubelogger:v1.6.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "LubeLogger", "version": "latest", "description": "LubeLogger is a self-hosted vehicle maintenance and service tracking application that helps you keep comprehensive records of all your vehicle's maintenance activities, repairs, and modifications. Designed for car enthusiasts, fleet managers, and anyone who wants to maintain detailed service histories, LubeLogger provides an intuitive web interface to log oil changes, tire rotations, repairs, upgrades, and more. The application allows you to track multiple vehicles, set maintenance reminders based on mileage or time intervals, and maintain a complete history of all service records with costs and notes. With support for uploading receipts and documents, you can keep all your vehicle maintenance information in one centralized location. LubeLogger features automatic odometer tracking, service interval reminders, cost analysis and reporting, tax deduction calculations for business use, and comprehensive search and filtering capabilities. Built with ASP.NET, it provides a responsive web interface that works seamlessly across desktop and mobile devices, allowing you to update maintenance records from anywhere. Perfect for vehicle owners who want to maintain detailed service histories, car collectors managing multiple vehicles, fleet managers tracking maintenance across multiple assets, mechanics and auto shops offering service tracking to customers, or anyone preparing to sell a vehicle and wanting to demonstrate a complete maintenance history to potential buyers.", "category": "productivity", "tags": ["Productivity", "Vehicle Management", "Maintenance Tracking", "Self-Hosted", "Fleet Management", "Record Keeping"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/hargata/lubelogger:v1.6.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://lubelogger.com"}, {"label": "GitHub", "url": "https://github.com/hargata/lubelog"}, {"label": "Documentation", "url": "https://docs.lubelogger.com"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "lubelogger", "port": "$PORT:8080", "volumes": ["/App/data", "/root/.aspnet/DataProtection-Keys"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('lychee', 'Lychee', 'Lychee is a free, self-hosted photo-management tool designed to make managing your photos a breeze. It allows you to upload, move, rename, describe, delete, and search your photos all in one place, right from your browser. With Lychee, you can easily share your photos and albums with just one click, and even protect them with passwords for added security. The app also allows you to view your images in full-screen mode, navigate using your keyboard, and make your photos public for others to enjoy. Lychee supports batch editing with desktop-like multi-select and displays your EXIF and IPTC Metadata. You can import your photos from various sources, tag them, or mark them as important. Lychee is designed with a beautiful, intuitive interface and is perfect for photographers as it offers unlimited storage, no compression, and no loss in data.', 'gallery', ARRAY['Gallery', 'Photo Management', 'Self-hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lycheeorg/lychee:v6.10.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Lychee", "version": "latest", "description": "Lychee is a free, self-hosted photo-management tool designed to make managing your photos a breeze. It allows you to upload, move, rename, describe, delete, and search your photos all in one place, right from your browser. With Lychee, you can easily share your photos and albums with just one click, and even protect them with passwords for added security. The app also allows you to view your images in full-screen mode, navigate using your keyboard, and make your photos public for others to enjoy. Lychee supports batch editing with desktop-like multi-select and displays your EXIF and IPTC Metadata. You can import your photos from various sources, tag them, or mark them as important. Lychee is designed with a beautiful, intuitive interface and is perfect for photographers as it offers unlimited storage, no compression, and no loss in data.", "category": "gallery", "tags": ["Gallery", "Photo Management", "Self-hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lycheeorg/lychee:v6.10.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://lycheeorg.github.io/"}, {"label": "Documentation", "url": "https://lycheeorg.github.io/docs/"}, {"label": "Github", "url": "https://github.com/LycheeOrg/Lychee"}, {"label": "Demo", "url": "https://lycheeorg.github.io/demo/"}], "instructions": "Lychee takes a few minutes to get ready. Sit back, relax, and have a coffee!", "install": [{"docker": {"image": "$IMAGE", "name": "lychee", "port": "$PORT:80", "volumes": ["/conf", "/sym", "/uploads"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Lychee takes a few minutes to get ready. Sit back, relax, and have a coffee!"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('lynx', 'Lynx', 'Lynx is a robust URL shortener application designed to simplify and streamline your web browsing experience. Built using the MEVN stack, Lynx offers a user-friendly interface and the ability to redirect the root path for a more personalized touch. The app also features a unique admin interface, providing you with full control over your shortened URLs. With Lynx, you can easily manage and customize your links, each of which includes a slug, destination, and id. The app also supports multiple users, integrates with ShareX, and offers two-factor authentication for enhanced security. Lynx is the sleek, powerful URL shortener you''ve been looking for.', 'url-shortener', ARRAY['URL Shortener', 'Web Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "jackbailey/lynx:1.10.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Lynx", "version": "latest", "description": "Lynx is a robust URL shortener application designed to simplify and streamline your web browsing experience. Built using the MEVN stack, Lynx offers a user-friendly interface and the ability to redirect the root path for a more personalized touch. The app also features a unique admin interface, providing you with full control over your shortened URLs. With Lynx, you can easily manage and customize your links, each of which includes a slug, destination, and id. The app also supports multiple users, integrates with ShareX, and offers two-factor authentication for enhanced security. Lynx is the sleek, powerful URL shortener you've been looking for.", "category": "url-shortener", "tags": ["URL Shortener", "Web Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "jackbailey/lynx:1.10.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Demo", "url": "https://demo.getlynx.dev/"}, {"label": "Github", "url": "https://github.com/Lynx-Shortener/Lynx/"}, {"label": "Website", "url": "https://getlynx.dev"}, {"label": "Docs", "url": "https://docs.getlynx.dev"}], "instructions": "Registration is disabled by default, but the first registration will always be allowed.", "install": [{"docker": {"image": "$IMAGE", "name": "lynx", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Registration is disabled by default, but the first registration will always be allowed."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('mageai', 'Mage-AI', 'Mage-AI is a powerful open-source data pipeline tool designed to simplify and accelerate building, deploying, and managing machine learning workflows. It empowers data engineers and scientists with a unified platform to seamlessly create pipelines for data ingestion, transformation, and model deployment. With Mage-AI''s user-friendly interface and robust features, it becomes an essential tool for teams aiming to deliver AI solutions efficiently and effectively.', 'data-pipelines', ARRAY['Data Pipelines', 'Machine Learning', 'AI', 'Automation', 'Data Engineering', 'Model Deployment', 'Open-Source', 'Scalable', 'Cloud'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "mageai/mageai:0.9.79"}, "port": {"type": "integer", "title": "Port HTTP", "default": 6789}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Mage-AI", "version": "latest", "description": "Mage-AI is a powerful open-source data pipeline tool designed to simplify and accelerate building, deploying, and managing machine learning workflows. It empowers data engineers and scientists with a unified platform to seamlessly create pipelines for data ingestion, transformation, and model deployment. With Mage-AI's user-friendly interface and robust features, it becomes an essential tool for teams aiming to deliver AI solutions efficiently and effectively.", "category": "data-pipelines", "tags": ["Data Pipelines", "Machine Learning", "AI", "Automation", "Data Engineering", "Model Deployment", "Open-Source", "Scalable", "Cloud"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "mageai/mageai:0.9.79"}, "port": {"type": "integer", "title": "Port HTTP", "default": 6789}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://docs.mage.ai/introduction/overview"}, {"label": "Documentation", "url": "https://docs.mage.ai/"}, {"label": "Github", "url": "https://github.com/mage-ai/mage-ai"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "mageai", "port": "$PORT:6789", "volumes": ["/home/src/"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('mailcrab', 'MailCrab', 'MailCrab is an email test server designed for development purposes. It is an accept-all SMTP server that provides a web interface for viewing and inspecting all incoming emails. You can view formatted mail, download attachments, view headers, or view the complete raw mail contents. The app runs on all amd64 and arm64 platforms using docker. The backend server and the frontend of the app are both written in Rust. The backend receives email over an unencrypted connection on a configurable port, and all email is stored in memory while the application is running. The frontend initially performs a call to receive all existing email metadata and then subscribes for new messages using the websocket connection. When opening a message, the endpoint is used to retrieve the complete message body and raw email. The backend also accepts a few commands over the websocket, to mark a message as opened, to delete a single message or delete all messages.', 'email', ARRAY['Email'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "marlonb/mailcrab:v1.6.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 1025}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "MailCrab", "version": "latest", "description": "MailCrab is an email test server designed for development purposes. It is an accept-all SMTP server that provides a web interface for viewing and inspecting all incoming emails. You can view formatted mail, download attachments, view headers, or view the complete raw mail contents. The app runs on all amd64 and arm64 platforms using docker. The backend server and the frontend of the app are both written in Rust. The backend receives email over an unencrypted connection on a configurable port, and all email is stored in memory while the application is running. The frontend initially performs a call to receive all existing email metadata and then subscribes for new messages using the websocket connection. When opening a message, the endpoint is used to retrieve the complete message body and raw email. The backend also accepts a few commands over the websocket, to mark a message as opened, to delete a single message or delete all messages.", "category": "email", "tags": ["Email"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "marlonb/mailcrab:v1.6.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 1025}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/tweedegolf/mailcrab"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "mailcrab", "port": "$PORT:1025", "volumes": [], "extra_ports": ["1080:1080"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('maildev', 'Maildev', 'Maildev is a simple, self-hosted SMTP server designed for testing and debugging emails in development environments. It captures all outgoing emails and provides a web-based UI to view, inspect, and test them. Maildev supports real-time email updates, allowing developers to see emails as they are sent. It also includes an API for programmatic access to emails and supports multiple inboxes for testing different email scenarios. Maildev is lightweight, easy to set up, and works seamlessly in local development and CI/CD pipelines.', 'email', ARRAY['Email', 'Development', 'Testing', 'Debugging'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "maildev/maildev:2.2.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 1025}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Maildev", "version": "latest", "description": "Maildev is a simple, self-hosted SMTP server designed for testing and debugging emails in development environments. It captures all outgoing emails and provides a web-based UI to view, inspect, and test them. Maildev supports real-time email updates, allowing developers to see emails as they are sent. It also includes an API for programmatic access to emails and supports multiple inboxes for testing different email scenarios. Maildev is lightweight, easy to set up, and works seamlessly in local development and CI/CD pipelines.", "category": "email", "tags": ["Email", "Development", "Testing", "Debugging"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "maildev/maildev:2.2.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 1025}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://github.com/maildev/maildev"}, {"label": "Github", "url": "https://github.com/maildev/maildev"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "maildev", "port": "$PORT:1025", "volumes": [], "extra_ports": ["1080:1080"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('mailhog', 'Mailhog', 'MailHog is an intuitive email testing tool designed for developers. It allows you to configure your application to use MailHog for SMTP delivery, enabling you to view your outgoing emails in a user-friendly web UI. The app also offers the option to release messages to real SMTP servers for delivery. With MailHog, you can view messages in the web UI or retrieve them using the JSON API. It supports SMTP AUTH and PIPELINING, and provides real-time updates using EventSource. MailHog also includes a Chaos Monkey for failure testing and HTTP basic authentication for its UI and API. It''s lightweight, portable, and requires no installation.', 'email', ARRAY['Email'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "mailhog/mailhog:v1.0.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 1025}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Mailhog", "version": "latest", "description": "MailHog is an intuitive email testing tool designed for developers. It allows you to configure your application to use MailHog for SMTP delivery, enabling you to view your outgoing emails in a user-friendly web UI. The app also offers the option to release messages to real SMTP servers for delivery. With MailHog, you can view messages in the web UI or retrieve them using the JSON API. It supports SMTP AUTH and PIPELINING, and provides real-time updates using EventSource. MailHog also includes a Chaos Monkey for failure testing and HTTP basic authentication for its UI and API. It's lightweight, portable, and requires no installation.", "category": "email", "tags": ["Email"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "mailhog/mailhog:v1.0.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 1025}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/mailhog/MailHog/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "mailhog", "port": "$PORT:1025", "volumes": [], "extra_ports": ["8025:8025"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('mailpit', 'Mailpit', 'Mailpit is a modern email testing tool designed for developers. It allows you to configure your application to use Mailpit for SMTP delivery, enabling you to view your outgoing emails in a user-friendly web UI. The app also offers the option to forward messages to real SMTP servers for delivery. With Mailpit, you can view messages in the web UI or retrieve them using the JSON API. It supports SMTP AUTH and PIPELINING and provides real-time updates using WebSocket. Mailpit also includes message search functionality, custom SMTP configurations, and HTTP basic authentication for its UI and API. It''s lightweight, portable, and easy to deploy.', 'email', ARRAY['Email', 'Email Testing', 'SMTP Testing Server'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "axllent/mailpit:v1.29.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 1025}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Mailpit", "version": "latest", "description": "Mailpit is a modern email testing tool designed for developers. It allows you to configure your application to use Mailpit for SMTP delivery, enabling you to view your outgoing emails in a user-friendly web UI. The app also offers the option to forward messages to real SMTP servers for delivery. With Mailpit, you can view messages in the web UI or retrieve them using the JSON API. It supports SMTP AUTH and PIPELINING and provides real-time updates using WebSocket. Mailpit also includes message search functionality, custom SMTP configurations, and HTTP basic authentication for its UI and API. It's lightweight, portable, and easy to deploy.", "category": "email", "tags": ["Email", "Email Testing", "SMTP Testing Server"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "axllent/mailpit:v1.29.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 1025}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/axllent/mailpit"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "mailpit", "port": "$PORT:1025", "volumes": ["/data"], "extra_ports": ["8025:8025"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('managerio', 'Manager.io', 'Manager.io is a versatile accounting software designed for small businesses. It allows you to manage your finances, track expenses, issue invoices, and generate comprehensive financial reports. The software supports multi-currency transactions, inventory tracking, payroll management, and tax calculations. With Manager.io, you can handle all your business accounting needs through an intuitive and user-friendly interface. It''s available for desktop, server, and cloud deployment, offering flexibility and scalability for businesses of all sizes.', 'accounting', ARRAY['Accounting', 'Business Management', 'Finance'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "cronet/manager.io:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Manager.io", "version": "latest", "description": "Manager.io is a versatile accounting software designed for small businesses. It allows you to manage your finances, track expenses, issue invoices, and generate comprehensive financial reports. The software supports multi-currency transactions, inventory tracking, payroll management, and tax calculations. With Manager.io, you can handle all your business accounting needs through an intuitive and user-friendly interface. It's available for desktop, server, and cloud deployment, offering flexibility and scalability for businesses of all sizes.", "category": "accounting", "tags": ["Accounting", "Business Management", "Finance"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "cronet/manager.io:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Official Website", "url": "https://www.manager.io/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "managerio", "port": "$PORT:8080", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('manticore-search', 'Manticore Search', 'Manticore Search is an easy to use open source fast database for search. It helps thousands of companies from small to large, such as Craigslist, to search and filter petabytes of text data on a single or hundreds of nodes, do stream full-text filtering, add auto-complete, spell correction, more-like-this, faceting and other search-related technologies to their websites and applications.', 'search', ARRAY['Search', 'Database', 'Full-text Search', 'Analytics', 'Open Source', 'High Performance', 'Scalable'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "manticoresearch/manticore:17.5.100"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9308}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Manticore Search", "version": "latest", "description": "Manticore Search is an easy to use open source fast database for search. It helps thousands of companies from small to large, such as Craigslist, to search and filter petabytes of text data on a single or hundreds of nodes, do stream full-text filtering, add auto-complete, spell correction, more-like-this, faceting and other search-related technologies to their websites and applications.", "category": "search", "tags": ["Search", "Database", "Full-text Search", "Analytics", "Open Source", "High Performance", "Scalable"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "manticoresearch/manticore:17.5.100"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9308}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://manticoresearch.com/"}, {"label": "Documentation", "url": "https://manual.manticoresearch.com/"}, {"label": "GitHub", "url": "https://github.com/manticoresoftware/manticoresearch"}], "instructions": "The configuration file within the instance can be found at /etc/manticoresearch/manticore.conf. To apply custom settings, ensure that this file is mounted to your own configuration file. The ports are 9306/9308/9312 for SQL/HTTP/Binary, expose them depending on how you are going to use Manticore.", "install": [{"docker": {"image": "$IMAGE", "name": "manticore-search", "port": "$PORT:9308", "volumes": ["/var/lib/manticore"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "The configuration file within the instance can be found at /etc/manticoresearch/manticore.conf. To apply custom settings, ensure that this file is mounted to your own configuration file. The ports are 9306/9308/9312 for SQL/HTTP/Binary, expose them depending on how you are going to use Manticore."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('mastodon', 'Mastodon', 'Mastodon is a unique social networking app that puts control back in your hands. It allows you to curate your own home feed, free from algorithms or ads, ensuring you see only what matters most to you. The app supports a wide range of content types, including audio, video, and picture posts, polls, content warnings, and more, enabling you to express yourself freely online. Mastodon is decentralized and open-source, meaning each server is a completely independent entity, yet able to interoperate with others to form a global social network. The app respects your agency, never serving ads or pushing profiles, and is built on open web protocols, allowing it to interact with any other platform that implements ActivityPub. With Mastodon, you have the power to manage your audience, moderate content, and create a social media experience that truly reflects you.', 'social-networking', ARRAY['Social Networking'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/mastodon/mastodon:v4.5.9"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Mastodon", "version": "latest", "description": "Mastodon is a unique social networking app that puts control back in your hands. It allows you to curate your own home feed, free from algorithms or ads, ensuring you see only what matters most to you. The app supports a wide range of content types, including audio, video, and picture posts, polls, content warnings, and more, enabling you to express yourself freely online. Mastodon is decentralized and open-source, meaning each server is a completely independent entity, yet able to interoperate with others to form a global social network. The app respects your agency, never serving ads or pushing profiles, and is built on open web protocols, allowing it to interact with any other platform that implements ActivityPub. With Mastodon, you have the power to manage your audience, moderate content, and create a social media experience that truly reflects you.", "category": "social-networking", "tags": ["Social Networking"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/mastodon/mastodon:v4.5.9"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://joinmastodon.org"}, {"label": "Docs", "url": "https://docs.joinmastodon.org"}, {"label": "Github", "url": "https://github.com/mastodon/mastodon"}], "instructions": "To create an admin account, type \"tootctl accounts create username --email user@example.com --confirmed --role Owner\" on the console.", "install": [{"docker": {"image": "$IMAGE", "name": "mastodon", "port": "$PORT:3000", "volumes": ["/mastodon/public", "/mastodon/public"], "extra_ports": ["4000:4000"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "To create an admin account, type \"tootctl accounts create username --email user@example.com --confirmed --role Owner\" on the console."}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('mathesar', 'Mathesar', 'Mathesar is an open-source database GUI that makes PostgreSQL accessible to non-technical users. It provides an intuitive interface for working with databases without requiring SQL knowledge. Users can visually create and edit tables, modify schemas, browse and manipulate data, and collaborate with team members. Built on PostgreSQL, it leverages the power and reliability of this proven database while adding user-friendly features like spreadsheet-like data editing, relationship visualization, and automated schema management. Mathesar is perfect for teams that need to work with data collaboratively but don''t have extensive database expertise. As a self-hosted solution, it gives organizations complete control over their data and infrastructure. Whether you''re managing content, organizing research data, or building internal tools, Mathesar makes database operations approachable while maintaining the full capabilities of PostgreSQL.', 'database-gui', ARRAY['Database GUI', 'PostgreSQL', 'No-code/Low-code', 'Self-hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "mathesar/mathesar:0.10.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Mathesar", "version": "latest", "description": "Mathesar is an open-source database GUI that makes PostgreSQL accessible to non-technical users. It provides an intuitive interface for working with databases without requiring SQL knowledge. Users can visually create and edit tables, modify schemas, browse and manipulate data, and collaborate with team members. Built on PostgreSQL, it leverages the power and reliability of this proven database while adding user-friendly features like spreadsheet-like data editing, relationship visualization, and automated schema management. Mathesar is perfect for teams that need to work with data collaboratively but don't have extensive database expertise. As a self-hosted solution, it gives organizations complete control over their data and infrastructure. Whether you're managing content, organizing research data, or building internal tools, Mathesar makes database operations approachable while maintaining the full capabilities of PostgreSQL.", "category": "database-gui", "tags": ["Database GUI", "PostgreSQL", "No-code/Low-code", "Self-hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "mathesar/mathesar:0.10.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.mathesar.org"}, {"label": "Documentation", "url": "https://docs.mathesar.org"}, {"label": "Github", "url": "https://github.com/mathesar-foundation/mathesar"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "mathesar", "port": "$PORT:8000", "volumes": ["/code/static", "/code/media", "/code/.secrets"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('matomo', 'Matomo', 'Matomo is a powerful web analytics platform that allows you to take full control of your data. As a leading global web analytics solution, it is trusted on over 1 million websites across more than 190 countries. Matomo provides an ethical alternative to other analytics platforms, ensuring the protection of your data and your customers'' privacy. With Matomo, you have 100% data ownership, meaning you know exactly where your data is stored and what''s happening to it. The platform offers a comprehensive range of features that provide actionable insights and a complete picture of your customers. It allows you to securely track personal data in accordance with privacy laws, and offers 100% accurate reporting for impactful decision-making. Matomo can be customised and extended to meet your every need, and it comes with no data limitations, allowing for an unlimited number of websites, users, and segments.', 'analytics', ARRAY['Analytics'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "matomo:5.7.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Matomo", "version": "latest", "description": "Matomo is a powerful web analytics platform that allows you to take full control of your data. As a leading global web analytics solution, it is trusted on over 1 million websites across more than 190 countries. Matomo provides an ethical alternative to other analytics platforms, ensuring the protection of your data and your customers' privacy. With Matomo, you have 100% data ownership, meaning you know exactly where your data is stored and what's happening to it. The platform offers a comprehensive range of features that provide actionable insights and a complete picture of your customers. It allows you to securely track personal data in accordance with privacy laws, and offers 100% accurate reporting for impactful decision-making. Matomo can be customised and extended to meet your every need, and it comes with no data limitations, allowing for an unlimited number of websites, users, and segments.", "category": "analytics", "tags": ["Analytics"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "matomo:5.7.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://matomo.org/"}, {"label": "Documentation", "url": "https://matomo.org/guide/installation-maintenance/matomo-on-premise-self-hosted/"}, {"label": "Github", "url": "https://github.com/matomo-org/matomo"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "matomo", "port": "$PORT:80", "volumes": ["/var/www/html"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('matrix-synapse', 'Matrix Synapse', 'Matrix is an open network designed for secure, decentralised communication. This app allows you to chat with friends, family, communities, and co-workers, providing a cozy, safe, and supercharged environment for your conversations. You can reclaim your space and build advanced, rich communication applications on top of Matrix. The app is part of a rich ecosystem that includes clients, servers, bots, and application services. It''s an open-source project, generously hosted by UpCloud. With Matrix, you can start a conversation, build apps, and explore the vast possibilities of a decentralised communication network.', 'chat', ARRAY['Chat', 'Communication', 'Social Networking'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "matrixdotorg/synapse:v1.152.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8008}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Matrix Synapse", "version": "latest", "description": "Matrix is an open network designed for secure, decentralised communication. This app allows you to chat with friends, family, communities, and co-workers, providing a cozy, safe, and supercharged environment for your conversations. You can reclaim your space and build advanced, rich communication applications on top of Matrix. The app is part of a rich ecosystem that includes clients, servers, bots, and application services. It's an open-source project, generously hosted by UpCloud. With Matrix, you can start a conversation, build apps, and explore the vast possibilities of a decentralised communication network.", "category": "chat", "tags": ["Chat", "Communication", "Social Networking"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "matrixdotorg/synapse:v1.152.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8008}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://matrix.org"}, {"label": "Docs", "url": "https://matrix-org.github.io/synapse"}, {"label": "Github", "url": "https://github.com/matrix-org/synapse"}, {"label": "Docker", "url": "https://hub.docker.com/r/matrixdotorg/synapse"}], "instructions": "To create a user, simply execute the command \"register_new_matrix_user -c data/homeserver.yaml\" via console connection.", "install": [{"docker": {"image": "$IMAGE", "name": "matrix-synapse", "port": "$PORT:8008", "volumes": ["/var/lib/postgresql/data", "/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "To create a user, simply execute the command \"register_new_matrix_user -c data/homeserver.yaml\" via console connection."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('mattermost', 'Mattermost', 'Mattermost is a secure collaboration platform designed to enhance the efficiency and productivity of technical and operational teams. It offers a range of features including team messaging, custom integrations, audio and screen sharing, and workflow automation. Mattermost is designed to improve time to response by 90%, decrease incident resolution time, and increase information availability by executing complex workflows faster and at a higher quality. It also helps in avoiding costly outages and downtime by decreasing the frequency and severity of system failures. The platform is built for enterprise scalability and can be deployed in air gapped networks and BYOD environments. It is also cloud neutral and offers self-host deployment options. Mattermost is open source and can be customized to fit your workflow with robust integrations or by building your own with its App Framework, Plugins, and open APIs.', 'chat', ARRAY['Chat', 'Collaboration', 'Security'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "mattermost/mattermost-team-edition:11.7.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8065}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Mattermost", "version": "latest", "description": "Mattermost is a secure collaboration platform designed to enhance the efficiency and productivity of technical and operational teams. It offers a range of features including team messaging, custom integrations, audio and screen sharing, and workflow automation. Mattermost is designed to improve time to response by 90%, decrease incident resolution time, and increase information availability by executing complex workflows faster and at a higher quality. It also helps in avoiding costly outages and downtime by decreasing the frequency and severity of system failures. The platform is built for enterprise scalability and can be deployed in air gapped networks and BYOD environments. It is also cloud neutral and offers self-host deployment options. Mattermost is open source and can be customized to fit your workflow with robust integrations or by building your own with its App Framework, Plugins, and open APIs.", "category": "chat", "tags": ["Chat", "Collaboration", "Security"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "mattermost/mattermost-team-edition:11.7.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8065}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://mattermost.com/"}, {"label": "Github", "url": "https://github.com/mattermost/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "mattermost", "port": "$PORT:8065", "volumes": ["/mattermost/data", "/mattermost/logs", "/mattermost/config", "/mattermost/plugins", "/mattermost/client/plugins"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('mautic', 'Mautic', 'Mautic is a powerful marketing automation platform designed to revolutionize the way businesses engage with their audience. Offering a comprehensive suite of features, Mautic enables marketers to automate and optimize their marketing strategies. The platform excels in open-source flexibility, allowing users to customize and extend its capabilities according to their unique needs. With a focus on lead tracking and nurturing, Mautic provides valuable insights into user behavior, enabling personalized and targeted campaigns for effective customer acquisition and retention. Its multi-channel marketing support ensures seamless engagement across various platforms, from email campaigns to social media interactions. Mautic''s robust campaign management tools, email marketing module, analytics, and reporting features contribute to a data-driven approach, empowering marketers to refine their strategies and achieve optimal return on investment. Integration capabilities further enhance its functionality, ensuring a connected marketing ecosystem. Whether you''re a marketing professional or a business owner, Mautic serves as a centralized solution to elevate and streamline your marketing efforts, fostering innovation and success.', 'marketing-automation', ARRAY['Marketing Automation', 'Open Source', 'Lead Nurturing', 'Multi-Channel Marketing'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "mautic/mautic:v4-apache"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Mautic", "version": "latest", "description": "Mautic is a powerful marketing automation platform designed to revolutionize the way businesses engage with their audience. Offering a comprehensive suite of features, Mautic enables marketers to automate and optimize their marketing strategies. The platform excels in open-source flexibility, allowing users to customize and extend its capabilities according to their unique needs. With a focus on lead tracking and nurturing, Mautic provides valuable insights into user behavior, enabling personalized and targeted campaigns for effective customer acquisition and retention. Its multi-channel marketing support ensures seamless engagement across various platforms, from email campaigns to social media interactions. Mautic's robust campaign management tools, email marketing module, analytics, and reporting features contribute to a data-driven approach, empowering marketers to refine their strategies and achieve optimal return on investment. Integration capabilities further enhance its functionality, ensuring a connected marketing ecosystem. Whether you're a marketing professional or a business owner, Mautic serves as a centralized solution to elevate and streamline your marketing efforts, fostering innovation and success.", "category": "marketing-automation", "tags": ["Marketing Automation", "Open Source", "Lead Nurturing", "Multi-Channel Marketing"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "mautic/mautic:v4-apache"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.mautic.org"}, {"label": "Github", "url": "https://github.com/mautic/mautic"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "mautic", "port": "$PORT:80", "volumes": ["/var/www/html"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('mautic5', 'Mautic 5', 'Mautic 5 is an open-source, comprehensive marketing automation platform that empowers businesses to manage and optimize customer engagement strategies. It enables marketers to streamline their workflows by automating marketing tasks such as email campaigns, SMS messaging, social media outreach, and lead generation. Mautic 5 offers detailed analytics, campaign tracking, and personalized communication, ensuring an efficient marketing strategy for businesses of all sizes. With its intuitive interface and powerful features, Mautic 5 helps businesses maximize customer engagement while reducing manual effort.', 'marketing', ARRAY['Marketing', 'Automation', 'Open-Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "mautic/mautic:7.1.1-apache"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Mautic 5", "version": "latest", "description": "Mautic 5 is an open-source, comprehensive marketing automation platform that empowers businesses to manage and optimize customer engagement strategies. It enables marketers to streamline their workflows by automating marketing tasks such as email campaigns, SMS messaging, social media outreach, and lead generation. Mautic 5 offers detailed analytics, campaign tracking, and personalized communication, ensuring an efficient marketing strategy for businesses of all sizes. With its intuitive interface and powerful features, Mautic 5 helps businesses maximize customer engagement while reducing manual effort.", "category": "marketing", "tags": ["Marketing", "Automation", "Open-Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "mautic/mautic:7.1.1-apache"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/mautic/mautic"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "mautic5", "port": "$PORT:80", "volumes": ["/opt/mautic/cron", "/var/www/html/docroot/media/images", "/var/www/html/docroot/media/files", "/var/www/html/var/logs", "/var/www/html/config", "/opt/mautic/cron", "/var/www/html/config", "/var/www/html/var/logs", "/var/www/html/docroot/media/files", "/var/www/html/docroot/media/images", "/opt/mautic/cron", "/var/www/html/config", "/var/www/html/var/logs", "/var/www/html/docroot/media/files", "/var/www/html/docroot/media/images"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('maxun', 'Maxun', 'Maxun is a self-hosted data automation platform that combines a modern frontend with a backend capable of browser automation (Playwright), file storage via MinIO, and PostgreSQL persistence. It lets you run data collection and integration workflows with headless Chromium, store assets in S3-compatible storage, and manage everything from a web interface. Ideal for teams who need a self-hosted automation stack with database, object storage, and browser automation included.', 'automation', ARRAY['Automation', 'Playwright', 'PostgreSQL', 'MinIO', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 5173}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Maxun", "version": "latest", "description": "Maxun is a self-hosted data automation platform that combines a modern frontend with a backend capable of browser automation (Playwright), file storage via MinIO, and PostgreSQL persistence. It lets you run data collection and integration workflows with headless Chromium, store assets in S3-compatible storage, and manage everything from a web interface. Ideal for teams who need a self-hosted automation stack with database, object storage, and browser automation included.", "category": "automation", "tags": ["Automation", "Playwright", "PostgreSQL", "MinIO", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 5173}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/getmaxun"}, {"label": "Website", "url": "https://www.maxun.dev/?ref=ghread"}, {"label": "Documentation", "url": "https://docs.maxun.dev/?ref=ghread"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "maxun", "port": "$PORT:5173", "volumes": ["/data", "/var/lib/maxun", "/ms-playwright", "/app/vite.config.js"], "extra_ports": ["8080:8080", "9000:9000", "9001:9001"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('maybe-finance', 'Maybe Finance', 'Maybe Finance is a modern, self-hosted finance management tool designed for tracking personal or business finances efficiently. It provides a clean and user-friendly interface, supports integrations for extended functionality, and offers detailed analytics for insights into your financial data. With Maybe Finance, you can take control of your finances, track expenses, and make informed decisions.', 'finance-management', ARRAY['Finance Management', 'Self-Hosted', 'Analytics', 'Budgeting'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/maybe-finance/maybe:sha-77b5469832758d1cbee1a940f3012a1ae1c74cd3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Maybe Finance", "version": "latest", "description": "Maybe Finance is a modern, self-hosted finance management tool designed for tracking personal or business finances efficiently. It provides a clean and user-friendly interface, supports integrations for extended functionality, and offers detailed analytics for insights into your financial data. With Maybe Finance, you can take control of your finances, track expenses, and make informed decisions.", "category": "finance-management", "tags": ["Finance Management", "Self-Hosted", "Analytics", "Budgeting"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/maybe-finance/maybe:sha-77b5469832758d1cbee1a940f3012a1ae1c74cd3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/maybe-finance/maybe"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "maybe-finance", "port": "$PORT:80", "volumes": ["/rails/storage"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('mazanoke', 'Mazanoke', 'Mazanoke is a self-hosted local image optimizer that runs in your browser. It works offline and keeps your images private without ever leaving your device. Created for everyday people and designed to be shared with family and friends, it serves as an alternative to questionable "free" online tools.', 'image-optimization', ARRAY['Image Optimization', 'Image Compression', 'Image Converter', 'Self-Hosted', 'Privacy', 'Offline'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/civilblur/mazanoke:v1.1.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Mazanoke", "version": "latest", "description": "Mazanoke is a self-hosted local image optimizer that runs in your browser. It works offline and keeps your images private without ever leaving your device. Created for everyday people and designed to be shared with family and friends, it serves as an alternative to questionable \"free\" online tools.", "category": "image-optimization", "tags": ["Image Optimization", "Image Compression", "Image Converter", "Self-Hosted", "Privacy", "Offline"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/civilblur/mazanoke:v1.1.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://github.com/civilblur/mazanoke"}, {"label": "Github", "url": "https://github.com/civilblur/mazanoke"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "mazanoke", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('mcaptcha', 'mCaptcha', 'mCaptcha is a proof-of-work based captcha system that prioritizes user privacy and offers a fully automated experience. Unlike traditional captcha systems, mCaptcha does not track or profile users, ensuring a privacy-focused user experience. It is designed to be robust and accurate, not relying on IP addresses for rate-limiting, making it suitable for users behind NATs. The user experience is silent and seamless, eliminating the need for annoying image-based captchas. mCaptcha uses a proof-of-work solution to fiercely defend your site, making it more expensive for attackers to target your site than for you to respond to their requests. It is a libre software, with client libraries licensed under proprietary-friendly free software licenses. mCaptcha is also compatible with reCAPTCHA and hCaptcha, making it a convenient drop-in replacement. The core functionality of mCaptcha is to use a SHA256 based proof-of-work system to rate limit users, providing a token upon successful validation that users can then submit with their request or form submission to the target website.', 'privacy', ARRAY['Privacy', 'Security', 'CAPTCHA'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "mcaptcha/mcaptcha:v0.1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "mCaptcha", "version": "latest", "description": "mCaptcha is a proof-of-work based captcha system that prioritizes user privacy and offers a fully automated experience. Unlike traditional captcha systems, mCaptcha does not track or profile users, ensuring a privacy-focused user experience. It is designed to be robust and accurate, not relying on IP addresses for rate-limiting, making it suitable for users behind NATs. The user experience is silent and seamless, eliminating the need for annoying image-based captchas. mCaptcha uses a proof-of-work solution to fiercely defend your site, making it more expensive for attackers to target your site than for you to respond to their requests. It is a libre software, with client libraries licensed under proprietary-friendly free software licenses. mCaptcha is also compatible with reCAPTCHA and hCaptcha, making it a convenient drop-in replacement. The core functionality of mCaptcha is to use a SHA256 based proof-of-work system to rate limit users, providing a token upon successful validation that users can then submit with their request or form submission to the target website.", "category": "privacy", "tags": ["Privacy", "Security", "CAPTCHA"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "mcaptcha/mcaptcha:v0.1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://mcaptcha.org"}, {"label": "Documentation", "url": "https://mcaptcha.org/docs"}, {"label": "Github", "url": "https://github.com/mcaptcha/mcaptcha"}], "instructions": "Login with aaronsw:password", "install": [{"docker": {"image": "$IMAGE", "name": "mcaptcha", "port": "$PORT:80", "volumes": [], "extra_ports": ["6379:6379"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Login with aaronsw:password"}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('mealie', 'Mealie', 'Mealie is a self-hosted recipe manager and meal planner designed to provide a pleasant user experience for the whole family. It features a RestAPI backend and a reactive frontend application built in Vue. With Mealie, you can quickly and easily import recipes from various websites using the built-in recipe scraper. The app ensures the safety of your data with automatic backups in any format supported by Jinja2 templates. It offers a rich and intuitive user interface that allows you to create, edit, and delete recipes with ease. The recipe editor supports markdown syntax for added convenience. Mealie also enables you to create meal plans for the week, month, or year. You can add new users, sort them into groups to share recipes and meal plans, and schedule webhooks to send notifications to 3rd party services with today''s meal plan data. The open API gives you full control of the backend server with interactive documentation.', 'food-&-drink', ARRAY['Food & Drink', 'Recipe Manager', 'Meal Planner'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "hkotel/mealie:v3.16.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Mealie", "version": "latest", "description": "Mealie is a self-hosted recipe manager and meal planner designed to provide a pleasant user experience for the whole family. It features a RestAPI backend and a reactive frontend application built in Vue. With Mealie, you can quickly and easily import recipes from various websites using the built-in recipe scraper. The app ensures the safety of your data with automatic backups in any format supported by Jinja2 templates. It offers a rich and intuitive user interface that allows you to create, edit, and delete recipes with ease. The recipe editor supports markdown syntax for added convenience. Mealie also enables you to create meal plans for the week, month, or year. You can add new users, sort them into groups to share recipes and meal plans, and schedule webhooks to send notifications to 3rd party services with today's meal plan data. The open API gives you full control of the backend server with interactive documentation.", "category": "food-&-drink", "tags": ["Food & Drink", "Recipe Manager", "Meal Planner"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "hkotel/mealie:v3.16.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://nightly.mealie.io/"}, {"label": "Github", "url": "https://github.com/hay-kot/mealie/"}], "instructions": "Please use the following credentials to login. changeme@easypanel.io|MyPassword", "install": [{"docker": {"image": "$IMAGE", "name": "mealie", "port": "$PORT:9000", "volumes": ["/app/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Please use the following credentials to login. changeme@easypanel.io|MyPassword"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('medama', 'Medama', 'Medama Analytics is an open-source project dedicated to providing self-hostable, cookie-free website analytics. With a lightweight tracker of less than 1KB, it aims to offer useful analytics while prioritising user privacy.', 'website-tracker', ARRAY['Website Tracker', 'Live Tracking', 'Website Monitoring', 'Analytics'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/medama-io/medama:v0.6.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Medama", "version": "latest", "description": "Medama Analytics is an open-source project dedicated to providing self-hostable, cookie-free website analytics. With a lightweight tracker of less than 1KB, it aims to offer useful analytics while prioritising user privacy.", "category": "website-tracker", "tags": ["Website Tracker", "Live Tracking", "Website Monitoring", "Analytics"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/medama-io/medama:v0.6.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/medama-io/medama"}, {"label": "Documentation", "url": "https://oss.medama.io/introduction"}], "instructions": "Login credentials, username; admin and password; CHANGE_ME_ON_FIRST_LOGIN", "install": [{"docker": {"image": "$IMAGE", "name": "medama", "port": "$PORT:8080", "volumes": ["/app/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Login credentials, username; admin and password; CHANGE_ME_ON_FIRST_LOGIN"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('mediamanager', 'MediaManager', 'MediaManager is a self-hosted media management application designed to help you organize, catalog, and manage your media collection. The application provides a clean web interface for browsing and managing your media files including movies, TV shows, music, and other digital content. With support for custom metadata, tagging, and categorization, MediaManager makes it easy to keep your media library organized and accessible. The application features automatic media scanning, metadata extraction, thumbnail generation, and search capabilities to quickly find content in large collections. Built with a PostgreSQL backend for reliable data storage, MediaManager can handle extensive media libraries with thousands of items. The flexible configuration system allows you to customize media directories, scanning behavior, and display preferences to match your needs. Perfect for home media enthusiasts who want to organize their digital collections, content creators managing large media archives, small organizations needing a simple media asset management solution, or anyone looking for a lightweight self-hosted alternative to complex media management systems.', 'media', ARRAY['Media', 'File Management', 'Organization', 'Self-Hosted', 'Library', 'Metadata', 'TV Shows'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/maxdorninger/mediamanager:1.12.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "MediaManager", "version": "latest", "description": "MediaManager is a self-hosted media management application designed to help you organize, catalog, and manage your media collection. The application provides a clean web interface for browsing and managing your media files including movies, TV shows, music, and other digital content. With support for custom metadata, tagging, and categorization, MediaManager makes it easy to keep your media library organized and accessible. The application features automatic media scanning, metadata extraction, thumbnail generation, and search capabilities to quickly find content in large collections. Built with a PostgreSQL backend for reliable data storage, MediaManager can handle extensive media libraries with thousands of items. The flexible configuration system allows you to customize media directories, scanning behavior, and display preferences to match your needs. Perfect for home media enthusiasts who want to organize their digital collections, content creators managing large media archives, small organizations needing a simple media asset management solution, or anyone looking for a lightweight self-hosted alternative to complex media management systems.", "category": "media", "tags": ["Media", "File Management", "Organization", "Self-Hosted", "Library", "Metadata", "TV Shows"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/maxdorninger/mediamanager:1.12.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://maxdorninger.github.io/MediaManager/"}, {"label": "Documentation", "url": "https://maxdorninger.github.io/MediaManager/introduction.html"}, {"label": "GitHub", "url": "https://github.com/maxdorninger/mediamanager"}], "instructions": "After deploy, edit the mounted config.toml on the MediaManager app service.\nSet [auth].admin_emails and [misc] library paths to match your setup.\nConfigure SMTP, OpenID, torrents, or indexers only if you use those features.\nSee https://maxdorninger.github.io/MediaManager/configuration-overview.html for details.\n", "install": [{"docker": {"image": "$IMAGE", "name": "mediamanager", "port": "$PORT:8000", "volumes": ["/data", "/data/images", "/data/tv", "/data/movies", "/data/torrents", "/app/config/config.toml"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deploy, edit the mounted config.toml on the MediaManager app service.\nSet [auth].admin_emails and [misc] library paths to match your setup.\nConfigure SMTP, OpenID, torrents, or indexers only if you use those features.\nSee https://maxdorninger.github.io/MediaManager/configuration-overview.html for details.\n"}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('mediawiki', 'MediaWiki', 'MediaWiki is a powerful, open-source wiki platform that powers some of the largest collaborative projects, including Wikipedia. It offers a flexible and extensible framework for creating and managing content, supporting features like user management, version control, and powerful extensions. MediaWiki provides multilingual support, ensuring global accessibility, and includes built-in tools for content organization, search, and collaboration. It is an ideal solution for knowledge bases, documentation sites, and community-driven content platforms. With a vibrant ecosystem of plugins and themes, MediaWiki can be customized to suit diverse use cases.', 'wiki', ARRAY['Wiki', 'Collaboration', 'Content Management', 'CMS'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "mediawiki:1.45.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "MediaWiki", "version": "latest", "description": "MediaWiki is a powerful, open-source wiki platform that powers some of the largest collaborative projects, including Wikipedia. It offers a flexible and extensible framework for creating and managing content, supporting features like user management, version control, and powerful extensions. MediaWiki provides multilingual support, ensuring global accessibility, and includes built-in tools for content organization, search, and collaboration. It is an ideal solution for knowledge bases, documentation sites, and community-driven content platforms. With a vibrant ecosystem of plugins and themes, MediaWiki can be customized to suit diverse use cases.", "category": "wiki", "tags": ["Wiki", "Collaboration", "Content Management", "CMS"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "mediawiki:1.45.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.mediawiki.org"}, {"label": "Documentation", "url": "https://www.mediawiki.org/wiki/Manual:Contents"}, {"label": "Github", "url": "https://github.com/wikimedia/mediawiki"}], "instructions": "During the installation, configure the database as prompted, and once completed, a file named \"LocalSettings.php\" will be downloaded. Open EasyPanel, navigate to the Storage section for MediaWiki, and create a file mount. Paste the content of the LocalSettings.php file into the mount and set its mount path to /var/www/html/LocalSettings.php. Finally, redeploy the MediaWiki app in EasyPanel to apply the configuration.", "install": [{"docker": {"image": "$IMAGE", "name": "mediawiki", "port": "$PORT:80", "volumes": ["/var/www/html/images"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "During the installation, configure the database as prompted, and once completed, a file named \"LocalSettings.php\" will be downloaded. Open EasyPanel, navigate to the Storage section for MediaWiki, and create a file mount. Paste the content of the LocalSettings.php file into the mount and set its mount path to /var/www/html/LocalSettings.php. Finally, redeploy the MediaWiki app in EasyPanel to apply the configuration."}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('medikeep', 'MediKeep', 'MediKeep is a lightweight, self-hosted application for managing your personal medical information. Keep your health records organized and accessible while maintaining complete control over your data privacy. Built with React frontend and FastAPI backend, MediKeep provides a secure platform for tracking medications, generating health reports, and managing your medical records with ease.', 'medical-records', ARRAY['Medical Records', 'Health Management', 'Self-Hosted', 'Privacy'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/afairgiant/medikeep:v0.64.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "MediKeep", "version": "latest", "description": "MediKeep is a lightweight, self-hosted application for managing your personal medical information. Keep your health records organized and accessible while maintaining complete control over your data privacy. Built with React frontend and FastAPI backend, MediKeep provides a secure platform for tracking medications, generating health reports, and managing your medical records with ease.", "category": "medical-records", "tags": ["Medical Records", "Health Management", "Self-Hosted", "Privacy"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/afairgiant/medikeep:v0.64.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://medikeeps.com"}, {"label": "GitHub", "url": "https://github.com/afairgiant/MediKeep"}, {"label": "Documentation", "url": "https://github.com/afairgiant/MediKeep/tree/main/docs"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "medikeep", "port": "$PORT:8000", "volumes": ["/app/uploads", "/app/logs", "/app/backups"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('medusa', 'Medusa', 'Medusa is an automatic Video Library Manager for TV Shows. It continuously monitors multiple sources for new episodes of your favorite TV shows and automatically downloads, processes, and organizes them. Medusa fetches metadata, renames files, and ensures your media library is structured and up-to-date. With a powerful and customizable automation system, it supports multiple download clients, subtitle providers, and metadata sources. Medusa integrates with popular media servers, ensuring seamless media management.', 'tv-shows', ARRAY['TV Shows', 'Media Management', 'Automation', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/medusa:1.0.25"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8081}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Medusa", "version": "latest", "description": "Medusa is an automatic Video Library Manager for TV Shows. It continuously monitors multiple sources for new episodes of your favorite TV shows and automatically downloads, processes, and organizes them. Medusa fetches metadata, renames files, and ensures your media library is structured and up-to-date. With a powerful and customizable automation system, it supports multiple download clients, subtitle providers, and metadata sources. Medusa integrates with popular media servers, ensuring seamless media management.", "category": "tv-shows", "tags": ["TV Shows", "Media Management", "Automation", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/medusa:1.0.25"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8081}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://github.com/pymedusa/Medusa/wiki"}, {"label": "Github", "url": "https://github.com/pymedusa/Medusa"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "medusa", "port": "$PORT:8081", "volumes": ["/config", "/downloads", "/tv"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('meilisearch', 'Meilisearch', 'Meilisearch Cloud is a next-generation, open-source search engine designed to enhance your search experience. This powerful tool can be effortlessly integrated into any website or application, providing lightning-fast, hyper-relevant search results in less than 50 milliseconds. With Meilisearch, you can deploy a user-focused search experience in just a few minutes, thanks to its smart presets that require zero configuration. It offers the most advanced full-text search engine with great relevancy that fits every use case. Meilisearch supports all languages and automatically detects them, allowing for a truly global search experience. It also allows for custom relevancy, enabling you to create your own ranking rules. Meilisearch ensures secure searches with API keys and tenant tokens, and even allows for real-world geo searches. With Meilisearch Cloud, you can enhance your user''s search experience with custom filters and build a faceted search interface in just a few lines of code.', 'developer-tools', ARRAY['Developer Tools', 'Search Engine'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "getmeili/meilisearch:v1.43.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 7700}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Meilisearch", "version": "latest", "description": "Meilisearch Cloud is a next-generation, open-source search engine designed to enhance your search experience. This powerful tool can be effortlessly integrated into any website or application, providing lightning-fast, hyper-relevant search results in less than 50 milliseconds. With Meilisearch, you can deploy a user-focused search experience in just a few minutes, thanks to its smart presets that require zero configuration. It offers the most advanced full-text search engine with great relevancy that fits every use case. Meilisearch supports all languages and automatically detects them, allowing for a truly global search experience. It also allows for custom relevancy, enabling you to create your own ranking rules. Meilisearch ensures secure searches with API keys and tenant tokens, and even allows for real-world geo searches. With Meilisearch Cloud, you can enhance your user's search experience with custom filters and build a faceted search interface in just a few lines of code.", "category": "developer-tools", "tags": ["Developer Tools", "Search Engine"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "getmeili/meilisearch:v1.43.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 7700}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://meilisearch.com/"}, {"label": "Documentation", "url": "https://docs.meilisearch.com/"}, {"label": "Github", "url": "https://github.com/meilisearch/meilisearch/"}, {"label": "Discord", "url": "https://discord.gg/meilisearch"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "meilisearch", "port": "$PORT:7700", "volumes": ["/meili_data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('memcached', 'Memcached', 'Memcached is a high-performance, distributed memory object caching system designed for speeding up dynamic web applications by alleviating database load. It works by storing data and objects in RAM to reduce the number of times an external data source must be read. Memcached is simple yet powerful, featuring a straightforward design that enables rapid deployment, ease of development, and solves many problems facing large data caches. It''s particularly useful for database call, API call, or page rendering result caching.', 'cache', ARRAY['Cache', 'In-Memory', 'Performance', 'Database'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "memcached:1.6.41"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Memcached", "version": "latest", "description": "Memcached is a high-performance, distributed memory object caching system designed for speeding up dynamic web applications by alleviating database load. It works by storing data and objects in RAM to reduce the number of times an external data source must be read. Memcached is simple yet powerful, featuring a straightforward design that enables rapid deployment, ease of development, and solves many problems facing large data caches. It's particularly useful for database call, API call, or page rendering result caching.", "category": "cache", "tags": ["Cache", "In-Memory", "Performance", "Database"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "memcached:1.6.41"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://memcached.org/"}, {"label": "Documentation", "url": "https://github.com/memcached/memcached/wiki"}, {"label": "Github", "url": "https://github.com/memcached/memcached"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "memcached", "port": "$PORT:80", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('memgraph', 'Memgraph', 'Memgraph is a high-performance, in-memory graph database designed for real-time analytics and machine learning applications. It provides fast graph traversal, pattern matching, and complex graph algorithms with support for Cypher query language. Memgraph MAGE (Memgraph Advanced Graph Extensions) includes pre-built graph algorithms and machine learning modules. The platform comes with Memgraph Lab, a visual interface for database management, query development, and graph visualization.', 'graph-database', ARRAY['Graph Database', 'Real-Time Analytics', 'Machine Learning', 'Cypher', 'Graph Algorithms', 'Visualization', 'MAGE', 'In-Memory', 'High Performance', 'Data Science'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Memgraph", "version": "latest", "description": "Memgraph is a high-performance, in-memory graph database designed for real-time analytics and machine learning applications. It provides fast graph traversal, pattern matching, and complex graph algorithms with support for Cypher query language. Memgraph MAGE (Memgraph Advanced Graph Extensions) includes pre-built graph algorithms and machine learning modules. The platform comes with Memgraph Lab, a visual interface for database management, query development, and graph visualization.", "category": "graph-database", "tags": ["Graph Database", "Real-Time Analytics", "Machine Learning", "Cypher", "Graph Algorithms", "Visualization", "MAGE", "In-Memory", "High Performance", "Data Science"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/memgraph/memgraph"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/memgraph/memgraph"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "memgraph", "port": "$PORT:3000", "volumes": [], "extra_ports": ["7687:7687"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('memos', 'Memos', 'Memos is a privacy-first, lightweight note-taking service designed to easily capture and share your great thoughts. With its focus on privacy, all data generated is saved in the SQLite database file, ensuring that you keep your own data by yourself. The app supports plain text with markdown, allowing you to save all content as plain text, not HTML, while also supporting a variety of useful markdown syntax. Despite being lightweight, Memos is powerful, utilizing a Go + React.js + SQLite architecture. The app is customizable, allowing you to modify the server name, icon, description, system style, and execution script. Memos is open source and free forever, embodying the belief that open source is the future. It offers a RESTful API for third-party services, enabling integration and new possibilities. With Memos, you can embrace a future where creativity knows no boundaries.', 'notes', ARRAY['Notes', 'Privacy'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "neosmemo/memos:0.28"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5230}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Memos", "version": "latest", "description": "Memos is a privacy-first, lightweight note-taking service designed to easily capture and share your great thoughts. With its focus on privacy, all data generated is saved in the SQLite database file, ensuring that you keep your own data by yourself. The app supports plain text with markdown, allowing you to save all content as plain text, not HTML, while also supporting a variety of useful markdown syntax. Despite being lightweight, Memos is powerful, utilizing a Go + React.js + SQLite architecture. The app is customizable, allowing you to modify the server name, icon, description, system style, and execution script. Memos is open source and free forever, embodying the belief that open source is the future. It offers a RESTful API for third-party services, enabling integration and new possibilities. With Memos, you can embrace a future where creativity knows no boundaries.", "category": "notes", "tags": ["Notes", "Privacy"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "neosmemo/memos:0.28"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5230}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://usememos.com/"}, {"label": "Documentation", "url": "https://github.com/usememos/memos#deploy-with-docker-in-seconds"}, {"label": "Github", "url": "https://github.com/usememos/memos"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "memos", "port": "$PORT:5230", "volumes": ["/var/opt/memos"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('metabase', 'Metabase', 'Metabase is a powerful, user-friendly application designed to enable your company to explore data independently. It offers fast analytics with integrated tooling and a friendly user interface. With Metabase, you can go from zero to dashboard in just 2 minutes, allowing you to connect directly to over 20+ data sources, from your startup’s production database to massive data warehouses, and query immediately without extracts. The application is trusted by over 50,000 companies and is accessible to all, with a range of plans from free open-source to pay-as-you-go Pro and Enterprise. Metabase allows you to create and share interactive dashboards, craft metadata-rich models, and free your data from the confines of SQL with a Visual Query Builder. It is designed to make self-service analytics a reality, providing a simple yet powerful tool for data exploration and dashboarding.', 'analytics', ARRAY['Analytics', 'Business Apps'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "metabase/metabase:v0.60.3.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Metabase", "version": "latest", "description": "Metabase is a powerful, user-friendly application designed to enable your company to explore data independently. It offers fast analytics with integrated tooling and a friendly user interface. With Metabase, you can go from zero to dashboard in just 2 minutes, allowing you to connect directly to over 20+ data sources, from your startup\u2019s production database to massive data warehouses, and query immediately without extracts. The application is trusted by over 50,000 companies and is accessible to all, with a range of plans from free open-source to pay-as-you-go Pro and Enterprise. Metabase allows you to create and share interactive dashboards, craft metadata-rich models, and free your data from the confines of SQL with a Visual Query Builder. It is designed to make self-service analytics a reality, providing a simple yet powerful tool for data exploration and dashboarding.", "category": "analytics", "tags": ["Analytics", "Business Apps"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "metabase/metabase:v0.60.3.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.metabase.com/"}, {"label": "Documentation", "url": "https://www.metabase.com/docs/latest/"}, {"label": "Github", "url": "https://github.com/metabase/metabase/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "metabase", "port": "$PORT:3000", "volumes": ["/metabase-data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('metaflow', 'Metaflow', 'Metaflow is an open-source framework for building and managing real-life ML, AI, and data science projects. Originally developed at Netflix and now supported by Outerbounds, Metaflow streamlines the entire development lifecycle—from rapid prototyping in notebooks to reliable production deployments. It unifies code, data, and compute at every stage, enabling teams to iterate quickly and deliver robust AI/ML systems. Used by Amazon, Doordash, Goldman Sachs, and many others.', 'machine-learning', ARRAY['Machine Learning', 'AI', 'Data Science', 'MLOps', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Metaflow", "version": "latest", "description": "Metaflow is an open-source framework for building and managing real-life ML, AI, and data science projects. Originally developed at Netflix and now supported by Outerbounds, Metaflow streamlines the entire development lifecycle\u2014from rapid prototyping in notebooks to reliable production deployments. It unifies code, data, and compute at every stage, enabling teams to iterate quickly and deliver robust AI/ML systems. Used by Amazon, Doordash, Goldman Sachs, and many others.", "category": "machine-learning", "tags": ["Machine Learning", "AI", "Data Science", "MLOps", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://metaflow.org/"}, {"label": "Documentation", "url": "https://docs.metaflow.org/"}, {"label": "GitHub", "url": "https://github.com/Netflix/metaflow"}, {"label": "Metaflow Service", "url": "https://github.com/Netflix/metaflow-service"}], "instructions": "Deploy Metaflow metadata service to track your flows. Configure your Metaflow client with METAFLOW_SERVICE_URL pointing to your deployment URL and METAFLOW_DEFAULT_METADATA=service. Run flows with `python myflow.py run` and metadata will be stored. Allow ~30 seconds for the metadata service to start.", "install": [{"docker": {"image": "$IMAGE", "name": "metaflow", "port": "$PORT:8080", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Deploy Metaflow metadata service to track your flows. Configure your Metaflow client with METAFLOW_SERVICE_URL pointing to your deployment URL and METAFLOW_DEFAULT_METADATA=service. Run flows with `python myflow.py run` and metadata will be stored. Allow ~30 seconds for the metadata service to start."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('metatrader5', 'MetaTrader5', 'MetaTrader 5 (MT5) is a powerful, multi-functional trading platform designed for financial institutions, brokers, and individual traders. It supports trading in various financial markets, including Forex, stocks, futures, and CFDs. MT5 offers advanced charting tools, technical indicators, and automated trading capabilities through Expert Advisors (EAs). With a focus on speed, reliability, and flexibility, MT5 enables seamless market analysis, efficient trade execution, and comprehensive risk management. The platform supports multi-asset trading, backtesting, and a robust API for custom integrations.', 'trading', ARRAY['Trading', 'Financial Markets', 'Automated Trading', 'Forex', 'Stocks'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "gmag11/metatrader5_vnc:2.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "MetaTrader5", "version": "latest", "description": "MetaTrader 5 (MT5) is a powerful, multi-functional trading platform designed for financial institutions, brokers, and individual traders. It supports trading in various financial markets, including Forex, stocks, futures, and CFDs. MT5 offers advanced charting tools, technical indicators, and automated trading capabilities through Expert Advisors (EAs). With a focus on speed, reliability, and flexibility, MT5 enables seamless market analysis, efficient trade execution, and comprehensive risk management. The platform supports multi-asset trading, backtesting, and a robust API for custom integrations.", "category": "trading", "tags": ["Trading", "Financial Markets", "Automated Trading", "Forex", "Stocks"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "gmag11/metatrader5_vnc:2.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.metatrader5.com/en"}, {"label": "Documentation", "url": "https://www.metatrader5.com/en/terminal/help"}, {"label": "Github", "url": "https://github.com/gmag11/MetaTrader5-Docker-Image"}, {"label": "Docker Guide", "url": "https://hub.docker.com/r/gmag11/metatrader5_vnc"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "metatrader5", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('metube', 'MeTube', 'MeTube is a web-based application that provides a user-friendly interface for the popular command-line tool, youtube-dl. It allows you to easily download videos from YouTube and dozens of other sites, right from your browser. The app supports playlist downloads, making it easy to grab an entire series of videos at once. It also offers a range of configuration options, allowing you to customize the download process to suit your needs. For instance, you can choose to save your downloads to a specific directory, separate audio-only downloads from video downloads, and even specify the filename template for your downloaded videos. MeTube also supports dark mode for a more comfortable viewing experience. The app runs in a Docker container, making it easy to deploy on any system that supports Docker.', 'media', ARRAY['Media', 'Video Downloader', 'Web GUI'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "alexta69/metube:2026.04.28"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8081}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "MeTube", "version": "latest", "description": "MeTube is a web-based application that provides a user-friendly interface for the popular command-line tool, youtube-dl. It allows you to easily download videos from YouTube and dozens of other sites, right from your browser. The app supports playlist downloads, making it easy to grab an entire series of videos at once. It also offers a range of configuration options, allowing you to customize the download process to suit your needs. For instance, you can choose to save your downloads to a specific directory, separate audio-only downloads from video downloads, and even specify the filename template for your downloaded videos. MeTube also supports dark mode for a more comfortable viewing experience. The app runs in a Docker container, making it easy to deploy on any system that supports Docker.", "category": "media", "tags": ["Media", "Video Downloader", "Web GUI"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "alexta69/metube:2026.04.28"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8081}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://github.com/alexta69/metube"}, {"label": "Github", "url": "https://github.com/alexta69/metube"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "metube", "port": "$PORT:8081", "volumes": ["/downloads"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('milvus', 'Milvus', 'Milvus is an open-source vector database designed for AI applications and similarity search. It provides high-performance vector search capabilities and is optimized for handling large-scale vector data. Milvus supports various index types and search methods, making it ideal for applications like recommendation systems, image search, and natural language processing.', 'database', ARRAY['Database', 'Vector Database', 'AI', 'Search', 'Machine Learning'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "milvusdb/milvus:v2.6.11"}, "port": {"type": "integer", "title": "Port HTTP", "default": 2379}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Milvus", "version": "latest", "description": "Milvus is an open-source vector database designed for AI applications and similarity search. It provides high-performance vector search capabilities and is optimized for handling large-scale vector data. Milvus supports various index types and search methods, making it ideal for applications like recommendation systems, image search, and natural language processing.", "category": "database", "tags": ["Database", "Vector Database", "AI", "Search", "Machine Learning"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "milvusdb/milvus:v2.6.11"}, "port": {"type": "integer", "title": "Port HTTP", "default": 2379}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://milvus.io/"}, {"label": "Documentation", "url": "https://milvus.io/docs/"}, {"label": "GitHub", "url": "https://github.com/milvus-io/milvus"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "milvus", "port": "$PORT:2379", "volumes": ["/var/lib/milvus", "/etcd", "/minio_data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('minecraft-server-bedrock', 'Minecraft Bedrock Server', 'The itzg/minecraft-bedrock-server app is designed to provide a seamless Minecraft Server experience for the Bedrock Edition. It automatically downloads the latest stable version of the Minecraft server at startup, ensuring you''re always up-to-date with the game''s latest features and improvements. The app also allows you to run or upgrade to any specific version or the latest snapshot, giving you full control over your gaming experience. If you''re using Minecraft clients on consoles, mobile, or native Windows, the app offers a dedicated Bedrock Server for optimal performance. The standard server port, 19132, will be exposed on your host machine for easy access and gameplay.', 'gaming', ARRAY['Gaming', 'Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "itzg/minecraft-bedrock-server:2025.12.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Minecraft Bedrock Server", "version": "latest", "description": "The itzg/minecraft-bedrock-server app is designed to provide a seamless Minecraft Server experience for the Bedrock Edition. It automatically downloads the latest stable version of the Minecraft server at startup, ensuring you're always up-to-date with the game's latest features and improvements. The app also allows you to run or upgrade to any specific version or the latest snapshot, giving you full control over your gaming experience. If you're using Minecraft clients on consoles, mobile, or native Windows, the app offers a dedicated Bedrock Server for optimal performance. The standard server port, 19132, will be exposed on your host machine for easy access and gameplay.", "category": "gaming", "tags": ["Gaming", "Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "itzg/minecraft-bedrock-server:2025.12.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/itzg/docker-minecraft-bedrock-server"}, {"label": "Docker", "url": "https://hub.docker.com/r/itzg/minecraft-bedrock-server"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "minecraft-server-bedrock", "port": "$PORT:80", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('minecraft-server', 'Minecraft Server', 'The itzg/minecraft-server app is designed to provide a seamless Minecraft Server experience. It automatically downloads the latest stable version of the Minecraft server at startup, ensuring you''re always up-to-date with the game''s latest features and improvements. The app also allows you to run or upgrade to any specific version or the latest snapshot, giving you full control over your gaming experience. If you''re using Minecraft clients on consoles, mobile, or native Windows, the app offers a dedicated Bedrock Server for optimal performance. The standard server port, 25565, will be exposed on your host machine for easy access and gameplay.', 'gaming', ARRAY['Gaming', 'Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "itzg/minecraft-server:2025.12.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Minecraft Server", "version": "latest", "description": "The itzg/minecraft-server app is designed to provide a seamless Minecraft Server experience. It automatically downloads the latest stable version of the Minecraft server at startup, ensuring you're always up-to-date with the game's latest features and improvements. The app also allows you to run or upgrade to any specific version or the latest snapshot, giving you full control over your gaming experience. If you're using Minecraft clients on consoles, mobile, or native Windows, the app offers a dedicated Bedrock Server for optimal performance. The standard server port, 25565, will be exposed on your host machine for easy access and gameplay.", "category": "gaming", "tags": ["Gaming", "Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "itzg/minecraft-server:2025.12.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/itzg/docker-minecraft-server"}, {"label": "Docker", "url": "https://hub.docker.com/r/itzg/minecraft-server"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "minecraft-server", "port": "$PORT:80", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('miniflux', 'Miniflux', 'Miniflux is a minimalist and opinionated feed reader designed to prioritize content and readability. It optimizes the page layout, fonts, and colors to ensure that they are screen-friendly. If you have feeds that display only a summary, Miniflux fetches the original article automatically. The app is designed with simplicity in mind, focusing on essential features and avoiding bloated software. It is fast and efficient, allowing you to navigate through the application using keyboard shortcuts and quickly scan your unread items with a lightweight user interface. Miniflux also respects your privacy, ensuring that no one resells your private data or tracks your usage. It automatically removes pixel trackers and does not feature any advertising or user tracking. Miniflux is a free, open-source project distributed under the permissive Apache 2.0 License.', 'rss', ARRAY['RSS', 'Privacy'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "miniflux/miniflux:2.2.19"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Miniflux", "version": "latest", "description": "Miniflux is a minimalist and opinionated feed reader designed to prioritize content and readability. It optimizes the page layout, fonts, and colors to ensure that they are screen-friendly. If you have feeds that display only a summary, Miniflux fetches the original article automatically. The app is designed with simplicity in mind, focusing on essential features and avoiding bloated software. It is fast and efficient, allowing you to navigate through the application using keyboard shortcuts and quickly scan your unread items with a lightweight user interface. Miniflux also respects your privacy, ensuring that no one resells your private data or tracks your usage. It automatically removes pixel trackers and does not feature any advertising or user tracking. Miniflux is a free, open-source project distributed under the permissive Apache 2.0 License.", "category": "rss", "tags": ["RSS", "Privacy"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "miniflux/miniflux:2.2.19"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://miniflux.app/"}, {"label": "Documentation", "url": "https://miniflux.app/docs/"}, {"label": "Github", "url": "https://github.com/miniflux"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "miniflux", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('minio', 'Minio', 'Minio is an open-source, self-hosted object storage solution designed to empower users with efficient data storage and management capabilities. Prioritizing control and privacy, Minio enables individuals and organizations to build their private cloud infrastructure. With its user-friendly interface and robust features, Minio allows seamless storage and retrieval of large amounts of data while offering secure access controls.', 'self-hosted', ARRAY[]::text[], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "minio/minio:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Minio", "version": "latest", "description": "Minio is an open-source, self-hosted object storage solution designed to empower users with efficient data storage and management capabilities. Prioritizing control and privacy, Minio enables individuals and organizations to build their private cloud infrastructure. With its user-friendly interface and robust features, Minio allows seamless storage and retrieval of large amounts of data while offering secure access controls.", "category": "self-hosted", "tags": [], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "minio/minio:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://min.io/docs/minio/linux/index.html"}, {"label": "Github", "url": "https://github.com/minio/minio"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "minio", "port": "$PORT:9000", "volumes": ["/data"], "extra_ports": ["9001:9001"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('mirotalk', 'MiroTalk P2P', 'MiroTalk P2P is a powerful WebRTC-based peer-to-peer video conferencing platform that enables secure, real-time communication directly between participants without requiring external servers for media transmission. It offers advanced features like screen sharing, file transfer, chat messaging, and room protection, making it perfect for businesses, educational institutions, and personal use that require privacy-focused video conferencing solutions.', 'video-conferencing', ARRAY['Video Conferencing', 'WebRTC', 'Peer-to-Peer', 'Communication', 'Collaboration', 'Screen Sharing', 'Real-time', 'Privacy', 'Security'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "mirotalk/p2p:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "MiroTalk P2P", "version": "latest", "description": "MiroTalk P2P is a powerful WebRTC-based peer-to-peer video conferencing platform that enables secure, real-time communication directly between participants without requiring external servers for media transmission. It offers advanced features like screen sharing, file transfer, chat messaging, and room protection, making it perfect for businesses, educational institutions, and personal use that require privacy-focused video conferencing solutions.", "category": "video-conferencing", "tags": ["Video Conferencing", "WebRTC", "Peer-to-Peer", "Communication", "Collaboration", "Screen Sharing", "Real-time", "Privacy", "Security"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "mirotalk/p2p:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://p2p.mirotalk.com"}, {"label": "Documentation", "url": "https://docs.mirotalk.com"}, {"label": "GitHub", "url": "https://github.com/miroslavpejic85/mirotalk"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "mirotalk", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('monetr', 'Monetr', 'Monetr is a self-hosted personal finance management application that helps you track your spending, manage budgets, and gain insights into your financial habits. Built with modern architecture, Monetr provides a comprehensive solution for managing your personal finances with features like transaction tracking, budget management, spending analysis, and financial goal setting. The system uses PostgreSQL for data persistence and Valkey (Redis-compatible) for caching and session management. Perfect for individuals looking for a self-hosted alternative to commercial personal finance applications.', 'finance', ARRAY['Finance', 'Personal Finance', 'Budgeting', 'Self-Hosted', 'PostgreSQL', 'Valkey', 'Docker'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/monetr/monetr:1.13.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Monetr", "version": "latest", "description": "Monetr is a self-hosted personal finance management application that helps you track your spending, manage budgets, and gain insights into your financial habits. Built with modern architecture, Monetr provides a comprehensive solution for managing your personal finances with features like transaction tracking, budget management, spending analysis, and financial goal setting. The system uses PostgreSQL for data persistence and Valkey (Redis-compatible) for caching and session management. Perfect for individuals looking for a self-hosted alternative to commercial personal finance applications.", "category": "finance", "tags": ["Finance", "Personal Finance", "Budgeting", "Self-Hosted", "PostgreSQL", "Valkey", "Docker"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/monetr/monetr:1.13.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/monetr/monetr"}, {"label": "Website", "url": "https://monetr.app"}, {"label": "Documentation", "url": "https://monetr.app/documentation/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "monetr", "port": "$PORT:4000", "volumes": ["/etc/monetr"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('mongo-express', 'Mongo Express', 'mongo-express is a web-based MongoDB admin interface designed with Node.js, Express, and Bootstrap3. It allows you to connect to multiple databases, view, add, delete databases, and manage collections. You can also view, add, update, and delete documents within these collections. The app supports previewing audio, video, and image assets inline in the collection view. Large or nested objects are collapsible for easy overview, and big document properties are loaded on-demand to keep the collection view fast. The app also supports GridFS, enabling you to add, get, and delete incredibly large files. It uses BSON data types in documents and is mobile responsive, thanks to Bootstrap 3. The app also supports connection and authentication to individual databases, as well as admin authentication to view all databases. It includes features for database blacklist/whitelist, custom CA, and CA validation disabling, and supports replica sets.', 'databases', ARRAY['Databases', 'Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "mongo-express:1.0.2-20-alpine3.19"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8081}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Mongo Express", "version": "latest", "description": "mongo-express is a web-based MongoDB admin interface designed with Node.js, Express, and Bootstrap3. It allows you to connect to multiple databases, view, add, delete databases, and manage collections. You can also view, add, update, and delete documents within these collections. The app supports previewing audio, video, and image assets inline in the collection view. Large or nested objects are collapsible for easy overview, and big document properties are loaded on-demand to keep the collection view fast. The app also supports GridFS, enabling you to add, get, and delete incredibly large files. It uses BSON data types in documents and is mobile responsive, thanks to Bootstrap 3. The app also supports connection and authentication to individual databases, as well as admin authentication to view all databases. It includes features for database blacklist/whitelist, custom CA, and CA validation disabling, and supports replica sets.", "category": "databases", "tags": ["Databases", "Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "mongo-express:1.0.2-20-alpine3.19"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8081}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/mongo-express/mongo-express"}, {"label": "Docker", "url": "https://hub.docker.com/_/mongo-express/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "mongo-express", "port": "$PORT:8081", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('monica', 'Monica', 'OfficeLife is an all-in-one tool designed to manage a company efficiently. It serves as your personal CRM, helping you organize and follow-up on your social interactions, thereby strengthening your relationships. With Monica, you can easily log and remember important details about your friends, family, and colleagues. It allows you to store everything you know about your loved ones in one place, from their work information, family details, activities you''ve done together, to reminders about important dates. Monica is designed for busy individuals striving to maintain a good work-life balance. It''s a private space, free from ads or malicious software, where you can safely document what you know about who you love. Monica is open source, ensuring transparency and security.', 'crm', ARRAY['CRM', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "monica:5.0-apache"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Monica", "version": "latest", "description": "OfficeLife is an all-in-one tool designed to manage a company efficiently. It serves as your personal CRM, helping you organize and follow-up on your social interactions, thereby strengthening your relationships. With Monica, you can easily log and remember important details about your friends, family, and colleagues. It allows you to store everything you know about your loved ones in one place, from their work information, family details, activities you've done together, to reminders about important dates. Monica is designed for busy individuals striving to maintain a good work-life balance. It's a private space, free from ads or malicious software, where you can safely document what you know about who you love. Monica is open source, ensuring transparency and security.", "category": "crm", "tags": ["CRM", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "monica:5.0-apache"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://monicahq.com"}, {"label": "Github", "url": "https://github.com/monicahq/monica"}, {"label": "Docker", "url": "https://hub.docker.com/_/monica"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "monica", "port": "$PORT:80", "volumes": ["/var/www/html/storage", "/var/www/html/app", "/var/www/html/database", "/var/www/html/resources", "/var/www/html/routes"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('moocup', 'Moocup', 'Moocup is a visual editor designed to create stunning screenshots in seconds. It provides a simple and functional interface where you can drop your screenshot, apply beautiful base styles, customize it however you wish, and export professional-looking visuals instantly. Built for developers, designers, and content creators who need to showcase their work with polished screenshots for portfolios, documentation, presentations, or social media. The tool offers an intuitive drag-and-drop workflow with real-time visual editing, eliminating the need for complex design software or manual styling. With Moocup''s self-hosted solution, your screenshots remain private and never leave your infrastructure, making it ideal for sensitive projects or proprietary applications. The browser-based editor requires zero installation and works seamlessly across devices with responsive design. Perfect for anyone who values simplicity and functionality but still wants to create eye-catching visuals that make their projects stand out without the overhead of heavyweight design tools or paid screenshot services.', 'screenshots', ARRAY['Screenshots', 'Visual Editor', 'Design Tool', 'Portfolio', 'Image Editor'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "jellydeck/moocup:1.0.48"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Moocup", "version": "latest", "description": "Moocup is a visual editor designed to create stunning screenshots in seconds. It provides a simple and functional interface where you can drop your screenshot, apply beautiful base styles, customize it however you wish, and export professional-looking visuals instantly. Built for developers, designers, and content creators who need to showcase their work with polished screenshots for portfolios, documentation, presentations, or social media. The tool offers an intuitive drag-and-drop workflow with real-time visual editing, eliminating the need for complex design software or manual styling. With Moocup's self-hosted solution, your screenshots remain private and never leave your infrastructure, making it ideal for sensitive projects or proprietary applications. The browser-based editor requires zero installation and works seamlessly across devices with responsive design. Perfect for anyone who values simplicity and functionality but still wants to create eye-catching visuals that make their projects stand out without the overhead of heavyweight design tools or paid screenshot services.", "category": "screenshots", "tags": ["Screenshots", "Visual Editor", "Design Tool", "Portfolio", "Image Editor"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "jellydeck/moocup:1.0.48"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://moocup.jaydip.me"}, {"label": "GitHub", "url": "https://github.com/jellydeck/moocup"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/jellydeck/moocup"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "moocup", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('moodle', 'Moodle', 'Moodle is a robust, scalable, and open-source learning management system (LMS) designed to provide educators and learners with a customizable platform to create and deliver personalized learning experiences. With Moodle, you can manage courses, track progress, and collaborate using a variety of tools like forums, assignments, and quizzes. It supports integrations with numerous third-party tools and plugins to enhance functionality. Moodle focuses on accessibility, ensuring an inclusive experience for all users. It is widely used in academic institutions, businesses, and non-profits globally to deliver quality online education. Moodle is a free, open-source project distributed under the GNU General Public License.', 'lms', ARRAY['LMS', 'Education', 'Open Source', 'Accessibility', 'Learning Management', 'Customization', 'E-learning'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "bitnamilegacy/moodle:5.0.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Moodle", "version": "latest", "description": "Moodle is a robust, scalable, and open-source learning management system (LMS) designed to provide educators and learners with a customizable platform to create and deliver personalized learning experiences. With Moodle, you can manage courses, track progress, and collaborate using a variety of tools like forums, assignments, and quizzes. It supports integrations with numerous third-party tools and plugins to enhance functionality. Moodle focuses on accessibility, ensuring an inclusive experience for all users. It is widely used in academic institutions, businesses, and non-profits globally to deliver quality online education. Moodle is a free, open-source project distributed under the GNU General Public License.", "category": "lms", "tags": ["LMS", "Education", "Open Source", "Accessibility", "Learning Management", "Customization", "E-learning"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "bitnamilegacy/moodle:5.0.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://moodle.org/"}, {"label": "Documentation", "url": "https://docs.moodle.org/"}, {"label": "Github", "url": "https://github.com/moodle"}], "instructions": "Moodle takes time to install. Default credentails; username=user, password=bitnami", "install": [{"docker": {"image": "$IMAGE", "name": "moodle", "port": "$PORT:8080", "volumes": ["/bitnami/mariadb", "/bitnami/moodle"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Moodle takes time to install. Default credentails; username=user, password=bitnami"}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('morphic', 'Morphic', 'Morphic is an AI-powered search and answer engine that combines the power of multiple AI models with real-time web search capabilities. It provides intelligent answers to user queries by leveraging various AI providers including OpenAI, Anthropic, Google, and Groq, while using SearxNG for privacy-focused web search. Morphic offers a conversational interface that delivers comprehensive, well-sourced answers with citations and follow-up questions, making it an excellent alternative to traditional search engines.', 'ai', ARRAY['AI', 'Search Engine', 'Chat', 'OpenAI', 'Anthropic', 'Google', 'Groq', 'Redis', 'Next.js'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/miurla/morphic:e4fd78357afc685db17e6c27404b9728b3205624"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Morphic", "version": "latest", "description": "Morphic is an AI-powered search and answer engine that combines the power of multiple AI models with real-time web search capabilities. It provides intelligent answers to user queries by leveraging various AI providers including OpenAI, Anthropic, Google, and Groq, while using SearxNG for privacy-focused web search. Morphic offers a conversational interface that delivers comprehensive, well-sourced answers with citations and follow-up questions, making it an excellent alternative to traditional search engines.", "category": "ai", "tags": ["AI", "Search Engine", "Chat", "OpenAI", "Anthropic", "Google", "Groq", "Redis", "Next.js"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/miurla/morphic:e4fd78357afc685db17e6c27404b9728b3205624"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/miurla/morphic"}, {"label": "Documentation", "url": "https://github.com/miurla/morphic#readme"}, {"label": "Demo", "url": "https://morphic.sh"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "morphic", "port": "$PORT:3000", "volumes": ["/data", "/etc/searxng/settings.yml", "/etc/searxng/limiter.toml"], "extra_ports": ["8080:8080", "8888:8888"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('motoradmin', 'MotorAdmin', 'MotorAdmin is a modern, open-source database administration tool that provides a user-friendly interface for managing and interacting with your databases. It offers features for data visualization, query building, and database management.', 'database', ARRAY['Database', 'Administration', 'Data Management', 'Visualization', 'Query Builder'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "motoradmin/motoradmin:0.4.21"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "MotorAdmin", "version": "latest", "description": "MotorAdmin is a modern, open-source database administration tool that provides a user-friendly interface for managing and interacting with your databases. It offers features for data visualization, query building, and database management.", "category": "database", "tags": ["Database", "Administration", "Data Management", "Visualization", "Query Builder"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "motoradmin/motoradmin:0.4.21"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.getmotoradmin.com"}, {"label": "Github", "url": "https://github.com/motor-admin/motor-admin"}, {"label": "Documentation", "url": "https://docs.getmotoradmin.com/guide/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "motoradmin", "port": "$PORT:3000", "volumes": ["/app"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('mstream', 'Mstream', 'mStream is a personal music streaming server that allows you to access your music collection from anywhere. It''s like having your private cloud for music. With mStream, you can sync your collection between your devices for offline access. It offers high-quality streaming for audiophiles and FLAC enthusiasts, allowing you to stream your music uncompressed. mStream respects your privacy, it does not collect statistics on your listening habits. It''s also beneficial for artists as buying music directly means your money goes directly to them. The server setup is quick and it runs on any operating system. It also has mobile apps for iOS & Android and allows you to stream your music in any browser. Other features include gapless playback, Milkdrop visualizer, playlist sharing, and drag and drop file uploading. All the code for mStream is open source.', 'media', ARRAY['Media', 'Music Streaming'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/mstream:6.6.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Mstream", "version": "latest", "description": "mStream is a personal music streaming server that allows you to access your music collection from anywhere. It's like having your private cloud for music. With mStream, you can sync your collection between your devices for offline access. It offers high-quality streaming for audiophiles and FLAC enthusiasts, allowing you to stream your music uncompressed. mStream respects your privacy, it does not collect statistics on your listening habits. It's also beneficial for artists as buying music directly means your money goes directly to them. The server setup is quick and it runs on any operating system. It also has mobile apps for iOS & Android and allows you to stream your music in any browser. Other features include gapless playback, Milkdrop visualizer, playlist sharing, and drag and drop file uploading. All the code for mStream is open source.", "category": "media", "tags": ["Media", "Music Streaming"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/mstream:6.6.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://mstream.io"}, {"label": "Github", "url": "https://github.com/IrosTheBeggar/mStream"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "mstream", "port": "$PORT:3000", "volumes": ["/config", "/music"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('muse', 'Muse', 'Muse is a self-hosted Discord music bot designed to enhance your music experience on Discord. It''s perfect for small to medium-sized groups, such as you and your friends. With Muse, you can livestream music, seek within a song or video, and even cache music locally for better performance. It also allows users to convert playlists, artists, albums, and songs from Spotify automatically. You can add custom shortcuts, and the bot supports multiple guilds. It normalizes volume across tracks for a consistent listening experience. Muse is written in TypeScript and is easily extendable. It''s a loyal Packers fan and doesn''t vote to skip - this is anarchy, not a democracy!', 'music', ARRAY['Music', 'Discord', 'Bot'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "codetheweb/muse:2.11.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Muse", "version": "latest", "description": "Muse is a self-hosted Discord music bot designed to enhance your music experience on Discord. It's perfect for small to medium-sized groups, such as you and your friends. With Muse, you can livestream music, seek within a song or video, and even cache music locally for better performance. It also allows users to convert playlists, artists, albums, and songs from Spotify automatically. You can add custom shortcuts, and the bot supports multiple guilds. It normalizes volume across tracks for a consistent listening experience. Muse is written in TypeScript and is easily extendable. It's a loyal Packers fan and doesn't vote to skip - this is anarchy, not a democracy!", "category": "music", "tags": ["Music", "Discord", "Bot"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "codetheweb/muse:2.11.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/codetheweb/muse"}, {"label": "Documentation", "url": "https://github.com/codetheweb/muse#running"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "muse", "port": "$PORT:80", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('mysql-backup', 'MySQL Backup', 'The mysql-backup-s3 app is a powerful tool designed to backup your MySQL databases to your AWS S3 bucket. It supports periodic backups, allowing you to schedule backup times in cron format, ensuring your data is always safe and up-to-date. The app also supports multi-files, meaning you can have one file per database if you choose to. The app requires your AWS access key, AWS secret key, and AWS S3 bucket path. It also requires your MySQL host, user, and password. You can customize the path prefix in your bucket, the AWS S3 bucket region, and the AWS Endpoint URL. The app also allows you to add extra mysqldump options without overriding the default ones. With the mysql-backup-s3 app, you can ensure your MySQL databases are always backed up and secure in your AWS S3 bucket.', 'databases', ARRAY['Databases', 'Backup'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "easypanel/mysql-backup-s3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "MySQL Backup", "version": "latest", "description": "The mysql-backup-s3 app is a powerful tool designed to backup your MySQL databases to your AWS S3 bucket. It supports periodic backups, allowing you to schedule backup times in cron format, ensuring your data is always safe and up-to-date. The app also supports multi-files, meaning you can have one file per database if you choose to. The app requires your AWS access key, AWS secret key, and AWS S3 bucket path. It also requires your MySQL host, user, and password. You can customize the path prefix in your bucket, the AWS S3 bucket region, and the AWS Endpoint URL. The app also allows you to add extra mysqldump options without overriding the default ones. With the mysql-backup-s3 app, you can ensure your MySQL databases are always backed up and secure in your AWS S3 bucket.", "category": "databases", "tags": ["Databases", "Backup"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "easypanel/mysql-backup-s3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://github.com/schickling/dockerfiles/tree/master/mysql-backup-s3"}, {"label": "Github", "url": "https://github.com/schickling/dockerfiles/tree/master/mysql-backup-s3"}], "instructions": "In order to test that you configured it properly, remove the SCHEDULE variable from the environment, click deploy and check the logs. If everything works fine, you can add the SCHEDULE variable back. You can read more about the environment variables here: https://github.com/schickling/dockerfiles/tree/master/mysql-backup-s3", "install": [{"docker": {"image": "$IMAGE", "name": "mysql-backup", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "In order to test that you configured it properly, remove the SCHEDULE variable from the environment, click deploy and check the logs. If everything works fine, you can add the SCHEDULE variable back. You can read more about the environment variables here: https://github.com/schickling/dockerfiles/tree/master/mysql-backup-s3"}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('mysql-workbench', 'MySQL-Workbench', 'MySQL Workbench is a unified visual tool for database architects, developers, and DBAs. It provides data modeling, SQL development, and comprehensive database management capabilities for MySQL and MariaDB. With MySQL Workbench, you can design and create new databases, reverse-engineer existing databases, and perform complex migrations. It offers a visual query builder, a powerful SQL editor, and support for data modeling and schema creation. MySQL Workbench is a trusted, easy-to-use tool to streamline database operations and improve productivity.', 'database', ARRAY['Database', 'MySQL', 'Development', 'Administration'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/mysql-workbench:8.0.47"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "MySQL-Workbench", "version": "latest", "description": "MySQL Workbench is a unified visual tool for database architects, developers, and DBAs. It provides data modeling, SQL development, and comprehensive database management capabilities for MySQL and MariaDB. With MySQL Workbench, you can design and create new databases, reverse-engineer existing databases, and perform complex migrations. It offers a visual query builder, a powerful SQL editor, and support for data modeling and schema creation. MySQL Workbench is a trusted, easy-to-use tool to streamline database operations and improve productivity.", "category": "database", "tags": ["Database", "MySQL", "Development", "Administration"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/mysql-workbench:8.0.47"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.mysql.com/products/workbench/"}, {"label": "Documentation", "url": "https://dev.mysql.com/doc/workbench/en/"}, {"label": "Github", "url": "https://github.com/mysql/mysql-workbench"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "mysql-workbench", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('n8n', 'n8n', 'n8n is a powerful workflow automation tool designed for technical people. It allows you to build complex automations 10x faster, without the need to fight with APIs. The app enables you to create flexible workflows focused on deep data integration. You can use JavaScript for complex tasks that require flexibility and the user-friendly UI for everything else. n8n provides the ability to connect APIs with no code for automating basic tasks, or write vanilla Javascript for manipulating complex data. It supports integration with any app and allows for the creation of custom scenarios at speed. With n8n, you can pump data around your entire tech stack with 350+ native integrations or use custom code to create your own. It also offers features like bulk operations, painless debugging, and the ability to host on your own infrastructure. n8n is not just a helpful tool, it''s the heart of your business, helping you optimize engineering resources, boost efficiency, and focus on your KPIs, not your APIs.', 'automation', ARRAY['Automation', 'Workflow', 'Integration'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "docker.n8n.io/n8nio/n8n:2.21.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5678}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "n8n", "version": "latest", "description": "n8n is a powerful workflow automation tool designed for technical people. It allows you to build complex automations 10x faster, without the need to fight with APIs. The app enables you to create flexible workflows focused on deep data integration. You can use JavaScript for complex tasks that require flexibility and the user-friendly UI for everything else. n8n provides the ability to connect APIs with no code for automating basic tasks, or write vanilla Javascript for manipulating complex data. It supports integration with any app and allows for the creation of custom scenarios at speed. With n8n, you can pump data around your entire tech stack with 350+ native integrations or use custom code to create your own. It also offers features like bulk operations, painless debugging, and the ability to host on your own infrastructure. n8n is not just a helpful tool, it's the heart of your business, helping you optimize engineering resources, boost efficiency, and focus on your KPIs, not your APIs.", "category": "automation", "tags": ["Automation", "Workflow", "Integration"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "docker.n8n.io/n8nio/n8n:2.21.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5678}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://n8n.io/"}, {"label": "Documentation", "url": "https://docs.n8n.io/"}, {"label": "Github", "url": "https://github.com/n8n-io/n8n"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "n8n", "port": "$PORT:5678", "volumes": ["/home/node/.n8n"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('nametag', 'Nametag', 'Nametag is a simple, yet effective Personal Relationship Manager (PRM) - like a CRM, but for your actual relationships instead of sales prospects. Built with Next.js, it helps you manage your personal network by tracking contacts, mapping relationships between people, and visualizing your network with interactive graphs. Remember when you last talked to an old friend, their kids'' names, or their birthday. Organize contacts into custom groups, set reminders for important dates and staying in touch, and keep all your relationship data in one secure, self-hosted location.', 'personal-relationship-manager', ARRAY['Personal Relationship Manager', 'PRM', 'CRM', 'Contacts', 'Relationships', 'Next.js', 'Self-Hosted', 'Network Visualization', 'Reminders'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/mattogodoy/nametag:0.44.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Nametag", "version": "latest", "description": "Nametag is a simple, yet effective Personal Relationship Manager (PRM) - like a CRM, but for your actual relationships instead of sales prospects. Built with Next.js, it helps you manage your personal network by tracking contacts, mapping relationships between people, and visualizing your network with interactive graphs. Remember when you last talked to an old friend, their kids' names, or their birthday. Organize contacts into custom groups, set reminders for important dates and staying in touch, and keep all your relationship data in one secure, self-hosted location.", "category": "personal-relationship-manager", "tags": ["Personal Relationship Manager", "PRM", "CRM", "Contacts", "Relationships", "Next.js", "Self-Hosted", "Network Visualization", "Reminders"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/mattogodoy/nametag:0.44.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/mattogodoy/nametag"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "nametag", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('nango', 'Nango', 'Nango is a powerful app designed to simplify and accelerate the process of building integrations. It provides a unified API, allowing you to drastically simplify your integration code and avoid dealing with each external API''s schema and quirks. With Nango, you can authorize any integration using our drop-in UI, and securely manage your users'' credentials. The app also enables continuous data synchronization with external APIs, using one of 100+ pre-built integrations, or you can customize them or build your own. Nango also supports 2-way syncs, write-backs, and real-time webhooks. It''s designed for engineering teams that want full control without the hassle, allowing you to build exactly the integration your customers need, in code. With Nango, you can leave the maintenance, scaling, and API specific quirks to us, and focus on what you do best.', 'developer-tools', ARRAY['Developer Tools', 'Integration', 'API'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "nango.docker.scarf.sh/nangohq/nango-server:0.36.78"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3003}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Nango", "version": "latest", "description": "Nango is a powerful app designed to simplify and accelerate the process of building integrations. It provides a unified API, allowing you to drastically simplify your integration code and avoid dealing with each external API's schema and quirks. With Nango, you can authorize any integration using our drop-in UI, and securely manage your users' credentials. The app also enables continuous data synchronization with external APIs, using one of 100+ pre-built integrations, or you can customize them or build your own. Nango also supports 2-way syncs, write-backs, and real-time webhooks. It's designed for engineering teams that want full control without the hassle, allowing you to build exactly the integration your customers need, in code. With Nango, you can leave the maintenance, scaling, and API specific quirks to us, and focus on what you do best.", "category": "developer-tools", "tags": ["Developer Tools", "Integration", "API"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "nango.docker.scarf.sh/nangohq/nango-server:0.36.78"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3003}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://nango.dev"}, {"label": "Documentation", "url": "https://docs.nango.dev"}, {"label": "Github", "url": "https://github.com/NangoHQ/nango"}], "instructions": "Check the environment tab for your API key. Follow the instructions in the FILE mount.", "install": [{"docker": {"image": "$IMAGE", "name": "nango", "port": "$PORT:3003", "volumes": ["/usr/nango-server/src/packages/server/providers.yaml"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Check the environment tab for your API key. Follow the instructions in the FILE mount."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('nanote', 'Nanote', 'Nanote is a lightweight, self-hosted note-taking application that provides a simple and clean interface for managing your notes. Built with privacy-focused design, Nanote allows you to store and organize your notes locally or on your own server. It features markdown support, file uploads, and a minimalistic interface that focuses on productivity without distractions.', 'notes', ARRAY['Notes', 'Markdown', 'Self-Hosted', 'Productivity', 'Documentation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "omarmir/nanote:0.11.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Nanote", "version": "latest", "description": "Nanote is a lightweight, self-hosted note-taking application that provides a simple and clean interface for managing your notes. Built with privacy-focused design, Nanote allows you to store and organize your notes locally or on your own server. It features markdown support, file uploads, and a minimalistic interface that focuses on productivity without distractions.", "category": "notes", "tags": ["Notes", "Markdown", "Self-Hosted", "Productivity", "Documentation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "omarmir/nanote:0.11.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/omarmir/nanote"}, {"label": "Website", "url": "https://nanote.link"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "nanote", "port": "$PORT:3000", "volumes": ["/nanote"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('nats', 'NATS', 'NATS is a simple, secure and performant messaging system for cloud native applications, IoT messaging, and microservices architectures. It provides lightweight publish-subscribe, request-reply, and point-to-point messaging patterns with high performance and minimal footprint.', 'messaging', ARRAY['Messaging', 'Message Broker', 'Pub-Sub', 'Microservices', 'Cloud Native'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "nats:2.14.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4222}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "NATS", "version": "latest", "description": "NATS is a simple, secure and performant messaging system for cloud native applications, IoT messaging, and microservices architectures. It provides lightweight publish-subscribe, request-reply, and point-to-point messaging patterns with high performance and minimal footprint.", "category": "messaging", "tags": ["Messaging", "Message Broker", "Pub-Sub", "Microservices", "Cloud Native"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "nats:2.14.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4222}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://docs.nats.io/"}, {"label": "Github", "url": "https://github.com/nats-io/nats-server"}, {"label": "Website", "url": "https://nats.io"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "nats", "port": "$PORT:4222", "volumes": [], "extra_ports": ["6222:6222", "8222:8222"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('navidrome', 'Navidrome', 'Welcome to Navidrome, your personal streaming service! This open-source software allows you to access and enjoy your music collection from anywhere, through a modern web UI and a wide range of third-party compatible mobile apps for both iOS and Android devices. Navidrome is lightweight, fast, and self-contained, capable of running well even on resource-limited platforms. It can handle large music libraries, and even transcodes your music files on the fly to prevent excessive data usage. Built with new technologies like GoLang, ReactJS, and Material-UI, Navidrome ensures modern features and compatibility. It is also compatible with the de facto standard Music API, supporting all its clients and ecosystem. With new releases on a regular basis, Navidrome continually adds features and bug fixes to enhance your music streaming experience.', 'media', ARRAY['Media', 'Music', 'Streaming'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "deluan/navidrome:pr-5351"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4533}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Navidrome", "version": "latest", "description": "Welcome to Navidrome, your personal streaming service! This open-source software allows you to access and enjoy your music collection from anywhere, through a modern web UI and a wide range of third-party compatible mobile apps for both iOS and Android devices. Navidrome is lightweight, fast, and self-contained, capable of running well even on resource-limited platforms. It can handle large music libraries, and even transcodes your music files on the fly to prevent excessive data usage. Built with new technologies like GoLang, ReactJS, and Material-UI, Navidrome ensures modern features and compatibility. It is also compatible with the de facto standard Music API, supporting all its clients and ecosystem. With new releases on a regular basis, Navidrome continually adds features and bug fixes to enhance your music streaming experience.", "category": "media", "tags": ["Media", "Music", "Streaming"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "deluan/navidrome:pr-5351"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4533}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.navidrome.org/"}, {"label": "Documentation", "url": "https://www.navidrome.org/docs/"}, {"label": "Github", "url": "https://github.com/navidrome/navidrome"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "navidrome", "port": "$PORT:4533", "volumes": ["/data", "/music"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('neko-rooms', 'Neko Rooms', 'Neko Rooms is a self-hosted, collaborative virtualized browser-sharing platform that enables users to share and interact with web applications in a fully isolated and secure environment. It allows multiple users to join a shared session, providing seamless co-browsing experiences with synchronized interactions. Neko Rooms is built for teams, support agents, and anyone needing real-time, interactive browsing collaboration. It is optimized for low-latency streaming and supports multiple configurations for enhanced flexibility and performance.', 'remote-collaboration', ARRAY['Remote Collaboration', 'Virtualized Browser', 'Self-Hosted', 'Secure Browsing'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "m1k1o/neko-rooms:1.6.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Neko Rooms", "version": "latest", "description": "Neko Rooms is a self-hosted, collaborative virtualized browser-sharing platform that enables users to share and interact with web applications in a fully isolated and secure environment. It allows multiple users to join a shared session, providing seamless co-browsing experiences with synchronized interactions. Neko Rooms is built for teams, support agents, and anyone needing real-time, interactive browsing collaboration. It is optimized for low-latency streaming and supports multiple configurations for enhanced flexibility and performance.", "category": "remote-collaboration", "tags": ["Remote Collaboration", "Virtualized Browser", "Self-Hosted", "Secure Browsing"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "m1k1o/neko-rooms:1.6.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/m1k1o/neko-rooms"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "neko-rooms", "port": "$PORT:8080", "volumes": ["/var/run/docker.sock"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('neo4j', 'Neo4j', 'Neo4j is a native graph database that brings data relationships to the foreground. It''s designed to store, manage, and analyze connected data efficiently. Neo4j is particularly well-suited for applications that need to model complex relationships between entities, such as social networks, recommendation engines, fraud detection, and knowledge graphs.', 'database', ARRAY['Database', 'Graph Database', 'NoSQL', 'Analytics', 'Knowledge Graph'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "neo4j:5.26.19"}, "port": {"type": "integer", "title": "Port HTTP", "default": 7474}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Neo4j", "version": "latest", "description": "Neo4j is a native graph database that brings data relationships to the foreground. It's designed to store, manage, and analyze connected data efficiently. Neo4j is particularly well-suited for applications that need to model complex relationships between entities, such as social networks, recommendation engines, fraud detection, and knowledge graphs.", "category": "database", "tags": ["Database", "Graph Database", "NoSQL", "Analytics", "Knowledge Graph"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "neo4j:5.26.19"}, "port": {"type": "integer", "title": "Port HTTP", "default": 7474}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://neo4j.com/"}, {"label": "Documentation", "url": "https://neo4j.com/docs/"}, {"label": "Docker Hub", "url": "https://hub.docker.com/_/neo4j"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "neo4j", "port": "$PORT:7474", "volumes": ["/logs", "/config", "/data", "/plugins"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('netalertx', 'NetAlertX', 'NetAlertX is a network monitoring and notification framework that scans your Wi-Fi/LAN network and alerts you when new or unknown devices are detected. It provides real-time network device discovery, ARP scanning, and customizable alert notifications. Built for network administrators and security-conscious users, NetAlertX helps you maintain visibility over your network by tracking connected devices and identifying unauthorized access. The application features a web-based dashboard, GraphQL API, and supports various notification methods to keep you informed about network changes.', 'network-monitoring', ARRAY['Network Monitoring', 'Security', 'Device Discovery', 'ARP Scanning', 'Self-Hosted', 'Network Management', 'Alerts'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/jokob-sk/netalertx:26.5.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 20211}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "NetAlertX", "version": "latest", "description": "NetAlertX is a network monitoring and notification framework that scans your Wi-Fi/LAN network and alerts you when new or unknown devices are detected. It provides real-time network device discovery, ARP scanning, and customizable alert notifications. Built for network administrators and security-conscious users, NetAlertX helps you maintain visibility over your network by tracking connected devices and identifying unauthorized access. The application features a web-based dashboard, GraphQL API, and supports various notification methods to keep you informed about network changes.", "category": "network-monitoring", "tags": ["Network Monitoring", "Security", "Device Discovery", "ARP Scanning", "Self-Hosted", "Network Management", "Alerts"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/jokob-sk/netalertx:26.5.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 20211}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://netalertx.com"}, {"label": "GitHub", "url": "https://github.com/jokob-sk/NetAlertX"}, {"label": "Documentation", "url": "https://docs.netalertx.com"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "netalertx", "port": "$PORT:20211", "volumes": ["/data", "/etc/localtime"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('netbird', 'NetBird', 'This template deploys a headless NetBird client/peer container that joins an existing NetBird network using a setup key. It does not deploy the NetBird management service, signal relay, or web dashboard. Use it to bootstrap a node on your private mesh for remote access, site-to-site connectivity, or secure service reachability over WireGuard.', 'vpn', ARRAY['VPN', 'WireGuard', 'Mesh Network', 'Networking', 'Security', 'Remote Access', 'Peer-to-Peer'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "netbirdio/netbird:0.59.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "NetBird", "version": "latest", "description": "This template deploys a headless NetBird client/peer container that joins an existing NetBird network using a setup key. It does not deploy the NetBird management service, signal relay, or web dashboard. Use it to bootstrap a node on your private mesh for remote access, site-to-site connectivity, or secure service reachability over WireGuard.", "category": "vpn", "tags": ["VPN", "WireGuard", "Mesh Network", "Networking", "Security", "Remote Access", "Peer-to-Peer"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "netbirdio/netbird:0.59.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://netbird.io"}, {"label": "Documentation", "url": "https://docs.netbird.io"}, {"label": "GitHub", "url": "https://github.com/netbirdio/netbird"}], "instructions": "This template runs only the NetBird client (peer). Before deploying, create an account at https://netbird.io or run your own NetBird management stack, then generate a reusable setup key. Enter that key in the NB_SETUP_KEY field during deployment. The container will join your existing NetBird network and persist client state in /var/lib/netbird.", "install": [{"docker": {"image": "$IMAGE", "name": "netbird", "port": "$PORT:80", "volumes": ["/var/lib/netbird"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "This template runs only the NetBird client (peer). Before deploying, create an account at https://netbird.io or run your own NetBird management stack, then generate a reusable setup key. Enter that key in the NB_SETUP_KEY field during deployment. The container will join your existing NetBird network and persist client state in /var/lib/netbird."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('netbox', 'Netbox', 'NetBox is a comprehensive solution designed to be the single source of truth for everything on your network. It provides a detailed overview of both physical and virtual assets, including power systems, cabling, IP addresses, and VLANs. The app is designed to facilitate network automation and monitoring, drawing from an authoritative plan to push out configurations and monitor changes across the enterprise. It offers a complete DCIM solution, providing visibility and control across the entire enterprise. NetBox also features efficient IP Address Management, ensuring the safe and efficient management of IP assets across the enterprise, thereby minimizing the risk of data entry errors. The app is customizable and can be integrated to extend its functionality to fit your specific needs.', 'network-tools', ARRAY['Network Tools', 'Documentation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/netbox:4.5.9"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Netbox", "version": "latest", "description": "NetBox is a comprehensive solution designed to be the single source of truth for everything on your network. It provides a detailed overview of both physical and virtual assets, including power systems, cabling, IP addresses, and VLANs. The app is designed to facilitate network automation and monitoring, drawing from an authoritative plan to push out configurations and monitor changes across the enterprise. It offers a complete DCIM solution, providing visibility and control across the entire enterprise. NetBox also features efficient IP Address Management, ensuring the safe and efficient management of IP assets across the enterprise, thereby minimizing the risk of data entry errors. The app is customizable and can be integrated to extend its functionality to fit your specific needs.", "category": "network-tools", "tags": ["Network Tools", "Documentation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/netbox:4.5.9"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://netbox.dev"}, {"label": "Documentation", "url": "https://docs.netbox.dev/"}, {"label": "Github", "url": "https://github.com/netbox-community/netbox"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "netbox", "port": "$PORT:8000", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('nextcloud', 'Nextcloud', 'Nextcloud Hub 5 is a comprehensive platform that integrates the four key Nextcloud products: Files, Talk, Groupware, and Office. It is designed to optimize the flow of collaboration, providing a seamless experience for users. Nextcloud Files offers an on-premise Universal File Access and sync platform with powerful collaboration capabilities and interfaces for desktop, mobile, and web. The platform ensures no data leaks to third parties, providing you with full control over your data. It is customizable, scalable, and can be deployed on-premises or in the cloud. Nextcloud is committed to providing technology that fits perfectly with your organization, whether it''s a government entity, enterprise, service provider, or educational institution. It is the most popular self-hosted collaboration solution, used by tens of millions of users at thousands of organizations across the globe.', 'file-management', ARRAY['File Management', 'Collaboration', 'Data Control'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "nextcloud:33.0.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Nextcloud", "version": "latest", "description": "Nextcloud Hub 5 is a comprehensive platform that integrates the four key Nextcloud products: Files, Talk, Groupware, and Office. It is designed to optimize the flow of collaboration, providing a seamless experience for users. Nextcloud Files offers an on-premise Universal File Access and sync platform with powerful collaboration capabilities and interfaces for desktop, mobile, and web. The platform ensures no data leaks to third parties, providing you with full control over your data. It is customizable, scalable, and can be deployed on-premises or in the cloud. Nextcloud is committed to providing technology that fits perfectly with your organization, whether it's a government entity, enterprise, service provider, or educational institution. It is the most popular self-hosted collaboration solution, used by tens of millions of users at thousands of organizations across the globe.", "category": "file-management", "tags": ["File Management", "Collaboration", "Data Control"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "nextcloud:33.0.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://nextcloud.com/"}, {"label": "Documentation", "url": "https://docs.nextcloud.com/"}, {"label": "Github", "url": "https://github.com/nextcloud"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "nextcloud", "port": "$PORT:80", "volumes": ["/var/www/html"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('nexterm', 'Nexterm', 'Nexterm is a powerful web-based terminal emulator that provides secure and convenient terminal access through your web browser. It offers a modern interface for remote terminal operations, making it ideal for developers and system administrators who need reliable terminal access from anywhere.', 'terminal', ARRAY['Terminal', 'Development', 'Web-Based'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "germannewsmaker/nexterm:1.0.9-OPEN-PREVIEW"}, "port": {"type": "integer", "title": "Port HTTP", "default": 6989}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Nexterm", "version": "latest", "description": "Nexterm is a powerful web-based terminal emulator that provides secure and convenient terminal access through your web browser. It offers a modern interface for remote terminal operations, making it ideal for developers and system administrators who need reliable terminal access from anywhere.", "category": "terminal", "tags": ["Terminal", "Development", "Web-Based"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "germannewsmaker/nexterm:1.0.9-OPEN-PREVIEW"}, "port": {"type": "integer", "title": "Port HTTP", "default": 6989}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/gnmyt/Nexterm"}, {"label": "Website", "url": "https://nexterm.dev"}, {"label": "Documentation", "url": "https://docs.nexterm.dev"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "nexterm", "port": "$PORT:6989", "volumes": ["/app/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('ngrok', 'ngrok', 'ngrok is a secure tunneling service that creates secure tunnels from a public endpoint to a locally running web service. It''s perfect for exposing local development servers, testing webhooks, and sharing your work with others. This template provides easy deployment of ngrok with configurable authentication, regions, and target services.', 'tunneling', ARRAY['Tunneling', 'Development', 'Webhooks', 'Testing', 'Networking'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ngrok/ngrok:3.39.1-alpine"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4040}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "ngrok", "version": "latest", "description": "ngrok is a secure tunneling service that creates secure tunnels from a public endpoint to a locally running web service. It's perfect for exposing local development servers, testing webhooks, and sharing your work with others. This template provides easy deployment of ngrok with configurable authentication, regions, and target services.", "category": "tunneling", "tags": ["Tunneling", "Development", "Webhooks", "Testing", "Networking"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ngrok/ngrok:3.39.1-alpine"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4040}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://ngrok.com"}, {"label": "Documentation", "url": "https://ngrok.com/docs"}, {"label": "GitHub", "url": "https://github.com/ngrok/ngrok"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "ngrok", "port": "$PORT:4040", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('nitropage', 'Nitropage', 'Nitropage is an extensible, drag-and-drop website builder based on SolidStart, designed for individualists who want complete control over their web design. It is completely free and open source, offering a flexible and intuitive platform for building visually stunning websites without coding. Nitropage supports modular extensions, making it ideal for both beginners and advanced users who seek a personalized and efficient web development experience.', 'website-builder', ARRAY['Website Builder', 'Drag-and-Drop', 'Open Source', 'Visual Editor', 'SolidStart'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "codeberg.org/nitropage/nitropage:0.70.1-sqlite"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Nitropage", "version": "latest", "description": "Nitropage is an extensible, drag-and-drop website builder based on SolidStart, designed for individualists who want complete control over their web design. It is completely free and open source, offering a flexible and intuitive platform for building visually stunning websites without coding. Nitropage supports modular extensions, making it ideal for both beginners and advanced users who seek a personalized and efficient web development experience.", "category": "website-builder", "tags": ["Website Builder", "Drag-and-Drop", "Open Source", "Visual Editor", "SolidStart"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "codeberg.org/nitropage/nitropage:0.70.1-sqlite"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://nitropage.com/"}, {"label": "Documentation", "url": "https://nitropage.com/docs"}, {"label": "Github", "url": "https://codeberg.org/nitropage/nitropage"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "nitropage", "port": "$PORT:80", "volumes": ["/app/.data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('nocobase', 'Nocobase', 'NocoBase is an open-source, no-code development platform designed with scalability in mind. It allows you to build your own collaboration platform or management system without any programming required. With NocoBase, you can create independent data models using a variety of field types and association relationships. The platform also provides a free combination of block types for displaying and manipulating data within a page. It supports various operations to process data, including filtering, exporting, adding, deleting, modifying, and viewing. NocoBase also features role-based control of user''s system configuration rights, data action rights, and menu access rights. It replaces repetitive tasks with automation to increase efficiency and requires manual approval for important matters. NocoBase is built for extended development with a microkernel architecture that is flexible and easy to extend. It is Node.js-based and uses popular frameworks and technologies.', 'no-code', ARRAY['No-Code', 'Business Apps', 'Data Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "nocobase/nocobase:2.0.48"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Nocobase", "version": "latest", "description": "NocoBase is an open-source, no-code development platform designed with scalability in mind. It allows you to build your own collaboration platform or management system without any programming required. With NocoBase, you can create independent data models using a variety of field types and association relationships. The platform also provides a free combination of block types for displaying and manipulating data within a page. It supports various operations to process data, including filtering, exporting, adding, deleting, modifying, and viewing. NocoBase also features role-based control of user's system configuration rights, data action rights, and menu access rights. It replaces repetitive tasks with automation to increase efficiency and requires manual approval for important matters. NocoBase is built for extended development with a microkernel architecture that is flexible and easy to extend. It is Node.js-based and uses popular frameworks and technologies.", "category": "no-code", "tags": ["No-Code", "Business Apps", "Data Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "nocobase/nocobase:2.0.48"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.nocobase.com/"}, {"label": "Documentation", "url": "https://docs.nocobase.com"}, {"label": "Github", "url": "https://github.com/nocobase/nocobase"}], "instructions": "The initial account and password are admin@nocobase.com and admin123.", "install": [{"docker": {"image": "$IMAGE", "name": "nocobase", "port": "$PORT:80", "volumes": ["/app/nocobase/storage"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "The initial account and password are admin@nocobase.com and admin123."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('nocodb', 'NocoDB', 'NocoDB is an innovative open-source platform that transforms any database into a smart spreadsheet. It''s a powerful alternative to Airtable, designed to be flexible and user-friendly. With NocoDB, you can create unlimited grid views, gallery views, and form views from your own data. It offers ultra-ease in searching, sorting, and filtering columns and rows. You can invite your team with fine-grained access control, share views publicly or with password protection. NocoDB also allows you to build automations with your favourite apps like Microsoft Teams, Slack, Discord, Whatsapp, Twilio, Email & SMS. It provides instant REST APIs with Swagger. NocoDB is trusted by over 2000 organizations worldwide and is the fastest growing open source project. It''s free and self-hostable, offering endless solutions for your business workflows.', 'no-code', ARRAY['No-Code', 'Databases'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "nocodb/nocodb:2026.05.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "NocoDB", "version": "latest", "description": "NocoDB is an innovative open-source platform that transforms any database into a smart spreadsheet. It's a powerful alternative to Airtable, designed to be flexible and user-friendly. With NocoDB, you can create unlimited grid views, gallery views, and form views from your own data. It offers ultra-ease in searching, sorting, and filtering columns and rows. You can invite your team with fine-grained access control, share views publicly or with password protection. NocoDB also allows you to build automations with your favourite apps like Microsoft Teams, Slack, Discord, Whatsapp, Twilio, Email & SMS. It provides instant REST APIs with Swagger. NocoDB is trusted by over 2000 organizations worldwide and is the fastest growing open source project. It's free and self-hostable, offering endless solutions for your business workflows.", "category": "no-code", "tags": ["No-Code", "Databases"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "nocodb/nocodb:2026.05.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.nocodb.com/"}, {"label": "Documentation", "url": "https://docs.nocodb.com/getting-started/installation/"}, {"label": "Github", "url": "https://github.com/nocodb/nocodb"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "nocodb", "port": "$PORT:8080", "volumes": ["/usr/app/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('nodebb', 'NodeBB', 'NodeBB is a next-generation forum software that is powerful, mobile-ready, and easy to use. It is designed to provide a modern platform for your audience, fostering engagement and retaining customers. With NodeBB, you can enjoy a perfect experience on every device and screen, thanks to its mobile-first software. It offers built-in localization support with over 50 languages actively translated, making it a truly global platform. NodeBB is also search optimized with human-readable URLs, semantic HTML with embedded microdata, and more. It allows for social media integration, bringing more visitors to your community by sharing content to Facebook, Google, and Twitter. NodeBB also offers real-time interaction with instant notifications, streaming posts, and real-time chats. It comes with a native analytics dashboard so you can know what content your users enjoy most. Whether you''re a self-starter, a growing business, or a large corporation, NodeBB has a plan that works best for you.', 'forums', ARRAY['Forums', 'Communication', 'Mobile-first', 'Real-time', 'Analytics'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "nodebb/docker:2.8.11"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4567}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "NodeBB", "version": "latest", "description": "NodeBB is a next-generation forum software that is powerful, mobile-ready, and easy to use. It is designed to provide a modern platform for your audience, fostering engagement and retaining customers. With NodeBB, you can enjoy a perfect experience on every device and screen, thanks to its mobile-first software. It offers built-in localization support with over 50 languages actively translated, making it a truly global platform. NodeBB is also search optimized with human-readable URLs, semantic HTML with embedded microdata, and more. It allows for social media integration, bringing more visitors to your community by sharing content to Facebook, Google, and Twitter. NodeBB also offers real-time interaction with instant notifications, streaming posts, and real-time chats. It comes with a native analytics dashboard so you can know what content your users enjoy most. Whether you're a self-starter, a growing business, or a large corporation, NodeBB has a plan that works best for you.", "category": "forums", "tags": ["Forums", "Communication", "Mobile-first", "Real-time", "Analytics"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "nodebb/docker:2.8.11"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4567}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://nodebb.org/"}, {"label": "Documentation", "url": "https://docs.nodebb.org/"}, {"label": "Github", "url": "https://github.com/NodeBB/NodeBB"}, {"label": "Demo", "url": "https://try.nodebb.org/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "nodebb", "port": "$PORT:4567", "volumes": ["/usr/src/app"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('nodecast-tv', 'NodeCast TV', 'NodeCast TV is a self-hosted media casting and streaming application that allows you to cast and stream media content to various devices. Built with Node.js, NodeCast TV provides a simple and efficient way to manage and stream your media library. It features a web-based interface accessible on port 3000 and stores application data in a persistent volume for reliable operation. Perfect for home media servers and self-hosting enthusiasts looking for a lightweight media casting solution.', 'media', ARRAY['Media', 'Streaming', 'Casting', 'Self-Hosted', 'Node.js', 'Media Server'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/technomancer702/nodecast-tv:2.1.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "NodeCast TV", "version": "latest", "description": "NodeCast TV is a self-hosted media casting and streaming application that allows you to cast and stream media content to various devices. Built with Node.js, NodeCast TV provides a simple and efficient way to manage and stream your media library. It features a web-based interface accessible on port 3000 and stores application data in a persistent volume for reliable operation. Perfect for home media servers and self-hosting enthusiasts looking for a lightweight media casting solution.", "category": "media", "tags": ["Media", "Streaming", "Casting", "Self-Hosted", "Node.js", "Media Server"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/technomancer702/nodecast-tv:2.1.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/technomancer702/nodecast-tv"}, {"label": "Container", "url": "https://github.com/technomancer702/nodecast-tv/pkgs/container/nodecast-tv"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "nodecast-tv", "port": "$PORT:3000", "volumes": ["/app/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('nodered', 'Node-RED', 'Node-RED is a unique programming tool designed for creating event-driven applications in a low-code environment. It allows you to connect hardware devices, APIs, and online services in innovative ways. The app features a browser-based editor that simplifies the process of creating flows using a wide array of nodes available in the palette. These flows can be deployed to its runtime with just a single click. Node-RED also allows you to create JavaScript functions within the editor using a rich text editor and save useful functions, templates, or flows for future use. Built on Node.js, Node-RED is lightweight and can run on low-cost hardware like Raspberry Pi or in the cloud. It also supports the import and export of flows in JSON format for easy sharing.', 'developer-tools', ARRAY['Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "nodered/node-red:4.1.8-22"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8800}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Node-RED", "version": "latest", "description": "Node-RED is a unique programming tool designed for creating event-driven applications in a low-code environment. It allows you to connect hardware devices, APIs, and online services in innovative ways. The app features a browser-based editor that simplifies the process of creating flows using a wide array of nodes available in the palette. These flows can be deployed to its runtime with just a single click. Node-RED also allows you to create JavaScript functions within the editor using a rich text editor and save useful functions, templates, or flows for future use. Built on Node.js, Node-RED is lightweight and can run on low-cost hardware like Raspberry Pi or in the cloud. It also supports the import and export of flows in JSON format for easy sharing.", "category": "developer-tools", "tags": ["Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "nodered/node-red:4.1.8-22"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8800}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://nodered.org/"}, {"label": "Documentation", "url": "https://nodered.org/docs/"}, {"label": "Forum", "url": "https://discourse.nodered.org/"}, {"label": "Github", "url": "https://github.com/node-red"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "nodered", "port": "$PORT:8800", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('novu', 'Novu', 'Novu is an open-source notification infrastructure platform that provides a unified API for managing notifications across multiple channels including email, SMS, push notifications, in-app notifications, and chat. This template deploys a complete Novu infrastructure with separate services for API, Worker, WebSocket, and Dashboard components, backed by MongoDB and Redis. Built for developers who need reliable, scalable notification delivery with features like workflow automation, template management, subscriber management, and real-time analytics. Perfect for applications that require sophisticated notification systems with multi-channel delivery, personalization, and comprehensive tracking capabilities.', 'notifications', ARRAY['Notifications', 'Multi-Channel', 'Email', 'SMS', 'Push Notifications', 'In-App Messaging', 'Workflow Automation', 'API', 'Open Source', 'Developer Tools', 'Analytics', 'Templates'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/novuhq/novu/dashboard:3.15.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Novu", "version": "latest", "description": "Novu is an open-source notification infrastructure platform that provides a unified API for managing notifications across multiple channels including email, SMS, push notifications, in-app notifications, and chat. This template deploys a complete Novu infrastructure with separate services for API, Worker, WebSocket, and Dashboard components, backed by MongoDB and Redis. Built for developers who need reliable, scalable notification delivery with features like workflow automation, template management, subscriber management, and real-time analytics. Perfect for applications that require sophisticated notification systems with multi-channel delivery, personalization, and comprehensive tracking capabilities.", "category": "notifications", "tags": ["Notifications", "Multi-Channel", "Email", "SMS", "Push Notifications", "In-App Messaging", "Workflow Automation", "API", "Open Source", "Developer Tools", "Analytics", "Templates"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/novuhq/novu/dashboard:3.15.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/novuhq/novu"}, {"label": "Website", "url": "https://novu.co"}, {"label": "Documentation", "url": "https://docs.novu.co"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "novu", "port": "$PORT:3000", "volumes": [], "extra_ports": ["3002:3002", "4000:4000"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('ntfy', 'Ntfy', 'ntfy, pronounced as ''notify'', is a simple, HTTP-based pub-sub notification service that allows you to send push notifications to your phone or desktop from any computer. It operates via scripts using simple HTTP PUT or POST requests. This makes it a handy tool for notifying yourself when scripts fail or when long-running commands complete. To use ntfy, you simply need to install the app on your phone, subscribe to a topic of your choice, and start sending messages to your topic. The app is available on Google Play, F-Droid, and the App Store. ntfy is open-source and free to use, but also offers paid plans for those who wish to support its development.', 'notifications', ARRAY['Notifications', 'Push Notifications', 'Mobile Notifications', 'Desktop Notifications'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "binwiederhier/ntfy:v2.22"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Ntfy", "version": "latest", "description": "ntfy, pronounced as 'notify', is a simple, HTTP-based pub-sub notification service that allows you to send push notifications to your phone or desktop from any computer. It operates via scripts using simple HTTP PUT or POST requests. This makes it a handy tool for notifying yourself when scripts fail or when long-running commands complete. To use ntfy, you simply need to install the app on your phone, subscribe to a topic of your choice, and start sending messages to your topic. The app is available on Google Play, F-Droid, and the App Store. ntfy is open-source and free to use, but also offers paid plans for those who wish to support its development.", "category": "notifications", "tags": ["Notifications", "Push Notifications", "Mobile Notifications", "Desktop Notifications"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "binwiederhier/ntfy:v2.22"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://docs.ntfy.sh"}, {"label": "Github", "url": "https://github.com/binwiederhier/ntfy"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "ntfy", "port": "$PORT:80", "volumes": ["/var/cache/ntfy", "/etc/ntfy"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('nzbget', 'Nzbget', 'NZBGet is an efficient Usenet downloader that is open source and hosted on GitHub. This powerful tool is designed to download files from Usenet based on information provided in nzb-files. Known for its performance and efficiency, NZBGet is written in C++ and can run on almost any device, including classic PCs, NAS, media players, SAT-receivers, WLAN-routers, and more. It provides precompiled binaries for Windows, macOS, Linux, FreeBSD, and Android. The app also offers features like RSS and duplicate check for automating your downloads, VideoSort for sorting downloaded video files, and various scripts for enhancing functionality. With NZBGet, you can maximize your device''s performance and improve your downloading experience.', 'download', ARRAY['Download', 'Usenet', 'Downloader'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/nzbget:version-v25.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 6789}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Nzbget", "version": "latest", "description": "NZBGet is an efficient Usenet downloader that is open source and hosted on GitHub. This powerful tool is designed to download files from Usenet based on information provided in nzb-files. Known for its performance and efficiency, NZBGet is written in C++ and can run on almost any device, including classic PCs, NAS, media players, SAT-receivers, WLAN-routers, and more. It provides precompiled binaries for Windows, macOS, Linux, FreeBSD, and Android. The app also offers features like RSS and duplicate check for automating your downloads, VideoSort for sorting downloaded video files, and various scripts for enhancing functionality. With NZBGet, you can maximize your device's performance and improve your downloading experience.", "category": "download", "tags": ["Download", "Usenet", "Downloader"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/nzbget:version-v25.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 6789}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://nzbget.net/"}, {"label": "Documentation", "url": "https://nzbget.net/documentation"}, {"label": "Github", "url": "https://github.com/nzbget/nzbget"}], "instructions": "Default username=nzbget, password=tegbzn6789", "install": [{"docker": {"image": "$IMAGE", "name": "nzbget", "port": "$PORT:6789", "volumes": ["/config", "/downloads"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Default username=nzbget, password=tegbzn6789"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('nzbhydra2', 'Nzbhydra2', 'NZBHydra2 is an advanced meta search application designed to unify and manage searches across multiple Usenet and torrent indexers. It acts as a single access point for all your NZB and torrent needs, aggregating search results from various indexers to save time and improve efficiency. NZBHydra2 offers powerful filtering, duplicate management, and easy integration with automation tools like Sonarr, Radarr, and Lidarr. It provides a web-based interface for seamless configuration and search management, making it a must-have for Usenet and torrent enthusiasts.', 'nzb', ARRAY['NZB', 'Usenet', 'Torrents', 'Meta Search', 'Automation', 'Media Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/nzbhydra2:8.8.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5076}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Nzbhydra2", "version": "latest", "description": "NZBHydra2 is an advanced meta search application designed to unify and manage searches across multiple Usenet and torrent indexers. It acts as a single access point for all your NZB and torrent needs, aggregating search results from various indexers to save time and improve efficiency. NZBHydra2 offers powerful filtering, duplicate management, and easy integration with automation tools like Sonarr, Radarr, and Lidarr. It provides a web-based interface for seamless configuration and search management, making it a must-have for Usenet and torrent enthusiasts.", "category": "nzb", "tags": ["NZB", "Usenet", "Torrents", "Meta Search", "Automation", "Media Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/nzbhydra2:8.8.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5076}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://github.com/theotherp/nzbhydra2"}, {"label": "Documentation", "url": "https://github.com/theotherp/nzbhydra2/wiki"}, {"label": "Github", "url": "https://github.com/theotherp/nzbhydra2"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "nzbhydra2", "port": "$PORT:5076", "volumes": ["/config", "/downloads"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('obsidian', 'Obsidian', 'Obsidian is a powerful knowledge base that works on top of a local folder of plain text Markdown files. It provides a flexible and extensible platform for note-taking, knowledge management, and personal knowledge base creation.', 'note-taking', ARRAY['Note Taking', 'Knowledge Base', 'Markdown', 'Self-Hosted', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/obsidian:1.12.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Obsidian", "version": "latest", "description": "Obsidian is a powerful knowledge base that works on top of a local folder of plain text Markdown files. It provides a flexible and extensible platform for note-taking, knowledge management, and personal knowledge base creation.", "category": "note-taking", "tags": ["Note Taking", "Knowledge Base", "Markdown", "Self-Hosted", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/obsidian:1.12.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://obsidian.md"}, {"label": "Documentation", "url": "https://help.obsidian.md"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "obsidian", "port": "$PORT:3000", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('octobox', 'Octobox', 'Octobox is an innovative app designed to help you manage your GitHub notifications more efficiently. With Octobox, you no longer have to worry about losing track of important issues or waking up to hundreds of notifications. The app adds an extra ''archived'' state to each notification, allowing you to mark it as ''done''. If there''s any activity on an archived thread, issue or PR, Octobox will move it back into your inbox. You can also search and filter notifications by repository, organization, type, action, state, CI status, and reason. Octobox keeps your notifications up to date with issue/pull-request status, CI status, labels, and more. The app is free for open source projects and offers enhanced notifications for private projects at a cost. Octobox is the perfect tool for developers who want to stay organized and focused.', 'developer-tools', ARRAY['Developer Tools', 'Code Hosting'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "octoboxio/octobox:december-2025"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Octobox", "version": "latest", "description": "Octobox is an innovative app designed to help you manage your GitHub notifications more efficiently. With Octobox, you no longer have to worry about losing track of important issues or waking up to hundreds of notifications. The app adds an extra 'archived' state to each notification, allowing you to mark it as 'done'. If there's any activity on an archived thread, issue or PR, Octobox will move it back into your inbox. You can also search and filter notifications by repository, organization, type, action, state, CI status, and reason. Octobox keeps your notifications up to date with issue/pull-request status, CI status, labels, and more. The app is free for open source projects and offers enhanced notifications for private projects at a cost. Octobox is the perfect tool for developers who want to stay organized and focused.", "category": "developer-tools", "tags": ["Developer Tools", "Code Hosting"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "octoboxio/octobox:december-2025"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://octobox.io"}, {"label": "Documentation", "url": "https://octobox.io/documentation"}, {"label": "Github", "url": "https://github.com/octobox/octobox"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "octobox", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('octoprint', 'OctoPrint', 'OctoPrint is a comprehensive web interface designed to provide full remote control and monitoring of your 3D printer. It allows you to manage every aspect of your 3D printing jobs directly from your browser. With OctoPrint, you can access the embedded webcam feed to watch your printer in action, receive constant feedback on the progress of your print job, and even view a rendition of the GCODE you are currently printing. The app also enables you to monitor and adjust the temperatures of your hotends and print bed on the fly, move the print head along all axes, and start, stop, or pause your print job at any time. OctoPrint is compatible with most consumer 3D printers and its powerful plugin system allows for functionality extension. It is 100% open source, allowing everyone to modify it to their own needs. Additional features include creating timelapse recordings of your prints, slicing your STL files directly within the app, built-in access controls, and the ability to add system commands to the menu for easy shutdown or reboot of your OctoPrint server or printer.', 'developer-tools', ARRAY['Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "octoprint/octoprint:1.11.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "OctoPrint", "version": "latest", "description": "OctoPrint is a comprehensive web interface designed to provide full remote control and monitoring of your 3D printer. It allows you to manage every aspect of your 3D printing jobs directly from your browser. With OctoPrint, you can access the embedded webcam feed to watch your printer in action, receive constant feedback on the progress of your print job, and even view a rendition of the GCODE you are currently printing. The app also enables you to monitor and adjust the temperatures of your hotends and print bed on the fly, move the print head along all axes, and start, stop, or pause your print job at any time. OctoPrint is compatible with most consumer 3D printers and its powerful plugin system allows for functionality extension. It is 100% open source, allowing everyone to modify it to their own needs. Additional features include creating timelapse recordings of your prints, slicing your STL files directly within the app, built-in access controls, and the ability to add system commands to the menu for easy shutdown or reboot of your OctoPrint server or printer.", "category": "developer-tools", "tags": ["Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "octoprint/octoprint:1.11.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://octoprint.org"}, {"label": "Docs", "url": "https://docs.octoprint.org"}, {"label": "Github", "url": "https://github.com/OctoPrint/OctoPrint"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "octoprint", "port": "$PORT:80", "volumes": ["/octoprint"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('ocular', 'Ocular', 'Ocular is a self-hosted budget and finance app with dashboards, charts, multi-year tracking, imports, and authentication. This template runs the official container image, which bundles the static UI (Caddy) and the Genesis API backend, with persistent data under /data/genesis.', 'finance', ARRAY['Finance', 'Budget', 'Self-hosted', 'PWA', 'Analytics'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/simonwep/ocular:v2.3.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Ocular", "version": "latest", "description": "Ocular is a self-hosted budget and finance app with dashboards, charts, multi-year tracking, imports, and authentication. This template runs the official container image, which bundles the static UI (Caddy) and the Genesis API backend, with persistent data under /data/genesis.", "category": "finance", "tags": ["Finance", "Budget", "Self-hosted", "PWA", "Analytics"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/simonwep/ocular:v2.3.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://simonwep.github.io/ocular/"}, {"label": "Documentation", "url": "https://simonwep.github.io/ocular/pages/quickstart"}, {"label": "Deploy guide", "url": "https://simonwep.github.io/ocular/pages/deploy.html"}, {"label": "GitHub", "url": "https://github.com/simonwep/ocular"}, {"label": "Container registry", "url": "https://github.com/simonwep/ocular/pkgs/container/ocular"}], "instructions": "After deploy, open your domain and sign in using the initial user from GENESIS_CREATE_USERS (default is admin with a random password set at deploy time; copy it from the service environment if you did not set your own value). Use HTTPS in production; only enable HTTP cookies if you access the app without TLS. Change GENESIS_JWT_SECRET only if you understand that existing sessions will be invalidated.", "install": [{"docker": {"image": "$IMAGE", "name": "ocular", "port": "$PORT:80", "volumes": ["/data/genesis"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deploy, open your domain and sign in using the initial user from GENESIS_CREATE_USERS (default is admin with a random password set at deploy time; copy it from the service environment if you did not set your own value). Use HTTPS in production; only enable HTTP cookies if you access the app without TLS. Change GENESIS_JWT_SECRET only if you understand that existing sessions will be invalidated."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('odoo', 'Odoo', 'Odoo is a comprehensive, integrated software platform designed to streamline and automate your business operations. It offers a suite of open-source business applications that cover all your company needs, from sales and services integration to operations management, website building, financial management, and marketing. Odoo''s unique value proposition lies in its ease of use and full integration. The apps are designed to work seamlessly together, allowing you to automate and track everything you do in a centralized, online platform accessible from anywhere with any device. With Odoo, you can replace multiple applications with a single, cost-effective, and modular solution, eliminating the need for painful integrations and providing a comprehensive overview of your business. The platform evolves much faster than other solutions, with regular annual releases leveraging the expertise of thousands of developers and business experts. Whether you need a CRM, eCommerce, accounting, inventory, project management, or any other business application, Odoo has got you covered.', 'erp', ARRAY['ERP'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "odoo:19.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8069}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Odoo", "version": "latest", "description": "Odoo is a comprehensive, integrated software platform designed to streamline and automate your business operations. It offers a suite of open-source business applications that cover all your company needs, from sales and services integration to operations management, website building, financial management, and marketing. Odoo's unique value proposition lies in its ease of use and full integration. The apps are designed to work seamlessly together, allowing you to automate and track everything you do in a centralized, online platform accessible from anywhere with any device. With Odoo, you can replace multiple applications with a single, cost-effective, and modular solution, eliminating the need for painful integrations and providing a comprehensive overview of your business. The platform evolves much faster than other solutions, with regular annual releases leveraging the expertise of thousands of developers and business experts. Whether you need a CRM, eCommerce, accounting, inventory, project management, or any other business application, Odoo has got you covered.", "category": "erp", "tags": ["ERP"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "odoo:19.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8069}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.odoo.com"}, {"label": "Github", "url": "https://github.com/odoo/odoo"}, {"label": "Documentation", "url": "https://www.odoo.com/page/docs"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "odoo", "port": "$PORT:8069", "volumes": ["/var/lib/odoo", "/etc/odoo", "/mnt/extra-addons"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('offen', 'Offen', 'Offen is a fair and open alternative to common web analytics tools. It gives users access to their data and respects their privacy while providing website owners with the insights they need.', 'analytics', ARRAY['Analytics', 'Privacy', 'GDPR'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "offen/offen:v1.4.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Offen", "version": "latest", "description": "Offen is a fair and open alternative to common web analytics tools. It gives users access to their data and respects their privacy while providing website owners with the insights they need.", "category": "analytics", "tags": ["Analytics", "Privacy", "GDPR"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "offen/offen:v1.4.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.offen.dev"}, {"label": "Documentation", "url": "https://docs.offen.dev"}, {"label": "Github", "url": "https://github.com/offen/offen"}], "instructions": "After deployment, access your Offen instance through your browser to complete the setup process.", "install": [{"docker": {"image": "$IMAGE", "name": "offen", "port": "$PORT:80", "volumes": ["/var/www/.cache"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deployment, access your Offen instance through your browser to complete the setup process."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('olivetin', 'OliveTin', 'OliveTin is a web interface for running Linux shell commands. It provides a simple, elegant dashboard that lets you execute predefined commands with a single click. Perfect for system administrators, home automation enthusiasts, or anyone who wants to simplify repetitive tasks without memorizing complex command-line syntax. OliveTin is lightweight, secure, and highly customizable, allowing you to create buttons for anything from system maintenance to home automation controls.', 'system-administration', ARRAY['System Administration', 'Web Interface', 'Command Execution', 'Automation', 'Linux', 'Dashboard'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "jamesread/olivetin:3000.11.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 1337}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "OliveTin", "version": "latest", "description": "OliveTin is a web interface for running Linux shell commands. It provides a simple, elegant dashboard that lets you execute predefined commands with a single click. Perfect for system administrators, home automation enthusiasts, or anyone who wants to simplify repetitive tasks without memorizing complex command-line syntax. OliveTin is lightweight, secure, and highly customizable, allowing you to create buttons for anything from system maintenance to home automation controls.", "category": "system-administration", "tags": ["System Administration", "Web Interface", "Command Execution", "Automation", "Linux", "Dashboard"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "jamesread/olivetin:3000.11.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 1337}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/OliveTin/OliveTin"}, {"label": "Documentation", "url": "https://docs.olivetin.app"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/jamesread/olivetin"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "olivetin", "port": "$PORT:1337", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('ollama', 'Ollama', 'Ollama is a powerful tool designed to simplify the deployment and interaction with advanced AI models. It provides a streamlined solution for managing and hosting large language models (LLMs) with an intuitive interface. Ollama allows users to run queries and interact with models like OpenAI GPT and others in a secure and efficient manner. The tool includes a web-based interface that makes managing and testing models straightforward. Ollama is designed to support diverse use cases, from research and development to deploying AI capabilities in production systems. It offers flexible deployment options, powerful API integrations, and role-based access control to ensure secure and scalable AI solutions.', 'ai', ARRAY['AI', 'LLM', 'Machine Learning', 'Custom Applications'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ollama/ollama:0.23.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 11434}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Ollama", "version": "latest", "description": "Ollama is a powerful tool designed to simplify the deployment and interaction with advanced AI models. It provides a streamlined solution for managing and hosting large language models (LLMs) with an intuitive interface. Ollama allows users to run queries and interact with models like OpenAI GPT and others in a secure and efficient manner. The tool includes a web-based interface that makes managing and testing models straightforward. Ollama is designed to support diverse use cases, from research and development to deploying AI capabilities in production systems. It offers flexible deployment options, powerful API integrations, and role-based access control to ensure secure and scalable AI solutions.", "category": "ai", "tags": ["AI", "LLM", "Machine Learning", "Custom Applications"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ollama/ollama:0.23.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 11434}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://ollama.com"}, {"label": "Docs", "url": "https://docs.ollama.com"}, {"label": "Github", "url": "https://github.com/Ollama/Ollama"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "ollama", "port": "$PORT:11434", "volumes": ["/data", "/root/.ollama", "/app/backend/data"], "extra_ports": ["80:80"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('ombi', 'Ombi', 'Ombi allows you to host your own Plex Request and user management system. If you are sharing your Plex server with other users, allow them to request new content using an easy to manage interface! Manage all your requests for Movies and TV with ease, leave notes for the user and get notification when a user requests something. Allow your users to post issues against their requests so you know there is a problem with the audio etc. Even automatically send them weekly newsletters of new content that has been added to your Plex server!', 'self-hosted', ARRAY[]::text[], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/ombi:4.53.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3579}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Ombi", "version": "latest", "description": "Ombi allows you to host your own Plex Request and user management system. If you are sharing your Plex server with other users, allow them to request new content using an easy to manage interface! Manage all your requests for Movies and TV with ease, leave notes for the user and get notification when a user requests something. Allow your users to post issues against their requests so you know there is a problem with the audio etc. Even automatically send them weekly newsletters of new content that has been added to your Plex server!", "category": "self-hosted", "tags": [], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/ombi:4.53.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3579}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://ombi.io/"}, {"label": "Documentation", "url": "https://docs.linuxserver.io/images/docker-ombi/"}, {"label": "Github", "url": "https://github.com/linuxserver/docker-ombi"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "ombi", "port": "$PORT:3579", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('omnitools', 'Omni Tools', 'Omni Tools is a comprehensive collection of web-based utilities and tools designed to simplify everyday tasks for developers, designers, and general users. It provides a unified interface for accessing dozens of useful tools including text converters, encoders/decoders, formatters, generators, calculators, image processors, and more. With no need for installation or external dependencies, Omni Tools offers instant access to commonly needed utilities without leaving your browser. The self-hosted solution ensures your data remains private and never leaves your infrastructure, making it ideal for handling sensitive information. All tools run entirely in the web interface with a clean, intuitive design that makes finding and using utilities effortless. Perfect for development teams, content creators, system administrators, and anyone who regularly needs quick access to conversion, formatting, encoding, or calculation tools without relying on multiple online services or installing separate applications.', 'utilities', ARRAY['Utilities', 'Developer Tools', 'Converters', 'Productivity', 'Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "iib0011/omni-tools:0.6.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Omni Tools", "version": "latest", "description": "Omni Tools is a comprehensive collection of web-based utilities and tools designed to simplify everyday tasks for developers, designers, and general users. It provides a unified interface for accessing dozens of useful tools including text converters, encoders/decoders, formatters, generators, calculators, image processors, and more. With no need for installation or external dependencies, Omni Tools offers instant access to commonly needed utilities without leaving your browser. The self-hosted solution ensures your data remains private and never leaves your infrastructure, making it ideal for handling sensitive information. All tools run entirely in the web interface with a clean, intuitive design that makes finding and using utilities effortless. Perfect for development teams, content creators, system administrators, and anyone who regularly needs quick access to conversion, formatting, encoding, or calculation tools without relying on multiple online services or installing separate applications.", "category": "utilities", "tags": ["Utilities", "Developer Tools", "Converters", "Productivity", "Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "iib0011/omni-tools:0.6.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://omnitools.app"}, {"label": "GitHub", "url": "https://github.com/iib0011/omni-tools"}, {"label": "Documentation", "url": "https://github.com/iib0011/omni-tools#readme"}, {"label": "Releases", "url": "https://github.com/iib0011/omni-tools/releases"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/iib0011/omni-tools"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "omnitools", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('once-campfire', 'Once Campfire', 'Once Campfire is a modern, open-source team communication platform built by Basecamp. It provides a simple and intuitive interface for team messaging, file sharing, and collaboration. Once Campfire offers real-time messaging, threaded conversations, file uploads, and search functionality in a clean, distraction-free environment. It''s designed to help teams communicate effectively without the complexity of larger enterprise platforms.', 'team-communication', ARRAY['Team Communication', 'Messaging', 'Collaboration', 'Open Source', 'Basecamp', 'Real-Time', 'File Sharing', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/basecamp/once-campfire:sha-ba11a0a"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Once Campfire", "version": "latest", "description": "Once Campfire is a modern, open-source team communication platform built by Basecamp. It provides a simple and intuitive interface for team messaging, file sharing, and collaboration. Once Campfire offers real-time messaging, threaded conversations, file uploads, and search functionality in a clean, distraction-free environment. It's designed to help teams communicate effectively without the complexity of larger enterprise platforms.", "category": "team-communication", "tags": ["Team Communication", "Messaging", "Collaboration", "Open Source", "Basecamp", "Real-Time", "File Sharing", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/basecamp/once-campfire:sha-ba11a0a"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/basecamp/once-campfire"}], "instructions": "Setup the initial user and start using the app.", "install": [{"docker": {"image": "$IMAGE", "name": "once-campfire", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Setup the initial user and start using the app."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('onedev', 'OneDev', 'OneDev is a versatile app designed to streamline your project management and development processes. It offers a comprehensive suite of features including pull requests, issue tracking, and build management. With OneDev, you can easily manage your projects, track commits, and handle branches and tags. The app also provides a platform for managing pull requests, merging them, and discarding when necessary. It allows you to keep track of open and closed issues, as well as those that have been released. OneDev also offers a robust build management system, enabling you to monitor successful builds across various projects. The app is designed to support multiple projects, each with its own set of files, commits, branches, tags, pull requests, and builds. With OneDev, you can streamline your workflow, enhance collaboration, and improve productivity in your development projects.', 'code-hosting', ARRAY['Code Hosting', 'Developer Tools', 'CI/CD', 'Issue Tracking'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "1dev/server:15.0.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 6610}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "OneDev", "version": "latest", "description": "OneDev is a versatile app designed to streamline your project management and development processes. It offers a comprehensive suite of features including pull requests, issue tracking, and build management. With OneDev, you can easily manage your projects, track commits, and handle branches and tags. The app also provides a platform for managing pull requests, merging them, and discarding when necessary. It allows you to keep track of open and closed issues, as well as those that have been released. OneDev also offers a robust build management system, enabling you to monitor successful builds across various projects. The app is designed to support multiple projects, each with its own set of files, commits, branches, tags, pull requests, and builds. With OneDev, you can streamline your workflow, enhance collaboration, and improve productivity in your development projects.", "category": "code-hosting", "tags": ["Code Hosting", "Developer Tools", "CI/CD", "Issue Tracking"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "1dev/server:15.0.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 6610}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://code.onedev.io/"}, {"label": "Documentation", "url": "https://docs.onedev.io/"}, {"label": "Github", "url": "https://code.onedev.io/onedev/server"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "onedev", "port": "$PORT:6610", "volumes": ["/opt/onedev", "/var/run/docker.sock"], "extra_ports": ["6611:6611"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('onlyoffice', 'OnlyOffice', 'OnlyOffice is a self-hosted office suite that provides powerful document, spreadsheet, and presentation editing capabilities. It offers full compatibility with Microsoft Office formats and allows real-time document collaboration. Designed for businesses, teams, and individuals, OnlyOffice ensures secure, private, and efficient document management. It includes integration with various cloud storage services, supports plugins for extended functionality, and provides a modern web-based interface. OnlyOffice can be deployed on-premise or in the cloud and is ideal for organizations that need control over their document workflow. Additional features include a built-in document management system, mail integration, calendar, CRM tools, and a powerful API for automation.', 'office-suite', ARRAY['Office Suite', 'Productivity', 'Collaboration'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "onlyoffice/documentserver:9.3.1.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "OnlyOffice", "version": "latest", "description": "OnlyOffice is a self-hosted office suite that provides powerful document, spreadsheet, and presentation editing capabilities. It offers full compatibility with Microsoft Office formats and allows real-time document collaboration. Designed for businesses, teams, and individuals, OnlyOffice ensures secure, private, and efficient document management. It includes integration with various cloud storage services, supports plugins for extended functionality, and provides a modern web-based interface. OnlyOffice can be deployed on-premise or in the cloud and is ideal for organizations that need control over their document workflow. Additional features include a built-in document management system, mail integration, calendar, CRM tools, and a powerful API for automation.", "category": "office-suite", "tags": ["Office Suite", "Productivity", "Collaboration"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "onlyoffice/documentserver:9.3.1.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://helpcenter.onlyoffice.com/"}, {"label": "Github", "url": "https://github.com/ONLYOFFICE"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "onlyoffice", "port": "$PORT:80", "volumes": ["/var/log/onlyoffice", "/var/www/onlyoffice/Data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('ontime', 'Ontime', 'Ontime is free, open-source software for managing rundowns and event timers. Real-time rundown and timer management for broadcast and live events. Multi-device web access, delay workflow management, team collaboration, and automated or operator-controlled playback. HTTP API, WebSockets, and OSC (Open Sound Control) for integration with Qlab, OBS, disguise, and other tools.', 'broadcast', ARRAY['Broadcast', 'Timer', 'Rundown', 'Events', 'Open Source', 'OSC'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "getontime/ontime:v4.7.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4001}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Ontime", "version": "latest", "description": "Ontime is free, open-source software for managing rundowns and event timers. Real-time rundown and timer management for broadcast and live events. Multi-device web access, delay workflow management, team collaboration, and automated or operator-controlled playback. HTTP API, WebSockets, and OSC (Open Sound Control) for integration with Qlab, OBS, disguise, and other tools.", "category": "broadcast", "tags": ["Broadcast", "Timer", "Rundown", "Events", "Open Source", "OSC"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "getontime/ontime:v4.7.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4001}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.getontime.no/"}, {"label": "GitHub", "url": "https://github.com/cpvalente/ontime"}, {"label": "Documentation", "url": "https://docs.getontime.no/"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/getontime/ontime"}], "instructions": "After deployment, access the web UI on your assigned domain. Port 4001 serves\nthe web interface and WebSockets. Ports 8888 and 9999 (UDP) are for OSC input\nand output\u2014expose them if you need external control integration.\n", "install": [{"docker": {"image": "$IMAGE", "name": "ontime", "port": "$PORT:4001", "volumes": ["/data"], "extra_ports": ["8888:8888", "9999:9999"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deployment, access the web UI on your assigned domain. Port 4001 serves\nthe web interface and WebSockets. Ports 8888 and 9999 (UDP) are for OSC input\nand output\u2014expose them if you need external control integration.\n"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('open-archiver', 'Open Archiver', 'Open Archiver is a secure, sovereign, and open-source platform for email archiving and eDiscovery. It provides universal ingestion from IMAP, Google Workspace, Microsoft 365, PST files, mbox files, and zipped .eml files. Emails are stored in standard .eml format with deduplication, compression, and optional AES-256 encryption at rest. Features include full-text search across emails and attachments (PDF, DOCX, etc.), thread discovery, file integrity verification, immutable audit trails, role-based access control, and pluggable storage backends (local or S3-compatible). Built with SvelteKit, Node.js, PostgreSQL, Meilisearch, and BullMQ.', 'email', ARRAY['Email', 'Archiving', 'eDiscovery', 'Compliance', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "logiclabshq/open-archiver:v0.5.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Open Archiver", "version": "latest", "description": "Open Archiver is a secure, sovereign, and open-source platform for email archiving and eDiscovery. It provides universal ingestion from IMAP, Google Workspace, Microsoft 365, PST files, mbox files, and zipped .eml files. Emails are stored in standard .eml format with deduplication, compression, and optional AES-256 encryption at rest. Features include full-text search across emails and attachments (PDF, DOCX, etc.), thread discovery, file integrity verification, immutable audit trails, role-based access control, and pluggable storage backends (local or S3-compatible). Built with SvelteKit, Node.js, PostgreSQL, Meilisearch, and BullMQ.", "category": "email", "tags": ["Email", "Archiving", "eDiscovery", "Compliance", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "logiclabshq/open-archiver:v0.5.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://openarchiver.com"}, {"label": "GitHub", "url": "https://github.com/LogicLabs-OU/OpenArchiver"}, {"label": "Documentation", "url": "https://docs.openarchiver.com"}], "instructions": "After deployment, open the app URL and complete /setup as the first user.\nSecrets (JWT, encryption keys, Meilisearch master key, Redis password) are\ngenerated by the template. Configure ingestion sources from the dashboard.\n", "install": [{"docker": {"image": "$IMAGE", "name": "open-archiver", "port": "$PORT:3000", "volumes": ["/meili_data", "/var/data/open-archiver"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deployment, open the app URL and complete /setup as the first user.\nSecrets (JWT, encryption keys, Meilisearch master key, Redis password) are\ngenerated by the template. Configure ingestion sources from the dashboard.\n"}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('openblocks', 'Openblocks', 'Openblocks is an open-source low code platform designed to help you build internal apps quickly and efficiently. With Openblocks, you can create admin panels, dashboards, approval queues, and client support apps with ease and speed. The platform offers over 50 built-in UI components, allowing you to build beautiful, functional, and user-friendly apps. You can also customize new components and embed them seamlessly into your apps. Openblocks connects to most databases and any REST API platform within clicks, enabling full integration of heterogeneous data from anywhere. It''s a developer-first platform, allowing you to extend built-in components using JavaScript and leverage external JavaScript libraries. Openblocks also ensures security and reliability with role-based access control and audit logs. It''s loved by developers for its super-polished interface and mind-blowing functionality.', 'admin-panels', ARRAY['Admin Panels', 'Dashboards', 'Approval Queues', 'Client Support Apps', 'Opportunities', 'Possibilities'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "openblocksdev/openblocks-ce:1.1.8"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Openblocks", "version": "latest", "description": "Openblocks is an open-source low code platform designed to help you build internal apps quickly and efficiently. With Openblocks, you can create admin panels, dashboards, approval queues, and client support apps with ease and speed. The platform offers over 50 built-in UI components, allowing you to build beautiful, functional, and user-friendly apps. You can also customize new components and embed them seamlessly into your apps. Openblocks connects to most databases and any REST API platform within clicks, enabling full integration of heterogeneous data from anywhere. It's a developer-first platform, allowing you to extend built-in components using JavaScript and leverage external JavaScript libraries. Openblocks also ensures security and reliability with role-based access control and audit logs. It's loved by developers for its super-polished interface and mind-blowing functionality.", "category": "admin-panels", "tags": ["Admin Panels", "Dashboards", "Approval Queues", "Client Support Apps", "Opportunities", "Possibilities"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "openblocksdev/openblocks-ce:1.1.8"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://openblocks.dev/"}, {"label": "Documentation", "url": "https://docs.openblocks.dev/"}, {"label": "Github", "url": "https://github.com/openblocks-dev/openblocks"}, {"label": "Discord Community", "url": "https://discord.com/invite/z5W2YHXdtt"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "openblocks", "port": "$PORT:3000", "volumes": ["/openblocks-stacks"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('openclaw', 'OpenClaw', 'OpenClaw is your own personal AI assistant. Any OS. Any Platform. The lobster way. 🦞 An open-source personal AI assistant platform that gives you complete control over your data and AI interactions. Built for Molty, OpenClaw provides a gateway service for WebSocket connections, CLI tools for management, and support for multiple channels including WhatsApp, Telegram, Slack, Discord, and more. Deploy your personal AI assistant with full data ownership and privacy.', 'ai-assistant', ARRAY['AI Assistant', 'Personal Assistant', 'Self-Hosted', 'Open Source', 'Privacy', 'Claude', 'WhatsApp', 'Telegram', 'Slack', 'Discord', 'WebSocket', 'Automation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/openclaw/openclaw:2026.5.3-1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 18790}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "OpenClaw", "version": "latest", "description": "OpenClaw is your own personal AI assistant. Any OS. Any Platform. The lobster way. \ud83e\udd9e An open-source personal AI assistant platform that gives you complete control over your data and AI interactions. Built for Molty, OpenClaw provides a gateway service for WebSocket connections, CLI tools for management, and support for multiple channels including WhatsApp, Telegram, Slack, Discord, and more. Deploy your personal AI assistant with full data ownership and privacy.", "category": "ai-assistant", "tags": ["AI Assistant", "Personal Assistant", "Self-Hosted", "Open Source", "Privacy", "Claude", "WhatsApp", "Telegram", "Slack", "Discord", "WebSocket", "Automation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/openclaw/openclaw:2026.5.3-1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 18790}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://openclaw.ai"}, {"label": "GitHub", "url": "https://github.com/openclaw/openclaw"}, {"label": "Documentation", "url": "https://docs.openclaw.ai"}], "instructions": "Once deployed, the gateway service will start automatically. To complete setup, you can run the onboarding wizard by executing `node dist/index.js onboard --no-install-daemon` in the gateway service console. The gateway runs with `--allow-unconfigured` flag to enable initial setup.", "install": [{"docker": {"image": "$IMAGE", "name": "openclaw", "port": "$PORT:18790", "volumes": ["/home/node/.openclaw", "/home/node/.openclaw/workspace", "/var/run/docker.sock"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Once deployed, the gateway service will start automatically. To complete setup, you can run the onboarding wizard by executing `node dist/index.js onboard --no-install-daemon` in the gateway service console. The gateway runs with `--allow-unconfigured` flag to enable initial setup."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('openemr', 'OpenEMR', 'OpenEMR is a powerful, open-source electronic medical records and practice management solution designed for efficient healthcare operations. It provides a comprehensive, user-friendly interface, supports modular functionality, and offers robust reporting and analytics for clinical and administrative tasks. With OpenEMR, healthcare providers can manage patient records, appointments, billing, and more. The application is accessible via your host on ports 80 and 443. This container is built on a lightweight Docker image, providing additional environment variables and configurations for enhanced flexibility. It also supports the docker manifest for multi-platform awareness, ensuring the correct image for your architecture.', 'electronic-health-records', ARRAY['Electronic Health Records', 'Practice Management', 'Open Source', 'Healthcare'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "openemr/openemr:8.0.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "OpenEMR", "version": "latest", "description": "OpenEMR is a powerful, open-source electronic medical records and practice management solution designed for efficient healthcare operations. It provides a comprehensive, user-friendly interface, supports modular functionality, and offers robust reporting and analytics for clinical and administrative tasks. With OpenEMR, healthcare providers can manage patient records, appointments, billing, and more. The application is accessible via your host on ports 80 and 443. This container is built on a lightweight Docker image, providing additional environment variables and configurations for enhanced flexibility. It also supports the docker manifest for multi-platform awareness, ensuring the correct image for your architecture.", "category": "electronic-health-records", "tags": ["Electronic Health Records", "Practice Management", "Open Source", "Healthcare"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "openemr/openemr:8.0.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://www.open-emr.org/wiki/index.php/OpenEMR_Wiki_Home_Page"}, {"label": "Github", "url": "https://github.com/openemr/openemr"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "openemr", "port": "$PORT:80", "volumes": ["/var/www/localhost/htdocs/openemr/sites", "/var/log"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('opengist', 'OpenGist', 'OpenGist is a self-hosted pastebin powered by Git. All snippets are stored in a Git repository and can be read and/or modified using standard Git commands, or with the web interface. It is similar to GitHub Gist, but open-source and can be self-hosted. Create public, unlisted or private snippets with syntax highlighting, search functionality, and Git integration.', 'pastebin', ARRAY['Pastebin', 'Git', 'Code Sharing', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/thomiceli/opengist:1.12.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 6157}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "OpenGist", "version": "latest", "description": "OpenGist is a self-hosted pastebin powered by Git. All snippets are stored in a Git repository and can be read and/or modified using standard Git commands, or with the web interface. It is similar to GitHub Gist, but open-source and can be self-hosted. Create public, unlisted or private snippets with syntax highlighting, search functionality, and Git integration.", "category": "pastebin", "tags": ["Pastebin", "Git", "Code Sharing", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/thomiceli/opengist:1.12.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 6157}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://opengist.io/"}, {"label": "Documentation", "url": "https://opengist.io/"}, {"label": "Github", "url": "https://github.com/thomiceli/opengist"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "opengist", "port": "$PORT:6157", "volumes": ["/opengist"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('openhab', 'OpenHAB', 'OpenHAB is an open-source automation software designed to integrate and control smart home devices from various manufacturers. Written in Java, it enables you to create rules, manage devices, and automate processes within your smart home ecosystem. The platform provides a flexible and modular approach, allowing integration with hundreds of devices and technologies through add-ons. OpenHAB features a powerful rule engine, a unified user interface, and supports various communication protocols such as Z-Wave, Zigbee, and MQTT. It is highly customizable, secure, and community-driven, offering extensive documentation and support. OpenHAB supports real-time updates, is mobile-friendly, and can be deployed on multiple platforms including Docker and Kubernetes. Additional features include voice control integration, presence detection, and support for custom scripts.', 'smart-home', ARRAY['Smart Home', 'Automation', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "openhab/openhab:5.0.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "OpenHAB", "version": "latest", "description": "OpenHAB is an open-source automation software designed to integrate and control smart home devices from various manufacturers. Written in Java, it enables you to create rules, manage devices, and automate processes within your smart home ecosystem. The platform provides a flexible and modular approach, allowing integration with hundreds of devices and technologies through add-ons. OpenHAB features a powerful rule engine, a unified user interface, and supports various communication protocols such as Z-Wave, Zigbee, and MQTT. It is highly customizable, secure, and community-driven, offering extensive documentation and support. OpenHAB supports real-time updates, is mobile-friendly, and can be deployed on multiple platforms including Docker and Kubernetes. Additional features include voice control integration, presence detection, and support for custom scripts.", "category": "smart-home", "tags": ["Smart Home", "Automation", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "openhab/openhab:5.0.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://www.openhab.org/docs/"}, {"label": "Github", "url": "https://github.com/openhab/openhab-addons"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "openhab", "port": "$PORT:8080", "volumes": ["/openhab/addons", "/openhab/conf", "/openhab/userdata"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('openpanel', 'OpenPanel', 'OpenPanel is a powerful open-source product analytics platform that helps you track and analyze user behavior. Built with modern technologies, it provides real-time insights, custom event tracking, and intuitive dashboards. Features include user segmentation, funnel analysis, retention metrics, and comprehensive reporting capabilities. Self-hosted solution that gives you full control over your data while maintaining privacy and security.', 'analytics', ARRAY['Analytics', 'Self-Hosted', 'Product Analytics', 'User Tracking'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "OpenPanel", "version": "latest", "description": "OpenPanel is a powerful open-source product analytics platform that helps you track and analyze user behavior. Built with modern technologies, it provides real-time insights, custom event tracking, and intuitive dashboards. Features include user segmentation, funnel analysis, retention metrics, and comprehensive reporting capabilities. Self-hosted solution that gives you full control over your data while maintaining privacy and security.", "category": "analytics", "tags": ["Analytics", "Self-Hosted", "Product Analytics", "User Tracking"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://openpanel.dev/"}, {"label": "GitHub", "url": "https://github.com/Openpanel-dev/openpanel"}], "instructions": "You have to provide the domain name in order to access the OpenPanel dashboard successfully and use the Caddy service to access the OpenPanel.", "install": [{"docker": {"image": "$IMAGE", "name": "openpanel", "port": "$PORT:80", "volumes": ["/etc/caddy/Caddyfile", "/data", "/config", "/var/lib/clickhouse", "/var/log/clickhouse-server", "/etc/clickhouse-server/config.d", "/etc/clickhouse-server/users.d", "/docker-entrypoint-initdb.d"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "You have to provide the domain name in order to access the OpenPanel dashboard successfully and use the Caddy service to access the OpenPanel."}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('openproject', 'OpenProject', 'OpenProject is an open-source project management software designed to facilitate efficient project management in a secure environment. It caters to various project management styles including classic, agile, or hybrid. The software allows you to take control of your data with the highest standards in data security and privacy. OpenProject can be installed on-premises in your own infrastructure, ensuring full control and 100% data ownership. It offers a variety of security features such as https encryption of your data, password security, two-factor authentication, and more. OpenProject supports agile project management and methodologies such as Scrum and Kanban, allowing teams to deliver better and faster. It also features a team planner to visually assign tasks to team members, helping to plan activities and gain perspective on the team''s workload. OpenProject is also a powerful tool for project planning and scheduling, enabling teams to collaboratively create and visualize project plans, analyze required activities, and create a detailed plan for project deliverables.', 'project-management', ARRAY['Project Management', 'Open Source', 'Data Security'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "openproject/community:13.4.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "OpenProject", "version": "latest", "description": "OpenProject is an open-source project management software designed to facilitate efficient project management in a secure environment. It caters to various project management styles including classic, agile, or hybrid. The software allows you to take control of your data with the highest standards in data security and privacy. OpenProject can be installed on-premises in your own infrastructure, ensuring full control and 100% data ownership. It offers a variety of security features such as https encryption of your data, password security, two-factor authentication, and more. OpenProject supports agile project management and methodologies such as Scrum and Kanban, allowing teams to deliver better and faster. It also features a team planner to visually assign tasks to team members, helping to plan activities and gain perspective on the team's workload. OpenProject is also a powerful tool for project planning and scheduling, enabling teams to collaboratively create and visualize project plans, analyze required activities, and create a detailed plan for project deliverables.", "category": "project-management", "tags": ["Project Management", "Open Source", "Data Security"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "openproject/community:13.4.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://openproject.org/"}, {"label": "Docs", "url": "https://openproject.org/docs/"}, {"label": "Github", "url": "https://github.com/opf/openproject"}, {"label": "Docker", "url": "https://hub.docker.com/r/openproject/community"}], "instructions": "The default login credentials are admin:admin", "install": [{"docker": {"image": "$IMAGE", "name": "openproject", "port": "$PORT:3000", "volumes": ["/var/openproject/assets", "/var/openproject/pgdata"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "The default login credentials are admin:admin"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('openspeedtest', 'OpenSpeedTest', 'OpenSpeedTest is a powerful and accurate online bandwidth test application that works on any web browser without the need for Flash or Java. It is designed to replicate your real-world connection speed and is capable of testing any connection, from 1 Kbps to 1 Gbps+. The application uses the latest technology to automatically detect your stable download and upload speed from our servers. It also provides a guide on how to increase your internet speed and get more out of your connection. You can create your own network speed test without any client-side software or plugin. The application can also be embedded to your website or application, allowing your users to test their internet speed without leaving your page. It is also available as a standalone application for home or small office LAN and can be used for large-scale deployments as a self-hosted/on-premise network speed test.', 'network-tools', ARRAY['Network Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "openspeedtest/latest:v2.0.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "OpenSpeedTest", "version": "latest", "description": "OpenSpeedTest is a powerful and accurate online bandwidth test application that works on any web browser without the need for Flash or Java. It is designed to replicate your real-world connection speed and is capable of testing any connection, from 1 Kbps to 1 Gbps+. The application uses the latest technology to automatically detect your stable download and upload speed from our servers. It also provides a guide on how to increase your internet speed and get more out of your connection. You can create your own network speed test without any client-side software or plugin. The application can also be embedded to your website or application, allowing your users to test their internet speed without leaving your page. It is also available as a standalone application for home or small office LAN and can be used for large-scale deployments as a self-hosted/on-premise network speed test.", "category": "network-tools", "tags": ["Network Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "openspeedtest/latest:v2.0.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://openspeedtest.com/"}, {"label": "Github", "url": "https://github.com/openspeedtest/Speed-Test"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "openspeedtest", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('openvpn', 'OpenVPN Access Server', 'OpenVPN Access Server is a full-featured SSL VPN software solution that integrates OpenVPN server capabilities, enterprise-grade user management, granular access controls, and an easy-to-use web interface for administration.', 'network-tools', ARRAY['Network Tools', 'Security', 'VPN', 'OpenVPN', 'Remote Access'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "openvpn/openvpn-as:3.1.0-e22fe316-Ubuntu24"}, "port": {"type": "integer", "title": "Port HTTP", "default": 443}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "OpenVPN Access Server", "version": "latest", "description": "OpenVPN Access Server is a full-featured SSL VPN software solution that integrates OpenVPN server capabilities, enterprise-grade user management, granular access controls, and an easy-to-use web interface for administration.", "category": "network-tools", "tags": ["Network Tools", "Security", "VPN", "OpenVPN", "Remote Access"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "openvpn/openvpn-as:3.1.0-e22fe316-Ubuntu24"}, "port": {"type": "integer", "title": "Port HTTP", "default": 443}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://openvpn.net/access-server/"}, {"label": "Documentation", "url": "https://openvpn.net/vpn-server-resources/access-server-manager/"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/openvpn/openvpn-as"}, {"label": "Guide", "url": "https://openvpn.net/as-docs/docker.html#run-the-docker-container"}], "instructions": "Please use the Guide given below to get the password and access the portal. For admin portal access, use the following URL; https://$(EASYPANEL_HOST_IP):$(mgmtServicePort)/admin. User is openvpn and the password can be searched in logs as \"Auto-Generated pass\"", "install": [{"docker": {"image": "$IMAGE", "name": "openvpn", "port": "$PORT:443", "volumes": ["/openvpn"], "extra_ports": ["943:943", "1194:1194"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Please use the Guide given below to get the password and access the portal. For admin portal access, use the following URL; https://$(EASYPANEL_HOST_IP):$(mgmtServicePort)/admin. User is openvpn and the password can be searched in logs as \"Auto-Generated pass\""}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('openwebui', 'OpenWebUI', 'OpenWebUI is a self-hosted, open-source web-based UI for interacting with various Large Language Models (LLMs). It allows users to chat with AI models, manage API connections, and customize their experience through an intuitive interface. OpenWebUI supports multiple backends such as Ollama, OpenAI-compatible APIs, and local AI runners. It offers a sleek web-based UI, user authentication, and integration with popular LLMs. The application is containerized and easy to deploy with Docker, Kubernetes, or standalone installations. It provides real-time chat, conversation history, and advanced configuration options for AI interactions.', 'ai', ARRAY['AI', 'Chatbot', 'Productivity', 'Self-Hosting'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/open-webui/open-webui:0.9.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "OpenWebUI", "version": "latest", "description": "OpenWebUI is a self-hosted, open-source web-based UI for interacting with various Large Language Models (LLMs). It allows users to chat with AI models, manage API connections, and customize their experience through an intuitive interface. OpenWebUI supports multiple backends such as Ollama, OpenAI-compatible APIs, and local AI runners. It offers a sleek web-based UI, user authentication, and integration with popular LLMs. The application is containerized and easy to deploy with Docker, Kubernetes, or standalone installations. It provides real-time chat, conversation history, and advanced configuration options for AI interactions.", "category": "ai", "tags": ["AI", "Chatbot", "Productivity", "Self-Hosting"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/open-webui/open-webui:0.9.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://docs.openwebui.com/"}, {"label": "Github", "url": "https://github.com/open-webui/open-webui"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "openwebui", "port": "$PORT:80", "volumes": ["/app/backend/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('opera', 'Opera', 'Opera is a multi-platform web browser developed by Opera. This app is based on Chromium, but sets itself apart from other Chromium-based browsers through its unique user interface and additional features. The app can be accessed at http://yourhost:3000/ or https://yourhost:3001/. It provides a true lossless image at a high frame rate to your web browser by changing the Stream Quality preset to ''Lossless''. The app also allows you to specify one or multiple Chromium CLI flags, which will be passed to the application in full. This app is designed to avoid permission issues that can arise between the host OS and the container by allowing you to specify the user PUID and group PGID.', 'web-browsers', ARRAY['Web Browsers', 'Internet', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/opera:131.0.5877"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Opera", "version": "latest", "description": "Opera is a multi-platform web browser developed by Opera. This app is based on Chromium, but sets itself apart from other Chromium-based browsers through its unique user interface and additional features. The app can be accessed at http://yourhost:3000/ or https://yourhost:3001/. It provides a true lossless image at a high frame rate to your web browser by changing the Stream Quality preset to 'Lossless'. The app also allows you to specify one or multiple Chromium CLI flags, which will be passed to the application in full. This app is designed to avoid permission issues that can arise between the host OS and the container by allowing you to specify the user PUID and group PGID.", "category": "web-browsers", "tags": ["Web Browsers", "Internet", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/opera:131.0.5877"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://docs.linuxserver.io/images/docker-opera"}, {"label": "Github", "url": "https://github.com/linuxserver/docker-opera"}], "instructions": "use abc:abc to login. To access the login interface, add ?login=true to your URL.", "install": [{"docker": {"image": "$IMAGE", "name": "opera", "port": "$PORT:3000", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "use abc:abc to login. To access the login interface, add ?login=true to your URL."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('opnform', 'OpnForm', 'OpnForm is an open-source form builder that allows you to create beautiful, customizable forms with ease. It provides an intuitive interface for building forms,  collecting submissions, and analyzing data.', 'forms', ARRAY['Forms', 'Web Apps', 'Productivity', 'Business Apps'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "jhumanj/opnform-client:1.13.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "OpnForm", "version": "latest", "description": "OpnForm is an open-source form builder that allows you to create beautiful, customizable forms with ease. It provides an intuitive interface for building forms,  collecting submissions, and analyzing data.", "category": "forms", "tags": ["Forms", "Web Apps", "Productivity", "Business Apps"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "jhumanj/opnform-client:1.13.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://opnform.com/"}, {"label": "Documentation", "url": "https://docs.opnform.com/"}, {"label": "Github", "url": "https://github.com/JhumanJ/OpnForm"}], "instructions": "Login using the credentials, admin@opnform.com/password.", "install": [{"docker": {"image": "$IMAGE", "name": "opnform", "port": "$PORT:80", "volumes": ["/etc/nginx/conf.d/opnform.template", "/usr/share/nginx/html/storage", "/usr/share/nginx/html/storage", "/usr/share/nginx/html/storage"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Login using the credentials, admin@opnform.com/password."}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('orangehrm', 'OrangeHRM', 'OrangeHRM is a comprehensive, open-source Human Resource Management (HRM) solution designed to streamline HR processes and manage employee information. It provides modules for employee management, leave tracking, time management, recruitment, and performance reviews. With an intuitive interface and customizable features, OrangeHRM is a great choice for organizations of all sizes.', 'human-resource-management', ARRAY['Human Resource Management', 'Open Source', 'Employee Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "orangehrm/orangehrm:5.8.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "OrangeHRM", "version": "latest", "description": "OrangeHRM is a comprehensive, open-source Human Resource Management (HRM) solution designed to streamline HR processes and manage employee information. It provides modules for employee management, leave tracking, time management, recruitment, and performance reviews. With an intuitive interface and customizable features, OrangeHRM is a great choice for organizations of all sizes.", "category": "human-resource-management", "tags": ["Human Resource Management", "Open Source", "Employee Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "orangehrm/orangehrm:5.8.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.orangehrm.com/"}, {"label": "Github", "url": "https://github.com/orangehrm/orangehrm"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "orangehrm", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('organizer', 'Organizer', 'Organizer is a self-hosted service designed to help you manage and organize your various web applications efficiently. It serves as a centralized portal where you can categorize and access all your self-hosted apps in a simple and intuitive way. Written in PHP, Organizer provides a dashboard for quick navigation, supports authentication for security, and integrates with various third-party applications. It offers a customizable interface, supports mobile devices, and ensures a seamless experience for managing multiple services within your home or business environment.', 'dashboard', ARRAY['Dashboard', 'Productivity', 'App Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/organizr:version-f6d984d2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Organizer", "version": "latest", "description": "Organizer is a self-hosted service designed to help you manage and organize your various web applications efficiently. It serves as a centralized portal where you can categorize and access all your self-hosted apps in a simple and intuitive way. Written in PHP, Organizer provides a dashboard for quick navigation, supports authentication for security, and integrates with various third-party applications. It offers a customizable interface, supports mobile devices, and ensures a seamless experience for managing multiple services within your home or business environment.", "category": "dashboard", "tags": ["Dashboard", "Productivity", "App Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/organizr:version-f6d984d2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/causefx/Organizr"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "organizer", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('osticket', 'OSTicket', 'OSTicket is a widely-used, open-source ticketing system designed to streamline customer support management. It provides a user-friendly interface for handling, tracking, and organizing support tickets across multiple channels, including email, web forms, and API integrations. With OSTicket, you can efficiently manage inquiries, automate workflows, and improve customer satisfaction.', 'ticketing-system', ARRAY['Ticketing System', 'Customer Support', 'Self-Hosted', 'Workflow Automation', 'SLA Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "tiredofit/osticket:3.6.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "OSTicket", "version": "latest", "description": "OSTicket is a widely-used, open-source ticketing system designed to streamline customer support management. It provides a user-friendly interface for handling, tracking, and organizing support tickets across multiple channels, including email, web forms, and API integrations. With OSTicket, you can efficiently manage inquiries, automate workflows, and improve customer satisfaction.", "category": "ticketing-system", "tags": ["Ticketing System", "Customer Support", "Self-Hosted", "Workflow Automation", "SLA Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "tiredofit/osticket:3.6.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://docs.osticket.com"}, {"label": "Github", "url": "https://github.com/osTicket/osTicket"}], "instructions": "You can configure other Environmental settings in Environment Section.", "install": [{"docker": {"image": "$IMAGE", "name": "osticket", "port": "$PORT:80", "volumes": ["/www/osticket", "/www/logs"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "You can configure other Environmental settings in Environment Section."}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('otterwiki', 'OtterWiki', 'OtterWiki is a simple, easy-to-use wiki software for personal use and small teams. It''s designed to be minimalist, focusing on the essentials without unnecessary complexity. OtterWiki stores all content as Markdown files in a Git repository, providing automatic version control and the ability to edit pages using your favorite text editor. It features a clean, modern interface with syntax highlighting, file attachments, full-text search, and dark mode support. The wiki requires no database setup - everything is stored in plain text files, making backups and migrations simple. OtterWiki supports user authentication, page permissions, and comes with a built-in editor with live preview. Perfect for documentation, note-taking, knowledge management, and collaborative writing in small teams.', 'wiki', ARRAY['Wiki', 'Documentation', 'Markdown', 'Git', 'Knowledge Base'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "redimp/otterwiki:2.20.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "OtterWiki", "version": "latest", "description": "OtterWiki is a simple, easy-to-use wiki software for personal use and small teams. It's designed to be minimalist, focusing on the essentials without unnecessary complexity. OtterWiki stores all content as Markdown files in a Git repository, providing automatic version control and the ability to edit pages using your favorite text editor. It features a clean, modern interface with syntax highlighting, file attachments, full-text search, and dark mode support. The wiki requires no database setup - everything is stored in plain text files, making backups and migrations simple. OtterWiki supports user authentication, page permissions, and comes with a built-in editor with live preview. Perfect for documentation, note-taking, knowledge management, and collaborative writing in small teams.", "category": "wiki", "tags": ["Wiki", "Documentation", "Markdown", "Git", "Knowledge Base"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "redimp/otterwiki:2.20.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://otterwiki.com/"}, {"label": "Github", "url": "https://github.com/redimp/otterwiki"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/redimp/otterwiki"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "otterwiki", "port": "$PORT:80", "volumes": ["/app-data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('outline', 'Outline Wiki', 'Outline is a team knowledge base and wiki that helps organize your team''s information in a structured and searchable manner. It offers an intuitive editing experience with markdown support, slash commands, and rich embeds. You can collaborate on documents in real-time, with comments and threads keeping conversations organized. The platform integrates seamlessly with Slack, allowing you to search and share documents without leaving the chat. Outline also supports public sharing of documents with your own brand colors, logos, and domain. It''s designed to be fast, collaborative, and easy to use, with a focus on security and permissions. It also supports multiple languages and offers integrations with tools like Figma, Loom, and more.', 'documentation', ARRAY['Documentation', 'Productivity', 'Business Apps', 'Collaboration'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "outlinewiki/outline:0.85"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Outline Wiki", "version": "latest", "description": "Outline is a team knowledge base and wiki that helps organize your team's information in a structured and searchable manner. It offers an intuitive editing experience with markdown support, slash commands, and rich embeds. You can collaborate on documents in real-time, with comments and threads keeping conversations organized. The platform integrates seamlessly with Slack, allowing you to search and share documents without leaving the chat. Outline also supports public sharing of documents with your own brand colors, logos, and domain. It's designed to be fast, collaborative, and easy to use, with a focus on security and permissions. It also supports multiple languages and offers integrations with tools like Figma, Loom, and more.", "category": "documentation", "tags": ["Documentation", "Productivity", "Business Apps", "Collaboration"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "outlinewiki/outline:0.85"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.getoutline.com/"}, {"label": "Documentation", "url": "https://www.getoutline.com/developers"}, {"label": "Github", "url": "https://github.com/outline"}], "instructions": "Notice, Auththenication Method is Required to use Outline. To use Other Login Methods, Just fill in dummy Cridentials and edit the env! Check out the Docs https://wiki.generaloutline.com/s/hosting/doc/authentication-7ViKRmRY5o! Notice, Some sort of SMTP is Optinal! Check the env Here https://github.com/outline/outline/blob/main/.env.sample", "install": [{"docker": {"image": "$IMAGE", "name": "outline", "port": "$PORT:3000", "volumes": ["/data"], "extra_ports": ["9001:9001"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Notice, Auththenication Method is Required to use Outline. To use Other Login Methods, Just fill in dummy Cridentials and edit the env! Check out the Docs https://wiki.generaloutline.com/s/hosting/doc/authentication-7ViKRmRY5o! Notice, Some sort of SMTP is Optinal! Check the env Here https://github.com/outline/outline/blob/main/.env.sample"}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('overseerr', 'Overseerr', 'Overseerr is a request management and media discovery tool for the Plex ecosystem. It provides a clean, modern interface for users to browse and request content for Plex, seamlessly integrating with services like Sonarr, Radarr, and Jellyfin.', 'media', ARRAY['Media', 'Plex', 'Requests', 'Content Management', 'Sonarr', 'Radarr'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/overseerr:develop-7f868f38e6f2f1834ea12dc8f5c095000c7a3c09-ls368"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5055}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Overseerr", "version": "latest", "description": "Overseerr is a request management and media discovery tool for the Plex ecosystem. It provides a clean, modern interface for users to browse and request content for Plex, seamlessly integrating with services like Sonarr, Radarr, and Jellyfin.", "category": "media", "tags": ["Media", "Plex", "Requests", "Content Management", "Sonarr", "Radarr"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/overseerr:develop-7f868f38e6f2f1834ea12dc8f5c095000c7a3c09-ls368"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5055}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://overseerr.dev"}, {"label": "Documentation", "url": "https://docs.overseerr.dev"}, {"label": "GitHub", "url": "https://github.com/sct/overseerr"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/linuxserver/overseerr"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "overseerr", "port": "$PORT:5055", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('owncast', 'Owncast', 'Owncast is a free and open-source live video and web chat server that works seamlessly with your existing broadcasting software. It gives you complete control and ownership over your stream, allowing you to create the content you want. The app comes with a frictionless built-in chat feature that enables your viewers to engage and be a part of the action. You can include custom emotes and build chat bots to encourage viewer engagement. Owncast also allows your live stream to reach a wider audience on The Fediverse, including platforms like Mastodon and other Fediverse services. It''s a self-hosted and independent solution for live streaming, offering a high level of performance comparable to proprietary platforms.', 'chat', ARRAY['Chat', 'Media', 'Self-hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "gabekangas/owncast:0.2.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Owncast", "version": "latest", "description": "Owncast is a free and open-source live video and web chat server that works seamlessly with your existing broadcasting software. It gives you complete control and ownership over your stream, allowing you to create the content you want. The app comes with a frictionless built-in chat feature that enables your viewers to engage and be a part of the action. You can include custom emotes and build chat bots to encourage viewer engagement. Owncast also allows your live stream to reach a wider audience on The Fediverse, including platforms like Mastodon and other Fediverse services. It's a self-hosted and independent solution for live streaming, offering a high level of performance comparable to proprietary platforms.", "category": "chat", "tags": ["Chat", "Media", "Self-hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "gabekangas/owncast:0.2.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://owncast.online/"}, {"label": "Documentation", "url": "https://owncast.online/docs"}, {"label": "Github", "url": "https://github.com/owncast/owncast"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "owncast", "port": "$PORT:8080", "volumes": ["/app/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('owncloud', 'Owncloud', 'ownCloud Infinite Scale 3.0 is a secure cloud platform designed for real-time content collaboration. It is trusted by over 200 million users worldwide and offers a revolutionary project folder concept, Spaces, to boost seamless digital collaboration for remote teams of all sizes. The platform also provides a suite of powerful integrations through Web Office, including OnlyOffice, Microsoft 365, Collabora Online, and Microsoft Office Online, enabling users to collaborate seamlessly and securely from any location and device. ownCloud Infinite Scale 3.0 is designed with state-of-the-art security standards and best practices, ensuring superior data protection and privacy. It allows organizations to control their data at all times, anywhere, and can be deployed on-premises, in a data center of choice, or in a hybrid setup. The platform also supports multi-factor authentication, encryption, and elaborate file lifecycle management for enhanced security. ownCloud Infinite Scale 3.0 is designed to increase productivity by enabling modern teams to store, share, and work on their data and documents through a single point of access.', 'file-management', ARRAY['File Management', 'Collaboration', 'Data Security'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "owncloud/server:10.16.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Owncloud", "version": "latest", "description": "ownCloud Infinite Scale 3.0 is a secure cloud platform designed for real-time content collaboration. It is trusted by over 200 million users worldwide and offers a revolutionary project folder concept, Spaces, to boost seamless digital collaboration for remote teams of all sizes. The platform also provides a suite of powerful integrations through Web Office, including OnlyOffice, Microsoft 365, Collabora Online, and Microsoft Office Online, enabling users to collaborate seamlessly and securely from any location and device. ownCloud Infinite Scale 3.0 is designed with state-of-the-art security standards and best practices, ensuring superior data protection and privacy. It allows organizations to control their data at all times, anywhere, and can be deployed on-premises, in a data center of choice, or in a hybrid setup. The platform also supports multi-factor authentication, encryption, and elaborate file lifecycle management for enhanced security. ownCloud Infinite Scale 3.0 is designed to increase productivity by enabling modern teams to store, share, and work on their data and documents through a single point of access.", "category": "file-management", "tags": ["File Management", "Collaboration", "Data Security"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "owncloud/server:10.16.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://owncloud.com/"}, {"label": "Documentation", "url": "https://doc.owncloud.com/"}, {"label": "Github", "url": "https://github.com/owncloud/core"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "owncloud", "port": "$PORT:8080", "volumes": ["/mnt/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "mysql": {"type": "mysql", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('oxicloud', 'OxiCloud', 'OxiCloud is an ultra-fast, secure, and lightweight self-hosted cloud storage written in Rust. It serves as a lightweight alternative to NextCloud, designed for low-resource environments. OxiCloud runs on just 512MB RAM with sub-second response times, offering file management, user authentication, file deduplication, search, CalDAV calendars, CardDAV contacts, and multi-language support. Built with Clean Architecture, it provides a clean UI that works on desktop and mobile.', 'file-storage', ARRAY['File Storage', 'Cloud Storage', 'Self-Hosted', 'NextCloud Alternative', 'CalDAV', 'CardDAV'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "diocrafts/oxicloud:0.5.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8086}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "OxiCloud", "version": "latest", "description": "OxiCloud is an ultra-fast, secure, and lightweight self-hosted cloud storage written in Rust. It serves as a lightweight alternative to NextCloud, designed for low-resource environments. OxiCloud runs on just 512MB RAM with sub-second response times, offering file management, user authentication, file deduplication, search, CalDAV calendars, CardDAV contacts, and multi-language support. Built with Clean Architecture, it provides a clean UI that works on desktop and mobile.", "category": "file-storage", "tags": ["File Storage", "Cloud Storage", "Self-Hosted", "NextCloud Alternative", "CalDAV", "CardDAV"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "diocrafts/oxicloud:0.5.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8086}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/DioCrafts/OxiCloud"}, {"label": "Documentation", "url": "https://github.com/DioCrafts/OxiCloud/tree/main/doc"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/diocrafts/oxicloud"}], "instructions": "Set OXICLOUD_BASE_URL on the app service to your public URL (e.g. https://cloud.example.com)\nif you access OxiCloud via a domain; otherwise auth and share links can break. Database\nmigrations run automatically on first start. JWT signing uses a generated OXICLOUD_JWT_SECRET.\n", "install": [{"docker": {"image": "$IMAGE", "name": "oxicloud", "port": "$PORT:8086", "volumes": ["/app/storage"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Set OXICLOUD_BASE_URL on the app service to your public URL (e.g. https://cloud.example.com)\nif you access OxiCloud via a domain; otherwise auth and share links can break. Database\nmigrations run automatically on first start. JWT signing uses a generated OXICLOUD_JWT_SECRET.\n"}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('oxigen', 'Oxigen', 'Oxigen is a dynamic social media image generator designed to streamline the process of creating and customizing og images. With a user-friendly interface and API, Oxigen allows you to effortlessly generate images tailored to your specific needs. Whether you''re looking to create unique images for your social media posts or need a reliable tool for generating og images, Oxigen offers a flexible and efficient solution.', 'social-networking', ARRAY['Social Networking', 'Image Generator'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/yuriizinets/oxigen:2.1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Oxigen", "version": "latest", "description": "Oxigen is a dynamic social media image generator designed to streamline the process of creating and customizing og images. With a user-friendly interface and API, Oxigen allows you to effortlessly generate images tailored to your specific needs. Whether you're looking to create unique images for your social media posts or need a reliable tool for generating og images, Oxigen offers a flexible and efficient solution.", "category": "social-networking", "tags": ["Social Networking", "Image Generator"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/yuriizinets/oxigen:2.1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/yuriizinets/oxigen"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "oxigen", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('paaster', 'Paaster', 'Paaster is a secure and user-friendly pastebin application with end-to-end encryption. Content is encrypted locally in your browser—the key never reaches the server. Features paste history, delete-after-view, file drag & drop, and API. Supports MinIO, S3, R2, and other S3-compatible storage.', 'pastebin', ARRAY['Pastebin', 'Privacy', 'Encryption', 'Open Source', 'Self-hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "wardpearce/paaster:3.2.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Paaster", "version": "latest", "description": "Paaster is a secure and user-friendly pastebin application with end-to-end encryption. Content is encrypted locally in your browser\u2014the key never reaches the server. Features paste history, delete-after-view, file drag & drop, and API. Supports MinIO, S3, R2, and other S3-compatible storage.", "category": "pastebin", "tags": ["Pastebin", "Privacy", "Encryption", "Open Source", "Self-hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "wardpearce/paaster:3.2.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/WardPearce/paaster"}, {"label": "Website", "url": "https://paaster.com"}, {"label": "Documentation", "url": "https://github.com/WardPearce/paaster/blob/main/README.md"}], "instructions": "After deployment, access Paaster via the main domain. Pastes are E2EE by\ndefault. Uses built-in MinIO for storage. If using MinIO, create the bucket\n\"paaster\" in the MinIO console (minio-$(domain):9001) or via mc CLI:\nmc mb minio_instance/paaster; mc anonymous set none minio_instance/paaster.\nFor external S3/R2, set S3 env vars on the Paaster service.\n", "install": [{"docker": {"image": "$IMAGE", "name": "paaster", "port": "$PORT:3000", "volumes": ["/data"], "extra_ports": ["9001:9001"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deployment, access Paaster via the main domain. Pastes are E2EE by\ndefault. Uses built-in MinIO for storage. If using MinIO, create the bucket\n\"paaster\" in the MinIO console (minio-$(domain):9001) or via mc CLI:\nmc mb minio_instance/paaster; mc anonymous set none minio_instance/paaster.\nFor external S3/R2, set S3 env vars on the Paaster service.\n"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('pairdrop', 'PairDrop', 'PairDrop is an open-source peer-to-peer file sharing application designed for seamless and secure data transfer between devices on the same network. With its minimalist design and cross-platform compatibility, PairDrop ensures a user-friendly and efficient file sharing experience. It eliminates the need for third-party cloud services, offering a direct and private solution for sharing files, links, and other data securely.', 'file-sharing', ARRAY['File Sharing', 'Peer-to-Peer', 'Cross-Platform', 'Open Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/pairdrop:1.11.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "PairDrop", "version": "latest", "description": "PairDrop is an open-source peer-to-peer file sharing application designed for seamless and secure data transfer between devices on the same network. With its minimalist design and cross-platform compatibility, PairDrop ensures a user-friendly and efficient file sharing experience. It eliminates the need for third-party cloud services, offering a direct and private solution for sharing files, links, and other data securely.", "category": "file-sharing", "tags": ["File Sharing", "Peer-to-Peer", "Cross-Platform", "Open Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/pairdrop:1.11.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://pairdrop.net"}, {"label": "Documentation", "url": "https://pairdrop.net/docs"}, {"label": "Github", "url": "https://github.com/schlagmichdoch/pairdrop"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "pairdrop", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('paisa', 'Paisa', 'Paisa is a personal finance manager and expense tracker that helps you manage your finances, track expenses, and visualize your financial data.', 'finance', ARRAY['Finance', 'Budgeting', 'Expense Tracker', 'Self-Hosted', 'Personal Finance'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ananthakumaran/paisa:v0.7.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 7500}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Paisa", "version": "latest", "description": "Paisa is a personal finance manager and expense tracker that helps you manage your finances, track expenses, and visualize your financial data.", "category": "finance", "tags": ["Finance", "Budgeting", "Expense Tracker", "Self-Hosted", "Personal Finance"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ananthakumaran/paisa:v0.7.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 7500}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://paisa.fyi"}, {"label": "GitHub", "url": "https://github.com/ananthakumaran/paisa"}, {"label": "Documentation", "url": "https://paisa.fyi/reference/accounts/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "paisa", "port": "$PORT:7500", "volumes": ["/root/Documents/paisa/"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('palmr', 'Palmr', 'Palmr is a self-hosted file management and download application that provides a comprehensive solution for managing files and downloads. It features a modern web interface for file operations, download management, and file organization. Palmr supports various file operations including uploading, downloading, organizing, and managing your files in a centralized location.', 'file-management', ARRAY['File Management', 'Download Manager', 'Self-Hosted', 'Web Interface', 'File Storage', 'Download Queue', 'Memory Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "kyantech/palmr:v3.1.1-rc.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5487}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Palmr", "version": "latest", "description": "Palmr is a self-hosted file management and download application that provides a comprehensive solution for managing files and downloads. It features a modern web interface for file operations, download management, and file organization. Palmr supports various file operations including uploading, downloading, organizing, and managing your files in a centralized location.", "category": "file-management", "tags": ["File Management", "Download Manager", "Self-Hosted", "Web Interface", "File Storage", "Download Queue", "Memory Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "kyantech/palmr:v3.1.1-rc.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5487}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/kyantech/palmr"}, {"label": "Documentation", "url": "https://palmr.kyantech.com.br/docs/2.0.0-beta"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "palmr", "port": "$PORT:5487", "volumes": ["/app/server"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('papercups', 'Papercups', 'Papercups is a privacy-focused, open-source app designed to streamline communication with your customers. It provides a powerful dashboard to coordinate and reply to messages over various platforms including chat, email, Slack, and SMS. The app offers a customizable widget that you can tailor to your brand''s aesthetics, without the need for any coding. Papercups also integrates seamlessly with your existing work environment, eliminating the need to log in to another dashboard. It supports HTML, React, React Native, and Flutter integrations. The app is built with Elixir on top of BEAM for incredible scalability, making it a suitable choice for businesses of all sizes. It also offers personalized support, managing your deployment on your infrastructure while providing the benefits of self-hosting with the reliability and scalability of the cloud.', 'customer-support', ARRAY['Customer Support', 'Communication', 'Privacy'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "papercups/papercups:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Papercups", "version": "latest", "description": "Papercups is a privacy-focused, open-source app designed to streamline communication with your customers. It provides a powerful dashboard to coordinate and reply to messages over various platforms including chat, email, Slack, and SMS. The app offers a customizable widget that you can tailor to your brand's aesthetics, without the need for any coding. Papercups also integrates seamlessly with your existing work environment, eliminating the need to log in to another dashboard. It supports HTML, React, React Native, and Flutter integrations. The app is built with Elixir on top of BEAM for incredible scalability, making it a suitable choice for businesses of all sizes. It also offers personalized support, managing your deployment on your infrastructure while providing the benefits of self-hosting with the reliability and scalability of the cloud.", "category": "customer-support", "tags": ["Customer Support", "Communication", "Privacy"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "papercups/papercups:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://papercups.io"}, {"label": "Documentation", "url": "https://docs.papercups.io/"}, {"label": "Github", "url": "https://github.com/papercups-io/papercups"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "papercups", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('paperlessngx', 'Paperless-ngx', 'Paperless-ngx is a modern document management system designed to convert your physical documents into a searchable online archive, helping you maintain a clutter-free, paperless environment. It uses advanced OCR technology to add selectable text to image-only documents, and allows you to organize and index your scanned documents with tags, correspondents, types, and more. The app supports a variety of file formats including PDFs, images, plain text files, and Office documents. It also features a single-page application front end with a dashboard that displays basic statistics and allows document upload. With its full-text search functionality, you can easily find the documents you need, with results sorted by relevance to your search query. The app also includes email processing, enabling it to add documents from your email accounts. Moreover, Paperless-ngx is powered by machine learning, enabling it to learn from your documents and automatically assign tags, correspondents, and types to documents once you''ve stored a few documents in it. It is optimized for multi-core systems, allowing it to process multiple documents in parallel.', 'documents', ARRAY['Documents', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "paperlessngx/paperless-ngx:2.20.15"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Paperless-ngx", "version": "latest", "description": "Paperless-ngx is a modern document management system designed to convert your physical documents into a searchable online archive, helping you maintain a clutter-free, paperless environment. It uses advanced OCR technology to add selectable text to image-only documents, and allows you to organize and index your scanned documents with tags, correspondents, types, and more. The app supports a variety of file formats including PDFs, images, plain text files, and Office documents. It also features a single-page application front end with a dashboard that displays basic statistics and allows document upload. With its full-text search functionality, you can easily find the documents you need, with results sorted by relevance to your search query. The app also includes email processing, enabling it to add documents from your email accounts. Moreover, Paperless-ngx is powered by machine learning, enabling it to learn from your documents and automatically assign tags, correspondents, and types to documents once you've stored a few documents in it. It is optimized for multi-core systems, allowing it to process multiple documents in parallel.", "category": "documents", "tags": ["Documents", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "paperlessngx/paperless-ngx:2.20.15"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://paperless-ngx.readthedocs.io/en/latest/"}, {"label": "Github", "url": "https://github.com/paperless-ngx/paperless-ngx"}], "instructions": "Please use the following credentials to login. admin|password", "install": [{"docker": {"image": "$IMAGE", "name": "paperlessngx", "port": "$PORT:8000", "volumes": ["/usr/src/paperless/consume", "/usr/src/paperless/data", "/usr/src/paperless/export", "/usr/src/paperless/media"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Please use the following credentials to login. admin|password"}, "services": {"redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('papermerge', 'Papermerge', 'Papermerge is an open-source document management system (DMS) designed to help you digitize, store, and organize documents efficiently. It simplifies document workflows with features like automated OCR, smart categorization, and role-based access control. By centralizing all your documents in a single platform, Papermerge enables teams to improve collaboration and streamline document handling processes.', 'document-management', ARRAY['Document Management', 'OCR', 'Workflow Automation', 'Open-Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "papermerge/papermerge:3.5.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Papermerge", "version": "latest", "description": "Papermerge is an open-source document management system (DMS) designed to help you digitize, store, and organize documents efficiently. It simplifies document workflows with features like automated OCR, smart categorization, and role-based access control. By centralizing all your documents in a single platform, Papermerge enables teams to improve collaboration and streamline document handling processes.", "category": "document-management", "tags": ["Document Management", "OCR", "Workflow Automation", "Open-Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "papermerge/papermerge:3.5.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://docs.papermerge.io/3.3/"}, {"label": "GitHub", "url": "https://github.com/ciur/papermerge"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "papermerge", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('papra', 'Papra', 'Papra is a modern, open-source project management and collaboration platform designed to help teams organize their work, track progress, and collaborate effectively. It provides a comprehensive suite of tools for task management, team communication, file sharing, and project tracking in a single, integrated platform. Papra offers an intuitive interface with powerful features for managing complex projects and workflows.', 'project-management', ARRAY['Project Management', 'Team Collaboration', 'Task Management', 'Self-Hosted', 'Productivity', 'Workflow', 'Communication', 'File Sharing', 'Progress Tracking', 'Mobile Access'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/papra-hq/papra:0.9.1-rootless"}, "port": {"type": "integer", "title": "Port HTTP", "default": 1221}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Papra", "version": "latest", "description": "Papra is a modern, open-source project management and collaboration platform designed to help teams organize their work, track progress, and collaborate effectively. It provides a comprehensive suite of tools for task management, team communication, file sharing, and project tracking in a single, integrated platform. Papra offers an intuitive interface with powerful features for managing complex projects and workflows.", "category": "project-management", "tags": ["Project Management", "Team Collaboration", "Task Management", "Self-Hosted", "Productivity", "Workflow", "Communication", "File Sharing", "Progress Tracking", "Mobile Access"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/papra-hq/papra:0.9.1-rootless"}, "port": {"type": "integer", "title": "Port HTTP", "default": 1221}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/papra-hq/papra"}, {"label": "Documentation", "url": "https://docs.papra.app"}, {"label": "Website", "url": "https://papra.app"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "papra", "port": "$PORT:1221", "volumes": ["/app/app-data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('passbolt', 'Passbolt', 'Passbolt is a security-first, open source password manager designed for teams and businesses. It is trusted by thousands of organizations worldwide, including Fortune 500 companies, defense industry, universities, startups, and many others. The app puts security first, with top penetration testers regularly assessing its software. It supports user-owned secret keys and end-to-end encryption even in complex scenarios. Passbolt is also built for collaboration, allowing organizations and teams to securely share credentials with powerful auditing tools. It offers unparalleled granularity for both access controls and encrypted data. The app is headquartered in the EU, ensuring that privacy is not only a top priority but also guaranteed by law. Passbolt can be used from your browser or mobile phone, with real-time sharing. It also supports programmatic password retrieval, storage, and sharing with its JSON API.', 'security', ARRAY['Security', 'Password Manager', 'Collaboration'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "passbolt/passbolt:5.11.0-1-ce"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Passbolt", "version": "latest", "description": "Passbolt is a security-first, open source password manager designed for teams and businesses. It is trusted by thousands of organizations worldwide, including Fortune 500 companies, defense industry, universities, startups, and many others. The app puts security first, with top penetration testers regularly assessing its software. It supports user-owned secret keys and end-to-end encryption even in complex scenarios. Passbolt is also built for collaboration, allowing organizations and teams to securely share credentials with powerful auditing tools. It offers unparalleled granularity for both access controls and encrypted data. The app is headquartered in the EU, ensuring that privacy is not only a top priority but also guaranteed by law. Passbolt can be used from your browser or mobile phone, with real-time sharing. It also supports programmatic password retrieval, storage, and sharing with its JSON API.", "category": "security", "tags": ["Security", "Password Manager", "Collaboration"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "passbolt/passbolt:5.11.0-1-ce"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://passbolt.com"}, {"label": "Documentation", "url": "https://help.passbolt.com"}, {"label": "Github", "url": "https://github.com/passbolt/"}], "instructions": "In order to create the first admin account, the following needs to be executed inside the passpolt container \"su -m -c \"bin/cake passbolt register_user -u YOUR@EMAIL.COM -f YOURNAME -l SURNAME -r admin\" -s /bin/sh www-data\". Please follow further instructions of the command output.", "install": [{"docker": {"image": "$IMAGE", "name": "passbolt", "port": "$PORT:80", "volumes": ["/etc/passbolt/gpg", "/etc/passbolt/jwt"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "In order to create the first admin account, the following needs to be executed inside the passpolt container \"su -m -c \"bin/cake passbolt register_user -u YOUR@EMAIL.COM -f YOURNAME -l SURNAME -r admin\" -s /bin/sh www-data\". Please follow further instructions of the command output."}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('passky', 'Passky Server', 'Passky is a simple, modern, lightweight, open source and secure password manager. It allows you to securely store and manage your passwords, ensuring your sensitive credentials remain protected. This self-hosted server component works with the Passky clients (web, desktop, and mobile apps) to provide a complete password management solution that puts you in control of your data.', 'password-manager', ARRAY['Password Manager', 'Security', 'Authentication', 'Self-Hosted', 'Privacy'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "rabbitcompany/passky-server:8.1.8"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Passky Server", "version": "latest", "description": "Passky is a simple, modern, lightweight, open source and secure password manager. It allows you to securely store and manage your passwords, ensuring your sensitive credentials remain protected. This self-hosted server component works with the Passky clients (web, desktop, and mobile apps) to provide a complete password management solution that puts you in control of your data.", "category": "password-manager", "tags": ["Password Manager", "Security", "Authentication", "Self-Hosted", "Privacy"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "rabbitcompany/passky-server:8.1.8"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://passky.org"}, {"label": "GitHub", "url": "https://github.com/Rabbit-Company/Passky-Server"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/rabbitcompany/passky-server"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "passky", "port": "$PORT:80", "volumes": ["/var/www/html/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('passwordpusher', 'Password Pusher', 'Password Pusher is an open-source, self-hosted application designed to securely share passwords and sensitive information via unique, time-sensitive URLs. It eliminates the need to send sensitive credentials through insecure channels like email or messaging apps. The app is lightweight, easy to deploy, and prioritizes user privacy and security. Password Pusher allows for fine-grained control over link expiration, including the number of views or days before a link expires. It ensures that shared passwords are destroyed after expiration, adding an extra layer of security. The app can be deployed on various platforms such as Docker or Kubernetes, making it highly flexible and accessible for individuals and organizations alike.', 'security', ARRAY['Security', 'Password Sharing', 'Privacy'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "pglombardo/pwpush:1.68"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Password Pusher", "version": "latest", "description": "Password Pusher is an open-source, self-hosted application designed to securely share passwords and sensitive information via unique, time-sensitive URLs. It eliminates the need to send sensitive credentials through insecure channels like email or messaging apps. The app is lightweight, easy to deploy, and prioritizes user privacy and security. Password Pusher allows for fine-grained control over link expiration, including the number of views or days before a link expires. It ensures that shared passwords are destroyed after expiration, adding an extra layer of security. The app can be deployed on various platforms such as Docker or Kubernetes, making it highly flexible and accessible for individuals and organizations alike.", "category": "security", "tags": ["Security", "Password Sharing", "Privacy"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "pglombardo/pwpush:1.68"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://pwpush.com"}, {"label": "Documentation", "url": "https://github.com/pglombardo/PasswordPusher/wiki"}, {"label": "Github", "url": "https://github.com/pglombardo/PasswordPusher"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "passwordpusher", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('pastefy', 'Pastefy', 'Pastefy is a feature-rich, open-source, self-hostable pastebin alternative to GitHub Gist or Pastebin. Share code snippets with friends or save them for yourself with syntax highlighting, file format previews, folder organization, OAuth2 authentication, API access, and powerful features for developers. Upload files via curl, integrate with VS Code, and enjoy extensive format support including Markdown, Mermaid, CSV, GeoJSON, and more.', 'pastebin', ARRAY['Pastebin', 'Code Sharing', 'API', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "interaapps/pastefy:7.2.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Pastefy", "version": "latest", "description": "Pastefy is a feature-rich, open-source, self-hostable pastebin alternative to GitHub Gist or Pastebin. Share code snippets with friends or save them for yourself with syntax highlighting, file format previews, folder organization, OAuth2 authentication, API access, and powerful features for developers. Upload files via curl, integrate with VS Code, and enjoy extensive format support including Markdown, Mermaid, CSV, GeoJSON, and more.", "category": "pastebin", "tags": ["Pastebin", "Code Sharing", "API", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "interaapps/pastefy:7.2.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://pastefy.app/"}, {"label": "Documentation", "url": "https://github.com/interaapps/pastefy/wiki"}, {"label": "Github", "url": "https://github.com/interaapps/pastefy"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "pastefy", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('paymenter', 'Paymenter', 'Paymenter is a modern, open-source billing and client management system. It provides a seamless platform for handling payments, subscriptions, and client services with support for multiple payment gateways and automated billing processes.', 'billing', ARRAY['Billing', 'Payment', 'Client Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/paymenter/paymenter:v1.4.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Paymenter", "version": "latest", "description": "Paymenter is a modern, open-source billing and client management system. It provides a seamless platform for handling payments, subscriptions, and client services with support for multiple payment gateways and automated billing processes.", "category": "billing", "tags": ["Billing", "Payment", "Client Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/paymenter/paymenter:v1.4.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://paymenter.org"}, {"label": "Documentation", "url": "https://paymenter.org/docs/getting-started/introduction"}, {"label": "Github", "url": "https://github.com/paymenter/paymenter"}], "instructions": "Connect the shell and run \"php artisan app:init\" to initialize the application, and paste your domain inside. Secondly, create an admin user on the same shell using \"php artisan app:user:create\".", "install": [{"docker": {"image": "$IMAGE", "name": "paymenter", "port": "$PORT:80", "volumes": ["/app/var", "/app/storage/logs", "/app/storage/public"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Connect the shell and run \"php artisan app:init\" to initialize the application, and paste your domain inside. Secondly, create an admin user on the same shell using \"php artisan app:user:create\"."}, "services": {"mysql": {"type": "mysql", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('pdfding', 'PdfDing', 'PdfDing is a self-hosted PDF management and processing application that provides a comprehensive solution for handling PDF documents. It offers features for viewing, organizing, and managing PDF files with a clean web interface. PdfDing supports various PDF operations including viewing, searching, and organizing your PDF collection in a centralized location.', 'pdf-management', ARRAY['PDF Management', 'Document Viewer', 'Self-Hosted', 'Web Interface', 'SQLite', 'File Management', 'Document Organization'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "mrmn/pdfding:v1.7.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "PdfDing", "version": "latest", "description": "PdfDing is a self-hosted PDF management and processing application that provides a comprehensive solution for handling PDF documents. It offers features for viewing, organizing, and managing PDF files with a clean web interface. PdfDing supports various PDF operations including viewing, searching, and organizing your PDF collection in a centralized location.", "category": "pdf-management", "tags": ["PDF Management", "Document Viewer", "Self-Hosted", "Web Interface", "SQLite", "File Management", "Document Organization"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "mrmn/pdfding:v1.7.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/mrmn2/PdfDing"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "pdfding", "port": "$PORT:8000", "volumes": ["/home/nonroot/pdfding/db", "/home/nonroot/pdfding/media"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('peertube', 'PeerTube', 'PeerTube is a revolutionary video sharing tool developed by Framasoft, a French non-profit organization. It offers an alternative to mainstream video platforms, allowing you to establish your own video platform with complete independence. Unlike other platforms, PeerTube doesn''t rely on opaque algorithms or obscure moderation policies. The platforms you visit are built, managed, and moderated by their owners. PeerTube also enables platforms to connect with each other, forming a large network of autonomous yet interconnected platforms. Importantly, PeerTube doesn''t depend on advertising and doesn''t track your activities. It hosts a wide variety of content, with over 600,000 videos across 1,000 platforms in the PeerTube network. PeerTube is free, open-source, and created for non-commercial purposes, ensuring that you are treated as a person, not a product. It is a tool that truly belongs to you and respects your fundamental freedoms as a user.', 'media', ARRAY['Media', 'Video', 'Social Networking'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "chocobozzz/peertube:v8.1.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "PeerTube", "version": "latest", "description": "PeerTube is a revolutionary video sharing tool developed by Framasoft, a French non-profit organization. It offers an alternative to mainstream video platforms, allowing you to establish your own video platform with complete independence. Unlike other platforms, PeerTube doesn't rely on opaque algorithms or obscure moderation policies. The platforms you visit are built, managed, and moderated by their owners. PeerTube also enables platforms to connect with each other, forming a large network of autonomous yet interconnected platforms. Importantly, PeerTube doesn't depend on advertising and doesn't track your activities. It hosts a wide variety of content, with over 600,000 videos across 1,000 platforms in the PeerTube network. PeerTube is free, open-source, and created for non-commercial purposes, ensuring that you are treated as a person, not a product. It is a tool that truly belongs to you and respects your fundamental freedoms as a user.", "category": "media", "tags": ["Media", "Video", "Social Networking"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "chocobozzz/peertube:v8.1.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://joinpeertube.org/"}, {"label": "Documentation", "url": "https://docs.joinpeertube.org/"}, {"label": "Github", "url": "https://github.com/Chocobozzz/PeerTube"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "peertube", "port": "$PORT:9000", "volumes": ["/app/client/dist", "/data", "/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('penpot', 'Penpot', 'Penpot is an open-source, design and prototyping platform that empowers teams to collaborate and bring creative ideas to life. Unlike other design tools, Penpot is entirely web-based and runs on open standards, allowing teams to access it from anywhere and on any platform. Trusted by designers and developers worldwide, Penpot is known for its flexibility and integration within diverse workflows. It offers real-time collaboration, making it easy for team members to co-create, review, and provide feedback instantly. The app supports complex design requirements, from vector editing to responsive design, and prioritizes user control over projects with extensive customization options. Penpot is built by a team dedicated to privacy and security, with a strong commitment to open-source principles. It ensures that designers and developers alike have the freedom to innovate without restrictions, providing a transparent, community-driven alternative to proprietary tools.', 'design', ARRAY['Design', 'Prototyping', 'Collaboration', 'Open Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "penpotapp/frontend:2.14.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Penpot", "version": "latest", "description": "Penpot is an open-source, design and prototyping platform that empowers teams to collaborate and bring creative ideas to life. Unlike other design tools, Penpot is entirely web-based and runs on open standards, allowing teams to access it from anywhere and on any platform. Trusted by designers and developers worldwide, Penpot is known for its flexibility and integration within diverse workflows. It offers real-time collaboration, making it easy for team members to co-create, review, and provide feedback instantly. The app supports complex design requirements, from vector editing to responsive design, and prioritizes user control over projects with extensive customization options. Penpot is built by a team dedicated to privacy and security, with a strong commitment to open-source principles. It ensures that designers and developers alike have the freedom to innovate without restrictions, providing a transparent, community-driven alternative to proprietary tools.", "category": "design", "tags": ["Design", "Prototyping", "Collaboration", "Open Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "penpotapp/frontend:2.14.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://penpot.app"}, {"label": "Documentation", "url": "https://help.penpot.app"}, {"label": "Github", "url": "https://github.com/penpot"}], "instructions": "In order to configure email invitations for team members, please configure the environment variables provided in backend configuration.", "install": [{"docker": {"image": "$IMAGE", "name": "penpot", "port": "$PORT:80", "volumes": ["/opt/data/assets", "/opt/data/assets"], "extra_ports": ["8080:8080"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "In order to configure email invitations for team members, please configure the environment variables provided in backend configuration."}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('peppermint', 'Peppermint', 'Peppermint is a cutting-edge, open-source issue management and helpdesk platform designed to rival Jira and Zendesk while remaining cost-effective and highly customizable. Built with the user in mind, Peppermint empowers teams to manage support tickets, customer requests, and projects with efficiency and ease.', 'issue-management', ARRAY['Issue Management', 'Helpdesk', 'Open-Source', 'Self-Hosted', 'Analytics'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "pepperlabs/peppermint:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Peppermint", "version": "latest", "description": "Peppermint is a cutting-edge, open-source issue management and helpdesk platform designed to rival Jira and Zendesk while remaining cost-effective and highly customizable. Built with the user in mind, Peppermint empowers teams to manage support tickets, customer requests, and projects with efficiency and ease.", "category": "issue-management", "tags": ["Issue Management", "Helpdesk", "Open-Source", "Self-Hosted", "Analytics"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "pepperlabs/peppermint:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://peppermint.sh/"}, {"label": "Github", "url": "https://github.com/Peppermint-Lab/peppermint"}], "instructions": "Default credentials are; email; admin@admin.com, password; 1234", "install": [{"docker": {"image": "$IMAGE", "name": "peppermint", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Default credentials are; email; admin@admin.com, password; 1234"}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('pgadmin', 'Pgadmin', 'PGAdmin is a popular open-source administration and management tool for PostgreSQL databases. It provides a web-based interface to interact with PostgreSQL databases, allowing users to create, modify, and manage databases, tables, roles, and queries with ease. PGAdmin supports advanced query execution, database performance analysis, and extensive user management capabilities. With a modern and intuitive UI, it is designed for database administrators, developers, and analysts to efficiently work with PostgreSQL databases. Additional features include SQL query editor, ERD diagrams, scheduled backups, and monitoring tools.', 'database-management', ARRAY['Database Management', 'PostgreSQL', 'Web UI', 'Administration'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "dpage/pgadmin4:9.14"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Pgadmin", "version": "latest", "description": "PGAdmin is a popular open-source administration and management tool for PostgreSQL databases. It provides a web-based interface to interact with PostgreSQL databases, allowing users to create, modify, and manage databases, tables, roles, and queries with ease. PGAdmin supports advanced query execution, database performance analysis, and extensive user management capabilities. With a modern and intuitive UI, it is designed for database administrators, developers, and analysts to efficiently work with PostgreSQL databases. Additional features include SQL query editor, ERD diagrams, scheduled backups, and monitoring tools.", "category": "database-management", "tags": ["Database Management", "PostgreSQL", "Web UI", "Administration"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "dpage/pgadmin4:9.14"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://www.pgadmin.org/docs/"}, {"label": "Github", "url": "https://github.com/pgadmin-org/pgadmin4"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "pgadmin", "port": "$PORT:80", "volumes": ["/var/lib/pgadmin"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('pgbackweb', 'PgBackWeb', 'PgBackWeb is a comprehensive web-based backup solution for PostgreSQL databases. It provides an intuitive interface to manage, schedule, and monitor PostgreSQL backups with support for multiple backup destinations including local storage and S3-compatible object storage. The application allows you to configure automated backup schedules, manage retention policies, and restore databases through a user-friendly web interface. PgBackWeb ensures your PostgreSQL databases are safely backed up with encryption support, making it an essential tool for database administrators who need reliable backup management without complex command-line operations. It supports multiple PostgreSQL instances and provides detailed backup logs and notifications.', 'database', ARRAY['Database', 'Backup', 'PostgreSQL', 'Data Management', 'Database Tools', 'Self-Hosted', 'Disaster Recovery', 'Automation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "eduardolat/pgbackweb:0.5.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8085}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "PgBackWeb", "version": "latest", "description": "PgBackWeb is a comprehensive web-based backup solution for PostgreSQL databases. It provides an intuitive interface to manage, schedule, and monitor PostgreSQL backups with support for multiple backup destinations including local storage and S3-compatible object storage. The application allows you to configure automated backup schedules, manage retention policies, and restore databases through a user-friendly web interface. PgBackWeb ensures your PostgreSQL databases are safely backed up with encryption support, making it an essential tool for database administrators who need reliable backup management without complex command-line operations. It supports multiple PostgreSQL instances and provides detailed backup logs and notifications.", "category": "database", "tags": ["Database", "Backup", "PostgreSQL", "Data Management", "Database Tools", "Self-Hosted", "Disaster Recovery", "Automation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "eduardolat/pgbackweb:0.5.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8085}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/eduardolat/pgbackweb"}, {"label": "Documentation", "url": "https://github.com/eduardolat/pgbackweb#readme"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "pgbackweb", "port": "$PORT:8085", "volumes": ["/backups"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('pghero', 'PgHero', 'PgHero is a powerful performance dashboard for PostgreSQL databases that provides real-time insights into query performance, slow queries, index usage, and database health metrics. It helps database administrators and developers optimize their PostgreSQL databases by identifying performance bottlenecks, unused indexes, and query patterns. The dashboard features an intuitive web interface with detailed analytics and recommendations for database optimization.', 'postgresql', ARRAY['PostgreSQL', 'Database', 'Monitoring', 'Performance', 'Analytics', 'Dashboard'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ankane/pghero:v3.8.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "PgHero", "version": "latest", "description": "PgHero is a powerful performance dashboard for PostgreSQL databases that provides real-time insights into query performance, slow queries, index usage, and database health metrics. It helps database administrators and developers optimize their PostgreSQL databases by identifying performance bottlenecks, unused indexes, and query patterns. The dashboard features an intuitive web interface with detailed analytics and recommendations for database optimization.", "category": "postgresql", "tags": ["PostgreSQL", "Database", "Monitoring", "Performance", "Analytics", "Dashboard"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ankane/pghero:v3.8.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/ankane/pghero"}, {"label": "Documentation", "url": "https://github.com/ankane/pghero#readme"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "pghero", "port": "$PORT:8080", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('pgvector', 'pgvector', 'pgvector is an open-source app designed to facilitate vector similarity search for Postgres. It allows you to store all your application data in one place, supporting both exact and approximate nearest neighbor search. The app is capable of handling L2 distance, inner product, and cosine distance, making it versatile for various data analysis needs. It is compatible with any language that has a Postgres client. The app also boasts of ACID compliance, point-in-time recovery, JOINs, and all the other great features of Postgres. With pgvector, you can create a new table with a vector column or add a vector column to an existing table, insert vectors, upsert vectors, update vectors, and delete vectors. It also allows you to get the nearest neighbors to a vector or a row, and get rows within a certain distance. The app also supports indexing for improved search performance. It is a powerful tool for managing and analyzing your data in a Postgres environment.', 'databases', ARRAY['Databases', 'Data Science'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "pgvector", "version": "latest", "description": "pgvector is an open-source app designed to facilitate vector similarity search for Postgres. It allows you to store all your application data in one place, supporting both exact and approximate nearest neighbor search. The app is capable of handling L2 distance, inner product, and cosine distance, making it versatile for various data analysis needs. It is compatible with any language that has a Postgres client. The app also boasts of ACID compliance, point-in-time recovery, JOINs, and all the other great features of Postgres. With pgvector, you can create a new table with a vector column or add a vector column to an existing table, insert vectors, upsert vectors, update vectors, and delete vectors. It also allows you to get the nearest neighbors to a vector or a row, and get rows within a certain distance. The app also supports indexing for improved search performance. It is a powerful tool for managing and analyzing your data in a Postgres environment.", "category": "databases", "tags": ["Databases", "Data Science"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/pgvector/pgvector"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "pgvector", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('pgweb', 'pgweb', 'Pgweb is a simple, web-based, cross-platform PostgreSQL database explorer. It is designed to work seamlessly on Mac, Linux, and Windows machines. The app is distributed as a single binary with zero dependencies, making it incredibly easy to use. It supports PostgreSQL 9.1 and later versions, and allows for multiple database sessions. With Pgweb, you can execute and analyze custom SQL queries, export table and query data to CSV/JSON/XML, and keep track of your query history. The app also supports native SSH tunnels and server bookmarks for easy navigation.', 'databases', ARRAY['Databases'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "sosedoff/pgweb:0.17.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8081}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "pgweb", "version": "latest", "description": "Pgweb is a simple, web-based, cross-platform PostgreSQL database explorer. It is designed to work seamlessly on Mac, Linux, and Windows machines. The app is distributed as a single binary with zero dependencies, making it incredibly easy to use. It supports PostgreSQL 9.1 and later versions, and allows for multiple database sessions. With Pgweb, you can execute and analyze custom SQL queries, export table and query data to CSV/JSON/XML, and keep track of your query history. The app also supports native SSH tunnels and server bookmarks for easy navigation.", "category": "databases", "tags": ["Databases"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "sosedoff/pgweb:0.17.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8081}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://github.com/sosedoff/pgweb/wiki"}, {"label": "Github", "url": "https://github.com/sosedoff/pgweb"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "pgweb", "port": "$PORT:8081", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('photoprism', 'PhotoPrism', 'PhotoPrism is an AI-powered photos app designed for the decentralized web. It uses the latest technologies to automatically tag and find pictures without interrupting your workflow. You can run it at home, on a private server, or in the cloud. PhotoPrism allows you to browse all your photos and videos without worrying about RAW conversion, duplicates, or video formats. It offers powerful search filters to easily find specific pictures and includes high-resolution world maps to relive your favorite trips. The app supports playing Live Photos by hovering over them in albums and search results, recognizes the faces of your family and friends, and automatically classifies pictures based on their content and location. PhotoPrism is committed to user and privacy-friendly solutions, ensuring your data is never shared without your consent.', 'media', ARRAY['Media', 'Gallery', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "photoprism/photoprism:251130"}, "port": {"type": "integer", "title": "Port HTTP", "default": 2342}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "PhotoPrism", "version": "latest", "description": "PhotoPrism is an AI-powered photos app designed for the decentralized web. It uses the latest technologies to automatically tag and find pictures without interrupting your workflow. You can run it at home, on a private server, or in the cloud. PhotoPrism allows you to browse all your photos and videos without worrying about RAW conversion, duplicates, or video formats. It offers powerful search filters to easily find specific pictures and includes high-resolution world maps to relive your favorite trips. The app supports playing Live Photos by hovering over them in albums and search results, recognizes the faces of your family and friends, and automatically classifies pictures based on their content and location. PhotoPrism is committed to user and privacy-friendly solutions, ensuring your data is never shared without your consent.", "category": "media", "tags": ["Media", "Gallery", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "photoprism/photoprism:251130"}, "port": {"type": "integer", "title": "Port HTTP", "default": 2342}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://photoprism.app"}, {"label": "Demo", "url": "https://try.photoprism.app"}, {"label": "Github", "url": "https://github.com/photoprism/photoprism"}, {"label": "Docker", "url": "https://hub.docker.com/r/photoprism/photoprism"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "photoprism", "port": "$PORT:2342", "volumes": ["/photoprism/originals", "/photoprism/storage"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('photoview', 'Photoview', 'Photoview is a user-friendly photo gallery designed for photographers. It allows you to easily navigate through directories filled with high-resolution photos and videos. The app syncs with your file system, automatically organizing your media based on the file structure. Directories become albums filled with the photos and videos found within them. Photoview also automatically rescans for new media, keeping your gallery updated. Multiple users can be configured, each with their own directory of photos and videos, and each user''s media is kept private with a username and password. Albums and individual photos or videos can be shared through public or password-protected links. Photoview also analyzes photos for EXIF metadata, displaying this information next to the photo and using it to present photos on a map. The app also has a mobile version for iOS, allowing you to quickly access your media library from your phone. Photoview supports RAW images, automatically extracts metadata from images and videos, and optimizes videos for the web. It also generates thumbnails automatically and ensures that your media is secure and private.', 'gallery', ARRAY['Gallery', 'Media', 'Photography', 'Photos', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "photoview/photoview:2.4.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Photoview", "version": "latest", "description": "Photoview is a user-friendly photo gallery designed for photographers. It allows you to easily navigate through directories filled with high-resolution photos and videos. The app syncs with your file system, automatically organizing your media based on the file structure. Directories become albums filled with the photos and videos found within them. Photoview also automatically rescans for new media, keeping your gallery updated. Multiple users can be configured, each with their own directory of photos and videos, and each user's media is kept private with a username and password. Albums and individual photos or videos can be shared through public or password-protected links. Photoview also analyzes photos for EXIF metadata, displaying this information next to the photo and using it to present photos on a map. The app also has a mobile version for iOS, allowing you to quickly access your media library from your phone. Photoview supports RAW images, automatically extracts metadata from images and videos, and optimizes videos for the web. It also generates thumbnails automatically and ensures that your media is secure and private.", "category": "gallery", "tags": ["Gallery", "Media", "Photography", "Photos", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "photoview/photoview:2.4.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://photoview.github.io/"}, {"label": "Github", "url": "https://github.com/photoview/photoview"}, {"label": "Demo", "url": "https://photos.qpqp.dk/"}], "instructions": "After deployment, you need to mount your photos directory to the /photos path.\nThis can be done using bind mounts in Easypanel's advanced settings.\nOn first access, you will be prompted to create an admin user and configure\nthe photo source path (use /photos as the path).\n", "install": [{"docker": {"image": "$IMAGE", "name": "photoview", "port": "$PORT:80", "volumes": ["/home/photoview/media-cache", "/home/photoview/database", "/photos"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deployment, you need to mount your photos directory to the /photos path.\nThis can be done using bind mounts in Easypanel's advanced settings.\nOn first access, you will be prompted to create an admin user and configure\nthe photo source path (use /photos as the path).\n"}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('phpbb', 'phpBB', 'phpBB is a free and open-source bulletin board software that enables you to create online communities and discussion forums. It offers a highly customizable platform with a user-friendly interface that supports multiple languages and includes features like custom BBCode, private messaging, search functionality, and user groups. The Bitnami phpBB container provides a ready-to-use instance of phpBB with all its dependencies, configured for security and performance. This deployment includes both the phpBB application and a MariaDB database for storing your forum data.', 'forum', ARRAY['Forum', 'Community', 'Discussion Board', 'Bulletin Board'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "bitnami/phpbb:3.3.12"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "phpBB", "version": "latest", "description": "phpBB is a free and open-source bulletin board software that enables you to create online communities and discussion forums. It offers a highly customizable platform with a user-friendly interface that supports multiple languages and includes features like custom BBCode, private messaging, search functionality, and user groups. The Bitnami phpBB container provides a ready-to-use instance of phpBB with all its dependencies, configured for security and performance. This deployment includes both the phpBB application and a MariaDB database for storing your forum data.", "category": "forum", "tags": ["Forum", "Community", "Discussion Board", "Bulletin Board"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "bitnami/phpbb:3.3.12"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.phpbb.com/"}, {"label": "Documentation", "url": "https://www.phpbb.com/support/documentation/"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/bitnami/phpbb"}], "instructions": "Login to the phpBB forum via the provided URL. During the first login, use the username \"admin\" and the passowrd is \"admin\"", "install": [{"docker": {"image": "$IMAGE", "name": "phpbb", "port": "$PORT:8080", "volumes": ["/bitnami/phpbb"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Login to the phpBB forum via the provided URL. During the first login, use the username \"admin\" and the passowrd is \"admin\""}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('phpmyadmin', 'phpMyAdmin', 'phpMyAdmin is a free software tool designed to manage MySQL over the web. This powerful tool supports a broad spectrum of operations on MySQL and MariaDB. It allows you to perform frequently used operations such as managing databases, tables, columns, relations, indexes, users, permissions, and more through its user-friendly interface. Additionally, it provides the flexibility to directly execute any SQL statement. phpMyAdmin also features an intuitive web interface and supports most MySQL features. You can browse and drop databases, tables, views, fields, and indexes; create, copy, drop, rename, and alter databases, tables, fields, and indexes; manage MySQL user accounts and privileges; and much more. It also allows you to import data from CSV and SQL, export data to various formats, administer multiple servers, create graphics of your database layout in various formats, and create complex queries using Query-by-example (QBE).', 'databases', ARRAY['Databases', 'Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "phpmyadmin:5.2.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "phpMyAdmin", "version": "latest", "description": "phpMyAdmin is a free software tool designed to manage MySQL over the web. This powerful tool supports a broad spectrum of operations on MySQL and MariaDB. It allows you to perform frequently used operations such as managing databases, tables, columns, relations, indexes, users, permissions, and more through its user-friendly interface. Additionally, it provides the flexibility to directly execute any SQL statement. phpMyAdmin also features an intuitive web interface and supports most MySQL features. You can browse and drop databases, tables, views, fields, and indexes; create, copy, drop, rename, and alter databases, tables, fields, and indexes; manage MySQL user accounts and privileges; and much more. It also allows you to import data from CSV and SQL, export data to various formats, administer multiple servers, create graphics of your database layout in various formats, and create complex queries using Query-by-example (QBE).", "category": "databases", "tags": ["Databases", "Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "phpmyadmin:5.2.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.phpmyadmin.net/"}, {"label": "Documentation", "url": "https://www.phpmyadmin.net/docs/"}, {"label": "Github", "url": "https://github.com/phpmyadmin/phpmyadmin"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "phpmyadmin", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('pic-o', 'Pic-O', 'Pic-O is a modern self-hosted photo gallery application with a clean web interface for browsing and organizing image collections. This template deploys Pic-O with a MariaDB backend and preconfigured application settings so the app and database communicate correctly at first startup.', 'photos', ARRAY['Photos', 'Gallery', 'MariaDB', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "xirtnl/pic-o:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Pic-O", "version": "latest", "description": "Pic-O is a modern self-hosted photo gallery application with a clean web interface for browsing and organizing image collections. This template deploys Pic-O with a MariaDB backend and preconfigured application settings so the app and database communicate correctly at first startup.", "category": "photos", "tags": ["Photos", "Gallery", "MariaDB", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "xirtnl/pic-o:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://github.com/Xirt/Pic-O#readme"}, {"label": "GitHub", "url": "https://github.com/Xirt/Pic-O"}], "instructions": "Deploy the template and wait until both services are healthy, then open the configured domain to access the Pic-O interface and complete initial setup in the web UI.", "install": [{"docker": {"image": "$IMAGE", "name": "pic-o", "port": "$PORT:80", "volumes": ["/var/www/resources/photos", "/var/www/storage/app"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Deploy the template and wait until both services are healthy, then open the configured domain to access the Pic-O interface and complete initial setup in the web UI."}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('picoshare', 'Picoshare', 'Picoshare is a lightweight, self-hosted file-sharing platform designed for simplicity and privacy. It provides a minimalistic interface for uploading, sharing, and managing files, without the complexity of traditional cloud storage services. Picoshare emphasizes ease of use and security, making it an ideal solution for personal or small team file-sharing needs. It supports a variety of file types and provides a secure, private environment for sharing files with full control over your data.', 'file-sharing', ARRAY['File Sharing', 'Privacy', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "mtlynch/picoshare:1.5.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4001}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Picoshare", "version": "latest", "description": "Picoshare is a lightweight, self-hosted file-sharing platform designed for simplicity and privacy. It provides a minimalistic interface for uploading, sharing, and managing files, without the complexity of traditional cloud storage services. Picoshare emphasizes ease of use and security, making it an ideal solution for personal or small team file-sharing needs. It supports a variety of file types and provides a secure, private environment for sharing files with full control over your data.", "category": "file-sharing", "tags": ["File Sharing", "Privacy", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "mtlynch/picoshare:1.5.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4001}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://picoshare.net/"}, {"label": "Documentation", "url": "https://github.com/mtlynch/picoshare/wiki"}, {"label": "Github", "url": "https://github.com/mtlynch/picoshare"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "picoshare", "port": "$PORT:4001", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('picsur', 'Picsur', 'Picsur is a simple and fast image hosting service. It provides a user-friendly interface for uploading, managing, and sharing images with support for various image formats and features.', 'image-hosting', ARRAY['Image Hosting', 'File Sharing', 'PostgreSQL', 'Web Interface'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/caramelfur/picsur:0.5.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Picsur", "version": "latest", "description": "Picsur is a simple and fast image hosting service. It provides a user-friendly interface for uploading, managing, and sharing images with support for various image formats and features.", "category": "image-hosting", "tags": ["Image Hosting", "File Sharing", "PostgreSQL", "Web Interface"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/caramelfur/picsur:0.5.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/caramelfur/picsur"}, {"label": "Documentation", "url": "https://github.com/caramelfur/picsur#readme"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "picsur", "port": "$PORT:8080", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('pidgin', 'Pidgin', 'Pidgin is a versatile chat application that allows you to log into multiple chat networks simultaneously. This means you can chat with friends on XMPP while also participating in an IRC channel. The application supports a wide range of chat networks, including but not limited to Bonjour, Discord, Facebook, Google Talk, Hangouts, ICQ, Instagram, IRC, Skype, Slack, Telegram, and XMPP. This Pidgin installation comes with default chat plugins and a series of third-party ones. The application also includes Firefox to help you fill out captchas or pre-auth before loading your credentials into the program. Pidgin can be accessed at http://yourhost:3000/ or https://yourhost:3001/. The app is designed to provide a seamless and integrated chat experience across multiple platforms.', 'chat', ARRAY['Chat'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/pidgin:2.14.14"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Pidgin", "version": "latest", "description": "Pidgin is a versatile chat application that allows you to log into multiple chat networks simultaneously. This means you can chat with friends on XMPP while also participating in an IRC channel. The application supports a wide range of chat networks, including but not limited to Bonjour, Discord, Facebook, Google Talk, Hangouts, ICQ, Instagram, IRC, Skype, Slack, Telegram, and XMPP. This Pidgin installation comes with default chat plugins and a series of third-party ones. The application also includes Firefox to help you fill out captchas or pre-auth before loading your credentials into the program. Pidgin can be accessed at http://yourhost:3000/ or https://yourhost:3001/. The app is designed to provide a seamless and integrated chat experience across multiple platforms.", "category": "chat", "tags": ["Chat"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/pidgin:2.14.14"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://docs.linuxserver.io/images/docker-pidgin"}, {"label": "Github", "url": "https://github.com/linuxserver/docker-pidgin"}], "instructions": "use abc:abc to login. To access the login interface, add ?login=true to your URL.", "install": [{"docker": {"image": "$IMAGE", "name": "pidgin", "port": "$PORT:3000", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "use abc:abc to login. To access the login interface, add ?login=true to your URL."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('pigeon-pod', 'Pigeon Pod', 'Pigeon Pod is a self-hosted application that converts YouTube channels or playlists into podcast feeds. It supports automatic syncing of new uploads, backfilling historical content, media downloads, and secure RSS feeds compatible with standard podcast players. Built with Spring Boot, Pigeon Pod provides a web interface for managing YouTube subscriptions and generates podcast-compatible RSS feeds that work with any standard podcast player. Perfect for podcast enthusiasts who want to listen to YouTube content as podcasts while maintaining complete control over their data and subscriptions.', 'podcast', ARRAY['Podcast', 'YouTube', 'RSS', 'Self-Hosted', 'Media', 'Audio', 'Video'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/aizhimou/pigeon-pod:release-1.28.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Pigeon Pod", "version": "latest", "description": "Pigeon Pod is a self-hosted application that converts YouTube channels or playlists into podcast feeds. It supports automatic syncing of new uploads, backfilling historical content, media downloads, and secure RSS feeds compatible with standard podcast players. Built with Spring Boot, Pigeon Pod provides a web interface for managing YouTube subscriptions and generates podcast-compatible RSS feeds that work with any standard podcast player. Perfect for podcast enthusiasts who want to listen to YouTube content as podcasts while maintaining complete control over their data and subscriptions.", "category": "podcast", "tags": ["Podcast", "YouTube", "RSS", "Self-Hosted", "Media", "Audio", "Video"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/aizhimou/pigeon-pod:release-1.28.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/aizhimou/pigeon-pod"}, {"label": "Website", "url": "https://pigeonpod.cloud"}, {"label": "Guides", "url": "https://pigeonpod.cloud/guides/"}], "instructions": "Login using the credentials; username=root, password=Root@123", "install": [{"docker": {"image": "$IMAGE", "name": "pigeon-pod", "port": "$PORT:8080", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Login using the credentials; username=root, password=Root@123"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('pihole', 'Pi-hole', 'Pi-hole is a network-wide ad blocker that acts as a DNS sinkhole to protect your devices from unwanted content without installing any client-side software. It blocks ads at the DNS level, meaning ads are blocked before they even reach your devices, resulting in faster browsing, reduced bandwidth usage, and enhanced privacy. Pi-hole provides a powerful web interface for easy management and detailed statistics about your network''s DNS queries. It can block millions of ad-serving domains and supports custom block lists. The application also includes features like DHCP server capabilities, DNS-over-HTTPS (DoH) support, and comprehensive query logging. With Pi-hole, you can monitor all DNS requests on your network, see which domains are being blocked, and maintain complete control over your network''s DNS filtering.', 'privacy', ARRAY['Privacy', 'Security', 'DNS', 'Ad Blocker', 'Network Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "pihole/pihole:2024.07.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 53}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Pi-hole", "version": "latest", "description": "Pi-hole is a network-wide ad blocker that acts as a DNS sinkhole to protect your devices from unwanted content without installing any client-side software. It blocks ads at the DNS level, meaning ads are blocked before they even reach your devices, resulting in faster browsing, reduced bandwidth usage, and enhanced privacy. Pi-hole provides a powerful web interface for easy management and detailed statistics about your network's DNS queries. It can block millions of ad-serving domains and supports custom block lists. The application also includes features like DHCP server capabilities, DNS-over-HTTPS (DoH) support, and comprehensive query logging. With Pi-hole, you can monitor all DNS requests on your network, see which domains are being blocked, and maintain complete control over your network's DNS filtering.", "category": "privacy", "tags": ["Privacy", "Security", "DNS", "Ad Blocker", "Network Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "pihole/pihole:2024.07.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 53}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://pi-hole.net/"}, {"label": "Documentation", "url": "https://docs.pi-hole.net/"}, {"label": "GitHub", "url": "https://github.com/pi-hole/pi-hole"}, {"label": "Docker", "url": "https://hub.docker.com/r/pihole/pihole"}], "instructions": "After the deployment of the Pi-Hole Service, it might not start straight away, you have to stop the systemd-resolved.service, or service which would be occupying the DNS port 53, make sure you also disable that so it doesn't starts on boot.", "install": [{"docker": {"image": "$IMAGE", "name": "pihole", "port": "$PORT:53", "volumes": ["/etc/dnsmasq.d", "/etc/pihole"], "extra_ports": ["67:67", "80:80"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After the deployment of the Pi-Hole Service, it might not start straight away, you have to stop the systemd-resolved.service, or service which would be occupying the DNS port 53, make sure you also disable that so it doesn't starts on boot."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('pinchflat', 'Pinchflat', 'Pinchflat is a modern, self-hosted media management and download application designed for organizing and managing your digital media collection. It provides an intuitive web interface for downloading, organizing, and accessing your media files with support for various formats and sources. Pinchflat offers powerful features for media discovery, automated downloads, and collection management in a clean, user-friendly environment.', 'media-management', ARRAY['Media Management', 'Download Manager', 'Self-Hosted', 'Web Interface', 'File Organization', 'Media Collection', 'Automation', 'Search', 'Multi-Format', 'API'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/kieraneglin/pinchflat:v2025.6.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8945}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Pinchflat", "version": "latest", "description": "Pinchflat is a modern, self-hosted media management and download application designed for organizing and managing your digital media collection. It provides an intuitive web interface for downloading, organizing, and accessing your media files with support for various formats and sources. Pinchflat offers powerful features for media discovery, automated downloads, and collection management in a clean, user-friendly environment.", "category": "media-management", "tags": ["Media Management", "Download Manager", "Self-Hosted", "Web Interface", "File Organization", "Media Collection", "Automation", "Search", "Multi-Format", "API"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/kieraneglin/pinchflat:v2025.6.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8945}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/kieraneglin/pinchflat"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/kieraneglin/pinchflat"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "pinchflat", "port": "$PORT:8945", "volumes": ["/config", "/downloads"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('piwigo', 'piwigo', 'Piwigo is a powerful, self-hosted photo gallery solution designed for managing and organizing your image collections efficiently. It provides a user-friendly web interface, supports a vast array of plugins for extended functionality, and offers advanced photo organization features such as albums, tags, and batch processing. With Piwigo, you can maintain full control over your photo storage and sharing.', 'photo-gallery', ARRAY['Photo Gallery', 'Self-Hosted', 'Image Management', 'Open Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/piwigo:16.4.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "piwigo", "version": "latest", "description": "Piwigo is a powerful, self-hosted photo gallery solution designed for managing and organizing your image collections efficiently. It provides a user-friendly web interface, supports a vast array of plugins for extended functionality, and offers advanced photo organization features such as albums, tags, and batch processing. With Piwigo, you can maintain full control over your photo storage and sharing.", "category": "photo-gallery", "tags": ["Photo Gallery", "Self-Hosted", "Image Management", "Open Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/piwigo:16.4.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://piwigo.org/"}, {"label": "DockerHub", "url": "https://hub.docker.com/r/linuxserver/piwigo"}], "instructions": "Configure the database in the installation wizard.", "install": [{"docker": {"image": "$IMAGE", "name": "piwigo", "port": "$PORT:80", "volumes": ["/gallery", "/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Configure the database in the installation wizard."}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('pixapop', 'Pixapop', 'Pixapop is a modern photo management and sharing application that provides a beautiful web interface for organizing, viewing, and sharing your photo collection. It features automatic photo organization, metadata extraction, and a clean, responsive interface for browsing your photos from any device.', 'photo-management', ARRAY['Photo Management', 'Photo Sharing', 'Self-hosted', 'Web Interface', 'Metadata', 'Organization', 'Gallery', 'LinuxServer'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/pixapop:1.2.20221014"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Pixapop", "version": "latest", "description": "Pixapop is a modern photo management and sharing application that provides a beautiful web interface for organizing, viewing, and sharing your photo collection. It features automatic photo organization, metadata extraction, and a clean, responsive interface for browsing your photos from any device.", "category": "photo-management", "tags": ["Photo Management", "Photo Sharing", "Self-hosted", "Web Interface", "Metadata", "Organization", "Gallery", "LinuxServer"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/pixapop:1.2.20221014"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://github.com/linuxserver-archive/docker-pixapop/blob/master/README.md"}, {"label": "GitHub", "url": "https://github.com/linuxserver/docker-pixapop"}], "instructions": "You need to mount the photos volume to the container to make the application work.", "install": [{"docker": {"image": "$IMAGE", "name": "pixapop", "port": "$PORT:80", "volumes": ["/config", "/photos"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "You need to mount the photos volume to the container to make the application work."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('plane', 'Plane', 'Plane is an open-source project management tool designed to help teams manage tasks, sprints, and product roadmaps efficiently. It offers features like issue tracking, cycles, modules, custom views, pages, and real-time analytics.', 'self-hosted', ARRAY[]::text[], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Plane", "version": "latest", "description": "Plane is an open-source project management tool designed to help teams manage tasks, sprints, and product roadmaps efficiently. It offers features like issue tracking, cycles, modules, custom views, pages, and real-time analytics.", "category": "self-hosted", "tags": [], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://plane.so"}, {"label": "Documentation", "url": "https://docs.plane.so/introduction/home"}, {"label": "Github", "url": "https://github.com/makeplane/plane"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "plane", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('planka', 'Planka', 'Planka is a free, open-source Kanban board designed to streamline project management for workgroups. With Planka, you can create projects, boards, lists, cards, labels, and tasks, all in one place. It allows you to add card members, track time, set due dates, add attachments, and write comments. It also supports markdown in card descriptions and comments. The app provides real-time updates, ensuring all changes in cards or boards are instantly visible to your colleagues. You can customize your project background and filter tasks by members and labels. User notifications keep everyone in the loop about project updates. The app also supports multiple languages, making it a versatile tool for international teams.', 'project-management', ARRAY['Project Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/planka:2.1.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 1337}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Planka", "version": "latest", "description": "Planka is a free, open-source Kanban board designed to streamline project management for workgroups. With Planka, you can create projects, boards, lists, cards, labels, and tasks, all in one place. It allows you to add card members, track time, set due dates, add attachments, and write comments. It also supports markdown in card descriptions and comments. The app provides real-time updates, ensuring all changes in cards or boards are instantly visible to your colleagues. You can customize your project background and filter tasks by members and labels. User notifications keep everyone in the loop about project updates. The app also supports multiple languages, making it a versatile tool for international teams.", "category": "project-management", "tags": ["Project Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/planka:2.1.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 1337}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://planka.app"}, {"label": "Documentation", "url": "https://docs.planka.cloud"}, {"label": "Github", "url": "https://github.com/plankanban/planka"}], "instructions": "Login with demo@demo.demo:demo", "install": [{"docker": {"image": "$IMAGE", "name": "planka", "port": "$PORT:1337", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Login with demo@demo.demo:demo"}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('plausible', 'Plausible', 'Plausible is a simple, lightweight, and open-source web analytics tool that serves as a privacy-friendly alternative to Google Analytics. It is designed to be intuitive and easy to use, providing essential insights about your website''s traffic on a single page, without the need for complex menus or custom reports. The Plausible script is 45 times smaller than Google Analytics, ensuring your site loads faster and contributes to a greener web. It respects user privacy by not using cookies or collecting personal data, and all data processing is carried out anonymously within the EU. Plausible also allows you to track goal conversions, revenue, and campaigns, segment your audience, and analyze referral sources. You can share your stats publicly or privately, invite team members, and even import your historical stats from Google Analytics. It''s a powerful tool for understanding your website''s performance while respecting user privacy.', 'analytics', ARRAY['Analytics', 'Privacy'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "plausible/analytics:v2.0.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Plausible", "version": "latest", "description": "Plausible is a simple, lightweight, and open-source web analytics tool that serves as a privacy-friendly alternative to Google Analytics. It is designed to be intuitive and easy to use, providing essential insights about your website's traffic on a single page, without the need for complex menus or custom reports. The Plausible script is 45 times smaller than Google Analytics, ensuring your site loads faster and contributes to a greener web. It respects user privacy by not using cookies or collecting personal data, and all data processing is carried out anonymously within the EU. Plausible also allows you to track goal conversions, revenue, and campaigns, segment your audience, and analyze referral sources. You can share your stats publicly or privately, invite team members, and even import your historical stats from Google Analytics. It's a powerful tool for understanding your website's performance while respecting user privacy.", "category": "analytics", "tags": ["Analytics", "Privacy"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "plausible/analytics:v2.0.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://plausible.io"}, {"label": "Documentation", "url": "https://plausible.io/docs"}, {"label": "Github", "url": "https://github.com/plausible/plausible"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "plausible", "port": "$PORT:80", "volumes": ["/var/lib/clickhouse", "/etc/clickhouse-server/users.d/logging.xml", "/etc/clickhouse-server/config.d/logging.xml"], "extra_ports": ["8123:8123"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('plex', 'Plex', 'Plex Media Server is a powerful app that makes it easy to manage and stream your media collection to all your devices, anytime, anywhere. With Plex, you can stream your video, music, and photo collections from your phone, tablet, gaming console, smart TV, or any other favorite streaming device. The app is designed to work with three types of networking: bridge, host, and macvlan, each offering a unique way to connect your media server to your devices. Plex also offers advanced features like hardware transcoding support for Intel Quick Sync, making it a versatile choice for all your media streaming needs.', 'media', ARRAY['Media', 'Streaming', 'Video', 'Music', 'Photos'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/plex:1.43.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 32400}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Plex", "version": "latest", "description": "Plex Media Server is a powerful app that makes it easy to manage and stream your media collection to all your devices, anytime, anywhere. With Plex, you can stream your video, music, and photo collections from your phone, tablet, gaming console, smart TV, or any other favorite streaming device. The app is designed to work with three types of networking: bridge, host, and macvlan, each offering a unique way to connect your media server to your devices. Plex also offers advanced features like hardware transcoding support for Intel Quick Sync, making it a versatile choice for all your media streaming needs.", "category": "media", "tags": ["Media", "Streaming", "Video", "Music", "Photos"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/plex:1.43.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 32400}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://support.plex.tv/articles/catagories/plex-media-server"}, {"label": "Github", "url": "https://github.com/plexinc/pms-docker"}], "instructions": "If you get a libusb error, please ignore it.", "install": [{"docker": {"image": "$IMAGE", "name": "plex", "port": "$PORT:32400", "volumes": ["/config", "/tv", "/movies"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "If you get a libusb error, please ignore it."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('ploi-roadmap', 'Ploi Roadmap', 'Roadmap is an open-source software designed to streamline your roadmapping process. It offers a completely customizable platform where you can mention users in comments, upvote items to prioritize them, and generate automatic slugs. The software also features a Filament admin panel and a simplified role system that includes administrator, employee, and user roles. Roadmap supports OAuth 2 single sign-on with your own application and automatically generates OG images, including the branding color you''ve set up. It also integrates with GitHub, allowing you to assign a repository to each project and manage issues directly from the roadmap admin. The software is built with PHP and requires a database to function.', 'project-management', ARRAY['Project Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/easypanel-community/docker-ploi-roadmap:1.44.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Ploi Roadmap", "version": "latest", "description": "Roadmap is an open-source software designed to streamline your roadmapping process. It offers a completely customizable platform where you can mention users in comments, upvote items to prioritize them, and generate automatic slugs. The software also features a Filament admin panel and a simplified role system that includes administrator, employee, and user roles. Roadmap supports OAuth 2 single sign-on with your own application and automatically generates OG images, including the branding color you've set up. It also integrates with GitHub, allowing you to assign a repository to each project and manage issues directly from the roadmap admin. The software is built with PHP and requires a database to function.", "category": "project-management", "tags": ["Project Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/easypanel-community/docker-ploi-roadmap:1.44.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/ploi-deploy/roadmap"}], "instructions": "After First Deployment, run \"php artisan roadmap:install\" to setup the inital user account.", "install": [{"docker": {"image": "$IMAGE", "name": "ploi-roadmap", "port": "$PORT:80", "volumes": ["/vendor", "/app"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After First Deployment, run \"php artisan roadmap:install\" to setup the inital user account."}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('pocketbase', 'PocketBase', 'PocketBase is a powerful backend solution for your next SaaS or Mobile app. It is designed to be ready to use out of the box, providing a realtime database, user authentication, file storage, and an admin dashboard all in one file. The realtime database is embedded and performant, featuring a schema builder, data validations, realtime subscriptions, and an easy-to-use REST API. The authentication feature allows you to manage your app users and handle email/password and OAuth2 sign ups from various platforms like Google, Facebook, GitHub, GitLab without any hassle. The file storage feature allows you to store files locally or in an S3 storage, attach media to your database records, and generate thumbnails on the fly. PocketBase is extendable and can be used as a standalone app or as a Go framework, which you can extend via hooks to create your own custom portable backend. It also provides official client SDKs for seamless integration.', 'databases', ARRAY['Databases', 'Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "spectado/pocketbase:0.23.12"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "PocketBase", "version": "latest", "description": "PocketBase is a powerful backend solution for your next SaaS or Mobile app. It is designed to be ready to use out of the box, providing a realtime database, user authentication, file storage, and an admin dashboard all in one file. The realtime database is embedded and performant, featuring a schema builder, data validations, realtime subscriptions, and an easy-to-use REST API. The authentication feature allows you to manage your app users and handle email/password and OAuth2 sign ups from various platforms like Google, Facebook, GitHub, GitLab without any hassle. The file storage feature allows you to store files locally or in an S3 storage, attach media to your database records, and generate thumbnails on the fly. PocketBase is extendable and can be used as a standalone app or as a Go framework, which you can extend via hooks to create your own custom portable backend. It also provides official client SDKs for seamless integration.", "category": "databases", "tags": ["Databases", "Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "spectado/pocketbase:0.23.12"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://pocketbase.io"}, {"label": "Documentation", "url": "https://pocketbase.io/docs"}, {"label": "Github", "url": "https://github.com/pocketbase/pocketbase"}], "instructions": "Admin Dashboard can be accessed via \"DOMAIN/_/\"\"", "install": [{"docker": {"image": "$IMAGE", "name": "pocketbase", "port": "$PORT:80", "volumes": ["/pb_data", "/pb_public", "/pb_migrations"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Admin Dashboard can be accessed via \"DOMAIN/_/\"\""}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('podfetch', 'Podfetch', 'Podfetch is a self-hosted podcast manager and aggregator that allows you to subscribe to, download, and organize your favorite podcasts from a single centralized interface. It automatically fetches new episodes from RSS feeds at configurable intervals, stores podcast metadata and audio files locally, and provides a web-based interface for browsing and managing your podcast library. The application features automatic episode downloading, customizable polling intervals for checking new content, SQLite database for lightweight data management, and organized file storage for podcast episodes. With its built-in audio player, you can stream episodes directly from the web interface without needing external podcast clients. Podfetch supports multiple podcast subscriptions, episode filtering, playback progress tracking, and automatic cleanup of old episodes to manage storage. The Rust-based backend ensures efficient performance and low resource usage, making it ideal for running on home servers or low-powered devices. Perfect for podcast enthusiasts who want complete control over their podcast library, users seeking privacy and independence from commercial podcast platforms, home lab administrators building media server ecosystems, or anyone who wants to archive and organize podcast episodes without relying on third-party services or dealing with platform-specific limitations.', 'podcast', ARRAY['Podcast', 'Media Manager', 'RSS Feed', 'Audio', 'Self-Hosted', 'Media Server'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "samuel19982/podfetch:v4.9.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Podfetch", "version": "latest", "description": "Podfetch is a self-hosted podcast manager and aggregator that allows you to subscribe to, download, and organize your favorite podcasts from a single centralized interface. It automatically fetches new episodes from RSS feeds at configurable intervals, stores podcast metadata and audio files locally, and provides a web-based interface for browsing and managing your podcast library. The application features automatic episode downloading, customizable polling intervals for checking new content, SQLite database for lightweight data management, and organized file storage for podcast episodes. With its built-in audio player, you can stream episodes directly from the web interface without needing external podcast clients. Podfetch supports multiple podcast subscriptions, episode filtering, playback progress tracking, and automatic cleanup of old episodes to manage storage. The Rust-based backend ensures efficient performance and low resource usage, making it ideal for running on home servers or low-powered devices. Perfect for podcast enthusiasts who want complete control over their podcast library, users seeking privacy and independence from commercial podcast platforms, home lab administrators building media server ecosystems, or anyone who wants to archive and organize podcast episodes without relying on third-party services or dealing with platform-specific limitations.", "category": "podcast", "tags": ["Podcast", "Media Manager", "RSS Feed", "Audio", "Self-Hosted", "Media Server"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "samuel19982/podfetch:v4.9.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.samtv.fyi/PodFetch/"}, {"label": "GitHub", "url": "https://github.com/SamTV12345/PodFetch"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/samuel19982/podfetch"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "podfetch", "port": "$PORT:8000", "volumes": ["/app/podcasts", "/app/db"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('portainer', 'Portainer', 'Portainer is a powerful container management platform trusted by over a million users worldwide. It simplifies the deployment, configuration, troubleshooting, and securing of containers on Kubernetes, Docker, and Swarm across any data center, cloud, network edge, or IIOT device. Portainer is designed to accelerate container adoption and reduce deployment times, making it easier for teams with little to no knowledge of Kubernetes to work autonomously. It also aids in managing and updating deployments, setting up, maintaining, and troubleshooting container infrastructure, and ensuring security and compliance. Portainer supports hybrid and multi-cloud, multi-cluster, multi-device container management, making it a versatile tool for managing complex container ecosystems.', 'container-management', ARRAY['Container Management', 'Deployment', 'Troubleshooting', 'Lifecycle Management', 'Platform Management', 'Security & Compliance'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "portainer/portainer-ce:2.41.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Portainer", "version": "latest", "description": "Portainer is a powerful container management platform trusted by over a million users worldwide. It simplifies the deployment, configuration, troubleshooting, and securing of containers on Kubernetes, Docker, and Swarm across any data center, cloud, network edge, or IIOT device. Portainer is designed to accelerate container adoption and reduce deployment times, making it easier for teams with little to no knowledge of Kubernetes to work autonomously. It also aids in managing and updating deployments, setting up, maintaining, and troubleshooting container infrastructure, and ensuring security and compliance. Portainer supports hybrid and multi-cloud, multi-cluster, multi-device container management, making it a versatile tool for managing complex container ecosystems.", "category": "container-management", "tags": ["Container Management", "Deployment", "Troubleshooting", "Lifecycle Management", "Platform Management", "Security & Compliance"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "portainer/portainer-ce:2.41.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.portainer.io/"}, {"label": "Documentation", "url": "https://docs.portainer.io/"}, {"label": "Github", "url": "https://github.com/portainer/portainer#readme"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "portainer", "port": "$PORT:9000", "volumes": ["/var/run/docker.sock", "/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('portnote', 'PortNote', 'PortNote is a self-hosted port tracking application that helps you keep track of used ports across your servers and VMs. Stop juggling spreadsheets and guessing which service uses which port — PortNote gives you a clear, organized view of your entire port landscape. Add your servers via a sleek web interface, assign and document port usage across all systems, and avoid conflicts before they happen.', 'port-tracking', ARRAY['Port Tracking', 'Infrastructure Management', 'Self-Hosted', 'Web Interface', 'PostgreSQL', 'JWT Authentication', 'DevOps'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "PortNote", "version": "latest", "description": "PortNote is a self-hosted port tracking application that helps you keep track of used ports across your servers and VMs. Stop juggling spreadsheets and guessing which service uses which port \u2014 PortNote gives you a clear, organized view of your entire port landscape. Add your servers via a sleek web interface, assign and document port usage across all systems, and avoid conflicts before they happen.", "category": "port-tracking", "tags": ["Port Tracking", "Infrastructure Management", "Self-Hosted", "Web Interface", "PostgreSQL", "JWT Authentication", "DevOps"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/crocofied/PortNote"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "portnote", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('portracker', 'Portracker', 'Portracker is a self-hosted port tracking and monitoring application that provides real-time visibility into port usage across your infrastructure. It automatically discovers and tracks ports used by services running on your system, including Docker containers, and provides a comprehensive dashboard for port management and conflict detection. Perfect for DevOps teams and system administrators who need to maintain organized port assignments.', 'port-tracking', ARRAY['Port Tracking', 'Infrastructure Monitoring', 'Self-Hosted', 'Docker Integration', 'DevOps', 'System Administration', 'Port Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "mostafawahied/portracker:1.3.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4999}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Portracker", "version": "latest", "description": "Portracker is a self-hosted port tracking and monitoring application that provides real-time visibility into port usage across your infrastructure. It automatically discovers and tracks ports used by services running on your system, including Docker containers, and provides a comprehensive dashboard for port management and conflict detection. Perfect for DevOps teams and system administrators who need to maintain organized port assignments.", "category": "port-tracking", "tags": ["Port Tracking", "Infrastructure Monitoring", "Self-Hosted", "Docker Integration", "DevOps", "System Administration", "Port Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "mostafawahied/portracker:1.3.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4999}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/mostafawahied/portracker"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "portracker", "port": "$PORT:4999", "volumes": ["/data", "/var/run/docker.sock"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('poste', 'Poste', 'Poste is a self-hosted mail server solution that provides a complete and secure email hosting platform. It offers built-in features such as spam filtering, DKIM signing, and webmail access to ensure a reliable email experience. This app is a Docker containerized version of Poste, making it easy to deploy and manage across various environments.', 'email', ARRAY['Email', 'Self-Hosted', 'Mail Server', 'Security', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "analogic/poste.io:2.5.11"}, "port": {"type": "integer", "title": "Port HTTP", "default": 25}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Poste", "version": "latest", "description": "Poste is a self-hosted mail server solution that provides a complete and secure email hosting platform. It offers built-in features such as spam filtering, DKIM signing, and webmail access to ensure a reliable email experience. This app is a Docker containerized version of Poste, making it easy to deploy and manage across various environments.", "category": "email", "tags": ["Email", "Self-Hosted", "Mail Server", "Security", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "analogic/poste.io:2.5.11"}, "port": {"type": "integer", "title": "Port HTTP", "default": 25}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://poste.io/docs"}, {"label": "Github", "url": "https://github.com/analogic/poste.io"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "poste", "port": "$PORT:25", "volumes": ["/data", "/etc/localtime"], "extra_ports": ["110:110", "143:143", "465:465", "587:587", "993:993", "995:995", "4190:4190"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('posterizarr', 'Posterizarr', 'Posterizarr automates creation and management of textless posters for Plex, Jellyfin, and Emby libraries. This template deploys the official Posterizarr container with persistent paths for config and generated assets.', 'media', ARRAY['Media', 'Posters', 'Plex', 'Jellyfin', 'Emby', 'Automation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/fscorrupt/posterizarr:2.2.40"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Posterizarr", "version": "latest", "description": "Posterizarr automates creation and management of textless posters for Plex, Jellyfin, and Emby libraries. This template deploys the official Posterizarr container with persistent paths for config and generated assets.", "category": "media", "tags": ["Media", "Posters", "Plex", "Jellyfin", "Emby", "Automation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/fscorrupt/posterizarr:2.2.40"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://fscorrupt.github.io/posterizarr/"}, {"label": "Documentation", "url": "https://fscorrupt.github.io/posterizarr/installation/"}, {"label": "GitHub", "url": "https://github.com/fscorrupt/posterizarr"}, {"label": "Container registry", "url": "https://github.com/fscorrupt/posterizarr/pkgs/container/posterizarr"}], "instructions": "After deployment, open your domain and complete setup in the web UI. Mounts are already configured for /config, /assets, /assetsbackup, and /manualassets.", "install": [{"docker": {"image": "$IMAGE", "name": "posterizarr", "port": "$PORT:8000", "volumes": ["/config", "/config/Logs", "/config/temp", "/assets", "/assetsbackup", "/manualassets"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deployment, open your domain and complete setup in the web UI. Mounts are already configured for /config, /assets, /assetsbackup, and /manualassets."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('postfixadmin', 'PostfixAdmin', 'PostfixAdmin is a robust, web-based administration interface for managing mail servers using Postfix. It allows you to easily manage virtual domains, mailboxes, and aliases through an intuitive and flexible interface. PostfixAdmin supports advanced features like quota management, domain statistics, and DKIM integration, making it an ideal tool for administrators of self-hosted email solutions.', 'email-administration', ARRAY['Email Administration', 'Self-Hosted', 'Mail Server', 'Postfix'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "postfixadmin:4.0.1-apache"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "PostfixAdmin", "version": "latest", "description": "PostfixAdmin is a robust, web-based administration interface for managing mail servers using Postfix. It allows you to easily manage virtual domains, mailboxes, and aliases through an intuitive and flexible interface. PostfixAdmin supports advanced features like quota management, domain statistics, and DKIM integration, making it an ideal tool for administrators of self-hosted email solutions.", "category": "email-administration", "tags": ["Email Administration", "Self-Hosted", "Mail Server", "Postfix"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "postfixadmin:4.0.1-apache"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://postfix-configuration.readthedocs.io/en/latest/postfixadmin/"}, {"label": "GitHub", "url": "https://github.com/postfixadmin/postfixadmin"}], "instructions": "To create an admin user, run the following commands in the PostfixAdmin container \"chmod +x /var/www/html/scripts/postfixadmin-cli\" and \"/var/www/html/scripts/postfixadmin-cli admin add\". This will create a new admin user for accessing the PostfixAdmin interface.", "install": [{"docker": {"image": "$IMAGE", "name": "postfixadmin", "port": "$PORT:80", "volumes": ["/var/www/html/"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "To create an admin user, run the following commands in the PostfixAdmin container \"chmod +x /var/www/html/scripts/postfixadmin-cli\" and \"/var/www/html/scripts/postfixadmin-cli admin add\". This will create a new admin user for accessing the PostfixAdmin interface."}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('postgres-backup', 'Postgres Backup', 'The postgres-backup-s3 app is a powerful tool designed to backup your PostgreSQL databases to Amazon S3. It supports periodic backups, allowing you to schedule automatic backups at your convenience. This ensures that your data is always safe and can be restored whenever needed. The app also offers the option to backup all available databases at once, creating a single archive with a timestamp for easy identification. For added security, the app provides an encryption feature. By setting an encryption password, your backup can be encrypted and only decrypted with the correct password. This app is perfect for those who want to ensure their PostgreSQL databases are securely backed up in a reliable and efficient manner.', 'databases', ARRAY['Databases', 'Backup'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "easypanel/postgres-backup-s3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Postgres Backup", "version": "latest", "description": "The postgres-backup-s3 app is a powerful tool designed to backup your PostgreSQL databases to Amazon S3. It supports periodic backups, allowing you to schedule automatic backups at your convenience. This ensures that your data is always safe and can be restored whenever needed. The app also offers the option to backup all available databases at once, creating a single archive with a timestamp for easy identification. For added security, the app provides an encryption feature. By setting an encryption password, your backup can be encrypted and only decrypted with the correct password. This app is perfect for those who want to ensure their PostgreSQL databases are securely backed up in a reliable and efficient manner.", "category": "databases", "tags": ["Databases", "Backup"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "easypanel/postgres-backup-s3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://github.com/schickling/dockerfiles/tree/master/postgres-backup-s3"}, {"label": "Github", "url": "https://github.com/schickling/dockerfiles/tree/master/postgres-backup-s3"}], "instructions": "In order to test that you configured it properly, remove the SCHEDULE variable from the environment, click deploy and check the logs. If everything works fine, you can add the SCHEDULE variable back. You can read more about the environment variables here: https://github.com/schickling/dockerfiles/tree/master/postgres-backup-s3", "install": [{"docker": {"image": "$IMAGE", "name": "postgres-backup", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "In order to test that you configured it properly, remove the SCHEDULE variable from the environment, click deploy and check the logs. If everything works fine, you can add the SCHEDULE variable back. You can read more about the environment variables here: https://github.com/schickling/dockerfiles/tree/master/postgres-backup-s3"}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('postgresus', 'PostgresUS', 'PostgresUS is a self-hosted PostgreSQL management and administration tool that provides a web-based interface for managing PostgreSQL databases. The application offers a user-friendly dashboard for database operations, query execution, schema management, and database administration tasks. With its intuitive interface, PostgresUS makes it easy to interact with PostgreSQL databases without requiring command-line tools or complex database management software. The application supports multiple database connections, query building, data visualization, and common database administration operations. Perfect for database administrators who need a simple web interface for PostgreSQL management, developers looking for a lightweight database tool, teams requiring a self-hosted alternative to cloud database management platforms, or anyone who wants a convenient way to manage PostgreSQL databases through a browser.', 'database', ARRAY['Database', 'PostgreSQL', 'Database Management', 'Self-Hosted', 'Admin Tool'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/rostislavdugin/charts/postgresus:2.15.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4005}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "PostgresUS", "version": "latest", "description": "PostgresUS is a self-hosted PostgreSQL management and administration tool that provides a web-based interface for managing PostgreSQL databases. The application offers a user-friendly dashboard for database operations, query execution, schema management, and database administration tasks. With its intuitive interface, PostgresUS makes it easy to interact with PostgreSQL databases without requiring command-line tools or complex database management software. The application supports multiple database connections, query building, data visualization, and common database administration operations. Perfect for database administrators who need a simple web interface for PostgreSQL management, developers looking for a lightweight database tool, teams requiring a self-hosted alternative to cloud database management platforms, or anyone who wants a convenient way to manage PostgreSQL databases through a browser.", "category": "database", "tags": ["Database", "PostgreSQL", "Database Management", "Self-Hosted", "Admin Tool"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/rostislavdugin/charts/postgresus:2.15.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4005}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Docker Hub", "url": "https://hub.docker.com/r/rostislavdugin/postgresus"}, {"label": "GitHub", "url": "https://github.com/RostislavDugin/postgresus"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "postgresus", "port": "$PORT:4005", "volumes": ["/postgresus-data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('postiz', 'Postiz', 'Postiz is a modern, self-hosted social media management platform that helps you schedule, publish, and analyze content across multiple social networks. It provides a unified dashboard for managing posts, tracking engagement, and optimizing your social media strategy.', 'social-media', ARRAY['Social Media', 'Content Management', 'Scheduling', 'Analytics', 'Marketing'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/gitroomhq/postiz-app:v2.21.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Postiz", "version": "latest", "description": "Postiz is a modern, self-hosted social media management platform that helps you schedule, publish, and analyze content across multiple social networks. It provides a unified dashboard for managing posts, tracking engagement, and optimizing your social media strategy.", "category": "social-media", "tags": ["Social Media", "Content Management", "Scheduling", "Analytics", "Marketing"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/gitroomhq/postiz-app:v2.21.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://postiz.com"}, {"label": "Documentation", "url": "https://docs.postiz.com"}, {"label": "GitHub", "url": "https://github.com/postiz/postiz"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/postiz/postiz"}, {"label": "Environment Variables", "url": "https://github.com/gitroomhq/postiz-app/blob/main/.env.example"}], "instructions": "You can modify the settings by adding the env variables provided.", "install": [{"docker": {"image": "$IMAGE", "name": "postiz", "port": "$PORT:5000", "volumes": ["/app/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "You can modify the settings by adding the env variables provided."}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('powerdns-admin', 'PowerDNS-Admin', 'PowerDNS-Admin is a comprehensive web interface for PowerDNS with a plethora of advanced features. It offers forward and reverse zone management, zone templating, and user management with role-based access control. The app also provides zone-specific access control and activity logging. It supports various authentication methods including Local User, SAML, LDAP, and OAuth with Google, GitHub, Azure, and OpenID. It also supports two-factor authentication (TOTP). PowerDNS-Admin is equipped with PDNS Service Configuration & Statistics Monitoring and supports the DynDNS 2 protocol. It makes IPv6 PTR record editing easy and provides an API for zone and record management. The app also fully supports IDN/Punycode. PowerDNS-Admin can be run in several ways, with Docker being the quickest.', 'dns-management', ARRAY['DNS Management', 'Web Interface', 'User Management', 'API'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ngoduykhanh/powerdns-admin:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "PowerDNS-Admin", "version": "latest", "description": "PowerDNS-Admin is a comprehensive web interface for PowerDNS with a plethora of advanced features. It offers forward and reverse zone management, zone templating, and user management with role-based access control. The app also provides zone-specific access control and activity logging. It supports various authentication methods including Local User, SAML, LDAP, and OAuth with Google, GitHub, Azure, and OpenID. It also supports two-factor authentication (TOTP). PowerDNS-Admin is equipped with PDNS Service Configuration & Statistics Monitoring and supports the DynDNS 2 protocol. It makes IPv6 PTR record editing easy and provides an API for zone and record management. The app also fully supports IDN/Punycode. PowerDNS-Admin can be run in several ways, with Docker being the quickest.", "category": "dns-management", "tags": ["DNS Management", "Web Interface", "User Management", "API"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ngoduykhanh/powerdns-admin:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/PowerDNS-Admin/PowerDNS-Admin"}, {"label": "Documentation", "url": "https://github.com/PowerDNS-Admin/PowerDNS-Admin/wiki"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "powerdns-admin", "port": "$PORT:80", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('poznote', 'Poznote', 'Poznote is a lightweight, self-hosted note-taking application designed for personal knowledge management and quick note capture. It provides a simple, clean interface for creating, organizing, and managing notes without unnecessary complexity. Poznote uses SQLite for data storage, making it easy to deploy without requiring external database setup. The application features secure authentication, markdown support, and fast search capabilities to help you find information quickly. All your notes are stored locally in a SQLite database file, ensuring privacy and complete control over your data. Perfect for individuals who want a straightforward, fast, and private note-taking solution that can be accessed from any browser.', 'notes', ARRAY['Notes', 'Note Taking', 'Knowledge Management', 'Markdown', 'SQLite'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/timothepoznanski/poznote:1.9.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Poznote", "version": "latest", "description": "Poznote is a lightweight, self-hosted note-taking application designed for personal knowledge management and quick note capture. It provides a simple, clean interface for creating, organizing, and managing notes without unnecessary complexity. Poznote uses SQLite for data storage, making it easy to deploy without requiring external database setup. The application features secure authentication, markdown support, and fast search capabilities to help you find information quickly. All your notes are stored locally in a SQLite database file, ensuring privacy and complete control over your data. Perfect for individuals who want a straightforward, fast, and private note-taking solution that can be accessed from any browser.", "category": "notes", "tags": ["Notes", "Note Taking", "Knowledge Management", "Markdown", "SQLite"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/timothepoznanski/poznote:1.9.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://poznote.com"}, {"label": "Documentation", "url": "https://github.com/timothepoznanski/poznote?tab=readme-ov-file#table-of-content"}, {"label": "Github", "url": "https://github.com/TimothePoznanski/poznote"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "poznote", "port": "$PORT:80", "volumes": ["/var/www/html/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('prestashop', 'Prestashop', 'Prestashop is an open-source e-commerce platform that empowers businesses to build and manage their online stores. It provides a user-friendly interface, a robust product catalog system, order management, and customizable themes, making it an ideal choice for merchants of all sizes. Prestashop supports multiple payment gateways, multilingual and multi-currency features, and SEO optimization to ensure a global reach and enhanced online visibility. Additionally, it offers a vibrant marketplace for modules and themes, enabling seamless customization and integration with third-party services.', 'e-commerce', ARRAY['E-commerce', 'Web Development', 'Online Store', 'CMS'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "prestashop/prestashop:9.1.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Prestashop", "version": "latest", "description": "Prestashop is an open-source e-commerce platform that empowers businesses to build and manage their online stores. It provides a user-friendly interface, a robust product catalog system, order management, and customizable themes, making it an ideal choice for merchants of all sizes. Prestashop supports multiple payment gateways, multilingual and multi-currency features, and SEO optimization to ensure a global reach and enhanced online visibility. Additionally, it offers a vibrant marketplace for modules and themes, enabling seamless customization and integration with third-party services.", "category": "e-commerce", "tags": ["E-commerce", "Web Development", "Online Store", "CMS"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "prestashop/prestashop:9.1.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.prestashop.com"}, {"label": "Documentation", "url": "https://devdocs.prestashop.com"}, {"label": "Github", "url": "https://github.com/PrestaShop/PrestaShop"}], "instructions": "Configure the database during the installation wizard. Use the provided domains for the admin panel and storefront setup.", "install": [{"docker": {"image": "$IMAGE", "name": "prestashop", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Configure the database during the installation wizard. Use the provided domains for the admin panel and storefront setup."}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('privatebin', 'PrivateBin', 'PrivateBin is a minimalist, open-source, self-hosted pastebin solution designed for secure and private data sharing. It features end-to-end encryption, ensuring that your shared content remains confidential. With its simple interface and focus on privacy, PrivateBin is an excellent tool for individuals and teams who value secure communication.', 'secure-sharing', ARRAY['Secure Sharing', 'Self-Hosted', 'Privacy', 'Pastebin'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "privatebin/nginx-fpm-alpine:2.0.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "PrivateBin", "version": "latest", "description": "PrivateBin is a minimalist, open-source, self-hosted pastebin solution designed for secure and private data sharing. It features end-to-end encryption, ensuring that your shared content remains confidential. With its simple interface and focus on privacy, PrivateBin is an excellent tool for individuals and teams who value secure communication.", "category": "secure-sharing", "tags": ["Secure Sharing", "Self-Hosted", "Privacy", "Pastebin"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "privatebin/nginx-fpm-alpine:2.0.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://privatebin.info/"}, {"label": "Github", "url": "https://github.com/PrivateBin/PrivateBin"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "privatebin", "port": "$PORT:80", "volumes": ["/srv/data", "/srv/cfg/conf.php"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('projectsend', 'ProjectSend', 'ProjectSend is a self-hosted file sharing platform designed to securely share files with clients and collaborators. It provides a user-friendly interface, supports advanced user management, and allows for detailed activity tracking. With ProjectSend, you can maintain control over your files and ensure secure access for authorized users.', 'file-sharing', ARRAY['File Sharing', 'Self-Hosted', 'Secure Collaboration'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/projectsend:version-r2029"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "ProjectSend", "version": "latest", "description": "ProjectSend is a self-hosted file sharing platform designed to securely share files with clients and collaborators. It provides a user-friendly interface, supports advanced user management, and allows for detailed activity tracking. With ProjectSend, you can maintain control over your files and ensure secure access for authorized users.", "category": "file-sharing", "tags": ["File Sharing", "Self-Hosted", "Secure Collaboration"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/projectsend:version-r2029"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.projectsend.org/"}, {"label": "Github", "url": "https://github.com/projectsend/projectsend"}], "instructions": "After Connecting with the DB, configure the URL to be https in next screen of installation wizard and run chmod 755 /app/www/public/emails in the terminal after the installation.", "install": [{"docker": {"image": "$IMAGE", "name": "projectsend", "port": "$PORT:80", "volumes": ["/data", "/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After Connecting with the DB, configure the URL to be https in next screen of installation wizard and run chmod 755 /app/www/public/emails in the terminal after the installation."}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('promethus', 'Prometheus', 'Prometheus is an open-source monitoring and alerting toolkit designed for reliability and scalability. It collects metrics from configured targets at specified intervals, evaluates rule expressions, and triggers alerts when specified conditions are observed. Prometheus stores all data as time-series, making it ideal for monitoring application and system performance over time. Its powerful query language, PromQL, allows for real-time data analysis, and its flexible integrations support various exporters and service discovery mechanisms. Prometheus can also integrate with alerting tools like Alertmanager to send notifications via email, Slack, or other channels. With native support for Docker, Kubernetes, and other container platforms, Prometheus provides deep visibility into modern infrastructure and services.', 'monitoring', ARRAY['Monitoring', 'Time-Series', 'Alerting', 'PromQL', 'Cloud-Native'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "prom/prometheus:v3.8.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9090}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Prometheus", "version": "latest", "description": "Prometheus is an open-source monitoring and alerting toolkit designed for reliability and scalability. It collects metrics from configured targets at specified intervals, evaluates rule expressions, and triggers alerts when specified conditions are observed. Prometheus stores all data as time-series, making it ideal for monitoring application and system performance over time. Its powerful query language, PromQL, allows for real-time data analysis, and its flexible integrations support various exporters and service discovery mechanisms. Prometheus can also integrate with alerting tools like Alertmanager to send notifications via email, Slack, or other channels. With native support for Docker, Kubernetes, and other container platforms, Prometheus provides deep visibility into modern infrastructure and services.", "category": "monitoring", "tags": ["Monitoring", "Time-Series", "Alerting", "PromQL", "Cloud-Native"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "prom/prometheus:v3.8.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9090}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/prometheus/prometheus"}, {"label": "Documentation", "url": "https://prometheus.io/docs/introduction/overview/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "promethus", "port": "$PORT:9090", "volumes": ["/prometheus"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('prowlarr', 'Prowlarr', 'Prowlarr is a powerful indexer manager and proxy designed to integrate with various PVR applications. It is built on the popular arr .net/reactjs base stack, offering a seamless experience for users. Prowlarr supports the management of both Torrent Trackers and Usenet Indexers, eliminating the need for per app Indexer setup. It works in harmony with LazyLibrarian, Lidarr, Mylar3, Radarr, Readarr, and Sonarr, providing comprehensive management of your indexers. The app includes features such as Usenet support for 24 indexers natively, Torrent support for over 500 trackers, support for custom YML definitions, Indexer Sync to various apps, manual searching of Trackers & Indexers, and much more. Prowlarr also provides Indexer health and status notifications and supports multiple releases pushing directly to your download clients.', 'indexer-manager', ARRAY['Indexer Manager', 'Proxy', 'PVR Apps'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/prowlarr:1.37.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9696}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Prowlarr", "version": "latest", "description": "Prowlarr is a powerful indexer manager and proxy designed to integrate with various PVR applications. It is built on the popular arr .net/reactjs base stack, offering a seamless experience for users. Prowlarr supports the management of both Torrent Trackers and Usenet Indexers, eliminating the need for per app Indexer setup. It works in harmony with LazyLibrarian, Lidarr, Mylar3, Radarr, Readarr, and Sonarr, providing comprehensive management of your indexers. The app includes features such as Usenet support for 24 indexers natively, Torrent support for over 500 trackers, support for custom YML definitions, Indexer Sync to various apps, manual searching of Trackers & Indexers, and much more. Prowlarr also provides Indexer health and status notifications and supports multiple releases pushing directly to your download clients.", "category": "indexer-manager", "tags": ["Indexer Manager", "Proxy", "PVR Apps"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/prowlarr:1.37.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9696}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://prowlarr.com/"}, {"label": "Documentation", "url": "https://wiki.servarr.com/prowlarr"}, {"label": "Github", "url": "https://github.com/Prowlarr/Prowlarr/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "prowlarr", "port": "$PORT:9696", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('prunemate', 'PruneMate', 'PruneMate is a self-hosted Docker cleanup and management tool that provides a web-based interface for pruning unused Docker resources from your system. It helps you reclaim disk space by identifying and removing unused containers, images, volumes, networks, and build cache. With its intuitive dashboard, you can easily monitor Docker resource usage, schedule automatic cleanup tasks, and manually trigger pruning operations without using command-line tools. PruneMate connects directly to your Docker daemon via the Docker socket, allowing it to safely analyze and clean up orphaned resources that accumulate over time. The application features configurable cleanup schedules, selective pruning options to choose which resource types to clean, detailed logging of all cleanup operations, and real-time statistics showing disk space recovered. With timezone support and customizable time format settings, you can schedule cleanup operations to run during off-peak hours. Perfect for developers and system administrators who manage Docker environments and want to automate the cleanup of unused resources, homelab enthusiasts running multiple containers who need to manage disk space efficiently, CI/CD environments where frequent image builds create significant cleanup overhead, or anyone looking for a simple web interface to manage Docker resource cleanup without remembering complex docker system prune commands.', 'docker', ARRAY['Docker', 'DevOps', 'System Administration', 'Cleanup', 'Disk Management', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "anoniemerd/prunemate:1.3.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "PruneMate", "version": "latest", "description": "PruneMate is a self-hosted Docker cleanup and management tool that provides a web-based interface for pruning unused Docker resources from your system. It helps you reclaim disk space by identifying and removing unused containers, images, volumes, networks, and build cache. With its intuitive dashboard, you can easily monitor Docker resource usage, schedule automatic cleanup tasks, and manually trigger pruning operations without using command-line tools. PruneMate connects directly to your Docker daemon via the Docker socket, allowing it to safely analyze and clean up orphaned resources that accumulate over time. The application features configurable cleanup schedules, selective pruning options to choose which resource types to clean, detailed logging of all cleanup operations, and real-time statistics showing disk space recovered. With timezone support and customizable time format settings, you can schedule cleanup operations to run during off-peak hours. Perfect for developers and system administrators who manage Docker environments and want to automate the cleanup of unused resources, homelab enthusiasts running multiple containers who need to manage disk space efficiently, CI/CD environments where frequent image builds create significant cleanup overhead, or anyone looking for a simple web interface to manage Docker resource cleanup without remembering complex docker system prune commands.", "category": "docker", "tags": ["Docker", "DevOps", "System Administration", "Cleanup", "Disk Management", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "anoniemerd/prunemate:1.3.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://prunemate.org"}, {"label": "Github", "url": "https://github.com/anoniemerd/PruneMate"}, {"label": "Documentation", "url": "https://prunemate.org/documentation.html"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "prunemate", "port": "$PORT:8080", "volumes": ["/var/run/docker.sock", "/var/log", "/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('psitransfer', 'PsiTransfer', 'PsiTransfer is a simple, open-source, self-hosted file sharing solution designed to provide an alternative to paid services like Dropbox and WeTransfer. The app allows for the sharing of many and very large files with ease, thanks to its support for streams. It also offers resumable uploads and downloads, ensuring you never lose progress. With PsiTransfer, you can set an expiry time for your upload bucket, and even offer one-time downloads. The app also supports downloading all files as a zip or tar.gz archive, and provides a modal-style file preview. For added security, PsiTransfer offers a password-protected download list. The app is lightweight and mobile-friendly, making it easy to use on any device. It also allows for explicit named bucket IDs with a query param sid=<myBucketID>.', 'file-management', ARRAY['File Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "psitrax/psitransfer:v2.4.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "PsiTransfer", "version": "latest", "description": "PsiTransfer is a simple, open-source, self-hosted file sharing solution designed to provide an alternative to paid services like Dropbox and WeTransfer. The app allows for the sharing of many and very large files with ease, thanks to its support for streams. It also offers resumable uploads and downloads, ensuring you never lose progress. With PsiTransfer, you can set an expiry time for your upload bucket, and even offer one-time downloads. The app also supports downloading all files as a zip or tar.gz archive, and provides a modal-style file preview. For added security, PsiTransfer offers a password-protected download list. The app is lightweight and mobile-friendly, making it easy to use on any device. It also allows for explicit named bucket IDs with a query param sid=<myBucketID>.", "category": "file-management", "tags": ["File Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "psitrax/psitransfer:v2.4.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://github.com/psi-4ward/psitransfer/tree/master/docs"}, {"label": "Github", "url": "https://github.com/psi-4ward/psitransfer"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "psitransfer", "port": "$PORT:3000", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('pterodactyl-panel', 'Pterodactyl Panel', 'Pterodactyl® is a free, open-source game server management panel that allows you to manage your game servers with ease and efficiency. It is built with PHP, React, and Go, and designed with a focus on security. Pterodactyl runs all game servers in isolated Docker containers, providing a secure environment for each game. It also offers a beautiful and intuitive user interface, making it easy for anyone to use. The platform supports a wide variety of games, including Minecraft, Rust, Terraria, Teamspeak, Mumble, Team Fortress 2, Counter Strike Global Offensive, Garry''s Mod, ARK Survival Evolved, and many more. With Pterodactyl, you can host your games across the world without having to bloat each physical machine with additional dependencies. It''s time to make game servers a first-class citizen on your platform with Pterodactyl.', 'gaming', ARRAY['Gaming', 'Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/pterodactyl/panel:v1.12.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Pterodactyl Panel", "version": "latest", "description": "Pterodactyl\u00ae is a free, open-source game server management panel that allows you to manage your game servers with ease and efficiency. It is built with PHP, React, and Go, and designed with a focus on security. Pterodactyl runs all game servers in isolated Docker containers, providing a secure environment for each game. It also offers a beautiful and intuitive user interface, making it easy for anyone to use. The platform supports a wide variety of games, including Minecraft, Rust, Terraria, Teamspeak, Mumble, Team Fortress 2, Counter Strike Global Offensive, Garry's Mod, ARK Survival Evolved, and many more. With Pterodactyl, you can host your games across the world without having to bloat each physical machine with additional dependencies. It's time to make game servers a first-class citizen on your platform with Pterodactyl.", "category": "gaming", "tags": ["Gaming", "Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/pterodactyl/panel:v1.12.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://pterodactyl.io/"}, {"label": "Documentation", "url": "https://pterodactyl.io/project/introduction.html"}, {"label": "Github", "url": "https://github.com/pterodactyl/panel"}], "instructions": "After installing, open the console and run \"php artisan p:user:make\".", "install": [{"docker": {"image": "$IMAGE", "name": "pterodactyl-panel", "port": "$PORT:80", "volumes": ["/app/var/", "/app/storage/logs", "/etc/nginx/http.d/"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After installing, open the console and run \"php artisan p:user:make\"."}, "services": {"mysql": {"type": "mysql", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('pufferpanel', 'Pufferpanel', 'PufferPanel is a free, open-source game server management panel that simplifies the management of your game servers. It supports a wide variety of games including Minecraft, Forge, Spigot, Sponge, Source Dedicated Servers, BungeeCord, PocketMine, and many more. With PufferPanel, you can easily manage multiple game servers from one central location, providing a streamlined and efficient way to control your gaming environment. Whether you''re an individual user or a large network, PufferPanel''s user-friendly interface makes game server management a breeze.', 'game-server-management', ARRAY['Game Server Management', 'Open Source', 'Easy to Use'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "pufferpanel/pufferpanel:2.7.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 22}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Pufferpanel", "version": "latest", "description": "PufferPanel is a free, open-source game server management panel that simplifies the management of your game servers. It supports a wide variety of games including Minecraft, Forge, Spigot, Sponge, Source Dedicated Servers, BungeeCord, PocketMine, and many more. With PufferPanel, you can easily manage multiple game servers from one central location, providing a streamlined and efficient way to control your gaming environment. Whether you're an individual user or a large network, PufferPanel's user-friendly interface makes game server management a breeze.", "category": "game-server-management", "tags": ["Game Server Management", "Open Source", "Easy to Use"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "pufferpanel/pufferpanel:2.7.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 22}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://pufferpanel.com/"}, {"label": "Documentation", "url": "https://docs.pufferpanel.com/en/latest"}, {"label": "Github", "url": "https://github.com/PufferPanel/PufferPanel"}], "instructions": "Run \"./pufferpanel user add\" in the console to create a new user.", "install": [{"docker": {"image": "$IMAGE", "name": "pufferpanel", "port": "$PORT:22", "volumes": ["/var/lib/pufferpanel", "/etc/pufferpanel"], "extra_ports": ["2222:2222", "5657:5657", "8080:8080"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Run \"./pufferpanel user add\" in the console to create a new user."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('pwndrop', 'Pwndrop', 'Pwndrop is a self-deployable file hosting service for red teamers, designed for sending payloads and collecting loot in penetration testing operations. It provides a lightweight, standalone solution for hosting and managing files during security assessments. With its simple web interface, you can easily upload, organize, and share files with customizable download links. Pwndrop offers features like file tracking, download notifications, and an admin portal protected by a secret path for enhanced security.', 'file-sharing', ARRAY['File Sharing', 'Security Tools', 'Red Team', 'Penetration Testing', 'File Hosting', 'Self-Hosted', 'Lightweight', 'Admin Portal'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/pwndrop:1.0.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Pwndrop", "version": "latest", "description": "Pwndrop is a self-deployable file hosting service for red teamers, designed for sending payloads and collecting loot in penetration testing operations. It provides a lightweight, standalone solution for hosting and managing files during security assessments. With its simple web interface, you can easily upload, organize, and share files with customizable download links. Pwndrop offers features like file tracking, download notifications, and an admin portal protected by a secret path for enhanced security.", "category": "file-sharing", "tags": ["File Sharing", "Security Tools", "Red Team", "Penetration Testing", "File Hosting", "Self-Hosted", "Lightweight", "Admin Portal"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/pwndrop:1.0.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://breakdev.org/pwndrop/"}, {"label": "GitHub", "url": "https://github.com/kgretzky/pwndrop"}, {"label": "Documentation", "url": "https://breakdev.org/pwndrop/"}], "instructions": "After deployment, user will be redirected to create an account.", "install": [{"docker": {"image": "$IMAGE", "name": "pwndrop", "port": "$PORT:8080", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deployment, user will be redirected to create an account."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('pyload-ng', 'pyLoad-NG', 'pyLoad-NG is a modern download manager with a web interface, supporting various download services and protocols. It features a clean interface, download scheduling, and extensive plugin support.', 'download-manager', ARRAY['Download Manager', 'File Transfer', 'Self-hosted', 'Open Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/pyload-ng:develop-version-3c5e1c66"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "pyLoad-NG", "version": "latest", "description": "pyLoad-NG is a modern download manager with a web interface, supporting various download services and protocols. It features a clean interface, download scheduling, and extensive plugin support.", "category": "download-manager", "tags": ["Download Manager", "File Transfer", "Self-hosted", "Open Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/pyload-ng:develop-version-3c5e1c66"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/pyload/pyload"}, {"label": "Documentation", "url": "https://github.com/pyload/pyload/wiki"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/linuxserver/pyload-ng"}], "instructions": "Default credentials are pyload/pyload.", "install": [{"docker": {"image": "$IMAGE", "name": "pyload-ng", "port": "$PORT:8000", "volumes": ["/config", "/downloads"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Default credentials are pyload/pyload."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('qbitorrent', 'qBittorrent', 'qBittorrent is a powerful, open-source BitTorrent client designed to provide an efficient and feature-rich experience for downloading and sharing files. It offers a user-friendly interface, robust functionality, and cross-platform compatibility. qBittorrent supports advanced features like sequential downloading, IP filtering, RSS feed support, and a built-in search engine for finding torrents. It also includes a web-based interface for managing downloads remotely. Designed to balance performance, simplicity, and advanced capabilities, qBittorrent is ideal for users seeking a secure and reliable torrenting solution.', 'torrenting', ARRAY['Torrenting', 'BitTorrent', 'File Sharing', 'Open Source', 'Remote Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/qbittorrent:5.1.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "qBittorrent", "version": "latest", "description": "qBittorrent is a powerful, open-source BitTorrent client designed to provide an efficient and feature-rich experience for downloading and sharing files. It offers a user-friendly interface, robust functionality, and cross-platform compatibility. qBittorrent supports advanced features like sequential downloading, IP filtering, RSS feed support, and a built-in search engine for finding torrents. It also includes a web-based interface for managing downloads remotely. Designed to balance performance, simplicity, and advanced capabilities, qBittorrent is ideal for users seeking a secure and reliable torrenting solution.", "category": "torrenting", "tags": ["Torrenting", "BitTorrent", "File Sharing", "Open Source", "Remote Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/qbittorrent:5.1.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.qbittorrent.org"}, {"label": "Docs", "url": "https://github.com/qbittorrent/qBittorrent/wiki"}, {"label": "Github", "url": "https://github.com/qbittorrent/qBittorrent"}], "instructions": "Username is admin, password is provided in the overview logs.", "install": [{"docker": {"image": "$IMAGE", "name": "qbitorrent", "port": "$PORT:8080", "volumes": ["/downloads", "/config"], "extra_ports": ["6881:6881"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Username is admin, password is provided in the overview logs."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('qbitwebui', 'qBitWebUI', 'qBitWebUI is a modern web interface for qBittorrent, providing an enhanced user experience for managing your torrent downloads. It offers a clean, responsive design with advanced features like dark mode, mobile support, and improved usability compared to the default qBittorrent web UI. Perfect for users who want a better way to manage their torrents remotely through a web browser.', 'torrent', ARRAY['Torrent', 'qBittorrent', 'Web UI', 'Download Manager', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/maciejonos/qbitwebui:2.21"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "qBitWebUI", "version": "latest", "description": "qBitWebUI is a modern web interface for qBittorrent, providing an enhanced user experience for managing your torrent downloads. It offers a clean, responsive design with advanced features like dark mode, mobile support, and improved usability compared to the default qBittorrent web UI. Perfect for users who want a better way to manage their torrents remotely through a web browser.", "category": "torrent", "tags": ["Torrent", "qBittorrent", "Web UI", "Download Manager", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/maciejonos/qbitwebui:2.21"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/maciejonos/qbitwebui"}, {"label": "Website", "url": "https://maciejonos.github.io/qbitwebui/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "qbitwebui", "port": "$PORT:3000", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('qdrant', 'Qdrant', 'Qdrant is a powerful vector database and vector similarity search engine designed to power the next generation of AI applications. It deploys as an API service, providing search for the nearest high-dimensional vectors. This allows embeddings or neural network encoders to be turned into full-fledged applications for matching, searching, recommending, and much more. Qdrant supports a large variety of data types and query conditions, including string matching, numerical ranges, geo-locations, and more. It is cloud-native and scales horizontally, ensuring efficient utilization of resources. With Qdrant, you can build and deploy semantic neural search on your data in minutes, understand user behavior in real time, and find similar images or detect duplicates with ease.', 'data-science', ARRAY['Data Science', 'Databases', 'Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "qdrant/qdrant:v1.17"}, "port": {"type": "integer", "title": "Port HTTP", "default": 6333}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Qdrant", "version": "latest", "description": "Qdrant is a powerful vector database and vector similarity search engine designed to power the next generation of AI applications. It deploys as an API service, providing search for the nearest high-dimensional vectors. This allows embeddings or neural network encoders to be turned into full-fledged applications for matching, searching, recommending, and much more. Qdrant supports a large variety of data types and query conditions, including string matching, numerical ranges, geo-locations, and more. It is cloud-native and scales horizontally, ensuring efficient utilization of resources. With Qdrant, you can build and deploy semantic neural search on your data in minutes, understand user behavior in real time, and find similar images or detect duplicates with ease.", "category": "data-science", "tags": ["Data Science", "Databases", "Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "qdrant/qdrant:v1.17"}, "port": {"type": "integer", "title": "Port HTTP", "default": 6333}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://qdrant.tech/"}, {"label": "Documentation", "url": "https://qdrant.tech/documentation/"}, {"label": "Github", "url": "https://github.com/qdrant/qdrant"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "qdrant", "port": "$PORT:6333", "volumes": ["/qdrant/storage"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('qloapps', 'QloApps', 'QloApps is a comprehensive hotel booking and property management system built on PrestaShop. It provides a complete solution for hoteliers to manage their properties, bookings, and customers. The system includes features like room management, booking engine, customer management, and payment processing. QloApps is designed to help hotels streamline their operations and improve guest experience.', 'hotel-management', ARRAY['Hotel Management', 'Booking System', 'Property Management', 'Hospitality', 'E-commerce'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "webkul/qloapps_docker:1.6.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "QloApps", "version": "latest", "description": "QloApps is a comprehensive hotel booking and property management system built on PrestaShop. It provides a complete solution for hoteliers to manage their properties, bookings, and customers. The system includes features like room management, booking engine, customer management, and payment processing. QloApps is designed to help hotels streamline their operations and improve guest experience.", "category": "hotel-management", "tags": ["Hotel Management", "Booking System", "Property Management", "Hospitality", "E-commerce"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "webkul/qloapps_docker:1.6.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://qloapps.com/"}, {"label": "Documentation", "url": "https://qloapps.com/hotel-website/"}, {"label": "Github", "url": "https://github.com/Qloapps/QloApps"}], "instructions": "Login email admin@qloapps.local and password 12345678", "install": [{"docker": {"image": "$IMAGE", "name": "qloapps", "port": "$PORT:80", "volumes": ["/var/www/html"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Login email admin@qloapps.local and password 12345678"}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('rabbitmq', 'RabbitMQ', 'RabbitMQ is an open-source message broker software that facilitates reliable messaging between applications and services. It supports a variety of messaging protocols such as AMQP and MQTT, making it a versatile solution for modern distributed systems. With RabbitMQ, you can efficiently manage message queues, exchanges, and routing, enabling seamless communication across different components of your application. It also provides a user-friendly web-based management interface for monitoring, configuration, and troubleshooting.', 'message-broker', ARRAY['Message Broker', 'AMQP', 'MQTT', 'High Availability', 'Queue Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "rabbitmq:3-management"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5672}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "RabbitMQ", "version": "latest", "description": "RabbitMQ is an open-source message broker software that facilitates reliable messaging between applications and services. It supports a variety of messaging protocols such as AMQP and MQTT, making it a versatile solution for modern distributed systems. With RabbitMQ, you can efficiently manage message queues, exchanges, and routing, enabling seamless communication across different components of your application. It also provides a user-friendly web-based management interface for monitoring, configuration, and troubleshooting.", "category": "message-broker", "tags": ["Message Broker", "AMQP", "MQTT", "High Availability", "Queue Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "rabbitmq:3-management"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5672}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.rabbitmq.com/"}, {"label": "Documentation", "url": "https://www.rabbitmq.com/documentation.html"}, {"label": "GitHub", "url": "https://github.com/rabbitmq"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "rabbitmq", "port": "$PORT:5672", "volumes": ["/var/lib/rabbitmq"], "extra_ports": ["15672:15672"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('rachoon', 'Rachoon', 'Rachoon is a self-hosted invoicing platform for creating and tracking invoices, managing clients, and exporting professional PDFs. This template deploys Rachoon with PostgreSQL and Gotenberg as required dependencies.', 'invoicing', ARRAY['Invoicing', 'Billing', 'Finance', 'PostgreSQL', 'Gotenberg', 'Self-hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/ad-on-is/rachoon:v1.3.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Rachoon", "version": "latest", "description": "Rachoon is a self-hosted invoicing platform for creating and tracking invoices, managing clients, and exporting professional PDFs. This template deploys Rachoon with PostgreSQL and Gotenberg as required dependencies.", "category": "invoicing", "tags": ["Invoicing", "Billing", "Finance", "PostgreSQL", "Gotenberg", "Self-hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/ad-on-is/rachoon:v1.3.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://github.com/ad-on-is/rachoon#readme"}, {"label": "GitHub", "url": "https://github.com/ad-on-is/rachoon"}, {"label": "Container registry", "url": "https://github.com/ad-on-is/rachoon/pkgs/container/rachoon"}], "instructions": "After deployment, open your domain and create your account in the Rachoon UI. The APP_KEY is generated automatically unless you provide one. Database values are wired automatically to the bundled PostgreSQL service.", "install": [{"docker": {"image": "$IMAGE", "name": "rachoon", "port": "$PORT:8080", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deployment, open your domain and create your account in the Rachoon UI. The APP_KEY is generated automatically unless you provide one. Database values are wired automatically to the bundled PostgreSQL service."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('radarr', 'Radarr', 'Radarr is a movie collection manager designed for Usenet and BitTorrent users. It monitors multiple RSS feeds for new movies and interfaces with clients and indexers to grab, sort, and rename them. Radarr also has the ability to automatically upgrade the quality of existing files in your library when a better quality format becomes available. The app features a calendar to see all your upcoming movies in one place, manual search to find all the releases and choose the one you want, and automatic handling of failed downloads. Radarr ensures you get the right release every time with its custom formats feature, which allows fine control over release prioritization and selection. It also supports major platforms like Windows, Linux, macOS, and others.', 'media', ARRAY['Media', 'Download Manager'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/radarr:6.1.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 7878}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Radarr", "version": "latest", "description": "Radarr is a movie collection manager designed for Usenet and BitTorrent users. It monitors multiple RSS feeds for new movies and interfaces with clients and indexers to grab, sort, and rename them. Radarr also has the ability to automatically upgrade the quality of existing files in your library when a better quality format becomes available. The app features a calendar to see all your upcoming movies in one place, manual search to find all the releases and choose the one you want, and automatic handling of failed downloads. Radarr ensures you get the right release every time with its custom formats feature, which allows fine control over release prioritization and selection. It also supports major platforms like Windows, Linux, macOS, and others.", "category": "media", "tags": ["Media", "Download Manager"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/radarr:6.1.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 7878}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://radarr.video/"}, {"label": "Documentation", "url": "https://wiki.servarr.com/radarr"}, {"label": "Github", "url": "https://github.com/Radarr/Radarr"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "radarr", "port": "$PORT:7878", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('radicale', 'Radicale', 'Radicale is a small but powerful CalDAV (calendars, to-do lists) and CardDAV (contacts) server. It allows you to share calendars and contact lists through CalDAV, CardDAV, and HTTP. Radicale supports events, todos, journal entries, and business cards. It works out-of-the-box, requiring no complicated setup or configuration. Radicale can limit access by authentication and secure connections with TLS. It works with many CalDAV and CardDAV clients, stores all data on the file system in a simple folder structure, and can be extended with plugins. Radicale is GPLv3-licensed free software.', 'calendars', ARRAY['Calendars', 'Productivity', 'Business Apps'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "tomsquest/docker-radicale:3.7.1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5232}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Radicale", "version": "latest", "description": "Radicale is a small but powerful CalDAV (calendars, to-do lists) and CardDAV (contacts) server. It allows you to share calendars and contact lists through CalDAV, CardDAV, and HTTP. Radicale supports events, todos, journal entries, and business cards. It works out-of-the-box, requiring no complicated setup or configuration. Radicale can limit access by authentication and secure connections with TLS. It works with many CalDAV and CardDAV clients, stores all data on the file system in a simple folder structure, and can be extended with plugins. Radicale is GPLv3-licensed free software.", "category": "calendars", "tags": ["Calendars", "Productivity", "Business Apps"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "tomsquest/docker-radicale:3.7.1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5232}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://radicale.org/"}, {"label": "Documentation", "url": "https://radicale.org/v3.html"}, {"label": "Github", "url": "https://github.com/Kozea/Radicale"}], "instructions": "Login with any username or password", "install": [{"docker": {"image": "$IMAGE", "name": "radicale", "port": "$PORT:5232", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Login with any username or password"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('rallly', 'Rallly', 'Rallly is a free, open-source tool designed to simplify your scheduling process. It allows you to create meeting polls in seconds, helping you find a time that works for everyone. With Rallly, you can ditch the back-and-forth emails and streamline your scheduling tasks for a more organized and less stressful workday. The app supports multiple languages and has been used to create over 100k+ polls by 45k+ registered users. Whether you''re an executive assistant at a large organization or simply trying to coordinate a group event, Rallly is the perfect tool to keep your RSVPs simple and your scheduling process efficient.', 'calendars', ARRAY['Calendars', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lukevella/rallly:4.10.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Rallly", "version": "latest", "description": "Rallly is a free, open-source tool designed to simplify your scheduling process. It allows you to create meeting polls in seconds, helping you find a time that works for everyone. With Rallly, you can ditch the back-and-forth emails and streamline your scheduling tasks for a more organized and less stressful workday. The app supports multiple languages and has been used to create over 100k+ polls by 45k+ registered users. Whether you're an executive assistant at a large organization or simply trying to coordinate a group event, Rallly is the perfect tool to keep your RSVPs simple and your scheduling process efficient.", "category": "calendars", "tags": ["Calendars", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lukevella/rallly:4.10.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://rallly.co"}, {"label": "Documentation", "url": "https://support.rallly.co/"}, {"label": "Selfhosting Instructions", "url": "https://github.com/lukevella/rallly-selfhosted"}, {"label": "Github", "url": "https://github.com/lukevella/rallly"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "rallly", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('raneto', 'Raneto', 'Raneto is an open source Knowledgebase platform that uses static Markdown files to power your Knowledgebase.', 'self-hosted', ARRAY[]::text[], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/raneto:0.18.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Raneto", "version": "latest", "description": "Raneto is an open source Knowledgebase platform that uses static Markdown files to power your Knowledgebase.", "category": "self-hosted", "tags": [], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/raneto:0.18.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://raneto.com"}, {"label": "Documentation", "url": "https://docs.linuxserver.io/images/docker-raneto"}, {"label": "Github", "url": "https://github.com/linuxserver/docker-raneto"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "raneto", "port": "$PORT:3000", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('reactive-resume', 'Reactive Resume', 'Reactive Resume is a free and open-source resume builder that simplifies the process of creating, updating, and sharing your resume. With zero user tracking or advertising, your privacy is a top priority. The platform is extremely user-friendly and can be self-hosted in less than 30 seconds if you wish to own your data completely. It''s available in multiple languages and comes packed with features such as real-time editing, dozens of templates, drag-and-drop customisation, and integration with OpenAI for enhancing your writing. You can share a personalised link of your resume to potential employers, track its views or downloads, and customise your page layout by dragging-and-dropping sections.', 'resume-builder', ARRAY['Resume Builder', 'CV', 'Career', 'PDF Generator', 'Privacy', 'Open Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "amruthpillai/reactive-resume:v4.4.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Reactive Resume", "version": "latest", "description": "Reactive Resume is a free and open-source resume builder that simplifies the process of creating, updating, and sharing your resume. With zero user tracking or advertising, your privacy is a top priority. The platform is extremely user-friendly and can be self-hosted in less than 30 seconds if you wish to own your data completely. It's available in multiple languages and comes packed with features such as real-time editing, dozens of templates, drag-and-drop customisation, and integration with OpenAI for enhancing your writing. You can share a personalised link of your resume to potential employers, track its views or downloads, and customise your page layout by dragging-and-dropping sections.", "category": "resume-builder", "tags": ["Resume Builder", "CV", "Career", "PDF Generator", "Privacy", "Open Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "amruthpillai/reactive-resume:v4.4.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://rxresu.me/"}, {"label": "Documentation", "url": "https://docs.rxresume.org/self-hosting/docker"}, {"label": "GitHub", "url": "https://github.com/AmruthPillai/Reactive-Resume"}, {"label": "Demo", "url": "https://rxresu.me/"}], "instructions": "Deploy the stack and open the app on your domain then create the first account and start building resumes, this template uses the Reactive Resume v4.4.5 legacy compatible environment schema with PostgreSQL printer.", "install": [{"docker": {"image": "$IMAGE", "name": "reactive-resume", "port": "$PORT:3000", "volumes": ["/data", "/app/data"], "extra_ports": ["9000:9000"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Deploy the stack and open the app on your domain then create the first account and start building resumes, this template uses the Reactive Resume v4.4.5 legacy compatible environment schema with PostgreSQL printer."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('readarr', 'Readarr', 'Readarr is an ebook and audiobook collection manager designed for Usenet and BitTorrent users. It monitors multiple RSS feeds for new ebooks and audiobooks and interfaces with clients and indexers to grab, sort, and rename them. Readarr also has the ability to automatically upgrade the quality of existing files in your library when a better quality format becomes available. The app features a calendar to see all your upcoming releases in one place, manual search to find all the releases and choose the ones you want, and automatic handling of failed downloads. Readarr ensures you get the right release every time with its custom formats feature, which allows fine control over release prioritization and selection. It also supports major platforms like Windows, Linux, macOS, and others.', 'media', ARRAY['Media', 'Download Manager', 'Books', 'Ebooks', 'Audiobooks'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/readarr:0.4.19-nightly"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8787}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Readarr", "version": "latest", "description": "Readarr is an ebook and audiobook collection manager designed for Usenet and BitTorrent users. It monitors multiple RSS feeds for new ebooks and audiobooks and interfaces with clients and indexers to grab, sort, and rename them. Readarr also has the ability to automatically upgrade the quality of existing files in your library when a better quality format becomes available. The app features a calendar to see all your upcoming releases in one place, manual search to find all the releases and choose the ones you want, and automatic handling of failed downloads. Readarr ensures you get the right release every time with its custom formats feature, which allows fine control over release prioritization and selection. It also supports major platforms like Windows, Linux, macOS, and others.", "category": "media", "tags": ["Media", "Download Manager", "Books", "Ebooks", "Audiobooks"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/readarr:0.4.19-nightly"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8787}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://readarr.com/"}, {"label": "Documentation", "url": "https://wiki.servarr.com/readarr"}, {"label": "Github", "url": "https://github.com/Readarr/Readarr"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "readarr", "port": "$PORT:8787", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('readeck', 'Readeck', 'Readeck is a self-hosted read-it-later service that allows you to save articles, web pages, and other content for later reading. It provides a clean and distraction-free reading experience with features for organizing and managing your saved content.', 'reading', ARRAY['Reading', 'Bookmarking', 'Self-Hosted', 'Articles', 'Content Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "codeberg.org/readeck/readeck:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Readeck", "version": "latest", "description": "Readeck is a self-hosted read-it-later service that allows you to save articles, web pages, and other content for later reading. It provides a clean and distraction-free reading experience with features for organizing and managing your saved content.", "category": "reading", "tags": ["Reading", "Bookmarking", "Self-Hosted", "Articles", "Content Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "codeberg.org/readeck/readeck:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Codeberg", "url": "https://codeberg.org/readeck/readeck"}, {"label": "Website", "url": "https://readeck.org"}, {"label": "Documentation", "url": "https://readeck.org/en/docs/"}], "instructions": "After installation, access the web interface through the provided domain to start saving and organizing your reading list.", "install": [{"docker": {"image": "$IMAGE", "name": "readeck", "port": "$PORT:8000", "volumes": ["/readeck"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After installation, access the web interface through the provided domain to start saving and organizing your reading list."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('readmeabook', 'ReadMeABook', 'ReadMeABook is a self-hosted audiobook request and automation platform—like Radarr/Sonarr + Overseerr for audiobooks. Integrates with Plex or Audiobookshelf, supports torrents (qBittorrent) and Usenet (SABnzbd), Prowlarr for search. Features multi-file chapter merging, e-book sidecars, AI recommendations (BookDate), and admin approval workflows. Includes PostgreSQL and Redis.', 'audiobook', ARRAY['Audiobook', 'Media', 'Plex', 'Automation', 'Open Source', 'Self-hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/kikootwo/readmeabook:1.1.8"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3030}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "ReadMeABook", "version": "latest", "description": "ReadMeABook is a self-hosted audiobook request and automation platform\u2014like Radarr/Sonarr + Overseerr for audiobooks. Integrates with Plex or Audiobookshelf, supports torrents (qBittorrent) and Usenet (SABnzbd), Prowlarr for search. Features multi-file chapter merging, e-book sidecars, AI recommendations (BookDate), and admin approval workflows. Includes PostgreSQL and Redis.", "category": "audiobook", "tags": ["Audiobook", "Media", "Plex", "Automation", "Open Source", "Self-hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/kikootwo/readmeabook:1.1.8"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3030}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/kikootwo/readmeabook"}, {"label": "Documentation", "url": "https://github.com/kikootwo/readmeabook/tree/main/documentation"}], "instructions": "After deployment, access the web UI and run the setup wizard. Set PUBLIC_URL to your domain (e.g. `https://readmeabook.yourdomain.com`) for OAuth (Plex/OIDC). Mount downloads and media volumes for audiobook storage. Connect to Plex or Audiobookshelf, and configure qBittorrent/SABnzbd for downloads.", "install": [{"docker": {"image": "$IMAGE", "name": "readmeabook", "port": "$PORT:3030", "volumes": ["/app/config", "/app/cache", "/downloads", "/media", "/var/lib/postgresql/data", "/var/lib/redis"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deployment, access the web UI and run the setup wizard. Set PUBLIC_URL to your domain (e.g. `https://readmeabook.yourdomain.com`) for OAuth (Plex/OIDC). Mount downloads and media volumes for audiobook storage. Connect to Plex or Audiobookshelf, and configure qBittorrent/SABnzbd for downloads."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('red-discordbot', 'Red-DiscordBot', 'Red-DiscordBot is a fully modular bot for Discord, designed to be easy to use and highly customizable. It features a robust command system, extensive documentation, and a large collection of community-created cogs (modules). The bot supports features like moderation, music playback, games, utility functions, and much more. With its modular design, users can easily add or remove functionality by loading and unloading cogs, making it perfect for both small and large Discord communities.', 'discord', ARRAY['Discord', 'Bot', 'Automation', 'Community', 'Chat', 'Dashboard'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "phasecorex/red-discordbot:audio-py311"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Red-DiscordBot", "version": "latest", "description": "Red-DiscordBot is a fully modular bot for Discord, designed to be easy to use and highly customizable. It features a robust command system, extensive documentation, and a large collection of community-created cogs (modules). The bot supports features like moderation, music playback, games, utility functions, and much more. With its modular design, users can easily add or remove functionality by loading and unloading cogs, making it perfect for both small and large Discord communities.", "category": "discord", "tags": ["Discord", "Bot", "Automation", "Community", "Chat", "Dashboard"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "phasecorex/red-discordbot:audio-py311"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/Cog-Creators/Red-DiscordBot"}, {"label": "Documentation", "url": "https://docs.discord.red/"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/phasecorex/red-discordbot"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "red-discordbot", "port": "$PORT:80", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('redisinsight', 'Redis Insight', 'Redis Insight is an ideal tool for developers who build with any Redis deployments and who want to optimize their development process. Redis Insight lets you visually browse and interact with data, take advantage of the advanced command line interface and diagnostic tools, and so much more.', 'redis', ARRAY['Redis', 'Database Management', 'Data Visualization', 'Performance Monitoring', 'Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "redis/redisinsight:2.70.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5540}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Redis Insight", "version": "latest", "description": "Redis Insight is an ideal tool for developers who build with any Redis deployments and who want to optimize their development process. Redis Insight lets you visually browse and interact with data, take advantage of the advanced command line interface and diagnostic tools, and so much more.", "category": "redis", "tags": ["Redis", "Database Management", "Data Visualization", "Performance Monitoring", "Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "redis/redisinsight:2.70.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5540}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://redis.io/insight"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/redis/redisinsight"}, {"label": "Configuration", "url": "https://redis.io/docs/latest/operate/redisinsight/configuration"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "redisinsight", "port": "$PORT:5540", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('redlib', 'Redlib', 'Redlib is a privacy-focused and lightweight alternative frontend for Reddit, designed to enhance user experience by removing ads, tracking, and unnecessary JavaScript. Built using Rust, Redlib delivers a fast and efficient browsing experience while ensuring user privacy by proxying all requests, including media, through its server. It provides an ad-free, clutter-free interface inspired by Reddit''s modern design, making it an ideal choice for users seeking a secure and streamlined way to browse Reddit content.', 'privacy', ARRAY['Privacy', 'Reddit', 'Alternative Frontend', 'Lightweight', 'Open Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "quay.io/redlib/redlib:sha-ba98178"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Redlib", "version": "latest", "description": "Redlib is a privacy-focused and lightweight alternative frontend for Reddit, designed to enhance user experience by removing ads, tracking, and unnecessary JavaScript. Built using Rust, Redlib delivers a fast and efficient browsing experience while ensuring user privacy by proxying all requests, including media, through its server. It provides an ad-free, clutter-free interface inspired by Reddit's modern design, making it an ideal choice for users seeking a secure and streamlined way to browse Reddit content.", "category": "privacy", "tags": ["Privacy", "Reddit", "Alternative Frontend", "Lightweight", "Open Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "quay.io/redlib/redlib:sha-ba98178"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://github.com/redlib-org/redlib"}, {"label": "Documentation", "url": "https://github.com/redlib-org/redlib#readme"}, {"label": "Public Instances", "url": "https://github.com/redlib-org/redlib-instances"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "redlib", "port": "$PORT:8080", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('redmine', 'Redmine', 'Redmine is an open-source project management and issue-tracking tool. It provides a flexible framework for managing multiple projects and teams, offering features such as Gantt charts, calendar views, and time tracking to keep your projects organized. Redmine supports multiple databases and can be extended through plugins for additional functionality, making it a highly customizable solution for managing tasks, bugs, and collaboration among teams. The tool also includes role-based access control, allowing administrators to assign different permissions to users based on their responsibilities. Redmine integrates with version control systems like Git, Subversion, and Mercurial, enabling developers to track code changes directly from the platform. It supports major platforms including Windows, Linux, and macOS, and can be accessed via a web browser.', 'project-management', ARRAY['Project Management', 'Issue Tracking', 'Collaboration', 'Time Tracking', 'Open Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "redmine:6.1.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Redmine", "version": "latest", "description": "Redmine is an open-source project management and issue-tracking tool. It provides a flexible framework for managing multiple projects and teams, offering features such as Gantt charts, calendar views, and time tracking to keep your projects organized. Redmine supports multiple databases and can be extended through plugins for additional functionality, making it a highly customizable solution for managing tasks, bugs, and collaboration among teams. The tool also includes role-based access control, allowing administrators to assign different permissions to users based on their responsibilities. Redmine integrates with version control systems like Git, Subversion, and Mercurial, enabling developers to track code changes directly from the platform. It supports major platforms including Windows, Linux, and macOS, and can be accessed via a web browser.", "category": "project-management", "tags": ["Project Management", "Issue Tracking", "Collaboration", "Time Tracking", "Open Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "redmine:6.1.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.redmine.org/"}, {"label": "Documentation", "url": "https://www.redmine.org/guide"}, {"label": "Github", "url": "https://github.com/redmine/redmine"}], "instructions": "Default admin login; admin/admin", "install": [{"docker": {"image": "$IMAGE", "name": "redmine", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Default admin login; admin/admin"}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('reitti', 'Reitti', 'Reitti is a self-hosted journey planning and route optimization application designed for public transportation, cycling, and walking routes. Built on OpenStreetMap data, it provides intelligent route calculations using the Photon geocoding engine for address lookups and PostGIS for spatial data processing. The application features a web-based interface for planning multi-modal journeys, real-time route optimization, and comprehensive mapping capabilities. With RabbitMQ for task queuing and Redis for high-performance caching, Reitti delivers fast and responsive route calculations even with complex multi-leg journeys. The system can be configured for specific regions to optimize data storage and performance, making it suitable for cities, regions, or entire countries depending on your needs. Perfect for organizations wanting to provide their own journey planning services, transportation agencies developing custom routing solutions, smart city initiatives requiring private routing infrastructure, or developers building location-based applications with routing capabilities without relying on commercial APIs or sharing user data with third-party services.', 'route-planning', ARRAY['Route Planning', 'Journey Planner', 'Navigation', 'OpenStreetMap', 'Geocoding', 'Transportation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "dedicatedcode/reitti:4.0.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Reitti", "version": "latest", "description": "Reitti is a self-hosted journey planning and route optimization application designed for public transportation, cycling, and walking routes. Built on OpenStreetMap data, it provides intelligent route calculations using the Photon geocoding engine for address lookups and PostGIS for spatial data processing. The application features a web-based interface for planning multi-modal journeys, real-time route optimization, and comprehensive mapping capabilities. With RabbitMQ for task queuing and Redis for high-performance caching, Reitti delivers fast and responsive route calculations even with complex multi-leg journeys. The system can be configured for specific regions to optimize data storage and performance, making it suitable for cities, regions, or entire countries depending on your needs. Perfect for organizations wanting to provide their own journey planning services, transportation agencies developing custom routing solutions, smart city initiatives requiring private routing infrastructure, or developers building location-based applications with routing capabilities without relying on commercial APIs or sharing user data with third-party services.", "category": "route-planning", "tags": ["Route Planning", "Journey Planner", "Navigation", "OpenStreetMap", "Geocoding", "Transportation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "dedicatedcode/reitti:4.0.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Docker Hub", "url": "https://hub.docker.com/r/dedicatedcode/reitti"}, {"label": "Github", "url": "https://github.com/dedicatedcode/reitti"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "reitti", "port": "$PORT:8080", "volumes": ["/var/lib/rabbitmq", "/photon/data", "/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('remmina', 'Remmina', 'Remmina is a remote desktop client designed to be useful for system administrators and travellers who need to work with multiple remote computers. It supports a variety of network protocols, including RDP, VNC, SPICE, NX, XDMCP, SSH and EXEC, all within an integrated and consistent user interface. The app is written in GTK and is designed to be functional on both large and tiny screens. It can be accessed via http://yourhost:3000/ or https://yourhost:3001/. The app is based on Docker Baseimage KasmVNC, which provides additional environment variables and run configurations to enable or disable specific functionality.', 'remote-desktop', ARRAY['Remote Desktop', 'System Administration', 'Network Protocols'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/remmina:1.4.43"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Remmina", "version": "latest", "description": "Remmina is a remote desktop client designed to be useful for system administrators and travellers who need to work with multiple remote computers. It supports a variety of network protocols, including RDP, VNC, SPICE, NX, XDMCP, SSH and EXEC, all within an integrated and consistent user interface. The app is written in GTK and is designed to be functional on both large and tiny screens. It can be accessed via http://yourhost:3000/ or https://yourhost:3001/. The app is based on Docker Baseimage KasmVNC, which provides additional environment variables and run configurations to enable or disable specific functionality.", "category": "remote-desktop", "tags": ["Remote Desktop", "System Administration", "Network Protocols"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/remmina:1.4.43"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://docs.linuxserver.io/images/docker-remmina"}, {"label": "Github", "url": "https://github.com/linuxserver/docker-remmina"}, {"label": "Website", "url": "https://remmina.org"}], "instructions": "use abc:abc to login. To access the login interface, add ?login=true to your URL.", "install": [{"docker": {"image": "$IMAGE", "name": "remmina", "port": "$PORT:3000", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "use abc:abc to login. To access the login interface, add ?login=true to your URL."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('remotely', 'Remotely', 'Remotely is a free, open-source remote support and remote access solution that enables IT professionals to provide remote assistance to users and manage computers remotely. Built with ASP.NET Core, it offers secure remote desktop access, file transfer capabilities, remote command execution, and comprehensive device management features. The platform includes a web-based dashboard for managing connected devices, user authentication, and audit logging. Perfect for IT support teams, managed service providers, and organizations that need to provide remote technical support and system administration.', 'remote-access', ARRAY['Remote Access', 'IT Support', 'Remote Desktop', 'System Administration', 'Remote Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "immybot/remotely:1037"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Remotely", "version": "latest", "description": "Remotely is a free, open-source remote support and remote access solution that enables IT professionals to provide remote assistance to users and manage computers remotely. Built with ASP.NET Core, it offers secure remote desktop access, file transfer capabilities, remote command execution, and comprehensive device management features. The platform includes a web-based dashboard for managing connected devices, user authentication, and audit logging. Perfect for IT support teams, managed service providers, and organizations that need to provide remote technical support and system administration.", "category": "remote-access", "tags": ["Remote Access", "IT Support", "Remote Desktop", "System Administration", "Remote Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "immybot/remotely:1037"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/immense/Remotely"}, {"label": "Documentation", "url": "https://github.com/immense/Remotely#readme"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "remotely", "port": "$PORT:5000", "volumes": ["/app/AppData"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('request-baskets', 'Request Baskets', 'Request Baskets is a lightweight application designed for developers to capture and inspect HTTP requests. It allows creating disposable endpoints to test webhooks, APIs, or any HTTP-based interaction. The application provides an intuitive web interface for monitoring and debugging incoming requests in real time.', 'http-requests', ARRAY['HTTP Requests', 'API Testing', 'Webhooks'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "darklynx/request-baskets:v1.2.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Request Baskets", "version": "latest", "description": "Request Baskets is a lightweight application designed for developers to capture and inspect HTTP requests. It allows creating disposable endpoints to test webhooks, APIs, or any HTTP-based interaction. The application provides an intuitive web interface for monitoring and debugging incoming requests in real time.", "category": "http-requests", "tags": ["HTTP Requests", "API Testing", "Webhooks"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "darklynx/request-baskets:v1.2.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Demo", "url": "https://rbaskets.in/web"}, {"label": "Github", "url": "https://github.com/darklynx/request-baskets"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "request-baskets", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('resiliosync', 'Resilio Sync', 'Sync (Resilio Sync) is a self-hosted file synchronization and sharing application that allows users to securely sync files between devices without relying on cloud storage. It provides a powerful alternative to proprietary cloud-based file sharing services, ensuring complete control over data and privacy. With Sync, users can transfer large files quickly, collaborate on projects in real-time, and maintain data consistency across multiple devices. Built with efficiency and security in mind, Sync is ideal for both personal and business use.', 'file-synchronization', ARRAY['File Synchronization', 'Self-Hosted', 'Privacy', 'Collaboration'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "resilio/sync:2.8.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8888}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Resilio Sync", "version": "latest", "description": "Sync (Resilio Sync) is a self-hosted file synchronization and sharing application that allows users to securely sync files between devices without relying on cloud storage. It provides a powerful alternative to proprietary cloud-based file sharing services, ensuring complete control over data and privacy. With Sync, users can transfer large files quickly, collaborate on projects in real-time, and maintain data consistency across multiple devices. Built with efficiency and security in mind, Sync is ideal for both personal and business use.", "category": "file-synchronization", "tags": ["File Synchronization", "Self-Hosted", "Privacy", "Collaboration"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "resilio/sync:2.8.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8888}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://help.resilio.com/hc/en-us"}, {"label": "Dockerhub Documentation", "url": "https://hub.docker.com/r/resilio/sync"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "resiliosync", "port": "$PORT:8888", "volumes": ["/mnt/sync"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('resourcespace', 'ResourceSpace', 'ResourceSpace is an open-source Digital Asset Management (DAM) system that helps organizations manage, organize, and share their digital assets efficiently. It provides a web-based interface for managing files, images, videos, and other digital resources with features like metadata management, version control, and access control.', 'dam', ARRAY['DAM', 'Asset Management', 'File Management', 'Web Interface', 'Database'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "creecros/resourcespace-docker:v9.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "ResourceSpace", "version": "latest", "description": "ResourceSpace is an open-source Digital Asset Management (DAM) system that helps organizations manage, organize, and share their digital assets efficiently. It provides a web-based interface for managing files, images, videos, and other digital resources with features like metadata management, version control, and access control.", "category": "dam", "tags": ["DAM", "Asset Management", "File Management", "Web Interface", "Database"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "creecros/resourcespace-docker:v9.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.resourcespace.com/"}, {"label": "Documentation", "url": "https://www.resourcespace.com/documentation"}, {"label": "GitHub", "url": "https://github.com/ResourceSpace/ResourceSpace"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "resourcespace", "port": "$PORT:80", "volumes": ["/var/www/html/include", "/var/www/html/filestore", "/srv/storage/testdir"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('restreamer', 'Restreamer', 'datarhei Restreamer is a powerful video streaming platform designed to provide real-time live video streaming on websites and social media platforms. It eliminates the need for additional streaming provider costs for video hosting or software licensing. The app allows teams to live stream and restream everything from webcams to broadcasting, making streaming more efficient and user-friendly. It offers live streaming on websites without additional service providers or video hosting providers, and it''s instantly available, free of charge, and without advertising. Users can share live videos publicly or privately with anyone, or use a secret link to give their audience access to private content. The app also provides a simple streaming server with self-installation on your server or Raspberry Pi. The fully documented API makes datarhei Restreamer easy to adapt to any project.', 'media', ARRAY['Media', 'Video Streaming', 'Live Streaming'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "datarhei/restreamer:2.12.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Restreamer", "version": "latest", "description": "datarhei Restreamer is a powerful video streaming platform designed to provide real-time live video streaming on websites and social media platforms. It eliminates the need for additional streaming provider costs for video hosting or software licensing. The app allows teams to live stream and restream everything from webcams to broadcasting, making streaming more efficient and user-friendly. It offers live streaming on websites without additional service providers or video hosting providers, and it's instantly available, free of charge, and without advertising. Users can share live videos publicly or privately with anyone, or use a secret link to give their audience access to private content. The app also provides a simple streaming server with self-installation on your server or Raspberry Pi. The fully documented API makes datarhei Restreamer easy to adapt to any project.", "category": "media", "tags": ["Media", "Video Streaming", "Live Streaming"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "datarhei/restreamer:2.12.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://docs.datarhei.com/restreamer/"}, {"label": "Github", "url": "https://github.com/datarhei/restreamer"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "restreamer", "port": "$PORT:8080", "volumes": ["/core/config", "/core/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('rocketchat', 'Rocket.Chat', 'Rocket.Chat SIX is a secure and scalable collaboration platform designed to enhance team productivity and customer service experiences. It allows you to own your data and offers extensive customization and integration options. The platform brings together messages, projects, and tasks into one place, enabling teams to work more efficiently. It also provides an omnichannel customer service experience, allowing businesses to engage in contextual interactions with customers, fostering long-term relationships and improved business outcomes. Additionally, Rocket.Chat SIX features a chat engine to drive higher user engagement within your app or website. The platform is built for teams that need more control, offering end-to-end encryption, compliance with various data protection regulations, and a wide range of deployment options to meet your security needs.', 'chat', ARRAY['Chat', 'Communication', 'Collaboration'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "rocketchat/rocket.chat:7.12.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Rocket.Chat", "version": "latest", "description": "Rocket.Chat SIX is a secure and scalable collaboration platform designed to enhance team productivity and customer service experiences. It allows you to own your data and offers extensive customization and integration options. The platform brings together messages, projects, and tasks into one place, enabling teams to work more efficiently. It also provides an omnichannel customer service experience, allowing businesses to engage in contextual interactions with customers, fostering long-term relationships and improved business outcomes. Additionally, Rocket.Chat SIX features a chat engine to drive higher user engagement within your app or website. The platform is built for teams that need more control, offering end-to-end encryption, compliance with various data protection regulations, and a wide range of deployment options to meet your security needs.", "category": "chat", "tags": ["Chat", "Communication", "Collaboration"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "rocketchat/rocket.chat:7.12.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://rocket.chat/"}, {"label": "Documentation", "url": "https://docs.rocket.chat/"}, {"label": "Github", "url": "https://github.com/RocketChat/Rocket.Chat"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "rocketchat", "port": "$PORT:80", "volumes": ["/bitnami/mongodb"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('rotki', 'Rotki', 'Rotki is a comprehensive asset management and accounting application, specifically designed for crypto assets. The app is designed to help with tax reporting by importing, displaying, storing, and generating reports and statistics from cryptocurrency transaction data and other assets. It integrates with multiple exchanges, providing a centralized platform for managing your crypto assets. Rotki also offers the ability to generate profit/loss reports, making it easier to understand your financial standing. It''s important to note that while Rotki aids in tax reporting, it does not provide tax or legal advice, and it''s the user''s responsibility to ensure the accuracy of the data provided to the service. The app is not intended for continuous monitoring of transaction data or for automatic transmission of your transaction data to any tax authority.', 'finance', ARRAY['Finance', 'Analytics'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "rotki/rotki:v1.42.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Rotki", "version": "latest", "description": "Rotki is a comprehensive asset management and accounting application, specifically designed for crypto assets. The app is designed to help with tax reporting by importing, displaying, storing, and generating reports and statistics from cryptocurrency transaction data and other assets. It integrates with multiple exchanges, providing a centralized platform for managing your crypto assets. Rotki also offers the ability to generate profit/loss reports, making it easier to understand your financial standing. It's important to note that while Rotki aids in tax reporting, it does not provide tax or legal advice, and it's the user's responsibility to ensure the accuracy of the data provided to the service. The app is not intended for continuous monitoring of transaction data or for automatic transmission of your transaction data to any tax authority.", "category": "finance", "tags": ["Finance", "Analytics"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "rotki/rotki:v1.42.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://rotki.readthedocs.io/en/latest/"}, {"label": "Github", "url": "https://github.com/rotki/rotki"}, {"label": "Website", "url": "https://rotki.com/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "rotki", "port": "$PORT:80", "volumes": ["/data", "/logs"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('roundcube', 'Roundcube', 'Roundcube webmail is a browser-based, multilingual IMAP client that offers an application-like user interface. It is designed to provide all the functionalities you would expect from an email client. This includes MIME support, an address book, folder manipulation, message searching, and spell checking. The app also supports drag-and-drop message management, multiple sender identities, and a full-featured address book with groups and LDAP connectors. It offers a threaded message listing, IDNA and SMTPUTF8 support, and a responsive skin for multi-device support. Roundcube webmail also features built-in caching for fast mailbox access, unlimited users and messages, import/export functions, and support for PGP encryption.', 'email', ARRAY['Email'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "roundcube/roundcubemail:1.6.15-apache"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Roundcube", "version": "latest", "description": "Roundcube webmail is a browser-based, multilingual IMAP client that offers an application-like user interface. It is designed to provide all the functionalities you would expect from an email client. This includes MIME support, an address book, folder manipulation, message searching, and spell checking. The app also supports drag-and-drop message management, multiple sender identities, and a full-featured address book with groups and LDAP connectors. It offers a threaded message listing, IDNA and SMTPUTF8 support, and a responsive skin for multi-device support. Roundcube webmail also features built-in caching for fast mailbox access, unlimited users and messages, import/export functions, and support for PGP encryption.", "category": "email", "tags": ["Email"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "roundcube/roundcubemail:1.6.15-apache"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://roundcube.net/"}, {"label": "Github", "url": "https://github.com/roundcube/roundcubemail/"}, {"label": "Docker", "url": "https://hub.docker.com/r/roundcube/roundcubemail/"}], "instructions": "After Roundcube is installed, you can log in to the mail accounts on the service where you entered the \"SMTP\" information.", "install": [{"docker": {"image": "$IMAGE", "name": "roundcube", "port": "$PORT:80", "volumes": ["/var/www/html", "/var/roundcube/config", "/var/roundcube/db"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After Roundcube is installed, you can log in to the mail accounts on the service where you entered the \"SMTP\" information."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('rss-bridge', 'RSS-Bridge', 'RSS-Bridge is a self-hosted, open-source tool that generates RSS and Atom feeds for websites that do not provide them natively. It enables users to extract and aggregate content from various web pages, social media platforms, and other online sources into a single, unified RSS feed. This allows users to stay updated with the latest content from multiple sources without manually visiting each site. RSS-Bridge supports various website connectors, filtering options, and output formats to provide a customized feed experience.', 'rss', ARRAY['RSS', 'Feed Aggregation', 'News', 'Content Filtering', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "rssbridge/rss-bridge:sha-ac2608a"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "RSS-Bridge", "version": "latest", "description": "RSS-Bridge is a self-hosted, open-source tool that generates RSS and Atom feeds for websites that do not provide them natively. It enables users to extract and aggregate content from various web pages, social media platforms, and other online sources into a single, unified RSS feed. This allows users to stay updated with the latest content from multiple sources without manually visiting each site. RSS-Bridge supports various website connectors, filtering options, and output formats to provide a customized feed experience.", "category": "rss", "tags": ["RSS", "Feed Aggregation", "News", "Content Filtering", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "rssbridge/rss-bridge:sha-ac2608a"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://rss-bridge.github.io/rss-bridge/"}, {"label": "GitHub", "url": "https://github.com/RSS-Bridge/rss-bridge"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "rss-bridge", "port": "$PORT:80", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('rsshub', 'RSSHub', 'RSSHub is an open-source, user-friendly, and extensible RSS feed generator. It is designed to create RSS feeds from virtually any content. With the ability to aggregate millions of contents from various sources, RSSHub ensures the delivery of new routes, features, and bug fixes. The app is compatible with the browser extension RSSHub Radar and mobile auxiliary apps RSSBud (iOS) and RSSAid (Android). It has adapted to hundreds of websites and thousands of content types, making it a versatile tool for generating RSS feeds.', 'rss', ARRAY['RSS'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "diygod/rsshub:2026-05-04"}, "port": {"type": "integer", "title": "Port HTTP", "default": 1200}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "RSSHub", "version": "latest", "description": "RSSHub is an open-source, user-friendly, and extensible RSS feed generator. It is designed to create RSS feeds from virtually any content. With the ability to aggregate millions of contents from various sources, RSSHub ensures the delivery of new routes, features, and bug fixes. The app is compatible with the browser extension RSSHub Radar and mobile auxiliary apps RSSBud (iOS) and RSSAid (Android). It has adapted to hundreds of websites and thousands of content types, making it a versatile tool for generating RSS feeds.", "category": "rss", "tags": ["RSS"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "diygod/rsshub:2026-05-04"}, "port": {"type": "integer", "title": "Port HTTP", "default": 1200}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://rsshub.app/"}, {"label": "Documentation", "url": "https://docs.rsshub.app/"}, {"label": "Github", "url": "https://github.com/DIYgod/RSSHub"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "rsshub", "port": "$PORT:1200", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('rstudio', 'RStudio', 'RStudio is a powerful integrated development environment (IDE) for R programming and statistical computing. It provides a comprehensive set of tools for data analysis, visualization, and statistical modeling. This server-based version allows you to access RStudio through your web browser, enabling collaborative work and remote access to your R projects from anywhere. Perfect for data scientists, statisticians, and researchers working with R.', 'development', ARRAY['Development', 'IDE', 'R', 'Statistics', 'Data Science', 'Analytics'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "rocker/rstudio:4.5.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8787}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "RStudio", "version": "latest", "description": "RStudio is a powerful integrated development environment (IDE) for R programming and statistical computing. It provides a comprehensive set of tools for data analysis, visualization, and statistical modeling. This server-based version allows you to access RStudio through your web browser, enabling collaborative work and remote access to your R projects from anywhere. Perfect for data scientists, statisticians, and researchers working with R.", "category": "development", "tags": ["Development", "IDE", "R", "Statistics", "Data Science", "Analytics"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "rocker/rstudio:4.5.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8787}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://posit.co/products/open-source/rstudio/"}, {"label": "Documentation", "url": "https://docs.posit.co/ide/server-pro/"}, {"label": "GitHub", "url": "https://github.com/rstudio/rstudio"}], "instructions": "Default username is rstudio and password is 1234", "install": [{"docker": {"image": "$IMAGE", "name": "rstudio", "port": "$PORT:8787", "volumes": ["/home/rstudio"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Default username is rstudio and password is 1234"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('rustdesk', 'Rustdesk', 'Rustdesk is a self-hosted remote desktop application that allows you to access and control devices remotely. It provides an open-source alternative to proprietary remote desktop software, offering full control over your own remote access infrastructure. With Rustdesk, users can securely connect to their computers from anywhere, manage remote desktops efficiently, and ensure privacy by hosting their own Rustdesk relay and ID server. Rustdesk is built with high-performance and encryption in mind, making it suitable for both personal and enterprise use.', 'remote-desktop', ARRAY['Remote Desktop', 'Productivity', 'Security'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/rustdesk:1.4.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Rustdesk", "version": "latest", "description": "Rustdesk is a self-hosted remote desktop application that allows you to access and control devices remotely. It provides an open-source alternative to proprietary remote desktop software, offering full control over your own remote access infrastructure. With Rustdesk, users can securely connect to their computers from anywhere, manage remote desktops efficiently, and ensure privacy by hosting their own Rustdesk relay and ID server. Rustdesk is built with high-performance and encryption in mind, making it suitable for both personal and enterprise use.", "category": "remote-desktop", "tags": ["Remote Desktop", "Productivity", "Security"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/rustdesk:1.4.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://rustdesk.com/docs/en/"}, {"label": "Github", "url": "https://github.com/rustdesk/rustdesk"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "rustdesk", "port": "$PORT:3000", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('rustfs', 'RustFS', 'RustFS is a high-performance, S3-compatible object storage system built in Rust. It is 2.3x faster than MinIO for small object payloads and offers full S3 API compatibility, a built-in web management console, erasure coding with Reed-Solomon for data protection, bitrot detection via HighwayHash, and server-side encryption with AES-256-GCM and ChaCha20-Poly1305. RustFS supports event notifications, bucket versioning, object lifecycle management, bucket replication, and CORS configuration. Licensed under the permissive Apache 2.0 license, it is designed for data lakes, AI workloads, and large-scale storage with a user-friendly deployment experience.', 'object-storage', ARRAY['Object Storage', 'S3', 'Self-Hosted', 'Rust', 'Cloud Storage', 'MinIO Alternative'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "rustfs/rustfs:1.0.0-alpha.99"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9001}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "RustFS", "version": "latest", "description": "RustFS is a high-performance, S3-compatible object storage system built in Rust. It is 2.3x faster than MinIO for small object payloads and offers full S3 API compatibility, a built-in web management console, erasure coding with Reed-Solomon for data protection, bitrot detection via HighwayHash, and server-side encryption with AES-256-GCM and ChaCha20-Poly1305. RustFS supports event notifications, bucket versioning, object lifecycle management, bucket replication, and CORS configuration. Licensed under the permissive Apache 2.0 license, it is designed for data lakes, AI workloads, and large-scale storage with a user-friendly deployment experience.", "category": "object-storage", "tags": ["Object Storage", "S3", "Self-Hosted", "Rust", "Cloud Storage", "MinIO Alternative"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "rustfs/rustfs:1.0.0-alpha.99"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9001}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/rustfs/rustfs"}, {"label": "Documentation", "url": "https://docs.rustfs.com"}, {"label": "Website", "url": "https://rustfs.com"}], "instructions": "Login to the web console using the Access Key and Secret Key configured during setup. The console is available on the default domain.", "install": [{"docker": {"image": "$IMAGE", "name": "rustfs", "port": "$PORT:9001", "volumes": ["/data/rustfs0", "/data/rustfs1", "/data/rustfs2", "/data/rustfs3", "/app/logs"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Login to the web console using the Access Key and Secret Key configured during setup. The console is available on the default domain."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('rybbit', 'Rybbit', 'Rybbit is a comprehensive analytics platform that provides powerful insights into user behavior and application performance. Built with modern web technologies including React frontend and Node.js backend, it offers real-time data processing with ClickHouse and PostgreSQL databases. The platform features a sleek dashboard for visualizing analytics data, user management with authentication, and configurable signup settings. Perfect for businesses looking to gain deep insights into their applications and user interactions.', 'analytics', ARRAY['Analytics', 'Dashboard', 'Self-Hosted', 'Real-time', 'Authentication'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Rybbit", "version": "latest", "description": "Rybbit is a comprehensive analytics platform that provides powerful insights into user behavior and application performance. Built with modern web technologies including React frontend and Node.js backend, it offers real-time data processing with ClickHouse and PostgreSQL databases. The platform features a sleek dashboard for visualizing analytics data, user management with authentication, and configurable signup settings. Perfect for businesses looking to gain deep insights into their applications and user interactions.", "category": "analytics", "tags": ["Analytics", "Dashboard", "Self-Hosted", "Real-time", "Authentication"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/rybbit-io"}, {"label": "Website", "url": "https://rybbit.io"}, {"label": "Documentation", "url": "https://www.rybbit.io/docs"}], "instructions": "After deployment, open your mapped domain to reach the Rybbit UI (Caddy serves the web app and proxies API traffic to the backend). The template generates PostgreSQL and ClickHouse passwords and a Better Auth secret automatically; you do not need to set them by hand unless you rotate credentials later in the services. Create the first account from the UI when sign-up is enabled. To send email (invites, password reset, etc.), add a Resend API key in the backend service environment. For custom domains or HTTPS, finish DNS and routing in Easypanel so the public URL matches how you access the app.", "install": [{"docker": {"image": "$IMAGE", "name": "rybbit", "port": "$PORT:80", "volumes": ["/etc/caddy/Caddyfile", "/data", "/config", "/var/lib/clickhouse", "/etc/clickhouse-server/config.d"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deployment, open your mapped domain to reach the Rybbit UI (Caddy serves the web app and proxies API traffic to the backend). The template generates PostgreSQL and ClickHouse passwords and a Better Auth secret automatically; you do not need to set them by hand unless you rotate credentials later in the services. Create the first account from the UI when sign-up is enabled. To send email (invites, password reset, etc.), add a Resend API key in the backend service environment. For custom domains or HTTPS, finish DNS and routing in Easypanel so the public URL matches how you access the app."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('ryot', 'Ryot', 'Ryot is a self-hosted platform for tracking and managing your media consumption across movies, TV shows, books, anime, manga, video games, podcasts, and more. Designed as an all-in-one solution for media enthusiasts, Ryot lets you maintain a comprehensive record of everything you''ve watched, read, played, or listened to. The application provides powerful tracking features including progress monitoring, ratings, reviews, and custom lists to organize your media library. With integrations for popular platforms like Trakt, Goodreads, and various media databases, Ryot can automatically fetch metadata, cover images, and detailed information for your media entries. The clean, modern interface works seamlessly across devices, allowing you to update your progress from anywhere. Key features include import capabilities from other tracking services, detailed statistics and insights about your media consumption habits, calendar views for upcoming releases, and recommendation suggestions based on your history. Built with performance in mind, Ryot uses PostgreSQL for reliable data storage and provides a fast, responsive experience. Perfect for media enthusiasts who want complete control over their tracking data, users migrating from commercial tracking services who want privacy and ownership, collectors who want to catalog their media libraries, or anyone who enjoys keeping detailed records of their entertainment consumption without relying on third-party platforms.', 'media-tracking', ARRAY['Media Tracking', 'Movies', 'TV Shows', 'Books', 'Video Games', 'Self-Hosted', 'Entertainment'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ignisda/ryot:v10.3.10"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Ryot", "version": "latest", "description": "Ryot is a self-hosted platform for tracking and managing your media consumption across movies, TV shows, books, anime, manga, video games, podcasts, and more. Designed as an all-in-one solution for media enthusiasts, Ryot lets you maintain a comprehensive record of everything you've watched, read, played, or listened to. The application provides powerful tracking features including progress monitoring, ratings, reviews, and custom lists to organize your media library. With integrations for popular platforms like Trakt, Goodreads, and various media databases, Ryot can automatically fetch metadata, cover images, and detailed information for your media entries. The clean, modern interface works seamlessly across devices, allowing you to update your progress from anywhere. Key features include import capabilities from other tracking services, detailed statistics and insights about your media consumption habits, calendar views for upcoming releases, and recommendation suggestions based on your history. Built with performance in mind, Ryot uses PostgreSQL for reliable data storage and provides a fast, responsive experience. Perfect for media enthusiasts who want complete control over their tracking data, users migrating from commercial tracking services who want privacy and ownership, collectors who want to catalog their media libraries, or anyone who enjoys keeping detailed records of their entertainment consumption without relying on third-party platforms.", "category": "media-tracking", "tags": ["Media Tracking", "Movies", "TV Shows", "Books", "Video Games", "Self-Hosted", "Entertainment"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ignisda/ryot:v10.3.10"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://ryot.io"}, {"label": "GitHub", "url": "https://github.com/ignisda/ryot"}, {"label": "Documentation", "url": "https://docs.ryot.io"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "ryot", "port": "$PORT:8000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('saltcorn', 'Saltcorn', 'Saltcorn is an extensible open-source no-code database application builder. It allows you to build web applications based on relational data with flexible views, data types, and layouts. With Saltcorn, you can create dynamic applications without writing code, making it a powerful tool for both developers and non-developers alike.', 'no-code', ARRAY['No-Code', 'Self-Hosted', 'Database Management', 'Web Applications', 'Multi-Tenant'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "saltcorn/saltcorn:1.5.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Saltcorn", "version": "latest", "description": "Saltcorn is an extensible open-source no-code database application builder. It allows you to build web applications based on relational data with flexible views, data types, and layouts. With Saltcorn, you can create dynamic applications without writing code, making it a powerful tool for both developers and non-developers alike.", "category": "no-code", "tags": ["No-Code", "Self-Hosted", "Database Management", "Web Applications", "Multi-Tenant"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "saltcorn/saltcorn:1.5.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://saltcorn.com/"}, {"label": "Github", "url": "https://github.com/saltcorn/saltcorn"}], "instructions": "Delete the migration container, once that is done with migrations.", "install": [{"docker": {"image": "$IMAGE", "name": "saltcorn", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Delete the migration container, once that is done with migrations."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('satisfactory', 'Satisfactory Server', 'Satisfactory Server is a dedicated server for the popular factory building game Satisfactory by Coffee Stain Studios. This containerized server allows you to host your own multiplayer world for friends to join and collaborate on massive factory projects. The server handles all game logic, world persistence, and player connections, while requiring minimal setup and maintenance. Perfect for players who want reliable, 24/7 access to their factory world without having to host the game on their own computer.', 'gaming', ARRAY['Gaming', 'Game Server', 'Multiplayer', 'Factory Simulation', 'Dedicated Server'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "wolveix/satisfactory-server:v1.9.10"}, "port": {"type": "integer", "title": "Port HTTP", "default": 7777}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Satisfactory Server", "version": "latest", "description": "Satisfactory Server is a dedicated server for the popular factory building game Satisfactory by Coffee Stain Studios. This containerized server allows you to host your own multiplayer world for friends to join and collaborate on massive factory projects. The server handles all game logic, world persistence, and player connections, while requiring minimal setup and maintenance. Perfect for players who want reliable, 24/7 access to their factory world without having to host the game on their own computer.", "category": "gaming", "tags": ["Gaming", "Game Server", "Multiplayer", "Factory Simulation", "Dedicated Server"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "wolveix/satisfactory-server:v1.9.10"}, "port": {"type": "integer", "title": "Port HTTP", "default": 7777}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Docker Hub", "url": "https://hub.docker.com/r/wolveix/satisfactory-server"}, {"label": "GitHub", "url": "https://github.com/wolveix/satisfactory-server"}, {"label": "Game Website", "url": "https://www.satisfactorygame.com/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "satisfactory", "port": "$PORT:7777", "volumes": ["/config"], "extra_ports": ["15000:15000", "15777:15777"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('scylladb', 'ScyllaDB', 'ScyllaDB is a distributed NoSQL database that is compatible with Apache Cassandra but offers superior performance and lower latency. It''s designed to handle high-throughput, low-latency workloads with linear scalability. ScyllaDB is written in C++ and uses a shared-nothing architecture, making it highly efficient for modern hardware. It''s particularly well-suited for applications requiring high availability, consistent performance, and massive scalability.', 'database', ARRAY['Database', 'NoSQL', 'Distributed', 'High Performance', 'Scalable'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "scylladb/scylla:6.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 7000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "ScyllaDB", "version": "latest", "description": "ScyllaDB is a distributed NoSQL database that is compatible with Apache Cassandra but offers superior performance and lower latency. It's designed to handle high-throughput, low-latency workloads with linear scalability. ScyllaDB is written in C++ and uses a shared-nothing architecture, making it highly efficient for modern hardware. It's particularly well-suited for applications requiring high availability, consistent performance, and massive scalability.", "category": "database", "tags": ["Database", "NoSQL", "Distributed", "High Performance", "Scalable"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "scylladb/scylla:6.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 7000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.scylladb.com/"}, {"label": "Documentation", "url": "https://docs.scylladb.com/"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/scylladb/scylla"}], "instructions": "Once the server is up, you can connect to ScyllaDB using the following ports 9042 - Native transport (CQL) 9160 - Thrift transport 7000 - Inter-node communication 7001 - SSL inter-node communication 10000 - REST API", "install": [{"docker": {"image": "$IMAGE", "name": "scylladb", "port": "$PORT:7000", "volumes": ["/var/lib/scylla/data", "/var/lib/scylla/commitlog"], "extra_ports": ["7001:7001", "9042:9042", "9160:9160", "10000:10000"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Once the server is up, you can connect to ScyllaDB using the following ports 9042 - Native transport (CQL) 9160 - Thrift transport 7000 - Inter-node communication 7001 - SSL inter-node communication 10000 - REST API"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('seafile', 'Seafile', 'Seafile is a professional, open-source file synchronization and sharing platform with privacy protection and teamwork features. It provides secure file storage, synchronization, and sharing capabilities with end-to-end encryption, making it perfect for teams and organizations that need to collaborate on files while maintaining data security. Seafile supports file versioning, online editing, and mobile access across all platforms.', 'file-sync', ARRAY['File Sync', 'File Sharing', 'Collaboration', 'Self-Hosted', 'Encryption', 'Team Work', 'Document Management', 'Cloud Storage', 'WebDAV', 'Mobile Access'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "seafileltd/seafile-mc:13.0.21"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Seafile", "version": "latest", "description": "Seafile is a professional, open-source file synchronization and sharing platform with privacy protection and teamwork features. It provides secure file storage, synchronization, and sharing capabilities with end-to-end encryption, making it perfect for teams and organizations that need to collaborate on files while maintaining data security. Seafile supports file versioning, online editing, and mobile access across all platforms.", "category": "file-sync", "tags": ["File Sync", "File Sharing", "Collaboration", "Self-Hosted", "Encryption", "Team Work", "Document Management", "Cloud Storage", "WebDAV", "Mobile Access"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "seafileltd/seafile-mc:13.0.21"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/haiwen/seafile"}, {"label": "Documentation", "url": "https://manual.seafile.com/"}, {"label": "Website", "url": "https://hub.docker.com/r/seafileltd/seafile-mc"}], "instructions": "Please go to this document https://ahsonshaikh616.medium.com/deploying-seafile-via-easypanel-feature-rich-file-sync-share-1d2df0a37345", "install": [{"docker": {"image": "$IMAGE", "name": "seafile", "port": "$PORT:80", "volumes": ["/shared"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Please go to this document https://ahsonshaikh616.medium.com/deploying-seafile-via-easypanel-feature-rich-file-sync-share-1d2df0a37345"}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('searxng', 'SearXNG', 'SearXNG is a powerful, privacy-focused metasearch engine that aggregates results from over 70 search services, ensuring your searches remain private and untracked. It offers secure, encrypted connections and the option to use it over Tor for enhanced online anonymity. With about 130 integrated search engines and 60 translations, SearXNG provides a comprehensive and versatile search experience. The app also offers easy integration of search engines and maintains high standards of professional development, including continuous integration, quality assurance, and automated UI testing. SearXNG was launched in 2021 as a fork of the searx project, and it continues to evolve with user-friendly features and improvements.', 'privacy', ARRAY['Privacy', 'Search'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "searxng/searxng:2026.5.5-d3566fe8a"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "SearXNG", "version": "latest", "description": "SearXNG is a powerful, privacy-focused metasearch engine that aggregates results from over 70 search services, ensuring your searches remain private and untracked. It offers secure, encrypted connections and the option to use it over Tor for enhanced online anonymity. With about 130 integrated search engines and 60 translations, SearXNG provides a comprehensive and versatile search experience. The app also offers easy integration of search engines and maintains high standards of professional development, including continuous integration, quality assurance, and automated UI testing. SearXNG was launched in 2021 as a fork of the searx project, and it continues to evolve with user-friendly features and improvements.", "category": "privacy", "tags": ["Privacy", "Search"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "searxng/searxng:2026.5.5-d3566fe8a"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Docs", "url": "https://docs.searxng.org/"}, {"label": "Github", "url": "https://github.com/searxng/searxng"}, {"label": "Docker", "url": "https://hub.docker.com/r/searxng/searxng"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "searxng", "port": "$PORT:8080", "volumes": ["/etc/searxng"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('seatsurfing', 'SeatSurfing', 'SeatSurfing is a comprehensive desk and room booking system that helps organizations manage their workspace efficiently. It provides a user-friendly interface for employees to book desks and meeting rooms, while giving administrators powerful tools to manage spaces, users, and bookings. The system includes features like real-time availability, booking management, and analytics to optimize space utilization.', 'workspace-management', ARRAY['Workspace Management', 'Desk Booking', 'Room Booking', 'Space Management', 'Workplace Analytics'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "seatsurfing/backend:1.28.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "SeatSurfing", "version": "latest", "description": "SeatSurfing is a comprehensive desk and room booking system that helps organizations manage their workspace efficiently. It provides a user-friendly interface for employees to book desks and meeting rooms, while giving administrators powerful tools to manage spaces, users, and bookings. The system includes features like real-time availability, booking management, and analytics to optimize space utilization.", "category": "workspace-management", "tags": ["Workspace Management", "Desk Booking", "Room Booking", "Space Management", "Workplace Analytics"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "seatsurfing/backend:1.28.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://seatsurfing.app/"}, {"label": "Documentation", "url": "https://docs.seatsurfing.app/"}, {"label": "Github", "url": "https://github.com/seatsurfing"}], "instructions": "Login email admin@seatsurfing.local and password 12345678", "install": [{"docker": {"image": "$IMAGE", "name": "seatsurfing", "port": "$PORT:8080", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Login email admin@seatsurfing.local and password 12345678"}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('seaweedfs', 'SeaweedFS', 'SeaweedFS is a fast, simple, and highly scalable distributed file system for storing and serving billions of files. Starting as an object store with O(1) disk seek performance, it has grown into a full-featured storage platform supporting S3 API, WebDAV, FUSE mount, HDFS, and Hadoop integration. The architecture separates concerns into a master server for volume management, a volume server for blob storage, a filer for directory/file abstraction, an S3 gateway for S3 compatibility, and a WebDAV server for mounted drive access. Features include erasure coding, cloud tiering, cross-datacenter replication, AES-256-GCM encryption, automatic compaction, file TTL, and a built-in admin UI. Licensed under Apache 2.0 with 30k+ GitHub stars.', 'object-storage', ARRAY['Object Storage', 'Distributed Storage', 'S3', 'WebDAV', 'Self-Hosted', 'File System'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "chrislusf/seaweedfs:4.23"}, "port": {"type": "integer", "title": "Port HTTP", "default": 7333}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "SeaweedFS", "version": "latest", "description": "SeaweedFS is a fast, simple, and highly scalable distributed file system for storing and serving billions of files. Starting as an object store with O(1) disk seek performance, it has grown into a full-featured storage platform supporting S3 API, WebDAV, FUSE mount, HDFS, and Hadoop integration. The architecture separates concerns into a master server for volume management, a volume server for blob storage, a filer for directory/file abstraction, an S3 gateway for S3 compatibility, and a WebDAV server for mounted drive access. Features include erasure coding, cloud tiering, cross-datacenter replication, AES-256-GCM encryption, automatic compaction, file TTL, and a built-in admin UI. Licensed under Apache 2.0 with 30k+ GitHub stars.", "category": "object-storage", "tags": ["Object Storage", "Distributed Storage", "S3", "WebDAV", "Self-Hosted", "File System"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "chrislusf/seaweedfs:4.23"}, "port": {"type": "integer", "title": "Port HTTP", "default": 7333}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/seaweedfs/seaweedfs"}, {"label": "Documentation", "url": "https://github.com/seaweedfs/seaweedfs/wiki"}, {"label": "Website", "url": "https://seaweedfs.com"}], "instructions": "Open the admin UI.", "install": [{"docker": {"image": "$IMAGE", "name": "seaweedfs", "port": "$PORT:7333", "volumes": ["/data", "/data", "/data"], "extra_ports": ["8333:8333", "8888:8888", "9333:9333", "23646:23646"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Open the admin UI."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('serpbear', 'SerpBear', 'SerpBear is an open-source search engine position tracking app designed to help you monitor your website''s keyword positions in Google. With SerpBear, you can add unlimited domains and keywords to track their Search Engine Results Page (SERP) positions. The app provides email notifications to keep you updated on your keyword position changes on a daily, weekly, or monthly basis. It also features a built-in SERP API for integration with your marketing and data reporting tools. SerpBear integrates with Google Search Console, allowing you to get actual visit counts, impressions, and more for each keyword. You can discover new keywords, identify the most performing ones, and find the most visited pages and countries. The app also allows you to export your domain keywords and their data in CSV files. For a better mobile experience, you can add the PWA app to your mobile. SerpBear is free to run on platforms like mogenius.com or Fly.io. The app uses third-party website scrapers like ScrapingAnt, ScrapingRobot, or your given Proxy IPs to scrape Google search results to see if your domain appears in the search result for the given keyword.', 'analytics', ARRAY['Analytics', 'SEO'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "towfiqi/serpbear:2.0.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "SerpBear", "version": "latest", "description": "SerpBear is an open-source search engine position tracking app designed to help you monitor your website's keyword positions in Google. With SerpBear, you can add unlimited domains and keywords to track their Search Engine Results Page (SERP) positions. The app provides email notifications to keep you updated on your keyword position changes on a daily, weekly, or monthly basis. It also features a built-in SERP API for integration with your marketing and data reporting tools. SerpBear integrates with Google Search Console, allowing you to get actual visit counts, impressions, and more for each keyword. You can discover new keywords, identify the most performing ones, and find the most visited pages and countries. The app also allows you to export your domain keywords and their data in CSV files. For a better mobile experience, you can add the PWA app to your mobile. SerpBear is free to run on platforms like mogenius.com or Fly.io. The app uses third-party website scrapers like ScrapingAnt, ScrapingRobot, or your given Proxy IPs to scrape Google search results to see if your domain appears in the search result for the given keyword.", "category": "analytics", "tags": ["Analytics", "SEO"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "towfiqi/serpbear:2.0.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://docs.serpbear.com"}, {"label": "Github", "url": "https://github.com/towfiqi/serpbear"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "serpbear", "port": "$PORT:80", "volumes": ["/app/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('servas', 'Servas', 'Servas is a self-hosted bookmark management tool that allows you to organize and access your bookmarks in a more efficient and streamlined manner. With Servas, you can categorize your bookmarks using tags and groups, which can also be nested for better organization. The app also features a ''Later List'' where you can add bookmarks that you wish to access at a later time. Servas also comes with a Chrome browser extension, allowing you to add sites to your bookmark list directly from your browser. The app supports multiple user accounts and boasts a responsive design that ensures it looks good on all your devices. For added security, Servas also offers Two Factor Authentication.', 'bookmarks', ARRAY['Bookmarks', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "beromir/servas:1.1.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Servas", "version": "latest", "description": "Servas is a self-hosted bookmark management tool that allows you to organize and access your bookmarks in a more efficient and streamlined manner. With Servas, you can categorize your bookmarks using tags and groups, which can also be nested for better organization. The app also features a 'Later List' where you can add bookmarks that you wish to access at a later time. Servas also comes with a Chrome browser extension, allowing you to add sites to your bookmark list directly from your browser. The app supports multiple user accounts and boasts a responsive design that ensures it looks good on all your devices. For added security, Servas also offers Two Factor Authentication.", "category": "bookmarks", "tags": ["Bookmarks", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "beromir/servas:1.1.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/beromir/Servas"}], "instructions": "Visit /register to create an account", "install": [{"docker": {"image": "$IMAGE", "name": "servas", "port": "$PORT:80", "volumes": ["/var/www/html"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Visit /register to create an account"}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('sessy', 'Sessy', 'Sessy is a self-hosted web application built with Ruby on Rails designed for managing and interacting with AWS Simple Email Service (SES). The application provides a user-friendly interface for managing email sending operations, monitoring email delivery, and working with AWS SES configurations. With persistent storage for application data, Sessy ensures your settings and configurations are retained across container restarts. The application offers a straightforward deployment model with minimal configuration requirements, making it easy to set up and operate. Built on the robust Ruby on Rails framework, Sessy provides a reliable foundation for email service management. Perfect for developers and teams working with AWS SES who want a self-hosted management interface, organizations needing a simple way to interact with their email service infrastructure, or anyone looking for a lightweight self-hosted solution for AWS SES operations without relying on external services.', 'aws', ARRAY['AWS', 'SES', 'Web Application', 'Rails', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/marckohlbrugge/sessy:sha-8d93bde"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Sessy", "version": "latest", "description": "Sessy is a self-hosted web application built with Ruby on Rails designed for managing and interacting with AWS Simple Email Service (SES). The application provides a user-friendly interface for managing email sending operations, monitoring email delivery, and working with AWS SES configurations. With persistent storage for application data, Sessy ensures your settings and configurations are retained across container restarts. The application offers a straightforward deployment model with minimal configuration requirements, making it easy to set up and operate. Built on the robust Ruby on Rails framework, Sessy provides a reliable foundation for email service management. Perfect for developers and teams working with AWS SES who want a self-hosted management interface, organizations needing a simple way to interact with their email service infrastructure, or anyone looking for a lightweight self-hosted solution for AWS SES operations without relying on external services.", "category": "aws", "tags": ["AWS", "SES", "Web Application", "Rails", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/marckohlbrugge/sessy:sha-8d93bde"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://sessy.do"}, {"label": "GitHub", "url": "https://github.com/marckohlbrugge/sessy"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/marckohlbrugge/sessy"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "sessy", "port": "$PORT:80", "volumes": ["/rails/storage"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('sftpgo', 'SFTPGo', 'SFTPGo is a fully featured and highly configurable SFTP server with optional HTTP/S, FTP/S and WebDAV support. It supports local filesystem, encrypted local filesystem, S3 (compatible) Object Storage, Google Cloud Storage, Azure Blob Storage, SFTP.', 'sftp', ARRAY['SFTP', 'File Transfer', 'Self-hosted', 'Open Source', 'Security'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "drakkan/sftpgo:2.7.x"}, "port": {"type": "integer", "title": "Port HTTP", "default": 2022}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "SFTPGo", "version": "latest", "description": "SFTPGo is a fully featured and highly configurable SFTP server with optional HTTP/S, FTP/S and WebDAV support. It supports local filesystem, encrypted local filesystem, S3 (compatible) Object Storage, Google Cloud Storage, Azure Blob Storage, SFTP.", "category": "sftp", "tags": ["SFTP", "File Transfer", "Self-hosted", "Open Source", "Security"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "drakkan/sftpgo:2.7.x"}, "port": {"type": "integer", "title": "Port HTTP", "default": 2022}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://sftpgo.com/"}, {"label": "GitHub", "url": "https://github.com/drakkan/sftpgo"}, {"label": "Documentation", "url": "https://docs.sftpgo.com/2.6/"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/drakkan/sftpgo"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "sftpgo", "port": "$PORT:2022", "volumes": ["/srv/sftpgo", "/var/lib/sftpgo"], "extra_ports": ["2121:2121", "8080:8080", "10080:10080"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('shaarli', 'Shaarli', 'Shaarli is a personal, minimalist, super-fast, and database-free bookmarking service. It allows you to manage and share the links you discover, making it an ideal tool for those who frequently come across interesting content on the web. With Shaarli, you can share, comment, and save links, use it as a minimal blog or writing platform, or even as a read-it-later/todo list. It also serves as a notepad for drafting and saving articles, posts, or ideas, and a knowledge base for keeping notes, documentation, and code snippets. You can edit, view, and search your links, organize them with tags, and even generate ATOM and RSS feeds. Shaarli is self-hosted, meaning you install it on your own server, ensuring your data remains yours. It''s an excellent alternative to commercial services, and it''s free and open-source.', 'bookmarks', ARRAY['Bookmarks', 'Documentation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/shaarli/shaarli:v0.16.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Shaarli", "version": "latest", "description": "Shaarli is a personal, minimalist, super-fast, and database-free bookmarking service. It allows you to manage and share the links you discover, making it an ideal tool for those who frequently come across interesting content on the web. With Shaarli, you can share, comment, and save links, use it as a minimal blog or writing platform, or even as a read-it-later/todo list. It also serves as a notepad for drafting and saving articles, posts, or ideas, and a knowledge base for keeping notes, documentation, and code snippets. You can edit, view, and search your links, organize them with tags, and even generate ATOM and RSS feeds. Shaarli is self-hosted, meaning you install it on your own server, ensuring your data remains yours. It's an excellent alternative to commercial services, and it's free and open-source.", "category": "bookmarks", "tags": ["Bookmarks", "Documentation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/shaarli/shaarli:v0.16.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://demo.shaarli.org/doc/html/index.html"}, {"label": "Github", "url": "https://github.com/shaarli/Shaarli"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "shaarli", "port": "$PORT:80", "volumes": ["/var/www/shaarli/cache", "/var/www/shaarli/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('sharkord', 'Sharkord', 'Sharkord is a lightweight, open-source, self-hosted chat platform designed as a privacy-focused alternative to Discord for small groups. It provides voice, video, text chat, and screen sharing—all running on your own server. Supports screen sharing up to 4K@60fps. Designed for 5-25 users.', 'chat', ARRAY['Chat', 'Voice', 'Video', 'Open Source', 'Self-hosted', 'Discord Alternative', 'Privacy'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "sharkord/sharkord:v0.0.19"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4991}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Sharkord", "version": "latest", "description": "Sharkord is a lightweight, open-source, self-hosted chat platform designed as a privacy-focused alternative to Discord for small groups. It provides voice, video, text chat, and screen sharing\u2014all running on your own server. Supports screen sharing up to 4K@60fps. Designed for 5-25 users.", "category": "chat", "tags": ["Chat", "Voice", "Video", "Open Source", "Self-hosted", "Discord Alternative", "Privacy"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "sharkord/sharkord:v0.0.19"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4991}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://sharkord.com/"}, {"label": "Documentation", "url": "https://sharkord.com/docs"}, {"label": "GitHub", "url": "https://github.com/Sharkord/sharkord"}, {"label": "Demo", "url": "https://demo.sharkord.com/"}], "instructions": "After deployment, access Sharkord via the main domain. Create your server and\ninvite others. Voice and video use port 40000. Data is stored in the data volume.\nNote: Sharkord is in alpha\u2014expect bugs and breaking changes.\n", "install": [{"docker": {"image": "$IMAGE", "name": "sharkord", "port": "$PORT:4991", "volumes": ["/home/bun/.config/sharkord"], "extra_ports": ["40000:40000"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deployment, access Sharkord via the main domain. Create your server and\ninvite others. Voice and video use port 40000. Data is stored in the data volume.\nNote: Sharkord is in alpha\u2014expect bugs and breaking changes.\n"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('shelf', 'Shelf', 'Shelf.nu is an open-source asset management platform designed to help organizations track and manage their physical assets efficiently. It provides features for asset tracking, inventory management, check-in/check-out functionality, and reporting. The platform includes location tracking with maps, user management, and email notifications for asset-related activities.', 'asset-management', ARRAY['Asset Management', 'Inventory', 'Tracking', 'Business', 'PostgreSQL'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/shelf-nu/shelf.nu:main-e54458e"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Shelf", "version": "latest", "description": "Shelf.nu is an open-source asset management platform designed to help organizations track and manage their physical assets efficiently. It provides features for asset tracking, inventory management, check-in/check-out functionality, and reporting. The platform includes location tracking with maps, user management, and email notifications for asset-related activities.", "category": "asset-management", "tags": ["Asset Management", "Inventory", "Tracking", "Business", "PostgreSQL"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/shelf-nu/shelf.nu:main-e54458e"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://docs.shelf.nu/"}, {"label": "GitHub", "url": "https://github.com/shelf-nu/shelf.nu"}, {"label": "Website", "url": "https://www.shelf.nu"}], "instructions": "Make sure to setup your Supabase instance before deploying this template.", "install": [{"docker": {"image": "$IMAGE", "name": "shelf", "port": "$PORT:8080", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Make sure to setup your Supabase instance before deploying this template."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('shelfmark', 'Shelfmark', 'Shelfmark is a self-hosted book management and organization application that provides comprehensive tools for managing your digital book library. Built with modern architecture, Shelfmark offers a web-based interface accessible on port 8084 for organizing, cataloging, and managing your book collection. The system supports book downloads, configuration management, and integration with torrent and usenet download clients. Perfect for book enthusiasts and libraries looking for a self-hosted solution to manage their digital book collections.', 'books', ARRAY['Books', 'Library', 'Self-Hosted', 'E-Books', 'Management', 'Docker'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/calibrain/shelfmark:sha-ba62771"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8084}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Shelfmark", "version": "latest", "description": "Shelfmark is a self-hosted book management and organization application that provides comprehensive tools for managing your digital book library. Built with modern architecture, Shelfmark offers a web-based interface accessible on port 8084 for organizing, cataloging, and managing your book collection. The system supports book downloads, configuration management, and integration with torrent and usenet download clients. Perfect for book enthusiasts and libraries looking for a self-hosted solution to manage their digital book collections.", "category": "books", "tags": ["Books", "Library", "Self-Hosted", "E-Books", "Management", "Docker"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/calibrain/shelfmark:sha-ba62771"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8084}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/calibrain/shelfmark"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "shelfmark", "port": "$PORT:8084", "volumes": ["/books", "/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('shiori', 'Shiori', 'Shiori is a straightforward bookmarks manager, designed as a simple alternative to Pocket. It is written in the Go language and can be used as either a command line application or a web application. Shiori allows for basic bookmark management, including adding, editing, deleting, and searching bookmarks. It also supports importing and exporting bookmarks from and to Netscape Bookmark file and importing bookmarks from Pocket. The application features a clean command line interface and a user-friendly web interface. It is portable and supports sqlite3, PostgreSQL, and MySQL as its database. Shiori also creates an offline archive of the webpage where possible. The Shiori Web Extension is a simple extension for managing bookmarks using Shiori, intended to integrate Shiori with your favorite web browser, allowing you to save and remove bookmarks in Shiori without leaving your current page.', 'bookmarks', ARRAY['Bookmarks', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/go-shiori/shiori:v1.8.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Shiori", "version": "latest", "description": "Shiori is a straightforward bookmarks manager, designed as a simple alternative to Pocket. It is written in the Go language and can be used as either a command line application or a web application. Shiori allows for basic bookmark management, including adding, editing, deleting, and searching bookmarks. It also supports importing and exporting bookmarks from and to Netscape Bookmark file and importing bookmarks from Pocket. The application features a clean command line interface and a user-friendly web interface. It is portable and supports sqlite3, PostgreSQL, and MySQL as its database. Shiori also creates an offline archive of the webpage where possible. The Shiori Web Extension is a simple extension for managing bookmarks using Shiori, intended to integrate Shiori with your favorite web browser, allowing you to save and remove bookmarks in Shiori without leaving your current page.", "category": "bookmarks", "tags": ["Bookmarks", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/go-shiori/shiori:v1.8.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/go-shiori/shiori"}, {"label": "Web Extension", "url": "https://github.com/go-shiori/shiori-web-ext"}], "instructions": "The default account is \"shiori\" with password \"gopher\". It is removed once another \"owner\" account is created.", "install": [{"docker": {"image": "$IMAGE", "name": "shiori", "port": "$PORT:8080", "volumes": ["/src/shiori"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "The default account is \"shiori\" with password \"gopher\". It is removed once another \"owner\" account is created."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('shlink', 'Shlink', 'Shlink is an open-source URL shortener that allows you to create a short URL for your website. It provides a simple and intuitive interface that allows you to create a short URL for your website.', 'url-shortener', ARRAY['URL Shortener', 'Analytics', 'Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "shlinkio/shlink:5.0.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Shlink", "version": "latest", "description": "Shlink is an open-source URL shortener that allows you to create a short URL for your website. It provides a simple and intuitive interface that allows you to create a short URL for your website.", "category": "url-shortener", "tags": ["URL Shortener", "Analytics", "Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "shlinkio/shlink:5.0.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://shlink.io/"}, {"label": "Documentation", "url": "https://shlink.io/documentation/"}, {"label": "Github", "url": "https://github.com/shlinkio/shlink"}], "instructions": "To use this service we need a license key. Create an Account for GeoLite2, Generate a license key, and add it.", "install": [{"docker": {"image": "$IMAGE", "name": "shlink", "port": "$PORT:8080", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "To use this service we need a license key. Create an Account for GeoLite2, Generate a license key, and add it."}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('shm', 'SHM', 'SHM (Self-Hosted Metrics) is privacy-first, agnostic telemetry for self-hosted software—collect usage stats, verify active instances, and understand adoption without spying on users. Instances sign payloads with Ed25519; PostgreSQL stores JSON metrics behind a single Go binary with an embedded dashboard (port 8080). AGPL-3.0; upstream lives under the kOlapsis GitHub organization.', 'telemetry', ARRAY['Telemetry', 'Metrics', 'Self-Hosted', 'PostgreSQL', 'Privacy', 'Go'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/kolapsis/shm:sha-fd3affa"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "SHM", "version": "latest", "description": "SHM (Self-Hosted Metrics) is privacy-first, agnostic telemetry for self-hosted software\u2014collect usage stats, verify active instances, and understand adoption without spying on users. Instances sign payloads with Ed25519; PostgreSQL stores JSON metrics behind a single Go binary with an embedded dashboard (port 8080). AGPL-3.0; upstream lives under the kOlapsis GitHub organization.", "category": "telemetry", "tags": ["Telemetry", "Metrics", "Self-Hosted", "PostgreSQL", "Privacy", "Go"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/kolapsis/shm:sha-fd3affa"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://self-hosted-metrics.com/"}, {"label": "GitHub", "url": "https://github.com/kOlapsis/shm"}, {"label": "Documentation", "url": "https://github.com/kOlapsis/shm/blob/main/docs/DEPLOYMENT.md"}, {"label": "Container registry", "url": "https://github.com/kOlapsis/shm/pkgs/container/shm"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "shm", "port": "$PORT:8080", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('shotcut', 'Shotcut', 'Shotcut is a free, open-source, cross-platform video editor that enables users to create and edit professional-quality videos. Written in C++, it supports a wide range of video formats and codecs thanks to FFmpeg integration. Shotcut provides powerful features such as multi-format timeline editing, 4K resolution support, and advanced video effects and filters. The app offers intuitive drag-and-drop functionality, customizable UI, and support for hardware acceleration. It also includes audio editing tools, frame-accurate seeking, and video compositing capabilities. Shotcut is designed to be user-friendly while offering advanced tools for video enthusiasts and professionals alike. Additional features include support for network stream playback, webcam capture, and external monitoring.', 'video-editing', ARRAY['Video Editing', 'Media', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/shotcut:26.4.30"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Shotcut", "version": "latest", "description": "Shotcut is a free, open-source, cross-platform video editor that enables users to create and edit professional-quality videos. Written in C++, it supports a wide range of video formats and codecs thanks to FFmpeg integration. Shotcut provides powerful features such as multi-format timeline editing, 4K resolution support, and advanced video effects and filters. The app offers intuitive drag-and-drop functionality, customizable UI, and support for hardware acceleration. It also includes audio editing tools, frame-accurate seeking, and video compositing capabilities. Shotcut is designed to be user-friendly while offering advanced tools for video enthusiasts and professionals alike. Additional features include support for network stream playback, webcam capture, and external monitoring.", "category": "video-editing", "tags": ["Video Editing", "Media", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/shotcut:26.4.30"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.shotcut.org/"}, {"label": "Github", "url": "https://github.com/mltframework/shotcut"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "shotcut", "port": "$PORT:3000", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('shynet', 'Shynet', 'Shynet is a powerful, open-source analytics tool designed to provide you with clear, comprehensive insights about your website''s traffic and user behavior. Unlike traditional analytics platforms, Shynet respects user privacy and does not track individual users across websites. Instead, it focuses on providing aggregate data and trends, helping you understand how users interact with your website as a whole. Shynet offers a range of features including real-time analytics, session tracking, and primary key integration. It also supports single-page applications, ensuring you get accurate data even when users navigate between pages within your application. With Shynet, you can easily create and manage multiple services, each with its own unique tracking script. The app also offers an API, allowing you to access all the information displayed on the dashboard programmatically. Whether you''re a small business owner, a web developer, or a data analyst, Shynet provides you with the tools you need to make informed decisions about your website.', 'analytics', ARRAY['Analytics'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "milesmcc/shynet:v0.13.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Shynet", "version": "latest", "description": "Shynet is a powerful, open-source analytics tool designed to provide you with clear, comprehensive insights about your website's traffic and user behavior. Unlike traditional analytics platforms, Shynet respects user privacy and does not track individual users across websites. Instead, it focuses on providing aggregate data and trends, helping you understand how users interact with your website as a whole. Shynet offers a range of features including real-time analytics, session tracking, and primary key integration. It also supports single-page applications, ensuring you get accurate data even when users navigate between pages within your application. With Shynet, you can easily create and manage multiple services, each with its own unique tracking script. The app also offers an API, allowing you to access all the information displayed on the dashboard programmatically. Whether you're a small business owner, a web developer, or a data analyst, Shynet provides you with the tools you need to make informed decisions about your website.", "category": "analytics", "tags": ["Analytics"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "milesmcc/shynet:v0.13.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://github.com/milesmcc/shynet/blob/master/GUIDE.md"}, {"label": "Github", "url": "https://github.com/milesmcc/shynet/"}], "instructions": "Open a console session and run ./manage.py createsuperuser to create your administrator account", "install": [{"docker": {"image": "$IMAGE", "name": "shynet", "port": "$PORT:8080", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Open a console session and run ./manage.py createsuperuser to create your administrator account"}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('sickchill', 'Sickchill', 'SickChill is a self-hosted personal video recorder (PVR) application designed to automate the process of downloading and managing TV shows. It supports a wide range of sources to download content, including torrents and Usenet. With its intuitive interface, you can search for and schedule episodes, track your show library, and get detailed information about your favorite series. SickChill integrates with various media players and tools to organize and play content seamlessly. It also includes features like automatic quality selection, subtitles, and episode renaming for a streamlined viewing experience.', 'tv-shows', ARRAY['TV Shows', 'Media', 'Automation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/sickchill:2024.3.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8081}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Sickchill", "version": "latest", "description": "SickChill is a self-hosted personal video recorder (PVR) application designed to automate the process of downloading and managing TV shows. It supports a wide range of sources to download content, including torrents and Usenet. With its intuitive interface, you can search for and schedule episodes, track your show library, and get detailed information about your favorite series. SickChill integrates with various media players and tools to organize and play content seamlessly. It also includes features like automatic quality selection, subtitles, and episode renaming for a streamlined viewing experience.", "category": "tv-shows", "tags": ["TV Shows", "Media", "Automation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/sickchill:2024.3.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8081}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://github.com/SickChill/SickChill/wiki"}, {"label": "Github", "url": "https://github.com/SickChill/SickChill"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "sickchill", "port": "$PORT:8081", "volumes": ["/config", "/downloads", "/tv"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('sidequests', 'SideQuests', 'SideQuests is a task management application that helps you organize and track your tasks and projects. It provides a simple and intuitive interface for managing your daily activities and side projects.', 'task-management', ARRAY['Task Management', 'Project Management', 'Organization', 'Productivity', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "need4swede/sidequests:1.1.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "SideQuests", "version": "latest", "description": "SideQuests is a task management application that helps you organize and track your tasks and projects. It provides a simple and intuitive interface for managing your daily activities and side projects.", "category": "task-management", "tags": ["Task Management", "Project Management", "Organization", "Productivity", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "need4swede/sidequests:1.1.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/need4swede/sidequests"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "sidequests", "port": "$PORT:8080", "volumes": ["/app/instance"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('silicon-notes', 'Silicon Notes', 'Silicon Notes is a lightweight, low-friction personal knowledge base designed to streamline your note-taking and information organization. The app allows you to edit your notes in plaintext using Markdown, with the added benefit of language syntax highlighting in the rendered HTML. It offers powerful full-text and page title search capabilities, making it easier than ever to find the information you need. The app also features bi-directional page relationships, allowing you to create a complex web of interconnected information. Silicon Notes also includes a table of contents in the left sidebar for easy navigation, and a mobile layout that makes it accessible on any device. The app''s no-frills UI ensures a smooth and distraction-free user experience. Silicon Notes is built with a minimal tech stack, relying on a few smallish dependencies, making it a lightweight and efficient tool for your personal knowledge management.', 'notes', ARRAY['Notes', 'Documentation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "bityard/silicon:0.1.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Silicon Notes", "version": "latest", "description": "Silicon Notes is a lightweight, low-friction personal knowledge base designed to streamline your note-taking and information organization. The app allows you to edit your notes in plaintext using Markdown, with the added benefit of language syntax highlighting in the rendered HTML. It offers powerful full-text and page title search capabilities, making it easier than ever to find the information you need. The app also features bi-directional page relationships, allowing you to create a complex web of interconnected information. Silicon Notes also includes a table of contents in the left sidebar for easy navigation, and a mobile layout that makes it accessible on any device. The app's no-frills UI ensures a smooth and distraction-free user experience. Silicon Notes is built with a minimal tech stack, relying on a few smallish dependencies, making it a lightweight and efficient tool for your personal knowledge management.", "category": "notes", "tags": ["Notes", "Documentation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "bityard/silicon:0.1.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/cu/silicon"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "silicon-notes", "port": "$PORT:5000", "volumes": ["/home/silicon/instance"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('simpletorrent', 'SimpleTorrent', 'SimpleTorrent is a self-hosted remote torrent client that allows you to manage your torrents remotely. Written in Go (golang), it enables you to start torrents remotely and download sets of files on the local disk of the server. These files are then retrievable or streamable via HTTP. The app offers individual file download control, the ability to run an external program on task completion, and a seeding ratio to stop tasks when reached. It also provides a download/upload speed limiter and detailed transfer stats in the web UI. SimpleTorrent supports real-time updates, is mobile-friendly, and offers a fast content server. It also supports IPv6 out of the box and has an updated torrent engine from anacrolix/torrent. Additional features include a torrent watcher, K8s/docker health-check endpoint, extra trackers from an external source, and a protocol handler to magnet.', 'file-management', ARRAY['File Management', 'Media', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "boypt/cloud-torrent:1.3.9"}, "port": {"type": "integer", "title": "Port HTTP", "default": 81}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "SimpleTorrent", "version": "latest", "description": "SimpleTorrent is a self-hosted remote torrent client that allows you to manage your torrents remotely. Written in Go (golang), it enables you to start torrents remotely and download sets of files on the local disk of the server. These files are then retrievable or streamable via HTTP. The app offers individual file download control, the ability to run an external program on task completion, and a seeding ratio to stop tasks when reached. It also provides a download/upload speed limiter and detailed transfer stats in the web UI. SimpleTorrent supports real-time updates, is mobile-friendly, and offers a fast content server. It also supports IPv6 out of the box and has an updated torrent engine from anacrolix/torrent. Additional features include a torrent watcher, K8s/docker health-check endpoint, extra trackers from an external source, and a protocol handler to magnet.", "category": "file-management", "tags": ["File Management", "Media", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "boypt/cloud-torrent:1.3.9"}, "port": {"type": "integer", "title": "Port HTTP", "default": 81}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://github.com/boypt/simple-torrent/wiki"}, {"label": "Github", "url": "https://github.com/boypt/simple-torrent"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "simpletorrent", "port": "$PORT:81", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('simstudio', 'SimStudio AI', 'SimStudio AI is an advanced AI simulation platform that combines cutting-edge artificial intelligence with intuitive design tools. It provides a comprehensive environment for creating, running, and analyzing AI-powered simulations with support for various AI models and integrations. The platform features authentication, email notifications, and extensible AI provider support including local models via Ollama.', 'ai', ARRAY['AI', 'Simulation', 'Machine Learning', 'PostgreSQL', 'Vector Database', 'OAuth', 'Next.js'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/simstudioai/simstudio:v0.6.66"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "SimStudio AI", "version": "latest", "description": "SimStudio AI is an advanced AI simulation platform that combines cutting-edge artificial intelligence with intuitive design tools. It provides a comprehensive environment for creating, running, and analyzing AI-powered simulations with support for various AI models and integrations. The platform features authentication, email notifications, and extensible AI provider support including local models via Ollama.", "category": "ai", "tags": ["AI", "Simulation", "Machine Learning", "PostgreSQL", "Vector Database", "OAuth", "Next.js"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/simstudioai/simstudio:v0.6.66"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://simstudio.ai"}, {"label": "GitHub", "url": "https://github.com/simstudioai/sim"}, {"label": "Documentation", "url": "https://docs.simstudio.ai/introduction"}], "instructions": "Please provide the OAuth credentials for Google or GitHub or both.", "install": [{"docker": {"image": "$IMAGE", "name": "simstudio", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Please provide the OAuth credentials for Google or GitHub or both."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('sinusbot', 'Sinusbot', 'Sinusbot is a powerful and versatile music bot designed for communication platforms like TeamSpeak and Discord. It allows users to stream high-quality audio, manage playlists, and automate music playback seamlessly. Sinusbot is lightweight, highly customizable, and provides an intuitive web interface for managing audio playback. With support for plugins and scripting, Sinusbot can be tailored to meet the needs of any community, enhancing the audio experience for gaming, collaboration, or leisure activities.', 'music-bot', ARRAY['Music Bot', 'Audio Streaming', 'TeamSpeak', 'Discord', 'Automation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "sinusbot/docker:1.0.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8087}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Sinusbot", "version": "latest", "description": "Sinusbot is a powerful and versatile music bot designed for communication platforms like TeamSpeak and Discord. It allows users to stream high-quality audio, manage playlists, and automate music playback seamlessly. Sinusbot is lightweight, highly customizable, and provides an intuitive web interface for managing audio playback. With support for plugins and scripting, Sinusbot can be tailored to meet the needs of any community, enhancing the audio experience for gaming, collaboration, or leisure activities.", "category": "music-bot", "tags": ["Music Bot", "Audio Streaming", "TeamSpeak", "Discord", "Automation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "sinusbot/docker:1.0.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8087}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://sinusbot.github.io/docs/"}, {"label": "Github", "url": "https://github.com/SinusBot"}], "instructions": "Create a user using this command \"useradd --no-create-home -s /sbin/nologin -U sinusbot\", then create directories using this command \"mkdir -p /opt/sinusbot/data /opt/sinusbot/scripts\", then give user permissions to this folder using this command \"chown -R sinusbot:sinusbot /opt/sinusbot\", then run echo $(id -u sinusbot) and echo $(id -g sinusbot) and copy the uid and guid, paste the given ids in the Environmental Section and redeploy, if UID/GUID is\"1000\"/\"1000\", then just redeploy after performing the above instructions", "install": [{"docker": {"image": "$IMAGE", "name": "sinusbot", "port": "$PORT:8087", "volumes": ["/opt/sinusbot/scripts", "/opt/sinusbot/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Create a user using this command \"useradd --no-create-home -s /sbin/nologin -U sinusbot\", then create directories using this command \"mkdir -p /opt/sinusbot/data /opt/sinusbot/scripts\", then give user permissions to this folder using this command \"chown -R sinusbot:sinusbot /opt/sinusbot\", then run echo $(id -u sinusbot) and echo $(id -g sinusbot) and copy the uid and guid, paste the given ids in the Environmental Section and redeploy, if UID/GUID is\"1000\"/\"1000\", then just redeploy after performing the above instructions"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('slash', 'Slash', 'Slash is an open source, self-hosted platform designed to help you organize, manage, and share your most important links. Easily create customizable, human-readable shortcuts to streamline your link management. Use tags to categorize your links and share them easily with your team or publicly.', 'link-management', ARRAY['Link Management', 'Self-Hosted', 'Open Source', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "yourselfhosted/slash:1.0.0-rc.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5231}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Slash", "version": "latest", "description": "Slash is an open source, self-hosted platform designed to help you organize, manage, and share your most important links. Easily create customizable, human-readable shortcuts to streamline your link management. Use tags to categorize your links and share them easily with your team or publicly.", "category": "link-management", "tags": ["Link Management", "Self-Hosted", "Open Source", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "yourselfhosted/slash:1.0.0-rc.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5231}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/yourselfhosted/slash"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "slash", "port": "$PORT:5231", "volumes": ["/var/opt/slash"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('slink', 'Slink', 'Slink is a self-hosted image hosting service that provides secure image upload, storage, and sharing capabilities. It features user management with approval workflows, configurable password requirements, and image processing options. Perfect for teams and organizations that need controlled image sharing.', 'image-hosting', ARRAY['Image Hosting', 'File Sharing', 'User Management', 'Image Processing', 'Web Interface'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "anirdev/slink:v1.6.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Slink", "version": "latest", "description": "Slink is a self-hosted image hosting service that provides secure image upload, storage, and sharing capabilities. It features user management with approval workflows, configurable password requirements, and image processing options. Perfect for teams and organizations that need controlled image sharing.", "category": "image-hosting", "tags": ["Image Hosting", "File Sharing", "User Management", "Image Processing", "Web Interface"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "anirdev/slink:v1.6.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/anirdev/slink"}, {"label": "Documentation", "url": "https://docs.slinkapp.io"}, {"label": "DockerHub", "url": "https://hub.docker.com/r/anirdev/slink"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "slink", "port": "$PORT:3000", "volumes": ["/app/var/data", "/app/slink/images"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('slskd', 'slskd', 'slskd is a modern, web-based client for the Soulseek peer-to-peer file sharing network. It provides a clean, intuitive web interface for browsing, searching, and downloading files from the Soulseek network. Unlike traditional desktop clients, slskd runs as a daemon service that you can access from any device with a web browser. The application supports all core Soulseek features including user searches, room browsing, private messaging, and file sharing. With its containerized deployment, slskd makes it easy to run a persistent Soulseek client on a server or NAS device. It''s perfect for music enthusiasts, collectors, and anyone who wants to participate in the Soulseek community without running a desktop application. The daemon continues to operate even when you''re not actively using the web interface, ensuring you never miss downloads or messages.', 'file-sharing', ARRAY['File Sharing', 'P2P', 'Media', 'Music', 'Self-Hosted', 'Download Manager', 'Soulseek', 'Community'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "slskd/slskd:0.25.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5030}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "slskd", "version": "latest", "description": "slskd is a modern, web-based client for the Soulseek peer-to-peer file sharing network. It provides a clean, intuitive web interface for browsing, searching, and downloading files from the Soulseek network. Unlike traditional desktop clients, slskd runs as a daemon service that you can access from any device with a web browser. The application supports all core Soulseek features including user searches, room browsing, private messaging, and file sharing. With its containerized deployment, slskd makes it easy to run a persistent Soulseek client on a server or NAS device. It's perfect for music enthusiasts, collectors, and anyone who wants to participate in the Soulseek community without running a desktop application. The daemon continues to operate even when you're not actively using the web interface, ensuring you never miss downloads or messages.", "category": "file-sharing", "tags": ["File Sharing", "P2P", "Media", "Music", "Self-Hosted", "Download Manager", "Soulseek", "Community"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "slskd/slskd:0.25.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5030}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://slskd.org"}, {"label": "Documentation", "url": "https://github.com/slskd/slskd/tree/master/docs"}, {"label": "GitHub", "url": "https://github.com/slskd/slskd"}], "instructions": "Default credentials are slskd/slskd.", "install": [{"docker": {"image": "$IMAGE", "name": "slskd", "port": "$PORT:5030", "volumes": ["/app"], "extra_ports": ["5031:5031", "50300:50300"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Default credentials are slskd/slskd."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('smokeping', 'SmokePing', 'SmokePing is a powerful open-source tool designed for network monitoring and latency measurement. It provides real-time visualizations of network latency and packet loss, making it easier to identify and diagnose connectivity issues. SmokePing uses ICMP and other protocols to monitor latency across multiple targets and generates detailed graphs to highlight network performance over time. It supports alerting, letting you know when latency or packet loss exceeds predefined thresholds. With its flexible configuration and plugin system, SmokePing can be adapted to various network environments, providing valuable insights into network health and reliability.', 'network-monitoring', ARRAY['Network Monitoring', 'Latency Measurement', 'Open Source', 'Connectivity', 'Troubleshooting'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/smokeping:2.9.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "SmokePing", "version": "latest", "description": "SmokePing is a powerful open-source tool designed for network monitoring and latency measurement. It provides real-time visualizations of network latency and packet loss, making it easier to identify and diagnose connectivity issues. SmokePing uses ICMP and other protocols to monitor latency across multiple targets and generates detailed graphs to highlight network performance over time. It supports alerting, letting you know when latency or packet loss exceeds predefined thresholds. With its flexible configuration and plugin system, SmokePing can be adapted to various network environments, providing valuable insights into network health and reliability.", "category": "network-monitoring", "tags": ["Network Monitoring", "Latency Measurement", "Open Source", "Connectivity", "Troubleshooting"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/smokeping:2.9.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://oss.oetiker.ch/smokeping/doc/smokeping_install.en.html"}, {"label": "Github", "url": "https://github.com/oetiker/SmokePing"}], "instructions": "You may configure your targets by taking the console from Easypanel", "install": [{"docker": {"image": "$IMAGE", "name": "smokeping", "port": "$PORT:80", "volumes": ["/config", "/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "You may configure your targets by taking the console from Easypanel"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('snapdrop', 'SnapDrop', 'Snapdrop is a self-hosted, browser-based file-sharing platform that allows you to seamlessly transfer files between devices on the same local network. Inspired by Apple''s AirDrop, Snapdrop works across any device and browser without requiring an account or installation. It provides fast, peer-to-peer file transfers using WebRTC, ensuring privacy and efficiency. Snapdrop''s lightweight design ensures minimal resource usage while offering an intuitive user interface for easy file sharing.', 'file-sharing', ARRAY['File Sharing', 'Peer-to-Peer', 'Browser-Based', 'Cross-Platform', 'Productivity', 'WebRTC', 'Secure Transfers', 'Local Network'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/snapdrop:version-b8b78cc2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "SnapDrop", "version": "latest", "description": "Snapdrop is a self-hosted, browser-based file-sharing platform that allows you to seamlessly transfer files between devices on the same local network. Inspired by Apple's AirDrop, Snapdrop works across any device and browser without requiring an account or installation. It provides fast, peer-to-peer file transfers using WebRTC, ensuring privacy and efficiency. Snapdrop's lightweight design ensures minimal resource usage while offering an intuitive user interface for easy file sharing.", "category": "file-sharing", "tags": ["File Sharing", "Peer-to-Peer", "Browser-Based", "Cross-Platform", "Productivity", "WebRTC", "Secure Transfers", "Local Network"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/snapdrop:version-b8b78cc2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://github.com/linuxserver/docker-snapdrop"}, {"label": "GitHub", "url": "https://github.com/RobinLinus/snapdrop"}], "instructions": "Access the Snapdrop service via your browser on devices connected to the same network. Simply drag and drop files to transfer them to other devices detected on the Snapdrop interface.", "install": [{"docker": {"image": "$IMAGE", "name": "snapdrop", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Access the Snapdrop service via your browser on devices connected to the same network. Simply drag and drop files to transfer them to other devices detected on the Snapdrop interface."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('snappymail', 'Snappymail', 'SnappyMail is a lightweight, fast, and self-hosted webmail client designed for efficient email management. Built with a focus on speed and security, SnappyMail offers a clean user interface, seamless IMAP integration, and multi-account support. It is optimized for both desktop and mobile use, providing a smooth and responsive email experience. SnappyMail supports advanced email features such as PGP encryption, custom folders, and customizable themes. With its self-hosted nature, users maintain full control over their emails, ensuring privacy and security.', 'email', ARRAY['Email', 'Webmail', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "djmaze/snappymail:v2.38.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8888}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Snappymail", "version": "latest", "description": "SnappyMail is a lightweight, fast, and self-hosted webmail client designed for efficient email management. Built with a focus on speed and security, SnappyMail offers a clean user interface, seamless IMAP integration, and multi-account support. It is optimized for both desktop and mobile use, providing a smooth and responsive email experience. SnappyMail supports advanced email features such as PGP encryption, custom folders, and customizable themes. With its self-hosted nature, users maintain full control over their emails, ensuring privacy and security.", "category": "email", "tags": ["Email", "Webmail", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "djmaze/snappymail:v2.38.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8888}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://github.com/the-djmaze/snappymail/wiki"}, {"label": "Github", "url": "https://github.com/the-djmaze/snappymail"}], "instructions": "Configure SnappyMail with your IMAP server settings for full functionality.", "install": [{"docker": {"image": "$IMAGE", "name": "snappymail", "port": "$PORT:8888", "volumes": ["/snappymail/data/"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Configure SnappyMail with your IMAP server settings for full functionality."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('snipe-it', 'Snipe-IT', 'Snipe-IT is a powerful, open-source IT asset management system designed to help organizations efficiently manage and track their IT assets. From laptops to licenses, Snipe-IT provides a centralized platform to store, monitor, and manage asset information securely. Unlike traditional asset management systems, Snipe-IT is modern, intuitive, and built for ease of use. It features detailed reporting, asset auditing, and check-in/check-out functionality, ensuring accountability and accuracy for IT teams. Snipe-IT also supports role-based user management and integrates seamlessly with LDAP and SMTP for user authentication and notifications. Whether you''re managing 10 or 10,000 assets, Snipe-IT offers the tools you need to stay organized and improve IT workflow. With robust API support, it can integrate with third-party systems for automation and enhanced reporting. Ideal for businesses of all sizes, Snipe-IT makes IT asset management easy and effective.', 'asset-management', ARRAY['Asset Management', 'Open Source', 'Auditing', 'Reporting'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "snipe/snipe-it:v8.4.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Snipe-IT", "version": "latest", "description": "Snipe-IT is a powerful, open-source IT asset management system designed to help organizations efficiently manage and track their IT assets. From laptops to licenses, Snipe-IT provides a centralized platform to store, monitor, and manage asset information securely. Unlike traditional asset management systems, Snipe-IT is modern, intuitive, and built for ease of use. It features detailed reporting, asset auditing, and check-in/check-out functionality, ensuring accountability and accuracy for IT teams. Snipe-IT also supports role-based user management and integrates seamlessly with LDAP and SMTP for user authentication and notifications. Whether you're managing 10 or 10,000 assets, Snipe-IT offers the tools you need to stay organized and improve IT workflow. With robust API support, it can integrate with third-party systems for automation and enhanced reporting. Ideal for businesses of all sizes, Snipe-IT makes IT asset management easy and effective.", "category": "asset-management", "tags": ["Asset Management", "Open Source", "Auditing", "Reporting"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "snipe/snipe-it:v8.4.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://snipe-it.readme.io/"}, {"label": "GitHub", "url": "https://github.com/snipe/snipe-it"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "snipe-it", "port": "$PORT:80", "volumes": ["/var/lib/snipeit"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('soketi', 'Soketi', 'Soketi Serverless is an open-source WebSockets server that offers a cost-effective, fast, and resilient solution for real-time deployment to Cloudflare. It is designed to be cheaper than any competitor, as you only pay for your infrastructure. It guarantees core message delivery in less than 100ms, thanks to its construction on top of C and porting to Node.js. Soketi is compatible with Pusher Protocol v7, meaning you can connect to the server without needing to replace your existing code. It is ready for production and can scale to hundreds of servers with Redis or NATS without losing performance. Soketi also offers built-in app management, allowing you to define your own app credentials and read from any database. Additionally, it features HTTP Webhooks that trigger HTTP requests whenever a channel gets occupied. Soketi can be deployed to Cloudflare Workers, bringing it closer to your users worldwide. It is also compatible with most popular databases, like MySQL or DynamoDB.', 'developer-tools', ARRAY['Developer Tools', 'Communication'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "quay.io/soketi/soketi:1.6-16-debian"}, "port": {"type": "integer", "title": "Port HTTP", "default": 6001}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Soketi", "version": "latest", "description": "Soketi Serverless is an open-source WebSockets server that offers a cost-effective, fast, and resilient solution for real-time deployment to Cloudflare. It is designed to be cheaper than any competitor, as you only pay for your infrastructure. It guarantees core message delivery in less than 100ms, thanks to its construction on top of C and porting to Node.js. Soketi is compatible with Pusher Protocol v7, meaning you can connect to the server without needing to replace your existing code. It is ready for production and can scale to hundreds of servers with Redis or NATS without losing performance. Soketi also offers built-in app management, allowing you to define your own app credentials and read from any database. Additionally, it features HTTP Webhooks that trigger HTTP requests whenever a channel gets occupied. Soketi can be deployed to Cloudflare Workers, bringing it closer to your users worldwide. It is also compatible with most popular databases, like MySQL or DynamoDB.", "category": "developer-tools", "tags": ["Developer Tools", "Communication"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "quay.io/soketi/soketi:1.6-16-debian"}, "port": {"type": "integer", "title": "Port HTTP", "default": 6001}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://soketi.app/"}, {"label": "Documentation", "url": "https://docs.soketi.app/"}, {"label": "Github", "url": "https://github.com/soketi/soketi/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "soketi", "port": "$PORT:6001", "volumes": [], "extra_ports": ["9601:9601"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('solr', 'Apache Solr', 'Apache Solr is a highly reliable, scalable and fault-tolerant search platform that provides distributed indexing, replication and load-balanced querying, automated failover and recovery, centralized configuration and more. Solr powers the search and navigation features of many of the world''s largest internet sites.', 'search-engine', ARRAY['Search Engine', 'Full-Text Search', 'Apache', 'Indexing', 'Enterprise Search'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "solr:10.0.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8983}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Apache Solr", "version": "latest", "description": "Apache Solr is a highly reliable, scalable and fault-tolerant search platform that provides distributed indexing, replication and load-balanced querying, automated failover and recovery, centralized configuration and more. Solr powers the search and navigation features of many of the world's largest internet sites.", "category": "search-engine", "tags": ["Search Engine", "Full-Text Search", "Apache", "Indexing", "Enterprise Search"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "solr:10.0.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8983}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Official Website", "url": "https://solr.apache.org/"}, {"label": "Documentation", "url": "https://solr.apache.org/guide/"}, {"label": "GitHub", "url": "https://github.com/apache/solr"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "solr", "port": "$PORT:8983", "volumes": ["/var/solr"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('sonarqube', 'SonarQube Community', 'SonarQube Community is an open-source platform for continuous inspection of code quality, designed to detect bugs, vulnerabilities, and code smells across multiple programming languages. It integrates with various CI/CD pipelines, providing valuable insights into code health and maintainability. SonarQube helps teams ensure that their code meets quality standards and aligns with security requirements, promoting efficient software development practices. The Community version is feature-rich and free to use, making it an ideal choice for developers and organizations focused on improving code quality without incurring costs.', 'developer-tools', ARRAY['Developer Tools', 'Code Quality', 'Security', 'Continuous Integration'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "sonarqube:26.4.0.121862-community"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "SonarQube Community", "version": "latest", "description": "SonarQube Community is an open-source platform for continuous inspection of code quality, designed to detect bugs, vulnerabilities, and code smells across multiple programming languages. It integrates with various CI/CD pipelines, providing valuable insights into code health and maintainability. SonarQube helps teams ensure that their code meets quality standards and aligns with security requirements, promoting efficient software development practices. The Community version is feature-rich and free to use, making it an ideal choice for developers and organizations focused on improving code quality without incurring costs.", "category": "developer-tools", "tags": ["Developer Tools", "Code Quality", "Security", "Continuous Integration"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "sonarqube:26.4.0.121862-community"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.sonarqube.org/"}, {"label": "Documentation", "url": "https://docs.sonarqube.org/latest/"}, {"label": "GitHub", "url": "https://github.com/SonarSource/sonarqube"}], "instructions": "Default login; username=admin, password=admin", "install": [{"docker": {"image": "$IMAGE", "name": "sonarqube", "port": "$PORT:9000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Default login; username=admin, password=admin"}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('sonarr', 'Sonarr', 'Sonarr is a Personal Video Recorder (PVR) designed for Usenet and BitTorrent users. It monitors multiple RSS feeds for new episodes of your favorite shows and automatically grabs, sorts, and renames them. Sonarr can also be configured to automatically upgrade the quality of files already downloaded when a better quality format becomes available. It features a calendar to see all your upcoming episodes in one convenient location, and a manual search to find all the releases and choose the one you want. Sonarr also handles failed downloads, automatically blocking the release and trying another one until it finds one that works. It is fully integrated with SABnzbd, NZBGet, Kodi, and Plex, and supports major platforms including Windows, Linux, macOS, and Raspberry Pi.', 'media', ARRAY['Media', 'Calendars', 'Download'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/sonarr:4.0.16"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8989}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Sonarr", "version": "latest", "description": "Sonarr is a Personal Video Recorder (PVR) designed for Usenet and BitTorrent users. It monitors multiple RSS feeds for new episodes of your favorite shows and automatically grabs, sorts, and renames them. Sonarr can also be configured to automatically upgrade the quality of files already downloaded when a better quality format becomes available. It features a calendar to see all your upcoming episodes in one convenient location, and a manual search to find all the releases and choose the one you want. Sonarr also handles failed downloads, automatically blocking the release and trying another one until it finds one that works. It is fully integrated with SABnzbd, NZBGet, Kodi, and Plex, and supports major platforms including Windows, Linux, macOS, and Raspberry Pi.", "category": "media", "tags": ["Media", "Calendars", "Download"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/sonarr:4.0.16"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8989}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://sonarr.tv/"}, {"label": "Documentation", "url": "https://wiki.servarr.com/Sonarr"}, {"label": "Github", "url": "https://github.com/Sonarr/Sonarr"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "sonarr", "port": "$PORT:8989", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('sonatype-nexus', 'Sonatype Nexus', 'Sonatype Nexus is a powerful repository manager designed to streamline the management and storage of binary components. It enables development teams to efficiently organize, share, and deploy artifacts across various formats, such as Maven, npm, Docker, and more. With its robust feature set and enterprise-grade capabilities, Sonatype Nexus improves DevOps workflows by providing secure, scalable, and centralized storage for software assets.', 'repository-management', ARRAY['Repository Management', 'DevOps', 'Artifact Storage', 'Security', 'Open Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "sonatype/nexus3:3.91.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8081}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Sonatype Nexus", "version": "latest", "description": "Sonatype Nexus is a powerful repository manager designed to streamline the management and storage of binary components. It enables development teams to efficiently organize, share, and deploy artifacts across various formats, such as Maven, npm, Docker, and more. With its robust feature set and enterprise-grade capabilities, Sonatype Nexus improves DevOps workflows by providing secure, scalable, and centralized storage for software assets.", "category": "repository-management", "tags": ["Repository Management", "DevOps", "Artifact Storage", "Security", "Open Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "sonatype/nexus3:3.91.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8081}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/sonatype/nexus-public"}, {"label": "Documentation", "url": "https://help.sonatype.com/repomanager3"}, {"label": "Demo", "url": "https://www.sonatype.com/nexus-repository-sonatype"}], "instructions": "After logging in without a password, log out and then log back in using the username admin. To get the password, open the container console tab and run the command cat /nexus-data/admin.password. Once logged in, you will be prompted to change the password.", "install": [{"docker": {"image": "$IMAGE", "name": "sonatype-nexus", "port": "$PORT:8081", "volumes": ["/nexus-data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After logging in without a password, log out and then log back in using the username admin. To get the password, open the container console tab and run the command cat /nexus-data/admin.password. Once logged in, you will be prompted to change the password."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('sortarr', 'Sortarr', 'Sortarr is a read-only analytics and organization tool for Sonarr and Radarr media libraries. It provides a data-driven management layer that helps you identify missing media, mismatches, and optimization opportunities using real playback data from providers like Tautulli, Jellystat, or Plex. Sortarr supports multiple Sonarr and Radarr instances, presents a unified PowerBI-like spreadsheet interface with actionable insights, and never modifies, moves, or renames your media files. All operations are strictly read-only and safe.', 'media', ARRAY['Media', 'Sonarr', 'Radarr', 'Analytics', 'Self-Hosted', 'Plex'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/jaredharper1/sortarr:0.8.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8787}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Sortarr", "version": "latest", "description": "Sortarr is a read-only analytics and organization tool for Sonarr and Radarr media libraries. It provides a data-driven management layer that helps you identify missing media, mismatches, and optimization opportunities using real playback data from providers like Tautulli, Jellystat, or Plex. Sortarr supports multiple Sonarr and Radarr instances, presents a unified PowerBI-like spreadsheet interface with actionable insights, and never modifies, moves, or renames your media files. All operations are strictly read-only and safe.", "category": "media", "tags": ["Media", "Sonarr", "Radarr", "Analytics", "Self-Hosted", "Plex"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/jaredharper1/sortarr:0.8.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8787}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/Jaredharper1/Sortarr"}, {"label": "Documentation", "url": "https://github.com/Jaredharper1/Sortarr/wiki"}], "instructions": "On first launch, add your Sonarr/Radarr instances, a history provider (Tautulli, Jellystat, or Plex), and a playback provider (Plex). Test connections, save configuration, and Sortarr will begin analyzing your libraries immediately.", "install": [{"docker": {"image": "$IMAGE", "name": "sortarr", "port": "$PORT:8787", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "On first launch, add your Sonarr/Radarr instances, a history provider (Tautulli, Jellystat, or Plex), and a playback provider (Plex). Test connections, save configuration, and Sortarr will begin analyzing your libraries immediately."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('soulbeet', 'Soulbeet', 'Soulbeet is a self-hosted music management and downloading application that integrates with slskd (Soulseek daemon) and beets to create a seamless music acquisition and organization workflow. The application provides a web interface for searching and downloading music through the Soulseek peer-to-peer network, then automatically organizing your downloads using beets'' powerful music library management capabilities. Soulbeet connects to your slskd instance to handle the actual Soulseek network communication, allowing you to search for tracks, browse user shares, and queue downloads. Once files are downloaded, beets integration enables automatic tagging, metadata correction, album art fetching, and file organization based on your configured rules. The application uses SQLite for lightweight data persistence and supports custom beets configurations for advanced music library management. Perfect for music enthusiasts who want to build and maintain a well-organized digital music collection, users looking for a self-hosted alternative to music streaming services, audiophiles who prefer to own their music with proper metadata and organization, or anyone who wants to combine the power of Soulseek''s peer-to-peer network with beets'' music library management in a single unified interface.', 'music', ARRAY['Music', 'Downloads', 'Media', 'Self-Hosted', 'Soulseek', 'Library Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "docker.io/docccccc/soulbeet:0.3.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5030}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Soulbeet", "version": "latest", "description": "Soulbeet is a self-hosted music management and downloading application that integrates with slskd (Soulseek daemon) and beets to create a seamless music acquisition and organization workflow. The application provides a web interface for searching and downloading music through the Soulseek peer-to-peer network, then automatically organizing your downloads using beets' powerful music library management capabilities. Soulbeet connects to your slskd instance to handle the actual Soulseek network communication, allowing you to search for tracks, browse user shares, and queue downloads. Once files are downloaded, beets integration enables automatic tagging, metadata correction, album art fetching, and file organization based on your configured rules. The application uses SQLite for lightweight data persistence and supports custom beets configurations for advanced music library management. Perfect for music enthusiasts who want to build and maintain a well-organized digital music collection, users looking for a self-hosted alternative to music streaming services, audiophiles who prefer to own their music with proper metadata and organization, or anyone who wants to combine the power of Soulseek's peer-to-peer network with beets' music library management in a single unified interface.", "category": "music", "tags": ["Music", "Downloads", "Media", "Self-Hosted", "Soulseek", "Library Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "docker.io/docccccc/soulbeet:0.3.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5030}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/terry90/soulbeet"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/docccccc/soulbeet"}, {"label": "Documentation", "url": "https://github.com/terry90/soulbeet#readme"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "soulbeet", "port": "$PORT:5030", "volumes": ["/app", "/app/downloads", "/data", "/downloads", "/music", "/config", "/config/config.yaml"], "extra_ports": ["9765:9765", "50300:50300"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('soulsync', 'SoulSync', 'SoulSync is an automated music synchronization service that bridges the gap between streaming platforms and your local media library. It automatically syncs your Spotify and Tidal playlists to your self-hosted media servers like Plex, Jellyfin, or Navidrome by downloading tracks from Soulseek. The web-based interface provides a centralized dashboard for managing playlist synchronization, monitoring download progress, configuring OAuth connections with streaming services, and organizing your music collection. With automated discovery and intelligent matching algorithms, SoulSync ensures your local library stays up-to-date with your streaming playlists without manual intervention. The service handles the complete workflow from playlist detection through download orchestration to media server integration, making it effortless to maintain an offline music collection that mirrors your online listening habits. Perfect for music enthusiasts who want the convenience of streaming services combined with the reliability and ownership of local media files, audiophiles building high-quality music collections, or users preparing for offline listening scenarios while maintaining synchronization with their curated playlists.', 'music', ARRAY['Music', 'Streaming', 'Synchronization', 'Spotify', 'Tidal', 'Media Server'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "boulderbadgedad/soulsync:2.4.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8008}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "SoulSync", "version": "latest", "description": "SoulSync is an automated music synchronization service that bridges the gap between streaming platforms and your local media library. It automatically syncs your Spotify and Tidal playlists to your self-hosted media servers like Plex, Jellyfin, or Navidrome by downloading tracks from Soulseek. The web-based interface provides a centralized dashboard for managing playlist synchronization, monitoring download progress, configuring OAuth connections with streaming services, and organizing your music collection. With automated discovery and intelligent matching algorithms, SoulSync ensures your local library stays up-to-date with your streaming playlists without manual intervention. The service handles the complete workflow from playlist detection through download orchestration to media server integration, making it effortless to maintain an offline music collection that mirrors your online listening habits. Perfect for music enthusiasts who want the convenience of streaming services combined with the reliability and ownership of local media files, audiophiles building high-quality music collections, or users preparing for offline listening scenarios while maintaining synchronization with their curated playlists.", "category": "music", "tags": ["Music", "Streaming", "Synchronization", "Spotify", "Tidal", "Media Server"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "boulderbadgedad/soulsync:2.4.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8008}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/Nezreka/SoulSync"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/boulderbadgedad/soulsync"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "soulsync", "port": "$PORT:8008", "volumes": ["/app/logs", "/app/downloads", "/app/database", "/music"], "extra_ports": ["8888:8888", "8889:8889"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('sourcegraph', 'Sourcegraph', 'Sourcegraph is a universal code search and intelligence platform designed to help developers find, explore, and understand code across all repositories. It enables teams to improve productivity and code quality by providing a centralized interface for searching, navigating, and understanding codebases. Sourcegraph supports multiple version control systems, languages, and integrations, making it a powerful tool for developers, DevOps, and enterprises. With features like code insights, precise code navigation, and batch changes, Sourcegraph enhances collaboration and streamlines development workflows.', 'code-search', ARRAY['Code Search', 'Developer Tools', 'Productivity', 'Open Source', 'Collaboration'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "sourcegraph/server:6.12.5040"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3370}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Sourcegraph", "version": "latest", "description": "Sourcegraph is a universal code search and intelligence platform designed to help developers find, explore, and understand code across all repositories. It enables teams to improve productivity and code quality by providing a centralized interface for searching, navigating, and understanding codebases. Sourcegraph supports multiple version control systems, languages, and integrations, making it a powerful tool for developers, DevOps, and enterprises. With features like code insights, precise code navigation, and batch changes, Sourcegraph enhances collaboration and streamlines development workflows.", "category": "code-search", "tags": ["Code Search", "Developer Tools", "Productivity", "Open Source", "Collaboration"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "sourcegraph/server:6.12.5040"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3370}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/sourcegraph"}, {"label": "Documentation", "url": "https://docs.sourcegraph.com"}, {"label": "Demo", "url": "https://sourcegraph.com"}], "instructions": "Once the server is ready (logo is displayed in the terminal), navigate to the hostname or IP address on port 7080. Create the admin account, then you'll be guided through setting up Sourcegraph for code searching and navigation.", "install": [{"docker": {"image": "$IMAGE", "name": "sourcegraph", "port": "$PORT:3370", "volumes": ["/etc/sourcegraph", "/var/opt/sourcegraph"], "extra_ports": ["7080:7080"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Once the server is ready (logo is displayed in the terminal), navigate to the hostname or IP address on port 7080. Create the admin account, then you'll be guided through setting up Sourcegraph for code searching and navigation."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('spacebin', 'Spacebin', 'Spacebin is a modern, fast, and reliable pastebin server implemented in Go. Text sharing for the final frontier with features like syntax highlighting, password-protected encrypted pastes, configurable expiration, QR codes, reader view mode, and full API support. 99% self-contained requiring only a database to run, making it perfect for self-hosting.', 'pastebin', ARRAY['Pastebin', 'Go', 'Text Sharing', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "spacebinorg/spirit:v1.1.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Spacebin", "version": "latest", "description": "Spacebin is a modern, fast, and reliable pastebin server implemented in Go. Text sharing for the final frontier with features like syntax highlighting, password-protected encrypted pastes, configurable expiration, QR codes, reader view mode, and full API support. 99% self-contained requiring only a database to run, making it perfect for self-hosting.", "category": "pastebin", "tags": ["Pastebin", "Go", "Text Sharing", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "spacebinorg/spirit:v1.1.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://spaceb.in/"}, {"label": "Documentation", "url": "https://github.com/lukewhrit/spacebin#documentation"}, {"label": "Github", "url": "https://github.com/lukewhrit/spacebin"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "spacebin", "port": "$PORT:9000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('spacedrive', 'SpaceDrive', 'SpaceDrive is a powerful storage and file management solution designed to streamline the organization, synchronization, and access of data across multiple devices. It enables users to efficiently manage their files with real-time synchronization, end-to-end encryption, and scalable storage options. With its robust feature set and enterprise-grade capabilities, SpaceDrive enhances productivity by providing secure, distributed, and decentralized storage for personal and professional use.', 'file-management', ARRAY['File Management', 'Cloud Storage', 'Decentralized Storage', 'Security', 'Open Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/spacedriveapp/spacedrive/server:0.4.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "SpaceDrive", "version": "latest", "description": "SpaceDrive is a powerful storage and file management solution designed to streamline the organization, synchronization, and access of data across multiple devices. It enables users to efficiently manage their files with real-time synchronization, end-to-end encryption, and scalable storage options. With its robust feature set and enterprise-grade capabilities, SpaceDrive enhances productivity by providing secure, distributed, and decentralized storage for personal and professional use.", "category": "file-management", "tags": ["File Management", "Cloud Storage", "Decentralized Storage", "Security", "Open Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/spacedriveapp/spacedrive/server:0.4.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/spacedriveapp/spacedrive"}, {"label": "Documentation", "url": "https:/spacedrive.com"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "spacedrive", "port": "$PORT:80", "volumes": ["/var/spacedrive"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('sparkyfitness', 'SparkyFitness', 'SparkyFitness is a self-hosted, privacy-first alternative to MyFitnessPal. Track nutrition, exercise, hydration, and body metrics while keeping full control of your data. Built for families with AI-powered features, SparkyFitness offers comprehensive health tracking with integrations for Apple Health, Google Health Connect, Fitbit, Garmin Connect, and Withings. Features include goal setting, interactive charts, long-term reports, and optional AI chatbot for conversational data logging.', 'fitness', ARRAY['Fitness', 'Health Tracking', 'Self-Hosted', 'Privacy', 'Nutrition'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "codewithcj/sparkyfitness:v0.16.5.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "SparkyFitness", "version": "latest", "description": "SparkyFitness is a self-hosted, privacy-first alternative to MyFitnessPal. Track nutrition, exercise, hydration, and body metrics while keeping full control of your data. Built for families with AI-powered features, SparkyFitness offers comprehensive health tracking with integrations for Apple Health, Google Health Connect, Fitbit, Garmin Connect, and Withings. Features include goal setting, interactive charts, long-term reports, and optional AI chatbot for conversational data logging.", "category": "fitness", "tags": ["Fitness", "Health Tracking", "Self-Hosted", "Privacy", "Nutrition"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "codewithcj/sparkyfitness:v0.16.5.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://codewithcj.github.io/SparkyFitness"}, {"label": "GitHub", "url": "https://github.com/CodeWithCJ/SparkyFitness"}, {"label": "Documentation", "url": "https://codewithcj.github.io/SparkyFitness"}, {"label": "Docker Hub Server", "url": "https://hub.docker.com/r/codewithcj/sparkyfitness_server"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "sparkyfitness", "port": "$PORT:80", "volumes": ["/app/SparkyFitnessServer/backup", "/app/SparkyFitnessServer/uploads"], "extra_ports": ["3010:3010"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('speedtest-tracker', 'Speedtest Tracker', 'Speedtest Tracker is a self-hosted internet performance tracking application that runs speedtests and displays the results in a clean web interface. It automatically runs periodic speed tests using various providers like Ookla Speedtest, and stores historical data to track your internet connection performance over time. Perfect for monitoring ISP performance, network troubleshooting, and keeping records of internet speed changes.', 'network-monitoring', ARRAY['Network Monitoring', 'Speed Test', 'Performance', 'Self-Hosted', 'Tracking'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/speedtest-tracker:1.14.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Speedtest Tracker", "version": "latest", "description": "Speedtest Tracker is a self-hosted internet performance tracking application that runs speedtests and displays the results in a clean web interface. It automatically runs periodic speed tests using various providers like Ookla Speedtest, and stores historical data to track your internet connection performance over time. Perfect for monitoring ISP performance, network troubleshooting, and keeping records of internet speed changes.", "category": "network-monitoring", "tags": ["Network Monitoring", "Speed Test", "Performance", "Self-Hosted", "Tracking"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/speedtest-tracker:1.14.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://docs.speedtest-tracker.dev/"}, {"label": "GitHub", "url": "https://github.com/alexjustesen/speedtest-tracker"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "speedtest-tracker", "port": "$PORT:80", "volumes": ["/config", "/config/keys"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('sqlchat', 'SQLChat', 'SQLChat is a chat-based SQL client powered by ChatGPT that allows you to interact with your databases using natural language. It provides an intuitive interface for querying databases, exploring data, and learning SQL through conversational interactions. SQLChat supports multiple database types and integrates with OpenAI''s GPT models to translate natural language queries into SQL statements, making database interactions more accessible for both beginners and experienced developers.', 'database', ARRAY['Database', 'SQL', 'AI', 'ChatGPT', 'Query Tool', 'Natural Language', 'Next.js'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "sqlchat/sqlchat:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "SQLChat", "version": "latest", "description": "SQLChat is a chat-based SQL client powered by ChatGPT that allows you to interact with your databases using natural language. It provides an intuitive interface for querying databases, exploring data, and learning SQL through conversational interactions. SQLChat supports multiple database types and integrates with OpenAI's GPT models to translate natural language queries into SQL statements, making database interactions more accessible for both beginners and experienced developers.", "category": "database", "tags": ["Database", "SQL", "AI", "ChatGPT", "Query Tool", "Natural Language", "Next.js"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "sqlchat/sqlchat:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/sqlchat/sqlchat"}, {"label": "Documentation", "url": "https://github.com/sqlchat/sqlchat#readme"}, {"label": "Demo", "url": "https://sqlchat.ai"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "sqlchat", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('squidex', 'Squidex', 'Squidex is an open-source, headless CMS designed for seamless content management across multiple platforms. It provides a real-time GraphQL API, fine-grained permissions, and a flexible workflow for content collaboration. Squidex supports event sourcing and integrates well with modern applications, ensuring a structured and efficient content distribution.', 'headless-cms', ARRAY['Headless CMS', 'API-Driven', 'Content Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "squidex/squidex:7.23.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Squidex", "version": "latest", "description": "Squidex is an open-source, headless CMS designed for seamless content management across multiple platforms. It provides a real-time GraphQL API, fine-grained permissions, and a flexible workflow for content collaboration. Squidex supports event sourcing and integrates well with modern applications, ensuring a structured and efficient content distribution.", "category": "headless-cms", "tags": ["Headless CMS", "API-Driven", "Content Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "squidex/squidex:7.23.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://docs.squidex.io/"}, {"label": "Github", "url": "https://github.com/Squidex/squidex"}], "instructions": "If you do not choose any identity provider, you can register a user when you go to the browser.", "install": [{"docker": {"image": "$IMAGE", "name": "squidex", "port": "$PORT:80", "volumes": ["/app/Assets"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "If you do not choose any identity provider, you can register a user when you go to the browser."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('sshwifty', 'Sshwifty', 'Sshwifty is a web-based SSH and Telnet client that allows you to access these services directly from any standard web browser. It can be deployed on your computer or server, providing a convenient and accessible interface for SSH and Telnet connections. Sshwifty is designed to be highly configurable, allowing you to set up multiple servers, define presets for known remotes, and even restrict connections to preset remotes only. It also supports secure connections through TLS, and can be configured to connect through a Socks5 proxy. Whether you need to connect to a remote server or a local machine, Sshwifty provides a flexible and user-friendly solution.', 'developer-tools', ARRAY['Developer Tools', 'SSH', 'Telnet'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "niruix/sshwifty:0.4.5-beta-release"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8182}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Sshwifty", "version": "latest", "description": "Sshwifty is a web-based SSH and Telnet client that allows you to access these services directly from any standard web browser. It can be deployed on your computer or server, providing a convenient and accessible interface for SSH and Telnet connections. Sshwifty is designed to be highly configurable, allowing you to set up multiple servers, define presets for known remotes, and even restrict connections to preset remotes only. It also supports secure connections through TLS, and can be configured to connect through a Socks5 proxy. Whether you need to connect to a remote server or a local machine, Sshwifty provides a flexible and user-friendly solution.", "category": "developer-tools", "tags": ["Developer Tools", "SSH", "Telnet"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "niruix/sshwifty:0.4.5-beta-release"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8182}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/nirui/sshwifty"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "sshwifty", "port": "$PORT:8182", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('stalwart', 'Stalwart', 'Stalwart is a modern, all-in-one mail and collaboration server written in Rust for security and performance. It bundles SMTP, IMAP, JMAP, POP3, CalDAV, CardDAV, and WebDAV into a single binary with a unified configuration. Features include a built-in spam and phishing filter with LLM-driven analysis, DMARC/DKIM/SPF/ARC authentication, encryption at rest with S/MIME or OpenPGP, automatic TLS via ACME, full-text search in 17 languages, Sieve scripting, and a web-based admin dashboard. It supports pluggable storage backends (RocksDB, FoundationDB, PostgreSQL, MySQL, SQLite, S3, Redis) and scales from a single instance to thousands of nodes with built-in clustering, load balancing, and fault tolerance.', 'email', ARRAY['Email', 'Mail Server', 'SMTP', 'IMAP', 'CalDAV', 'CardDAV', 'Self-Hosted', 'Collaboration'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/stalwartlabs/stalwart:v0.15.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 25}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Stalwart", "version": "latest", "description": "Stalwart is a modern, all-in-one mail and collaboration server written in Rust for security and performance. It bundles SMTP, IMAP, JMAP, POP3, CalDAV, CardDAV, and WebDAV into a single binary with a unified configuration. Features include a built-in spam and phishing filter with LLM-driven analysis, DMARC/DKIM/SPF/ARC authentication, encryption at rest with S/MIME or OpenPGP, automatic TLS via ACME, full-text search in 17 languages, Sieve scripting, and a web-based admin dashboard. It supports pluggable storage backends (RocksDB, FoundationDB, PostgreSQL, MySQL, SQLite, S3, Redis) and scales from a single instance to thousands of nodes with built-in clustering, load balancing, and fault tolerance.", "category": "email", "tags": ["Email", "Mail Server", "SMTP", "IMAP", "CalDAV", "CardDAV", "Self-Hosted", "Collaboration"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/stalwartlabs/stalwart:v0.15.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 25}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://stalw.art"}, {"label": "GitHub", "url": "https://github.com/stalwartlabs/stalwart"}, {"label": "Documentation", "url": "https://stalw.art/docs/install/get-started"}], "instructions": "On first boot, Stalwart auto-generates admin credentials and prints them to the container logs. Check the service logs to find the admin username and password. Then access the web admin at the service domain and log in. From there, configure your domain under Management > Directory > Domains, and Stalwart will generate the required DNS records (MX, DKIM, SPF, DMARC) for you. Set the correct server hostname in Settings > Server > Network. Mail ports (SMTP 25, submission 587/465, IMAP 143/993, POP3 110/995, ManageSieve 4190) are exposed for direct access.", "install": [{"docker": {"image": "$IMAGE", "name": "stalwart", "port": "$PORT:25", "volumes": ["/opt/stalwart"], "extra_ports": ["110:110", "143:143", "465:465", "587:587", "993:993", "995:995", "4190:4190", "8080:8080"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "On first boot, Stalwart auto-generates admin credentials and prints them to the container logs. Check the service logs to find the admin username and password. Then access the web admin at the service domain and log in. From there, configure your domain under Management > Directory > Domains, and Stalwart will generate the required DNS records (MX, DKIM, SPF, DMARC) for you. Set the correct server hostname in Settings > Server > Network. Mail ports (SMTP 25, submission 587/465, IMAP 143/993, POP3 110/995, ManageSieve 4190) are exposed for direct access."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('standardnotes', 'StandardNotes', 'StandardNotes is a private, end-to-end encrypted notes app that provides a secure platform for writing and organizing your thoughts. It offers a clean, distraction-free interface with strong encryption to protect your privacy. The self-hosted version gives you complete control over your data while maintaining all the security features of the cloud version.', 'notes-app', ARRAY['Notes App', 'Encryption', 'Self-Hosted', 'Privacy', 'Writing', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "standardnotes/web:f4a94811848ea19550703d5dcd2b446091bf9536"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "StandardNotes", "version": "latest", "description": "StandardNotes is a private, end-to-end encrypted notes app that provides a secure platform for writing and organizing your thoughts. It offers a clean, distraction-free interface with strong encryption to protect your privacy. The self-hosted version gives you complete control over your data while maintaining all the security features of the cloud version.", "category": "notes-app", "tags": ["Notes App", "Encryption", "Self-Hosted", "Privacy", "Writing", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "standardnotes/web:f4a94811848ea19550703d5dcd2b446091bf9536"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://docs.standardnotes.com/self-hosting/getting-started"}, {"label": "Github", "url": "https://github.com/standardnotes/app"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "standardnotes", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('statping-ng', 'Statping-ng', 'Statping is a web and app status monitoring tool designed for any type of project. It automatically fetches your application and generates a beautiful, feature-rich status page. This status page generator supports MySQL, Postgres, or SQLite on multiple operating systems, ensuring future-proof and resilient monitoring. If your server crashes, your Statping service will remain online to notify your users of downtime. Lightweight and fast, Statping is available for Linux, Mac, and Windows, and even on a Raspberry Pi. The mobile app, available on the App Store and Google Play, allows you to view services, receive notifications when a service is offline, and manage groups, users, services, and messages. Statping can run on any server, from Docker to AWS EC2, and offers custom SASS styling for complete customization of your status page. It includes email notification via SMTP and Slack integration, and allows you to create your own plugins to interact with every element of your status page. With its easy-to-use dashboard, you can monitor your websites and applications with a basic HTTP GET request or a POST request with your own JSON.', 'monitoring', ARRAY['Monitoring', 'Status Page', 'Notifications'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "adamboutcher/statping-ng:v0.90.78"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Statping-ng", "version": "latest", "description": "Statping is a web and app status monitoring tool designed for any type of project. It automatically fetches your application and generates a beautiful, feature-rich status page. This status page generator supports MySQL, Postgres, or SQLite on multiple operating systems, ensuring future-proof and resilient monitoring. If your server crashes, your Statping service will remain online to notify your users of downtime. Lightweight and fast, Statping is available for Linux, Mac, and Windows, and even on a Raspberry Pi. The mobile app, available on the App Store and Google Play, allows you to view services, receive notifications when a service is offline, and manage groups, users, services, and messages. Statping can run on any server, from Docker to AWS EC2, and offers custom SASS styling for complete customization of your status page. It includes email notification via SMTP and Slack integration, and allows you to create your own plugins to interact with every element of your status page. With its easy-to-use dashboard, you can monitor your websites and applications with a basic HTTP GET request or a POST request with your own JSON.", "category": "monitoring", "tags": ["Monitoring", "Status Page", "Notifications"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "adamboutcher/statping-ng:v0.90.78"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://github.com/statping/statping"}, {"label": "Documentation", "url": "https://github.com/statping/statping"}, {"label": "Github", "url": "https://github.com/statping/statping"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "statping-ng", "port": "$PORT:8080", "volumes": ["/app"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('steamcmd', 'SteamCMD', 'SteamCMD is a command-line version of the Steam client for installing and updating Steam games and dedicated servers. It''s perfect for managing game servers and game installations.', 'steam', ARRAY['Steam', 'Game Server', 'Self-hosted', 'Gaming'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "steamcmd/steamcmd:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "SteamCMD", "version": "latest", "description": "SteamCMD is a command-line version of the Steam client for installing and updating Steam games and dedicated servers. It's perfect for managing game servers and game installations.", "category": "steam", "tags": ["Steam", "Game Server", "Self-hosted", "Gaming"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "steamcmd/steamcmd:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://developer.valvesoftware.com/wiki/SteamCMD"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/steamcmd/steamcmd"}], "instructions": "After installation, you can use SteamCMD to install and update games. The installation directory can be configured in the settings.", "install": [{"docker": {"image": "$IMAGE", "name": "steamcmd", "port": "$PORT:80", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After installation, you can use SteamCMD to install and update games. The installation directory can be configured in the settings."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('stirlingpdf', 'StirlingPDF', 'StirlingPDF is an open-source PDF management tool designed to streamline PDF handling tasks for both individual users and businesses. It enables users to create, merge, split, compress, and convert PDF documents with ease. Built to support a wide range of platforms, including Linux, Windows, and macOS, StirlingPDF ensures flexibility and resilience for everyday PDF management. Its user-friendly interface and powerful backend make it suitable for both simple and complex PDF workflows. StirlingPDF can run on personal computers or be deployed on servers, offering seamless API access for integration into larger systems. Lightweight and efficient, StirlingPDF is ideal for individual users, small businesses, and large enterprises alike, ensuring reliable PDF manipulation without the need for costly subscriptions. It supports MySQL, PostgreSQL, or SQLite databases, providing robust data handling across various infrastructures.', 'pdf', ARRAY['PDF', 'Document Management', 'Open Source', 'API Integration', 'PDF Conversion'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "frooodle/s-pdf:2.10.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "StirlingPDF", "version": "latest", "description": "StirlingPDF is an open-source PDF management tool designed to streamline PDF handling tasks for both individual users and businesses. It enables users to create, merge, split, compress, and convert PDF documents with ease. Built to support a wide range of platforms, including Linux, Windows, and macOS, StirlingPDF ensures flexibility and resilience for everyday PDF management. Its user-friendly interface and powerful backend make it suitable for both simple and complex PDF workflows. StirlingPDF can run on personal computers or be deployed on servers, offering seamless API access for integration into larger systems. Lightweight and efficient, StirlingPDF is ideal for individual users, small businesses, and large enterprises alike, ensuring reliable PDF manipulation without the need for costly subscriptions. It supports MySQL, PostgreSQL, or SQLite databases, providing robust data handling across various infrastructures.", "category": "pdf", "tags": ["PDF", "Document Management", "Open Source", "API Integration", "PDF Conversion"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "frooodle/s-pdf:2.10.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://stirlingpdf.io/"}, {"label": "Documentation", "url": "https://stirlingpdf.io/"}, {"label": "Github", "url": "https://github.com/Stirling-Tools/Stirling-PDF"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "stirlingpdf", "port": "$PORT:8080", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('strapi', 'Strapi', 'Strapi is a leading open-source headless CMS that is fully customizable and built with 100% JavaScript. It allows you to manage any content, anywhere, providing you with the freedom to use your favorite tools and frameworks. With Strapi, you can build apps quickly, getting your backend done in minutes instead of weeks. You can easily build customizable content APIs and use them with a modern tech stack. Strapi also allows you to effortlessly create content structures that flex to your needs, write, edit, and manage any content types, and build apps and digital experiences without the distraction of CMS complexities. You can consume Strapi API from any client using REST or GraphQL, and deploy on Strapi Cloud or on any cloud platforms.', 'cms', ARRAY['CMS'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "strapi/strapi:3.6.8-alpine"}, "port": {"type": "integer", "title": "Port HTTP", "default": 1337}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Strapi", "version": "latest", "description": "Strapi is a leading open-source headless CMS that is fully customizable and built with 100% JavaScript. It allows you to manage any content, anywhere, providing you with the freedom to use your favorite tools and frameworks. With Strapi, you can build apps quickly, getting your backend done in minutes instead of weeks. You can easily build customizable content APIs and use them with a modern tech stack. Strapi also allows you to effortlessly create content structures that flex to your needs, write, edit, and manage any content types, and build apps and digital experiences without the distraction of CMS complexities. You can consume Strapi API from any client using REST or GraphQL, and deploy on Strapi Cloud or on any cloud platforms.", "category": "cms", "tags": ["CMS"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "strapi/strapi:3.6.8-alpine"}, "port": {"type": "integer", "title": "Port HTTP", "default": 1337}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://strapi.io/"}, {"label": "Documentation", "url": "https://docs.strapi.io/developer-docs/latest/getting-started/introduction.html"}, {"label": "Github", "url": "https://github.com/strapi"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "strapi", "port": "$PORT:1337", "volumes": ["/srv/app"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('streampanel', 'StreamPanel', 'StreamPanel simplifies app deployment and management, streamlining your workflow and boosting productivity.', 'cloud-computing', ARRAY['Cloud Computing', 'App Deployment'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "StreamPanel", "version": "latest", "description": "StreamPanel simplifies app deployment and management, streamlining your workflow and boosting productivity.", "category": "cloud-computing", "tags": ["Cloud Computing", "App Deployment"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/wish-oss/stream-panel"}], "instructions": "Make sure to update the EasyPanel, Google and Github environment variables.", "install": [{"docker": {"image": "$IMAGE", "name": "streampanel", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Make sure to update the EasyPanel, Google and Github environment variables."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('stremio', 'Stremio', 'Stremio is a modern media center application that provides a unified platform for streaming movies, TV shows, and live TV content. This template uses the community Docker image tsaridas/stremio-docker (server and web UI). The self-hosted setup lets you run your own Stremio server, giving you complete control over your media streaming experience. With support for various content sources and add-ons, Stremio aggregates content from multiple providers into a single interface. The application features automatic server URL configuration and CORS handling, making it easy to access from any device. With persistent storage for server data and configurations, Stremio ensures your settings and preferences are retained across container restarts. Perfect for media enthusiasts who want a centralized streaming solution, users looking for a self-hosted alternative to commercial streaming services, or anyone seeking a flexible media center that can aggregate content from multiple sources.', 'media', ARRAY['Media', 'Streaming', 'Movies', 'TV Shows', 'Self-Hosted', 'Media Center'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "tsaridas/stremio-docker:v1.2.16"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Stremio", "version": "latest", "description": "Stremio is a modern media center application that provides a unified platform for streaming movies, TV shows, and live TV content. This template uses the community Docker image tsaridas/stremio-docker (server and web UI). The self-hosted setup lets you run your own Stremio server, giving you complete control over your media streaming experience. With support for various content sources and add-ons, Stremio aggregates content from multiple providers into a single interface. The application features automatic server URL configuration and CORS handling, making it easy to access from any device. With persistent storage for server data and configurations, Stremio ensures your settings and preferences are retained across container restarts. Perfect for media enthusiasts who want a centralized streaming solution, users looking for a self-hosted alternative to commercial streaming services, or anyone seeking a flexible media center that can aggregate content from multiple sources.", "category": "media", "tags": ["Media", "Streaming", "Movies", "TV Shows", "Self-Hosted", "Media Center"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "tsaridas/stremio-docker:v1.2.16"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/tsaridas/stremio-docker"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/tsaridas/stremio-docker"}, {"label": "Website", "url": "https://www.stremio.com"}, {"label": "Blog", "url": "https://blog.stremio.com"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "stremio", "port": "$PORT:8080", "volumes": ["/root/.stremio-server"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('stump', 'Stump', 'Stump is a fast, free and open source audiobook and e-book server. It provides a web interface for accessing and managing your digital book collection, supporting various formats including audiobooks and e-books. Stump offers streaming capabilities, library management, and a modern responsive interface for reading and listening to your books from any device.', 'audiobook-server', ARRAY['Audiobook Server', 'E-book Reader', 'Digital Library', 'Self-Hosted', 'Web Interface', 'Books'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "aaronleopold/stump:0.1.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 10801}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Stump", "version": "latest", "description": "Stump is a fast, free and open source audiobook and e-book server. It provides a web interface for accessing and managing your digital book collection, supporting various formats including audiobooks and e-books. Stump offers streaming capabilities, library management, and a modern responsive interface for reading and listening to your books from any device.", "category": "audiobook-server", "tags": ["Audiobook Server", "E-book Reader", "Digital Library", "Self-Hosted", "Web Interface", "Books"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "aaronleopold/stump:0.1.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 10801}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.stumpapp.dev"}, {"label": "Documentation", "url": "https://www.stumpapp.dev/installation/docker"}, {"label": "Github", "url": "https://github.com/aaronleopold/stump"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "stump", "port": "$PORT:10801", "volumes": ["/config", "/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('substreamer', 'Substreamer', 'Substreamer is a free client app designed to provide you with a seamless and personalized music experience. It works in conjunction with the Subsonic music server, allowing you to organize and access your music library in a way that suits you best. Substreamer is compatible with Subsonic forks such as Airsonic, Madsonic, and others that implement the Subsonic API v1.13 or higher, including Navidrome and Ampache. This app is packed with features that enhance your music listening experience. With Substreamer, your music is always at your fingertips, just the way you like it.', 'music', ARRAY['Music', 'Streaming', 'Server'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghenry22/substreamer:6.0.43"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8081}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Substreamer", "version": "latest", "description": "Substreamer is a free client app designed to provide you with a seamless and personalized music experience. It works in conjunction with the Subsonic music server, allowing you to organize and access your music library in a way that suits you best. Substreamer is compatible with Subsonic forks such as Airsonic, Madsonic, and others that implement the Subsonic API v1.13 or higher, including Navidrome and Ampache. This app is packed with features that enhance your music listening experience. With Substreamer, your music is always at your fingertips, just the way you like it.", "category": "music", "tags": ["Music", "Streaming", "Server"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghenry22/substreamer:6.0.43"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8081}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Community", "url": "https://reddit.com/substreamer"}, {"label": "Website", "url": "https://substreamerapp.com"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "substreamer", "port": "$PORT:8081", "volumes": ["/usr/share/nginx/html"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('suitecrm', 'SuiteCRM', 'SuiteCRM is the world''s leading Open Source CRM, designed to help you sell, market, and service smarter. This feature-rich, enterprise-ready alternative to Salesforce offers all the benefits of CRM at a significantly lower cost, with the freedom and flexibility of Open Source. With SuiteCRM, you can gain a 360-degree view of your customers by creating a central repository for all your customer data, enabling you to gain key insights to enhance and nurture your business relationships. The platform is highly customizable and easy to use, with hundreds of extensions and integrations. SuiteCRM 8, our most advanced upgrade to date, promises to give you better control of your data and business solutions. The platform also allows for seamless integration with core business systems using our open REST API, enhancing productivity across your organization. With SuiteCRM, you can automate key actions, improve efficiency, understand your customers'' needs, convert more leads, and engage your customers more effectively with personalized experiences and consistent messaging. It also empowers your customer service team to service smarter, faster, and more professionally.', 'crm', ARRAY['CRM'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "bitnamilegacy/suitecrm:8.8.1-debian-12-r3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "SuiteCRM", "version": "latest", "description": "SuiteCRM is the world's leading Open Source CRM, designed to help you sell, market, and service smarter. This feature-rich, enterprise-ready alternative to Salesforce offers all the benefits of CRM at a significantly lower cost, with the freedom and flexibility of Open Source. With SuiteCRM, you can gain a 360-degree view of your customers by creating a central repository for all your customer data, enabling you to gain key insights to enhance and nurture your business relationships. The platform is highly customizable and easy to use, with hundreds of extensions and integrations. SuiteCRM 8, our most advanced upgrade to date, promises to give you better control of your data and business solutions. The platform also allows for seamless integration with core business systems using our open REST API, enhancing productivity across your organization. With SuiteCRM, you can automate key actions, improve efficiency, understand your customers' needs, convert more leads, and engage your customers more effectively with personalized experiences and consistent messaging. It also empowers your customer service team to service smarter, faster, and more professionally.", "category": "crm", "tags": ["CRM"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "bitnamilegacy/suitecrm:8.8.1-debian-12-r3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://suitecrm.com/"}, {"label": "Documentation", "url": "https://docs.suitecrm.com/"}, {"label": "Github", "url": "https://github.com/salesagility/SuiteCRM"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "suitecrm", "port": "$PORT:8080", "volumes": ["/bitnami/suitecrm"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('supabase', 'Supabase', 'Supabase is an open source Firebase alternative. Supabase is built on top of Postgres, and it''s easy to set up and use. Supabase is also completely free to use, and it''s completely open source.', 'self-hosted', ARRAY[]::text[], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Supabase", "version": "latest", "description": "Supabase is an open source Firebase alternative. Supabase is built on top of Postgres, and it's easy to set up and use. Supabase is also completely free to use, and it's completely open source.", "category": "self-hosted", "tags": [], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://supabase.com/"}, {"label": "Documentation", "url": "https://supabase.com/docs"}, {"label": "Github", "url": "https://github.com/supabase/supabase"}], "instructions": "Username is `supabase` and password is `this_password_is_insecure_and_should_be_updated`. You can change these by editing the environment variables.", "install": [{"docker": {"image": "$IMAGE", "name": "supabase", "port": "$PORT:8000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Username is `supabase` and password is `this_password_is_insecure_and_should_be_updated`. You can change these by editing the environment variables."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('supertokens-core', 'Supertokens Core', 'SuperTokens is an advanced user authentication solution designed to streamline your app''s security. It offers a range of features including user roles, two-factor authentication (2FA), Single Sign-On (SSO) with platforms like AD and Okta, session management, user management, account linking, and machine authentication. The app is trusted by startups and enterprises alike for its ease of setup and use. With SuperTokens, you can host your login page on your own domain, eliminating the need for redirects. It also provides prebuilt UIs and frontend SDKs to help you build your own login page quickly. SuperTokens is also capable of handling multitenant SSO, allowing each customer to have their own user pool. Loved by the world''s best teams, SuperTokens is your go-to solution for user authentication and session management.', 'developer-tools', ARRAY['Developer Tools', 'Security'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "supertokens/supertokens-postgresql:11.4.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3567}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Supertokens Core", "version": "latest", "description": "SuperTokens is an advanced user authentication solution designed to streamline your app's security. It offers a range of features including user roles, two-factor authentication (2FA), Single Sign-On (SSO) with platforms like AD and Okta, session management, user management, account linking, and machine authentication. The app is trusted by startups and enterprises alike for its ease of setup and use. With SuperTokens, you can host your login page on your own domain, eliminating the need for redirects. It also provides prebuilt UIs and frontend SDKs to help you build your own login page quickly. SuperTokens is also capable of handling multitenant SSO, allowing each customer to have their own user pool. Loved by the world's best teams, SuperTokens is your go-to solution for user authentication and session management.", "category": "developer-tools", "tags": ["Developer Tools", "Security"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "supertokens/supertokens-postgresql:11.4.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3567}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://supertokens.com/"}, {"label": "Documentation", "url": "https://supertokens.com/docs"}, {"label": "Github", "url": "https://github.com/supertokens"}], "instructions": "Check environment tab for your API key", "install": [{"docker": {"image": "$IMAGE", "name": "supertokens-core", "port": "$PORT:3567", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Check environment tab for your API key"}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('sure', 'Sure', 'Sure is a self-hosted personal finance management application built with Ruby on Rails. It helps individuals and families track expenses, manage budgets, monitor income, and gain insights into their financial health. Sure features an intuitive interface for recording transactions, categorizing expenses, creating budgets, and generating financial reports. With real-time data processing via Sidekiq background jobs and optional AI-powered features through OpenAI integration, Sure provides intelligent financial insights, spending pattern analysis, and automated categorization. Built for privacy-conscious users, Sure keeps all your financial data on your own infrastructure without sharing sensitive information with third-party services. Perfect for anyone seeking complete control over their personal finance tracking and analysis.', 'finance', ARRAY['Finance', 'Personal Finance', 'Budget', 'Expense Tracker', 'Money Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/we-promise/sure:0.7.1-alpha.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Sure", "version": "latest", "description": "Sure is a self-hosted personal finance management application built with Ruby on Rails. It helps individuals and families track expenses, manage budgets, monitor income, and gain insights into their financial health. Sure features an intuitive interface for recording transactions, categorizing expenses, creating budgets, and generating financial reports. With real-time data processing via Sidekiq background jobs and optional AI-powered features through OpenAI integration, Sure provides intelligent financial insights, spending pattern analysis, and automated categorization. Built for privacy-conscious users, Sure keeps all your financial data on your own infrastructure without sharing sensitive information with third-party services. Perfect for anyone seeking complete control over their personal finance tracking and analysis.", "category": "finance", "tags": ["Finance", "Personal Finance", "Budget", "Expense Tracker", "Money Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/we-promise/sure:0.7.1-alpha.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/we-promise/sure"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "sure", "port": "$PORT:3000", "volumes": ["/rails/storage", "/rails/storage"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('surmai', 'Surmai', 'Surmai is a personal and family travel organizer—a Progressive Web App for collaborative trip planning with privacy-first, self-hosted data. Built on PocketBase, it helps you keep itineraries, bookings, documents, and trip details in one place, with multi-user collaboration and offline-friendly access. The stack exposes the web UI on port 8080 and persists PocketBase data under /pb_data.', 'travel', ARRAY['Travel', 'Trip Planning', 'Self-Hosted', 'PocketBase', 'PWA', 'Collaboration'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/rohitkumbhar/surmai:v0.5.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Surmai", "version": "latest", "description": "Surmai is a personal and family travel organizer\u2014a Progressive Web App for collaborative trip planning with privacy-first, self-hosted data. Built on PocketBase, it helps you keep itineraries, bookings, documents, and trip details in one place, with multi-user collaboration and offline-friendly access. The stack exposes the web UI on port 8080 and persists PocketBase data under /pb_data.", "category": "travel", "tags": ["Travel", "Trip Planning", "Self-Hosted", "PocketBase", "PWA", "Collaboration"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/rohitkumbhar/surmai:v0.5.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://surmai.app/"}, {"label": "Documentation", "url": "https://surmai.app/documentation/"}, {"label": "GitHub", "url": "https://github.com/rohitkumbhar/surmai"}], "instructions": "After deploy, sign in with the admin email you configured and the password\nshown in the service environment (SURMAI_ADMIN_PASSWORD)\u2014it is auto-generated\nfor a strong default. Change it after first login if you like. See\nhttps://surmai.app/documentation/installation for Docker details.\n", "install": [{"docker": {"image": "$IMAGE", "name": "surmai", "port": "$PORT:8080", "volumes": ["/pb_data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deploy, sign in with the admin email you configured and the password\nshown in the service environment (SURMAI_ADMIN_PASSWORD)\u2014it is auto-generated\nfor a strong default. Change it after first login if you like. See\nhttps://surmai.app/documentation/installation for Docker details.\n"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('suwayomi-server', 'Suwayomi Server', 'Suwayomi Server is a free and open source manga reader server that runs on the desktop and mobile. It provides a web interface for reading manga from various sources and supports multiple extensions. Suwayomi Server allows you to organize your manga library, track reading progress, and access your collection from any device through a modern web interface.', 'manga-reader', ARRAY['Manga Reader', 'Digital Library', 'Reading', 'Self-Hosted', 'Web Interface', 'Comics'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/suwayomi/suwayomi-server:v2.1.2099"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4567}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Suwayomi Server", "version": "latest", "description": "Suwayomi Server is a free and open source manga reader server that runs on the desktop and mobile. It provides a web interface for reading manga from various sources and supports multiple extensions. Suwayomi Server allows you to organize your manga library, track reading progress, and access your collection from any device through a modern web interface.", "category": "manga-reader", "tags": ["Manga Reader", "Digital Library", "Reading", "Self-Hosted", "Web Interface", "Comics"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/suwayomi/suwayomi-server:v2.1.2099"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4567}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://suwayomi.org/"}, {"label": "Github", "url": "https://github.com/Suwayomi/Suwayomi-Server"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "suwayomi-server", "port": "$PORT:4567", "volumes": ["/home/suwayomi/.local/share/Tachidesk/downloads", "/home/suwayomi/.local/share/Tachidesk"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('swetrix', 'Swetrix', 'Swetrix is a powerful, privacy-focused analytics platform that provides comprehensive website and application analytics. Built with modern technologies, it offers real-time data collection, beautiful dashboards, and detailed insights into user behavior. Features include event tracking, performance monitoring, user session analysis, and customizable reports. Self-hosted solution that ensures complete data privacy and control while providing enterprise-grade analytics capabilities.', 'analytics', ARRAY['Analytics', 'Privacy', 'Self-Hosted', 'Real-time', 'Dashboard'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Swetrix", "version": "latest", "description": "Swetrix is a powerful, privacy-focused analytics platform that provides comprehensive website and application analytics. Built with modern technologies, it offers real-time data collection, beautiful dashboards, and detailed insights into user behavior. Features include event tracking, performance monitoring, user session analysis, and customizable reports. Self-hosted solution that ensures complete data privacy and control while providing enterprise-grade analytics capabilities.", "category": "analytics", "tags": ["Analytics", "Privacy", "Self-Hosted", "Real-time", "Dashboard"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/Swetrix/swetrix"}, {"label": "Website", "url": "https://swetrix.com"}, {"label": "Documentation", "url": "https://docs.swetrix.com"}], "instructions": "After deployment, open the Swetrix frontend URL and click Sign Up to create your account. Once registered, log in with your credentials to access the dashboard.", "install": [{"docker": {"image": "$IMAGE", "name": "swetrix", "port": "$PORT:3000", "volumes": ["/var/lib/clickhouse", "/etc/clickhouse-server/config.d"], "extra_ports": ["5005:5005"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deployment, open the Swetrix frontend URL and click Sign Up to create your account. Once registered, log in with your credentials to access the dashboard."}, "services": {"redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('swingmusic', 'Swingmusic', 'Swingmusic is a beautiful, self-hosted music player and streaming server for your personal music collection. It provides a modern, intuitive web interface that allows you to stream your music library from anywhere. With support for various audio formats and a clean, responsive design, Swingmusic makes it easy to enjoy your music collection across all your devices. The application offers features like playlist management, search functionality, and album artwork display, making it a perfect alternative to commercial streaming services for those who want to keep their music library private and under their control.', 'music', ARRAY['Music', 'Media Server', 'Self-Hosted', 'Streaming', 'Music Player', 'Audio', 'Entertainment', 'Personal Media'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/swingmx/swingmusic:v2.1.10"}, "port": {"type": "integer", "title": "Port HTTP", "default": 1970}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Swingmusic", "version": "latest", "description": "Swingmusic is a beautiful, self-hosted music player and streaming server for your personal music collection. It provides a modern, intuitive web interface that allows you to stream your music library from anywhere. With support for various audio formats and a clean, responsive design, Swingmusic makes it easy to enjoy your music collection across all your devices. The application offers features like playlist management, search functionality, and album artwork display, making it a perfect alternative to commercial streaming services for those who want to keep their music library private and under their control.", "category": "music", "tags": ["Music", "Media Server", "Self-Hosted", "Streaming", "Music Player", "Audio", "Entertainment", "Personal Media"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/swingmx/swingmusic:v2.1.10"}, "port": {"type": "integer", "title": "Port HTTP", "default": 1970}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/swingmx/swingmusic"}, {"label": "Documentation", "url": "https://github.com/swingmx/swingmusic#readme"}, {"label": "Demo", "url": "https://swingmx.com"}], "instructions": "Default credentials are admin/admin", "install": [{"docker": {"image": "$IMAGE", "name": "swingmusic", "port": "$PORT:1970", "volumes": ["/music", "/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Default credentials are admin/admin"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('syncthing', 'Syncthing', 'Syncthing is a powerful, real-time file synchronization program designed to keep your data secure and under your control. It enables the synchronization of files between two or more computers, ensuring your data is always up-to-date across your devices. Syncthing prioritizes your privacy and security, with no data ever stored on a central server that could be compromised. All communication is encrypted and authenticated, with only devices you have explicitly allowed able to connect to your other devices. The app is easy to use, with a responsive and powerful interface accessible via your browser. It works across various operating systems including Mac OS X, Windows, Linux, FreeBSD, Solaris, OpenBSD, and many others. Syncthing doesn''t require complex configuration or IP addresses, it simply works, over LAN and over the Internet. You can synchronize as many folders as you need with different people or just between your own devices.', 'file-management', ARRAY['File Management', 'Security', 'Privacy'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "syncthing/syncthing:1.30"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8384}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Syncthing", "version": "latest", "description": "Syncthing is a powerful, real-time file synchronization program designed to keep your data secure and under your control. It enables the synchronization of files between two or more computers, ensuring your data is always up-to-date across your devices. Syncthing prioritizes your privacy and security, with no data ever stored on a central server that could be compromised. All communication is encrypted and authenticated, with only devices you have explicitly allowed able to connect to your other devices. The app is easy to use, with a responsive and powerful interface accessible via your browser. It works across various operating systems including Mac OS X, Windows, Linux, FreeBSD, Solaris, OpenBSD, and many others. Syncthing doesn't require complex configuration or IP addresses, it simply works, over LAN and over the Internet. You can synchronize as many folders as you need with different people or just between your own devices.", "category": "file-management", "tags": ["File Management", "Security", "Privacy"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "syncthing/syncthing:1.30"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8384}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://syncthing.net"}, {"label": "Docs", "url": "https://docs.syncthing.net"}, {"label": "GitHub", "url": "https://github.com/syncthing/syncthing"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "syncthing", "port": "$PORT:8384", "volumes": ["/var/syncthing"], "extra_ports": ["21027:21027", "22000:22000"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('tandoor', 'Tandoor', 'Tandoor is an online recipe management app designed to help you manage and grow your recipe collection. It allows you to drop your collection of links and notes, and provides a platform for recipe management, storage, sharing, and collaborative cooking. Tandoor is equipped with a powerful fuzzy search engine that helps you find your recipes faster. You can search for keywords, ingredients and more. The app also allows you to import your favorite recipes from thousands of websites online, and if you already have a digital recipe collection, you can import your data from many other managers. Tandoor also provides the functionality to create shopping lists for your recipes, making meal planning and shopping a breeze. It''s the perfect tool for cooking enthusiasts looking to digitize and share their cookbooks and recipes.', 'recipe-management', ARRAY['Recipe Management', 'Cooking', 'Meal Planning'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "vabene1111/recipes:1.5.35"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Tandoor", "version": "latest", "description": "Tandoor is an online recipe management app designed to help you manage and grow your recipe collection. It allows you to drop your collection of links and notes, and provides a platform for recipe management, storage, sharing, and collaborative cooking. Tandoor is equipped with a powerful fuzzy search engine that helps you find your recipes faster. You can search for keywords, ingredients and more. The app also allows you to import your favorite recipes from thousands of websites online, and if you already have a digital recipe collection, you can import your data from many other managers. Tandoor also provides the functionality to create shopping lists for your recipes, making meal planning and shopping a breeze. It's the perfect tool for cooking enthusiasts looking to digitize and share their cookbooks and recipes.", "category": "recipe-management", "tags": ["Recipe Management", "Cooking", "Meal Planning"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "vabene1111/recipes:1.5.35"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://tandoor.dev"}, {"label": "Documentation", "url": "https://docs.tandoor.dev"}, {"label": "Github", "url": "https://github.com/TandoorRecipes/recipes"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "tandoor", "port": "$PORT:8080", "volumes": ["/opt/recipes/mediafiles", "/opt/recipes/staticfiles"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('taskcafe', 'TaskCafe', 'TaskCafe is a modern, open-source project management tool that helps teams organize and track their work. It provides an intuitive interface for managing projects, tasks, and collaborations with features similar to Trello and other project management tools.', 'project-management', ARRAY['Project Management', 'Task Tracking', 'Collaboration', 'Team', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "taskcafe/taskcafe:0.3.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3333}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "TaskCafe", "version": "latest", "description": "TaskCafe is a modern, open-source project management tool that helps teams organize and track their work. It provides an intuitive interface for managing projects, tasks, and collaborations with features similar to Trello and other project management tools.", "category": "project-management", "tags": ["Project Management", "Task Tracking", "Collaboration", "Team", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "taskcafe/taskcafe:0.3.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3333}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/JordanKnott/taskcafe"}, {"label": "Documentation", "url": "https://github.com/JordanKnott/taskcafe/wiki"}], "instructions": "After installation, access the web interface through the provided domain to start managing your projects and tasks.", "install": [{"docker": {"image": "$IMAGE", "name": "taskcafe", "port": "$PORT:3333", "volumes": ["/root/uploads"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After installation, access the web interface through the provided domain to start managing your projects and tasks."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('tautulli', 'Tautuilli', 'Tautulli is a powerful web application designed to monitor, analyze, and notify you about your Plex Media Server''s activities. It runs alongside your Plex Media Server, tracking a variety of statistics including what has been watched, who watched it, when and where it was watched, and how it was watched. The app presents all these statistics in a clean, user-friendly interface with tables and graphs. Tautulli also allows you to monitor current activity on your Plex Media Server, log watch history for all your users, view streaming trends with intuitive graphs, trigger notifications or scripts from events on your Plex server, and keep track of when content is added to your Plex library. You can also create and send newsletters for recently added media, view and delete all synced content from your server, see detailed information on all of your media, and even download the official app to view activity and stats on the go. Tautulli is compatible with any system that supports python.', 'monitoring', ARRAY['Monitoring', 'Media'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/tautulli:2.17.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8181}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Tautuilli", "version": "latest", "description": "Tautulli is a powerful web application designed to monitor, analyze, and notify you about your Plex Media Server's activities. It runs alongside your Plex Media Server, tracking a variety of statistics including what has been watched, who watched it, when and where it was watched, and how it was watched. The app presents all these statistics in a clean, user-friendly interface with tables and graphs. Tautulli also allows you to monitor current activity on your Plex Media Server, log watch history for all your users, view streaming trends with intuitive graphs, trigger notifications or scripts from events on your Plex server, and keep track of when content is added to your Plex library. You can also create and send newsletters for recently added media, view and delete all synced content from your server, see detailed information on all of your media, and even download the official app to view activity and stats on the go. Tautulli is compatible with any system that supports python.", "category": "monitoring", "tags": ["Monitoring", "Media"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/tautulli:2.17.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8181}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://tautulli.com/"}, {"label": "Github", "url": "https://github.com/Tautulli/Tautulli"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "tautulli", "port": "$PORT:8181", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('teable', 'Teable', 'Teable is a powerful, self-hosted service designed for managing team collaboration and projects efficiently. It offers a clean and user-friendly interface, supports plugins for extended functionality, and provides detailed analytics on team activities. With Teable, you can maintain full control over your data and workflows.', 'project-management', ARRAY['Project Management', 'Self-Hosted', 'Team Collaboration', 'Analytics'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/teableio/teable:bfd290f274cf8b0cc1defe9e1e6fd2b6826fed6b"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Teable", "version": "latest", "description": "Teable is a powerful, self-hosted service designed for managing team collaboration and projects efficiently. It offers a clean and user-friendly interface, supports plugins for extended functionality, and provides detailed analytics on team activities. With Teable, you can maintain full control over your data and workflows.", "category": "project-management", "tags": ["Project Management", "Self-Hosted", "Team Collaboration", "Analytics"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/teableio/teable:bfd290f274cf8b0cc1defe9e1e6fd2b6826fed6b"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://teable.io/docs"}, {"label": "Github", "url": "https://github.com/teableio/teable"}], "instructions": "Wait for the migration to complete, then start using Teable for managing your projects.", "install": [{"docker": {"image": "$IMAGE", "name": "teable", "port": "$PORT:3000", "volumes": ["/app/.assets"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Wait for the migration to complete, then start using Teable for managing your projects."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('teamcity', 'TeamCity', 'TeamCity is a build management and continuous integration server from JetBrains.', 'ci/cd', ARRAY['CI/CD', 'Build Server', 'Continuous Integration', 'Deployment', 'Automation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "jetbrains/teamcity-server:2025.11.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8111}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "TeamCity", "version": "latest", "description": "TeamCity is a build management and continuous integration server from JetBrains.", "category": "ci/cd", "tags": ["CI/CD", "Build Server", "Continuous Integration", "Deployment", "Automation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "jetbrains/teamcity-server:2025.11.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8111}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/JetBrains/teamcity-docker-images"}, {"label": "Documentation", "url": "https://www.jetbrains.com/help/teamcity/teamcity-docker.html"}], "instructions": "After setup, connect your Git repository and create a Build Configuration. If you enabled the bundled agent, it will auto-register to the server; approve it in **Agents** before running your first build.", "install": [{"docker": {"image": "$IMAGE", "name": "teamcity", "port": "$PORT:8111", "volumes": ["/data/teamcity_server/datadir", "/opt/teamcity/logs", "/data/teamcity_agent/conf", "/opt/buildagent/work", "/opt/buildagent/temp", "/opt/buildagent/tools", "/opt/buildagent/plugins", "/opt/buildagent/system"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After setup, connect your Git repository and create a Build Configuration. If you enabled the bundled agent, it will auto-register to the server; approve it in **Agents** before running your first build."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('teammapper', 'TeamMapper', 'TeamMapper is a powerful team mapping and visualization tool designed to help organizations understand team structures, relationships, and collaboration patterns. It provides an intuitive interface for creating interactive team maps that visualize team members, their roles, departments, and connections. TeamMapper enables teams to better understand their organizational structure, identify collaboration opportunities, and optimize team dynamics. The platform supports real-time updates, customizable visualizations, and comprehensive team analytics to help organizations make data-driven decisions about team composition and workflow optimization.', 'team-management', ARRAY['Team Management', 'Visualization', 'Organization', 'Collaboration', 'Analytics', 'Web App', 'Self-hosted', 'PostgreSQL'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/b310-digital/teammapper:v0.2.6-1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "TeamMapper", "version": "latest", "description": "TeamMapper is a powerful team mapping and visualization tool designed to help organizations understand team structures, relationships, and collaboration patterns. It provides an intuitive interface for creating interactive team maps that visualize team members, their roles, departments, and connections. TeamMapper enables teams to better understand their organizational structure, identify collaboration opportunities, and optimize team dynamics. The platform supports real-time updates, customizable visualizations, and comprehensive team analytics to help organizations make data-driven decisions about team composition and workflow optimization.", "category": "team-management", "tags": ["Team Management", "Visualization", "Organization", "Collaboration", "Analytics", "Web App", "Self-hosted", "PostgreSQL"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/b310-digital/teammapper:v0.2.6-1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://teammapper.io"}, {"label": "GitHub", "url": "https://github.com/b310-digital/teammapper"}, {"label": "Container registry", "url": "https://github.com/b310-digital/teammapper/pkgs/container/teammapper"}], "instructions": "Deploy the stack and open your assigned domain to complete TeamMapper setup. The application connects automatically to the internal PostgreSQL service created by this template. On first startup, create your initial account in the web interface and then configure your organization and team structure. Data is persisted in /app/data and in PostgreSQL volumes, so updates and restarts keep existing content. DELETE_AFTER_DAYS is set to 30 by default in this template. Change it after deploy if your retention requirements differ.", "install": [{"docker": {"image": "$IMAGE", "name": "teammapper", "port": "$PORT:3000", "volumes": ["/app/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Deploy the stack and open your assigned domain to complete TeamMapper setup. The application connects automatically to the internal PostgreSQL service created by this template. On first startup, create your initial account in the web interface and then configure your organization and team structure. Data is persisted in /app/data and in PostgreSQL volumes, so updates and restarts keep existing content. DELETE_AFTER_DAYS is set to 30 by default in this template. Change it after deploy if your retention requirements differ."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('teamspeak', 'Teamspeak', 'TeamSpeak is a powerful and flexible VoIP (Voice over Internet Protocol) application designed for online gaming, business communication, and remote collaboration. It provides crystal-clear voice communication with minimal latency, making it ideal for teams that require real-time coordination. TeamSpeak offers a secure and scalable environment, allowing users to create and manage their own servers with customizable permissions and roles. The application supports a wide range of integrations and plugins, providing extended functionality. TeamSpeak is widely used in gaming communities, corporate environments, and educational institutions for efficient communication.', 'voip', ARRAY['VoIP', 'Communication', 'Gaming', 'Business', 'Secure'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "teamspeak:3.13.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9987}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Teamspeak", "version": "latest", "description": "TeamSpeak is a powerful and flexible VoIP (Voice over Internet Protocol) application designed for online gaming, business communication, and remote collaboration. It provides crystal-clear voice communication with minimal latency, making it ideal for teams that require real-time coordination. TeamSpeak offers a secure and scalable environment, allowing users to create and manage their own servers with customizable permissions and roles. The application supports a wide range of integrations and plugins, providing extended functionality. TeamSpeak is widely used in gaming communities, corporate environments, and educational institutions for efficient communication.", "category": "voip", "tags": ["VoIP", "Communication", "Gaming", "Business", "Secure"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "teamspeak:3.13.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9987}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.teamspeak.com/"}, {"label": "Github", "url": "https://github.com/TeamSpeak-Systems"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "teamspeak", "port": "$PORT:9987", "volumes": [], "extra_ports": ["10011:10011", "30033:30033"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('temporal', 'Temporal', 'Temporal is an open-source, self-hosted workflow orchestration engine designed to simplify and enhance the development of scalable, fault-tolerant, and long-running workflows. It empowers developers to build reliable distributed systems by providing built-in state management, automatic retries, and advanced task scheduling. Temporal offers a user-friendly developer experience, powerful SDKs, and seamless integration with various languages, making it ideal for automating complex business processes and microservice orchestration. By providing a self-hosted solution, Temporal ensures data privacy, high availability, and complete control over your workflows and infrastructure.', 'workflow-orchestration', ARRAY['Workflow Orchestration', 'Self-Hosted', 'Fault-Tolerant', 'Distributed Systems', 'Observability'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "temporalio/auto-setup:1.29.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Temporal", "version": "latest", "description": "Temporal is an open-source, self-hosted workflow orchestration engine designed to simplify and enhance the development of scalable, fault-tolerant, and long-running workflows. It empowers developers to build reliable distributed systems by providing built-in state management, automatic retries, and advanced task scheduling. Temporal offers a user-friendly developer experience, powerful SDKs, and seamless integration with various languages, making it ideal for automating complex business processes and microservice orchestration. By providing a self-hosted solution, Temporal ensures data privacy, high availability, and complete control over your workflows and infrastructure.", "category": "workflow-orchestration", "tags": ["Workflow Orchestration", "Self-Hosted", "Fault-Tolerant", "Distributed Systems", "Observability"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "temporalio/auto-setup:1.29.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://docs.temporal.io/"}, {"label": "Github", "url": "https://github.com/temporalio/temporal"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "temporal", "port": "$PORT:8080", "volumes": ["/etc/temporal/config/dynamicconfig/development-sql.yaml", "/etc/temporal/config/dynamicconfig/development-cass.yaml", "/var/lib/elasticsearch/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('termix', 'Termix', 'Termix is a lightweight, web-based terminal emulator and SSH client that allows you to access and manage remote servers directly from your browser. It provides a modern, intuitive interface for executing commands, managing files, and administering systems without needing a traditional terminal application. Termix features session persistence, multiple connection management, customizable themes, and secure SSH connections. The web interface is responsive and works seamlessly across desktop and mobile devices, making it perfect for system administrators who need remote access on the go. All connection data is stored locally, ensuring your credentials and sessions remain private and secure.', 'terminal', ARRAY['Terminal', 'SSH', 'Remote Access', 'Web Terminal', 'System Admin'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/lukegus/termix:release-1.11.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Termix", "version": "latest", "description": "Termix is a lightweight, web-based terminal emulator and SSH client that allows you to access and manage remote servers directly from your browser. It provides a modern, intuitive interface for executing commands, managing files, and administering systems without needing a traditional terminal application. Termix features session persistence, multiple connection management, customizable themes, and secure SSH connections. The web interface is responsive and works seamlessly across desktop and mobile devices, making it perfect for system administrators who need remote access on the go. All connection data is stored locally, ensuring your credentials and sessions remain private and secure.", "category": "terminal", "tags": ["Terminal", "SSH", "Remote Access", "Web Terminal", "System Admin"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/lukegus/termix:release-1.11.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/lukegus/termix"}, {"label": "Documentation", "url": "https://docs.termix.site"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "termix", "port": "$PORT:8080", "volumes": ["/app/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('thelounge', 'The Lounge', 'Welcome to The Lounge, your self-hosted web IRC client for the 21st century. With modern features such as push notifications, link previews, and file uploads, The Lounge brings IRC into the modern era. Stay connected to IRC servers even when you''re offline and resume where you left off on any device, thanks to its responsive interface that works smoothly on every desktop, smartphone, and tablet. The Lounge supports multiple user accounts, allowing you to share your server with friends. It''s a free and open-source app, licensed under the MIT license, and works on any OS where Node.js runs. The Lounge offers two modes: private and public. In private mode, it acts like a bouncer and a client combined, offering an experience similar to other modern chat applications. In public mode, it acts as an open chat available to anyone without registration. Enjoy the convenience of a modern, responsive, cross-platform, self-hosted web IRC client with The Lounge.', 'chat', ARRAY['Chat'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/thelounge/thelounge:4.4.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "The Lounge", "version": "latest", "description": "Welcome to The Lounge, your self-hosted web IRC client for the 21st century. With modern features such as push notifications, link previews, and file uploads, The Lounge brings IRC into the modern era. Stay connected to IRC servers even when you're offline and resume where you left off on any device, thanks to its responsive interface that works smoothly on every desktop, smartphone, and tablet. The Lounge supports multiple user accounts, allowing you to share your server with friends. It's a free and open-source app, licensed under the MIT license, and works on any OS where Node.js runs. The Lounge offers two modes: private and public. In private mode, it acts like a bouncer and a client combined, offering an experience similar to other modern chat applications. In public mode, it acts as an open chat available to anyone without registration. Enjoy the convenience of a modern, responsive, cross-platform, self-hosted web IRC client with The Lounge.", "category": "chat", "tags": ["Chat"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/thelounge/thelounge:4.4.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://thelounge.chat/"}, {"label": "Docs", "url": "https://thelounge.chat/docs"}, {"label": "GitHub", "url": "https://github.com/thelounge"}], "instructions": "To create a user, type thelounge add <name> in the console.", "install": [{"docker": {"image": "$IMAGE", "name": "thelounge", "port": "$PORT:9000", "volumes": ["/var/opt/thelounge"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "To create a user, type thelounge add <name> in the console."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('thingsboard', 'Thingsboard', 'ThingsBoard is an open-source IoT platform designed to simplify the process of collecting, processing, and visualizing data from IoT devices. It provides features like real-time device management, telemetry data visualization, and rule engine workflows to automate tasks and actions.', 'iot', ARRAY['IoT', 'Device Management', 'Data Visualization', 'Automation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "thingsboard/tb-postgres:4.2.1.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9090}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Thingsboard", "version": "latest", "description": "ThingsBoard is an open-source IoT platform designed to simplify the process of collecting, processing, and visualizing data from IoT devices. It provides features like real-time device management, telemetry data visualization, and rule engine workflows to automate tasks and actions.", "category": "iot", "tags": ["IoT", "Device Management", "Data Visualization", "Automation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "thingsboard/tb-postgres:4.2.1.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9090}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://thingsboard.io/docs/"}, {"label": "Docker Guide", "url": "https://thingsboard.io/docs/user-guide/install/docker/"}, {"label": "Github", "url": "https://github.com/thingsboard/thingsboard"}], "instructions": "Copy the email and passwords. sysadmin@thingsboard.org / sysadmin, tenant@thingsboard.org / tenant, customer@thingsboard.org / customer. Expose the ports mentioned inside the documentation based on your requirements.", "install": [{"docker": {"image": "$IMAGE", "name": "thingsboard", "port": "$PORT:9090", "volumes": ["/var/log/thingsboard", "/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Copy the email and passwords. sysadmin@thingsboard.org / sysadmin, tenant@thingsboard.org / tenant, customer@thingsboard.org / customer. Expose the ports mentioned inside the documentation based on your requirements."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('thumbor', 'Thumbor', 'Thumbor is an intelligent imaging service designed to streamline and enhance your image processing tasks. It offers on-demand cropping, resizing, and flipping of images, ensuring the most important parts of your pictures are always preserved. Leveraging advanced face and feature detection algorithms, Thumbor smartly identifies key points in an image for optimal cropping and resizing. It also supports a variety of image filters for post-processing, which can be applied in a sequence for desired effects. Filters include brightness, contrast, grayscale, red-eye, and blur, among others. Thumbor also supports the WebP format, a superior image format that compresses better than jpeg and png, improving your website''s performance. With Thumbor, you can store and load images from any location, and it''s easy to implement a new loader or storage. It''s a complete solution for your imaging needs, from uploading images to rendering them with smart face-recognition cropping.', 'image-processing', ARRAY['Image Processing', 'Open Source', 'Smart Imaging'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "thumbororg/thumbor:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8888}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Thumbor", "version": "latest", "description": "Thumbor is an intelligent imaging service designed to streamline and enhance your image processing tasks. It offers on-demand cropping, resizing, and flipping of images, ensuring the most important parts of your pictures are always preserved. Leveraging advanced face and feature detection algorithms, Thumbor smartly identifies key points in an image for optimal cropping and resizing. It also supports a variety of image filters for post-processing, which can be applied in a sequence for desired effects. Filters include brightness, contrast, grayscale, red-eye, and blur, among others. Thumbor also supports the WebP format, a superior image format that compresses better than jpeg and png, improving your website's performance. With Thumbor, you can store and load images from any location, and it's easy to implement a new loader or storage. It's a complete solution for your imaging needs, from uploading images to rendering them with smart face-recognition cropping.", "category": "image-processing", "tags": ["Image Processing", "Open Source", "Smart Imaging"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "thumbororg/thumbor:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8888}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.thumbor.org"}, {"label": "Documentation", "url": "https://thumbor.readthedocs.io"}, {"label": "Github", "url": "https://github.com/thumbor/thumbor"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "thumbor", "port": "$PORT:8888", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('tianji', 'Tianji', 'All-in-One Insight Hub. Insight into everything, Website Analytics + Uptime Monitor + Server Status. not only another GA alternatives', 'website-monitor', ARRAY['Website Monitor', 'Analytics', 'Server Monitor'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "moonrailgun/tianji:1.31.24"}, "port": {"type": "integer", "title": "Port HTTP", "default": 12345}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Tianji", "version": "latest", "description": "All-in-One Insight Hub. Insight into everything, Website Analytics + Uptime Monitor + Server Status. not only another GA alternatives", "category": "website-monitor", "tags": ["Website Monitor", "Analytics", "Server Monitor"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "moonrailgun/tianji:1.31.24"}, "port": {"type": "integer", "title": "Port HTTP", "default": 12345}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://tianji.msgbyte.com/"}, {"label": "Documentation", "url": "https://tianji.msgbyte.com/docs/intro"}, {"label": "Github", "url": "https://github.com/msgbyte/tianji"}], "instructions": "Default login is \"admin\" / \"admin\".", "install": [{"docker": {"image": "$IMAGE", "name": "tianji", "port": "$PORT:12345", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Default login is \"admin\" / \"admin\"."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('tiddlywiki', 'Tiddlywiki', 'Tiddlywiki is a unique open-source, single-file wiki designed to help you organize, capture, and share information effectively. It is a versatile personal notebook that allows you to create, organize, and navigate your notes in a self-contained HTML file. Tiddlywiki is highly customizable, enabling users to tweak layouts, styles, and functionality through plugins and scripts. It works offline and can be hosted online for collaboration or personal use. Whether you''re creating a personal knowledge base, journaling, or managing projects, Tiddlywiki provides a flexible platform to meet your needs.', 'wiki', ARRAY['Wiki', 'Personal Knowledge Management', 'Note-Taking'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "nicolaw/tiddlywiki:5.3.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Tiddlywiki", "version": "latest", "description": "Tiddlywiki is a unique open-source, single-file wiki designed to help you organize, capture, and share information effectively. It is a versatile personal notebook that allows you to create, organize, and navigate your notes in a self-contained HTML file. Tiddlywiki is highly customizable, enabling users to tweak layouts, styles, and functionality through plugins and scripts. It works offline and can be hosted online for collaboration or personal use. Whether you're creating a personal knowledge base, journaling, or managing projects, Tiddlywiki provides a flexible platform to meet your needs.", "category": "wiki", "tags": ["Wiki", "Personal Knowledge Management", "Note-Taking"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "nicolaw/tiddlywiki:5.3.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://tiddlywiki.com"}, {"label": "Docs", "url": "https://tiddlywiki.com/#Documentation"}, {"label": "Github", "url": "https://github.com/Jermolene/TiddlyWiki5"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "tiddlywiki", "port": "$PORT:8080", "volumes": ["/var/lib/tiddlywiki"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('timescaledb', 'TimescaleDB', 'TimescaleDB is an open-source time-series database optimized for fast ingest and complex queries. It is built on top of PostgreSQL and provides automatic partitioning across time and space, making it ideal for IoT, monitoring, analytics, and other time-series data applications. It offers native time-series functionality while maintaining the reliability and flexibility of PostgreSQL.', 'database', ARRAY['Database', 'Time-Series', 'PostgreSQL', 'Analytics', 'IoT'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "timescale/timescaledb-ha:pg17"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5432}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "TimescaleDB", "version": "latest", "description": "TimescaleDB is an open-source time-series database optimized for fast ingest and complex queries. It is built on top of PostgreSQL and provides automatic partitioning across time and space, making it ideal for IoT, monitoring, analytics, and other time-series data applications. It offers native time-series functionality while maintaining the reliability and flexibility of PostgreSQL.", "category": "database", "tags": ["Database", "Time-Series", "PostgreSQL", "Analytics", "IoT"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "timescale/timescaledb-ha:pg17"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5432}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.timescale.com/"}, {"label": "Documentation", "url": "https://docs.timescale.com/"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/timescale/timescaledb-ha"}], "instructions": "After deployment, connect to TimescaleDB using your app domain on port 5432 with username `postgres`, password set in Database Password, and database `postgres`; for example, `psql \"postgresql://postgres:<YOUR_PASSWORD>@<YOUR_DOMAIN>:5432/postgres\"`; TimescaleDB is PostgreSQL-compatible, so any PostgreSQL client or ORM can use the same connection details.", "install": [{"docker": {"image": "$IMAGE", "name": "timescaledb", "port": "$PORT:5432", "volumes": ["/home/postgres/pgdata/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deployment, connect to TimescaleDB using your app domain on port 5432 with username `postgres`, password set in Database Password, and database `postgres`; for example, `psql \"postgresql://postgres:<YOUR_PASSWORD>@<YOUR_DOMAIN>:5432/postgres\"`; TimescaleDB is PostgreSQL-compatible, so any PostgreSQL client or ORM can use the same connection details."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('tinymediamanager', 'TinyMediaManager', 'TinyMediaManager is a media management tool designed to organize and manage your movie and TV show collections. It automatically fetches metadata from various sources, downloads artwork, and helps keep your media library well-organized with proper naming conventions and metadata files for media servers like Plex, Emby, and Jellyfin.', 'media-manager', ARRAY['Media Manager', 'Movies', 'TV Shows', 'Metadata', 'Plex', 'Emby', 'Jellyfin'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "tinymediamanager/tinymediamanager:5.2.11"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "TinyMediaManager", "version": "latest", "description": "TinyMediaManager is a media management tool designed to organize and manage your movie and TV show collections. It automatically fetches metadata from various sources, downloads artwork, and helps keep your media library well-organized with proper naming conventions and metadata files for media servers like Plex, Emby, and Jellyfin.", "category": "media-manager", "tags": ["Media Manager", "Movies", "TV Shows", "Metadata", "Plex", "Emby", "Jellyfin"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "tinymediamanager/tinymediamanager:5.2.11"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.tinymediamanager.org/"}, {"label": "Documentation", "url": "https://www.tinymediamanager.org/docs/"}, {"label": "GitHub", "url": "https://github.com/tinyMediaManager/tinyMediaManager"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/tinymediamanager/tinymediamanager"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "tinymediamanager", "port": "$PORT:4000", "volumes": ["/data", "/media/movies", "/media/tv_shows"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('tolgee', 'Tolgee', 'Tolgee is a revolutionary localization platform designed to simplify and speed up the translation process of your application. With Tolgee, you can translate your app into any language without modifying your code. It offers a range of features including in-context translating, translation memory, machine translations, auto translation, and activity log. The in-context translating feature allows you to translate strings directly in the app you develop, even in production. Translation memory ensures you don''t translate the same string twice by reusing strings you''ve already translated. Machine translations let you leverage the power of DeepL, Google Translate, and AWS translate. Auto translation delivers your translations instantly right after you add them. The activity log feature helps you monitor the translation activities. Tolgee also allows users to add screenshots with a single click, providing context for translations. It is designed to be developer-friendly with easy integration with all major JS frameworks. Tolgee is not only easy to use for developers but also for translators, making the localization process seamless and efficient.', 'developer-tools', ARRAY['Developer Tools', 'Localization', 'Translation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "tolgee/tolgee:v3.184.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Tolgee", "version": "latest", "description": "Tolgee is a revolutionary localization platform designed to simplify and speed up the translation process of your application. With Tolgee, you can translate your app into any language without modifying your code. It offers a range of features including in-context translating, translation memory, machine translations, auto translation, and activity log. The in-context translating feature allows you to translate strings directly in the app you develop, even in production. Translation memory ensures you don't translate the same string twice by reusing strings you've already translated. Machine translations let you leverage the power of DeepL, Google Translate, and AWS translate. Auto translation delivers your translations instantly right after you add them. The activity log feature helps you monitor the translation activities. Tolgee also allows users to add screenshots with a single click, providing context for translations. It is designed to be developer-friendly with easy integration with all major JS frameworks. Tolgee is not only easy to use for developers but also for translators, making the localization process seamless and efficient.", "category": "developer-tools", "tags": ["Developer Tools", "Localization", "Translation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "tolgee/tolgee:v3.184.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://tolgee.io"}, {"label": "Documentation", "url": "https://tolgee.io/platform"}, {"label": "Github", "url": "https://github.com/tolgee/tolgee-platform"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "tolgee", "port": "$PORT:8080", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('tooljet', 'Tooljet', 'Tooljet is an open-source low-code platform for building internal tools and business applications. It provides a visual interface builder, database connectors, API integrations, and workflow automation capabilities. With Tooljet, teams can quickly build custom dashboards, admin panels, CRUD applications, and complex business tools without extensive coding. The platform supports multiple data sources, real-time collaboration, and enterprise-grade security features.', 'low-code', ARRAY['Low-Code', 'Internal Tools', 'Business Applications', 'Dashboard', 'Database', 'API', 'Workflow', 'Automation', 'Visual Builder', 'Enterprise'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "tooljet/tooljet-ce:v3.20.154-lts"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Tooljet", "version": "latest", "description": "Tooljet is an open-source low-code platform for building internal tools and business applications. It provides a visual interface builder, database connectors, API integrations, and workflow automation capabilities. With Tooljet, teams can quickly build custom dashboards, admin panels, CRUD applications, and complex business tools without extensive coding. The platform supports multiple data sources, real-time collaboration, and enterprise-grade security features.", "category": "low-code", "tags": ["Low-Code", "Internal Tools", "Business Applications", "Dashboard", "Database", "API", "Workflow", "Automation", "Visual Builder", "Enterprise"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "tooljet/tooljet-ce:v3.20.154-lts"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/ToolJet/ToolJet"}, {"label": "Documentation", "url": "https://docs.tooljet.com/"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/tooljet/tooljet"}], "instructions": "Please run migrations inside the tooljet container if required, it will take 2-3 minutes to complete. \"npm run db:migrate:prod\"", "install": [{"docker": {"image": "$IMAGE", "name": "tooljet", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Please run migrations inside the tooljet container if required, it will take 2-3 minutes to complete. \"npm run db:migrate:prod\""}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('tracardi', 'Tracardi', 'Tracardi is an open-source customer data platform (CDP) designed for real-time data processing, customer segmentation, and workflow automation. It enables businesses to collect, process, and analyze customer data while offering actionable insights. Tracardi provides a powerful visual interface, robust API support, and scalable deployment options.', 'customer-data-platform', ARRAY['Customer Data Platform', 'Real-Time Analytics', 'Workflow Automation', 'Open-Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Tracardi", "version": "latest", "description": "Tracardi is an open-source customer data platform (CDP) designed for real-time data processing, customer segmentation, and workflow automation. It enables businesses to collect, process, and analyze customer data while offering actionable insights. Tracardi provides a powerful visual interface, robust API support, and scalable deployment options.", "category": "customer-data-platform", "tags": ["Customer Data Platform", "Real-Time Analytics", "Workflow Automation", "Open-Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://docs.tracardi.com"}, {"label": "GitHub", "url": "https://github.com/Tracardi/tracardi"}], "instructions": "Configure the API Domain in the GUI.", "install": [{"docker": {"image": "$IMAGE", "name": "tracardi", "port": "$PORT:80", "volumes": ["/usr/share/elasticsearch/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Configure the API Domain in the GUI."}, "services": {"mysql": {"type": "mysql", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('traccar', 'Traccar', 'Traccar is an open-source GPS tracking system designed for real-time tracking of vehicles, assets, and individuals. It supports a wide range of GPS devices and mobile apps, providing a secure, reliable, and highly customizable platform for tracking and managing your data. Traccar is ideal for fleet management, personal tracking, and asset monitoring.', 'gps-tracking', ARRAY['GPS Tracking', 'Fleet Management', 'Real-Time Tracking', 'Self-Hosted', 'Asset Monitoring'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "traccar/traccar:6.13.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Traccar", "version": "latest", "description": "Traccar is an open-source GPS tracking system designed for real-time tracking of vehicles, assets, and individuals. It supports a wide range of GPS devices and mobile apps, providing a secure, reliable, and highly customizable platform for tracking and managing your data. Traccar is ideal for fleet management, personal tracking, and asset monitoring.", "category": "gps-tracking", "tags": ["GPS Tracking", "Fleet Management", "Real-Time Tracking", "Self-Hosted", "Asset Monitoring"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "traccar/traccar:6.13.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.traccar.org/"}, {"label": "Github", "url": "https://github.com/traccar/traccar"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "traccar", "port": "$PORT:5000", "volumes": ["/opt/traccar/logs", "/opt/traccar/conf/traccar.xml"], "extra_ports": ["5150:5150", "8082:8082"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('traduora', 'Traduora', 'Traduora is a modern, self-hosted translation management platform designed for teams and developers. It provides a clean and intuitive interface for managing translation projects across multiple languages. With Traduora, you can easily import and export translations in various formats, collaborate with translators, and integrate translations into your applications via API. The platform supports real-time updates, version control of translations, and role-based access control to manage translator permissions. Traduora helps streamline the localization workflow by providing a centralized place to manage all your translation needs while maintaining full control over your translation data and processes.', 'translation-management', ARRAY['Translation Management', 'Self-Hosted', 'Localization'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "everco/ever-traduora:v0.21.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Traduora", "version": "latest", "description": "Traduora is a modern, self-hosted translation management platform designed for teams and developers. It provides a clean and intuitive interface for managing translation projects across multiple languages. With Traduora, you can easily import and export translations in various formats, collaborate with translators, and integrate translations into your applications via API. The platform supports real-time updates, version control of translations, and role-based access control to manage translator permissions. Traduora helps streamline the localization workflow by providing a centralized place to manage all your translation needs while maintaining full control over your translation data and processes.", "category": "translation-management", "tags": ["Translation Management", "Self-Hosted", "Localization"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "everco/ever-traduora:v0.21.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://docs.traduora.co/docs/getting-started"}, {"label": "Github", "url": "https://github.com/traduora/traduora"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "traduora", "port": "$PORT:8080", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('traffic-source', 'Traffic Source', 'Traffic Source is an open-source, self-hosted web analytics platform for tracking pageviews, referrers, UTM attribution, visitor journeys, and conversions. It is cookie-free by default, supports multi-site tracking, and stores data locally in SQLite so you keep full ownership. It also includes affiliate tracking and Stripe conversion syncing.', 'analytics', ARRAY['Analytics', 'Web Analytics', 'Privacy', 'Self-Hosted', 'Marketing', 'Attribution'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Traffic Source", "version": "latest", "description": "Traffic Source is an open-source, self-hosted web analytics platform for tracking pageviews, referrers, UTM attribution, visitor journeys, and conversions. It is cookie-free by default, supports multi-site tracking, and stores data locally in SQLite so you keep full ownership. It also includes affiliate tracking and Stripe conversion syncing.", "category": "analytics", "tags": ["Analytics", "Web Analytics", "Privacy", "Self-Hosted", "Marketing", "Attribution"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://trafficsource.app"}, {"label": "GitHub", "url": "https://github.com/mddanishyusuf/traffic-source"}, {"label": "Documentation", "url": "https://github.com/mddanishyusuf/traffic-source#readme"}], "instructions": "After deploy, open the app and create the first user (registration is only\navailable for the first account). Then create a site and add the tracking\nscript snippet from your instance to your website. For geo data, place the\napp behind Cloudflare proxy as documented upstream.\n", "install": [{"docker": {"image": "$IMAGE", "name": "traffic-source", "port": "$PORT:3000", "volumes": ["/app/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deploy, open the app and create the first user (registration is only\navailable for the first account). Then create a site and add the tracking\nscript snippet from your instance to your website. For geo data, place the\napp behind Cloudflare proxy as documented upstream.\n"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('traggo', 'Traggo', 'Traggo is a powerful, self-hosted time tracking and project management tool designed to help teams and individuals organize their workflows and track time efficiently. It features an intuitive interface, flexible reporting, and customizable dashboards. With Traggo, you can maintain complete control over your data, ensuring privacy and productivity.', 'time-tracking', ARRAY['Time Tracking', 'Self-Hosted', 'Productivity', 'Project Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "traggo/server:0.8.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3030}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Traggo", "version": "latest", "description": "Traggo is a powerful, self-hosted time tracking and project management tool designed to help teams and individuals organize their workflows and track time efficiently. It features an intuitive interface, flexible reporting, and customizable dashboards. With Traggo, you can maintain complete control over your data, ensuring privacy and productivity.", "category": "time-tracking", "tags": ["Time Tracking", "Self-Hosted", "Productivity", "Project Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "traggo/server:0.8.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3030}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://traggo.net/"}, {"label": "Github", "url": "https://github.com/traggo/server"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "traggo", "port": "$PORT:3030", "volumes": ["/opt/traggo/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('transmission', 'Transmission', 'Transmission is designed for easy, powerful use. Transmission has the features you want from a BitTorrent client, encryption, a web interface, peer exchange, magnet links, DHT, µTP, UPnP and NAT-PMP port forwarding, webseed support, watch directories, tracker editing, global and per-torrent speed limits, and more.', 'torrent', ARRAY['Torrent', 'BitTorrent Client'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/transmission:4.1.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9091}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Transmission", "version": "latest", "description": "Transmission is designed for easy, powerful use. Transmission has the features you want from a BitTorrent client, encryption, a web interface, peer exchange, magnet links, DHT, \u00b5TP, UPnP and NAT-PMP port forwarding, webseed support, watch directories, tracker editing, global and per-torrent speed limits, and more.", "category": "torrent", "tags": ["Torrent", "BitTorrent Client"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/transmission:4.1.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9091}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://docs.linuxserver.io/images/docker-transmission/"}, {"label": "Github", "url": "https://github.com/linuxserver/docker-transmission"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "transmission", "port": "$PORT:9091", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('trigger', 'Trigger', 'Trigger.dev is a free and open-source platform that simplifies building workflows and automations directly within your codebase. It provides a powerful way to connect your application to APIs, schedule tasks, and manage real-time and delayed workflows with ease. By integrating seamlessly into your development process, Trigger.dev allows developers to focus on delivering high-value features instead of managing complex infrastructure. Its scalability and ease of use make it a great fit for modern web applications and cloud-based systems.', 'workflow-automation', ARRAY['Workflow Automation', 'API Integration', 'Real-Time', 'Open Source', 'Cloud-Based'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/triggerdotdev/trigger.dev:v3.3.18"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3030}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Trigger", "version": "latest", "description": "Trigger.dev is a free and open-source platform that simplifies building workflows and automations directly within your codebase. It provides a powerful way to connect your application to APIs, schedule tasks, and manage real-time and delayed workflows with ease. By integrating seamlessly into your development process, Trigger.dev allows developers to focus on delivering high-value features instead of managing complex infrastructure. Its scalability and ease of use make it a great fit for modern web applications and cloud-based systems.", "category": "workflow-automation", "tags": ["Workflow Automation", "API Integration", "Real-Time", "Open Source", "Cloud-Based"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/triggerdotdev/trigger.dev:v3.3.18"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3030}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://trigger.dev/"}, {"label": "Documentation", "url": "https://docs.trigger.dev/"}, {"label": "Github", "url": "https://github.com/triggerdotdev/trigger.dev"}], "instructions": "You should connect your application to Trigger.dev using the provided SDKs and API endpoints for effortless workflow automation.", "install": [{"docker": {"image": "$IMAGE", "name": "trigger", "port": "$PORT:3030", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "You should connect your application to Trigger.dev using the provided SDKs and API endpoints for effortless workflow automation."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('trilium', 'Trilium Notes', 'Trilium is a hierarchical note-taking application designed for creating and managing large personal knowledge bases. With Trilium, you can arrange your notes into an arbitrarily deep tree structure, with the ability to place a single note in multiple locations. The app offers rich WYSIWYG note editing, including tables, images, and math, with markdown autoformat. It also supports editing notes with source code, complete with syntax highlighting. Trilium provides seamless note versioning and attributes for note organization, querying, and advanced scripting. The app also includes a synchronization feature with a self-hosted sync server. For enhanced security, Trilium offers strong note encryption with per-note granularity. Other features include sketching diagrams with built-in Excalidraw, visualizing notes and their relations with relation maps and link maps, and a REST API for automation. Trilium is optimized for both usability and performance, capable of handling upwards of 100,000 notes.', 'notes', ARRAY['Notes'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "zadam/trilium:0.63.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Trilium Notes", "version": "latest", "description": "Trilium is a hierarchical note-taking application designed for creating and managing large personal knowledge bases. With Trilium, you can arrange your notes into an arbitrarily deep tree structure, with the ability to place a single note in multiple locations. The app offers rich WYSIWYG note editing, including tables, images, and math, with markdown autoformat. It also supports editing notes with source code, complete with syntax highlighting. Trilium provides seamless note versioning and attributes for note organization, querying, and advanced scripting. The app also includes a synchronization feature with a self-hosted sync server. For enhanced security, Trilium offers strong note encryption with per-note granularity. Other features include sketching diagrams with built-in Excalidraw, visualizing notes and their relations with relation maps and link maps, and a REST API for automation. Trilium is optimized for both usability and performance, capable of handling upwards of 100,000 notes.", "category": "notes", "tags": ["Notes"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "zadam/trilium:0.63.7"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://github.com/zadam/trilium/wiki"}, {"label": "Github", "url": "https://github.com/zadam/trilium"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "trilium", "port": "$PORT:8080", "volumes": ["/home/node/trilium-data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('troddit', 'Troddit', 'Troddit is a web-based Reddit client that provides a clean, modern interface for browsing Reddit. It offers an alternative frontend experience with improved user interface design and functionality. Troddit allows users to browse subreddits, view posts, and navigate Reddit content through a streamlined web interface without requiring the official Reddit app or website.', 'reddit', ARRAY['Reddit', 'Social Media', 'Web Client', 'Frontend', 'Privacy'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "bsyed/troddit:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Troddit", "version": "latest", "description": "Troddit is a web-based Reddit client that provides a clean, modern interface for browsing Reddit. It offers an alternative frontend experience with improved user interface design and functionality. Troddit allows users to browse subreddits, view posts, and navigate Reddit content through a streamlined web interface without requiring the official Reddit app or website.", "category": "reddit", "tags": ["Reddit", "Social Media", "Web Client", "Frontend", "Privacy"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "bsyed/troddit:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/burhan-syed/troddit"}, {"label": "Website", "url": "https://www.troddit.com"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "troddit", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('trudesk', 'Trudesk', 'Trudesk is a self-hosted, open-source help desk and ticketing system designed for businesses and teams to efficiently manage customer support inquiries. It provides a modern and user-friendly web interface for tracking, organizing, and resolving support tickets. Trudesk includes role-based user management, real-time notifications, reporting tools, and an API for integration with other services. It supports multiple authentication methods, including OAuth and LDAP, making it suitable for enterprise environments. Additionally, Trudesk offers email integration, enabling automatic ticket creation from emails. With its containerized deployment, it ensures scalability and ease of management.', 'help-desk', ARRAY['Help Desk', 'Customer Support', 'Ticketing System', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "polonel/trudesk:1.2.11"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8118}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Trudesk", "version": "latest", "description": "Trudesk is a self-hosted, open-source help desk and ticketing system designed for businesses and teams to efficiently manage customer support inquiries. It provides a modern and user-friendly web interface for tracking, organizing, and resolving support tickets. Trudesk includes role-based user management, real-time notifications, reporting tools, and an API for integration with other services. It supports multiple authentication methods, including OAuth and LDAP, making it suitable for enterprise environments. Additionally, Trudesk offers email integration, enabling automatic ticket creation from emails. With its containerized deployment, it ensures scalability and ease of management.", "category": "help-desk", "tags": ["Help Desk", "Customer Support", "Ticketing System", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "polonel/trudesk:1.2.11"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8118}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://docs.trudesk.io"}, {"label": "Github", "url": "https://github.com/polonel/trudesk"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "trudesk", "port": "$PORT:8118", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('trufflehog', 'TruffleHog', 'TruffleHog is a security tool that finds secrets in your code, repositories, and files. It uses pattern matching, entropy analysis, and other methods to detect potential secrets and credentials.', 'security', ARRAY['Security', 'Code Analysis', 'Secret Detection', 'Self-hosted', 'Open Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "trufflesecurity/trufflehog:3.93.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "TruffleHog", "version": "latest", "description": "TruffleHog is a security tool that finds secrets in your code, repositories, and files. It uses pattern matching, entropy analysis, and other methods to detect potential secrets and credentials.", "category": "security", "tags": ["Security", "Code Analysis", "Secret Detection", "Self-hosted", "Open Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "trufflesecurity/trufflehog:3.93.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://trufflesecurity.com"}, {"label": "GitHub", "url": "https://github.com/trufflesecurity/trufflehog"}, {"label": "Documentation", "url": "https://trufflesecurity.com/docs/trufflehog"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/trufflesecurity/trufflehog"}], "instructions": "After installation, TruffleHog will scan the specified directory for secrets. Configure the scan path and command options in the settings.", "install": [{"docker": {"image": "$IMAGE", "name": "trufflehog", "port": "$PORT:80", "volumes": ["/workdir"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After installation, TruffleHog will scan the specified directory for secrets. Configure the scan path and command options in the settings."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('tubearchivist', 'TubeArchivist', 'TubeArchivist is a self-hosted YouTube archiving tool that allows you to manage and organize your YouTube content locally. It downloads videos, indexes metadata, and provides a web-based interface for searching, organizing, and playing content. Designed for personal use, TubeArchivist integrates with Elasticsearch for advanced search capabilities and Redis for optimized caching and task management. It also supports custom playlists, video tagging, and offline playback, providing complete control over your video collection.', 'video-management', ARRAY['Video Management', 'YouTube Archiving', 'Offline Playback', 'Personal Media Server'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "bbilly1/tubearchivist:v0.5.10"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "TubeArchivist", "version": "latest", "description": "TubeArchivist is a self-hosted YouTube archiving tool that allows you to manage and organize your YouTube content locally. It downloads videos, indexes metadata, and provides a web-based interface for searching, organizing, and playing content. Designed for personal use, TubeArchivist integrates with Elasticsearch for advanced search capabilities and Redis for optimized caching and task management. It also supports custom playlists, video tagging, and offline playback, providing complete control over your video collection.", "category": "video-management", "tags": ["Video Management", "YouTube Archiving", "Offline Playback", "Personal Media Server"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "bbilly1/tubearchivist:v0.5.10"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://github.com/tubearchivist/tubearchivist/wiki"}, {"label": "Dockerhub", "url": "https://hub.docker.com/r/bbilly1/tubearchivist"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "tubearchivist", "port": "$PORT:8000", "volumes": ["/youtube", "/usr/share/elasticsearch/data", "/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('tubesync', 'TubeSync', 'TubeSync is a powerful self-hosted application designed to automatically sync and download YouTube videos from subscriptions or playlists. It provides an intuitive web interface to manage downloads, supports filtering by keywords, and integrates with various media management systems. TubeSync allows users to schedule automatic downloads, ensuring they never miss new content from their favorite channels. It is built for efficiency, offering high-speed downloads and optimized storage handling. The application runs as a lightweight container, making it easy to deploy and manage.', 'youtube', ARRAY['YouTube', 'Video Management', 'Automation', 'Media'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/meeb/tubesync:v0.17.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4848}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "TubeSync", "version": "latest", "description": "TubeSync is a powerful self-hosted application designed to automatically sync and download YouTube videos from subscriptions or playlists. It provides an intuitive web interface to manage downloads, supports filtering by keywords, and integrates with various media management systems. TubeSync allows users to schedule automatic downloads, ensuring they never miss new content from their favorite channels. It is built for efficiency, offering high-speed downloads and optimized storage handling. The application runs as a lightweight container, making it easy to deploy and manage.", "category": "youtube", "tags": ["YouTube", "Video Management", "Automation", "Media"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/meeb/tubesync:v0.17.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4848}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/meeb/tubesync"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "tubesync", "port": "$PORT:4848", "volumes": ["/config", "/downloads"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('tugtainer', 'Tugtainer', 'Tugtainer is a self-hosted Docker container management application that provides a web-based interface for managing Docker containers and images. Built with modern architecture, Tugtainer offers comprehensive container management capabilities including container lifecycle management, image management, and network configuration. The system uses a secure socket proxy service to safely access the Docker socket, providing an additional layer of security. Perfect for developers and system administrators looking for a self-hosted alternative to manage Docker containers with a user-friendly interface.', 'docker', ARRAY['Docker', 'Container Management', 'Self-Hosted', 'Management', 'DevOps', 'Infrastructure'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/quenary/tugtainer:v1.29.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Tugtainer", "version": "latest", "description": "Tugtainer is a self-hosted Docker container management application that provides a web-based interface for managing Docker containers and images. Built with modern architecture, Tugtainer offers comprehensive container management capabilities including container lifecycle management, image management, and network configuration. The system uses a secure socket proxy service to safely access the Docker socket, providing an additional layer of security. Perfect for developers and system administrators looking for a self-hosted alternative to manage Docker containers with a user-friendly interface.", "category": "docker", "tags": ["Docker", "Container Management", "Self-Hosted", "Management", "DevOps", "Infrastructure"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/quenary/tugtainer:v1.29.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/quenary/tugtainer"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "tugtainer", "port": "$PORT:80", "volumes": ["/var/run/docker.sock", "/tugtainer"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('tunarr', 'Tunarr', 'Tunarr is a modern IPTV server that creates custom TV channels from your personal media library. It automatically generates continuous programming schedules using your movies, TV shows, and other content, creating an authentic TV viewing experience. Tunarr provides intelligent scheduling, program guide generation, and seamless integration with popular media libraries like Plex, Jellyfin, and Emby. Perfect for home entertainment setups, it transforms your digital media collection into personalized TV channels that can be watched on any IPTV-compatible device or application.', 'iptv', ARRAY['IPTV', 'Media Server', 'TV Channels', 'Streaming', 'Home Entertainment', 'Plex Integration', 'Jellyfin Integration'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "chrisbenincasa/tunarr:0.22.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Tunarr", "version": "latest", "description": "Tunarr is a modern IPTV server that creates custom TV channels from your personal media library. It automatically generates continuous programming schedules using your movies, TV shows, and other content, creating an authentic TV viewing experience. Tunarr provides intelligent scheduling, program guide generation, and seamless integration with popular media libraries like Plex, Jellyfin, and Emby. Perfect for home entertainment setups, it transforms your digital media collection into personalized TV channels that can be watched on any IPTV-compatible device or application.", "category": "iptv", "tags": ["IPTV", "Media Server", "TV Channels", "Streaming", "Home Entertainment", "Plex Integration", "Jellyfin Integration"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "chrisbenincasa/tunarr:0.22.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://tunarr.com"}, {"label": "GitHub", "url": "https://github.com/chrisbenincasa/tunarr"}, {"label": "Documentation", "url": "https://tunarr.com/api-docs"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/chrisbenincasa/tunarr"}], "instructions": "After deployment, access Tunarr through your domain. The web interface will guide you through the initial setup process. You'll need to configure your media library connections (Plex, Jellyfin, Emby, or local files), set up TV channels and programming schedules, and configure your IPTV player to connect to the generated M3U playlist. Tunarr will automatically scan your media library and create intelligent programming schedules for your custom TV channels.", "install": [{"docker": {"image": "$IMAGE", "name": "tunarr", "port": "$PORT:8000", "volumes": ["/config/tunarr"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deployment, access Tunarr through your domain. The web interface will guide you through the initial setup process. You'll need to configure your media library connections (Plex, Jellyfin, Emby, or local files), set up TV channels and programming schedules, and configure your IPTV player to connect to the generated M3U playlist. Tunarr will automatically scan your media library and create intelligent programming schedules for your custom TV channels."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('twenty', 'Twenty CRM', 'Twenty is a modern, open-source CRM platform designed to help businesses manage their customer relationships efficiently.  It offers a user-friendly interface for tracking contacts, organizations, and opportunities while providing powerful customization options.', 'crm', ARRAY['CRM', 'Business Apps', 'Productivity', 'Collaboration'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "twentycrm/twenty:v2.5.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Twenty CRM", "version": "latest", "description": "Twenty is a modern, open-source CRM platform designed to help businesses manage their customer relationships efficiently.  It offers a user-friendly interface for tracking contacts, organizations, and opportunities while providing powerful customization options.", "category": "crm", "tags": ["CRM", "Business Apps", "Productivity", "Collaboration"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "twentycrm/twenty:v2.5.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://twenty.com/"}, {"label": "Documentation", "url": "https://docs.twenty.com/"}, {"label": "Github", "url": "https://github.com/twentyhq/twenty"}], "instructions": "Twenty CRM is deployed with a server and a background worker service. The SERVER_URL is automatically set to the Easypanel-generated domain. If you configure a custom domain for the Twenty service, also update the SERVER_URL environment variable in the worker service to match.", "install": [{"docker": {"image": "$IMAGE", "name": "twenty", "port": "$PORT:3000", "volumes": ["/app/packages/twenty-server/.local-storage", "/app/packages/twenty-server/.local-storage"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Twenty CRM is deployed with a server and a background worker service. The SERVER_URL is automatically set to the Easypanel-generated domain. If you configure a custom domain for the Twenty service, also update the SERVER_URL environment variable in the worker service to match."}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('twingate', 'Twingate', 'Twingate Connector securely bridges your private network resources to the Twingate Zero Trust platform without exposing inbound ports. Deploy a lightweight connector container and authenticate it with your tenant network and connector tokens.', 'security', ARRAY['Security', 'Zero Trust', 'Networking', 'Remote Access'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "twingate/connector:1.88.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Twingate", "version": "latest", "description": "Twingate Connector securely bridges your private network resources to the Twingate Zero Trust platform without exposing inbound ports. Deploy a lightweight connector container and authenticate it with your tenant network and connector tokens.", "category": "security", "tags": ["Security", "Zero Trust", "Networking", "Remote Access"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "twingate/connector:1.88.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.twingate.com"}, {"label": "GitHub", "url": "https://github.com/Twingate/docker"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/twingate/connector"}], "instructions": "Before deploying, create a Connector in your Twingate Admin Console and copy the generated tokens. Set `Twingate Network` to your tenant name (the subdomain part of your Twingate URL), then paste the connector `Access Token` and `Refresh Token` into the template fields. Deploy at least one connector; for production, run two connectors on separate hosts for high availability.", "install": [{"docker": {"image": "$IMAGE", "name": "twingate", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Before deploying, create a Connector in your Twingate Admin Console and copy the generated tokens. Set `Twingate Network` to your tenant name (the subdomain part of your Twingate URL), then paste the connector `Access Token` and `Refresh Token` into the template fields. Deploy at least one connector; for production, run two connectors on separate hosts for high availability."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('tyk-gateway', 'Tyk Gateway', 'Tyk Gateway is an open-source API gateway for securing, scaling, and observing APIs. It sits in front of your upstream services and handles rate limiting, authentication, analytics, and transformations. This template runs the gateway in standalone mode with Redis for storage.', 'api-gateway', ARRAY['API Gateway', 'API', 'Redis', 'Open Source', 'Self-hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 6379}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Tyk Gateway", "version": "latest", "description": "Tyk Gateway is an open-source API gateway for securing, scaling, and observing APIs. It sits in front of your upstream services and handles rate limiting, authentication, analytics, and transformations. This template runs the gateway in standalone mode with Redis for storage.", "category": "api-gateway", "tags": ["API Gateway", "API", "Redis", "Open Source", "Self-hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 6379}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://tyk.io/"}, {"label": "Documentation", "url": "https://tyk.io/docs/"}, {"label": "GitHub", "url": "https://github.com/TykTechnologies/tyk"}, {"label": "Docker examples", "url": "https://github.com/TykTechnologies/tyk-gateway-docker"}], "instructions": "After deployment, access Tyk Gateway on the main domain (port 8080). Add API\ndefinitions by placing JSON files in the apps volume (mounted at\n/opt/tyk-gateway/apps). Configure policies in the policies volume and\nmiddleware in the middleware volume. TYK_GW_SECRET is auto-generated; use it\nwhen calling the Gateway API or with the Dashboard.\n", "install": [{"docker": {"image": "$IMAGE", "name": "tyk-gateway", "port": "$PORT:6379", "volumes": ["/opt/tyk-gateway/tyk.conf", "/opt/tyk-gateway/apps", "/opt/tyk-gateway/middleware", "/opt/tyk-gateway/certs", "/opt/tyk-gateway/policies"], "extra_ports": ["8080:8080"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deployment, access Tyk Gateway on the main domain (port 8080). Add API\ndefinitions by placing JSON files in the apps volume (mounted at\n/opt/tyk-gateway/apps). Configure policies in the policies volume and\nmiddleware in the middleware volume. TYK_GW_SECRET is auto-generated; use it\nwhen calling the Gateway API or with the Dashboard.\n"}, "services": {"redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('typebot', 'Typebot', 'Typebot is an innovative app designed to revolutionize the way you collect information. It allows you to build advanced chatbots visually, using powerful blocks to create unique chat experiences. You can embed these chatbots anywhere on your web or mobile apps and start collecting results instantly. Typebot is designed to replace your old school forms with chatbots, leading to an increase in customer satisfaction, retention, and a threefold increase in your conversion rate compared to traditional forms. With Typebot, you can easily drag and drop blocks to create your app, and even add custom code for your specific needs. It also offers native integration blocks and instructions on how to embed the chatbot on various platforms. One of the main advantages of Typebot is its real-time data collection feature, ensuring that you won''t lose any valuable data. It also offers many more powerful features such as hidden fields, team collaboration, linking to sub chatbots, custom code, custom domains, and folder management. Typebot is loved by teams and creators from all around the world for its intelligent features and drag-and-drop simplicity.', 'chat', ARRAY['Chat', 'Forms', 'Customer Support'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Typebot", "version": "latest", "description": "Typebot is an innovative app designed to revolutionize the way you collect information. It allows you to build advanced chatbots visually, using powerful blocks to create unique chat experiences. You can embed these chatbots anywhere on your web or mobile apps and start collecting results instantly. Typebot is designed to replace your old school forms with chatbots, leading to an increase in customer satisfaction, retention, and a threefold increase in your conversion rate compared to traditional forms. With Typebot, you can easily drag and drop blocks to create your app, and even add custom code for your specific needs. It also offers native integration blocks and instructions on how to embed the chatbot on various platforms. One of the main advantages of Typebot is its real-time data collection feature, ensuring that you won't lose any valuable data. It also offers many more powerful features such as hidden fields, team collaboration, linking to sub chatbots, custom code, custom domains, and folder management. Typebot is loved by teams and creators from all around the world for its intelligent features and drag-and-drop simplicity.", "category": "chat", "tags": ["Chat", "Forms", "Customer Support"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": ""}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://typebot.io"}, {"label": "Documentation", "url": "https://docs.typebot.io/"}, {"label": "Github", "url": "https://github.com/baptisteArno/typebot.io/"}], "instructions": "Please configure at least one OAuth provider for authentication.", "install": [{"docker": {"image": "$IMAGE", "name": "typebot", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Please configure at least one OAuth provider for authentication."}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('typesense', 'Typesense', 'Typesense is a powerful, fast, and typo-tolerant search engine designed to provide delightful search experiences. It is an open-source alternative to Algolia and a more user-friendly alternative to ElasticSearch. Typesense is capable of handling typographical errors gracefully, right out of the box. It is meticulously architected for low-latency, instant searches, offering a response time of less than 50ms. The app allows easy tailoring of search results, sorting of results based on a particular field at query time, and refining of results through faceting and filtering. It also supports grouping of similar results, federated search across multiple collections, geographic location-based search and sorting, and vector searching. Typesense also allows the generation of API keys for access to specific records, making it suitable for multi-tenant applications. It is designed to be simple to set up, integrate with, operate, and scale, making it a perfect choice for building delightful search experiences.', 'documentation', ARRAY['Documentation', 'Developer Tools', 'Data Science', 'Search'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "typesense/typesense:30.2.rc4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8108}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Typesense", "version": "latest", "description": "Typesense is a powerful, fast, and typo-tolerant search engine designed to provide delightful search experiences. It is an open-source alternative to Algolia and a more user-friendly alternative to ElasticSearch. Typesense is capable of handling typographical errors gracefully, right out of the box. It is meticulously architected for low-latency, instant searches, offering a response time of less than 50ms. The app allows easy tailoring of search results, sorting of results based on a particular field at query time, and refining of results through faceting and filtering. It also supports grouping of similar results, federated search across multiple collections, geographic location-based search and sorting, and vector searching. Typesense also allows the generation of API keys for access to specific records, making it suitable for multi-tenant applications. It is designed to be simple to set up, integrate with, operate, and scale, making it a perfect choice for building delightful search experiences.", "category": "documentation", "tags": ["Documentation", "Developer Tools", "Data Science", "Search"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "typesense/typesense:30.2.rc4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8108}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://typesense.org/docs/"}, {"label": "Github", "url": "https://github.com/typesense/typesense"}, {"label": "Website", "url": "https://typesense.org/"}], "instructions": "Find your API key in the environment tab", "install": [{"docker": {"image": "$IMAGE", "name": "typesense", "port": "$PORT:8108", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Find your API key in the environment tab"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('ubooquity', 'Ubooquity', 'Ubooquity is a free, lightweight and easy-to-use home server for your comics and ebooks. It provides a clean web interface to browse, read, and organize your digital library from any device. Ubooquity supports various formats including CBZ, CBR, CB7, PDF, EPUB, and many more. It features user management, reading progress tracking, and can serve your media collection to multiple users simultaneously. The server includes both a library interface for browsing and an admin interface for configuration, making it perfect for managing your digital book and comic collection at home.', 'books', ARRAY['Books', 'Comics', 'Digital Library', 'Media Server', 'Reading', 'Home Server', 'Web Interface', 'Library Management', 'PDF Reader', 'Comic Reader'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/ubooquity:2.1.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 2202}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Ubooquity", "version": "latest", "description": "Ubooquity is a free, lightweight and easy-to-use home server for your comics and ebooks. It provides a clean web interface to browse, read, and organize your digital library from any device. Ubooquity supports various formats including CBZ, CBR, CB7, PDF, EPUB, and many more. It features user management, reading progress tracking, and can serve your media collection to multiple users simultaneously. The server includes both a library interface for browsing and an admin interface for configuration, making it perfect for managing your digital book and comic collection at home.", "category": "books", "tags": ["Books", "Comics", "Digital Library", "Media Server", "Reading", "Home Server", "Web Interface", "Library Management", "PDF Reader", "Comic Reader"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/ubooquity:2.1.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 2202}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://vaemendis.net/ubooquity/"}, {"label": "Documentation", "url": "https://vaemendis.github.io/ubooquity-doc/pages/installation-guide.html"}, {"label": "GitHub", "url": "https://github.com/vaemendis/ubooquity-doc"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "ubooquity", "port": "$PORT:2202", "volumes": ["/config", "/books", "/comics", "/files"], "extra_ports": ["2203:2203"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('ulogger', 'uLogger', 'uLogger is a lightweight, self-hosted GPS tracking platform that allows you to track and visualize your location data. It''s perfect for personal use, fleet management, or tracking outdoor activities.', 'gps-tracking', ARRAY['GPS Tracking', 'Location', 'Self-hosted', 'Open Source', 'Mobile'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "bfabiszewski/ulogger:v1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "uLogger", "version": "latest", "description": "uLogger is a lightweight, self-hosted GPS tracking platform that allows you to track and visualize your location data. It's perfect for personal use, fleet management, or tracking outdoor activities.", "category": "gps-tracking", "tags": ["GPS Tracking", "Location", "Self-hosted", "Open Source", "Mobile"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "bfabiszewski/ulogger:v1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/bfabiszewski/ulogger-server"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/bfabiszewski/ulogger"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "ulogger", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('umami', 'Umami', 'Umami is a privacy-focused, open-source alternative to Google Analytics. It is designed to respect user privacy by not collecting any personal information, using cookies, or tracking users across websites. It is GDPR compliant and ensures that all data collected is anonymized, making it impossible to identify any individual user. Umami is simple and easy to use, collecting only the metrics you care about and presenting them on a single page. It is a reliable and transparent product with over 4 million downloads. With Umami, you can own your data and stay compliant with ever-changing data privacy laws.', 'analytics', ARRAY['Analytics', 'Privacy'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/umami-software/umami:postgresql-v2.20.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Umami", "version": "latest", "description": "Umami is a privacy-focused, open-source alternative to Google Analytics. It is designed to respect user privacy by not collecting any personal information, using cookies, or tracking users across websites. It is GDPR compliant and ensures that all data collected is anonymized, making it impossible to identify any individual user. Umami is simple and easy to use, collecting only the metrics you care about and presenting them on a single page. It is a reliable and transparent product with over 4 million downloads. With Umami, you can own your data and stay compliant with ever-changing data privacy laws.", "category": "analytics", "tags": ["Analytics", "Privacy"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/umami-software/umami:postgresql-v2.20.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://umami.is/"}, {"label": "Github", "url": "https://github.com/umami-software/umami"}, {"label": "Documentation", "url": "https://umami.is/docs"}], "instructions": "You can login with username \"admin\" and password \"umami\".", "install": [{"docker": {"image": "$IMAGE", "name": "umami", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "You can login with username \"admin\" and password \"umami\"."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('universalmediaserver', 'Universal Media Server', 'Universal Media Server (UMS) is a DLNA-compliant media server that can share videos, audio, and images to any DLNA-capable device, including smart TVs, game consoles, mobile devices, and other computers. It supports a wide range of formats and offers extensive customization options for transcoding and streaming.', 'media-server', ARRAY['Media Server', 'DLNA', 'Streaming', 'Transcoding', 'Home Media'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "universalmediaserver/ums:14.12.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9001}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Universal Media Server", "version": "latest", "description": "Universal Media Server (UMS) is a DLNA-compliant media server that can share videos, audio, and images to any DLNA-capable device, including smart TVs, game consoles, mobile devices, and other computers. It supports a wide range of formats and offers extensive customization options for transcoding and streaming.", "category": "media-server", "tags": ["Media Server", "DLNA", "Streaming", "Transcoding", "Home Media"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "universalmediaserver/ums:14.12.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 9001}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.universalmediaserver.com/"}, {"label": "GitHub", "url": "https://github.com/UniversalMediaServer/UniversalMediaServer"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/universalmediaserver/ums"}], "instructions": "Mount your media library to the `ums-media` volume at `/root/media`, then open Universal Media Server from your Easypanel domain and complete the initial library scan and device discovery setup.", "install": [{"docker": {"image": "$IMAGE", "name": "universalmediaserver", "port": "$PORT:9001", "volumes": ["/root/media"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Mount your media library to the `ums-media` volume at `/root/media`, then open Universal Media Server from your Easypanel domain and complete the initial library scan and device discovery setup."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('unleash', 'Unleash', 'Unleash is an open-source feature management software designed to cater to the needs of large enterprises. It provides a private, secure, and scalable platform that is ready to handle complex setups right out of the box. Unleash allows you to code freely, release confidently, and then scale your software. It offers a ''buy, then build'' solution that is flexible, multilingual, and scales along with your business processes. This results in reduced costs, efficient hours, and less technical debt. Unleash also allows for progressive, targeted feature rollouts, enabling you to release features to selected users the moment you''re ready. It supports change requests and approvals, and provides resilience during service outages. With Unleash, you can easily customize the software to your specific use cases, build multiple environments on separate instances, and keep your user data safe through privacy by design, data residency, and flexible hosting options.', 'developer-tools', ARRAY['Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "unleashorg/unleash-server:7.6.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4242}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Unleash", "version": "latest", "description": "Unleash is an open-source feature management software designed to cater to the needs of large enterprises. It provides a private, secure, and scalable platform that is ready to handle complex setups right out of the box. Unleash allows you to code freely, release confidently, and then scale your software. It offers a 'buy, then build' solution that is flexible, multilingual, and scales along with your business processes. This results in reduced costs, efficient hours, and less technical debt. Unleash also allows for progressive, targeted feature rollouts, enabling you to release features to selected users the moment you're ready. It supports change requests and approvals, and provides resilience during service outages. With Unleash, you can easily customize the software to your specific use cases, build multiple environments on separate instances, and keep your user data safe through privacy by design, data residency, and flexible hosting options.", "category": "developer-tools", "tags": ["Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "unleashorg/unleash-server:7.6.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4242}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://getunleash.io"}, {"label": "Documentation", "url": "https://docs.getunleash.io"}, {"label": "Github", "url": "https://github.com/Unleash/unleash"}, {"label": "Demo", "url": "https://www.getunleash.io/interactive-demo"}], "instructions": "Login with admin:unleash4all", "install": [{"docker": {"image": "$IMAGE", "name": "unleash", "port": "$PORT:4242", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Login with admin:unleash4all"}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('unsend', 'Unsend', 'Unsend is a self-hosted, alternative email-sending platform that provides a reliable and cost-effective way to send emails using Amazon SES. With a powerful dashboard, Unsend allows users to manage contacts, send bulk emails (such as newsletters and product updates), and handle subscriptions seamlessly. Future updates aim to support additional communication channels, including SMS, push notifications, and WhatsApp.', 'email', ARRAY['Email', 'Self-Hosted', 'Amazon SES', 'Bulk Email', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/unsend-dev/unsend:v1.5.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Unsend", "version": "latest", "description": "Unsend is a self-hosted, alternative email-sending platform that provides a reliable and cost-effective way to send emails using Amazon SES. With a powerful dashboard, Unsend allows users to manage contacts, send bulk emails (such as newsletters and product updates), and handle subscriptions seamlessly. Future updates aim to support additional communication channels, including SMS, push notifications, and WhatsApp.", "category": "email", "tags": ["Email", "Self-Hosted", "Amazon SES", "Bulk Email", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/unsend-dev/unsend:v1.5.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://unsend.dev/"}, {"label": "Github", "url": "https://github.com/unsend-dev/unsend/tree/main"}], "instructions": "You can use Minio for S3 Compatibility and provide AWS like credentials for it.", "install": [{"docker": {"image": "$IMAGE", "name": "unsend", "port": "$PORT:3000", "volumes": ["/data", "/data"], "extra_ports": ["9000:9000", "9001:9001"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "You can use Minio for S3 Compatibility and provide AWS like credentials for it."}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('upsnap', 'UpSnap', 'UpSnap is a self-hosted wake-on-lan (WOL) server with a modern web interface. It allows you to remotely power on computers on your local network from anywhere through an intuitive dashboard. UpSnap features device management with customizable names and MAC addresses, wake history tracking, and user authentication. Perfect for home networks, small offices, or lab environments where you need to remotely manage the power state of multiple machines.', 'wake-on-lan', ARRAY['Wake-on-LAN', 'Network Management', 'Remote Access', 'System Administration', 'Power Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/seriousm4x/upsnap:4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8090}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "UpSnap", "version": "latest", "description": "UpSnap is a self-hosted wake-on-lan (WOL) server with a modern web interface. It allows you to remotely power on computers on your local network from anywhere through an intuitive dashboard. UpSnap features device management with customizable names and MAC addresses, wake history tracking, and user authentication. Perfect for home networks, small offices, or lab environments where you need to remotely manage the power state of multiple machines.", "category": "wake-on-lan", "tags": ["Wake-on-LAN", "Network Management", "Remote Access", "System Administration", "Power Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/seriousm4x/upsnap:4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8090}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/seriousm4x/upsnap"}, {"label": "Container", "url": "https://github.com/seriousm4x/upsnap/pkgs/container/upsnap"}], "instructions": "Open UpSnap from your domain, create an admin account, then add your devices with their MAC addresses and host details. Ensure Wake-on-LAN is enabled in each target machine BIOS/UEFI and network adapter settings.", "install": [{"docker": {"image": "$IMAGE", "name": "upsnap", "port": "$PORT:8090", "volumes": ["/app/pb_data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Open UpSnap from your domain, create an admin account, then add your devices with their MAC addresses and host details. Ensure Wake-on-LAN is enabled in each target machine BIOS/UEFI and network adapter settings."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('uptimekuma', 'UptimeKuma', 'Uptime Kuma is a self-hosted monitoring tool designed to keep track of your website''s uptime. It provides a comprehensive monitoring solution for HTTP(s), TCP, HTTP(s) Keyword, HTTP(s) Json Query, Ping, DNS Record, Push, Steam Game Server, and Docker Containers. The tool features a user-friendly, reactive, and fast UI/UX. It offers notifications via various platforms including Telegram, Discord, Gotify, Slack, Pushover, and Email (SMTP), among others. Uptime Kuma supports multi-language interfaces and multiple status pages, allowing users to map status pages to specific domains. It also provides ping charts, certificate info, proxy support, and 2FA support for enhanced security. This tool is perfect for those who want to ensure their website is always up and running.', 'monitoring', ARRAY['Monitoring', 'Self-hosted', 'Uptime'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "louislam/uptime-kuma:2.3.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3001}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "UptimeKuma", "version": "latest", "description": "Uptime Kuma is a self-hosted monitoring tool designed to keep track of your website's uptime. It provides a comprehensive monitoring solution for HTTP(s), TCP, HTTP(s) Keyword, HTTP(s) Json Query, Ping, DNS Record, Push, Steam Game Server, and Docker Containers. The tool features a user-friendly, reactive, and fast UI/UX. It offers notifications via various platforms including Telegram, Discord, Gotify, Slack, Pushover, and Email (SMTP), among others. Uptime Kuma supports multi-language interfaces and multiple status pages, allowing users to map status pages to specific domains. It also provides ping charts, certificate info, proxy support, and 2FA support for enhanced security. This tool is perfect for those who want to ensure their website is always up and running.", "category": "monitoring", "tags": ["Monitoring", "Self-hosted", "Uptime"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "louislam/uptime-kuma:2.3.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3001}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://uptime.kuma.pet"}, {"label": "Documentation", "url": "https://github.com/louislam/uptime-kuma/wiki"}, {"label": "Github", "url": "https://github.com/louislam/uptime-kuma"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "uptimekuma", "port": "$PORT:3001", "volumes": ["/app/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('uptrace', 'Uptrace', 'Uptrace is an open-source APM platform for traces, metrics, and logs using OpenTelemetry, with ClickHouse storage and PostgreSQL metadata. This template follows the official example/docker compose stack (Uptrace, ClickHouse, Postgres, Redis, OTel Collector, Vector, Grafana, Prometheus, Alertmanager, Mailpit). The Vector image uses timberio/vector:0.28.X-alpine to match that upstream example (legacy Docker Hub namespace); migrate to distroless/vector only when you intentionally diverge from upstream.', 'monitoring', ARRAY['Monitoring', 'APM', 'OpenTelemetry', 'Observability', 'Tracing'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "uptrace/uptrace:2.1.0-beta.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Uptrace", "version": "latest", "description": "Uptrace is an open-source APM platform for traces, metrics, and logs using OpenTelemetry, with ClickHouse storage and PostgreSQL metadata. This template follows the official example/docker compose stack (Uptrace, ClickHouse, Postgres, Redis, OTel Collector, Vector, Grafana, Prometheus, Alertmanager, Mailpit). The Vector image uses timberio/vector:0.28.X-alpine to match that upstream example (legacy Docker Hub namespace); migrate to distroless/vector only when you intentionally diverge from upstream.", "category": "monitoring", "tags": ["Monitoring", "APM", "OpenTelemetry", "Observability", "Tracing"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "uptrace/uptrace:2.1.0-beta.5"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://uptrace.dev"}, {"label": "GitHub", "url": "https://github.com/uptrace/uptrace"}, {"label": "Documentation", "url": "https://uptrace.dev/get"}], "instructions": "Login; Use the admin name/email/password from the template form (password is random if left blank). The project DSN token is generated once per deploy and embedded in `/etc/uptrace/config.yml`, OTel Collector, Grafana datasource, Prometheus remote_write, and Vector\u2014keep file mounts stable or regenerate configs together. Ingestion; Published host ports match the upstream example\u201414317\u21924317 (Uptrace gRPC, referenced in `site.ingest_url`), 4317/4318 (OTLP on the collector). On shared hosts these can conflict; change published ports in Easypanel and update `ingest_url` / client endpoints accordingly. Grafana & Mailpit use separate app domains on ports 3000 and 8025; assign subdomains or paths in Easypanel as needed. TLS; Upstream compose mounts TLS certs; this template omits them for HTTPS termination at the proxy\u2014see Uptrace docs if you need in-container TLS.", "install": [{"docker": {"image": "$IMAGE", "name": "uptrace", "port": "$PORT:80", "volumes": ["/etc/uptrace/config.yml", "/var/lib/clickhouse", "/etc/clickhouse-server/config.d/config.xml", "/etc/otelcol-contrib/config.yaml", "/etc/alertmanager/config.yml", "/alertmanager", "/etc/vector/vector.toml", "/etc/grafana/provisioning/datasources/datasource.yml", "/etc/grafana/grafana.ini", "/etc/prometheus/prometheus.yml", "/prometheus", "/data"], "extra_ports": ["1025:1025", "3000:3000", "4317:4317", "4318:4318", "8025:8025", "14317:14317"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Login; Use the admin name/email/password from the template form (password is random if left blank). The project DSN token is generated once per deploy and embedded in `/etc/uptrace/config.yml`, OTel Collector, Grafana datasource, Prometheus remote_write, and Vector\u2014keep file mounts stable or regenerate configs together. Ingestion; Published host ports match the upstream example\u201414317\u21924317 (Uptrace gRPC, referenced in `site.ingest_url`), 4317/4318 (OTLP on the collector). On shared hosts these can conflict; change published ports in Easypanel and update `ingest_url` / client endpoints accordingly. Grafana & Mailpit use separate app domains on ports 3000 and 8025; assign subdomains or paths in Easypanel as needed. TLS; Upstream compose mounts TLS certs; this template omits them for HTTPS termination at the proxy\u2014see Uptrace docs if you need in-container TLS."}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('upvote-rss', 'Upvote RSS', 'Upvote RSS is a self-hosted RSS feed generator for popular posts from social aggregation sites. It supports Reddit, Hacker News, Lemmy, Lobsters, PieFed, Mbin, and GitHub—build rich RSS feeds with filtering (e.g. average posts per day), embedded media, optional AI summaries (Ollama, OpenAI, Gemini, Anthropic, and more), article content parsing, and top comments. Reddit OAuth env vars are optional and only needed for Reddit-specific feeds; other platforms are configured in the web UI. Cache data under /app/cache for performance across container updates.', 'rss', ARRAY['RSS', 'Reddit', 'Hacker News', 'Lemmy', 'Self-Hosted', 'Feed Generator', 'Open Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/johnwarne/upvote-rss:v1.8.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Upvote RSS", "version": "latest", "description": "Upvote RSS is a self-hosted RSS feed generator for popular posts from social aggregation sites. It supports Reddit, Hacker News, Lemmy, Lobsters, PieFed, Mbin, and GitHub\u2014build rich RSS feeds with filtering (e.g. average posts per day), embedded media, optional AI summaries (Ollama, OpenAI, Gemini, Anthropic, and more), article content parsing, and top comments. Reddit OAuth env vars are optional and only needed for Reddit-specific feeds; other platforms are configured in the web UI. Cache data under /app/cache for performance across container updates.", "category": "rss", "tags": ["RSS", "Reddit", "Hacker News", "Lemmy", "Self-Hosted", "Feed Generator", "Open Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/johnwarne/upvote-rss:v1.8.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/johnwarne/upvote-rss"}, {"label": "Website", "url": "https://www.upvote-rss.com/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "upvote-rss", "port": "$PORT:80", "volumes": ["/app/cache"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('urocissa', 'Urocissa', 'Urocissa is a self-hosted photo and video gallery designed to serve massive collections, capable of handling millions of images and videos. Built with Rust and Vue, it features blazing fast performance with an in-memory cached database that can instantly serve, search, and filter one million photos in under a second. It runs on as little as 4 GB of RAM even with a million photos, offers infinite scrolling without pagination using advanced virtual scrolling, and supports instant boolean search (and, or, not) across your entire library. Features include upload support, auto-sync from local folders, EXIF data extraction, user-defined tags, duplicate handling, shareable albums, and read-only mode.', 'photos', ARRAY['Photos', 'Gallery', 'Self-Hosted', 'Media', 'Images'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "hsa00000/urocissa:2.0.14"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5673}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Urocissa", "version": "latest", "description": "Urocissa is a self-hosted photo and video gallery designed to serve massive collections, capable of handling millions of images and videos. Built with Rust and Vue, it features blazing fast performance with an in-memory cached database that can instantly serve, search, and filter one million photos in under a second. It runs on as little as 4 GB of RAM even with a million photos, offers infinite scrolling without pagination using advanced virtual scrolling, and supports instant boolean search (and, or, not) across your entire library. Features include upload support, auto-sync from local folders, EXIF data extraction, user-defined tags, duplicate handling, shareable albums, and read-only mode.", "category": "photos", "tags": ["Photos", "Gallery", "Self-Hosted", "Media", "Images"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "hsa00000/urocissa:2.0.14"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5673}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://hsa00000.github.io/urocissa/"}, {"label": "GitHub", "url": "https://github.com/hsa00000/Urocissa"}, {"label": "Documentation", "url": "https://github.com/hsa00000/Urocissa/blob/main/docs/CONFIG.md"}, {"label": "Demo", "url": "https://demo.photoserver.tw"}], "instructions": "Default password is generated automatically.", "install": [{"docker": {"image": "$IMAGE", "name": "urocissa", "port": "$PORT:5673", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Default password is generated automatically."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('usermemos', 'Usermemos', 'Usermemos is a lightweight, self-hosted note-taking application designed for simplicity, accessibility, and efficiency. It provides an intuitive interface for capturing and organizing memos with support for markdown formatting, tagging, and searching. This app is a Docker containerized version of Usermemos, making it easy to deploy and manage in various environments. The app supports multiple architectures, including x86-64 and arm64, and can be accessed via HTTP or HTTPS. It offers additional environment variables and configurations to enable customization. Usermemos is designed for both personal and collaborative usage, ensuring that users can manage their notes effectively.', 'productivity', ARRAY['Productivity', 'Note-Taking', 'Self-Hosted', 'Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "neosmemo/memos:0.28.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5230}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Usermemos", "version": "latest", "description": "Usermemos is a lightweight, self-hosted note-taking application designed for simplicity, accessibility, and efficiency. It provides an intuitive interface for capturing and organizing memos with support for markdown formatting, tagging, and searching. This app is a Docker containerized version of Usermemos, making it easy to deploy and manage in various environments. The app supports multiple architectures, including x86-64 and arm64, and can be accessed via HTTP or HTTPS. It offers additional environment variables and configurations to enable customization. Usermemos is designed for both personal and collaborative usage, ensuring that users can manage their notes effectively.", "category": "productivity", "tags": ["Productivity", "Note-Taking", "Self-Hosted", "Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "neosmemo/memos:0.28.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5230}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://www.usememos.com/docs"}, {"label": "Github", "url": "https://github.com/usememos/memos"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "usermemos", "port": "$PORT:5230", "volumes": ["/var/opt/memos"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('usertour', 'Usertour', 'Usertour.io is an open-source user onboarding platform that helps developers create interactive product tours, feature introductions, and user guides without writing a single line of code. It allows you to design and deploy interactive walkthroughs, checklists, and tooltips to improve user activation and adoption. The platform provides a visual editor for creating tours, targeting specific user segments, and collecting analytics on user engagement. Usertour.io integrates seamlessly with your application, offering customization options to match your branding and design. With its developer-friendly approach, it enables teams to create, test, and deploy product tours quickly while maintaining a native look and feel.', 'user-onboarding', ARRAY['User Onboarding', 'Product Tours', 'User Experience', 'Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "usertour/usertour:0.4.9"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Usertour", "version": "latest", "description": "Usertour.io is an open-source user onboarding platform that helps developers create interactive product tours, feature introductions, and user guides without writing a single line of code. It allows you to design and deploy interactive walkthroughs, checklists, and tooltips to improve user activation and adoption. The platform provides a visual editor for creating tours, targeting specific user segments, and collecting analytics on user engagement. Usertour.io integrates seamlessly with your application, offering customization options to match your branding and design. With its developer-friendly approach, it enables teams to create, test, and deploy product tours quickly while maintaining a native look and feel.", "category": "user-onboarding", "tags": ["User Onboarding", "Product Tours", "User Experience", "Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "usertour/usertour:0.4.9"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://www.usertour.io/"}, {"label": "Documentation", "url": "https://docs.usertour.io/"}, {"label": "Github", "url": "https://github.com/usertour/usertour"}], "instructions": "Login using the email; lisa@simpson.com, password; secret42", "install": [{"docker": {"image": "$IMAGE", "name": "usertour", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Login using the email; lisa@simpson.com, password; secret42"}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('usesend', 'Usesend', 'Usesend is a self-hosted email marketing and transactional email platform that gives you complete control over your email infrastructure. It provides a modern, user-friendly interface for creating, sending, and tracking email campaigns, newsletters, and transactional emails. Usesend features advanced segmentation, email automation, template management, analytics, and subscriber management. Built with Next.js and powered by PostgreSQL, Redis, and MinIO for reliable storage, it offers enterprise-grade features without vendor lock-in or usage-based pricing. Usesend supports GitHub OAuth for authentication and includes API rate limiting and SMTP configuration for sending emails. Perfect for businesses and developers who want full ownership of their email marketing infrastructure.', 'email-marketing', ARRAY['Email Marketing', 'Newsletter', 'Transactional Email', 'SMTP', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "usesend/usesend:v1.8.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Usesend", "version": "latest", "description": "Usesend is a self-hosted email marketing and transactional email platform that gives you complete control over your email infrastructure. It provides a modern, user-friendly interface for creating, sending, and tracking email campaigns, newsletters, and transactional emails. Usesend features advanced segmentation, email automation, template management, analytics, and subscriber management. Built with Next.js and powered by PostgreSQL, Redis, and MinIO for reliable storage, it offers enterprise-grade features without vendor lock-in or usage-based pricing. Usesend supports GitHub OAuth for authentication and includes API rate limiting and SMTP configuration for sending emails. Perfect for businesses and developers who want full ownership of their email marketing infrastructure.", "category": "email-marketing", "tags": ["Email Marketing", "Newsletter", "Transactional Email", "SMTP", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "usesend/usesend:v1.8.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://usesend.com/"}, {"label": "Documentation", "url": "https://docs.usesend.com/"}, {"label": "Github", "url": "https://github.com/usesend/usesend"}], "instructions": "After deployment, configure your GitHub OAuth app credentials and AWS Access Key and Secret Key.", "install": [{"docker": {"image": "$IMAGE", "name": "usesend", "port": "$PORT:3000", "volumes": ["/data"], "extra_ports": ["9001:9001", "9002:9002"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deployment, configure your GitHub OAuth app credentials and AWS Access Key and Secret Key."}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('vane', 'Vane', 'Vane is a privacy focused AI answering engine that combines web search with local and cloud LLM providers. It supports cited answers, file uploads, search history, and configurable model backends while running on your own hardware.', 'ai', ARRAY['AI', 'Search Engine', 'LLM', 'RAG', 'Privacy'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "itzcrazykns1337/vane:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Vane", "version": "latest", "description": "Vane is a privacy focused AI answering engine that combines web search with local and cloud LLM providers. It supports cited answers, file uploads, search history, and configurable model backends while running on your own hardware.", "category": "ai", "tags": ["AI", "Search Engine", "LLM", "RAG", "Privacy"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "itzcrazykns1337/vane:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://github.com/ItzCrazyKns/Vane/tree/master/docs"}, {"label": "GitHub", "url": "https://github.com/ItzCrazyKns/Vane"}], "instructions": "Deploy and open your domain to complete setup from the in-app onboarding screen. The default image includes bundled SearxNG, so no extra search service is required. To use your own SearxNG instance, set SearxNG API URL in the template form. Data persists in /home/vane/data through the mounted volume.", "install": [{"docker": {"image": "$IMAGE", "name": "vane", "port": "$PORT:3000", "volumes": ["/home/vane/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Deploy and open your domain to complete setup from the in-app onboarding screen. The default image includes bundled SearxNG, so no extra search service is required. To use your own SearxNG instance, set SearxNG API URL in the template form. Data persists in /home/vane/data through the mounted volume."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('vaultwarden', 'Vaultwarden', 'Vaultwarden is an unofficial Bitwarden server implementation designed for self-hosted deployments. It is written in Rust and is compatible with the official Bitwarden clients. This application is ideal for individuals, families, and smaller organizations who find the official resource-heavy service undesirable. Vaultwarden supports a wide range of features including personal and organization vault support, password sharing and access control, file attachments, two-step login via email, Duo, YubiKey, and FIDO2 WebAuthn, and many more. It also supports live sync for desktop/browser clients/extensions and mobile clients (Android/iOS). However, it does not prioritize the development of features mainly useful to larger organizations such as single sign-on and directory syncing.', 'password-manager', ARRAY['Password Manager', 'Security', 'Self-hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "vaultwarden/server:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Vaultwarden", "version": "latest", "description": "Vaultwarden is an unofficial Bitwarden server implementation designed for self-hosted deployments. It is written in Rust and is compatible with the official Bitwarden clients. This application is ideal for individuals, families, and smaller organizations who find the official resource-heavy service undesirable. Vaultwarden supports a wide range of features including personal and organization vault support, password sharing and access control, file attachments, two-step login via email, Duo, YubiKey, and FIDO2 WebAuthn, and many more. It also supports live sync for desktop/browser clients/extensions and mobile clients (Android/iOS). However, it does not prioritize the development of features mainly useful to larger organizations such as single sign-on and directory syncing.", "category": "password-manager", "tags": ["Password Manager", "Security", "Self-hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "vaultwarden/server:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://github.com/dani-garcia/vaultwarden/wiki"}, {"label": "Github", "url": "https://github.com/dani-garcia/vaultwarden"}, {"label": "Enviroment Variables", "url": "https://github.com/dani-garcia/vaultwarden/blob/main/.env.template"}], "instructions": "To access the administration interface, please go to /admin on your installation url. The admin token is in your \"Environment\" tab.", "install": [{"docker": {"image": "$IMAGE", "name": "vaultwarden", "port": "$PORT:80", "volumes": ["/data", "/web-vault"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "To access the administration interface, please go to /admin on your installation url. The admin token is in your \"Environment\" tab."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('verdaccio', 'Verdaccio', 'Verdaccio is a lightweight, private npm proxy registry built in Node.js, designed to simplify and enhance your development workflow. It provides a simple, zero-configuration-required local private NPM registry, eliminating the need for a full database to get started. Verdaccio comes equipped with its own compact database and the capability to proxy other registries, such as npmjs.org, while caching the downloaded modules for improved efficiency. It allows you to use all the benefits of the npm package system in your company without exposing all your code to the public. You can link multiple registries, fetch packages from multiple sources in a single project, and even publish locally modified versions of third-party packages. Verdaccio is compatible with popular npm clients like npm, yarn, and pnpm, and supports various plugins for extended storage capabilities.', 'developer-tools', ARRAY['Developer Tools', 'Package Manager'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "verdaccio/verdaccio:6.5.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4873}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Verdaccio", "version": "latest", "description": "Verdaccio is a lightweight, private npm proxy registry built in Node.js, designed to simplify and enhance your development workflow. It provides a simple, zero-configuration-required local private NPM registry, eliminating the need for a full database to get started. Verdaccio comes equipped with its own compact database and the capability to proxy other registries, such as npmjs.org, while caching the downloaded modules for improved efficiency. It allows you to use all the benefits of the npm package system in your company without exposing all your code to the public. You can link multiple registries, fetch packages from multiple sources in a single project, and even publish locally modified versions of third-party packages. Verdaccio is compatible with popular npm clients like npm, yarn, and pnpm, and supports various plugins for extended storage capabilities.", "category": "developer-tools", "tags": ["Developer Tools", "Package Manager"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "verdaccio/verdaccio:6.5.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4873}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://verdaccio.org/"}, {"label": "Documentation", "url": "https://verdaccio.org/docs/what-is-verdaccio"}, {"label": "Github", "url": "https://github.com/verdaccio/verdaccio"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "verdaccio", "port": "$PORT:4873", "volumes": ["/opt/verdaccio"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('vexa-dashboard', 'Vexa Dashboard', 'Vexa Dashboard is a complete, all-in-one solution for self-hosted meeting transcription. This template deploys both the Vexa API (real-time meeting transcription engine) and its web dashboard in a single click.
INSERT INTO recipes VALUES ('vikunja', 'Vikunja', 'Vikunja is a self-hosted To-Do list application and task management tool. It provides a clean and intuitive interface for organizing tasks, projects, and team collaboration. With features like task lists, labels, assignees, due dates, and more, Vikunja helps individuals and teams stay organized and productive.', 'task-management', ARRAY['Task Management', 'To-Do List', 'Project Management', 'Productivity', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "vikunja/vikunja:0.24.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3456}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Vikunja", "version": "latest", "description": "Vikunja is a self-hosted To-Do list application and task management tool. It provides a clean and intuitive interface for organizing tasks, projects, and team collaboration. With features like task lists, labels, assignees, due dates, and more, Vikunja helps individuals and teams stay organized and productive.", "category": "task-management", "tags": ["Task Management", "To-Do List", "Project Management", "Productivity", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "vikunja/vikunja:0.24.6"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3456}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://vikunja.io/docs/"}, {"label": "Github", "url": "https://github.com/go-vikunja/vikunja"}], "instructions": "Create a new user and login to the application.", "install": [{"docker": {"image": "$IMAGE", "name": "vikunja", "port": "$PORT:3456", "volumes": ["/app/vikunja/files"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Create a new user and login to the application."}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('viseron', 'Viseron', 'Viseron is a self-hosted, local network video recorder (NVR) and AI-powered video surveillance system designed for privacy-conscious users. It supports multiple camera streams with advanced features like object detection, motion detection, face recognition, and license plate recognition using machine learning models. Viseron can record continuous video, create event-based clips, generate timelapses, and send real-time notifications. It integrates seamlessly with Home Assistant and supports various camera protocols including RTSP, HTTP, and USB cameras. The system features a modern web interface for live viewing, playback, and configuration. All processing happens locally on your hardware, ensuring your video data never leaves your network. Perfect for home security, surveillance systems, and smart home automation.', 'nvr', ARRAY['NVR', 'Video Surveillance', 'AI', 'Security Camera', 'Home Assistant', 'Object Detection'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "roflcoopter/viseron:3.5.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8888}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Viseron", "version": "latest", "description": "Viseron is a self-hosted, local network video recorder (NVR) and AI-powered video surveillance system designed for privacy-conscious users. It supports multiple camera streams with advanced features like object detection, motion detection, face recognition, and license plate recognition using machine learning models. Viseron can record continuous video, create event-based clips, generate timelapses, and send real-time notifications. It integrates seamlessly with Home Assistant and supports various camera protocols including RTSP, HTTP, and USB cameras. The system features a modern web interface for live viewing, playback, and configuration. All processing happens locally on your hardware, ensuring your video data never leaves your network. Perfect for home security, surveillance systems, and smart home automation.", "category": "nvr", "tags": ["NVR", "Video Surveillance", "AI", "Security Camera", "Home Assistant", "Object Detection"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "roflcoopter/viseron:3.5.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8888}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://viseron.netlify.app/"}, {"label": "Documentation", "url": "https://viseron.netlify.app/latest/"}, {"label": "Github", "url": "https://github.com/roflcoopter/viseron"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/roflcoopter/viseron"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "viseron", "port": "$PORT:8888", "volumes": ["/segments", "/snapshots", "/thumbnails", "/event_clips", "/timelapse", "/config", "/etc/localtime"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('vitess', 'Vitess', 'Vitess is a database clustering system for horizontal scaling of MySQL. It is designed to make it easier to scale and manage large deployments of MySQL databases. Vitess helps handle sharding, connection pooling, and query routing efficiently, making it a great choice for cloud-native applications and high-traffic websites. It is used by companies like YouTube and Slack to manage massive database workloads. Vitess provides built-in automation, strong consistency, and MySQL compatibility while being resilient to failures and easy to operate at scale.', 'database', ARRAY['Database', 'Scalability', 'Cloud-Native', 'MySQL'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "vitess/vttestserver:mysql84"}, "port": {"type": "integer", "title": "Port HTTP", "default": 33574}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Vitess", "version": "latest", "description": "Vitess is a database clustering system for horizontal scaling of MySQL. It is designed to make it easier to scale and manage large deployments of MySQL databases. Vitess helps handle sharding, connection pooling, and query routing efficiently, making it a great choice for cloud-native applications and high-traffic websites. It is used by companies like YouTube and Slack to manage massive database workloads. Vitess provides built-in automation, strong consistency, and MySQL compatibility while being resilient to failures and easy to operate at scale.", "category": "database", "tags": ["Database", "Scalability", "Cloud-Native", "MySQL"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "vitess/vttestserver:mysql84"}, "port": {"type": "integer", "title": "Port HTTP", "default": 33574}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://vitess.io/docs/"}, {"label": "Github", "url": "https://github.com/vitessio/vitess"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "vitess", "port": "$PORT:33574", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('vscode-server', 'Visual Studio Code Server', 'The LinuxServer.io team presents the docker-code-server, a powerful tool that allows you to run VS Code on a remote server, accessible through your browser. This means you can code on your Chromebook, tablet, and laptop with a consistent development environment. If you''re using a Windows or Mac workstation, you can more easily develop for Linux. The app also allows you to leverage large cloud servers to speed up tests, compilations, downloads, and more. It helps preserve battery life when you''re on the go, as all intensive computation runs on your server, eliminating the need for running excess instances of Chrome.', 'developer-tools', ARRAY['Developer Tools', 'Code Hosting'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/code-server:4.118.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Visual Studio Code Server", "version": "latest", "description": "The LinuxServer.io team presents the docker-code-server, a powerful tool that allows you to run VS Code on a remote server, accessible through your browser. This means you can code on your Chromebook, tablet, and laptop with a consistent development environment. If you're using a Windows or Mac workstation, you can more easily develop for Linux. The app also allows you to leverage large cloud servers to speed up tests, compilations, downloads, and more. It helps preserve battery life when you're on the go, as all intensive computation runs on your server, eliminating the need for running excess instances of Chrome.", "category": "developer-tools", "tags": ["Developer Tools", "Code Hosting"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/code-server:4.118.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://github.com/linuxserver/docker-code-server/blob/master/README.md"}, {"label": "Github", "url": "https://github.com/linuxserver/docker-code-server"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "vscode-server", "port": "$PORT:80", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('waha', 'WAHA', 'WAHA (WhatsApp HTTP API) is a self-hosted, privacy-focused WhatsApp API that you can run in a click! It provides a REST API to send and receive WhatsApp messages, manage groups, channels, and status updates. WAHA runs a real instance of WhatsApp Web to avoid getting blocked and supports automation through HTTP API. The core version is completely free with no limits on messages or time, making it perfect for WhatsApp automation, chatbots, and integrations.', 'whatsapp', ARRAY['WhatsApp', 'API', 'Messaging', 'Automation', 'Chatbot'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "devlikeapro/waha:latest-2026.4.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "WAHA", "version": "latest", "description": "WAHA (WhatsApp HTTP API) is a self-hosted, privacy-focused WhatsApp API that you can run in a click! It provides a REST API to send and receive WhatsApp messages, manage groups, channels, and status updates. WAHA runs a real instance of WhatsApp Web to avoid getting blocked and supports automation through HTTP API. The core version is completely free with no limits on messages or time, making it perfect for WhatsApp automation, chatbots, and integrations.", "category": "whatsapp", "tags": ["WhatsApp", "API", "Messaging", "Automation", "Chatbot"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "devlikeapro/waha:latest-2026.4.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://waha.devlike.pro/"}, {"label": "Github", "url": "https://github.com/devlikeapro/waha"}, {"label": "Documentation", "url": "https://waha.devlike.pro/docs"}], "instructions": "After deployment, access the WAHA dashboard at your service domain. The\ndefault username is \"admin\" and the password is auto-generated \u2014 check\nthe WAHA_DASHBOARD_PASSWORD environment variable in the service settings.\nThe same credentials are used for the Swagger API docs. The WAHA_API_KEY\nis also auto-generated and required for API authentication.\n", "install": [{"docker": {"image": "$IMAGE", "name": "waha", "port": "$PORT:3000", "volumes": ["/app/.sessions"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After deployment, access the WAHA dashboard at your service domain. The\ndefault username is \"admin\" and the password is auto-generated \u2014 check\nthe WAHA_DASHBOARD_PASSWORD environment variable in the service settings.\nThe same credentials are used for the Swagger API docs. The WAHA_API_KEY\nis also auto-generated and required for API authentication.\n"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('wakatime', 'Wakapi', 'Wakapi is a powerful open-source tool designed to help you track and analyze your coding time. It allows you to monitor the time you''ve spent coding on various projects, in different programming languages, and more. It''s perfect for those who love statistics and want to gain insights into their coding habits. Wakapi provides fancy statistics and plots, public leaderboards, cool badges for readmes, and weekly email reports. It''s built by developers for developers, ensuring it meets your needs perfectly. With Wakapi, you can easily keep track of your coding time and improve your productivity.', 'developer-tools', ARRAY['Developer Tools', 'Analytics'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "n1try/wakapi:2.17.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Wakapi", "version": "latest", "description": "Wakapi is a powerful open-source tool designed to help you track and analyze your coding time. It allows you to monitor the time you've spent coding on various projects, in different programming languages, and more. It's perfect for those who love statistics and want to gain insights into their coding habits. Wakapi provides fancy statistics and plots, public leaderboards, cool badges for readmes, and weekly email reports. It's built by developers for developers, ensuring it meets your needs perfectly. With Wakapi, you can easily keep track of your coding time and improve your productivity.", "category": "developer-tools", "tags": ["Developer Tools", "Analytics"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "n1try/wakapi:2.17.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://wakapi.dev/"}, {"label": "Github", "url": "https://github.com/muety/wakapi"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "wakatime", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('wallabag', 'Wallabag', 'Wallabag is a self-hosted read-it-later application that allows you to save web articles and access them later in a clean, distraction-free format. Written in PHP, it enables you to store and organize articles, categorize them with tags, and sync across multiple devices. Wallabag is privacy-focused, supports importing from services like Pocket and Instapaper, and provides a RESTful API for integration with other tools. The app offers browser extensions, a mobile-friendly interface, and multiple export options, including PDF, ePub, and plain text.', 'productivity', ARRAY['Productivity', 'Reading', 'Bookmarking'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "wallabag/wallabag:2.6.14"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Wallabag", "version": "latest", "description": "Wallabag is a self-hosted read-it-later application that allows you to save web articles and access them later in a clean, distraction-free format. Written in PHP, it enables you to store and organize articles, categorize them with tags, and sync across multiple devices. Wallabag is privacy-focused, supports importing from services like Pocket and Instapaper, and provides a RESTful API for integration with other tools. The app offers browser extensions, a mobile-friendly interface, and multiple export options, including PDF, ePub, and plain text.", "category": "productivity", "tags": ["Productivity", "Reading", "Bookmarking"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "wallabag/wallabag:2.6.14"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://doc.wallabag.org"}, {"label": "Github", "url": "https://github.com/wallabag/wallabag"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "wallabag", "port": "$PORT:80", "volumes": ["/var/www/wallabag/web/assets/images", "/var/www/wallabag/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('wallos', 'Wallos', 'Wallos is an open-source, self-hosted network monitoring and management platform that provides comprehensive network visibility, device discovery, and network analytics. It helps network administrators monitor network health, track bandwidth usage, and manage network devices efficiently.', 'network-monitoring', ARRAY['Network Monitoring', 'Network Management', 'Device Discovery', 'Bandwidth Monitoring', 'Network Analytics', 'Infrastructure', 'DevOps'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "bellamy/wallos:4.8.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Wallos", "version": "latest", "description": "Wallos is an open-source, self-hosted network monitoring and management platform that provides comprehensive network visibility, device discovery, and network analytics. It helps network administrators monitor network health, track bandwidth usage, and manage network devices efficiently.", "category": "network-monitoring", "tags": ["Network Monitoring", "Network Management", "Device Discovery", "Bandwidth Monitoring", "Network Analytics", "Infrastructure", "DevOps"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "bellamy/wallos:4.8.4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://wallos.app/"}, {"label": "Documentation", "url": "https://docs.wallos.app/"}, {"label": "Github", "url": "https://github.com/ellite/Wallos"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "wallos", "port": "$PORT:80", "volumes": ["/var/www/html/db", "/var/www/html/images/uploads/logos"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('wally', 'Wally', 'Wally is a lightweight web application designed for data management and tracking. It provides a clean web interface accessible through your browser, with persistent data storage to ensure your information is safely retained across restarts. The application can be pre-loaded with demo data for testing and evaluation purposes, making it easy to explore its features before using it with your own data. Wally runs efficiently in a containerized environment and requires minimal configuration to get started.', 'web-app', ARRAY['Web App', 'Data Management', 'Self-Hosted', 'Lightweight', 'Docker'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "poliuscorp/wally:1.14"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Wally", "version": "latest", "description": "Wally is a lightweight web application designed for data management and tracking. It provides a clean web interface accessible through your browser, with persistent data storage to ensure your information is safely retained across restarts. The application can be pre-loaded with demo data for testing and evaluation purposes, making it easy to explore its features before using it with your own data. Wally runs efficiently in a containerized environment and requires minimal configuration to get started.", "category": "web-app", "tags": ["Web App", "Data Management", "Self-Hosted", "Lightweight", "Docker"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "poliuscorp/wally:1.14"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://github.com/polius/Wally/blob/main/README.md"}, {"label": "GitHub", "url": "https://github.com/polius/Wally"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "wally", "port": "$PORT:80", "volumes": ["/wally/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('warracker', 'Warracker', 'Warracker is a self-hosted warranty tracking application that helps you manage and track warranties for your products and assets. It provides a comprehensive solution for storing warranty information, tracking expiration dates, managing documentation, and receiving notifications about upcoming warranty expirations. Built with a modern web interface and PostgreSQL database for reliable data storage.', 'warranty-tracking', ARRAY['Warranty Tracking', 'Asset Management', 'Self-Hosted', 'Web Interface', 'PostgreSQL', 'Email Notifications', 'Document Management'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/sassanix/warracker/main:0.10.1.14"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Warracker", "version": "latest", "description": "Warracker is a self-hosted warranty tracking application that helps you manage and track warranties for your products and assets. It provides a comprehensive solution for storing warranty information, tracking expiration dates, managing documentation, and receiving notifications about upcoming warranty expirations. Built with a modern web interface and PostgreSQL database for reliable data storage.", "category": "warranty-tracking", "tags": ["Warranty Tracking", "Asset Management", "Self-Hosted", "Web Interface", "PostgreSQL", "Email Notifications", "Document Management"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/sassanix/warracker/main:0.10.1.14"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/sassanix/warracker"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "warracker", "port": "$PORT:80", "volumes": ["/data/uploads"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('wastebin', 'Wastebin', 'Wastebin is a self-hosted, minimal pastebin designed for quick and simple text sharing. With a clean and intuitive interface inspired by bin, it allows users to create and share text snippets easily. Wastebin supports private pastes, syntax highlighting, and expiration settings for better control over shared content. It is lightweight, fast, and easy to deploy with minimal system requirements.', 'pastebin', ARRAY['Pastebin', 'Productivity', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "quxfoo/wastebin:3.6.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8088}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Wastebin", "version": "latest", "description": "Wastebin is a self-hosted, minimal pastebin designed for quick and simple text sharing. With a clean and intuitive interface inspired by bin, it allows users to create and share text snippets easily. Wastebin supports private pastes, syntax highlighting, and expiration settings for better control over shared content. It is lightweight, fast, and easy to deploy with minimal system requirements.", "category": "pastebin", "tags": ["Pastebin", "Productivity", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "quxfoo/wastebin:3.6.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8088}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://github.com/quxfoo/wastebin/wiki"}, {"label": "Github", "url": "https://github.com/quxfoo/wastebin"}], "instructions": "In case of Sqlite write error. Go to your host machine and go the directory. \"cd /etc/easypanel/projects/your-project/wastebin/volumes/\" and do this \"chown -R 10001:10001 data/\" then redeploy.", "install": [{"docker": {"image": "$IMAGE", "name": "wastebin", "port": "$PORT:8088", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "In case of Sqlite write error. Go to your host machine and go the directory. \"cd /etc/easypanel/projects/your-project/wastebin/volumes/\" and do this \"chown -R 10001:10001 data/\" then redeploy."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('watchtower', 'Watchtower', 'Watchtower is a process for automating Docker container base image updates. It monitors running containers and automatically updates them when their base image changes.', 'docker', ARRAY['Docker', 'Automation', 'Container', 'Self-hosted', 'Open Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "containrrr/watchtower:1.7.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Watchtower", "version": "latest", "description": "Watchtower is a process for automating Docker container base image updates. It monitors running containers and automatically updates them when their base image changes.", "category": "docker", "tags": ["Docker", "Automation", "Container", "Self-hosted", "Open Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "containrrr/watchtower:1.7.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://containrrr.dev/watchtower"}, {"label": "GitHub", "url": "https://github.com/containrrr/watchtower"}, {"label": "Documentation", "url": "https://containrrr.dev/watchtower/"}], "instructions": "Mount `/var/run/docker.sock` in the Watchtower service to let it inspect and update running containers. Add the label `com.centurylinklabs.watchtower.enable=true` to each container you want Watchtower to manage, then enable label filtering in Watchtower. Set your preferred check interval or schedule, and add `--cleanup` to remove old image layers after successful updates.", "install": [{"docker": {"image": "$IMAGE", "name": "watchtower", "port": "$PORT:80", "volumes": ["/var/run/docker.sock"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Mount `/var/run/docker.sock` in the Watchtower service to let it inspect and update running containers. Add the label `com.centurylinklabs.watchtower.enable=true` to each container you want Watchtower to manage, then enable label filtering in Watchtower. Set your preferred check interval or schedule, and add `--cleanup` to remove old image layers after successful updates."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('wbo', 'WBO', 'WBO (Whiteboard Online) is an open-source, self-hosted, collaborative whiteboard tool that allows users to draw, brainstorm, and share ideas in real-time. It provides a flexible and accessible platform for teams, classrooms, or personal use, enabling simultaneous collaboration on a shared digital canvas. WBO offers tools for free-hand drawing, adding shapes, text, and images, making it ideal for team brainstorming sessions, remote meetings, and educational activities. With a clean and intuitive interface, WBO enhances remote collaboration and facilitates interactive learning.', 'collaboration', ARRAY['Collaboration', 'Whiteboard', 'Self-hosted', 'Open-source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lovasoa/wbo:v1.22.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "WBO", "version": "latest", "description": "WBO (Whiteboard Online) is an open-source, self-hosted, collaborative whiteboard tool that allows users to draw, brainstorm, and share ideas in real-time. It provides a flexible and accessible platform for teams, classrooms, or personal use, enabling simultaneous collaboration on a shared digital canvas. WBO offers tools for free-hand drawing, adding shapes, text, and images, making it ideal for team brainstorming sessions, remote meetings, and educational activities. With a clean and intuitive interface, WBO enhances remote collaboration and facilitates interactive learning.", "category": "collaboration", "tags": ["Collaboration", "Whiteboard", "Self-hosted", "Open-source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lovasoa/wbo:v1.22.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://wbo.ophir.dev"}, {"label": "GitHub", "url": "https://github.com/lovasoa/whitebophir"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "wbo", "port": "$PORT:80", "volumes": ["/opt/app/server-data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('weaviate', 'Weaviate', 'Weaviate is an open-source vector database that allows you to store and retrieve data objects based on their semantic properties by indexing them with vectors. It can be used stand-alone or with a variety of modules that can do the vectorization for you and extend the core capabilities. Weaviate provides a lightning-fast pure vector similarity search over raw vectors or data objects, even with filters. It combines keyword-based search with vector search techniques for state-of-the-art results. You can also use any generative model in combination with your data, for example to do Q&A over your dataset. Weaviate''s next-gen vector database can power a wide range of innovative apps.', 'developer-tools', ARRAY['Developer Tools', 'Data Science', 'Databases'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "semitechnologies/weaviate:1.33.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Weaviate", "version": "latest", "description": "Weaviate is an open-source vector database that allows you to store and retrieve data objects based on their semantic properties by indexing them with vectors. It can be used stand-alone or with a variety of modules that can do the vectorization for you and extend the core capabilities. Weaviate provides a lightning-fast pure vector similarity search over raw vectors or data objects, even with filters. It combines keyword-based search with vector search techniques for state-of-the-art results. You can also use any generative model in combination with your data, for example to do Q&A over your dataset. Weaviate's next-gen vector database can power a wide range of innovative apps.", "category": "developer-tools", "tags": ["Developer Tools", "Data Science", "Databases"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "semitechnologies/weaviate:1.33.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://weaviate.io"}, {"label": "Documentation", "url": "https://weaviate.io/developers/weaviate"}, {"label": "Github", "url": "https://github.com/weaviate/weaviate"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "weaviate", "port": "$PORT:8080", "volumes": ["/var/lib/weaviate"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('web-check', 'Web-Check', 'A comprehensive OSINT tool for analyzing websites, providing insights into security configurations, server architecture, and technologies.', 'osint', ARRAY['OSINT', 'Security', 'Web Analysis', 'DNS', 'SSL', 'Performance'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lissy93/web-check"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Web-Check", "version": "latest", "description": "A comprehensive OSINT tool for analyzing websites, providing insights into security configurations, server architecture, and technologies.", "category": "osint", "tags": ["OSINT", "Security", "Web Analysis", "DNS", "SSL", "Performance"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lissy93/web-check"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://web-check.xyz/"}, {"label": "Github", "url": "https://github.com/Lissy93/web-check"}, {"label": "Documentation", "url": "https://web-check.xyz/about"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "web-check", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('web-portal', 'Web Portal', 'Web Portal is a lightweight and customizable dashboard application developed by enchant97. It provides a central hub for accessing your self-hosted applications and services. With a clean and intuitive interface, Web Portal helps you organize and access your web applications efficiently. It features a SQLite database for configuration storage and supports custom plugins for extended functionality. This containerized solution is perfect for home server enthusiasts and self-hosters looking for a clean, efficient way to manage their web applications.', 'dashboard', ARRAY['Dashboard', 'Web Portal', 'Self-hosted', 'Docker', 'Application Directory'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/enchant97/web-portal:2.5.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Web Portal", "version": "latest", "description": "Web Portal is a lightweight and customizable dashboard application developed by enchant97. It provides a central hub for accessing your self-hosted applications and services. With a clean and intuitive interface, Web Portal helps you organize and access your web applications efficiently. It features a SQLite database for configuration storage and supports custom plugins for extended functionality. This containerized solution is perfect for home server enthusiasts and self-hosters looking for a clean, efficient way to manage their web applications.", "category": "dashboard", "tags": ["Dashboard", "Web Portal", "Self-hosted", "Docker", "Application Directory"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/enchant97/web-portal:2.5.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/enchant97/web-portal"}, {"label": "Container", "url": "https://github.com/enchant97/web-portal/pkgs/container/web-portal"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "web-portal", "port": "$PORT:8000", "volumes": ["/app/data", "/app/plugins"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('webcord', 'Webcord', 'WebCord is an application designed to enhance your Discord experience. It is a pack of security and privacy hardenings, Discord features reimplementations, Electron / Chromium / Discord bugs workarounds, stylesheets, internal pages and wrapped https://discord.com page. It is designed to conform with ToS as much as it is possible. The application can be accessed at: http://yourhost:3000/ or https://yourhost:3001/. This container is based on Docker Baseimage KasmVNC which means there are additional environment variables and run configurations to enable or disable specific functionality.', 'chat', ARRAY['Chat', 'Privacy'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/webcord:4.13.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Webcord", "version": "latest", "description": "WebCord is an application designed to enhance your Discord experience. It is a pack of security and privacy hardenings, Discord features reimplementations, Electron / Chromium / Discord bugs workarounds, stylesheets, internal pages and wrapped https://discord.com page. It is designed to conform with ToS as much as it is possible. The application can be accessed at: http://yourhost:3000/ or https://yourhost:3001/. This container is based on Docker Baseimage KasmVNC which means there are additional environment variables and run configurations to enable or disable specific functionality.", "category": "chat", "tags": ["Chat", "Privacy"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/webcord:4.13.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://docs.linuxserver.io/images/docker-webcord"}, {"label": "Github", "url": "https://github.com/SpacingBat3/WebCord"}], "instructions": "use abc:abc to login. To access the login interface, add ?login=true to your URL.", "install": [{"docker": {"image": "$IMAGE", "name": "webcord", "port": "$PORT:3000", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "use abc:abc to login. To access the login interface, add ?login=true to your URL."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('weblate', 'Weblate', 'Weblate is a powerful, web-based continuous localization system. It is designed to simplify the process of translating text from one language to another, making it an invaluable tool for projects and companies operating in multiple countries. With Weblate, users can easily translate using the platform, download and upload translations, and even integrate with version control systems for seamless workflow. The app supports a wide range of file formats, and it also provides a REST API and Python API for further flexibility. Weblate also offers features like automatic suggestions, translation memory, and various checks and fixups to ensure high-quality translations. Whether you''re starting with internationalization or managing an established translators community, Weblate has the features to support your translation needs.', 'localization', ARRAY['Localization', 'Translation', 'Web-based'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "weblate/weblate:5.16.0.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Weblate", "version": "latest", "description": "Weblate is a powerful, web-based continuous localization system. It is designed to simplify the process of translating text from one language to another, making it an invaluable tool for projects and companies operating in multiple countries. With Weblate, users can easily translate using the platform, download and upload translations, and even integrate with version control systems for seamless workflow. The app supports a wide range of file formats, and it also provides a REST API and Python API for further flexibility. Weblate also offers features like automatic suggestions, translation memory, and various checks and fixups to ensure high-quality translations. Whether you're starting with internationalization or managing an established translators community, Weblate has the features to support your translation needs.", "category": "localization", "tags": ["Localization", "Translation", "Web-based"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "weblate/weblate:5.16.0.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://docs.weblate.org/en/latest/index.html"}, {"label": "Github", "url": "https://github.com/WeblateOrg/weblate"}], "instructions": "Please use the following credentials to login. changeme@easypanel.io|changeme", "install": [{"docker": {"image": "$IMAGE", "name": "weblate", "port": "$PORT:8080", "volumes": ["/app/data", "/app/cache"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Please use the following credentials to login. changeme@easypanel.io|changeme"}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('webtop', 'WebTop', 'WebTop is a browser-based Linux desktop environment, self-hosted using Docker. It provides a full-featured desktop experience accessible from any device with a modern web browser. WebTop supports multiple desktop environments and applications, making it a versatile tool for productivity, remote work, and development.', 'browser-based', ARRAY['Browser-Based', 'Self-Hosted', 'Productivity', 'Remote Desktop'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/webtop:ubuntu-xfce-version-4e5d70f4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "WebTop", "version": "latest", "description": "WebTop is a browser-based Linux desktop environment, self-hosted using Docker. It provides a full-featured desktop experience accessible from any device with a modern web browser. WebTop supports multiple desktop environments and applications, making it a versatile tool for productivity, remote work, and development.", "category": "browser-based", "tags": ["Browser-Based", "Self-Hosted", "Productivity", "Remote Desktop"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/webtop:ubuntu-xfce-version-4e5d70f4"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://docs.linuxserver.io/images/docker-webtop/"}, {"label": "Github", "url": "https://github.com/linuxserver/docker-webtop"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "webtop", "port": "$PORT:3000", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('wekan', 'Wekan', 'WeKan is an open-source, customizable, and privacy-focused Kanban app designed for efficient task management. It allows you to create multiple boards for different projects or tasks, with each board having columns to represent different stages of your work such as ''To Do'', ''Doing'', and ''Done''. You can add cards to each board to represent tasks, complete with titles, descriptions, and due dates. WeKan uses lists on a Kanban board to represent different stages of a workflow, helping you organize and track tasks. You can customize lists by changing their color or adding custom fields to capture more information about tasks. A card in WeKan represents a task on a Kanban board, including a title, description, due date, labels, and comments. As work progresses, you can move the card from one column to another. WeKan also offers several features to protect your data, including a self-hosting option, access controls, and open-source code for security auditing. It is designed with security in mind, and its features and options are built to help you protect your data and keep it secure.', 'project-management', ARRAY['Project Management', 'Open-Source', 'Task Management', 'Kanban'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/wekan/wekan:v7.93"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Wekan", "version": "latest", "description": "WeKan is an open-source, customizable, and privacy-focused Kanban app designed for efficient task management. It allows you to create multiple boards for different projects or tasks, with each board having columns to represent different stages of your work such as 'To Do', 'Doing', and 'Done'. You can add cards to each board to represent tasks, complete with titles, descriptions, and due dates. WeKan uses lists on a Kanban board to represent different stages of a workflow, helping you organize and track tasks. You can customize lists by changing their color or adding custom fields to capture more information about tasks. A card in WeKan represents a task on a Kanban board, including a title, description, due date, labels, and comments. As work progresses, you can move the card from one column to another. WeKan also offers several features to protect your data, including a self-hosting option, access controls, and open-source code for security auditing. It is designed with security in mind, and its features and options are built to help you protect your data and keep it secure.", "category": "project-management", "tags": ["Project Management", "Open-Source", "Task Management", "Kanban"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/wekan/wekan:v7.93"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://wekan.github.io/"}, {"label": "Docs", "url": "https://github.com/wekan/wekan/wiki"}, {"label": "Github", "url": "https://github.com/wekan/wekan"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "wekan", "port": "$PORT:8080", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('wg-easy', 'Wg-easy', 'WireGuard Easy is an all-in-one application designed to simplify the installation and management of WireGuard on any Linux host. With a user-friendly web interface, it allows you to list, create, edit, delete, enable, and disable clients with ease. You can also view a client''s QR code and download a client''s configuration file directly from the app. The app provides statistics on which clients are connected and features Tx/Rx charts for each connected client. It also supports Gravatar. WireGuard Easy requires a host with a kernel that supports WireGuard and Docker installed.', 'network-tools', ARRAY['Network Tools', 'Security', 'VPN', 'WireGuard'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/wg-easy/wg-easy:15.2.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 51820}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Wg-easy", "version": "latest", "description": "WireGuard Easy is an all-in-one application designed to simplify the installation and management of WireGuard on any Linux host. With a user-friendly web interface, it allows you to list, create, edit, delete, enable, and disable clients with ease. You can also view a client's QR code and download a client's configuration file directly from the app. The app provides statistics on which clients are connected and features Tx/Rx charts for each connected client. It also supports Gravatar. WireGuard Easy requires a host with a kernel that supports WireGuard and Docker installed.", "category": "network-tools", "tags": ["Network Tools", "Security", "VPN", "WireGuard"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/wg-easy/wg-easy:15.2.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 51820}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/wg-easy/wg-easy"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "wg-easy", "port": "$PORT:51820", "volumes": ["/etc/wireguard", "/lib/modules"], "extra_ports": ["51821:51821"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('whisparr', 'Whisparr', 'Whisparr is an adult video collection manager designed for Usenet and BitTorrent users. It monitors multiple RSS feeds for new adult content and interfaces with clients and indexers to grab, sort, and rename them. Whisparr also features automatic upgrades of existing files in your library to better quality formats when available. It includes a calendar to track upcoming releases, manual search for precise selection, and automatic handling of failed downloads. Whisparr ensures optimal release selection with its custom formats feature, offering detailed control over prioritization. It supports major platforms like Windows, Linux, macOS, and others.', 'adult-media', ARRAY['Adult Media', 'Download Manager'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "hotio/whisparr:v3-41ddd1f"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Whisparr", "version": "latest", "description": "Whisparr is an adult video collection manager designed for Usenet and BitTorrent users. It monitors multiple RSS feeds for new adult content and interfaces with clients and indexers to grab, sort, and rename them. Whisparr also features automatic upgrades of existing files in your library to better quality formats when available. It includes a calendar to track upcoming releases, manual search for precise selection, and automatic handling of failed downloads. Whisparr ensures optimal release selection with its custom formats feature, offering detailed control over prioritization. It supports major platforms like Windows, Linux, macOS, and others.", "category": "adult-media", "tags": ["Adult Media", "Download Manager"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "hotio/whisparr:v3-41ddd1f"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://whisparr.com/"}, {"label": "Documentation", "url": "https://wiki.servarr.com/whisparr"}, {"label": "Github", "url": "https://github.com/Whisparr/Whisparr/"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "whisparr", "port": "$PORT:80", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('whiteboard', 'Whiteboard', 'Whiteboard is a lightweight, NodeJS-based collaborative sketchboard that can be easily customized to your needs. It allows multiple users to draw and write together in real-time, with each user''s cursor visible to others. The app provides a range of features including the ability to undo and redo actions, drag and drop or copy and paste images or PDFs, resize, move, rotate and draw images, write text and sticky notes, and save the whiteboard to an image or JSON. You can also draw angle lines and squares by pressing ''Shift'' while drawing. The app is compatible with PC, tablet, and mobile devices, and can be used in various projects such as WebRTC conference tools and online collaboration learning activities.', 'productivity', ARRAY['Productivity', 'Collaboration', 'Whiteboard'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "rofl256/whiteboard:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Whiteboard", "version": "latest", "description": "Whiteboard is a lightweight, NodeJS-based collaborative sketchboard that can be easily customized to your needs. It allows multiple users to draw and write together in real-time, with each user's cursor visible to others. The app provides a range of features including the ability to undo and redo actions, drag and drop or copy and paste images or PDFs, resize, move, rotate and draw images, write text and sticky notes, and save the whiteboard to an image or JSON. You can also draw angle lines and squares by pressing 'Shift' while drawing. The app is compatible with PC, tablet, and mobile devices, and can be used in various projects such as WebRTC conference tools and online collaboration learning activities.", "category": "productivity", "tags": ["Productivity", "Collaboration", "Whiteboard"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "rofl256/whiteboard:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://github.com/cracker0dks/whiteboard"}, {"label": "Documentation", "url": "https://github.com/cracker0dks/whiteboard"}, {"label": "Github", "url": "https://github.com/cracker0dks/whiteboard"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "whiteboard", "port": "$PORT:8080", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('whoogle', 'Whoogle', 'Whoogle is an open-source, privacy-focused search engine that serves as a proxy for Google Search. It allows users to access Google’s powerful search capabilities without being tracked, monitored, or bombarded with ads. Whoogle removes trackers, logs, and ads, ensuring that search queries and browsing activities remain private and anonymous. Users benefit from Google''s accurate and comprehensive search results, while maintaining full control over their personal data. Its lightweight design makes it easy to deploy and use, often preferred by those seeking to balance search efficiency with enhanced privacy.', 'search', ARRAY['Search', 'Privacy', 'Open-Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "benbusby/whoogle-search:0.9.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Whoogle", "version": "latest", "description": "Whoogle is an open-source, privacy-focused search engine that serves as a proxy for Google Search. It allows users to access Google\u2019s powerful search capabilities without being tracked, monitored, or bombarded with ads. Whoogle removes trackers, logs, and ads, ensuring that search queries and browsing activities remain private and anonymous. Users benefit from Google's accurate and comprehensive search results, while maintaining full control over their personal data. Its lightweight design makes it easy to deploy and use, often preferred by those seeking to balance search efficiency with enhanced privacy.", "category": "search", "tags": ["Search", "Privacy", "Open-Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "benbusby/whoogle-search:0.9.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/benbusby/whoogle-search"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "whoogle", "port": "$PORT:5000", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('wikijs', 'Wiki.js', 'Wiki.js is a powerful and extensible open source Wiki software designed to make documentation a joy to write. It features a beautiful and intuitive interface that can be fully customized to your liking, including a light and dark mode. The software is compatible with various platforms and databases, including PostgreSQL, MySQL, MariaDB, MS SQL Server, and SQLite. With Wiki.js, you can manage all aspects of your wiki using the extensive and intuitive admin area. The software is built with performance in mind, running on the blazing fast Node.js engine. It is designed to intelligently make use of available resources, making it scalable whether it''s on a tiny Raspberry Pi or on a high performance VM in the cloud. Wiki.js also allows you to control the privacy of your wiki, making it public, completely private, or a mix of both. It offers a wide range of modules that can be turned on/off on demand, catering to the unique needs of different teams. These modules include authentication, editors, history, localization, media assets, rendering, search, storage, user management, and themes. Wiki.js is proudly licensed under AGPLv3 and has been downloaded over 50 million times.', 'wiki', ARRAY['Wiki', 'Documentation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/requarks/wiki:2.5.314"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Wiki.js", "version": "latest", "description": "Wiki.js is a powerful and extensible open source Wiki software designed to make documentation a joy to write. It features a beautiful and intuitive interface that can be fully customized to your liking, including a light and dark mode. The software is compatible with various platforms and databases, including PostgreSQL, MySQL, MariaDB, MS SQL Server, and SQLite. With Wiki.js, you can manage all aspects of your wiki using the extensive and intuitive admin area. The software is built with performance in mind, running on the blazing fast Node.js engine. It is designed to intelligently make use of available resources, making it scalable whether it's on a tiny Raspberry Pi or on a high performance VM in the cloud. Wiki.js also allows you to control the privacy of your wiki, making it public, completely private, or a mix of both. It offers a wide range of modules that can be turned on/off on demand, catering to the unique needs of different teams. These modules include authentication, editors, history, localization, media assets, rendering, search, storage, user management, and themes. Wiki.js is proudly licensed under AGPLv3 and has been downloaded over 50 million times.", "category": "wiki", "tags": ["Wiki", "Documentation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/requarks/wiki:2.5.314"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://js.wiki/"}, {"label": "Documentation", "url": "https://docs.requarks.io/"}, {"label": "Github", "url": "https://github.com/Requarks/wiki"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "wikijs", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}, "mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('windmill', 'Windmill', 'Windmill Cloud is a powerful tool that transforms scripts into workflows and user interfaces in just a few minutes. It is designed to help you create internal apps and robust workflows using code only where necessary. With Windmill Cloud, you can make your scripts production-grade and build all your internal tools using Python, Typescript, Go, Bash, Sql. You can compose your scripts as workflows using low-code and share an autogenerated UI or build one using low-code. The app is designed to run reliably at scale on your infrastructure or ours, with permissioning and monitoring included. It is a fully open-source alternative to Airplane, Superblocks & Retool, and it''s easy to deploy on both small and large infrastructures. With Windmill Cloud, you can run long-running heavy background jobs, script with complex dependencies, endpoints with high rpm or simple one-off tasks without any overhead. You can trigger them from a webhook or the auto-generated UI and monitor them easily. Additionally, Windmill Cloud allows you to build complex flows without complexity, from atomic scripts, either from your workspace or the Hub. You can also build super fast and powerful apps using drag and drop components, connect your data and deploy your app in minutes. Windmill Cloud is designed to be super performant, ensuring your app is always running smoothly, even when running complex apps.', 'developer-tools', ARRAY['Developer Tools'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/windmill-labs/windmill:1.696.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3001}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Windmill", "version": "latest", "description": "Windmill Cloud is a powerful tool that transforms scripts into workflows and user interfaces in just a few minutes. It is designed to help you create internal apps and robust workflows using code only where necessary. With Windmill Cloud, you can make your scripts production-grade and build all your internal tools using Python, Typescript, Go, Bash, Sql. You can compose your scripts as workflows using low-code and share an autogenerated UI or build one using low-code. The app is designed to run reliably at scale on your infrastructure or ours, with permissioning and monitoring included. It is a fully open-source alternative to Airplane, Superblocks & Retool, and it's easy to deploy on both small and large infrastructures. With Windmill Cloud, you can run long-running heavy background jobs, script with complex dependencies, endpoints with high rpm or simple one-off tasks without any overhead. You can trigger them from a webhook or the auto-generated UI and monitor them easily. Additionally, Windmill Cloud allows you to build complex flows without complexity, from atomic scripts, either from your workspace or the Hub. You can also build super fast and powerful apps using drag and drop components, connect your data and deploy your app in minutes. Windmill Cloud is designed to be super performant, ensuring your app is always running smoothly, even when running complex apps.", "category": "developer-tools", "tags": ["Developer Tools"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/windmill-labs/windmill:1.696.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3001}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://windmill.dev"}, {"label": "Documentation", "url": "https://docs.windmill.dev"}, {"label": "Github", "url": "https://github.com/windmill-labs/windmill"}], "instructions": "Login using admin@windmill.dev:changeme", "install": [{"docker": {"image": "$IMAGE", "name": "windmill", "port": "$PORT:3001", "volumes": ["/var/run/docker.sock", "/tmp/windmill/cache"], "extra_ports": ["8000:8000"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Login using admin@windmill.dev:changeme"}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('wishlist', 'Wishlist', 'Wishlist is a self-hosted gift registry and wishlist management application that simplifies gift-giving for families, friends, and special occasions. It provides a centralized platform where users can create and share wishlists, claim items to prevent duplicate gifts, and track purchase status. The application features automatic product data fetching from URLs, user-friendly interfaces accessible to all ages, and support for multiple groups to separate different circles like family, friends, or coworkers. Wishlist includes registry mode for wedding registries or single comprehensive lists, item claiming with privacy to prevent gift spoilers, purchase tracking for claimed items, gift suggestions from friends and family, and user invitation via email with SMTP integration. Built with a modern web interface and Progressive Web App support, Wishlist offers seamless access across devices with offline capabilities. The application uses SQLite for lightweight data storage and stores user-uploaded images locally, ensuring all data remains on your infrastructure. With OAuth authentication support and customizable token expiration, Wishlist provides secure access control while maintaining ease of use. Perfect for families coordinating holidays and birthdays, couples managing wedding registries, friend groups organizing gift exchanges, or anyone who wants a private alternative to public wishlist services with complete control over their data and privacy.', 'wishlist', ARRAY['Wishlist', 'Gift Registry', 'Family', 'Gift Management', 'Self-Hosted'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/cmintey/wishlist:v0.55.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3280}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Wishlist", "version": "latest", "description": "Wishlist is a self-hosted gift registry and wishlist management application that simplifies gift-giving for families, friends, and special occasions. It provides a centralized platform where users can create and share wishlists, claim items to prevent duplicate gifts, and track purchase status. The application features automatic product data fetching from URLs, user-friendly interfaces accessible to all ages, and support for multiple groups to separate different circles like family, friends, or coworkers. Wishlist includes registry mode for wedding registries or single comprehensive lists, item claiming with privacy to prevent gift spoilers, purchase tracking for claimed items, gift suggestions from friends and family, and user invitation via email with SMTP integration. Built with a modern web interface and Progressive Web App support, Wishlist offers seamless access across devices with offline capabilities. The application uses SQLite for lightweight data storage and stores user-uploaded images locally, ensuring all data remains on your infrastructure. With OAuth authentication support and customizable token expiration, Wishlist provides secure access control while maintaining ease of use. Perfect for families coordinating holidays and birthdays, couples managing wedding registries, friend groups organizing gift exchanges, or anyone who wants a private alternative to public wishlist services with complete control over their data and privacy.", "category": "wishlist", "tags": ["Wishlist", "Gift Registry", "Family", "Gift Management", "Self-Hosted"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/cmintey/wishlist:v0.55.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3280}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/cmintey/wishlist"}, {"label": "Docker Hub", "url": "https://github.com/cmintey/wishlist/pkgs/container/wishlist"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "wishlist", "port": "$PORT:3280", "volumes": ["/usr/src/app/uploads", "/usr/src/app/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('wizarr', 'Wizarr', 'Wizarr is an automatic user invitation system designed to streamline the process of inviting users to your media server. Whether you''re using Plex, Jellyfin, or Emby, Wizarr allows you to create a unique link to share with users, automatically inviting them to your server. The app also guides users on how to download the necessary client and provides instructions on how to use your request software. Wizarr offers a secure invitation environment, plug and play SSO support, multi-tiered invitations, and customizable duration for membership. It also integrates with Discord, allowing you to invite users to your Discord server. The app is customizable, allowing you to add any custom HTML as needed.', 'media', ARRAY['Media', 'Documentation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/wizarrrr/wizarr:v2026.2.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5690}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Wizarr", "version": "latest", "description": "Wizarr is an automatic user invitation system designed to streamline the process of inviting users to your media server. Whether you're using Plex, Jellyfin, or Emby, Wizarr allows you to create a unique link to share with users, automatically inviting them to your server. The app also guides users on how to download the necessary client and provides instructions on how to use your request software. Wizarr offers a secure invitation environment, plug and play SSO support, multi-tiered invitations, and customizable duration for membership. It also integrates with Discord, allowing you to invite users to your Discord server. The app is customizable, allowing you to add any custom HTML as needed.", "category": "media", "tags": ["Media", "Documentation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/wizarrrr/wizarr:v2026.2.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5690}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://docs.wizarr.dev"}, {"label": "Github", "url": "https://github.com/Wizarrrr/wizarr"}], "instructions": "The timezone format should be Continent/City", "install": [{"docker": {"image": "$IMAGE", "name": "wizarr", "port": "$PORT:5690", "volumes": ["/data/database"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "The timezone format should be Continent/City"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('woodpeckerci', 'WoodPecker CI', 'WoodPecker CI is a modern, open-source continuous integration (CI) and delivery tool designed for developers who value simplicity, flexibility, and scalability. It integrates seamlessly with GitHub, allowing teams to automate testing, build, and deployment workflows efficiently. WoodPecker CI is lightweight, easy to deploy, and supports a wide range of programming languages and platforms. With its agent-based architecture, it provides high customizability and performance, making it ideal for both small projects and large-scale software development pipelines.', 'ci/cd', ARRAY['CI/CD', 'Open-Source', 'DevOps'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "woodpeckerci/woodpecker-server:v3.13.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "WoodPecker CI", "version": "latest", "description": "WoodPecker CI is a modern, open-source continuous integration (CI) and delivery tool designed for developers who value simplicity, flexibility, and scalability. It integrates seamlessly with GitHub, allowing teams to automate testing, build, and deployment workflows efficiently. WoodPecker CI is lightweight, easy to deploy, and supports a wide range of programming languages and platforms. With its agent-based architecture, it provides high customizability and performance, making it ideal for both small projects and large-scale software development pipelines.", "category": "ci/cd", "tags": ["CI/CD", "Open-Source", "DevOps"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "woodpeckerci/woodpecker-server:v3.13.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/woodpecker-ci/woodpecker"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "woodpeckerci", "port": "$PORT:8000", "volumes": ["/var/lib/woodpecker/", "/etc/woodpecker", "/var/run/docker.sock"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('word-mastermind', 'Word Mastermind', 'Word Mastermind is a word-guessing game inspired by the classic Mastermind puzzle and games like Wordle. Players attempt to guess a hidden word within a limited number of attempts, receiving feedback after each guess to help narrow down the solution. This containerized version provides a clean web interface that allows you to host your own instance of the game for personal use, educational purposes, or family entertainment.', 'gaming', ARRAY['Gaming', 'Word Games', 'Educational', 'Browser Game', 'Puzzle'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/clupasq/word-mastermind:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Word Mastermind", "version": "latest", "description": "Word Mastermind is a word-guessing game inspired by the classic Mastermind puzzle and games like Wordle. Players attempt to guess a hidden word within a limited number of attempts, receiving feedback after each guess to help narrow down the solution. This containerized version provides a clean web interface that allows you to host your own instance of the game for personal use, educational purposes, or family entertainment.", "category": "gaming", "tags": ["Gaming", "Word Games", "Educational", "Browser Game", "Puzzle"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/clupasq/word-mastermind:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/clupasq/word-mastermind"}, {"label": "Container", "url": "https://github.com/clupasq/word-mastermind/pkgs/container/word-mastermind"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "word-mastermind", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('wordpress', 'Wordpress', 'WordPress is an open-source platform that empowers you to create a unique online space for your business, interests, or any other purpose. It offers a real-time, intuitive editing experience, allowing you to see exactly how your site will look as you add, edit, and rearrange your content. With flexible design tools and powerful features, you can create any kind of custom site. You can start with a blank canvas or choose from a wide variety of themes and patterns, customizing every detail from color and fonts to layouts and functionality. WordPress also offers over 55,000 plugins to extend your site''s capabilities, whether you need to add a store, mailing list, portfolio, social feed, analytics, or anything else. Your content, design, and data always belong to you, and WordPress is committed to keeping your site as stable and secure as possible. Whether you''re a global creative agency, a local business, or a personal blogger, WordPress offers endless possibilities for your online presence.', 'cms', ARRAY['CMS', 'Website Builder', 'Blogging'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "wordpress:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Wordpress", "version": "latest", "description": "WordPress is an open-source platform that empowers you to create a unique online space for your business, interests, or any other purpose. It offers a real-time, intuitive editing experience, allowing you to see exactly how your site will look as you add, edit, and rearrange your content. With flexible design tools and powerful features, you can create any kind of custom site. You can start with a blank canvas or choose from a wide variety of themes and patterns, customizing every detail from color and fonts to layouts and functionality. WordPress also offers over 55,000 plugins to extend your site's capabilities, whether you need to add a store, mailing list, portfolio, social feed, analytics, or anything else. Your content, design, and data always belong to you, and WordPress is committed to keeping your site as stable and secure as possible. Whether you're a global creative agency, a local business, or a personal blogger, WordPress offers endless possibilities for your online presence.", "category": "cms", "tags": ["CMS", "Website Builder", "Blogging"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "wordpress:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://wordpress.org/"}, {"label": "Documentation", "url": "https://learn.wordpress.org"}, {"label": "Github", "url": "https://github.com/WordPress/WordPress"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "wordpress", "port": "$PORT:80", "volumes": ["/var/www/html", "/usr/local/etc/php/conf.d/custom.ini"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('wps-office', 'WPS Office', 'WPS Office is a comprehensive office suite that is lightweight yet feature-rich. It offers high compatibility and a range of professional office software tools. With WPS Office, you can edit files in Writer, Presentation, Spreadsheet, and PDF, enhancing your work efficiency. The application can be accessed at your host on ports 3000 and 3001. This container is based on Docker Baseimage KasmVNC, which provides additional environment variables and run configurations to enable or disable specific functionality. The application also supports the docker manifest for multi-platform awareness, ensuring the correct image for your architecture is retrieved.', 'productivity', ARRAY['Productivity', 'Documents', 'Office Suite'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/wps-office:11.1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "WPS Office", "version": "latest", "description": "WPS Office is a comprehensive office suite that is lightweight yet feature-rich. It offers high compatibility and a range of professional office software tools. With WPS Office, you can edit files in Writer, Presentation, Spreadsheet, and PDF, enhancing your work efficiency. The application can be accessed at your host on ports 3000 and 3001. This container is based on Docker Baseimage KasmVNC, which provides additional environment variables and run configurations to enable or disable specific functionality. The application also supports the docker manifest for multi-platform awareness, ensuring the correct image for your architecture is retrieved.", "category": "productivity", "tags": ["Productivity", "Documents", "Office Suite"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/wps-office:11.1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://docs.linuxserver.io/images/docker-wps-office"}, {"label": "Github", "url": "https://github.com/linuxserver/docker-wps-office"}], "instructions": "use abc:abc to login. To access the login interface, add ?login=true to your URL.", "install": [{"docker": {"image": "$IMAGE", "name": "wps-office", "port": "$PORT:3000", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "use abc:abc to login. To access the login interface, add ?login=true to your URL."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('xbackbone', 'xBackbone', 'xBackbone is a versatile, self-hosted file and image sharing platform designed to manage and share content securely and efficiently. It features a clean and intuitive interface, supports multiple authentication options, and provides advanced file management capabilities. With xBackbone, you can maintain complete control over your shared content, ensuring privacy and flexibility.', 'file-sharing', ARRAY['File Sharing', 'Self-Hosted', 'Privacy', 'Analytics'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/xbackbone:3.8.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "xBackbone", "version": "latest", "description": "xBackbone is a versatile, self-hosted file and image sharing platform designed to manage and share content securely and efficiently. It features a clean and intuitive interface, supports multiple authentication options, and provides advanced file management capabilities. With xBackbone, you can maintain complete control over your shared content, ensuring privacy and flexibility.", "category": "file-sharing", "tags": ["File Sharing", "Self-Hosted", "Privacy", "Analytics"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "linuxserver/xbackbone:3.8.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://xbackbone.app/"}, {"label": "Github", "url": "https://github.com/SergiX44/XBackBone"}], "instructions": "Configure the Base URL and set up the database connection during installation.", "install": [{"docker": {"image": "$IMAGE", "name": "xbackbone", "port": "$PORT:80", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Configure the Base URL and set up the database connection during installation."}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('xwiki', 'Xwiki', 'XWiki is a powerful, open source enterprise wiki platform designed for collaboration and content management. It offers extensive features to create, manage, and share knowledge effectively.', 'wiki', ARRAY['Wiki', 'Collaboration', 'Documentation', 'Open Source'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "xwiki:18.2.1-postgres-tomcat"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Xwiki", "version": "latest", "description": "XWiki is a powerful, open source enterprise wiki platform designed for collaboration and content management. It offers extensive features to create, manage, and share knowledge effectively.", "category": "wiki", "tags": ["Wiki", "Collaboration", "Documentation", "Open Source"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "xwiki:18.2.1-postgres-tomcat"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/xwiki/xwiki-platform"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "xwiki", "port": "$PORT:8080", "volumes": ["/usr/local/xwiki", "/var/lib/postgresql/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('yacht', 'yacht', 'Yacht is a self-hosted web-based container management tool designed to provide a user-friendly and intuitive interface for managing Docker containers. It simplifies container deployment, monitoring, and management, making it accessible for both beginners and advanced users. Yacht supports multiple container engines and integrates with Docker Compose, allowing users to easily create, update, and manage their containerized applications.', 'docker', ARRAY['Docker', 'Container Management', 'DevOps', 'Self-Hosting'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "selfhostedpro/yacht:v0.0.7-alpha-2023-01-12--05"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "yacht", "version": "latest", "description": "Yacht is a self-hosted web-based container management tool designed to provide a user-friendly and intuitive interface for managing Docker containers. It simplifies container deployment, monitoring, and management, making it accessible for both beginners and advanced users. Yacht supports multiple container engines and integrates with Docker Compose, allowing users to easily create, update, and manage their containerized applications.", "category": "docker", "tags": ["Docker", "Container Management", "DevOps", "Self-Hosting"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "selfhostedpro/yacht:v0.0.7-alpha-2023-01-12--05"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://yacht.sh/"}, {"label": "Github", "url": "https://github.com/SelfhostedPro/Yacht"}], "instructions": "Login using credentials admin@yacht.local/pass", "install": [{"docker": {"image": "$IMAGE", "name": "yacht", "port": "$PORT:8000", "volumes": ["/config", "/var/run/docker.sock"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Login using credentials admin@yacht.local/pass"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('yacy', 'YaCy', 'YaCy is a free distributed search engine built on principles of peer-to-peer networks. Unlike traditional search engines that rely on centralized servers, YaCy operates in a decentralized manner where each user can contribute to the search index. It allows you to run your own search portal, create your own web index, and be independent from commercial search engine providers. YaCy is perfect for organizations that need private search capabilities, intranet search solutions, or those who value privacy and freedom in their search experience.', 'search-engine', ARRAY['Search Engine', 'Decentralized', 'P2P', 'Privacy', 'Indexing', 'Web Crawler'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "yacy/yacy_search_server:sha-f4509ae25923cf99f1b88467d17fc221d5b8d94f-alpine"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8090}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "YaCy", "version": "latest", "description": "YaCy is a free distributed search engine built on principles of peer-to-peer networks. Unlike traditional search engines that rely on centralized servers, YaCy operates in a decentralized manner where each user can contribute to the search index. It allows you to run your own search portal, create your own web index, and be independent from commercial search engine providers. YaCy is perfect for organizations that need private search capabilities, intranet search solutions, or those who value privacy and freedom in their search experience.", "category": "search-engine", "tags": ["Search Engine", "Decentralized", "P2P", "Privacy", "Indexing", "Web Crawler"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "yacy/yacy_search_server:sha-f4509ae25923cf99f1b88467d17fc221d5b8d94f-alpine"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8090}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/yacy/yacy_search_server"}, {"label": "Website", "url": "https://yacy.net/"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/yacy/yacy_search_server"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "yacy", "port": "$PORT:8090", "volumes": ["/opt/yacy_search_server/DATA"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('yakgpt', 'YakGPT', 'YakGPT is a simple, locally running ChatGPT UI that makes your text generation faster and chatting even more engaging! This hands-free interface provides direct access to OpenAI''s GPT models with advanced voice capabilities, including Speech-to-Text via Azure & OpenAI Whisper and Text-to-Speech via Azure & Eleven Labs. Run locally in your browser with no need to install applications, featuring faster performance than the official ChatGPT UI by connecting directly to the API. Perfect for users who want privacy, speed, and voice interaction with their AI assistant.', 'ai-chat', ARRAY['AI Chat', 'ChatGPT', 'OpenAI', 'Voice Interface', 'Speech-to-Text', 'Text-to-Speech', 'GPT-4', 'GPT-3.5', 'Hands-Free', 'Privacy-Focused', 'Local Storage', 'Next.js'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "yakgpt/yakgpt:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "YakGPT", "version": "latest", "description": "YakGPT is a simple, locally running ChatGPT UI that makes your text generation faster and chatting even more engaging! This hands-free interface provides direct access to OpenAI's GPT models with advanced voice capabilities, including Speech-to-Text via Azure & OpenAI Whisper and Text-to-Speech via Azure & Eleven Labs. Run locally in your browser with no need to install applications, featuring faster performance than the official ChatGPT UI by connecting directly to the API. Perfect for users who want privacy, speed, and voice interaction with their AI assistant.", "category": "ai-chat", "tags": ["AI Chat", "ChatGPT", "OpenAI", "Voice Interface", "Speech-to-Text", "Text-to-Speech", "GPT-4", "GPT-3.5", "Hands-Free", "Privacy-Focused", "Local Storage", "Next.js"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "yakgpt/yakgpt:latest"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub Repository", "url": "https://github.com/yakGPT/yakGPT"}, {"label": "Live Demo", "url": "https://yakgpt.vercel.app"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "yakgpt", "port": "$PORT:3000", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('yamtrack', 'Yamtrack', 'Yamtrack is a self-hosted media tracking application designed to help you keep track of your movies, TV shows, books, video games, and other media consumption. It provides a clean, modern interface for logging what you''re watching, reading, or playing, along with ratings, reviews, and personal notes. Yamtrack features automatic metadata fetching from popular databases, progress tracking, viewing statistics, and customizable lists. The application supports multiple media types and offers detailed analytics about your consumption habits. Built with a focus on privacy and simplicity, Yamtrack keeps all your tracking data under your control. Perfect for media enthusiasts who want to maintain a comprehensive log of their entertainment without relying on third-party services.', 'media-tracker', ARRAY['Media Tracker', 'Movies', 'TV Shows', 'Books', 'Gaming', 'Analytics'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/fuzzygrim/yamtrack:0.25.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Yamtrack", "version": "latest", "description": "Yamtrack is a self-hosted media tracking application designed to help you keep track of your movies, TV shows, books, video games, and other media consumption. It provides a clean, modern interface for logging what you're watching, reading, or playing, along with ratings, reviews, and personal notes. Yamtrack features automatic metadata fetching from popular databases, progress tracking, viewing statistics, and customizable lists. The application supports multiple media types and offers detailed analytics about your consumption habits. Built with a focus on privacy and simplicity, Yamtrack keeps all your tracking data under your control. Perfect for media enthusiasts who want to maintain a comprehensive log of their entertainment without relying on third-party services.", "category": "media-tracker", "tags": ["Media Tracker", "Movies", "TV Shows", "Books", "Gaming", "Analytics"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/fuzzygrim/yamtrack:0.25.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Github", "url": "https://github.com/FuzzyGrim/Yamtrack"}, {"label": "Documentation", "url": "https://github.com/FuzzyGrim/Yamtrack/wiki"}], "instructions": "Default credentials are admin/admin123.", "install": [{"docker": {"image": "$IMAGE", "name": "yamtrack", "port": "$PORT:8000", "volumes": ["/yamtrack/db"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Default credentials are admin/admin123."}, "services": {"redis": {"type": "redis", "version": "7"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('yao', 'YAO', 'YAO is a powerful open-source app engine designed to create web services and applications in a matter of minutes. It is versatile and suitable for a variety of use-cases including AI, IoT, Industrial Internet, Connected Vehicles, DevOps, Energy, and Finance. With YAO, you can create a database model, write an interface, and describe the interface using JSON, making it a truly codeless programming experience. It supports running on ARM devices and can be used in IoT, edge computing, and industrial internet. YAO also offers easy-to-use Business Intelligence components and functions, empowering businesses with more possibilities. It has many built-in processes and supports data processing in any form through data flow. The app also features a plug-in mechanism based on GRPC for function expansion using Nodejs, Python, and other languages. YAO also provides a built-in query engine and offers enterprise-level security with permission classification, separation of administrator and employee accounts, and API level permission control.', 'no-code', ARRAY['No-Code', 'Developer Tools', 'Business Apps', 'IoT', 'Data Science', 'ERP', 'CRM'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "yaoapp/yao:0.10.4-rc.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5099}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "YAO", "version": "latest", "description": "YAO is a powerful open-source app engine designed to create web services and applications in a matter of minutes. It is versatile and suitable for a variety of use-cases including AI, IoT, Industrial Internet, Connected Vehicles, DevOps, Energy, and Finance. With YAO, you can create a database model, write an interface, and describe the interface using JSON, making it a truly codeless programming experience. It supports running on ARM devices and can be used in IoT, edge computing, and industrial internet. YAO also offers easy-to-use Business Intelligence components and functions, empowering businesses with more possibilities. It has many built-in processes and supports data processing in any form through data flow. The app also features a plug-in mechanism based on GRPC for function expansion using Nodejs, Python, and other languages. YAO also provides a built-in query engine and offers enterprise-level security with permission classification, separation of administrator and employee accounts, and API level permission control.", "category": "no-code", "tags": ["No-Code", "Developer Tools", "Business Apps", "IoT", "Data Science", "ERP", "CRM"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "yaoapp/yao:0.10.4-rc.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5099}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://yaoapps.com/"}, {"label": "Documentation", "url": "https://yaoapps.com/en-US/doc/"}, {"label": "Github", "url": "https://github.com/YaoApp/yao"}], "instructions": "Use xiang@iqka.com:A123456p+ to login at /xiang/login/admin . Use amd64 instead of arm64 if you use a non ARM based system.", "install": [{"docker": {"image": "$IMAGE", "name": "yao", "port": "$PORT:5099", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Use xiang@iqka.com:A123456p+ to login at /xiang/login/admin . Use amd64 instead of arm64 if you use a non ARM based system."}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('yourls', 'YOURLS', 'YOURLS (Your Own URL Shortener) is a powerful, self-hosted service designed for creating and managing short URLs. It provides a clean and simple interface, supports plugins for extended functionality, and offers detailed link tracking analytics. With YOURLS, you can maintain control over your short links and branding. The application is accessible via your host on ports 8080 and 8081. This container is based on Docker Baseimage KasmVNC, providing additional environment variables and configurations for enhanced flexibility. It also supports the docker manifest for multi-platform awareness, ensuring the correct image for your architecture.', 'url-shortener', ARRAY['URL Shortener', 'Self-Hosted', 'Analytics'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'mysql'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "yourls:1.10.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "YOURLS", "version": "latest", "description": "YOURLS (Your Own URL Shortener) is a powerful, self-hosted service designed for creating and managing short URLs. It provides a clean and simple interface, supports plugins for extended functionality, and offers detailed link tracking analytics. With YOURLS, you can maintain control over your short links and branding. The application is accessible via your host on ports 8080 and 8081. This container is based on Docker Baseimage KasmVNC, providing additional environment variables and configurations for enhanced flexibility. It also supports the docker manifest for multi-platform awareness, ensuring the correct image for your architecture.", "category": "url-shortener", "tags": ["URL Shortener", "Self-Hosted", "Analytics"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "mysql"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "yourls:1.10.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 80}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://yourls.org/#Guide"}, {"label": "Github", "url": "https://github.com/YOURLS/YOURLS"}], "instructions": "Use admin:admin123 to login.", "install": [{"docker": {"image": "$IMAGE", "name": "yourls", "port": "$PORT:80", "volumes": [], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Use admin:admin123 to login."}, "services": {"mysql": {"type": "mysql", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('zabbix', 'Zabbix', 'Zabbix is a powerful, self-hosted monitoring solution designed for tracking and analyzing system performance, network utilization, and application health. It provides real-time monitoring, customizable alerts, and detailed visualization tools to help administrators maintain system reliability. Zabbix supports agent-based and agentless monitoring, automation capabilities, and integration with third-party tools. With its flexible architecture, Zabbix is suitable for small to enterprise-level environments. The application includes a web-based dashboard and supports a variety of database backends, making it a robust solution for IT infrastructure monitoring.', 'monitoring', ARRAY['Monitoring', 'Network Management', 'IT Infrastructure'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "zabbix/zabbix-web-nginx-pgsql:alpine-trunk"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Zabbix", "version": "latest", "description": "Zabbix is a powerful, self-hosted monitoring solution designed for tracking and analyzing system performance, network utilization, and application health. It provides real-time monitoring, customizable alerts, and detailed visualization tools to help administrators maintain system reliability. Zabbix supports agent-based and agentless monitoring, automation capabilities, and integration with third-party tools. With its flexible architecture, Zabbix is suitable for small to enterprise-level environments. The application includes a web-based dashboard and supports a variety of database backends, making it a robust solution for IT infrastructure monitoring.", "category": "monitoring", "tags": ["Monitoring", "Network Management", "IT Infrastructure"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "zabbix/zabbix-web-nginx-pgsql:alpine-trunk"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://www.zabbix.com/documentation"}, {"label": "Github", "url": "https://github.com/zabbix/zabbix-docker"}], "instructions": "Use the default credentials (Admin/zabbix) to log in.", "install": [{"docker": {"image": "$IMAGE", "name": "zabbix", "port": "$PORT:8080", "volumes": ["/var/lib/zabbix", "/var/lib/zabbix/snmptraps", "/var/lib/zabbix/export", "/usr/share/zabbix"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Use the default credentials (Admin/zabbix) to log in."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('zep', 'Zep', 'Zep is a powerful, self-hosted AI platform designed for seamless integration with large language models. It provides a clean and intuitive interface, supports plugins for extended functionality, and offers detailed analytics to monitor and optimize your AI workflows. With Zep, you maintain full control over your deployments and configurations. The application is accessible via your host on designated ports, ensuring secure and scalable operations. This container is based on Docker Baseimage KasmVNC, providing additional environment variables and configurations for enhanced flexibility. It also supports the docker manifest for multi-platform awareness, ensuring the correct image for your architecture.', 'ai', ARRAY['AI', 'Self-Hosted', 'API', 'Automation'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "zepai/zep:1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5432}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Zep", "version": "latest", "description": "Zep is a powerful, self-hosted AI platform designed for seamless integration with large language models. It provides a clean and intuitive interface, supports plugins for extended functionality, and offers detailed analytics to monitor and optimize your AI workflows. With Zep, you maintain full control over your deployments and configurations. The application is accessible via your host on designated ports, ensuring secure and scalable operations. This container is based on Docker Baseimage KasmVNC, providing additional environment variables and configurations for enhanced flexibility. It also supports the docker manifest for multi-platform awareness, ensuring the correct image for your architecture.", "category": "ai", "tags": ["AI", "Self-Hosted", "API", "Automation"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "zepai/zep:1.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 5432}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://www.getzep.com/"}, {"label": "Github", "url": "https://github.com/getzep/zep"}], "instructions": "Zep Community Edition can be used with any LLM provider that implements the OpenAI API.", "install": [{"docker": {"image": "$IMAGE", "name": "zep", "port": "$PORT:5432", "volumes": ["/app/zep.yaml"], "extra_ports": ["8000:8000"]}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Zep Community Edition can be used with any LLM provider that implements the OpenAI API."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('zerobyte', 'Zerobyte', 'Zerobyte is a self-hosted backup and restore management solution that provides a unified web interface for managing your backup repositories across multiple storage backends. It supports various cloud storage providers including S3-compatible storage, Google Cloud Storage, Azure Blob Storage, and local directories through rclone integration. With its intuitive web interface, you can configure backup sources, manage multiple repositories, schedule backups, and perform restores with ease. The application leverages FUSE filesystem capabilities to mount and interact with cloud storage as if it were local storage, enabling seamless backup and restore operations. Zerobyte features automatic backup scheduling, support for multiple storage backends, encrypted backup repositories, incremental backups for efficient storage usage, and comprehensive restore capabilities. The web-based dashboard allows you to monitor backup status, view repository statistics, and manage your backup configurations without command-line tools. Perfect for home lab enthusiasts who need reliable backup solutions, system administrators managing multiple backup repositories, organizations requiring self-hosted backup infrastructure, or anyone who wants to maintain control over their backup data with support for various cloud providers and local storage options.', 'backup', ARRAY['Backup', 'Storage', 'Cloud Storage', 'Data Management', 'Self-Hosted', 'Disaster Recovery'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/nicotsx/zerobyte:v0.36.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4096}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Zerobyte", "version": "latest", "description": "Zerobyte is a self-hosted backup and restore management solution that provides a unified web interface for managing your backup repositories across multiple storage backends. It supports various cloud storage providers including S3-compatible storage, Google Cloud Storage, Azure Blob Storage, and local directories through rclone integration. With its intuitive web interface, you can configure backup sources, manage multiple repositories, schedule backups, and perform restores with ease. The application leverages FUSE filesystem capabilities to mount and interact with cloud storage as if it were local storage, enabling seamless backup and restore operations. Zerobyte features automatic backup scheduling, support for multiple storage backends, encrypted backup repositories, incremental backups for efficient storage usage, and comprehensive restore capabilities. The web-based dashboard allows you to monitor backup status, view repository statistics, and manage your backup configurations without command-line tools. Perfect for home lab enthusiasts who need reliable backup solutions, system administrators managing multiple backup repositories, organizations requiring self-hosted backup infrastructure, or anyone who wants to maintain control over their backup data with support for various cloud providers and local storage options.", "category": "backup", "tags": ["Backup", "Storage", "Cloud Storage", "Data Management", "Self-Hosted", "Disaster Recovery"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/nicotsx/zerobyte:v0.36.0"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4096}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "GitHub", "url": "https://github.com/nicotsx/zerobyte"}], "instructions": "Zerobyte requires access to the /dev/fuse device for FUSE filesystem operations. After deploying this template, you may need to manually configure device access on your host system.", "install": [{"docker": {"image": "$IMAGE", "name": "zerobyte", "port": "$PORT:4096", "volumes": ["/var/lib/zerobyte"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Zerobyte requires access to the /dev/fuse device for FUSE filesystem operations. After deploying this template, you may need to manually configure device access on your host system."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('ziit', 'Ziit', 'Ziit (pronounced ''tseet'') is an open-source, self-hostable alternative to WakaTime. It provides a clean, minimal, and fast dashboard for displaying coding statistics, while ensuring privacy by keeping all data on your own server. Ziit tracks coding activity such as projects, languages, editors, files, branches, operating systems, and time spent coding, all presented in a familiar interface inspired by Plausible Analytics.', 'time-tracking', ARRAY['Time Tracking', 'Developer Tools', 'Coding Statistics', 'Self-Hosted', 'WakaTime Alternative', 'Productivity'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/0pandadev/ziit:v1.0.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Ziit", "version": "latest", "description": "Ziit (pronounced 'tseet') is an open-source, self-hostable alternative to WakaTime. It provides a clean, minimal, and fast dashboard for displaying coding statistics, while ensuring privacy by keeping all data on your own server. Ziit tracks coding activity such as projects, languages, editors, files, branches, operating systems, and time spent coding, all presented in a familiar interface inspired by Plausible Analytics.", "category": "time-tracking", "tags": ["Time Tracking", "Developer Tools", "Coding Statistics", "Self-Hosted", "WakaTime Alternative", "Productivity"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/0pandadev/ziit:v1.0.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Web App", "url": "https://ziit.app/login"}, {"label": "Documentation", "url": "https://docs.ziit.app"}, {"label": "Github", "url": "https://github.com/0pandadev/ziit"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "ziit", "port": "$PORT:3000", "volumes": ["/app/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('zincsearch', 'ZincSearch', 'ZincSearch is a lightweight, fast, and modern search engine built in Go. It provides full-text search capabilities with a simple REST API, making it an excellent alternative to Elasticsearch for smaller to medium-scale applications. ZincSearch offers easy deployment, low resource consumption, and compatibility with Elasticsearch APIs.', 'search-engine', ARRAY['Search Engine', 'Full-Text Search', 'API', 'Elasticsearch Alternative'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "public.ecr.aws/zinclabs/zincsearch:0.4.10"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "ZincSearch", "version": "latest", "description": "ZincSearch is a lightweight, fast, and modern search engine built in Go. It provides full-text search capabilities with a simple REST API, making it an excellent alternative to Elasticsearch for smaller to medium-scale applications. ZincSearch offers easy deployment, low resource consumption, and compatibility with Elasticsearch APIs.", "category": "search-engine", "tags": ["Search Engine", "Full-Text Search", "API", "Elasticsearch Alternative"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "public.ecr.aws/zinclabs/zincsearch:0.4.10"}, "port": {"type": "integer", "title": "Port HTTP", "default": 4080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://zincsearch-docs.zinc.dev/"}, {"label": "Github", "url": "https://github.com/zincsearch/zincsearch"}], "instructions": "Provide the admin password, or leave it blank to generate a random one.", "install": [{"docker": {"image": "$IMAGE", "name": "zincsearch", "port": "$PORT:4080", "volumes": ["/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "Provide the admin password, or leave it blank to generate a random one."}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('zipline', 'Zipline', 'Zipline is the next generation ShareX/File upload server, designed to make file sharing and management a breeze. With a user-friendly dashboard packed with features, Zipline allows you to upload any file type, view your files in a gallery, and even shorten URLs for easy sharing. The app also provides a way to organize your files with folders for easy access and management. Zipline also offers features like image compression, video thumbnail generation, and password protection for your uploads. With Zipline, you can quickly set up your own instance and configure it to your needs. It also offers an extensive API for a more fine-grained control over your instance. Zipline is not just a file upload server, it''s a comprehensive tool for managing and sharing your files with ease and efficiency.', 'file-management', ARRAY['File Management', 'Dashboard', 'URL Shortening', 'Image Compression', 'API'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker', 'postgres'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/diced/zipline:4.5.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Zipline", "version": "latest", "description": "Zipline is the next generation ShareX/File upload server, designed to make file sharing and management a breeze. With a user-friendly dashboard packed with features, Zipline allows you to upload any file type, view your files in a gallery, and even shorten URLs for easy sharing. The app also provides a way to organize your files with folders for easy access and management. Zipline also offers features like image compression, video thumbnail generation, and password protection for your uploads. With Zipline, you can quickly set up your own instance and configure it to your needs. It also offers an extensive API for a more fine-grained control over your instance. Zipline is not just a file upload server, it's a comprehensive tool for managing and sharing your files with ease and efficiency.", "category": "file-management", "tags": ["File Management", "Dashboard", "URL Shortening", "Image Compression", "API"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker", "postgres"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "ghcr.io/diced/zipline:4.5.3"}, "port": {"type": "integer", "title": "Port HTTP", "default": 3000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://zipline.diced.tech/"}, {"label": "Github", "url": "https://github.com/diced/zipline"}, {"label": "Documentation", "url": "https://zipline.diced.tech/docs/get-started"}], "instructions": "After installing Zipline for the first time, you may login to the dashboard with the username \"administrator\" and the password \"password\".", "install": [{"docker": {"image": "$IMAGE", "name": "zipline", "port": "$PORT:3000", "volumes": ["/zipline/uploads", "/zipline/public"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "After installing Zipline for the first time, you may login to the dashboard with the username \"administrator\" and the password \"password\"."}, "services": {"postgres": {"type": "postgres", "version": "latest"}}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('znc', 'ZNC', 'ZNC is an IRC bouncer that is designed to stay connected to IRC servers and channels, allowing you to access them at any time.', 'chat', ARRAY['Chat'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/znc:1.10.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 6501}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "ZNC", "version": "latest", "description": "ZNC is an IRC bouncer that is designed to stay connected to IRC servers and channels, allowing you to access them at any time.", "category": "chat", "tags": ["Chat"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "lscr.io/linuxserver/znc:1.10.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 6501}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://github.com/linuxserver"}, {"label": "Documentation", "url": "https://hub.docker.com/r/linuxserver/znc"}, {"label": "Github", "url": "https://github.com/linuxserver/docker-znc/"}], "instructions": "default login is admin/admin", "install": [{"docker": {"image": "$IMAGE", "name": "znc", "port": "$PORT:6501", "volumes": ["/config"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": "default login is admin/admin"}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('zoraxy', 'Zoraxy', 'Zoraxy is a general-purpose reverse proxy and web application gateway designed for self-hosting enthusiasts. It offers an intuitive web interface for managing multiple web services with features like automatic SSL certificate management via ACME/Let''s Encrypt, virtual directory hosting, HTTP to HTTPS redirection, and built-in authentication. Zoraxy supports WebSocket proxying, custom error pages, rate limiting, geographic access control with GeoIP, and Docker integration for seamless container management. Perfect for hosting multiple services on a single server with professional-grade routing, security, and access control.', 'reverse-proxy', ARRAY['Reverse Proxy', 'Gateway', 'SSL', 'Load Balancer', 'Docker', 'Security'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "zoraxydocker/zoraxy:v3.3.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Zoraxy", "version": "latest", "description": "Zoraxy is a general-purpose reverse proxy and web application gateway designed for self-hosting enthusiasts. It offers an intuitive web interface for managing multiple web services with features like automatic SSL certificate management via ACME/Let's Encrypt, virtual directory hosting, HTTP to HTTPS redirection, and built-in authentication. Zoraxy supports WebSocket proxying, custom error pages, rate limiting, geographic access control with GeoIP, and Docker integration for seamless container management. Perfect for hosting multiple services on a single server with professional-grade routing, security, and access control.", "category": "reverse-proxy", "tags": ["Reverse Proxy", "Gateway", "SSL", "Load Balancer", "Docker", "Security"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "zoraxydocker/zoraxy:v3.3.2"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8000}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Documentation", "url": "https://zoraxy.arozos.com/"}, {"label": "Github", "url": "https://github.com/tobychui/zoraxy"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/zoraxydocker/zoraxy"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "zoraxy", "port": "$PORT:8000", "volumes": ["/opt/zoraxy/config/", "/opt/zoraxy/plugin/", "/var/run/docker.sock", "/etc/localtime"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO recipes VALUES ('zusam', 'Zusam', 'Zusam is a free and open-source way to self-host private forums for friends and family. It''s a simple, modern, and privacy-focused platform for group discussions.', 'forum', ARRAY['Forum', 'Discussion', 'Self-hosted', 'Open Source', 'Privacy'], 'latest', NULL, ARRAY['ubuntu-22.04', 'ubuntu-24.04', 'debian-12'], ARRAY['docker'], $JSON${"image": {"type": "string", "title": "Image Docker", "default": "zusam/zusam:0.6.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}$JSON$::jsonb, $JSON${"metadata": {"name": "Zusam", "version": "latest", "description": "Zusam is a free and open-source way to self-host private forums for friends and family. It's a simple, modern, and privacy-focused platform for group discussions.", "category": "forum", "tags": ["Forum", "Discussion", "Self-hosted", "Open Source", "Privacy"], "os_support": ["ubuntu-22.04", "ubuntu-24.04", "debian-12"], "dependencies": ["docker"]}, "params": {"image": {"type": "string", "title": "Image Docker", "default": "zusam/zusam:0.6.1"}, "port": {"type": "integer", "title": "Port HTTP", "default": 8080}, "version": {"type": "string", "title": "Version", "default": "latest"}}, "links": [{"label": "Website", "url": "https://zusam.org"}, {"label": "Documentation", "url": "https://docs.zusam.org"}, {"label": "GitHub", "url": "https://github.com/zusam/zusam"}, {"label": "Docker Hub", "url": "https://hub.docker.com/r/zusam/zusam"}], "instructions": null, "install": [{"docker": {"image": "$IMAGE", "name": "zusam", "port": "$PORT:8080", "volumes": ["/zusam/data"], "extra_ports": []}}], "verify": [{"http_get": {"url": "http://localhost:$PORT", "expect": [200, 301, 302]}}], "output": {"url": "http://{{ server_ip }}:$PORT", "type": "webapp", "notes": null}}$JSON$::jsonb, NOW()) ON CONFLICT (id) DO NOTHING;
